# ==========================================
# 1. SETUP
# ==========================================
$AppVersion = "6.1"
$ErrorActionPreference = "SilentlyContinue"
# Set encoding dynamically based on the user's local Windows language
$OEMEncoding = [System.Text.Encoding]::GetEncoding([System.Globalization.CultureInfo]::CurrentCulture.TextInfo.OEMCodePage)
[Console]::OutputEncoding = $OEMEncoding
$OutputEncoding = $OEMEncoding

function Get-WmtCurrentProcessPath {
    try {
        $proc = [System.Diagnostics.Process]::GetCurrentProcess()
        if ($proc -and $proc.MainModule -and $proc.MainModule.FileName) {
            return $proc.MainModule.FileName
        }
    }
    catch {}
    return $null
}

$script:WmtScriptPath = if (-not [string]::IsNullOrWhiteSpace($PSCommandPath)) {
    $PSCommandPath
}
elseif ($MyInvocation.MyCommand.Path) {
    $MyInvocation.MyCommand.Path
}
else {
    $null
}

$script:WmtProcessPath = Get-WmtCurrentProcessPath
$script:WmtIsCompiledExe = $false
if (-not [string]::IsNullOrWhiteSpace($script:WmtProcessPath)) {
    $hostExe = Split-Path -Leaf $script:WmtProcessPath
    $script:WmtIsCompiledExe = @("powershell.exe", "pwsh.exe", "powershell_ise.exe") -notcontains $hostExe
}

$script:WmtLaunchPath = if ($script:WmtIsCompiledExe) {
    $script:WmtProcessPath
}
else {
    $script:WmtScriptPath
}

$script:WmtRootPath = $null
try {
    if (-not [string]::IsNullOrWhiteSpace($script:WmtLaunchPath)) {
        $script:WmtRootPath = Split-Path -Parent $script:WmtLaunchPath
    }
}
catch {}
if ([string]::IsNullOrWhiteSpace($script:WmtRootPath)) {
    $script:WmtRootPath = (Get-Location).Path
}

# HIDE CONSOLE + DPI + TOKEN MANIPULATOR (consolidated into one Add-Type call)
# This prevents crashes if you run the script twice in the same session
if (-not ([System.Management.Automation.PSTypeName]'WmtNativeStartup.Native').Type) {
    Add-Type -TypeDefinition @'
using System;
using System.Runtime.InteropServices;
namespace WmtNativeStartup {
    public class Native {
        [DllImport("user32.dll")] public static extern bool ShowWindow(IntPtr handle, int state);
        [DllImport("user32.dll")] public static extern bool SetProcessDPIAware();
    }
    public class TokenManipulator {
        [DllImport("advapi32.dll", ExactSpelling = true, SetLastError = true)]
        internal static extern bool AdjustTokenPrivileges(IntPtr htok, bool disall, ref TokPriv1Luid newst, int len, IntPtr prev, IntPtr relen);
        [DllImport("kernel32.dll", ExactSpelling = true)]
        internal static extern IntPtr GetCurrentProcess();
        [DllImport("advapi32.dll", ExactSpelling = true, SetLastError = true)]
        internal static extern bool OpenProcessToken(IntPtr h, int acc, ref IntPtr phtok);
        [DllImport("advapi32.dll", SetLastError = true)]
        internal static extern bool LookupPrivilegeValue(string host, string name, ref long pluid);
        [StructLayout(LayoutKind.Sequential, Pack = 1)]
        internal struct TokPriv1Luid { public int Count; public long Luid; public int Attr; }
        internal const int SE_PRIVILEGE_ENABLED = 0x00000002;
        internal const int TOKEN_ADJUST_PRIVILEGES = 0x00000020;
        internal const int TOKEN_QUERY = 0x00000008;
        public static bool EnablePrivilege(string privilege) {
            try {
                IntPtr htok = IntPtr.Zero;
                if (!OpenProcessToken(GetCurrentProcess(), TOKEN_ADJUST_PRIVILEGES | TOKEN_QUERY, ref htok)) return false;
                TokPriv1Luid tp; tp.Count = 1; tp.Attr = SE_PRIVILEGE_ENABLED; tp.Luid = 0;
                if (!LookupPrivilegeValue(null, privilege, ref tp.Luid)) return false;
                if (!AdjustTokenPrivileges(htok, false, ref tp, 0, IntPtr.Zero, IntPtr.Zero)) return false;
                return true;
            } catch { return false; }
        }
    }
}
'@
}
try {
    $hwnd = [System.Diagnostics.Process]::GetCurrentProcess().MainWindowHandle
    if ($hwnd -ne [IntPtr]::Zero) {
        [WmtNativeStartup.Native]::ShowWindow($hwnd, 0) | Out-Null
    }
}
catch {}

# ADMIN CHECK
$identity = [System.Security.Principal.WindowsIdentity]::GetCurrent()
$principal = New-Object System.Security.Principal.WindowsPrincipal($identity)
if (-not $principal.IsInRole([System.Security.Principal.WindowsBuiltInRole]::Administrator)) {
    try {
        if ($script:WmtIsCompiledExe -and (Test-Path -LiteralPath $script:WmtLaunchPath)) {
            Start-Process -FilePath $script:WmtLaunchPath -Verb RunAs -WorkingDirectory $script:WmtRootPath
        }
        elseif ($script:WmtScriptPath -and (Test-Path -LiteralPath $script:WmtScriptPath)) {
            $argList = @("-NoProfile", "-ExecutionPolicy", "Bypass", "-File", ('"{0}"' -f $script:WmtScriptPath))
            Start-Process -FilePath "powershell.exe" -ArgumentList $argList -Verb RunAs -WindowStyle Hidden -WorkingDirectory $script:WmtRootPath
        }
        else {
            throw "Could not resolve the WMT launch path."
        }
    }
    catch {
        try {
            Add-Type -AssemblyName PresentationFramework -ErrorAction SilentlyContinue
            [System.Windows.MessageBox]::Show("Failed to restart Windows Maintenance Tool as administrator.`r`n`r`n$($_.Exception.Message)", "WMT Launch Error", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Error) | Out-Null
        }
        catch {}
    }
    exit
}

# Keep one elevated WMT process per interactive Windows session. A later launch
# signals the existing window to restore/focus, then exits before doing any work.
$script:WmtSingleInstanceMutexName = "Local\WindowsMaintenanceTool.SingleInstance"
$script:WmtSingleInstanceActivationEventName = "Local\WindowsMaintenanceTool.Activate"
$script:WmtSingleInstanceMutex = $null
$script:WmtSingleInstanceActivationEvent = $null
$script:WmtSingleInstanceMutexOwned = $false
try {
    $script:WmtSingleInstanceActivationEvent = [System.Threading.EventWaitHandle]::new(
        $false,
        [System.Threading.EventResetMode]::AutoReset,
        $script:WmtSingleInstanceActivationEventName
    )

    $createdNew = $false
    $script:WmtSingleInstanceMutex = [System.Threading.Mutex]::new(
        $true,
        $script:WmtSingleInstanceMutexName,
        [ref]$createdNew
    )
    $script:WmtSingleInstanceMutexOwned = [bool]$createdNew

    if (-not $createdNew) {
        try { [void]$script:WmtSingleInstanceActivationEvent.Set() } catch {}
        try { $script:WmtSingleInstanceActivationEvent.Dispose() } catch {}
        try { $script:WmtSingleInstanceMutex.Dispose() } catch {}
        exit
    }
}
catch {
    try { if ($script:WmtSingleInstanceActivationEvent) { $script:WmtSingleInstanceActivationEvent.Dispose() } } catch {}
    try { if ($script:WmtSingleInstanceMutex) { $script:WmtSingleInstanceMutex.Dispose() } } catch {}
    $script:WmtSingleInstanceActivationEvent = $null
    $script:WmtSingleInstanceMutex = $null
    $script:WmtSingleInstanceMutexOwned = $false
}

# ENABLE HIGH-DPI AWARENESS (using consolidated type)
if ([Environment]::OSVersion.Version.Major -ge 6) {
    try { [WmtNativeStartup.Native]::SetProcessDPIAware() | Out-Null } catch {}
}

Add-Type -AssemblyName PresentationFramework, PresentationCore, WindowsBase, System.Data

# Token Manipulator (consolidated into WmtNativeStartup above)

# ==========================================
# 2. HELPER FUNCTIONS
# ==========================================

function Write-GuiLog {
    param($Msg)
    if ($script:LogBox) {
        $script:LogBox.AppendText("[$((Get-Date).ToString('HH:mm'))] $Msg`n")
        try { if ($script:LogBox.LineCount -gt ($script:WmtMaxLogLines + 100)) { Optimize-WmtLogMemory -MaxLines $script:WmtMaxLogLines } } catch {}
        if (-not $script:WmtLogAutoScrollAttached) {
            $script:LogBox.ScrollToEnd()
        }
    }
}

function ConvertTo-WmtVersion {
    param([string]$VersionText)

    $raw = ([string]$VersionText).Trim()
    $match = [regex]::Match($raw, '^\s*v?(\d+(?:\.\d+){0,3})\s*$', [System.Text.RegularExpressions.RegexOptions]::IgnoreCase)
    if (-not $match.Success) {
        throw "Invalid version string: $VersionText"
    }

    $parts = @($match.Groups[1].Value.Split("."))
    while ($parts.Count -lt 4) { $parts += "0" }
    return [System.Version]::new([int]$parts[0], [int]$parts[1], [int]$parts[2], [int]$parts[3])
}

function Invoke-UiCommand {
    param(
        [scriptblock]$Sb, 
        $Msg = "Processing...", 
        [object[]]$ArgumentList = @()
    )
    try {
        Set-WmtBusyCursor -Busy
        Write-GuiLog $Msg
        # Pass arguments to the scriptblock using splatting
        $res = & $Sb @ArgumentList | Out-String
        if (-not [string]::IsNullOrWhiteSpace($res)) { Write-GuiLog $res.Trim() }
        else { Write-GuiLog "Done." }
    }
    catch { 
        Write-GuiLog "ERROR: $($_.Exception.Message)" 
    }
    finally {
        Set-WmtBusyCursor
    }
}

function Enable-WmtWpfItemsVirtualization {
    param([System.Windows.Controls.ItemsControl]$Control)
    if (-not $Control) { return }
    try {
        [System.Windows.Controls.VirtualizingStackPanel]::SetIsVirtualizing($Control, $true)
        [System.Windows.Controls.VirtualizingStackPanel]::SetVirtualizationMode($Control, [System.Windows.Controls.VirtualizationMode]::Recycling)
        [System.Windows.Controls.ScrollViewer]::SetCanContentScroll($Control, $true)
    }
    catch {}
}

function Test-WmtDirectoryReparsePoint {
    param([string]$Path)
    if ([string]::IsNullOrWhiteSpace($Path)) { return $true }
    try {
        $attributes = [System.IO.Directory]::GetAttributes($Path)
        return (($attributes -band [System.IO.FileAttributes]::ReparsePoint) -ne 0)
    }
    catch {
        return $true
    }
}

function Get-WmtEnumeratedFiles {
    param(
        [string]$Path,
        [string]$Filter = "*",
        [switch]$Recurse
    )
    if ([string]::IsNullOrWhiteSpace($Path) -or -not [System.IO.Directory]::Exists($Path)) { return }

    if (-not $Recurse) {
        try {
            foreach ($file in [System.IO.Directory]::EnumerateFiles($Path, $Filter, [System.IO.SearchOption]::TopDirectoryOnly)) {
                $file
            }
        }
        catch {}
        return
    }

    $visited = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
    $pending = [System.Collections.Generic.Stack[string]]::new()
    try { $pending.Push([System.IO.DirectoryInfo]::new($Path).FullName) } catch { $pending.Push($Path) }
    while ($pending.Count -gt 0) {
        $dir = $pending.Pop()
        try { $dirKey = [System.IO.DirectoryInfo]::new($dir).FullName.TrimEnd([System.IO.Path]::DirectorySeparatorChar, [System.IO.Path]::AltDirectorySeparatorChar) } catch { $dirKey = $dir }
        if (-not $visited.Add($dirKey)) { continue }
        if (Test-WmtDirectoryReparsePoint -Path $dir) { continue }

        try {
            foreach ($file in [System.IO.Directory]::EnumerateFiles($dir, $Filter, [System.IO.SearchOption]::TopDirectoryOnly)) {
                $file
            }
        }
        catch {}

        try {
            foreach ($child in [System.IO.Directory]::EnumerateDirectories($dir, "*", [System.IO.SearchOption]::TopDirectoryOnly)) {
                if (Test-WmtDirectoryReparsePoint -Path $child) { continue }
                $pending.Push($child)
            }
        }
        catch {}
    }
}

function Find-WmtFirstEnumeratedFile {
    param([string]$Path, [string]$Filter)
    foreach ($file in Get-WmtEnumeratedFiles -Path $Path -Filter $Filter -Recurse) {
        return $file
    }
    return $null
}

function Measure-WmtPathBytes {
    param([string]$Path)
    if ([string]::IsNullOrWhiteSpace($Path)) { return 0 }
    try {
        if ([System.IO.File]::Exists($Path)) {
            return [System.IO.FileInfo]::new($Path).Length
        }
        if ([System.IO.Directory]::Exists($Path)) {
            $total = [int64]0
            foreach ($file in Get-WmtEnumeratedFiles -Path $Path -Recurse) {
                try { $total += [System.IO.FileInfo]::new($file).Length } catch {}
            }
            return $total
        }
    }
    catch {}
    return 0
}

function Test-WmtDirectoryHasEntries {
    param([string]$Path)
    if ([string]::IsNullOrWhiteSpace($Path) -or -not [System.IO.Directory]::Exists($Path)) { return $false }
    try {
        foreach ($entry in [System.IO.Directory]::EnumerateFileSystemEntries($Path)) {
            return $true
        }
    }
    catch {}
    return $false
}

function Remove-WmtEmptyChildDirectories {
    param(
        [string]$Path,
        [System.Collections.Generic.HashSet[string]]$Visited
    )
    if ([string]::IsNullOrWhiteSpace($Path) -or -not [System.IO.Directory]::Exists($Path)) { return }
    if (-not $Visited) {
        $Visited = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
    }
    try { $pathKey = [System.IO.DirectoryInfo]::new($Path).FullName.TrimEnd([System.IO.Path]::DirectorySeparatorChar, [System.IO.Path]::AltDirectorySeparatorChar) } catch { $pathKey = $Path }
    if (-not $Visited.Add($pathKey)) { return }
    if (Test-WmtDirectoryReparsePoint -Path $Path) { return }
    try {
        foreach ($dir in [System.IO.Directory]::EnumerateDirectories($Path, "*", [System.IO.SearchOption]::TopDirectoryOnly)) {
            if (Test-WmtDirectoryReparsePoint -Path $dir) { continue }
            Remove-WmtEmptyChildDirectories -Path $dir -Visited $Visited
            try { [System.IO.Directory]::Delete($dir, $false) } catch {}
        }
    }
    catch {}
}

function New-WmtVirtualRows {
    param([object[]]$Items)
    $rows = [System.Collections.ArrayList]::new()
    foreach ($item in @($Items)) { [void]$rows.Add($item) }
    return , $rows
}

