    return (Join-Path (Get-WmtGogdlRootPath) "gogdl_windows_x86_64.exe")
}

function Get-WmtGogdlAuthConfigPath {
    return (Join-Path (Get-WmtGogdlRootPath) "auth.json")
}

# Simple modal text viewer (read-only)
function Show-TextDialog {
    param(
        [string]$Title = "Output",
        [string]$Text = ""
    )

    [xml]$textDialogXaml = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Width="860" Height="620" MinWidth="520" MinHeight="360"
        WindowStartupLocation="CenterOwner" Background="{DynamicResource BgDark}" Foreground="{DynamicResource TextPrimary}"
        FontFamily="Segoe UI Variable Display, Segoe UI, Arial" FontSize="13">
    <Grid Margin="14">
        <Grid.RowDefinitions>
            <RowDefinition Height="*"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>

        <TextBox Name="txtOutput" Grid.Row="0" IsReadOnly="True" AcceptsReturn="True" AcceptsTab="True"
                 TextWrapping="NoWrap" VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Auto"
                 FontFamily="Consolas" FontSize="12" Background="{DynamicResource BgPanel}"/>

        <Button Name="btnClose" Grid.Row="1" Content="Close" Width="94" HorizontalAlignment="Right" Margin="0,12,0,0" IsCancel="True"/>
    </Grid>
</Window>
'@

    try {
        $dialog = New-WmtWindowFromFullXaml -Xaml $textDialogXaml
        $dialog.Title = $Title

        $txtOutput = $dialog.FindName("txtOutput")
        $btnClose = $dialog.FindName("btnClose")
        $txtOutput.Text = $Text
        $btnClose.Add_Click({ $dialog.Close() }.GetNewClosure())
        $dialog.ShowDialog() | Out-Null
    }
    catch {
        Write-GuiLog "Failed to open text dialog: $($_.Exception.Message)"
    }
}

function Get-WmtVisualAncestor {
    param(
        [object]$Element,
        [type]$AncestorType
    )

    $current = $Element
    while ($current -and ($current -is [System.Windows.DependencyObject])) {
        if ($AncestorType.IsInstanceOfType($current)) { return $current }
        try { $current = [System.Windows.Media.VisualTreeHelper]::GetParent($current) }
        catch { break }
    }
    return $null
}

function Get-WmtVisualDescendant {
    param(
        [object]$Element,
        [type]$DescendantType
    )

    if (-not $Element -or -not ($Element -is [System.Windows.DependencyObject]) -or -not $DescendantType) { return $null }

    $childCount = 0
    try { $childCount = [System.Windows.Media.VisualTreeHelper]::GetChildrenCount($Element) }
    catch { return $null }

    for ($i = 0; $i -lt $childCount; $i++) {
        $child = $null
        try { $child = [System.Windows.Media.VisualTreeHelper]::GetChild($Element, $i) } catch { continue }
        if ($child -and $DescendantType.IsInstanceOfType($child)) { return $child }

        $nested = Get-WmtVisualDescendant -Element $child -DescendantType $DescendantType
        if ($nested) { return $nested }
    }

    return $null
}

function Set-WmtListViewRightClickSelection {
    param(
        [System.Windows.Controls.ListView]$ListView,
        [object]$OriginalSource
    )

    if (-not $ListView -or -not $OriginalSource) { return }
    $itemContainer = Get-WmtVisualAncestor -Element $OriginalSource -AncestorType ([System.Windows.Controls.ListViewItem])
    if (-not $itemContainer) { return }

    if (-not $itemContainer.IsSelected) {
        $ListView.SelectedItems.Clear()
        $itemContainer.IsSelected = $true
    }
    try { $itemContainer.Focus() | Out-Null } catch {}
}

function Test-WingetManifestSupportedItem {
    param([object]$Item)

    if (-not $Item) { return $false }
    $id = [string]$Item.Id
    $source = ([string]$Item.Source).ToLowerInvariant()
    if ([string]::IsNullOrWhiteSpace($id)) { return $false }
    return ($source -in @("winget", "msstore"))
}

function ConvertTo-WmtUpdateRowClipboardText {
    param([object[]]$Items)

    $rows = @($Items | Where-Object { $null -ne $_ })
    if ($rows.Count -eq 0) { return "" }

    $preferredProperties = @(
        "Source",
        "Name",
        "Id",
        "Version",
        "Available",
        "IsChecked",
        "WUIsOptional",
        "VersionSort",
        "AvailableSort",
        "RawAvailable",
        "LibraryPath",
        "InstallDir",
        "ManifestPath",
        "ExecutablePath",
        "Platform"
    )
    $preferredSet = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
    foreach ($propertyName in $preferredProperties) { [void]$preferredSet.Add($propertyName) }

    $formatValue = {
        param($Value)
        if ($null -eq $Value) { return "" }
        if ($Value -is [System.Array]) {
            return ((@($Value) | ForEach-Object { [string]$_ }) -join ", ") -replace '\r?\n', ' '
        }
        return (([string]$Value) -replace '\r?\n', ' ').Trim()
    }

    $lines = [System.Collections.Generic.List[string]]::new()
    [void]$lines.Add("WMT Update Row Data")
    [void]$lines.Add("Count: $($rows.Count)")
    [void]$lines.Add("Copied: $((Get-Date).ToString('yyyy-MM-dd HH:mm:ss'))")

    $rowIndex = 0
    foreach ($row in $rows) {
        $rowIndex++
        [void]$lines.Add("")
        [void]$lines.Add("Row $rowIndex")

        foreach ($propertyName in $preferredProperties) {
            $property = $row.PSObject.Properties[$propertyName]
            if (-not $property) { continue }
            [void]$lines.Add("${propertyName}: $(& $formatValue $property.Value)")
        }

        $extraProperties = @($row.PSObject.Properties | Where-Object { -not $preferredSet.Contains($_.Name) } | Sort-Object Name)
        foreach ($property in $extraProperties) {
            [void]$lines.Add("$($property.Name): $(& $formatValue $property.Value)")
        }
    }

    return [string]::Join([Environment]::NewLine, $lines)
}

function Copy-WmtUpdateSelectedRowsToClipboard {
    param(
        [System.Windows.Controls.ListView]$ListView = $lstWinget
    )

    if (-not $ListView) { return $false }
    $selectedRows = @($ListView.SelectedItems | Where-Object { $null -ne $_ })
    if ($selectedRows.Count -eq 0 -and $ListView.SelectedItem) {
        $selectedRows = @($ListView.SelectedItem)
    }
    if ($selectedRows.Count -eq 0) {
        Write-GuiLog "Copy row data skipped: no update row selected."
        return $false
    }

    $text = ConvertTo-WmtUpdateRowClipboardText -Items $selectedRows
    if ([string]::IsNullOrWhiteSpace($text)) { return $false }

    try {
        [System.Windows.Clipboard]::SetText($text)
        Write-GuiLog "Copied $($selectedRows.Count) update row(s) to clipboard."
        return $true
    }
    catch {
        Write-GuiLog "ERROR: Could not copy update row data: $($_.Exception.Message)"
        return $false
    }
}

function ConvertTo-WmtProcessArgument {
    param([string]$Value)

    if ($null -eq $Value) { return '""' }
    return '"' + ($Value -replace '"', '\"') + '"'
}

function Get-WingetManifestText {
    param(
        [object]$Item,
        [int]$TimeoutMs = 45000
    )

    if (-not (Test-WingetManifestSupportedItem $Item)) {
        return [PSCustomObject]@{
            Success  = $false
            ExitCode = $null
            Text     = "App manifests are only available for winget and Microsoft Store packages."
        }
    }

    $id = [string]$Item.Id
    $source = ([string]$Item.Source).ToLowerInvariant()
    $argsLine = @(
        "show",
        "--id", (ConvertTo-WmtProcessArgument $id),
        "--source", (ConvertTo-WmtProcessArgument $source),
        "--exact",
        "--accept-source-agreements",
        "--disable-interactivity"
    ) -join " "

    try {
        $pInfo = New-Object System.Diagnostics.ProcessStartInfo
        $pInfo.FileName = "winget"
        $pInfo.Arguments = $argsLine
        $pInfo.RedirectStandardOutput = $true
        $pInfo.RedirectStandardError = $true
        $pInfo.UseShellExecute = $false
        $pInfo.CreateNoWindow = $true
        $pInfo.StandardOutputEncoding = [System.Text.UTF8Encoding]::new($false)
        $pInfo.StandardErrorEncoding = [System.Text.UTF8Encoding]::new($false)

        $proc = [System.Diagnostics.Process]::Start($pInfo)
        $outTask = $proc.StandardOutput.ReadToEndAsync()
        $errTask = $proc.StandardError.ReadToEndAsync()
        if (-not $proc.WaitForExit($TimeoutMs)) {
            try { $proc.Kill() } catch {}
            try { [void]$proc.WaitForExit(2000) } catch {}
            return [PSCustomObject]@{
                Success  = $false
                ExitCode = $null
                Text     = "Timed out while loading the manifest for $id.`r`n`r`nCommand: winget $argsLine"
            }
        }

        $out = $outTask.GetAwaiter().GetResult()
        $err = $errTask.GetAwaiter().GetResult()
        $textParts = @()
        if (-not [string]::IsNullOrWhiteSpace($out)) { $textParts += $out.TrimEnd() }
        if (-not [string]::IsNullOrWhiteSpace($err)) { $textParts += $err.TrimEnd() }
        $text = ($textParts -join "`r`n`r`n")
        if ([string]::IsNullOrWhiteSpace($text)) { $text = "No manifest output was returned for $id." }

        return [PSCustomObject]@{
            Success  = ($proc.ExitCode -eq 0)
            ExitCode = $proc.ExitCode
            Text     = $text
        }
    }
    catch {
        return [PSCustomObject]@{
            Success  = $false
            ExitCode = $null
            Text     = "Failed to load manifest for $id.`r`n`r`n$($_.Exception.Message)"
        }
    }
}

function Show-WingetPackageManifest {
    param([object]$Item)

    if (-not (Test-WingetManifestSupportedItem $Item)) {
        [System.Windows.MessageBox]::Show(
            "App manifests are only available for winget and Microsoft Store packages.",
            "Manifest Unavailable",
            [System.Windows.MessageBoxButton]::OK,
            [System.Windows.MessageBoxImage]::Information
        ) | Out-Null
        return
    }

    $name = [string]$Item.Name
    $id = [string]$Item.Id
    $source = ([string]$Item.Source).ToLowerInvariant()
    if ([string]::IsNullOrWhiteSpace($name)) { $name = $id }

    Write-GuiLog "Loading app manifest for $name ($id) from $source..."
    if ($lblWingetStatus) {
        $lblWingetStatus.Text = "Loading manifest for $name..."
        $lblWingetStatus.Visibility = "Visible"
    }

    Set-WmtBusyCursor -Busy
    try {
        $result = Get-WingetManifestText -Item $Item
        if (-not $result.Success) {
            Write-GuiLog "Manifest lookup failed for $id$(if ($null -ne $result.ExitCode) { " (exit $($result.ExitCode))" })."
        }
        else {
            Write-GuiLog "Manifest loaded for $id."
        }

        $header = "Package: $name`r`nID: $id`r`nSource: $source`r`nCommand: winget show --id `"$id`" --source $source --exact`r`n"
        $separator = ("-" * 80)
        Show-TextDialog -Title "App Manifest - $name" -Text "$header`r`n$separator`r`n`r`n$($result.Text)"
    }
    finally {
        Set-WmtBusyCursor
        if ($lblWingetStatus) {
            $lblWingetStatus.Text = "Ready"
            $lblWingetStatus.Visibility = "Hidden"
        }
    }
}

# --- SETTINGS MANAGER ---
# Initialize cache variable
$script:WmtSettingsCache = $null

function Save-WmtSettings {
    param($Settings)
    $path = Join-Path (Get-DataPath) "settings.json"
    try {
        # Update the memory cache immediately
        $script:WmtSettingsCache = $Settings

        # Convert Hashtable/OrderedDictionary to generic Object for cleaner JSON
        $saveObj = [PSCustomObject]@{
            TempCleanup                = $Settings.TempCleanup
            RegistryScan               = $Settings.RegistryScan
            WingetIgnore               = $Settings.WingetIgnore
            WingetIncludeUnknown       = [bool](Get-WmtWingetIncludeUnknown -Settings $Settings)
            UpdateAutoScanMinutes      = [int](Get-WmtUpdateAutoScanMinutes -Settings $Settings)
            UpdateNotificationsEnabled = [bool](Get-WmtUpdateNotificationsEnabled -Settings $Settings)
            UpdateSilentInstallEnabled = [bool](Get-WmtUpdateSilentInstallEnabled -Settings $Settings)
            UpdateAutoInstallEnabled   = [bool](Get-WmtUpdateAutoInstallEnabled -Settings $Settings)
            RunInTrayOnClose           = [bool](Get-WmtRunInTrayOnClose -Settings $Settings)
            ReduceRamInTray            = [bool](Get-WmtReduceRamInTray -Settings $Settings)
            LoadWinapp2                = [bool]$Settings.LoadWinapp2
            LoadCleanerML              = [bool]$Settings.LoadCleanerML
            EnabledProviders           = $Settings.EnabledProviders
            ProviderToggles            = if ($Settings.ProviderToggles) { $Settings.ProviderToggles } else { @{} }
            WuCategoryToggles          = if ($Settings.WuCategoryToggles) { $Settings.WuCategoryToggles } else { @{} }
            CustomDnsServers           = if ($Settings.CustomDnsServers) { @($Settings.CustomDnsServers) } else { @() }
            CustomDohTemplate          = if ($Settings.CustomDohTemplate) { [string]$Settings.CustomDohTemplate } else { "" }
            CustomDohEnabled           = [bool]$Settings.CustomDohEnabled
            Theme                      = if ($Settings.Theme) { [string]$Settings.Theme } else { "dark" }
            WindowState                = if ($Settings.WindowState) { [string]$Settings.WindowState } else { "Normal" }
            WindowBounds               = if ($Settings.WindowBounds) { $Settings.WindowBounds } else { $null }
        }
        $saveObj | ConvertTo-Json -Depth 5 | Set-Content $path -Force
    }
    catch {
        Write-Warning "Failed to save settings: $_"
    }
}

function Get-WmtSettings {
    # OPTIMIZATION: Return cached settings if available to avoid disk I/O.
    # Return a shallow clone so callers can't mutate the cache by reference.
    if ($script:WmtSettingsCache) {
        $clone = @{}
        foreach ($k in @($script:WmtSettingsCache.Keys)) {
            $clone[$k] = $script:WmtSettingsCache[$k]
        }
        return $clone
    }

    $path = Join-Path (Get-DataPath) "settings.json"
    
    # Default Structure
    $defaults = @{
        TempCleanup                = @{}
        RegistryScan               = @{}
        WingetIgnore               = @("228980") # Filter false positive updates for Steamworks Redist
        WingetIncludeUnknown       = $true
        UpdateAutoScanMinutes      = 0
        UpdateNotificationsEnabled = $true
        UpdateSilentInstallEnabled = $false
        UpdateAutoInstallEnabled   = $false
        RunInTrayOnClose           = $false
        ReduceRamInTray            = $true
        LoadWinapp2                = $false 
        LoadCleanerML              = $false
        EnabledProviders           = @("winget", "msstore", "windowsupdate", "pip", "npm", "pnpm", "dotnet", "psmodule", "composer", "chocolatey", "scoop", "gem", "cargo", "steam", "legendary", "gogdl")
        WuCategoryToggles          = @{}
        ProviderToggles            = @{}
        CustomDnsServers           = @()
        CustomDohTemplate          = ""
        CustomDohEnabled           = $false
        Theme                      = "dark"
        WindowState                = "Normal"
        WindowBounds               = @{
            Top    = 0
            Left   = 0
            Width  = 1280
            Height = 820
        }
    }
    
    if (Test-Path $path) {
        try {
            $json = Get-Content $path -Raw | ConvertFrom-Json
            
            if ($json.TempCleanup) { 
                foreach ($p in $json.TempCleanup.PSObject.Properties) { $defaults.TempCleanup[$p.Name] = $p.Value } 
            }
            if ($json.RegistryScan) { 
                foreach ($p in $json.RegistryScan.PSObject.Properties) { $defaults.RegistryScan[$p.Name] = $p.Value } 
            }
            if ($json.PSObject.Properties["WingetIgnore"]) {
                $raw = $json.WingetIgnore
                $clean = New-Object System.Collections.ArrayList
                if ($raw) { foreach ($item in $raw) { [void]$clean.Add("$item".Trim()) } }
                $defaults.WingetIgnore = $clean.ToArray()
            }
            if ($json.PSObject.Properties["WingetIncludeUnknown"]) { $defaults.WingetIncludeUnknown = [bool]$json.WingetIncludeUnknown }
            if ($json.PSObject.Properties["UpdateAutoScanMinutes"]) {
                try { $defaults.UpdateAutoScanMinutes = [int]$json.UpdateAutoScanMinutes } catch { $defaults.UpdateAutoScanMinutes = 0 }
                if ($defaults.UpdateAutoScanMinutes -lt 0) { $defaults.UpdateAutoScanMinutes = 0 }
            }
            if ($json.PSObject.Properties["UpdateNotificationsEnabled"]) { $defaults.UpdateNotificationsEnabled = [bool]$json.UpdateNotificationsEnabled }
            if ($json.PSObject.Properties["UpdateSilentInstallEnabled"]) { $defaults.UpdateSilentInstallEnabled = [bool]$json.UpdateSilentInstallEnabled }
            if ($json.PSObject.Properties["UpdateAutoInstallEnabled"]) { $defaults.UpdateAutoInstallEnabled = [bool]$json.UpdateAutoInstallEnabled }
            if ($json.PSObject.Properties["RunInTrayOnClose"]) { $defaults.RunInTrayOnClose = [bool]$json.RunInTrayOnClose }
            if ($json.PSObject.Properties["ReduceRamInTray"]) { $defaults.ReduceRamInTray = [bool]$json.ReduceRamInTray }
            if ($json.PSObject.Properties["LoadWinapp2"]) { $defaults.LoadWinapp2 = [bool]$json.LoadWinapp2 }
            if ($json.PSObject.Properties["LoadCleanerML"]) { $defaults.LoadCleanerML = [bool]$json.LoadCleanerML }
            if ($json.PSObject.Properties["EnabledProviders"]) { $defaults.EnabledProviders = $json.EnabledProviders }
            if ($json.PSObject.Properties["ProviderToggles"]) { $defaults.ProviderToggles = $json.ProviderToggles }
            if ($json.PSObject.Properties["WuCategoryToggles"]) { $defaults.WuCategoryToggles = $json.WuCategoryToggles }
            if ($json.PSObject.Properties["CustomDnsServers"]) {
                $customDnsServers = @()
                foreach ($server in @($json.CustomDnsServers)) {
                    $serverText = ([string]$server).Trim()
                    if (-not [string]::IsNullOrWhiteSpace($serverText)) { $customDnsServers += $serverText }
                }
                $defaults.CustomDnsServers = $customDnsServers
            }
            if ($json.PSObject.Properties["CustomDohTemplate"]) { $defaults.CustomDohTemplate = [string]$json.CustomDohTemplate }
            if ($json.PSObject.Properties["CustomDohEnabled"]) { $defaults.CustomDohEnabled = [bool]$json.CustomDohEnabled }
            if ($json.PSObject.Properties["Theme"] -and $json.Theme) { $defaults.Theme = [string]$json.Theme }
            if ($json.PSObject.Properties["WindowState"] -and $json.WindowState) { $defaults.WindowState = [string]$json.WindowState }
            if ($json.PSObject.Properties["WindowBounds"] -and $json.WindowBounds) {
                $defaults.WindowBounds = @{
                    Top    = [double]$json.WindowBounds.Top
                    Left   = [double]$json.WindowBounds.Left
                    Width  = [double]$json.WindowBounds.Width
                    Height = [double]$json.WindowBounds.Height
                }
            }
        }
        catch { 
            Write-GuiLog "Error loading settings: $($_.Exception.Message)" 
        }
    }
    $normalizedProviders = New-Object System.Collections.Generic.List[string]
    foreach ($provider in @($defaults.EnabledProviders)) {
        $providerKey = ([string]$provider).Trim().ToLowerInvariant()
        if ([string]::IsNullOrWhiteSpace($providerKey)) { continue }
        if ($providerKey -eq "comet") { $providerKey = "gogdl" }
        if (-not $normalizedProviders.Contains($providerKey)) {
            [void]$normalizedProviders.Add($providerKey)
        }
    }
    if ($normalizedProviders.Count -eq 0) {
        [void]$normalizedProviders.Add("winget")
    }
    $defaults.EnabledProviders = $normalizedProviders.ToArray()

    # Cache the result
    $script:WmtSettingsCache = $defaults
    return $defaults
}

function Get-WmtWingetIncludeUnknown {
    param($Settings)

    if (-not $Settings) { $Settings = Get-WmtSettings }

    if ($Settings -is [System.Collections.IDictionary] -and $Settings.Contains("WingetIncludeUnknown")) {
        return [bool]$Settings["WingetIncludeUnknown"]
    }
    if ($Settings.PSObject.Properties["WingetIncludeUnknown"]) {
        return [bool]$Settings.WingetIncludeUnknown
    }

    return $true
}

function Set-WmtWingetIncludeUnknown {
    param([bool]$IncludeUnknown)

    $settings = Get-WmtSettings
    if ($settings -is [System.Collections.IDictionary]) {
        $settings["WingetIncludeUnknown"] = $IncludeUnknown
    }
    elseif ($settings.PSObject.Properties["WingetIncludeUnknown"]) {
        $settings.WingetIncludeUnknown = $IncludeUnknown
    }
    else {
        $settings | Add-Member -MemberType NoteProperty -Name "WingetIncludeUnknown" -Value $IncludeUnknown -Force
    }
    Save-WmtSettings -Settings $settings
}

function Get-WmtUpdateAutoScanMinutes {
    param($Settings)

    if (-not $Settings) { $Settings = Get-WmtSettings }

    $value = 0
    try {
        if ($Settings -is [System.Collections.IDictionary] -and $Settings.Contains("UpdateAutoScanMinutes")) {
            $value = [int]$Settings["UpdateAutoScanMinutes"]
        }
        elseif ($Settings.PSObject.Properties["UpdateAutoScanMinutes"]) {
            $value = [int]$Settings.UpdateAutoScanMinutes
        }
    }
    catch {
        $value = 0
    }

    if ($value -lt 0) { return 0 }
    if ($value -gt 1440) { return 1440 }
    return $value
}

function Set-WmtUpdateAutoScanMinutes {
    param([int]$Minutes)

    if ($Minutes -lt 0) { $Minutes = 0 }
    if ($Minutes -gt 1440) { $Minutes = 1440 }

    $settings = Get-WmtSettings
    if ($settings -is [System.Collections.IDictionary]) {
        $settings["UpdateAutoScanMinutes"] = $Minutes
    }
    elseif ($settings.PSObject.Properties["UpdateAutoScanMinutes"]) {
        $settings.UpdateAutoScanMinutes = $Minutes
    }
    else {
        $settings | Add-Member -MemberType NoteProperty -Name "UpdateAutoScanMinutes" -Value $Minutes -Force
    }
    Save-WmtSettings -Settings $settings
}

