    if ($savedServers.Count -eq 0) { $savedServers = @("1.1.1.1", "1.0.0.1", "2606:4700:4700::1111", "2606:4700:4700::1001") }
    $txtDnsServers.Text = ($savedServers -join ", ")
    $txtDohTemplate.Text = if ($settings.CustomDohTemplate) { [string]$settings.CustomDohTemplate } else { "" }
    $chkRegisterDoh.IsChecked = [bool]$settings.CustomDohEnabled

    $setDohTemplateState = {
        $enabled = [bool]$chkRegisterDoh.IsChecked
        $txtDohTemplate.IsEnabled = $enabled
        $txtDohTemplate.Opacity = if ($enabled) { 1.0 } else { 0.55 }
    }.GetNewClosure()
    $chkRegisterDoh.Add_Checked($setDohTemplateState)
    $chkRegisterDoh.Add_Unchecked($setDohTemplateState)
    & $setDohTemplateState

    $dialog.Tag = $null

    $getValidatedCustomDns = {
        $lblError.Text = ""
        $addresses = $txtDnsServers.Text -split "[,;\s]+" | ForEach-Object { $_.Trim() } | Where-Object { $_ }
        $validation = Get-WmtValidatedDnsAddresses -Addresses $addresses
        if (-not $validation.Valid -or $validation.Valid.Count -eq 0) {
            $lblError.Text = "Enter at least one valid DNS server IP address."
            $null
        }
        else {
            $registerDoh = [bool]$chkRegisterDoh.IsChecked
            $dohTemplate = ([string]$txtDohTemplate.Text).Trim()

            if ($registerDoh -and -not (Test-WmtDohTemplateUrl -Url $dohTemplate)) {
                $lblError.Text = "Enter a valid HTTPS DoH template URL."
                $null
            }
            else {
                [PSCustomObject]@{
                    Addresses   = @($validation.Valid)
                    Invalid     = @($validation.Invalid)
                    RegisterDoh = $registerDoh
                    DohTemplate = $dohTemplate
                    Action      = "Apply"
                }
            }
        }
    }.GetNewClosure()

    $btnApply.Add_Click({
            $candidate = & $getValidatedCustomDns
            if (-not $candidate) { return }

            $dialog.Tag = $candidate
            $dialog.DialogResult = $true
        }.GetNewClosure())

    $btnRemoveDoh.Add_Click({
            $lblError.Text = ""
            $addresses = $txtDnsServers.Text -split "[,;\s]+" | ForEach-Object { $_.Trim() } | Where-Object { $_ }
            $validation = Get-WmtValidatedDnsAddresses -Addresses $addresses
            if (-not $validation.Valid -or $validation.Valid.Count -eq 0) {
                $lblError.Text = "Enter at least one valid DNS server IP address."
                return
            }

            $dialog.Tag = [PSCustomObject]@{
                Addresses   = @($validation.Valid)
                Invalid     = @($validation.Invalid)
                RegisterDoh = $false
                DohTemplate = ([string]$txtDohTemplate.Text).Trim()
                Action      = "RemoveDoh"
            }
            $dialog.DialogResult = $true
        }.GetNewClosure())

    $btnCancel.Add_Click({ $dialog.DialogResult = $false }.GetNewClosure())

    if ($dialog.ShowDialog() -eq $true) { return $dialog.Tag }
    return $null
}

function Invoke-CustomDnsSettings {
    $customDns = Show-CustomDnsDialog
    if (-not $customDns) { return }

    if ($customDns.Invalid.Count -gt 0) {
        Write-GuiLog "Invalid DNS skipped: $($customDns.Invalid -join ', ')"
    }

    $settings = Get-WmtSettings
    $settings.CustomDnsServers = @($customDns.Addresses)
    $settings.CustomDohTemplate = [string]$customDns.DohTemplate
    $settings.CustomDohEnabled = [bool]$customDns.RegisterDoh
    Save-WmtSettings -Settings $settings

    $customDohTargets = New-WmtDohTargets -Addresses $customDns.Addresses -Template $customDns.DohTemplate
    if ($customDns.Action -eq "RemoveDoh") {
        Start-DohJob -List $customDohTargets -IsEnable $false
        return
    }

    if ($customDns.RegisterDoh) {
        Set-DnsAddresses -Addresses $customDns.Addresses -Label "Custom DNS" -OnComplete ({
                param($Result)
                if ($Result -and $Result.Success) {
                    Start-DohJob -List $customDohTargets -IsEnable $true
                }
                else {
                    Write-GuiLog "Skipped DoH registration because custom DNS assignment did not complete successfully."
                }
            }.GetNewClosure())
        return
    }

    Set-DnsAddresses -Addresses $customDns.Addresses -Label "Custom DNS"
}

function Start-DohJob {
    param($List, $IsEnable)

    $dnsList = @($List)
    if (-not $dnsList -or $dnsList.Count -eq 0) {
        Write-GuiLog "No DoH targets configured."
        return
    }

    if (Test-WmtDnsRunspaceBusy) {
        Write-GuiLog "A DNS or DoH operation is already running."
        return
    }

    if ($script:DohRunspace) {
        try { $script:DohRunspace.Dispose() } catch {}
        $script:DohRunspace = $null
        $script:DohAsyncResult = $null
    }

    $isEnableForTimer = [bool]$IsEnable
    $actionStr = if ($isEnableForTimer) { "Registering" } else { "Removing" }
    Write-GuiLog "$actionStr DoH templates..."
    Set-WmtDnsActionButtonsEnabled $false

    try {
        $script:DohRunspace = [PowerShell]::Create().AddScript({
                param($List, $IsEnable)

                $cnt = 0
                $failures = @()

                foreach ($dns in $List) {
                    $server = [string]$dns.Server
                    $template = [string]$dns.Template
                    if ([string]::IsNullOrWhiteSpace($server)) { continue }

                    if ($IsEnable) {
                        & netsh.exe dns delete encryption "server=$server" 2>&1 | Out-Null
                        & netsh.exe dns add encryption "server=$server" "dohtemplate=$template" autoupgrade=yes udpfallback=no 2>&1 | Out-Null
                        if ($LASTEXITCODE -eq 0) { $cnt++ }
                        else { $failures += $server }
                    }
                    else {
                        & netsh.exe dns delete encryption "server=$server" 2>&1 | Out-Null
                        # Treat missing entries as already disabled; the desired end state is still reached.
                        $cnt++
                    }
                }

                ipconfig /flushdns | Out-Null
                try { Restart-Service Dnscache -Force -ErrorAction SilentlyContinue } catch {}
                
                [PSCustomObject]@{
                    Count    = $cnt
                    Failed   = $failures.Count
                    Failures = $failures
                    Success  = ($failures.Count -eq 0)
                }
            }).AddArgument($dnsList).AddArgument($isEnableForTimer)

        $script:DohAsyncResult = $script:DohRunspace.BeginInvoke()
    }
    catch {
        Write-GuiLog "Failed to start DoH runspace: $($_.Exception.Message)"
        try { if ($script:DohRunspace) { $script:DohRunspace.Dispose() } } catch {}
        $script:DohRunspace = $null
        $script:DohAsyncResult = $null
        Set-WmtDnsActionButtonsEnabled $true
        return
    }

    $dohRunspace = $script:DohRunspace
    $dohAsync = $script:DohAsyncResult
    if (-not $dohRunspace -or -not $dohAsync) {
        Write-GuiLog "Failed to start DoH runspace."
        Set-WmtDnsActionButtonsEnabled $true
        return
    }

    if ($script:DohTimer) { $script:DohTimer.Stop() }
    $dohTimer = New-Object System.Windows.Threading.DispatcherTimer
    $script:DohTimer = $dohTimer
    $dohTimer.Interval = [TimeSpan]::FromMilliseconds(250)
    
    $dohTimer.Add_Tick({
            if (-not $dohAsync -or -not $dohAsync.IsCompleted) { return }

            $dohTimer.Stop()
            try {
                $rawResults = $dohRunspace.EndInvoke($dohAsync)
                $res = $rawResults | Where-Object { $_ -is [PSCustomObject] -and $_.Psobject.Properties.Match('Count') } | Select-Object -Last 1

                if ($res -and $res.Success) {
                    $c = $res.Count
                    if ($isEnableForTimer) {
                        $finMsg = "Registered $c DoH templates."
                    }
                    else {
                        $finMsg = "Removed or verified $c DoH templates."
                    }

                    Write-GuiLog "Done. $finMsg"

                    if ($c -gt 0) {
                        [System.Windows.MessageBox]::Show($finMsg, "DoH Manager", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Information) | Out-Null
                    }
                }
                else {
                    $failedText = if ($res -and $res.Failures) { " Failed: $($res.Failures -join ', ')" } else { "" }
                    Write-GuiLog "DoH operation failed or no changes were made.$failedText"
                }
            }
            catch {
                Write-GuiLog "DoH Error: $($_.Exception.Message)"
            }
            finally {
                try {
                    $dohRunspace.Dispose()
                }
                catch {}
                if ([object]::ReferenceEquals($script:DohRunspace, $dohRunspace)) { $script:DohRunspace = $null }
                if ([object]::ReferenceEquals($script:DohAsyncResult, $dohAsync)) { $script:DohAsyncResult = $null }
                if ([object]::ReferenceEquals($script:DohTimer, $dohTimer)) { $script:DohTimer = $null }
                Set-WmtDnsActionButtonsEnabled $true
            }
        }.GetNewClosure())
    
    $dohTimer.Start()
}

# Redirect existing function calls to the new Async handler
function Enable-AllDoh { Start-DohJob -List $script:DohTargets -IsEnable $true }
function Disable-AllDoh { Start-DohJob -List $script:DohTargets -IsEnable $false }

# --- Hosts Adblock ---
function Invoke-HostsUpdate {
    Invoke-UiCommand {
        # 1. Find PATHS
        $hostsPath = "$env:windir\System32\drivers\etc\hosts"
        $backupDir = Join-Path (Get-DataPath) "hosts_backups"
        if (-not (Test-Path $backupDir)) { New-Item -ItemType Directory -Path $backupDir -Force | Out-Null }

        # 2. DOWNLOAD HOSTS FILE
        $mirrors = @(
            "https://o0.pages.dev/Lite/hosts.win",
            "https://raw.githubusercontent.com/badmojr/1Hosts/master/Lite/hosts.win"
        )
        $adBlockContent = $null
        foreach ($mirror in $mirrors) {
            try {
                $wc = New-Object System.Net.WebClient
                # CRITICAL SPEED FIX: Bypasses auto-proxy detection delay (saves 1-5s)
                $wc.Proxy = $null 
                $wc.Encoding = [System.Text.Encoding]::UTF8
                
                Write-GuiLog "Downloading from $mirror..."
                $tempContent = $wc.DownloadString($mirror)
                
                # SAFETY CHECK: Ensure file is valid (> 1KB)
                if ($tempContent.Length -gt 1024) { 
                    $adBlockContent = $tempContent
                    Write-Output "Download complete ($([math]::Round($adBlockContent.Length / 1KB, 2)) KB)"
                    break 
                }
            }
            catch { 
                Write-Output "Mirror failed: $mirror" 
            }
            finally { 
                if ($wc) { $wc.Dispose() } 
            }
        }

        if (-not $adBlockContent) { 
            Write-GuiLog "ERROR: Download failed or file was empty. Aborting."
            return 
        }

        # 3. BACKUP EXISTING
        if (Test-Path $hostsPath) {
            $bkName = "hosts_$(Get-Date -F yyyyMMdd_HHmmss).bak"
            Copy-Item $hostsPath (Join-Path $backupDir $bkName) -Force
            Write-Output "Backup created: $bkName"
        }

        # 4. PRESERVE CUSTOM ENTRIES
        $customStart = "# === BEGIN USER CUSTOM ENTRIES ==="
        $customEnd = "# === END USER CUSTOM ENTRIES ==="
        $userEntries = "$customStart`r`n# Add custom entries here`r`n127.0.0.1 localhost`r`n::1 localhost`r`n$customEnd"

        if (Test-Path $hostsPath) {
            try {
                $raw = Get-Content $hostsPath -Raw
                if ($raw -match "(?s)$([regex]::Escape($customStart))(.*?)$([regex]::Escape($customEnd))") {
                    $userEntries = $matches[0]
                }
            }
            catch {}
        }

        # 5. CONSTRUCT & WRITE
        $finalContent = "$userEntries`r`n`r`n# UPDATED: $(Get-Date)`r`n$adBlockContent"
        
        try {
            # FIX: Write file as UTF-8 without Byte Order Mark (BOM)
            $utf8NoBom = New-Object System.Text.UTF8Encoding $false
            [System.IO.File]::WriteAllText($hostsPath, $finalContent, $utf8NoBom)

            # FIX: Ensure Users have read access using Universal SID (Localization safe)
            try {
                $acl = Get-Acl -Path $hostsPath
                # Get Universal SID for Built-in "Users" group
                $usersSid = [System.Security.Principal.SecurityIdentifier]::new([System.Security.Principal.WellKnownSidType]::BuiltinUsersSid, $null)
                $rule = New-Object System.Security.AccessControl.FileSystemAccessRule($usersSid, "ReadAndExecute", "Allow")
                $acl.SetAccessRule($rule)
                Set-Acl -Path $hostsPath -AclObject $acl
                Write-Output "Applied universal read permissions to hosts file."
            }
            catch {
                Write-Output "Warning: Could not strictly apply permissions: $($_.Exception.Message)"
            }
            
            # Validation
            if ((Get-Item $hostsPath).Length -lt 100) { throw "Write verification failed (File empty)." }
            
            ipconfig /flushdns | Out-Null
            Write-Output "Hosts file updated and DNS flushed successfully."
        }
        catch {
            Write-GuiLog "CRITICAL ERROR: $($_.Exception.Message)"
            # Restore backup if write failed
            $latestBackup = @(Get-WmtEnumeratedFiles -Path $backupDir | ForEach-Object { [System.IO.FileInfo]::new($_) } | Sort-Object CreationTime -Descending | Select-Object -First 1)
            if ($latestBackup) {
                Copy-Item $latestBackup.FullName $hostsPath -Force
                Write-GuiLog "Restored backup due to failure."
            }
        }
    } "Updating hosts file..."
}

# --- HOSTS EDITOR ---
function Show-HostsEditor {
    $hostsPath = "$env:windir\System32\drivers\etc\hosts"
    $content = ""

    if (Test-Path $hostsPath) {
        $diskSize = (Get-Item $hostsPath).Length
        $content = Get-Content $hostsPath -Raw -ErrorAction SilentlyContinue

        if ($diskSize -gt 0 -and [string]::IsNullOrWhiteSpace($content)) {
            Show-WmtMessageBox -Message "Could not read Hosts file. Aborting." -Title "Error" -Image Error | Out-Null
            return
        }
    }

    [xml]$hostsEditorXaml = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="Hosts File Editor" Width="920" Height="720" MinWidth="660" MinHeight="460"
        WindowStartupLocation="CenterOwner" Background="{DynamicResource BgDark}" Foreground="{DynamicResource TextPrimary}"
        FontFamily="Segoe UI Variable Display, Segoe UI, Arial" FontSize="13">
    <Grid>
        <Grid.RowDefinitions>
            <RowDefinition Height="*"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>

        <TextBox Name="txtHosts" Grid.Row="0" Margin="14" AcceptsReturn="True" AcceptsTab="True"
                 TextWrapping="NoWrap" VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Auto"
                 FontFamily="Consolas" FontSize="13" Background="{DynamicResource BgPanel}"/>

        <Border Grid.Row="1" Background="{DynamicResource BgPanel}" BorderBrush="{DynamicResource BorderBrush}" BorderThickness="0,1,0,0" Padding="14,10">
            <Grid>
                <TextBlock Text="Ctrl+S to Save" Foreground="{DynamicResource TextSecondary}" VerticalAlignment="Center"/>
                <StackPanel Orientation="Horizontal" HorizontalAlignment="Right">
                    <Button Name="btnSave" Content="Save" Width="100" Background="{DynamicResource Success}" Foreground="{DynamicResource SuccessText}" Margin="0,0,8,0"/>
                    <Button Name="btnClose" Content="Close" Width="94" IsCancel="True"/>
                </StackPanel>
            </Grid>
        </Border>
    </Grid>
</Window>
'@

    try {
        $dialog = New-WmtWindowFromFullXaml -Xaml $hostsEditorXaml
    }
    catch {
        Write-GuiLog "Failed to open Hosts editor: $($_.Exception.Message)"
        return
    }

    $txtHosts = $dialog.FindName("txtHosts")
    $btnSave = $dialog.FindName("btnSave")
    $btnClose = $dialog.FindName("btnClose")
    $state = @{ Dirty = $false }

    $txtHosts.Text = $content

    $SaveAction = {
        param($DialogObj, $TextBox, $FilePath)

        try {
            if ([string]::IsNullOrWhiteSpace($TextBox.Text)) {
                $check = Show-WmtMessageBox -Owner $DialogObj -Message "Save EMPTY file?" -Title "Warning" -Button YesNo -Image Warning
                if ($check -ne [System.Windows.MessageBoxResult]::Yes) { return $false }
            }

            $utf8NoBom = New-Object System.Text.UTF8Encoding $false
            [System.IO.File]::WriteAllText($FilePath, $TextBox.Text, $utf8NoBom)

            try {
                $acl = Get-Acl -Path $FilePath
                $usersSid = [System.Security.Principal.SecurityIdentifier]::new([System.Security.Principal.WellKnownSidType]::BuiltinUsersSid, $null)
                $rule = New-Object System.Security.AccessControl.FileSystemAccessRule($usersSid, "ReadAndExecute", "Allow")
                $acl.SetAccessRule($rule)
                Set-Acl -Path $FilePath -AclObject $acl
            }
            catch {}

            ipconfig /flushdns | Out-Null

            if ((Get-Item $FilePath).Length -eq 0 -and $TextBox.Text.Length -gt 0) {
                throw "Write failed (0 bytes)."
            }

            $state.Dirty = $false
            if ($DialogObj) { $DialogObj.Title = "Hosts File Editor" }
            Show-WmtMessageBox -Owner $DialogObj -Message "Saved successfully and flushed DNS!" -Title "Success" -Image Information | Out-Null
            return $true
        }
        catch {
            Show-WmtMessageBox -Owner $DialogObj -Message "Error saving: $_" -Title "Error" -Image Error | Out-Null
            return $false
        }
    }

    $txtHosts.Add_TextChanged({
            $state.Dirty = $true
            if ($dialog.Title -notmatch "\*$") {
                $dialog.Title = "Hosts File Editor *"
            }
        }.GetNewClosure())

    $btnSave.Add_Click({
            $null = & $SaveAction -DialogObj $dialog -TextBox $txtHosts -FilePath $hostsPath
        }.GetNewClosure())

    $btnClose.Add_Click({ $dialog.Close() }.GetNewClosure())

    $dialog.Add_KeyDown({
            param($src, $e)
            if ($e.Key -eq [System.Windows.Input.Key]::S -and (([System.Windows.Input.Keyboard]::Modifiers -band [System.Windows.Input.ModifierKeys]::Control) -eq [System.Windows.Input.ModifierKeys]::Control)) {
                $e.Handled = $true
                $null = & $SaveAction -DialogObj $src -TextBox $txtHosts -FilePath $hostsPath
            }
        }.GetNewClosure())

    $dialog.Add_Closing({
            param($src, $e)

            if ($state.Dirty -eq $true) {
                $res = Show-WmtMessageBox -Owner $src -Message "You have unsaved changes. Save now?" -Title "Confirm" -Button YesNoCancel -Image Warning

                if ($res -eq [System.Windows.MessageBoxResult]::Yes) {
                    $success = & $SaveAction -DialogObj $src -TextBox $txtHosts -FilePath $hostsPath
                    if (-not $success) {
                        $e.Cancel = $true
                    }
                }
                elseif ($res -eq [System.Windows.MessageBoxResult]::Cancel) {
                    $e.Cancel = $true
                }
            }
        }.GetNewClosure())

    $dialog.ShowDialog() | Out-Null
}
# --- STORAGE / SYSTEM ---
function Invoke-ChkdskAll {
    $confirm = [System.Windows.MessageBox]::Show("Run CHKDSK /f /r on all file-system drives in a live console window?`n`nThis can take a long time. System drive repairs may be scheduled for next reboot.", "Confirm CHKDSK", [System.Windows.MessageBoxButton]::YesNo, [System.Windows.MessageBoxImage]::Warning)
    if ($confirm -ne "Yes") { return }
    Start-ChkdskConsole
}

function Start-ChkdskConsole {
    $consoleScript = @'
[Console]::OutputEncoding = [System.Text.UTF8Encoding]::new($false)
$ErrorActionPreference = "Continue"

Write-Host "WMT: CHKDSK started at $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')"
Write-Host ""

$drives = Get-PSDrive -PSProvider FileSystem -ErrorAction SilentlyContinue |
    Where-Object { $null -ne $_.Free } |
    Select-Object -ExpandProperty Name -Unique |
    Sort-Object

if (-not $drives -or $drives.Count -eq 0) {
    Write-Host "No file-system drives detected."
    Write-Host ""
    [void](Read-Host "Press Enter to close")
    exit
}

$systemDrive = (($env:SystemDrive -replace ":", "")).ToUpperInvariant()
$ok = 0
$fail = 0

foreach ($drive in $drives) {
    $letter = ([string]$drive).TrimEnd(":").ToUpperInvariant()
    $target = "$letter`:"

    Write-Host ""
    Write-Host "[$target] Running CHKDSK..."

    try {
        if ($letter -eq $systemDrive) {
            Write-Host "[$target] System drive detected. Auto-answering schedule prompt with 'Y' if required."
            $out = cmd.exe /c "echo Y|chkdsk $target /f /r" 2>&1
        } else {
            $out = cmd.exe /c "chkdsk $target /f /r /x" 2>&1
        }

        $exitCode = $LASTEXITCODE
        if ($out) { $out | ForEach-Object { if ($null -ne $_) { Write-Host $_ } } }

        if ($exitCode -eq 0) {
            Write-Host "[$target] Completed (exit 0)."
            $ok++
        } else {
            Write-Warning "[$target] Completed with exit code $exitCode."
            if ($letter -eq $systemDrive) {
                Write-Host "[$target] Note: System drive checks commonly require reboot scheduling."
            }
            $fail++
        }
    } catch {
        Write-Warning "[$target] Failed: $($_.Exception.Message)"
        $fail++
    }
}

Write-Host ""
Write-Host "Summary: completed_ok=$ok, completed_with_warnings=$fail"
Write-Host ""
[void](Read-Host "Press Enter to close")
'@

    $encoded = [Convert]::ToBase64String([System.Text.Encoding]::Unicode.GetBytes($consoleScript))
    Start-Process -FilePath "powershell.exe" -ArgumentList "-NoProfile -ExecutionPolicy Bypass -EncodedCommand $encoded" -WindowStyle Normal
    Write-GuiLog "[CHKDSK] Opened live CHKDSK console window."
}
# ==========================================
# WINAPP2.INI INTEGRATION
# ==========================================

function Expand-EnvPath {
    param($Path)
    if ([string]::IsNullOrWhiteSpace($Path)) { return $Path }
    # Expand standard vars (%AppData%, etc)
    $expanded = [Environment]::ExpandEnvironmentVariables($Path)
    # Handle common Winapp2 specific variables if needed (e.g. %ProgramFiles%)
    return $expanded
}

function Test-WmtCleanerMlOs {
    param($Node)

    if (-not $Node) { return $true }
    $os = ""
    try { $os = [string]$Node.os } catch {}
    if ([string]::IsNullOrWhiteSpace($os)) { return $true }
    return ($os -match "(?i)\bwindows\b")
}

function Get-WmtXmlInnerText {
    param($Node, [string]$Name)

    if (-not $Node) { return "" }
    $child = $Node.SelectSingleNode($Name)
    if (-not $child) { return "" }
    return ([string]$child.InnerText).Trim()
}

function Get-WmtCleanerMlEnvMap {
    $documents = [Environment]::GetFolderPath("MyDocuments")
    $music = [Environment]::GetFolderPath("MyMusic")
    $pictures = [Environment]::GetFolderPath("MyPictures")
    $videos = [Environment]::GetFolderPath("MyVideos")
    $programW6432 = if ($env:ProgramW6432) { $env:ProgramW6432 } else { $env:ProgramFiles }
    $commonProgramW6432 = if (${env:CommonProgramW6432}) { ${env:CommonProgramW6432} } else { ${env:CommonProgramFiles} }

    $map = @{
        "AppData"            = $env:APPDATA
        "LocalAppData"       = $env:LOCALAPPDATA
        "LocalAppDataLow"    = (Join-Path $env:USERPROFILE "AppData\LocalLow")
        "CommonAppData"      = $env:ProgramData
        "ProgramFiles"       = $env:ProgramFiles
        "ProgramW6432"       = $programW6432
        "ProgramFiles(x86)"  = ${env:ProgramFiles(x86)}
        "CommonProgramFiles" = ${env:CommonProgramFiles}
        "CommonProgramW6432" = $commonProgramW6432
        "UserProfile"        = $env:USERPROFILE
        "HOME"               = $env:USERPROFILE
        "Documents"          = $documents
        "Music"              = $music
        "Pictures"           = $pictures
        "Video"              = $videos
        "TEMP"               = $env:TEMP
        "TMP"                = $env:TEMP
        "WinDir"             = $env:WINDIR
        "SystemRoot"         = $env:SystemRoot
        "XDG_CACHE_HOME"     = (Join-Path $env:LOCALAPPDATA "cache")
        "XDG_CONFIG_HOME"    = $env:APPDATA
        "XDG_DATA_HOME"      = $env:LOCALAPPDATA
        "LOGNAME"            = $env:USERNAME
        "USERNAME"           = $env:USERNAME
        "cd"                 = (Get-Location).Path
    }

    return $map
}

function Expand-WmtCleanerMlPathVariants {
    param(
        [string]$Path,
        [hashtable]$Variables
    )

    if ([string]::IsNullOrWhiteSpace($Path)) { return @() }

    $paths = @([string]$Path)
    $multiMatches = [regex]::Matches($Path, '\$\$([A-Za-z0-9_\-]+)\$\$')
    foreach ($match in @($multiMatches)) {
        $name = $match.Groups[1].Value
        $token = '$$' + $name + '$$'
        $values = @()
        if ($Variables.ContainsKey($name)) { $values = @($Variables[$name]) }
        $values = @($values | Where-Object { -not [string]::IsNullOrWhiteSpace([string]$_) })
        if ($values.Count -eq 0) { return @() }

        $expanded = @()
        foreach ($pathCandidate in $paths) {
            foreach ($value in $values) {
                $expanded += $pathCandidate.Replace($token, [string]$value)
            }
        }
        $paths = $expanded
    }

    $envMap = Get-WmtCleanerMlEnvMap
    $final = New-Object System.Collections.Generic.List[string]
    foreach ($pathCandidate in $paths) {
        $p = [string]$pathCandidate
        if ($p.StartsWith("~/") -or $p.StartsWith("~\")) {
            $p = Join-Path $env:USERPROFILE $p.Substring(2)
        }
        elseif ($p -eq "~") {
            $p = $env:USERPROFILE
        }

        foreach ($key in $envMap.Keys) {
            $value = [string]$envMap[$key]
            if ([string]::IsNullOrWhiteSpace($value)) { continue }
            $escapedKey = [regex]::Escape([string]$key)
            $escapedValue = $value.Replace('$', '$$')
            $p = [regex]::Replace($p, '%' + $escapedKey + '%', $escapedValue, [System.Text.RegularExpressions.RegexOptions]::IgnoreCase)
            $p = [regex]::Replace($p, '\$\{' + $escapedKey + '\}', $escapedValue, [System.Text.RegularExpressions.RegexOptions]::IgnoreCase)
            $p = [regex]::Replace($p, '\$' + $escapedKey + '\$', $escapedValue, [System.Text.RegularExpressions.RegexOptions]::IgnoreCase)
            $p = [regex]::Replace($p, '\$' + $escapedKey + '\b', $escapedValue, [System.Text.RegularExpressions.RegexOptions]::IgnoreCase)
        }

        $p = [Environment]::ExpandEnvironmentVariables($p)
        $p = $p -replace '/', '\'
        if (-not [string]::IsNullOrWhiteSpace($p)) { [void]$final.Add($p) }
    }

    return @($final.ToArray() | Select-Object -Unique)
}

function ConvertTo-WmtRegistryProviderPath {
    param([string]$Path)

    if ([string]::IsNullOrWhiteSpace($Path)) { return "" }

    return $Path -replace "^(?i)HKCU\\?", "Registry::HKEY_CURRENT_USER\" `
        -replace "^(?i)HKLM\\?", "Registry::HKEY_LOCAL_MACHINE\" `
        -replace "^(?i)HKCR\\?", "Registry::HKEY_CLASSES_ROOT\" `
        -replace "^(?i)HKU\\?", "Registry::HKEY_USERS\"
}

function Get-WmtCleanerMlRegistryValue {
    param(
        [string]$Path,
        [string]$Name
    )

    $registryPath = ConvertTo-WmtRegistryProviderPath -Path $Path
    if ([string]::IsNullOrWhiteSpace($registryPath) -or -not (Test-Path -LiteralPath $registryPath)) { return @() }
    if ([string]::IsNullOrWhiteSpace($Name)) { return @($registryPath) }

    try {
        $item = Get-ItemProperty -LiteralPath $registryPath -Name $Name -ErrorAction Stop
        $value = $item.$Name
        if ($null -eq $value) { return @() }
        return @($value)
    }
    catch {
        return @()
    }
}

function Get-WmtCleanerMlWildcardRoot {
    param([string]$Path)

    if ([string]::IsNullOrWhiteSpace($Path)) { return "" }
    $wildcardIndex = $Path.IndexOfAny([char[]]@('*', '?'))
    if ($wildcardIndex -lt 0) { return "" }

    $beforeWildcard = $Path.Substring(0, $wildcardIndex)
    $separatorIndex = $beforeWildcard.LastIndexOfAny([char[]]@('\', '/'))
    if ($separatorIndex -le 0) { return "" }

    return $beforeWildcard.Substring(0, $separatorIndex).TrimEnd('\', '/')
}

function Test-WmtCleanerMlGenericEvidenceRoot {
    param([string]$Path)

    if ([string]::IsNullOrWhiteSpace($Path)) { return $true }

    try { $normalized = [System.IO.Path]::GetFullPath($Path).TrimEnd('\') }
    catch { $normalized = $Path.TrimEnd('\') }

    $genericRoots = @(
        $env:SystemDrive,
        $env:USERPROFILE,
        $env:APPDATA,
        $env:LOCALAPPDATA,
        $env:ProgramData,
        $env:ProgramFiles,
        ${env:ProgramFiles(x86)},
        $env:TEMP,
        $env:WINDIR,
        $env:SystemRoot
    ) | Where-Object { -not [string]::IsNullOrWhiteSpace([string]$_) }

    foreach ($root in $genericRoots) {
        try { $rootPath = [System.IO.Path]::GetFullPath([string]$root).TrimEnd('\') }
        catch { $rootPath = ([string]$root).TrimEnd('\') }
        if ($normalized.Equals($rootPath, [System.StringComparison]::OrdinalIgnoreCase)) { return $true }
    }

    return $false
}

function Test-WmtCleanerMlPathEvidence {
    param(
        [string]$Path,
        [string]$Search = "file"
    )

    if ([string]::IsNullOrWhiteSpace($Path)) { return $false }

    $expandedPath = [Environment]::ExpandEnvironmentVariables($Path) -replace '/', '\'
    if (-not (Test-WmtCleanerMlWindowsPath $expandedPath)) { return $false }

    try {
        if ($expandedPath -match '[\*\?]') {
            if (Test-Path -Path $expandedPath -ErrorAction SilentlyContinue) { return $true }
            $wildcardRoot = Get-WmtCleanerMlWildcardRoot -Path $expandedPath
            if (-not [string]::IsNullOrWhiteSpace($wildcardRoot) -and
                -not (Test-WmtCleanerMlGenericEvidenceRoot -Path $wildcardRoot) -and
                (Test-Path -LiteralPath $wildcardRoot -ErrorAction SilentlyContinue)) {
                return $true
            }
            return $false
        }

        if (Test-Path -LiteralPath $expandedPath -ErrorAction SilentlyContinue) { return $true }

        if ($Search -eq "file") {
            $parent = [System.IO.Path]::GetDirectoryName($expandedPath)
            if (-not [string]::IsNullOrWhiteSpace($parent) -and
                -not (Test-WmtCleanerMlGenericEvidenceRoot -Path $parent) -and
                (Test-Path -LiteralPath $parent -ErrorAction SilentlyContinue)) {
                return $true
            }
        }
    }
    catch {}

    return $false
}

function Test-WmtCleanerMlWindowsPath {
    param([string]$Path)

    if ([string]::IsNullOrWhiteSpace($Path)) { return $false }
    if ($Path -match '^[\\/](bin|boot|dev|etc|home|lib|media|mnt|opt|proc|root|run|sbin|srv|sys|tmp|usr|var)([\\/]|$)') {
        return $false
    }
    return $true
}

function Get-WmtBleachBitCleanerXmlDirectories {
    $dataPath = Get-DataPath
    $dirs = [System.Collections.Generic.List[string]]::new()
    [void]$dirs.Add((Join-Path $dataPath "bleachbit_cleanerml\bleachbit-master\cleaners"))
    [void]$dirs.Add((Join-Path $dataPath "bleachbit-master\bleachbit-master\cleaners"))
    [void]$dirs.Add((Join-Path $dataPath "cleanerml-master\cleanerml-master\release"))
    [void]$dirs.Add((Join-Path $env:APPDATA "BleachBit\cleaners"))
    [void]$dirs.Add((Join-Path $env:ProgramFiles "BleachBit\share\cleaners"))

    if (${env:ProgramFiles(x86)}) {
        [void]$dirs.Add((Join-Path ${env:ProgramFiles(x86)} "BleachBit\share\cleaners"))
    }

    $seen = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
    $existing = [System.Collections.Generic.List[string]]::new()
    foreach ($dir in $dirs) {
        if ([string]::IsNullOrWhiteSpace($dir) -or -not [System.IO.Directory]::Exists($dir)) { continue }
        try { $key = [System.IO.DirectoryInfo]::new($dir).FullName } catch { $key = $dir }
        if ($seen.Add($key)) { [void]$existing.Add($dir) }
    }
    return $existing.ToArray()
}

function Get-WmtBleachBitCleanerXmlFiles {
    $dirs = @(Get-WmtBleachBitCleanerXmlDirectories)
    if ($dirs.Count -eq 0) { return @() }

    $filesByPath = [System.Collections.Generic.SortedDictionary[string, System.IO.FileInfo]]::new([System.StringComparer]::OrdinalIgnoreCase)
    foreach ($dir in $dirs) {
        try {
            foreach ($path in [System.IO.Directory]::EnumerateFiles($dir, "*.xml", [System.IO.SearchOption]::TopDirectoryOnly)) {
                try {
                    $file = [System.IO.FileInfo]::new($path)
                    if (-not $filesByPath.ContainsKey($file.FullName)) { $filesByPath.Add($file.FullName, $file) }
                }
                catch {}
            }
        }
        catch {}
    }

    $files = [System.Collections.Generic.List[object]]::new()
    foreach ($file in $filesByPath.Values) { [void]$files.Add($file) }
    return $files.ToArray()
}

function Get-WmtCleanerMlSourceSignature {
    param($XmlFiles)

    $filesByPath = [System.Collections.Generic.SortedDictionary[string, System.IO.FileInfo]]::new([System.StringComparer]::OrdinalIgnoreCase)
    foreach ($item in @($XmlFiles)) {
        if (-not $item) { continue }
        try {
            $file = if ($item -is [System.IO.FileInfo]) { $item } else { [System.IO.FileInfo]::new([string]$item) }
            if (-not $filesByPath.ContainsKey($file.FullName)) { $filesByPath.Add($file.FullName, $file) }
        }
        catch {}
    }

    $totalLength = [int64]0
    $latestWriteTicks = [int64]0
    $fileMeta = New-Object System.Collections.Generic.List[object]

    foreach ($file in $filesByPath.Values) {
        $length = [int64]$file.Length
        $writeTicks = [int64]$file.LastWriteTimeUtc.Ticks
        $totalLength += $length
        if ($writeTicks -gt $latestWriteTicks) { $latestWriteTicks = $writeTicks }

        [void]$fileMeta.Add([PSCustomObject]@{
                Path              = [string]$file.FullName
                Length            = $length
                LastWriteUtcTicks = $writeTicks
            })
    }

    return [PSCustomObject]@{
        FileCount           = [int]$filesByPath.Count
        TotalLength         = $totalLength
        LatestWriteUtcTicks = $latestWriteTicks
        Files               = @($fileMeta.ToArray())
    }
}

function Test-WmtCleanerMlCacheMetaMatch {
    param(
        $Meta,
        $SourceSignature,
        [int]$CacheVersion
    )

    if (-not $Meta -or -not $SourceSignature) { return $false }

    try {
        if ([int]$Meta.CacheVersion -ne $CacheVersion) { return $false }
        if ([int]$Meta.FileCount -ne [int]$SourceSignature.FileCount) { return $false }
        if ([int64]$Meta.TotalLength -ne [int64]$SourceSignature.TotalLength) { return $false }
        if ([int64]$Meta.LatestWriteUtcTicks -ne [int64]$SourceSignature.LatestWriteUtcTicks) { return $false }

        $metaFiles = @($Meta.Files)
        $sourceFiles = @($SourceSignature.Files)
        if ($metaFiles.Count -ne $sourceFiles.Count) { return $false }

        for ($i = 0; $i -lt $sourceFiles.Count; $i++) {
            if ([string]$metaFiles[$i].Path -ne [string]$sourceFiles[$i].Path) { return $false }
            if ([int64]$metaFiles[$i].Length -ne [int64]$sourceFiles[$i].Length) { return $false }
            if ([int64]$metaFiles[$i].LastWriteUtcTicks -ne [int64]$sourceFiles[$i].LastWriteUtcTicks) { return $false }
        }

        return $true
    }
    catch {
        return $false
    }
}

function Update-WmtBleachBitCleanerMlFiles {
    $dataPath = Get-DataPath
    $targetRoot = Join-Path $dataPath "bleachbit_cleanerml"
    $zipPath = Join-Path $targetRoot "bleachbit-master.zip"
    $extractRoot = Join-Path $targetRoot "bleachbit-master"

    try {
        [System.IO.Directory]::CreateDirectory($targetRoot) | Out-Null
        [Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12
        $url = "https://codeload.github.com/bleachbit/bleachbit/zip/refs/heads/master"
        $wc = New-Object System.Net.WebClient
        $wc.DownloadFile($url, $zipPath)
        $wc.Dispose()

        if (Test-Path -LiteralPath $extractRoot) {
            Remove-Item -LiteralPath $extractRoot -Recurse -Force -ErrorAction SilentlyContinue
        }
        [System.IO.Directory]::CreateDirectory($extractRoot) | Out-Null
        Add-Type -AssemblyName System.IO.Compression.FileSystem
        [System.IO.Compression.ZipFile]::ExtractToDirectory($zipPath, $extractRoot)

        $nested = Get-ChildItem -LiteralPath $extractRoot -Directory -Filter "bleachbit-*" -ErrorAction SilentlyContinue | Select-Object -First 1
        if ($nested -and (Test-Path -LiteralPath (Join-Path $nested.FullName "cleaners"))) {
            $finalRoot = Join-Path $targetRoot "bleachbit-master-normalized"
            if (Test-Path -LiteralPath $finalRoot) {
                Remove-Item -LiteralPath $finalRoot -Recurse -Force -ErrorAction SilentlyContinue
            }
            Move-Item -LiteralPath $nested.FullName -Destination $finalRoot -Force
            Remove-Item -LiteralPath $extractRoot -Recurse -Force -ErrorAction SilentlyContinue
            Rename-Item -LiteralPath $finalRoot -NewName "bleachbit-master" -Force
        }
    }
    catch {
        Write-GuiLog "CleanerML download warning: $($_.Exception.Message)"
    }
}

function Get-WmtCleanerMlSection {
    param([string]$CleanerName)

    if ($CleanerName -match "(?i)\b(Chrome|Chromium|Edge|Firefox|Brave|Opera|Internet Explorer|SeaMonkey|Waterfox|LibreWolf|Vivaldi|Zen)\b") { return "Browsers / Internet" }
    if ($CleanerName -match "(?i)\b(Discord|Pidgin|Skype|Telegram|Signal|HexChat|Thunderbird|FileZilla)\b") { return "Internet & Chat" }
    if ($CleanerName -match "(?i)\b(Office|LibreOffice|Adobe|GIMP|Paint|Audacity|HandBrake|VLC|Java|Claude)\b") { return "Productivity" }
    if ($CleanerName -match "(?i)\b(Deep scan|System|Windows|Explorer|Thumbnails|Localizations)\b") { return "System" }
    if ($CleanerName -match "(?i)\b(Game|Steam|Minecraft|Roblox|Nexuiz|Warzone|Poker)\b") { return "Games" }
    return "Applications"
}

function ConvertFrom-WmtCleanerMlFile {
    param([string]$Path)

    try { [xml]$xml = Get-Content -LiteralPath $Path -Raw -ErrorAction Stop }
    catch { return @() }

    $cleaner = $xml.cleaner
    if (-not $cleaner -or -not (Test-WmtCleanerMlOs $cleaner)) { return @() }

    $cleanerId = if ($cleaner.id) { [string]$cleaner.id } else { [System.IO.Path]::GetFileNameWithoutExtension($Path) }
    $cleanerName = Get-WmtXmlInnerText -Node $cleaner -Name "label"
    if ([string]::IsNullOrWhiteSpace($cleanerName)) { $cleanerName = $cleanerId -replace '[_\-]+', ' ' }
    $cleanerDesc = Get-WmtXmlInnerText -Node $cleaner -Name "description"

    $envMapForVars = Get-WmtCleanerMlEnvMap
    $variables = @{}
    $variables["ProgramFiles"] = @($envMapForVars["ProgramFiles"], $envMapForVars["ProgramW6432"]) |
    Where-Object { -not [string]::IsNullOrWhiteSpace([string]$_) } |
    Select-Object -Unique
    $variables["CommonProgramFiles"] = @($envMapForVars["CommonProgramFiles"], $envMapForVars["CommonProgramW6432"]) |
    Where-Object { -not [string]::IsNullOrWhiteSpace([string]$_) } |
    Select-Object -Unique
    foreach ($var in @($cleaner.var)) {
        if (-not $var.name) { continue }
        $values = New-Object System.Collections.Generic.List[string]
        foreach ($valueNode in @($var.value)) {
            if (-not (Test-WmtCleanerMlOs $valueNode)) { continue }
            $searchType = if ($valueNode.search) { [string]$valueNode.search } else { "" }
            $expandedValues = @()

            if ($searchType -eq "winreg") {
                foreach ($registryValue in @(Get-WmtCleanerMlRegistryValue -Path ([string]$valueNode.path) -Name ([string]$valueNode.name))) {
                    $expandedValues += [string]$registryValue
                }
            }
            else {
                $expandedValues = @(Expand-WmtCleanerMlPathVariants -Path ([string]$valueNode.InnerText) -Variables $variables)
                if ($searchType -eq "glob") {
                    $globbedValues = New-Object System.Collections.Generic.List[string]
                    foreach ($expandedValue in $expandedValues) {
                        foreach ($match in @(Get-ChildItem -Path $expandedValue -Force -ErrorAction SilentlyContinue)) {
                            [void]$globbedValues.Add($match.FullName)
                        }
                    }
                    $expandedValues = @($globbedValues.ToArray())
                }
            }

            foreach ($expandedValue in $expandedValues) {
                if ((Test-WmtCleanerMlWindowsPath $expandedValue) -and (Test-WmtCleanerMlPathEvidence -Path $expandedValue -Search "file")) {
                    [void]$values.Add($expandedValue)
                }
            }
        }
        if ($values.Count -gt 0) { $variables[[string]$var.name] = @($values.ToArray() | Select-Object -Unique) }
    }

    $rules = New-Object System.Collections.Generic.List[object]
    foreach ($option in @($cleaner.option)) {
        if (-not (Test-WmtCleanerMlOs $option)) { continue }

        $optionId = if ($option.id) { [string]$option.id } else { "option" }
        $optionName = Get-WmtXmlInnerText -Node $option -Name "label"
        if ([string]::IsNullOrWhiteSpace($optionName)) { $optionName = $optionId -replace '[_\-]+', ' ' }
        $optionDesc = Get-WmtXmlInnerText -Node $option -Name "description"
        $optionWarning = Get-WmtXmlInnerText -Node $option -Name "warning"
        $paths = New-Object System.Collections.Generic.List[object]

        foreach ($action in @($option.action)) {
            if ([string]$action.command -ne "delete") { continue }
            if (-not (Test-WmtCleanerMlOs $action)) { continue }

            $search = if ($action.search) { [string]$action.search } else { "file" }
            if ($search -notin @("file", "glob", "walk.files", "walk.all", "walk.top", "deep")) { continue }

            $rawPath = if ($action.path) { [string]$action.path } elseif ($search -eq "deep") { "%UserProfile%" } else { "" }
            foreach ($expandedPath in (Expand-WmtCleanerMlPathVariants -Path $rawPath -Variables $variables)) {
                if (-not (Test-WmtCleanerMlWindowsPath $expandedPath)) { continue }
                [void]$paths.Add([PSCustomObject]@{
                        Path        = $expandedPath
                        Search      = $search
                        Regex       = if ($action.regex) { [string]$action.regex } else { "" }
                        WholeRegex  = if ($action.wholeregex) { [string]$action.wholeregex } else { "" }
                        NRegex      = if ($action.nregex) { [string]$action.nregex } else { "" }
                        NWholeRegex = if ($action.nwholeregex) { [string]$action.nwholeregex } else { "" }
                        Type        = if ($action.type) { [string]$action.type } elseif ($search -eq "file") { "f" } else { "" }
                    })
            }
        }

        $hasCleanerMlEvidence = $false
        foreach ($pathRule in @($paths.ToArray())) {
            if (Test-WmtCleanerMlPathEvidence -Path ([string]$pathRule.Path) -Search ([string]$pathRule.Search)) {
                $hasCleanerMlEvidence = $true
                break
            }
        }

        if ($paths.Count -gt 0 -and $hasCleanerMlEvidence) {
            $safeId = ("CleanerML_{0}_{1}" -f $cleanerId, $optionId) -replace '[^a-zA-Z0-9_]', ''
            [void]$rules.Add([PSCustomObject]@{
                    Name        = "$cleanerName - $optionName"
                    ID          = $safeId
                    Section     = Get-WmtCleanerMlSection -CleanerName $cleanerName
                    AppGroup    = $cleanerName
                    Paths       = @($paths.ToArray())
                    Desc        = (@($cleanerDesc, $optionDesc, $optionWarning) | Where-Object { -not [string]::IsNullOrWhiteSpace($_) }) -join " "
                    IsInternal  = $false
                    IsCleanerML = $true
                    Source      = "CleanerML"
                })
        }
    }

    return $rules.ToArray()
}

function Get-BleachBitCleanerMlRules {
    param([switch]$Download)

    $dataPath = Get-DataPath
    $cachePath = Join-Path $dataPath "cleanerml_cache.json"
    $cacheMetaPath = Join-Path $dataPath "cleanerml_cache.meta.json"
    $cacheVersion = 2

    if ($Download) { Update-WmtBleachBitCleanerMlFiles }
    if (-not $script:CleanerMlRulesMemoryCache) { $script:CleanerMlRulesMemoryCache = @{} }

    $xmlFiles = @(Get-WmtBleachBitCleanerXmlFiles)
    $sourceSignature = Get-WmtCleanerMlSourceSignature -XmlFiles $xmlFiles
    $memoryKey = if ($sourceSignature.FileCount -gt 0) {
        "{0}|{1}|{2}|{3}" -f $cacheVersion, [int]$sourceSignature.FileCount, [int64]$sourceSignature.TotalLength, [int64]$sourceSignature.LatestWriteUtcTicks
    }
    elseif (Test-Path $cachePath) {
        $cacheInfo = Get-Item -LiteralPath $cachePath -ErrorAction SilentlyContinue
        if ($cacheInfo) { "cache-only|{0}|{1}" -f [int64]$cacheInfo.Length, $cacheInfo.LastWriteTimeUtc.Ticks } else { "" }
    }
    else { "" }

    if (-not $Download -and $memoryKey -and $script:CleanerMlRulesMemoryCache.ContainsKey($memoryKey)) {
        return $script:CleanerMlRulesMemoryCache[$memoryKey]
    }

    $forceRebuild = $false
    if (Test-Path $cachePath) {
        try {
            if ($sourceSignature.FileCount -gt 0) {
                $cacheInfo = Get-Item -LiteralPath $cachePath -ErrorAction Stop
                $meta = $null
                if (Test-Path $cacheMetaPath) {
                    $meta = Get-Content -LiteralPath $cacheMetaPath -Raw -ErrorAction Stop | ConvertFrom-Json
                }

                if ($meta) {
                    if (-not (Test-WmtCleanerMlCacheMetaMatch -Meta $meta -SourceSignature $sourceSignature -CacheVersion $cacheVersion)) {
                        $forceRebuild = $true
                    }
                }
                elseif ($sourceSignature.LatestWriteUtcTicks -gt $cacheInfo.LastWriteTimeUtc.Ticks) {
                    $forceRebuild = $true
                }
            }
            elseif (Test-Path $cacheMetaPath) {
                $meta = Get-Content -LiteralPath $cacheMetaPath -Raw -ErrorAction Stop | ConvertFrom-Json
                if ([int]$meta.CacheVersion -ne $cacheVersion) { $forceRebuild = $true }
            }
        }
        catch {
            $forceRebuild = ($sourceSignature.FileCount -gt 0)
        }
    }

    if (-not $forceRebuild -and (Test-Path $cachePath)) {
        try {
            $cachedRules = @(Get-Content -LiteralPath $cachePath -Raw -ErrorAction Stop | ConvertFrom-Json)
            if ($cachedRules.Count -gt 0) {
                if (($sourceSignature.FileCount -gt 0) -and -not (Test-Path $cacheMetaPath)) {
                    try {
                        [PSCustomObject]@{
                            CacheVersion        = $cacheVersion
                            FileCount           = [int]$sourceSignature.FileCount
                            TotalLength         = [int64]$sourceSignature.TotalLength
                            LatestWriteUtcTicks = [int64]$sourceSignature.LatestWriteUtcTicks
                            Files               = @($sourceSignature.Files)
                        } | ConvertTo-Json -Depth 5 | Set-Content -LiteralPath $cacheMetaPath -Force
                    }
                    catch {}
                }
                if ($memoryKey) { $script:CleanerMlRulesMemoryCache[$memoryKey] = $cachedRules }
                return $cachedRules
            }
        }
        catch {}
    }

    if ($xmlFiles.Count -eq 0) { return @() }

    $allRules = New-Object System.Collections.Generic.List[object]
    foreach ($file in $xmlFiles) {
        foreach ($rule in @(ConvertFrom-WmtCleanerMlFile -Path $file.FullName)) {
            [void]$allRules.Add($rule)
        }
    }

    $final = @($allRules.ToArray() | Group-Object ID | ForEach-Object { $_.Group[0] } | Sort-Object Section, AppGroup, Name)

    try {
        $final | ConvertTo-Json -Depth 7 | Set-Content -LiteralPath $cachePath -Force
        [PSCustomObject]@{
            CacheVersion        = $cacheVersion
            FileCount           = [int]$sourceSignature.FileCount
            TotalLength         = [int64]$sourceSignature.TotalLength
            LatestWriteUtcTicks = [int64]$sourceSignature.LatestWriteUtcTicks
            Files               = @($sourceSignature.Files)
        } | ConvertTo-Json -Depth 5 | Set-Content -LiteralPath $cacheMetaPath -Force
        $memoryKey = "{0}|{1}|{2}|{3}" -f $cacheVersion, [int]$sourceSignature.FileCount, [int64]$sourceSignature.TotalLength, [int64]$sourceSignature.LatestWriteUtcTicks
    }
    catch {}

    if ($memoryKey) { $script:CleanerMlRulesMemoryCache[$memoryKey] = $final }
    return $final
}

function Get-Winapp2Rules {
    param([switch]$Download)

    $dataPath = Get-DataPath
    $iniPath = Join-Path $dataPath "winapp2.ini"
    $cachePath = Join-Path $dataPath "winapp2_cache.json" 
    $cacheMetaPath = Join-Path $dataPath "winapp2_cache.meta.json"
    $cacheVersion = 2
    if (-not $script:Winapp2RulesMemoryCache) { $script:Winapp2RulesMemoryCache = @{} }
    $iniInfoForCache = $null
    if (Test-Path $iniPath) {
        try { $iniInfoForCache = Get-Item -LiteralPath $iniPath -ErrorAction Stop } catch {}
    }
    $memoryKey = if ($iniInfoForCache) {
        "{0}|{1}|{2}" -f $cacheVersion, [int64]$iniInfoForCache.Length, $iniInfoForCache.LastWriteTimeUtc.Ticks
    }
    elseif (Test-Path $cachePath) {
        $cacheInfo = Get-Item -LiteralPath $cachePath -ErrorAction SilentlyContinue
        if ($cacheInfo) { "cache-only|{0}|{1}" -f [int64]$cacheInfo.Length, $cacheInfo.LastWriteTimeUtc.Ticks } else { "" }
    }
    else { "" }

    if (-not $Download -and $memoryKey -and $script:Winapp2RulesMemoryCache.ContainsKey($memoryKey)) {
        return $script:Winapp2RulesMemoryCache[$memoryKey]
    }

    # --- 1. SMART CACHE CHECK ---
    $forceRebuild = $false

    if (Test-Path $cachePath) {
        try {
            if (Test-Path $iniPath) {
                $iniInfo = Get-Item -LiteralPath $iniPath -ErrorAction Stop
                $cacheInfo = Get-Item -LiteralPath $cachePath -ErrorAction Stop
                $meta = $null
                if (Test-Path $cacheMetaPath) {
                    $meta = Get-Content -LiteralPath $cacheMetaPath -Raw -ErrorAction Stop | ConvertFrom-Json
                }

                if ($meta) {
                    if ([int]$meta.CacheVersion -ne $cacheVersion -or
                        [int64]$meta.IniLength -ne [int64]$iniInfo.Length -or
                        [datetime]$meta.IniLastWriteUtc -ne $iniInfo.LastWriteTimeUtc) {
                        $forceRebuild = $true
                    }
                }
                elseif ($iniInfo.LastWriteTimeUtc -gt $cacheInfo.LastWriteTimeUtc) {
                    $forceRebuild = $true
                }
            }
        }
        catch {
            if (-not (Test-Path $iniPath)) {
                $forceRebuild = $false
            }
            else {
                $forceRebuild = $true
            }
        }
    }

    # --- 2. DOWNLOAD ---
    if ($Download) {
        try {
            [Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12
            Add-Type -AssemblyName System.Net.Http
            $client = New-Object System.Net.Http.HttpClient
            $client.Timeout = [TimeSpan]::FromSeconds(15)
            
            $url = "https://cdn.jsdelivr.net/gh/MoscaDotTo/Winapp2@master/Winapp2.ini"
            $response = $client.GetAsync($url).Result
            if ($response.IsSuccessStatusCode) {
                $contentBytes = $response.Content.ReadAsByteArrayAsync().Result
                $iniContent = [System.Text.Encoding]::UTF8.GetString($contentBytes)
                [System.IO.File]::WriteAllText($iniPath, $iniContent)
                $forceRebuild = $true
            }
            $client.Dispose()
        }
        catch { Write-GuiLog "Download Warning: $($_.Exception.Message)" }
    }

    # --- 3. CACHE LOAD ---
    if (-not $forceRebuild -and (Test-Path $cachePath)) {
        try { 
            $cachedRules = Get-Content -LiteralPath $cachePath -Raw | ConvertFrom-Json
            if ($cachedRules.Count -gt 5) {
                if ((Test-Path $iniPath) -and -not (Test-Path $cacheMetaPath)) {
                    try {
                        $iniInfo = Get-Item -LiteralPath $iniPath -ErrorAction Stop
                        [PSCustomObject]@{
                            CacheVersion    = $cacheVersion
                            IniLength       = [int64]$iniInfo.Length
                            IniLastWriteUtc = $iniInfo.LastWriteTimeUtc
                        } | ConvertTo-Json -Depth 3 | Set-Content -LiteralPath $cacheMetaPath -Force
                    }
                    catch {}
                }
                if ($memoryKey) { $script:Winapp2RulesMemoryCache[$memoryKey] = $cachedRules }
                return $cachedRules
            }
        }
        catch {}
    }

    # --- 4. PARSE INI ---
    $iniContent = $null
    if (Test-Path $iniPath) { $iniContent = Get-Content $iniPath -Raw }
    if ([string]::IsNullOrWhiteSpace($iniContent)) { return @() }

    $rules = New-Object System.Collections.Generic.List[Object]
    
    $envVars = @{ 
        "%Documents%"         = [Environment]::GetFolderPath("MyDocuments")
        "%ProgramFiles%"      = $env:ProgramFiles
        "%ProgramFiles(x86)%" = ${env:ProgramFiles(x86)}
        "%SystemDrive%"       = $env:SystemDrive
        "%AppData%"           = $env:APPDATA
        "%LocalAppData%"      = $env:LOCALAPPDATA
        "%CommonAppData%"     = $env:ProgramData
        "%UserProfile%"       = $env:USERPROFILE
    }
    $dirCache = @{} 

    $lines = $iniContent -split "\r?\n"
    $currentApp = $null; $skipApp = $false; $hasDetect = $false

    foreach ($line in $lines) {
        if ([string]::IsNullOrWhiteSpace($line) -or $line[0] -eq ';') { continue }

        if ($line[0] -eq '[') {
            if ($currentApp -and -not $skipApp) { $rules.Add([PSCustomObject]$currentApp) }
            $appName = $line.Trim(" []")
            $currentApp = [ordered]@{ 
                Name       = $appName
                ID         = "Winapp2_" + ($appName -replace '[^a-zA-Z0-9]', '')
                Section    = "Applications"
                AppGroup   = "General"
                Paths      = New-Object System.Collections.Generic.List[Object]
                Desc       = ""
                IsInternal = $false
            }
            $skipApp = $false; $hasDetect = $false
            continue
        }

        $eqIndex = $line.IndexOf('=')
        if ($eqIndex -le 0) { continue }
        if ($skipApp) { continue }

        $key = $line.Substring(0, $eqIndex).Trim()
        $val = $line.Substring($eqIndex + 1).Trim()

        if ($key -eq "Section") { $currentApp.Section = $val }
        elseif ($key.StartsWith("Detect")) {
            if (-not $hasDetect) { $hasDetect = $true; $skipApp = $true } 
            
            if ($val.IndexOf('%') -ge 0) { 
                foreach ($k in $envVars.Keys) { 
                    if ($val.Contains($k)) { $val = $val.Replace($k, $envVars[$k]) } 
                } 
            }

            # Registry Detection
            if ($val -match "^HK") {
                $regPath = $val -replace "^(?i)HKCU", "Registry::HKEY_CURRENT_USER" `
                    -replace "^(?i)HKLM", "Registry::HKEY_LOCAL_MACHINE" `
                    -replace "^(?i)HKCR", "Registry::HKEY_CLASSES_ROOT" `
                    -replace "^(?i)HKU", "Registry::HKEY_USERS"
                if (Test-Path $regPath) { $skipApp = $false }
            } 
            # File Detection
            else {
                try {
                    $parent = [System.IO.Path]::GetDirectoryName($val)
                    if (-not [string]::IsNullOrWhiteSpace($parent)) {
                        if (-not $dirCache.ContainsKey($parent)) { $dirCache[$parent] = (Test-Path $parent) }
                        if ($dirCache[$parent]) { 
                            if (Test-Path $val) { $skipApp = $false } 
                        }
                    }
                }
                catch { 
                    if (Test-Path $val) { $skipApp = $false } 
                }
            }
        }
        elseif ($key.StartsWith("FileKey")) {
            $parts = $val -split "\|"
            if ($parts.Count -ge 2) {
                $rawPath = $parts[0]
                if ($rawPath.IndexOf('%') -ge 0) { foreach ($k in $envVars.Keys) { if ($rawPath.Contains($k)) { $rawPath = $rawPath.Replace($k, $envVars[$k]) } } }
                $rawPath = [Environment]::ExpandEnvironmentVariables($rawPath)
                if (-not $skipApp) { $currentApp.Paths.Add(@{ Path = $rawPath; Pattern = $parts[1]; Options = if ($parts.Count -gt 2) { $parts[2] } else { "" } }) }
            }
        }
        elseif ($key -eq "Description") { $currentApp.Desc = $val }
    }
    if ($currentApp -and -not $skipApp) { $rules.Add([PSCustomObject]$currentApp) }

    # --- 5. CATEGORIZATION ---
    $finalList = $rules | Where-Object { $_.Paths.Count -gt 0 }
    
    foreach ($app in $finalList) {
        $name = $app.Name

        # 1. BROWSERS
        if ($name -match "^Google Chrome") { $app.AppGroup = "Google Chrome"; $app.Section = "Browsers / Internet"; $app.Name = $name -replace "Google Chrome\s*", "" }
        elseif ($name -match "^Microsoft Edge") { $app.AppGroup = "Microsoft Edge"; $app.Section = "Browsers / Internet"; $app.Name = $name -replace "Microsoft Edge\s*", "" }
        elseif ($name -match "^Mozilla Firefox") { $app.AppGroup = "Mozilla Firefox"; $app.Section = "Browsers / Internet"; $app.Name = $name -replace "Mozilla Firefox\s*", "" }
        elseif ($name -match "^Opera") { $app.AppGroup = "Opera"; $app.Section = "Browsers / Internet" }
        elseif ($name -match "^Brave") { $app.AppGroup = "Brave"; $app.Section = "Browsers / Internet" }

        # 2. SPECIFIC PRODUCTIVITY
        elseif ($name -match "PowerToys") { 
            $app.Section = "Productivity"
            $app.AppGroup = "Microsoft PowerToys"
            $app.Name = $name -replace "^Microsoft\s*PowerToys\s*", "" 
        }
        elseif ($name -match "^Microsoft\sOffice|^Office\s") { $app.Section = "Productivity"; $app.AppGroup = "Microsoft Office" }
        elseif ($name -match "^Adobe\s") { $app.Section = "Productivity"; $app.AppGroup = "Adobe"; $app.Name = $name -replace "^Adobe\s+", "" }
        
        # 3. GAMES (New Category)
        elseif ($name -match "(?i)\b(Steam|Epic Games|Origin|Uplay|Ubisoft Connect|Battle.net|GOG Galaxy)\b") {
            $app.Section = "Games"
            $app.AppGroup = $name -split " " | Select-Object -First 1
        }

        # 4. CHAT APPS
        elseif ($name -match "(?i)\b(Discord|Spotify|Skype|TeamViewer|Zoom|Slack|Telegram|WhatsApp)\b") { 
            $app.Section = "Internet & Chat"
            $app.AppGroup = $name -split " " | Select-Object -First 1 
        }

        # 5. SYSTEM CATCH-ALL
        elseif ($name -match "^Windows\s" -or $name -eq "Windows" -or $name -match "Defender|Explorer|Store|Management Console") {
            $app.Section = "System"
            $app.AppGroup = "Windows"
            $app.Name = $name -replace "^Windows\s+", "" 
        }
    }

    try {
        $finalList | ConvertTo-Json -Depth 5 | Set-Content -LiteralPath $cachePath -Force
        if (Test-Path $iniPath) {
            $iniInfo = Get-Item -LiteralPath $iniPath -ErrorAction Stop
            [PSCustomObject]@{
                CacheVersion    = $cacheVersion
                IniLength       = [int64]$iniInfo.Length
                IniLastWriteUtc = $iniInfo.LastWriteTimeUtc
            } | ConvertTo-Json -Depth 3 | Set-Content -LiteralPath $cacheMetaPath -Force
            $memoryKey = "{0}|{1}|{2}" -f $cacheVersion, [int64]$iniInfo.Length, $iniInfo.LastWriteTimeUtc.Ticks
        }
    }
    catch {}

    if ($memoryKey) { $script:Winapp2RulesMemoryCache[$memoryKey] = $finalList }
    
    return $finalList
}
    
function Show-AdvancedCleanupSelection {
    Show-WmtAdvancedCleanupSelectionWpf
}


function Show-WmtAdvancedCleanupSelectionWpf {
    $currentSettings = Get-WmtSettings
    $savedStates = $currentSettings.TempCleanup
    $isWinapp2Enabled = [bool]$currentSettings.LoadWinapp2
    $isCleanerMlEnabled = [bool]$currentSettings.LoadCleanerML

    [xml]$cleanupSelectionXaml = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="Advanced Cleanup Selection" Width="720" Height="820" MinWidth="620" MinHeight="540"
        WindowStartupLocation="CenterOwner" Background="{DynamicResource BgDark}" Foreground="{DynamicResource TextPrimary}"
        FontFamily="Segoe UI Variable Display, Segoe UI, Arial" FontSize="13">
    <Grid>
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="*"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>

        <Border Grid.Row="0" Background="{DynamicResource BgPanel}" BorderBrush="{DynamicResource BorderBrush}" BorderThickness="0,0,0,1" Padding="16,12">
            <Grid>
                <Grid.ColumnDefinitions>
                    <ColumnDefinition Width="Auto"/>
                    <ColumnDefinition Width="*"/>
                    <ColumnDefinition Width="260"/>
                </Grid.ColumnDefinitions>
                <StackPanel>
                    <CheckBox Name="chkToggleWinapp2" Content="Winapp2.ini rules" FontWeight="SemiBold" Margin="0,0,0,8"/>
                    <CheckBox Name="chkToggleCleanerML" Content="BleachBit CleanerML" FontWeight="SemiBold"/>
                </StackPanel>
                <TextBlock Name="lblStatus" Grid.Column="1" Margin="18,0" VerticalAlignment="Center" Foreground="{DynamicResource Warning}"/>
                <StackPanel Grid.Column="2">
                    <TextBlock Text="Search" Foreground="{DynamicResource TextSecondary}" Margin="0,0,0,4"/>
                    <TextBox Name="txtSearch" Height="34" VerticalContentAlignment="Center"/>
                </StackPanel>
            </Grid>
        </Border>

        <ScrollViewer Grid.Row="1" VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Disabled" Padding="16,12">
            <StackPanel Name="pnlRules"/>
        </ScrollViewer>

        <Border Grid.Row="2" Background="{DynamicResource BgPanel}" BorderBrush="{DynamicResource BorderBrush}" BorderThickness="0,1,0,0" Padding="16,12">
            <Grid>
                <Button Name="btnEventLogs" Content="Clear Event Logs" Width="132" HorizontalAlignment="Left" Background="{DynamicResource Warning}" Foreground="{DynamicResource WarningText}"/>
                <StackPanel Orientation="Horizontal" HorizontalAlignment="Right">
                    <Button Name="btnCancel" Content="Cancel" Width="94" IsCancel="True" Margin="0,0,8,0"/>
                    <Button Name="btnAnalyze" Content="Analyze" Width="104" Background="{DynamicResource Accent}" Foreground="{DynamicResource AccentText}" Margin="0,0,8,0"/>
                    <Button Name="btnClean" Content="Clean Selected" Width="128" Background="{DynamicResource Success}" Foreground="{DynamicResource SuccessText}" IsDefault="True"/>
                </StackPanel>
            </Grid>
        </Border>
    </Grid>
</Window>
'@

    try {
        $dialog = New-WmtWindowFromFullXaml -Xaml $cleanupSelectionXaml
        $workArea = [System.Windows.SystemParameters]::WorkArea
        $dialog.Width = [Math]::Min(720, [Math]::Max(620, $workArea.Width - 80))
        $dialog.Height = [Math]::Min(820, [Math]::Max(540, $workArea.Height - 80))
    }
    catch {
        Write-GuiLog "Failed to open WPF cleanup selection: $($_.Exception.Message)"
        return $null
    }

    $chkToggleWinapp2 = $dialog.FindName("chkToggleWinapp2")
    $chkToggleCleanerML = $dialog.FindName("chkToggleCleanerML")
    $txtSearch = $dialog.FindName("txtSearch")
    $lblStatus = $dialog.FindName("lblStatus")
    $pnlRules = $dialog.FindName("pnlRules")
    $btnClean = $dialog.FindName("btnClean")
    $btnAnalyze = $dialog.FindName("btnAnalyze")
    $btnCancel = $dialog.FindName("btnCancel")
    $btnEventLogs = $dialog.FindName("btnEventLogs")

    $chkToggleWinapp2.IsChecked = $isWinapp2Enabled
    $chkToggleCleanerML.IsChecked = $isCleanerMlEnabled

    $internalRules = @(
        [PSCustomObject]@{ Section = "System"; AppGroup = "Windows"; Name = "Temporary Files"; Key = "TempFiles"; Desc = "User and System Temp"; IsInternal = $true }
        [PSCustomObject]@{ Section = "System"; AppGroup = "Windows"; Name = "Recycle Bin"; Key = "RecycleBin"; Desc = "Empties Recycle Bin"; IsInternal = $true }
        [PSCustomObject]@{ Section = "System"; AppGroup = "Windows"; Name = "Error Logs (WER)"; Key = "WER"; Desc = "Crash dumps"; IsInternal = $true }
        [PSCustomObject]@{ Section = "System"; AppGroup = "Windows"; Name = "DNS Cache"; Key = "DNS"; Desc = "Network cache"; IsInternal = $true }
        [PSCustomObject]@{ Section = "System"; AppGroup = "Explorer"; Name = "Thumbnail / Thumbs Cache"; Key = "Thumbnails"; Desc = "Explorer thumbcache_*.db thumbnail cache"; IsInternal = $true }
        [PSCustomObject]@{ Section = "System"; AppGroup = "Explorer"; Name = "Deep Scan: Thumbs.db"; Key = "ThumbsDb"; Desc = "Finds scattered Thumbs.db files under your user profile. Can be slow."; IsInternal = $true; DefaultChecked = $false }
        [PSCustomObject]@{ Section = "System"; AppGroup = "Explorer"; Name = "Recent Items"; Key = "Recent"; Desc = "Recent files list"; IsInternal = $true }
        [PSCustomObject]@{ Section = "System"; AppGroup = "Explorer"; Name = "Run History"; Key = "RunMRU"; Desc = "Run dialog history"; IsInternal = $true }
        [PSCustomObject]@{ Section = "Browsers / Internet"; AppGroup = "Google Chrome"; Name = "Cache (Internal)"; Key = "Chrome"; Desc = "Standard Cache"; IsInternal = $true }
        [PSCustomObject]@{ Section = "Browsers / Internet"; AppGroup = "Microsoft Edge"; Name = "Cache (Internal)"; Key = "Edge"; Desc = "Standard Cache"; IsInternal = $true }
        [PSCustomObject]@{ Section = "Browsers / Internet"; AppGroup = "Mozilla Firefox"; Name = "Cache (Internal)"; Key = "Firefox"; Desc = "Standard Cache"; IsInternal = $true }
        [PSCustomObject]@{ Section = "Browsers / Internet"; AppGroup = "Brave"; Name = "Cache (Internal)"; Key = "Brave"; Desc = "Standard Cache"; IsInternal = $true }
        [PSCustomObject]@{ Section = "Browsers / Internet"; AppGroup = "Opera"; Name = "Cache (Internal)"; Key = "Opera"; Desc = "Standard Cache"; IsInternal = $true }
    )

    $cleanupCheckboxes = [ordered]@{}
    $checkboxSearchText = @{}
    $sectionEntries = [System.Collections.Generic.List[object]]::new()

    $sectionOrder = @{
        "System"              = 0
        "Browsers / Internet" = 1
        "Productivity"        = 2
        "Internet & Chat"     = 3
        "Games"               = 4
        "Applications"        = 5
    }

    $preferredGroupOrder = @{
        "System|Windows"                      = 0
        "System|Explorer"                     = 1
        "System|Windows Update"               = 2
        "System|Windows Logs"                 = 3
        "Browsers / Internet|Google Chrome"   = 0
        "Browsers / Internet|Microsoft Edge"  = 1
        "Browsers / Internet|Mozilla Firefox" = 2
        "Browsers / Internet|Brave"           = 3
        "Browsers / Internet|Opera"           = 4
        "Productivity|Microsoft Office"       = 0
        "Productivity|Microsoft Outlook"      = 1
        "Productivity|Microsoft PowerToys"    = 2
        "Productivity|Adobe"                  = 3
        "Internet & Chat|Discord"             = 0
        "Internet & Chat|Spotify"             = 1
        "Games|Steam"                         = 0
        "Games|Epic Games"                    = 1
        "Games|Xbox"                          = 2
    }

    $normalizeCleanerName = {
        param($Text)
        $name = ([string]$Text).Trim().Trim(" *")
        $name = $name -replace "\s+", " "
        if ($name -eq ".Thumbnails") { return "Thumbnail / Thumbs Cache" }
        return $name
    }.GetNewClosure()

    $getCleanerDisplayGroup = {
        param($item)
        $rawGroup = ([string]$item.AppGroup).Trim()
        $name = & $normalizeCleanerName $item.Name
        if ([bool]$item.IsInternal) {
            if (-not [string]::IsNullOrWhiteSpace($rawGroup)) { return $rawGroup }
            return "Windows"
        }
        switch -Regex ($name) {
            "^(Google Chrome|Chrome)\b" { return "Google Chrome" }
            "^(Microsoft Edge|Edge)\b" { return "Microsoft Edge" }
            "^(Mozilla Firefox|Firefox)\b" { return "Mozilla Firefox" }
            "^Brave\b" { return "Brave" }
            "^Opera\b" { return "Opera" }
            "^SeaMonkey\b" { return "SeaMonkey" }
            "^Microsoft\s+Office\b|^Office\b" { return "Microsoft Office" }
            "^Microsoft\s+Outlook\b|^Outlook\b" { return "Microsoft Outlook" }
            "^Microsoft\s+PowerToys\b|^PowerToys\b" { return "Microsoft PowerToys" }
            "^Adobe\b|Flash Player" { return "Adobe" }
            "^Steam\b" { return "Steam" }
            "^Epic Games\b|^Epic\b|Fortnite" { return "Epic Games" }
            "^Xbox\b|Minecraft|Roblox" { return "Xbox" }
            "^Discord\b" { return "Discord" }
            "^Spotify\b" { return "Spotify" }
            "^NVIDIA\b" { return "NVIDIA" }
            "^AMD\b" { return "AMD" }
            "^Windows Update\b" { return "Windows Update" }
            "^Windows Logs\b|Event Logs|Event Viewer|Error Reporting" { return "Windows Logs" }
            "^Windows\b|^Microsoft Store\b|^Microsoft\s+Windows\b" { return "Windows" }
        }
        if (-not [string]::IsNullOrWhiteSpace($rawGroup) -and $rawGroup -ne "General") {
            if ($rawGroup -eq "Epic") { return "Epic Games" }
            return $rawGroup
        }
        return "Other Apps"
    }.GetNewClosure()

    $getCleanerDisplayName = {
        param($item)
        $itemKey = if ($item.Key) { [string]$item.Key } else { [string]$item.ID }
        if ($itemKey -eq "Thumbnails") { return "Thumbnail / Thumbs Cache" }
        $name = & $normalizeCleanerName $item.Name
        if (-not [bool]$item.IsInternal) {
            $displayGroup = & $getCleanerDisplayGroup $item
            if (-not [string]::IsNullOrWhiteSpace($displayGroup) -and $displayGroup -ne "Other Apps") {
                $name = ($name -replace ("^" + [regex]::Escape($displayGroup) + "\s*[-:]?\s*"), "").Trim()
            }
        }
        if ([string]::IsNullOrWhiteSpace($name)) { return "General Cleanup" }
        return $name
    }.GetNewClosure()

    $getCleanerDisplaySection = {
        param($item)
        $rawSection = ([string]$item.Section).Trim()
        $name = & $normalizeCleanerName $item.Name
        $group = & $getCleanerDisplayGroup $item
        if ([bool]$item.IsInternal) {
            if (-not [string]::IsNullOrWhiteSpace($rawSection)) { return $rawSection }
            return "System"
        }
        if ($group -in @("Google Chrome", "Microsoft Edge", "Mozilla Firefox", "Brave", "Opera", "SeaMonkey")) { return "Browsers / Internet" }
        if ($group -in @("Discord", "Spotify")) { return "Internet & Chat" }
        if ($group -in @("Steam", "Epic Games", "Xbox") -or $rawSection -eq "Games") { return "Games" }
        if ($group -in @("Microsoft Office", "Microsoft Outlook", "Microsoft PowerToys", "Adobe")) { return "Productivity" }
        if ($rawSection -in @("System", "Browsers / Internet", "Productivity", "Internet & Chat", "Games", "Applications")) { return $rawSection }
        if ($name -match "(?i)\b(Outlook|Office|PowerToys|Adobe)\b") { return "Productivity" }
        if ($name -match "(?i)\b(Chrome|Edge|Firefox|Brave|Opera|SeaMonkey|Browser)\b") { return "Browsers / Internet" }
        if ($name -match "(?i)\b(Discord|Spotify|Slack|Telegram|WhatsApp|Signal|Zoom)\b") { return "Internet & Chat" }
        if ($name -match "(?i)\b(Steam|Epic Games|Fortnite|Xbox|Minecraft|Roblox)\b") { return "Games" }
        return "Applications"
    }.GetNewClosure()

    $getCleanerSectionOrder = {
        param($section)
        $sectionName = [string]$section
        if ($sectionOrder.ContainsKey($sectionName)) { return [int]$sectionOrder[$sectionName] }
        return 99
    }.GetNewClosure()

    $getCleanerGroupOrder = {
        param($item)
        $section = & $getCleanerDisplaySection $item
        $group = & $getCleanerDisplayGroup $item
        $key = "$section|$group"
        if ($preferredGroupOrder.ContainsKey($key)) { return [int]$preferredGroupOrder[$key] }
        return 50
    }.GetNewClosure()

    $setVisibility = {
        param($Element, [bool]$Visible)
        if ($Element) {
            $Element.Visibility = if ($Visible) { [System.Windows.Visibility]::Visible } else { [System.Windows.Visibility]::Collapsed }
        }
    }.GetNewClosure()

    $applyCleanerSearch = {
        $q = ([string]$txtSearch.Text).ToLowerInvariant()
        foreach ($entry in @($sectionEntries.ToArray())) {
            $hasVisibleChildren = $false
            $currentGroupHeader = $null
            $currentGroupHasVisibleChildren = $false

            foreach ($child in @($entry.Flow.Children)) {
                if ([string]$child.Tag -eq "GROUPHEADER") {
                    if ($currentGroupHeader) {
                        & $setVisibility $currentGroupHeader ($q.Length -eq 0 -or $currentGroupHasVisibleChildren)
                    }
                    $currentGroupHeader = $child
                    $currentGroupHasVisibleChildren = $false
                    & $setVisibility $child ($q.Length -eq 0)
                    continue
                }

                if ($child -is [System.Windows.Controls.CheckBox]) {
                    $searchKey = [string]$child.Uid
                    $match = ($q.Length -eq 0 -or ($checkboxSearchText.ContainsKey($searchKey) -and $checkboxSearchText[$searchKey].Contains($q)))
                    & $setVisibility $child $match
                    if ($match) {
                        $hasVisibleChildren = $true
                        $currentGroupHasVisibleChildren = $true
                    }
                }
            }

            if ($currentGroupHeader) {
                & $setVisibility $currentGroupHeader ($q.Length -eq 0 -or $currentGroupHasVisibleChildren)
            }
            & $setVisibility $entry.Header $hasVisibleChildren
            & $setVisibility $entry.Flow $hasVisibleChildren
        }
    }.GetNewClosure()

    $RenderAllRules = {
        param($allRules)

        $prevStates = @{}
        foreach ($k in $cleanupCheckboxes.Keys) {
            $prevStates[$k] = [bool]$cleanupCheckboxes[$k].IsChecked
        }

        $pnlRules.Children.Clear()
        $cleanupCheckboxes.Clear()
        $checkboxSearchText.Clear()
        $sectionEntries.Clear()

        $grouped = $allRules |
        Group-Object -Property { & $getCleanerDisplaySection $_ } |
        Sort-Object @{ Expression = { & $getCleanerSectionOrder $_.Name } }, Name

        foreach ($group in $grouped) {
            $sec = $group.Name

            $header = [System.Windows.Controls.Border]::new()
            $header.Background = New-WmtBrush "BgPanel"
            $header.BorderBrush = New-WmtBrush "BorderBrush"
            $header.BorderThickness = "1"
            $header.CornerRadius = "4"
            $header.Padding = "10,7"
            $header.Margin = "0,10,0,6"

            $secChk = [System.Windows.Controls.CheckBox]::new()
            $secChk.Content = $sec
            $secChk.FontSize = 15
            $secChk.FontWeight = [System.Windows.FontWeights]::SemiBold
            Set-WmtThemedBrush -Object $secChk -Property ([System.Windows.Controls.CheckBox]::ForegroundProperty) -ColorOrKey "Accent"
            $header.Child = $secChk

            $flow = [System.Windows.Controls.StackPanel]::new()
            $flow.Margin = "16,0,0,4"

            $secItems = $group.Group | Sort-Object `
            @{ Expression = { & $getCleanerGroupOrder $_ } }, `
            @{ Expression = { & $getCleanerDisplayGroup $_ } }, `
            @{ Expression = { if ([bool]$_.IsInternal) { 0 } else { 1 } } }, `
            @{ Expression = { & $getCleanerDisplayName $_ } }

            $childChecks = [System.Collections.Generic.List[object]]::new()
            $currentGroup = $null
            $isSecChecked = $true

            foreach ($item in $secItems) {
                $displayGroup = & $getCleanerDisplayGroup $item
                if ($displayGroup -ne $currentGroup) {
                    $currentGroup = $displayGroup
                    $grpLbl = [System.Windows.Controls.TextBlock]::new()
                    $grpLbl.Text = $currentGroup
                    $grpLbl.Tag = "GROUPHEADER"
                    $grpLbl.Margin = "0,10,0,4"
                    $grpLbl.FontWeight = [System.Windows.FontWeights]::SemiBold
                    Set-WmtThemedBrush -Object $grpLbl -Property ([System.Windows.Controls.TextBlock]::ForegroundProperty) -ColorOrKey "TextSecondary"
                    [void]$flow.Children.Add($grpLbl)
                }

                $itemKey = if ($item.Key) { [string]$item.Key } else { [string]$item.ID }
                $displayName = & $getCleanerDisplayName $item

                $chk = [System.Windows.Controls.CheckBox]::new()
                $chk.Margin = "10,0,0,5"
                $chk.Uid = $itemKey
                $chk.Tag = if ($item.IsInternal) { $itemKey } else { $item }

                if ($item.IsInternal) {
                    $chk.Content = $displayName
                    Set-WmtThemedBrush -Object $chk -Property ([System.Windows.Controls.CheckBox]::ForegroundProperty) -ColorOrKey "TextPrimary"
                }
                elseif ($item.IsCleanerML) {
                    $chk.Content = "$displayName (CleanerML)"
                    Set-WmtThemedBrush -Object $chk -Property ([System.Windows.Controls.CheckBox]::ForegroundProperty) -ColorOrKey "Accent"
                }
                else {
                    $chk.Content = "$displayName (winapp2.ini)"
                    Set-WmtThemedBrush -Object $chk -Property ([System.Windows.Controls.CheckBox]::ForegroundProperty) -ColorOrKey "Accent"
                }

                $searchParts = [System.Collections.Generic.List[string]]::new()
                foreach ($part in @($chk.Content, $displayName, $displayGroup, $itemKey, $item.Name, $item.Desc, $item.AppGroup, $item.Section)) {
                    if (-not [string]::IsNullOrWhiteSpace([string]$part)) { $searchParts.Add([string]$part) }
                }
                if ($itemKey -eq "Thumbnails") {
                    $searchParts.AddRange([string[]]@("thumbs", "thumbcache", "thumbcache_*.db", "thumbs.db"))
                }
                elseif ($itemKey -eq "ThumbsDb") {
                    $searchParts.AddRange([string[]]@("thumbs", "thumbnail", "thumbs.db", "deep scan"))
                }
                elseif (-not $item.IsInternal -and $item.Paths) {
                    foreach ($pathRule in $item.Paths) {
                        if (-not [string]::IsNullOrWhiteSpace([string]$pathRule.Path)) { $searchParts.Add([string]$pathRule.Path) }
                        if (-not [string]::IsNullOrWhiteSpace([string]$pathRule.Pattern)) { $searchParts.Add([string]$pathRule.Pattern) }
                    }
                }
                $checkboxSearchText[$itemKey] = ($searchParts -join " ").ToLowerInvariant()

                if ($prevStates.ContainsKey($itemKey)) {
                    $chk.IsChecked = [bool]$prevStates[$itemKey]
                }
                elseif ($savedStates.ContainsKey($itemKey)) {
                    $chk.IsChecked = [bool]$savedStates[$itemKey]
                }
                elseif ($item.PSObject.Properties["DefaultChecked"]) {
                    $chk.IsChecked = [bool]$item.DefaultChecked
                }
                else {
                    $chk.IsChecked = ([bool]$item.IsInternal)
                }

                if (-not [bool]$chk.IsChecked) { $isSecChecked = $false }
                if ($item.Desc) { $chk.ToolTip = [string]$item.Desc }

                [void]$flow.Children.Add($chk)
                $cleanupCheckboxes[$itemKey] = $chk
                [void]$childChecks.Add($chk)
            }

            $secChk.IsChecked = $isSecChecked
            $secChk.Add_Checked({
                    param($s, $e)
                    $filterActive = -not [string]::IsNullOrWhiteSpace($txtSearch.Text)
                    foreach ($c in $childChecks) {
                        if (-not $filterActive -or $c.Visibility -eq [System.Windows.Visibility]::Visible) { $c.IsChecked = $true }
                    }
                }.GetNewClosure())
            $secChk.Add_Unchecked({
                    param($s, $e)
                    $filterActive = -not [string]::IsNullOrWhiteSpace($txtSearch.Text)
                    foreach ($c in $childChecks) {
                        if (-not $filterActive -or $c.Visibility -eq [System.Windows.Visibility]::Visible) { $c.IsChecked = $false }
                    }
                }.GetNewClosure())

            [void]$pnlRules.Children.Add($header)
            [void]$pnlRules.Children.Add($flow)
            [void]$sectionEntries.Add([PSCustomObject]@{ Header = $header; Flow = $flow; HeaderCheck = $secChk; Children = $childChecks })
        }

        & $applyCleanerSearch
    }.GetNewClosure()

    $externalRuleState = @{
        Winapp2   = @()
        CleanerML = @()
    }

    $renderCurrentCleanerRules = {
        $combined = @($internalRules)
        if ($externalRuleState.Winapp2) { $combined += @($externalRuleState.Winapp2) }
        if ($externalRuleState.CleanerML) { $combined += @($externalRuleState.CleanerML) }
        & $RenderAllRules -allRules $combined
    }.GetNewClosure()

    & $renderCurrentCleanerRules

    $loadExternalCleanerRules = {
        param(
            [switch]$ForceWinapp2Download,
            [switch]$ForceCleanerMlDownload
        )

        $lblStatus.Text = "Loading cleaner rules..."
        $dialog.Cursor = [System.Windows.Input.Cursors]::Wait
        Invoke-WmtDispatcherPump -Dispatcher $dialog.Dispatcher

        try {
            if ([bool]$chkToggleWinapp2.IsChecked) {
                $lblStatus.Text = "Loading Winapp2 rules..."
                Invoke-WmtDispatcherPump -Dispatcher $dialog.Dispatcher
                $iniPath = Join-Path (Get-DataPath) "winapp2.ini"
                $cachePath = Join-Path (Get-DataPath) "winapp2_cache.json"
                $shouldDownload = $ForceWinapp2Download -or ((-not (Test-Path $iniPath)) -and (-not (Test-Path $cachePath)))
                $externalRuleState.Winapp2 = @(Get-Winapp2Rules -Download:$shouldDownload)
            }
            else {
                $externalRuleState.Winapp2 = @()
            }

            if ([bool]$chkToggleCleanerML.IsChecked) {
                $lblStatus.Text = "Loading BleachBit CleanerML..."
                Invoke-WmtDispatcherPump -Dispatcher $dialog.Dispatcher
                $hasLocalCleanerMl = ((Get-WmtBleachBitCleanerXmlDirectories).Count -gt 0)
                $cachePath = Join-Path (Get-DataPath) "cleanerml_cache.json"
                $shouldDownloadCleanerMl = $ForceCleanerMlDownload -or ((-not $hasLocalCleanerMl) -and (-not (Test-Path $cachePath)))
                $externalRuleState.CleanerML = @(Get-BleachBitCleanerMlRules -Download:$shouldDownloadCleanerMl)
            }
            else {
                $externalRuleState.CleanerML = @()
            }

            & $renderCurrentCleanerRules
        }
        catch {
            Write-GuiLog "Cleaner rules warning: $($_.Exception.Message)"
            & $renderCurrentCleanerRules
        }
        finally {
            $dialog.Cursor = [System.Windows.Input.Cursors]::Arrow
            $lblStatus.Text = ""
        }
    }.GetNewClosure()

    $communityLoadState = @{ Started = $false }
    $loadCommunityRulesIfEnabled = {
        if ($communityLoadState.Started -or (-not [bool]$chkToggleWinapp2.IsChecked -and -not [bool]$chkToggleCleanerML.IsChecked)) { return }
        $communityLoadState.Started = $true
        & $loadExternalCleanerRules
    }.GetNewClosure()

    $dialog.Add_ContentRendered({ & $loadCommunityRulesIfEnabled }.GetNewClosure())
    $dialog.Add_Activated({ & $loadCommunityRulesIfEnabled }.GetNewClosure())

    $chkToggleWinapp2.Add_Click({
            $currentSettings.LoadWinapp2 = [bool]$chkToggleWinapp2.IsChecked
            Save-WmtSettings -Settings $currentSettings

            $iniPath = Join-Path (Get-DataPath) "winapp2.ini"
            $forceDownload = [bool]$chkToggleWinapp2.IsChecked -and (-not (Test-Path $iniPath))
            & $loadExternalCleanerRules -ForceWinapp2Download:$forceDownload
        }.GetNewClosure())

    $chkToggleCleanerML.Add_Click({
            $currentSettings.LoadCleanerML = [bool]$chkToggleCleanerML.IsChecked
            Save-WmtSettings -Settings $currentSettings

            $cachePath = Join-Path (Get-DataPath) "cleanerml_cache.json"
            $forceDownload = [bool]$chkToggleCleanerML.IsChecked -and ((Get-WmtBleachBitCleanerXmlDirectories).Count -eq 0) -and (-not (Test-Path $cachePath))
            & $loadExternalCleanerRules -ForceCleanerMlDownload:$forceDownload
        }.GetNewClosure())

    $searchDelayTimer = [System.Windows.Threading.DispatcherTimer]::new()
    $searchDelayTimer.Interval = [TimeSpan]::FromMilliseconds(250)
    $searchDelayTimer.Add_Tick({
            $searchDelayTimer.Stop()
            & $applyCleanerSearch
        }.GetNewClosure())

    $txtSearch.Add_TextChanged({
            $searchDelayTimer.Stop()
            $searchDelayTimer.Start()
        }.GetNewClosure())

    $dialog.Add_Closed({
            try { $searchDelayTimer.Stop() } catch {}
        }.GetNewClosure())

    $selectionState = @{ Result = $null }

    $getSelectedCleanerItems = {
        $selectedItems = [System.Collections.Generic.List[object]]::new()
        $filterActive = -not [string]::IsNullOrWhiteSpace($txtSearch.Text)
        foreach ($key in $cleanupCheckboxes.Keys) {
            $cb = $cleanupCheckboxes[$key]
            $isVisibleForAction = (-not $filterActive) -or ($cb.Visibility -eq [System.Windows.Visibility]::Visible -and $cb.Parent.Visibility -eq [System.Windows.Visibility]::Visible)
            if ([bool]$cb.IsChecked -and $isVisibleForAction) { [void]$selectedItems.Add($cb.Tag) }
        }
        return , $selectedItems
    }.GetNewClosure()

    $submitCleanupSelection = {
        param([string]$Action)

        $searchDelayTimer.Stop()
        & $applyCleanerSearch

        $selectedItems = & $getSelectedCleanerItems
        if ($selectedItems.Count -le 0) {
            $message = if ([string]::IsNullOrWhiteSpace($txtSearch.Text)) {
                "Select at least one cleaner first."
            }
            else {
                "No visible checked cleaners match the current search. Clear the search or check a visible cleaner."
            }
            Show-WmtMessageBox -Owner $dialog -Message $message -Title "No Cleaners Selected" -Image Information | Out-Null
            return
        }

        foreach ($key in $cleanupCheckboxes.Keys) {
            $currentSettings.TempCleanup[$key] = [bool]$cleanupCheckboxes[$key].IsChecked
        }
        $currentSettings.LoadWinapp2 = [bool]$chkToggleWinapp2.IsChecked
        $currentSettings.LoadCleanerML = [bool]$chkToggleCleanerML.IsChecked
        Save-WmtSettings -Settings $currentSettings

        $selectionState.Result = [PSCustomObject]@{
            Action = $Action
            Items  = $selectedItems.ToArray()
        }
        $dialog.DialogResult = $true
    }.GetNewClosure()

    $btnClean.Add_Click({ & $submitCleanupSelection "Clean" }.GetNewClosure())
    $btnAnalyze.Add_Click({ & $submitCleanupSelection "Analyze" }.GetNewClosure())
    $btnCancel.Add_Click({ $dialog.Close() }.GetNewClosure())

    $btnEventLogs.Add_Click({
            $confirm = Show-WmtMessageBox -Owner $dialog -Message "Clear all Windows Event Logs?`n`nThis safely flushes all registered Event Logs on your system.`n`nWARNING: This process can take several minutes to complete." -Title "Confirm Clear Logs" -Button YesNo -Image Warning
            if ($confirm -ne [System.Windows.MessageBoxResult]::Yes) { return }

            $dialog.Cursor = [System.Windows.Input.Cursors]::Wait
            $btnEventLogs.IsEnabled = $false
            $btnEventLogs.Content = "Clearing..."

            $script:EventLogRunspace = [PowerShell]::Create().AddScript({
                    $logs = wevtutil el
                    $cleared = 0
                    foreach ($log in $logs) {
                        wevtutil cl "$log" 2>$null
                        $cleared++
                    }
                    return $cleared
                })
            $script:EventLogAsyncResult = $script:EventLogRunspace.BeginInvoke()

            $script:EventLogTimer = [System.Windows.Threading.DispatcherTimer]::new()
            $script:EventLogTimer.Interval = [TimeSpan]::FromMilliseconds(250)
            $script:EventLogTimer.Add_Tick({
                    if ($script:EventLogAsyncResult.IsCompleted) {
                        $script:EventLogTimer.Stop()
                        $dialog.Cursor = [System.Windows.Input.Cursors]::Arrow
                        $btnEventLogs.IsEnabled = $true
                        $btnEventLogs.Content = "Clear Event Logs"
                        try {
                            $clearedCount = $script:EventLogRunspace.EndInvoke($script:EventLogAsyncResult)
                            if ($clearedCount -is [System.Collections.ObjectModel.Collection[PSObject]]) {
                                $clearedCount = $clearedCount[0]
                            }
                            Show-WmtMessageBox -Owner $dialog -Message "Successfully processed $clearedCount Event Logs." -Title "Success" -Image Information | Out-Null
                        }
                        catch {
                            Show-WmtMessageBox -Owner $dialog -Message "Error: $($_.Exception.Message)" -Title "Error" -Image Error | Out-Null
                        }
                        $script:EventLogRunspace.Dispose()
                    }
                }.GetNewClosure())
            $script:EventLogTimer.Start()
        }.GetNewClosure())

    $dialog.ShowDialog() | Out-Null
    return $selectionState.Result
}

function Show-WmtCleanupPreviewWpf {
    param(
        [System.Collections.IEnumerable]$PreviewList,
        [string]$FinalTotalFormatted
    )

    $formatPreviewBytes = {
        param([int64]$Bytes)
        if ($Bytes -ge 1GB) { return "{0:N2} GB" -f ($Bytes / 1GB) }
        if ($Bytes -ge 1MB) { return "{0:N2} MB" -f ($Bytes / 1MB) }
        if ($Bytes -ge 1KB) { return "{0:N2} KB" -f ($Bytes / 1KB) }
        return "$Bytes B"
    }.GetNewClosure()

    [xml]$cleanupPreviewXaml = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Width="960" Height="680" MinWidth="760" MinHeight="500" WindowStartupLocation="CenterOwner"
        Background="{DynamicResource BgDark}" Foreground="{DynamicResource TextPrimary}"
        FontFamily="Segoe UI Variable Display, Segoe UI, Arial" FontSize="13">
    <Grid Margin="16">
        <Grid.RowDefinitions>
            <RowDefinition Height="*"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>

        <DataGrid Name="dgPreview" Grid.Row="0" AlternationCount="2" IsReadOnly="True" CanUserAddRows="False" CanUserDeleteRows="False">
            <DataGrid.Columns>
                <DataGridTextColumn Header="RuleName" Binding="{Binding RuleName}" Width="180" IsReadOnly="True"/>
                <DataGridTextColumn Header="Status" Binding="{Binding Protection}" Width="160" IsReadOnly="True"/>
                <DataGridTextColumn Header="FilePath" Binding="{Binding FilePath}" Width="*" IsReadOnly="True"/>
                <DataGridTextColumn Header="Size" Binding="{Binding SizeText}" SortMemberPath="Size" Width="96" IsReadOnly="True"/>
            </DataGrid.Columns>
        </DataGrid>

        <Border Grid.Row="1" Background="{DynamicResource BgPanel}" BorderBrush="{DynamicResource BorderBrush}" BorderThickness="1" CornerRadius="4" Padding="12" Margin="0,12,0,0">
            <Grid>
                <CheckBox Name="chkHideProtected" Content="Hide protected" Foreground="{DynamicResource Warning}" VerticalAlignment="Center"/>
                <StackPanel Orientation="Horizontal" HorizontalAlignment="Right">
                    <Button Name="btnCleanSelected" Content="Clean Selected" MinWidth="124" Background="{DynamicResource Accent}" Foreground="{DynamicResource AccentText}" Margin="0,0,8,0"/>
                    <Button Name="btnCleanAll" Content="Clean All" MinWidth="104" Background="{DynamicResource Danger}" Foreground="{DynamicResource DangerText}" Margin="0,0,8,0"/>
                    <Button Name="btnClose" Content="Close" Width="90" IsCancel="True"/>
                </StackPanel>
            </Grid>
        </Border>
    </Grid>
</Window>
'@

    $previewWindow = New-WmtWindowFromFullXaml -Xaml $cleanupPreviewXaml

    $dg = $previewWindow.FindName("dgPreview")
    $chkHideProtected = $previewWindow.FindName("chkHideProtected")
    $btnCleanSelected = $previewWindow.FindName("btnCleanSelected")
    $btnCleanAll = $previewWindow.FindName("btnCleanAll")
    $btnClose = $previewWindow.FindName("btnClose")

    $allPreviewRows = [System.Collections.Generic.List[object]]::new()
    $rowId = 0
    foreach ($item in @($PreviewList)) {
        $isProtected = $false
        if ($item.PSObject.Properties["IsProtected"]) { $isProtected = [bool]$item.IsProtected }
        $protectionReason = ""
        if ($item.PSObject.Properties["ProtectionReason"]) { $protectionReason = [string]$item.ProtectionReason }
        if ($isProtected -and [string]::IsNullOrWhiteSpace($protectionReason)) { $protectionReason = "Protected / in use" }

        $bytes = [int64]0
        try { $bytes = [int64]$item.RawBytes } catch {}

        [void]$allPreviewRows.Add([PSCustomObject]@{
                RowId            = $rowId
                RuleName         = [string]$item.RuleName
                Protection       = if ($isProtected) { $protectionReason } else { "" }
                FilePath         = [string]$item.FilePath
                Size             = $bytes
                SizeText         = & $formatPreviewBytes $bytes
                IsProtected      = $isProtected
                ProtectionReason = $protectionReason
            })
        $rowId++
    }

    $previewRows = [System.Collections.ObjectModel.ObservableCollection[object]]::new()
    $dg.ItemsSource = $previewRows

    $ctxMenu = [System.Windows.Controls.ContextMenu]::new()
    Set-WmtContextMenuChrome -ContextMenu $ctxMenu
    $menuOpen = [System.Windows.Controls.MenuItem]::new()
    $menuOpen.Header = "Go to file [Open folder]"
    $menuDelete = [System.Windows.Controls.MenuItem]::new()
    $menuDelete.Header = "Delete file"
    [void]$ctxMenu.Items.Add($menuOpen)
    [void]$ctxMenu.Items.Add($menuDelete)
    $dg.ContextMenu = $ctxMenu

    $dg.Add_PreviewMouseRightButtonDown({
            param($s, $e)
            $row = Get-WmtVisualAncestor -Element $e.OriginalSource -AncestorType ([System.Windows.Controls.DataGridRow])
            if ($row) {
                if (-not $row.IsSelected) {
                    $dg.SelectedItems.Clear()
                    $row.IsSelected = $true
                }
                try { $row.Focus() | Out-Null } catch {}
            }
        }.GetNewClosure())

    $refreshPreviewFilter = {
        $previewRows.Clear()
        foreach ($row in @($allPreviewRows.ToArray())) {
            if ([bool]$chkHideProtected.IsChecked -and [bool]$row.IsProtected) { continue }
            [void]$previewRows.Add($row)
        }

        $protectedRemaining = @($allPreviewRows.ToArray() | Where-Object { [bool]$_.IsProtected }).Count
        $hiddenProtected = if ([bool]$chkHideProtected.IsChecked) { $protectedRemaining } else { 0 }
        if ($protectedRemaining -gt 0) {
            $suffix = "$protectedRemaining protected/in use"
            if ($hiddenProtected -gt 0) { $suffix += ", $hiddenProtected hidden" }
            $previewWindow.Title = "Cleanup Analysis Preview ($FinalTotalFormatted Total, $suffix)"
        }
        else {
            $previewWindow.Title = "Cleanup Analysis Preview ($FinalTotalFormatted Total)"
        }

        $hasRows = ($previewRows.Count -gt 0)
        $btnCleanSelected.IsEnabled = $hasRows
        $btnCleanAll.IsEnabled = $hasRows
        $menuDelete.IsEnabled = $hasRows
    }.GetNewClosure()

    $removePreviewRowsByIds = {
        param([int[]]$RowIds)
        if (-not $RowIds -or $RowIds.Count -eq 0) { return }
        $removeLookup = @{}
        foreach ($id in $RowIds) { $removeLookup[[int]$id] = $true }
        for ($i = $allPreviewRows.Count - 1; $i -ge 0; $i--) {
            if ($removeLookup.ContainsKey([int]$allPreviewRows[$i].RowId)) {
                $allPreviewRows.RemoveAt($i)
            }
        }
        & $refreshPreviewFilter
    }.GetNewClosure()

    $openSelectedPath = {
        if ($dg.SelectedItems.Count -le 0) { return }
        $path = [string]$dg.SelectedItems[0].FilePath
        if (Test-Path -LiteralPath $path) {
            Start-Process "explorer.exe" -ArgumentList "/select,`"$path`""
        }
    }.GetNewClosure()

    $invokePreviewDeletion = {
        param(
            [object[]]$Targets,
            [string]$ActionTitle
        )

        $formatDeleteBytes = {
            param([int64]$Bytes)
            if ($Bytes -ge 1GB) { return "{0:N2} GB" -f ($Bytes / 1GB) }
            if ($Bytes -ge 1MB) { return "{0:N2} MB" -f ($Bytes / 1MB) }
            if ($Bytes -ge 1KB) { return "{0:N2} KB" -f ($Bytes / 1KB) }
            return "$Bytes B"
        }.GetNewClosure()

        $deleteTargets = [System.Collections.Generic.List[object]]::new()
        $seenIds = @{}
        foreach ($target in @($Targets)) {
            if (-not $target) { continue }
            $id = [int]$target.RowId
            if ($seenIds.ContainsKey($id)) { continue }
            [void]$deleteTargets.Add([PSCustomObject]@{
                    RowId    = $id
                    FilePath = [string]$target.FilePath
                    Size     = [int64]$target.Size
                })
            $seenIds[$id] = $true
        }

        if ($deleteTargets.Count -eq 0) { return }

        $targetArray = $deleteTargets.ToArray()
        $completedIds = [System.Collections.ArrayList]::Synchronized([System.Collections.ArrayList]::new())
        $failedPaths = [System.Collections.ArrayList]::Synchronized([System.Collections.ArrayList]::new())
        $deleteState = [hashtable]::Synchronized(@{
                Total        = $targetArray.Count
                Processed    = 0
                Deleted      = 0
                Missing      = 0
                Failed       = 0
                Bytes        = [int64]0
                Current      = ""
                Cancel       = $false
                IsCompleted  = $false
                Error        = ""
                CompletedIds = $completedIds
                FailedPaths  = $failedPaths
            })

        [xml]$deleteProgressXaml = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Width="560" Height="190" ResizeMode="NoResize" WindowStartupLocation="CenterOwner"
        Background="{DynamicResource BgDark}" Foreground="{DynamicResource TextPrimary}"
        FontFamily="Segoe UI Variable Display, Segoe UI, Arial" FontSize="13">
    <Grid Margin="20">
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>
        <TextBlock Name="deleteLabel" Text="Preparing deletion..." TextTrimming="CharacterEllipsis"/>
        <TextBlock Name="deleteCurrent" Grid.Row="1" Text="Starting worker..." Foreground="{DynamicResource TextSecondary}" Margin="0,8,0,14" TextTrimming="CharacterEllipsis"/>
        <ProgressBar Name="deleteProgress" Grid.Row="2" Height="12" Minimum="0"/>
        <Button Name="btnCancelDelete" Grid.Row="3" Content="Cancel" Width="94" HorizontalAlignment="Right" Margin="0,16,0,0"/>
    </Grid>
</Window>
'@
        $deleteWindow = New-WmtWindowFromFullXaml -Xaml $deleteProgressXaml -NoOwner
        try { $deleteWindow.Owner = $previewWindow } catch {}
        $deleteWindow.Title = $ActionTitle
        $deleteLabel = $deleteWindow.FindName("deleteLabel")
        $deleteCurrent = $deleteWindow.FindName("deleteCurrent")
        $deleteProgress = $deleteWindow.FindName("deleteProgress")
        $btnCancelDelete = $deleteWindow.FindName("btnCancelDelete")
        $deleteProgress.Maximum = [Math]::Max(1, $targetArray.Count)

        $worker = @{
            PowerShell = $null
            Runspace   = $null
            Async      = $null
            Ended      = $false
        }

        $disposeWorker = {
            try { if ($worker.PowerShell) { $worker.PowerShell.Dispose() } } catch {}
            try {
                if ($worker.Runspace) {
                    $worker.Runspace.Close()
                    $worker.Runspace.Dispose()
                }
            }
            catch {}
            $worker.PowerShell = $null
            $worker.Runspace = $null
            $worker.Async = $null
        }.GetNewClosure()

        try {
            $runspace = [runspacefactory]::CreateRunspace()
            $runspace.ThreadOptions = "ReuseThread"
            $runspace.Open()

            $ps = [PowerShell]::Create()
            $ps.Runspace = $runspace
            [void]$ps.AddScript({
                    param([object[]]$Targets, [hashtable]$State)
                    $ErrorActionPreference = "SilentlyContinue"
                    try {
                        foreach ($target in @($Targets)) {
                            if ([bool]$State["Cancel"]) { break }

                            $path = [string]$target.FilePath
                            $rowId = [int]$target.RowId
                            $bytes = [int64]0
                            try { $bytes = [int64]$target.Size } catch {}

                            $State["Current"] = $path
                            try {
                                if ([string]::IsNullOrWhiteSpace($path)) {
                                    [void]$State["CompletedIds"].Add($rowId)
                                    $State["Missing"] = ([int]$State["Missing"]) + 1
                                    continue
                                }

                                if (Test-Path -LiteralPath $path) {
                                    $itemInfo = Get-Item -LiteralPath $path -Force -ErrorAction SilentlyContinue
                                    if ($itemInfo -and -not $itemInfo.PSIsContainer) {
                                        try { $itemInfo.Attributes = [System.IO.FileAttributes]::Normal } catch {}
                                    }
                                    Remove-Item -LiteralPath $path -Recurse -Force -ErrorAction Stop
                                    $State["Deleted"] = ([int]$State["Deleted"]) + 1
                                    $State["Bytes"] = ([int64]$State["Bytes"]) + $bytes
                                }
                                else {
                                    $State["Missing"] = ([int]$State["Missing"]) + 1
                                }
                                [void]$State["CompletedIds"].Add($rowId)
                            }
                            catch {
                                $State["Failed"] = ([int]$State["Failed"]) + 1
                                if (-not [string]::IsNullOrWhiteSpace($path)) {
                                    [void]$State["FailedPaths"].Add($path)
                                }
                            }
                            finally {
                                $State["Processed"] = ([int]$State["Processed"]) + 1
                            }
                        }
                    }
                    catch {
                        $State["Error"] = $_.Exception.Message
                    }
                    finally {
                        $State["IsCompleted"] = $true
                    }
                }).AddArgument($targetArray).AddArgument($deleteState)

            $worker.PowerShell = $ps
            $worker.Runspace = $runspace
            $worker.Async = $ps.BeginInvoke()
        }
        catch {
            & $disposeWorker
            Show-WmtMessageBox -Owner $previewWindow -Message "Could not start cleanup worker.`n$($_.Exception.Message)" -Title "Cleanup Error" -Image Error | Out-Null
            return
        }

        $btnCleanSelected.IsEnabled = $false
        $btnCleanAll.IsEnabled = $false
        $menuDelete.IsEnabled = $false

        $btnCancelDelete.Add_Click({
                $deleteState["Cancel"] = $true
                $btnCancelDelete.IsEnabled = $false
                $deleteCurrent.Text = "Stopping after the current item..."
            }.GetNewClosure())

        $deleteTimer = [System.Windows.Threading.DispatcherTimer]::new()
        $deleteTimer.Interval = [TimeSpan]::FromMilliseconds(150)
        $deleteTimer.Add_Tick({
                try {
                    $total = [Math]::Max(1, [int]$deleteState["Total"])
                    $processed = [Math]::Max(0, [int]$deleteState["Processed"])
                    $deleted = [Math]::Max(0, [int]$deleteState["Deleted"])
                    $missing = [Math]::Max(0, [int]$deleteState["Missing"])
                    $failed = [Math]::Max(0, [int]$deleteState["Failed"])
                    $bytes = [int64]$deleteState["Bytes"]
                    $currentPath = [string]$deleteState["Current"]
                    $freed = & $formatDeleteBytes $bytes

                    $deleteProgress.Value = [Math]::Min($deleteProgress.Maximum, $processed)
                    $deleteLabel.Text = "$processed/$total processed | Deleted: $deleted | Failed: $failed | Recovered: $freed"
                    if ([bool]$deleteState["Cancel"] -and -not [bool]$deleteState["IsCompleted"]) {
                        $deleteCurrent.Text = "Stopping after the current item..."
                    }
                    elseif ($missing -gt 0) {
                        $deleteCurrent.Text = "Current: $currentPath  ($missing already missing)"
                    }
                    else {
                        $deleteCurrent.Text = "Current: $currentPath"
                    }

                    if ([bool]$deleteState["IsCompleted"] -or ($worker.Async -and $worker.Async.IsCompleted)) {
                        $deleteTimer.Stop()
                        try {
                            if ($worker.Async -and -not $worker.Ended) {
                                [void]$worker.PowerShell.EndInvoke($worker.Async)
                                $worker.Ended = $true
                            }
                        }
                        catch {
                            if ([string]::IsNullOrWhiteSpace([string]$deleteState["Error"])) {
                                $deleteState["Error"] = $_.Exception.Message
                            }
                        }
                        $deleteWindow.Close()
                    }
                }
                catch {
                    $deleteState["Error"] = $_.Exception.Message
                    $deleteTimer.Stop()
                    $deleteWindow.Close()
                }
            }.GetNewClosure())

        try {
            $deleteWindow.Add_ContentRendered({ $deleteTimer.Start() }.GetNewClosure())
            $deleteWindow.ShowDialog() | Out-Null
        }
        finally {
            try { $deleteTimer.Stop() } catch {}
            try {
                if ($worker.Async -and $worker.Async.IsCompleted -and -not $worker.Ended) {
                    [void]$worker.PowerShell.EndInvoke($worker.Async)
                    $worker.Ended = $true
                }
            }
            catch {
                if ([string]::IsNullOrWhiteSpace([string]$deleteState["Error"])) {
                    $deleteState["Error"] = $_.Exception.Message
                }
            }
            & $disposeWorker
        }

        $completedRowIds = @($deleteState["CompletedIds"] | ForEach-Object { [int]$_ })
        $failedLookup = @{}
        foreach ($failedPath in @($deleteState["FailedPaths"])) {
            if (-not [string]::IsNullOrWhiteSpace([string]$failedPath)) { $failedLookup[[string]$failedPath] = $true }
        }

        if ($failedLookup.Count -gt 0) {
            foreach ($row in @($allPreviewRows.ToArray())) {
                if ($row -and $failedLookup.ContainsKey([string]$row.FilePath)) {
                    $row.IsProtected = $true
                    $row.ProtectionReason = "Delete failed"
                    $row.Protection = "Delete failed"
                }
            }
        }

        if ($completedRowIds.Count -gt 0) { & $removePreviewRowsByIds -RowIds ([int[]]$completedRowIds) }
        else { & $refreshPreviewFilter }

        $finalFreed = & $formatDeleteBytes ([int64]$deleteState["Bytes"])
        $finalDeleted = [int]$deleteState["Deleted"]
        $finalMissing = [int]$deleteState["Missing"]
        $finalFailed = [int]$deleteState["Failed"]
        $wasCanceled = [bool]$deleteState["Cancel"]
        $workerError = [string]$deleteState["Error"]

        if ($finalFailed -gt 0) {
            Write-GuiLog "Preview cleanup completed with $finalFailed failure(s). Recovered: $finalFreed"
            foreach ($failedPath in @($deleteState["FailedPaths"] | Select-Object -First 5)) {
                Write-GuiLog "Failed to delete from Analyze: $failedPath"
            }
        }
        elseif ($wasCanceled) {
            Write-GuiLog "Preview cleanup canceled. Recovered: $finalFreed"
        }
        else {
            Write-GuiLog "Preview cleanup finished. Recovered: $finalFreed"
        }

        $resultText = if ($wasCanceled) {
            "Cleanup canceled.`n`nDeleted: $finalDeleted`nAlready missing: $finalMissing`nFailed: $finalFailed`nRecovered: $finalFreed"
        }
        else {
            "Cleanup complete.`n`nDeleted: $finalDeleted`nAlready missing: $finalMissing`nFailed: $finalFailed`nRecovered: $finalFreed"
        }
        if (-not [string]::IsNullOrWhiteSpace($workerError)) { $resultText += "`n`nWorker note: $workerError" }

        $icon = if ($finalFailed -gt 0 -or -not [string]::IsNullOrWhiteSpace($workerError)) {
            [System.Windows.MessageBoxImage]::Warning
        }
        else {
            [System.Windows.MessageBoxImage]::Information
        }
        Show-WmtMessageBox -Owner $previewWindow -Message $resultText -Title "Cleanup Results" -Image $icon | Out-Null
    }.GetNewClosure()

    $menuOpen.Add_Click({ & $openSelectedPath }.GetNewClosure())
    $menuDelete.Add_Click({
            if ($dg.SelectedItems.Count -gt 0) {
                & $invokePreviewDeletion -Targets @($dg.SelectedItems) -ActionTitle "Deleting Preview Items"
            }
        }.GetNewClosure())
    $dg.Add_MouseDoubleClick({ & $openSelectedPath }.GetNewClosure())
    $chkHideProtected.Add_Checked({ & $refreshPreviewFilter }.GetNewClosure())
    $chkHideProtected.Add_Unchecked({ & $refreshPreviewFilter }.GetNewClosure())
    $btnClose.Add_Click({ $previewWindow.Close() }.GetNewClosure())
    $btnCleanSelected.Add_Click({
            if ($dg.SelectedItems.Count -gt 0) {
                & $invokePreviewDeletion -Targets @($dg.SelectedItems) -ActionTitle "Cleaning Selected Items"
            }
        }.GetNewClosure())
    $btnCleanAll.Add_Click({
            if ($previewRows.Count -eq 0) { return }
            $confirm = Show-WmtMessageBox -Owner $previewWindow -Message "Are you sure you want to permanently delete ALL $($previewRows.Count) files shown?" -Title "Confirm Clean All" -Button YesNo -Image Warning
            if ($confirm -eq [System.Windows.MessageBoxResult]::Yes) {
                & $invokePreviewDeletion -Targets @($previewRows) -ActionTitle "Cleaning All Preview Items"
            }
        }.GetNewClosure())

    $protectedPreviewCount = @($allPreviewRows.ToArray() | Where-Object { [bool]$_.IsProtected }).Count
    if ($protectedPreviewCount -gt 0) {
        Write-GuiLog "Analysis flagged $protectedPreviewCount protected or in-use item(s)."
    }
    & $refreshPreviewFilter
    $previewWindow.ShowDialog() | Out-Null
}

function Invoke-TempCleanup {
    # 1. GET SELECTION
    $uiResult = Show-WmtAdvancedCleanupSelectionWpf

    # FIX: Force the returned items into an array @() to prevent PowerShell
    # from unrolling single-item selections and losing the .Count property.
    $selections = @($uiResult.Items)

    if (-not $uiResult -or $selections.Count -eq 0) {
        Write-GuiLog "Cleanup/Analysis canceled: No items selected."
        return
    }

    $isAnalyze = ($uiResult.Action -eq "Analyze")

    # Generic List for high-performance preview tracking
    $previewList = New-Object System.Collections.Generic.List[PSCustomObject]

    # 2. SETUP PROGRESS UI
    [xml]$cleanupProgressXaml = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Width="520" Height="170" ResizeMode="NoResize" WindowStartupLocation="CenterOwner"
        Background="{DynamicResource BgDark}" Foreground="{DynamicResource TextPrimary}"
        FontFamily="Segoe UI Variable Display, Segoe UI, Arial" FontSize="13">
    <Grid Margin="20">
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>

        <TextBlock Name="pLabel" Text="Initializing..." Foreground="{DynamicResource TextPrimary}" TextTrimming="CharacterEllipsis"/>
        <TextBlock Name="pStatus" Grid.Row="1" Text="Preparing..." Foreground="{DynamicResource TextSecondary}" Margin="0,8,0,14" TextTrimming="CharacterEllipsis"/>
        <ProgressBar Name="pBar" Grid.Row="2" Minimum="0" Maximum="100" Height="12"/>
    </Grid>
</Window>
'@
    $pForm = New-WmtWindowFromFullXaml -Xaml $cleanupProgressXaml
    $pForm.Title = if ($isAnalyze) { "Analyzing System..." } else { "Deep Cleaning System" }
    $pLabel = $pForm.FindName("pLabel")
    $pStatus = $pForm.FindName("pStatus")
    $pBar = $pForm.FindName("pBar")
    $progressState = @{ Closed = $false }
    $pForm.Add_Closed({ $progressState.Closed = $true }.GetNewClosure())
    $pForm.Show()
    Invoke-WmtDispatcherPump -Dispatcher $pForm.Dispatcher

    # 3. STATS TRACKING
    $stats = @{
        Deleted  = 0
        Bytes    = 0
        Progress = 0.0
    }

    $ruleWeight = 100.0 / ($selections.Count)

    # --- HELPER: FILE SIZE FORMATTER ---
    function Format-FileSize {
        param([long]$Bytes)
        if ($Bytes -ge 1GB) { return "{0:N2} GB" -f ($Bytes / 1GB) }
        if ($Bytes -ge 1MB) { return "{0:N2} MB" -f ($Bytes / 1MB) }
        if ($Bytes -ge 1KB) { return "{0:N2} KB" -f ($Bytes / 1KB) }
        return "$Bytes B"
    }

    function Test-WmtCleanupPathStartsWith {
        param(
            [string]$Path,
            [string]$Root
        )

        if ([string]::IsNullOrWhiteSpace($Path) -or [string]::IsNullOrWhiteSpace($Root)) { return $false }

        try {
            $fullPath = [System.IO.Path]::GetFullPath($Path).TrimEnd("\")
            $fullRoot = [System.IO.Path]::GetFullPath($Root).TrimEnd("\")
            return ($fullPath.Equals($fullRoot, [System.StringComparison]::OrdinalIgnoreCase) -or
                $fullPath.StartsWith($fullRoot + "\", [System.StringComparison]::OrdinalIgnoreCase))
        }
        catch {
            return $false
        }
    }

    function Get-WmtCleanupProtectionInfo {
        param(
            [string]$Path,
            [System.IO.FileSystemInfo]$ItemInfo = $null
        )

        $reasons = [System.Collections.Generic.List[string]]::new()

        if ([string]::IsNullOrWhiteSpace($Path)) {
            return [PSCustomObject]@{ IsProtected = $false; Reason = "" }
        }

        try {
            if (-not $ItemInfo) {
                $ItemInfo = Get-Item -LiteralPath $Path -Force -ErrorAction Stop
            }
        }
        catch [System.UnauthorizedAccessException] {
            [void]$reasons.Add("Access denied")
        }
        catch {
            if ($_.Exception.Message -match "(?i)access.*denied|unauthorized") {
                [void]$reasons.Add("Access denied")
            }
        }

        if ($ItemInfo) {
            try {
                $attrs = $ItemInfo.Attributes
                if (($attrs -band [System.IO.FileAttributes]::System) -eq [System.IO.FileAttributes]::System) {
                    [void]$reasons.Add("System attribute")
                }

                $protectedRoots = @(
                    "$env:SystemRoot\Temp",
                    "$env:SystemRoot\System32",
                    "$env:SystemRoot\SysWOW64",
                    "$env:SystemRoot\WinSxS",
                    "$env:SystemRoot\servicing",
                    "$env:SystemRoot\SystemResources",
                    "$env:ProgramFiles\WindowsApps",
                    "$env:ProgramFiles\Windows Defender",
                    "${env:ProgramFiles(x86)}\Windows Defender",
                    "$env:ProgramData\Microsoft\Windows Defender"
                ) | Where-Object { -not [string]::IsNullOrWhiteSpace($_) }

                $isSystemArea = $false
                foreach ($root in $protectedRoots) {
                    if (Test-WmtCleanupPathStartsWith -Path $ItemInfo.FullName -Root $root) {
                        $isSystemArea = $true
                        break
                    }
                }

                if ($isSystemArea -or (($attrs -band [System.IO.FileAttributes]::System) -eq [System.IO.FileAttributes]::System)) {
                    try {
                        $owner = [string](Get-Acl -LiteralPath $ItemInfo.FullName -ErrorAction Stop).Owner
                        if ($owner -match "(?i)TrustedInstaller|NT AUTHORITY\\SYSTEM|^SYSTEM$") {
                            [void]$reasons.Add("System-owned")
                        }
                    }
                    catch {
                        if ($_.Exception.Message -match "(?i)access.*denied|unauthorized") {
                            [void]$reasons.Add("Access denied")
                        }
                    }
                }

                if (-not $ItemInfo.PSIsContainer) {
                    $stream = $null
                    try {
                        $stream = [System.IO.File]::Open($ItemInfo.FullName, [System.IO.FileMode]::Open, [System.IO.FileAccess]::Read, [System.IO.FileShare]::None)
                    }
                    catch [System.UnauthorizedAccessException] {
                        [void]$reasons.Add("Access denied")
                    }
                    catch [System.IO.IOException] {
                        [void]$reasons.Add("In use")
                    }
                    catch {}
                    finally {
                        if ($stream) {
                            try { $stream.Close() } catch {}
                            try { $stream.Dispose() } catch {}
                        }
                    }
                }
            }
            catch {}
        }

        $reasonText = (@($reasons.ToArray()) | Select-Object -Unique) -join ", "
        return [PSCustomObject]@{
            IsProtected = -not [string]::IsNullOrWhiteSpace($reasonText)
            Reason      = $reasonText
        }
    }

    # --- HELPER: ROBUST CLEANER ---
    function Invoke-RobustClean {
        param($Path, $Pattern = "*", $Recurse = $true, $RuleName = "System File")

        $Path = [Environment]::ExpandEnvironmentVariables($Path)
        $pathHasWildcard = ($Path -match '[\*\?]')
        if (-not $pathHasWildcard -and -not (Test-Path -LiteralPath $Path)) { return }

        $pStatus.Text = "Scanning: $(Split-Path $Path -Leaf)"
        Invoke-WmtDispatcherPump -Dispatcher $pForm.Dispatcher

        try {
            $batchCount = 0
            $patterns = @($Pattern -split ';' | ForEach-Object { ([string]$_).Trim() } | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
            if ($patterns.Count -eq 0) { $patterns = @("*") }

            $roots = @()
            if ($pathHasWildcard) {
                $roots = @(Get-ChildItem -Path $Path -Force -ErrorAction SilentlyContinue)
            }
            else {
                $roots = @(Get-Item -LiteralPath $Path -Force -ErrorAction SilentlyContinue)
            }

            foreach ($root in $roots) {
                if (-not $root) { continue }

                if (-not $root.PSIsContainer) {
                    foreach ($patternItem in $patterns) {
                        if ($root.Name -like $patternItem) {
                            Add-WmtCleanupTarget -Path $root.FullName -RuleName $RuleName
                            $batchCount++
                            break
                        }
                    }
                }
                else {
                    foreach ($patternItem in $patterns) {
                        foreach ($file in @(Get-ChildItem -LiteralPath $root.FullName -Filter $patternItem -File -Recurse:$Recurse -Force -ErrorAction SilentlyContinue)) {
                            Add-WmtCleanupTarget -Path $file.FullName -RuleName $RuleName
                            $batchCount++

                            if ($batchCount -gt 50) {
                                $mb = [math]::Round($stats.Bytes / 1MB, 2)
                                $verb = if ($isAnalyze) { "Found" } else { "Removed" }
                                $pLabel.Text = "${verb}: $($stats.Deleted) | Space: $mb MB"
                                Invoke-WmtDispatcherPump -Dispatcher $pForm.Dispatcher
                                $batchCount = 0
                            }
                        }
                    }
                }
            }

            if ($Recurse) {
                if (-not $isAnalyze) {
                    Remove-WmtEmptyChildDirectories -Path $Path
                }
            }
        }
        catch {}
    }

    function Add-WmtCleanupTarget {
        param(
            [string]$Path,
            [string]$RuleName = "System File"
        )

        if ([string]::IsNullOrWhiteSpace($Path) -or -not (Test-Path -LiteralPath $Path)) { return }

        try {
            $itemInfo = Get-Item -LiteralPath $Path -Force -ErrorAction Stop
            $size = if ($itemInfo.PSIsContainer) { Measure-WmtPathBytes -Path $Path } else { [int64]$itemInfo.Length }

            if (-not $isAnalyze) {
                if (-not $itemInfo.PSIsContainer) {
                    try { $itemInfo.Attributes = [System.IO.FileAttributes]::Normal } catch {}
                }
                Remove-Item -LiteralPath $Path -Recurse -Force -ErrorAction Stop
            }
            else {
                $protectionInfo = Get-WmtCleanupProtectionInfo -Path $Path -ItemInfo $itemInfo
                $previewList.Add([PSCustomObject]@{
                        RuleName         = $RuleName
                        FilePath         = $Path
                        RawBytes         = $size
                        IsProtected      = [bool]$protectionInfo.IsProtected
                        ProtectionReason = [string]$protectionInfo.Reason
                    })
            }

            $stats.Deleted++
            $stats.Bytes += $size
        }
        catch {}
    }

    function Test-WmtCleanerMlTargetMatch {
        param(
            [System.IO.FileSystemInfo]$Item,
            $Rule
        )

        if (-not $Item) { return $false }
        $type = [string]$Rule.Type
        if ($type -eq "f" -and $Item.PSIsContainer) { return $false }
        if ($type -eq "d" -and -not $Item.PSIsContainer) { return $false }

        $leaf = $Item.Name
        $full = $Item.FullName
        $regexOptions = [System.Text.RegularExpressions.RegexOptions]::IgnoreCase

        try {
            if ($Rule.Regex -and -not [regex]::IsMatch($leaf, [string]$Rule.Regex, $regexOptions)) { return $false }
            if ($Rule.WholeRegex -and -not [regex]::IsMatch($full, [string]$Rule.WholeRegex, $regexOptions)) { return $false }
            if ($Rule.NRegex -and [regex]::IsMatch($leaf, [string]$Rule.NRegex, $regexOptions)) { return $false }
            if ($Rule.NWholeRegex -and [regex]::IsMatch($full, [string]$Rule.NWholeRegex, $regexOptions)) { return $false }
        }
        catch {
            return $false
        }

        return $true
    }

    function Invoke-CleanerMlClean {
        param(
            $Rule,
            [string]$RuleName
        )

        $path = [Environment]::ExpandEnvironmentVariables([string]$Rule.Path)
        if ([string]::IsNullOrWhiteSpace($path)) { return }

        $search = if ($Rule.Search) { [string]$Rule.Search } else { "file" }
        $targets = New-Object System.Collections.Generic.List[System.IO.FileSystemInfo]

        try {
            switch ($search) {
                "file" {
                    if ($path -match '[\*\?]') {
                        foreach ($target in @(Get-ChildItem -Path $path -Force -ErrorAction SilentlyContinue)) {
                            if (Test-WmtCleanerMlTargetMatch -Item $target -Rule $Rule) { [void]$targets.Add($target) }
                        }
                    }
                    elseif (Test-Path -LiteralPath $path) {
                        $target = Get-Item -LiteralPath $path -Force -ErrorAction SilentlyContinue
                        if (Test-WmtCleanerMlTargetMatch -Item $target -Rule $Rule) { [void]$targets.Add($target) }
                    }
                }
                "glob" {
                    foreach ($target in @(Get-ChildItem -Path $path -Force -ErrorAction SilentlyContinue)) {
                        if (Test-WmtCleanerMlTargetMatch -Item $target -Rule $Rule) { [void]$targets.Add($target) }
                    }
                }
                "walk.files" {
                    $roots = @(Get-ChildItem -Path $path -Force -ErrorAction SilentlyContinue)
                    if ((Test-Path -LiteralPath $path) -and -not ($path -match '[\*\?]')) {
                        $roots = @(Get-Item -LiteralPath $path -Force -ErrorAction SilentlyContinue)
                    }
                    foreach ($root in $roots) {
                        if (-not $root) { continue }
                        if (-not $root.PSIsContainer) {
                            if (Test-WmtCleanerMlTargetMatch -Item $root -Rule $Rule) { [void]$targets.Add($root) }
                            continue
                        }
                        foreach ($target in @(Get-ChildItem -LiteralPath $root.FullName -File -Recurse -Force -ErrorAction SilentlyContinue)) {
                            if (Test-WmtCleanerMlTargetMatch -Item $target -Rule $Rule) { [void]$targets.Add($target) }
                        }
                    }
                }
                "walk.all" {
                    $roots = @(Get-ChildItem -Path $path -Force -ErrorAction SilentlyContinue)
                    if ((Test-Path -LiteralPath $path) -and -not ($path -match '[\*\?]')) {
                        $roots = @(Get-Item -LiteralPath $path -Force -ErrorAction SilentlyContinue)
                    }
                    foreach ($root in $roots) {
                        if (-not $root) { continue }
                        if (Test-WmtCleanerMlTargetMatch -Item $root -Rule $Rule) { [void]$targets.Add($root) }
                        if ($root.PSIsContainer) {
                            foreach ($target in @(Get-ChildItem -LiteralPath $root.FullName -Recurse -Force -ErrorAction SilentlyContinue)) {
                                if (Test-WmtCleanerMlTargetMatch -Item $target -Rule $Rule) { [void]$targets.Add($target) }
                            }
                        }
                    }
                }
                "walk.top" {
                    if (Test-Path -LiteralPath $path) {
                        $root = Get-Item -LiteralPath $path -Force -ErrorAction SilentlyContinue
                        if ($root -and (Test-WmtCleanerMlTargetMatch -Item $root -Rule $Rule)) { [void]$targets.Add($root) }
                        if ($root -and $root.PSIsContainer) {
                            foreach ($target in @(Get-ChildItem -LiteralPath $root.FullName -Force -ErrorAction SilentlyContinue)) {
                                if (Test-WmtCleanerMlTargetMatch -Item $target -Rule $Rule) { [void]$targets.Add($target) }
                            }
                        }
                    }
                }
                "deep" {
                    if (Test-Path -LiteralPath $path) {
                        $pStatus.Text = "Deep scan: $(Split-Path $path -Leaf)"
                        Invoke-WmtDispatcherPump -Dispatcher $pForm.Dispatcher
                        $root = Get-Item -LiteralPath $path -Force -ErrorAction SilentlyContinue
                        if ($root -and (Test-WmtCleanerMlTargetMatch -Item $root -Rule $Rule)) { [void]$targets.Add($root) }
                        if ($root -and $root.PSIsContainer) {
                            foreach ($target in @(Get-ChildItem -LiteralPath $root.FullName -Recurse -Force -ErrorAction SilentlyContinue)) {
                                if (Test-WmtCleanerMlTargetMatch -Item $target -Rule $Rule) { [void]$targets.Add($target) }
                            }
                        }
                    }
                }
            }

            foreach ($target in @($targets.ToArray() | Sort-Object FullName -Unique)) {
                Add-WmtCleanupTarget -Path $target.FullName -RuleName $RuleName
            }
        }
        catch {}
    }

    function Invoke-ThumbsDbDeepScan {
        param([string]$RuleName)

        $rule = [PSCustomObject]@{
            Path        = $env:USERPROFILE
            Search      = "deep"
            Regex       = "^Thumbs\.db(:encryptable)?$"
            WholeRegex  = ""
            NRegex      = ""
            NWholeRegex = ""
            Type        = "f"
        }
        Invoke-CleanerMlClean -Rule $rule -RuleName $RuleName
    }

    function Get-WmtCleanupObjectValue {
        param(
            $InputObject,
            [string]$Name,
            $Default = $null
        )

        if ($null -eq $InputObject -or [string]::IsNullOrWhiteSpace($Name)) { return $Default }

        try {
            if ($InputObject -is [System.Collections.IDictionary]) {
                if ($InputObject.Contains($Name)) { return $InputObject[$Name] }
                if ($InputObject.ContainsKey($Name)) { return $InputObject[$Name] }
            }
        }
        catch {}

        try {
            $prop = $InputObject.PSObject.Properties[$Name]
            if ($prop) { return $prop.Value }
        }
        catch {}

        return $Default
    }

    function Test-WmtCleanupObjectFlag {
        param(
            $InputObject,
            [string]$Name
        )

        try { return [bool](Get-WmtCleanupObjectValue -InputObject $InputObject -Name $Name -Default $false) }
        catch { return $false }
    }

    function Get-WmtCleanupItemPaths {
        param($Item)

        $paths = Get-WmtCleanupObjectValue -InputObject $Item -Name "Paths" -Default $null
        if ($null -eq $paths) { return @() }
        if ($paths -is [string]) { return @() }
        if ($paths -is [System.Collections.IDictionary]) { return , $paths }
        return @($paths)
    }

    function ConvertTo-WmtWinapp2PathRule {
        param($Rule)

        $path = ([string](Get-WmtCleanupObjectValue -InputObject $Rule -Name "Path" -Default "")).Trim()
        if ([string]::IsNullOrWhiteSpace($path)) { return $null }

        $pattern = ([string](Get-WmtCleanupObjectValue -InputObject $Rule -Name "Pattern" -Default "*")).Trim()
        if ([string]::IsNullOrWhiteSpace($pattern)) { $pattern = "*" }

        $options = ([string](Get-WmtCleanupObjectValue -InputObject $Rule -Name "Options" -Default "")).Trim()
        $hasRecurseFlag = ($options -match "(?i)(^|[\s,;|])(RECURSE|REMOVESELF)($|[\s,;|])")
        $hasRemoveSelfFlag = ($options -match "(?i)(^|[\s,;|])REMOVESELF($|[\s,;|])")

        return [PSCustomObject]@{
            Path       = $path
            Pattern    = $pattern
            Options    = $options
            Recurse    = [bool]$hasRecurseFlag
            RemoveSelf = [bool]$hasRemoveSelfFlag
        }
    }

    function Get-WmtCleanupItemDisplayName {
        param($Item)

        if ($Item -is [string]) {
            if ($internalRuleDisplayNames.ContainsKey($Item)) { return $internalRuleDisplayNames[$Item] }
            return $Item
        }

        $name = ([string](Get-WmtCleanupObjectValue -InputObject $Item -Name "Name" -Default "")).Trim().Trim(" *")
        if ([string]::IsNullOrWhiteSpace($name)) { return [string](Get-WmtCleanupObjectValue -InputObject $Item -Name "ID" -Default "") }
        return $name
    }

    function New-WmtAnalyzeScanTasks {
        param($Items)

        $tasks = [System.Collections.Generic.List[object]]::new()
        foreach ($item in $Items) {
            $itemName = Get-WmtCleanupItemDisplayName -Item $item
            $itemPaths = @(Get-WmtCleanupItemPaths -Item $item)

            if (Test-WmtCleanupObjectFlag -InputObject $item -Name "IsCleanerML") {
                foreach ($rule in $itemPaths) {
                    $path = ([string](Get-WmtCleanupObjectValue -InputObject $rule -Name "Path" -Default "")).Trim()
                    if ([string]::IsNullOrWhiteSpace($path)) { continue }
                    [void]$tasks.Add([PSCustomObject]@{
                            Engine      = "CleanerML"
                            RuleName    = $itemName
                            Path        = $path
                            Search      = [string](Get-WmtCleanupObjectValue -InputObject $rule -Name "Search" -Default "file")
                            Regex       = [string](Get-WmtCleanupObjectValue -InputObject $rule -Name "Regex" -Default "")
                            WholeRegex  = [string](Get-WmtCleanupObjectValue -InputObject $rule -Name "WholeRegex" -Default "")
                            NRegex      = [string](Get-WmtCleanupObjectValue -InputObject $rule -Name "NRegex" -Default "")
                            NWholeRegex = [string](Get-WmtCleanupObjectValue -InputObject $rule -Name "NWholeRegex" -Default "")
                            Type        = [string](Get-WmtCleanupObjectValue -InputObject $rule -Name "Type" -Default "")
                        })
                }
            }
            elseif ($itemPaths.Count -gt 0 -and -not ($item -is [string])) {
                foreach ($rawRule in $itemPaths) {
                    $rule = ConvertTo-WmtWinapp2PathRule -Rule $rawRule
                    if (-not $rule) { continue }
                    [void]$tasks.Add([PSCustomObject]@{
                            Engine   = "Robust"
                            RuleName = $itemName
                            Path     = [string]$rule.Path
                            Pattern  = [string]$rule.Pattern
                            Recurse  = [bool]$rule.Recurse
                        })
                }
            }
            else {
                switch ($item) {
                    "TempFiles" {
                        [void]$tasks.Add([PSCustomObject]@{ Engine = "Robust"; RuleName = $itemName; Path = $env:TEMP; Pattern = "*"; Recurse = $true })
                        [void]$tasks.Add([PSCustomObject]@{ Engine = "Robust"; RuleName = $itemName; Path = "$env:SystemRoot\Temp"; Pattern = "*"; Recurse = $true })
                    }
                    "RecycleBin" { [void]$tasks.Add([PSCustomObject]@{ Engine = "RecycleBin"; RuleName = $itemName }) }
                    "WER" { [void]$tasks.Add([PSCustomObject]@{ Engine = "Robust"; RuleName = $itemName; Path = "$env:ProgramData\Microsoft\Windows\WER"; Pattern = "*"; Recurse = $true }) }
                    "Thumbnails" { [void]$tasks.Add([PSCustomObject]@{ Engine = "Robust"; RuleName = $itemName; Path = "$env:LOCALAPPDATA\Microsoft\Windows\Explorer"; Pattern = "thumbcache_*.db"; Recurse = $false }) }
                    "ThumbsDb" { [void]$tasks.Add([PSCustomObject]@{ Engine = "CleanerML"; RuleName = $itemName; Path = $env:USERPROFILE; Search = "deep"; Regex = "^Thumbs\.db(:encryptable)?$"; WholeRegex = ""; NRegex = ""; NWholeRegex = ""; Type = "f" }) }
                    "Recent" { [void]$tasks.Add([PSCustomObject]@{ Engine = "Robust"; RuleName = $itemName; Path = "$env:APPDATA\Microsoft\Windows\Recent"; Pattern = "*"; Recurse = $true }) }
                    "Edge" { [void]$tasks.Add([PSCustomObject]@{ Engine = "Robust"; RuleName = $itemName; Path = "$env:LOCALAPPDATA\Microsoft\Edge\User Data\Default\Cache"; Pattern = "*"; Recurse = $true }) }
                    "Chrome" { [void]$tasks.Add([PSCustomObject]@{ Engine = "Robust"; RuleName = $itemName; Path = "$env:LOCALAPPDATA\Google\Chrome\User Data\Default\Cache"; Pattern = "*"; Recurse = $true }) }
                    "Brave" { [void]$tasks.Add([PSCustomObject]@{ Engine = "Robust"; RuleName = $itemName; Path = "$env:LOCALAPPDATA\BraveSoftware\Brave-Browser\User Data\Default\Cache"; Pattern = "*"; Recurse = $true }) }
                    "Firefox" {
                        if (Test-Path "$env:LOCALAPPDATA\Mozilla\Firefox\Profiles") {
                            try {
                                foreach ($profilePath in [System.IO.Directory]::EnumerateDirectories("$env:LOCALAPPDATA\Mozilla\Firefox\Profiles")) {
                                    [void]$tasks.Add([PSCustomObject]@{ Engine = "Robust"; RuleName = $itemName; Path = "$profilePath\cache2\entries"; Pattern = "*"; Recurse = $true })
                                }
                            }
                            catch {}
                        }
                    }
                    "Opera" { [void]$tasks.Add([PSCustomObject]@{ Engine = "Robust"; RuleName = $itemName; Path = "$env:APPDATA\Opera Software\Opera Stable\Cache"; Pattern = "*"; Recurse = $true }) }
                    "OperaGX" { [void]$tasks.Add([PSCustomObject]@{ Engine = "Robust"; RuleName = $itemName; Path = "$env:APPDATA\Opera Software\Opera GX Stable\Cache"; Pattern = "*"; Recurse = $true }) }
                }
            }
        }

        return $tasks.ToArray()
    }

    function Invoke-WmtOutOfProcessAnalyze {
        param($ScanTasks)

        $tasks = @($ScanTasks)
        if ($tasks.Count -eq 0) { return }

        $jobScript = {
            param($Task)

            $ErrorActionPreference = "SilentlyContinue"
            $results = [System.Collections.Generic.List[object]]::new()

            function Measure-WorkerPathBytes {
                param([string]$Path)

                try {
                    $item = Get-Item -LiteralPath $Path -Force -ErrorAction Stop
                    if (-not $item.PSIsContainer) { return [int64]$item.Length }

                    $total = [int64]0
                    foreach ($file in @(Get-ChildItem -LiteralPath $Path -File -Recurse -Force -ErrorAction SilentlyContinue)) {
                        try { $total += [int64]$file.Length } catch {}
                    }
                    return $total
                }
                catch { return [int64]0 }
            }

            function Test-WorkerPathStartsWith {
                param(
                    [string]$Path,
                    [string]$Root
                )

                if ([string]::IsNullOrWhiteSpace($Path) -or [string]::IsNullOrWhiteSpace($Root)) { return $false }

                try {
                    $fullPath = [System.IO.Path]::GetFullPath($Path).TrimEnd("\")
                    $fullRoot = [System.IO.Path]::GetFullPath($Root).TrimEnd("\")
                    return ($fullPath.Equals($fullRoot, [System.StringComparison]::OrdinalIgnoreCase) -or
                        $fullPath.StartsWith($fullRoot + "\", [System.StringComparison]::OrdinalIgnoreCase))
                }
                catch {
                    return $false
                }
            }

            function Get-WorkerProtectionInfo {
                param(
                    [string]$Path,
                    [System.IO.FileSystemInfo]$ItemInfo = $null
                )

                $reasons = [System.Collections.Generic.List[string]]::new()

                if ([string]::IsNullOrWhiteSpace($Path)) {
                    return [PSCustomObject]@{ IsProtected = $false; Reason = "" }
                }

                try {
                    if (-not $ItemInfo) {
                        $ItemInfo = Get-Item -LiteralPath $Path -Force -ErrorAction Stop
                    }
                }
                catch [System.UnauthorizedAccessException] {
                    [void]$reasons.Add("Access denied")
                }
                catch {
                    if ($_.Exception.Message -match "(?i)access.*denied|unauthorized") {
                        [void]$reasons.Add("Access denied")
                    }
                }

                if ($ItemInfo) {
                    try {
                        $attrs = $ItemInfo.Attributes
                        if (($attrs -band [System.IO.FileAttributes]::System) -eq [System.IO.FileAttributes]::System) {
                            [void]$reasons.Add("System attribute")
                        }

                        $protectedRoots = @(
                            "$env:SystemRoot\Temp",
                            "$env:SystemRoot\System32",
                            "$env:SystemRoot\SysWOW64",
                            "$env:SystemRoot\WinSxS",
                            "$env:SystemRoot\servicing",
                            "$env:SystemRoot\SystemResources",
                            "$env:ProgramFiles\WindowsApps",
                            "$env:ProgramFiles\Windows Defender",
                            "${env:ProgramFiles(x86)}\Windows Defender",
                            "$env:ProgramData\Microsoft\Windows Defender"
                        ) | Where-Object { -not [string]::IsNullOrWhiteSpace($_) }

                        $isSystemArea = $false
                        foreach ($root in $protectedRoots) {
                            if (Test-WorkerPathStartsWith -Path $ItemInfo.FullName -Root $root) {
                                $isSystemArea = $true
                                break
                            }
                        }

                        if ($isSystemArea -or (($attrs -band [System.IO.FileAttributes]::System) -eq [System.IO.FileAttributes]::System)) {
                            try {
                                $owner = [string](Get-Acl -LiteralPath $ItemInfo.FullName -ErrorAction Stop).Owner
                                if ($owner -match "(?i)TrustedInstaller|NT AUTHORITY\\SYSTEM|^SYSTEM$") {
                                    [void]$reasons.Add("System-owned")
                                }
                            }
                            catch {
                                if ($_.Exception.Message -match "(?i)access.*denied|unauthorized") {
                                    [void]$reasons.Add("Access denied")
                                }
                            }
                        }

                        if (-not $ItemInfo.PSIsContainer) {
                            $stream = $null
                            try {
                                $stream = [System.IO.File]::Open($ItemInfo.FullName, [System.IO.FileMode]::Open, [System.IO.FileAccess]::Read, [System.IO.FileShare]::None)
                            }
                            catch [System.UnauthorizedAccessException] {
                                [void]$reasons.Add("Access denied")
                            }
                            catch [System.IO.IOException] {
                                [void]$reasons.Add("In use")
                            }
                            catch {}
                            finally {
                                if ($stream) {
                                    try { $stream.Close() } catch {}
                                    try { $stream.Dispose() } catch {}
                                }
                            }
                        }
                    }
                    catch {}
                }

                $reasonText = (@($reasons.ToArray()) | Select-Object -Unique) -join ", "
                return [PSCustomObject]@{
                    IsProtected = -not [string]::IsNullOrWhiteSpace($reasonText)
                    Reason      = $reasonText
                }
            }

            function Add-WorkerTarget {
                param([string]$Path, [string]$RuleName)

                if ([string]::IsNullOrWhiteSpace($Path) -or -not (Test-Path -LiteralPath $Path)) { return }
                try {
                    $itemInfo = Get-Item -LiteralPath $Path -Force -ErrorAction SilentlyContinue
                    $size = Measure-WorkerPathBytes -Path $Path
                    $protectionInfo = Get-WorkerProtectionInfo -Path $Path -ItemInfo $itemInfo
                    [void]$results.Add([PSCustomObject]@{
                            RuleName         = $RuleName
                            FilePath         = $Path
                            RawBytes         = $size
                            IsProtected      = [bool]$protectionInfo.IsProtected
                            ProtectionReason = [string]$protectionInfo.Reason
                        })
                }
                catch {}
            }

            function Test-WorkerCleanerMlTargetMatch {
                param($Item, $Rule)

                if (-not $Item) { return $false }
                $type = [string]$Rule.Type
                if ($type -eq "f" -and $Item.PSIsContainer) { return $false }
                if ($type -eq "d" -and -not $Item.PSIsContainer) { return $false }

                $leaf = $Item.Name
                $full = $Item.FullName
                $regexOptions = [System.Text.RegularExpressions.RegexOptions]::IgnoreCase

                try {
                    if ($Rule.Regex -and -not [regex]::IsMatch($leaf, [string]$Rule.Regex, $regexOptions)) { return $false }
                    if ($Rule.WholeRegex -and -not [regex]::IsMatch($full, [string]$Rule.WholeRegex, $regexOptions)) { return $false }
                    if ($Rule.NRegex -and [regex]::IsMatch($leaf, [string]$Rule.NRegex, $regexOptions)) { return $false }
                    if ($Rule.NWholeRegex -and [regex]::IsMatch($full, [string]$Rule.NWholeRegex, $regexOptions)) { return $false }
                }
                catch { return $false }

                return $true
            }

            function Invoke-WorkerRobustScan {
                param($Task)

                $path = [Environment]::ExpandEnvironmentVariables([string]$Task.Path)
                $pathHasWildcard = ($path -match '[\*\?]')
                if (-not $pathHasWildcard -and -not (Test-Path -LiteralPath $path)) { return }

                $patterns = @([string]$Task.Pattern -split ';' | ForEach-Object { ([string]$_).Trim() } | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
                if ($patterns.Count -eq 0) { $patterns = @("*") }

                $roots = if ($pathHasWildcard) {
                    @(Get-ChildItem -Path $path -Force -ErrorAction SilentlyContinue)
                }
                else {
                    @(Get-Item -LiteralPath $path -Force -ErrorAction SilentlyContinue)
                }

                foreach ($root in $roots) {
                    if (-not $root) { continue }
                    if (-not $root.PSIsContainer) {
                        foreach ($patternItem in $patterns) {
                            if ($root.Name -like $patternItem) {
                                Add-WorkerTarget -Path $root.FullName -RuleName $Task.RuleName
                                break
                            }
                        }
                    }
                    else {
                        foreach ($patternItem in $patterns) {
                            foreach ($file in @(Get-ChildItem -LiteralPath $root.FullName -Filter $patternItem -File -Recurse:([bool]$Task.Recurse) -Force -ErrorAction SilentlyContinue)) {
                                Add-WorkerTarget -Path $file.FullName -RuleName $Task.RuleName
                            }
                        }
                    }
                }
            }

            function Invoke-WorkerCleanerMlScan {
                param($Task)

                $path = [Environment]::ExpandEnvironmentVariables([string]$Task.Path)
                if ([string]::IsNullOrWhiteSpace($path)) { return }

                $targets = [System.Collections.Generic.List[System.IO.FileSystemInfo]]::new()
                $search = if ($Task.Search) { [string]$Task.Search } else { "file" }

                switch ($search) {
                    "file" {
                        if ($path -match '[\*\?]') {
                            foreach ($target in @(Get-ChildItem -Path $path -Force -ErrorAction SilentlyContinue)) {
                                if (Test-WorkerCleanerMlTargetMatch -Item $target -Rule $Task) { [void]$targets.Add($target) }
                            }
                        }
                        elseif (Test-Path -LiteralPath $path) {
                            $target = Get-Item -LiteralPath $path -Force -ErrorAction SilentlyContinue
                            if (Test-WorkerCleanerMlTargetMatch -Item $target -Rule $Task) { [void]$targets.Add($target) }
                        }
                    }
                    "glob" {
                        foreach ($target in @(Get-ChildItem -Path $path -Force -ErrorAction SilentlyContinue)) {
                            if (Test-WorkerCleanerMlTargetMatch -Item $target -Rule $Task) { [void]$targets.Add($target) }
                        }
                    }
                    "walk.files" {
                        $roots = @(Get-ChildItem -Path $path -Force -ErrorAction SilentlyContinue)
                        if ((Test-Path -LiteralPath $path) -and -not ($path -match '[\*\?]')) {
                            $roots = @(Get-Item -LiteralPath $path -Force -ErrorAction SilentlyContinue)
                        }
                        foreach ($root in $roots) {
                            if (-not $root) { continue }
                            if (-not $root.PSIsContainer) {
                                if (Test-WorkerCleanerMlTargetMatch -Item $root -Rule $Task) { [void]$targets.Add($root) }
                                continue
                            }
                            foreach ($target in @(Get-ChildItem -LiteralPath $root.FullName -File -Recurse -Force -ErrorAction SilentlyContinue)) {
                                if (Test-WorkerCleanerMlTargetMatch -Item $target -Rule $Task) { [void]$targets.Add($target) }
                            }
                        }
                    }
                    "walk.all" {
                        $roots = @(Get-ChildItem -Path $path -Force -ErrorAction SilentlyContinue)
                        if ((Test-Path -LiteralPath $path) -and -not ($path -match '[\*\?]')) {
                            $roots = @(Get-Item -LiteralPath $path -Force -ErrorAction SilentlyContinue)
                        }
                        foreach ($root in $roots) {
                            if (-not $root) { continue }
                            if (Test-WorkerCleanerMlTargetMatch -Item $root -Rule $Task) { [void]$targets.Add($root) }
                            if ($root.PSIsContainer) {
                                foreach ($target in @(Get-ChildItem -LiteralPath $root.FullName -Recurse -Force -ErrorAction SilentlyContinue)) {
                                    if (Test-WorkerCleanerMlTargetMatch -Item $target -Rule $Task) { [void]$targets.Add($target) }
                                }
                            }
                        }
                    }
                    "walk.top" {
                        if (Test-Path -LiteralPath $path) {
                            $root = Get-Item -LiteralPath $path -Force -ErrorAction SilentlyContinue
                            if ($root -and (Test-WorkerCleanerMlTargetMatch -Item $root -Rule $Task)) { [void]$targets.Add($root) }
                            if ($root -and $root.PSIsContainer) {
                                foreach ($target in @(Get-ChildItem -LiteralPath $root.FullName -Force -ErrorAction SilentlyContinue)) {
                                    if (Test-WorkerCleanerMlTargetMatch -Item $target -Rule $Task) { [void]$targets.Add($target) }
                                }
                            }
                        }
                    }
                    "deep" {
                        if (Test-Path -LiteralPath $path) {
                            $root = Get-Item -LiteralPath $path -Force -ErrorAction SilentlyContinue
                            if ($root -and (Test-WorkerCleanerMlTargetMatch -Item $root -Rule $Task)) { [void]$targets.Add($root) }
                            if ($root -and $root.PSIsContainer) {
                                foreach ($target in @(Get-ChildItem -LiteralPath $root.FullName -Recurse -Force -ErrorAction SilentlyContinue)) {
                                    if (Test-WorkerCleanerMlTargetMatch -Item $target -Rule $Task) { [void]$targets.Add($target) }
                                }
                            }
                        }
                    }
                }

                foreach ($target in @($targets.ToArray() | Sort-Object FullName -Unique)) {
                    Add-WorkerTarget -Path $target.FullName -RuleName $Task.RuleName
                }
            }

            function Invoke-WorkerRecycleBinScan {
                param($Task)

                try {
                    $shell = New-Object -ComObject Shell.Application
                    $bin = $shell.Namespace(0xA)
                    foreach ($f in @($bin.Items())) {
                        try {
                            $path = $f.Path
                            if ($path -and (Test-Path -LiteralPath $path)) {
                                Add-WorkerTarget -Path $path -RuleName $Task.RuleName
                            }
                        }
                        catch {}
                    }
                }
                catch {}
            }

            switch ([string]$Task.Engine) {
                "Robust" { Invoke-WorkerRobustScan -Task $Task }
                "CleanerML" { Invoke-WorkerCleanerMlScan -Task $Task }
                "RecycleBin" { Invoke-WorkerRecycleBinScan -Task $Task }
            }

            return $results.ToArray()
        }

        $maxParallel = [Math]::Max(1, [Math]::Min(4, [Environment]::ProcessorCount))
        $queue = [System.Collections.Generic.Queue[object]]::new()
        foreach ($task in $tasks) { $queue.Enqueue($task) }

        $running = @{}
        $completed = 0
        $total = $tasks.Count
        Write-GuiLog "Analyze scanner: starting $total task(s), up to $maxParallel out-of-process worker(s)."

        while ($queue.Count -gt 0 -or $running.Count -gt 0) {
            while ($queue.Count -gt 0 -and $running.Count -lt $maxParallel) {
                $task = $queue.Dequeue()
                $job = Start-Job -ScriptBlock $jobScript -ArgumentList @($task)
                $running[[int]$job.Id] = [PSCustomObject]@{ Job = $job; Task = $task }
                $pStatus.Text = "Scanning: $($task.RuleName)"
            }

            foreach ($entry in @($running.GetEnumerator())) {
                $job = $entry.Value.Job
                if ($job.State -notin @("Completed", "Failed", "Stopped")) { continue }

                $task = $entry.Value.Task
                $rows = @()
                try { $rows = @(Receive-Job -Job $job -ErrorAction SilentlyContinue) } catch {}
                foreach ($row in $rows) {
                    if (-not $row.FilePath) { continue }
                    $rawBytes = [int64]0
                    try { $rawBytes = [int64]$row.RawBytes } catch {}
                    $previewList.Add([PSCustomObject]@{
                            RuleName         = [string]$row.RuleName
                            FilePath         = [string]$row.FilePath
                            RawBytes         = $rawBytes
                            IsProtected      = [bool]$row.IsProtected
                            ProtectionReason = [string]$row.ProtectionReason
                        })
                    $stats.Deleted++
                    $stats.Bytes += $rawBytes
                }

                try { Remove-Job -Job $job -Force -ErrorAction SilentlyContinue } catch {}
                $running.Remove($entry.Key)
                $completed++

                $stats.Progress = (100.0 * $completed / [Math]::Max(1, $total))
                $pBar.Value = [Math]::Min(100, [int]$stats.Progress)
                $mb = [math]::Round($stats.Bytes / 1MB, 2)
                $pLabel.Text = "Found: $($stats.Deleted) | Space: $mb MB"
                $pStatus.Text = "Finished: $($task.RuleName)"
            }

            Invoke-WmtDispatcherPump -Dispatcher $pForm.Dispatcher
            Start-Sleep -Milliseconds 120

            if ($progressState.Closed) {
                foreach ($entry in @($running.GetEnumerator())) {
                    try { Stop-Job -Job $entry.Value.Job -Force -ErrorAction SilentlyContinue } catch {}
                    try { Remove-Job -Job $entry.Value.Job -Force -ErrorAction SilentlyContinue } catch {}
                }
                break
            }
        }
    }

    # 4. MAIN EXECUTION LOOP
    $actionText = if ($isAnalyze) { "Analyzing" } else { "Cleaning" }
    Write-GuiLog "--- Starting $actionText ---"
    $internalRuleDisplayNames = @{
        "TempFiles"  = "Temporary Files"
        "RecycleBin" = "Recycle Bin"
        "WER"        = "Error Logs (WER)"
        "DNS"        = "DNS Cache"
        "Thumbnails" = "Thumbnail / Thumbs Cache"
        "ThumbsDb"   = "Deep Scan: Thumbs.db"
        "Recent"     = "Recent Items"
        "RunMRU"     = "Run History"
        "Edge"       = "Microsoft Edge Cache"
        "Chrome"     = "Google Chrome Cache"
        "Brave"      = "Brave Cache"
        "Firefox"    = "Mozilla Firefox Cache"
        "Opera"      = "Opera Cache"
        "OperaGX"    = "Opera GX Cache"
    }

    $usedOutOfProcessAnalyze = $false
    if ($isAnalyze) {
        try {
            $scanTasks = @(New-WmtAnalyzeScanTasks -Items $selections)
            if ($scanTasks.Count -gt 0) {
                Invoke-WmtOutOfProcessAnalyze -ScanTasks $scanTasks
                $usedOutOfProcessAnalyze = $true
            }
        }
        catch {
            Write-GuiLog "Out-of-process analyzer failed; falling back to in-process scan: $($_.Exception.Message)"
            $usedOutOfProcessAnalyze = $false
        }
    }

    try {
        if (-not $usedOutOfProcessAnalyze) {
            foreach ($item in $selections) {
                if ($progressState.Closed) { break }

                $startBytes = $stats.Bytes

                $stats.Progress += $ruleWeight
                $pBar.Value = [Math]::Min(100, [int]$stats.Progress)

                $itemName = Get-WmtCleanupItemDisplayName -Item $item
                $pLabel.Text = "${actionText}: $itemName"

                $itemPaths = @(Get-WmtCleanupItemPaths -Item $item)

                # --- A. BLEACHBIT CLEANERML RULES ---
                if (Test-WmtCleanupObjectFlag -InputObject $item -Name "IsCleanerML") {
                    foreach ($rule in $itemPaths) {
                        Invoke-CleanerMlClean -Rule $rule -RuleName $itemName
                    }
                }
                # --- B. WINAPP2 RULES ---
                elseif ($itemPaths.Count -gt 0 -and -not ($item -is [string])) {
                    foreach ($rawRule in $itemPaths) {
                        $rule = ConvertTo-WmtWinapp2PathRule -Rule $rawRule
                        if (-not $rule) { continue }
                        Invoke-RobustClean -Path $rule.Path -Pattern $rule.Pattern -Recurse ([bool]$rule.Recurse) -RuleName $itemName
                    }
                }
                # --- C. INTERNAL RULES ---
                else {
                    switch ($item) {
                        "TempFiles" {
                            Invoke-RobustClean $env:TEMP -RuleName $itemName
                            Invoke-RobustClean "$env:SystemRoot\Temp" -RuleName $itemName
                        }
                        "RecycleBin" {
                            try {
                                $shell = New-Object -ComObject Shell.Application
                                $bin = $shell.Namespace(0xA)
                                $items = $bin.Items()
                                $count = $items.Count

                                if ($count -gt 0) {
                                    Write-GuiLog "Recycle Bin: Processing $count items..."
                                    foreach ($f in $items) {
                                        try {
                                            $path = $f.Path
                                            if ($path -and (Test-Path -LiteralPath $path)) {
                                                $size = Measure-WmtPathBytes -Path $path
                                                $stats.Bytes += $size
                                            
                                                if (-not $isAnalyze) {
                                                    Remove-Item -LiteralPath $path -Recurse -Force -ErrorAction SilentlyContinue
                                                }
                                                else {
                                                    $protectionInfo = Get-WmtCleanupProtectionInfo -Path $path
                                                    $previewList.Add([PSCustomObject]@{
                                                            RuleName         = "Recycle Bin"
                                                            FilePath         = $path
                                                            RawBytes         = $size
                                                            IsProtected      = [bool]$protectionInfo.IsProtected
                                                            ProtectionReason = [string]$protectionInfo.Reason
                                                        })
                                                }
                                                $stats.Deleted++
                                            }
                                        }
                                        catch {}
                                    }
                                }
                            }
                            catch { Write-GuiLog "Recycle Bin Error: $($_.Exception.Message)" }
                        }
                        "WER" { Invoke-RobustClean "$env:ProgramData\Microsoft\Windows\WER" -RuleName $itemName }
                        "DNS" { if (-not $isAnalyze) { Clear-DnsClientCache -ErrorAction SilentlyContinue } }
                        "Thumbnails" { Invoke-RobustClean "$env:LOCALAPPDATA\Microsoft\Windows\Explorer" -Pattern "thumbcache_*.db" -Recurse:$false -RuleName $itemName }
                        "ThumbsDb" { Invoke-ThumbsDbDeepScan -RuleName $itemName }
                        "Recent" { Invoke-RobustClean "$env:APPDATA\Microsoft\Windows\Recent" -RuleName $itemName }
                        "RunMRU" { if (-not $isAnalyze) { Remove-ItemProperty -Path "HKCU:\Software\Microsoft\Windows\CurrentVersion\Explorer\RunMRU" -Name * -ErrorAction SilentlyContinue } }
                        "Edge" { Invoke-RobustClean "$env:LOCALAPPDATA\Microsoft\Edge\User Data\Default\Cache" -RuleName $itemName }
                        "Chrome" { Invoke-RobustClean "$env:LOCALAPPDATA\Google\Chrome\User Data\Default\Cache" -RuleName $itemName }
                        "Brave" { Invoke-RobustClean "$env:LOCALAPPDATA\BraveSoftware\Brave-Browser\User Data\Default\Cache" -RuleName $itemName }
                        "Firefox" { 
                            if (Test-Path "$env:LOCALAPPDATA\Mozilla\Firefox\Profiles") {
                                try {
                                    foreach ($profilePath in [System.IO.Directory]::EnumerateDirectories("$env:LOCALAPPDATA\Mozilla\Firefox\Profiles")) {
                                        Invoke-RobustClean "$profilePath\cache2\entries" -RuleName $itemName
                                    }
                                }
                                catch {}
                            }
                        }
                        "Opera" { Invoke-RobustClean "$env:APPDATA\Opera Software\Opera Stable\Cache" -RuleName $itemName }
                        "OperaGX" { Invoke-RobustClean "$env:APPDATA\Opera Software\Opera GX Stable\Cache" -RuleName $itemName }
                    }
                }

                $diffBytes = $stats.Bytes - $startBytes
                if ($diffBytes -gt 0) {
                    $itemStr = Format-FileSize $diffBytes
                    $verb = if ($isAnalyze) { "Found" } else { "Cleaned" }
                    Write-GuiLog "$verb $itemName : $itemStr"
                }
            }
        }
    }
    catch {
        Write-GuiLog "Error: $($_.Exception.Message)"
    }
    finally {
        $pForm.Close()
    }

    # 5. FINAL REPORT & PREVIEW
    $finalTotalFormatted = Format-FileSize $stats.Bytes
    
    if ($isAnalyze) {
        Write-GuiLog "Total Found: $finalTotalFormatted"
        
        if ($previewList.Count -gt 0) {
            Show-WmtCleanupPreviewWpf -PreviewList $previewList -FinalTotalFormatted $finalTotalFormatted
            return


        }
        else {
            Show-WmtMessageBox -Message "No files found to clean." -Title "Analysis Results" -Image Information | Out-Null
        }
    }
    else {
        Write-GuiLog "Total Removed: $finalTotalFormatted"
        $msg = "Cleanup Complete.`n`nFiles Removed: $($stats.Deleted)`nSpace Recovered: $finalTotalFormatted"
        Show-WmtMessageBox -Message $msg -Title "Cleanup Results" -Image Information | Out-Null
    }
}

# --- Registry Scan Selection UI ---
function Show-RegScanSelection {
    # 1. LOAD SETTINGS
    $currentSettings = Get-WmtSettings
    $savedStates = $currentSettings.RegistryScan

    # --- Define Categories ---
    $categories = [ordered]@{
        "Missing Shared DLLs"             = "SharedDLLs"
        "Unused File Extensions (System)" = "Ext"
        "Unused File Extensions (User)"   = "FileExts"
        "ActiveX & COM Issues"            = "ActiveX"
        "Type Libraries (TLB)"            = "TypeLib"
        "Application Paths"               = "AppPaths"
        "Applications (Registered)"       = "Apps"
        "Installer Folders"               = "Installer"
        "Obsolete Software (Uninstall)"   = "Uninstall"
        "Run At Startup"                  = "Startup"
        "Invalid Default Icons"           = "Icons"
        "File Associations"               = "ProgIDs"
        "Windows Services"                = "Services"
        "MUI Cache (MRU Lists)"           = "MuiCache"
        "Compatibility Store (Flags)"     = "AppCompat"
        "Notification Area Icons"         = "NotifyIcons"
        "Obsolete App Module Caches"      = "AppModules"
        "Empty User Software Keys"        = "EmptyUserSoftware"
        "Shell Extensions"                = "ShellExtensions"
        "Explorer Namespace Entries"      = "ExplorerNamespace"
        "Font Entries"                    = "Fonts"
        "App Execution Aliases"           = "AppAliases"
        "Scheduled Task Cache"            = "TaskCache"
        "Scheduled Task Actions"          = "TaskActions"
        "Uninstall Metadata Values"       = "UninstallMetadata"
        "Environment PATH Entries"        = "EnvPath"
        "RunOnce & Policy Startup"        = "StartupExtended"
        "AppCompat Layers"                = "AppCompatLayers"
        "User MRU Caches"                 = "UserMru"
        "Per-User Shell Commands"         = "UserShellCommands"
        "Image File Execution Options"    = "IFEO"
        "Firewall Rules"                  = "Firewall"
    }

    foreach ($savedKey in @($savedStates.Keys)) {
        if ($savedKey -notin @($categories.Values)) {
            [void]$currentSettings.RegistryScan.Remove($savedKey)
        }
    }

    [xml]$regScanXaml = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="Select Registry Scan Targets" Width="680" Height="720" MinWidth="620" MinHeight="640"
        WindowStartupLocation="CenterOwner" Background="{DynamicResource BgDark}" Foreground="{DynamicResource TextPrimary}"
        FontFamily="Segoe UI Variable Display, Segoe UI, Arial" FontSize="13">
    <Window.Resources>
        <Style TargetType="Button">
            <Setter Property="Height" Value="34"/>
            <Setter Property="MinWidth" Value="106"/>
            <Setter Property="Margin" Value="6,0,0,0"/>
            <Setter Property="Padding" Value="14,0"/>
            <Setter Property="Background" Value="{DynamicResource BgElevated}"/>
            <Setter Property="Foreground" Value="{DynamicResource TextPrimary}"/>
            <Setter Property="BorderBrush" Value="{DynamicResource BorderBrush}"/>
            <Setter Property="BorderThickness" Value="1"/>
        </Style>
        <Style TargetType="CheckBox">
            <Setter Property="Foreground" Value="{DynamicResource TextPrimary}"/>
            <Setter Property="Margin" Value="0,0,16,10"/>
            <Setter Property="VerticalAlignment" Value="Center"/>
        </Style>
    </Window.Resources>
    <Grid Margin="18">
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="*"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>

        <StackPanel Grid.Row="0" Margin="0,0,0,14">
            <TextBlock Text="Select areas to scan" FontSize="18" FontWeight="SemiBold" Foreground="{DynamicResource TextPrimary}"/>
            <TextBlock Text="Checked targets are saved for future registry scans." Margin="0,4,0,0" Foreground="{DynamicResource TextSecondary}"/>
        </StackPanel>

        <Border Grid.Row="1" Background="{DynamicResource BgPanel}" BorderBrush="{DynamicResource BorderBrush}" BorderThickness="1" CornerRadius="4" Padding="14">
            <ScrollViewer VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Disabled">
                <UniformGrid Name="pnlChecks" Columns="2"/>
            </ScrollViewer>
        </Border>

        <Grid Grid.Row="2" Margin="0,14,0,0">
            <StackPanel Orientation="Horizontal" HorizontalAlignment="Left">
                <Button Name="btnCancel" Content="Cancel" IsCancel="True"/>
                <Button Name="btnBackupHKLM" Content="Export HKLM"/>
                <Button Name="btnRestore" Content="Import Backup"/>
            </StackPanel>
            <Button Name="btnScan" Content="Start Deep Scan" HorizontalAlignment="Right" Background="{DynamicResource Success}" Foreground="{DynamicResource SuccessText}" IsDefault="True"/>
        </Grid>
    </Grid>
</Window>
'@

    $dialog = New-WmtWindowFromFullXaml -Xaml $regScanXaml

    $pnlChecks = $dialog.FindName("pnlChecks")
    $btnBackupHKLM = $dialog.FindName("btnBackupHKLM")
    $btnRestore = $dialog.FindName("btnRestore")
    $btnScan = $dialog.FindName("btnScan")

    $chkBoxes = [System.Collections.Generic.List[object]]::new()
    foreach ($key in $categories.Keys) {
        $tag = $categories[$key]
        $chk = [System.Windows.Controls.CheckBox]::new()
        $chk.Content = $key
        $chk.Tag = $tag
        $chk.IsChecked = if ($savedStates.ContainsKey($tag)) { [bool]$savedStates[$tag] } else { $true }
        [void]$pnlChecks.Children.Add($chk)
        [void]$chkBoxes.Add($chk)
    }

    $btnBackupHKLM.Add_Click({ Invoke-RegistryTask -Action "BackupHKLM" }.GetNewClosure())
    $btnRestore.Add_Click({ Invoke-RegistryTask -Action "Restore" }.GetNewClosure())
    $btnScan.Add_Click({
            $selected = [System.Collections.Generic.List[object]]::new()
            foreach ($c in $chkBoxes) {
                if ([bool]$c.IsChecked) { [void]$selected.Add($c.Tag) }
                $currentSettings.RegistryScan[$c.Tag] = [bool]$c.IsChecked
            }
            Save-WmtSettings -Settings $currentSettings

            $dialog.Tag = @($selected)
            $dialog.DialogResult = $true
            $dialog.Close()
        }.GetNewClosure())

    if ($dialog.ShowDialog() -eq $true) { return $dialog.Tag }
    return $null
}
# --- Registry Results UI ---
function Show-RegistryCleaner {
    param($ScanResults)

    function script:ConvertTo-WmtRegistryResultClipboardText {
        param([object[]]$Rows)

        $selectedRows = @($Rows | Where-Object { $null -ne $_ })
        $lines = [System.Collections.Generic.List[string]]::new()
        [void]$lines.Add("WMT Registry Cleaner Details")
        [void]$lines.Add("Count: $($selectedRows.Count)")
        [void]$lines.Add("")

        $index = 1
        foreach ($row in $selectedRows) {
            $cleanValue = {
                param($Value)
                if ($null -eq $Value) { return "" }
                $text = [string]$Value
                $text = $text -replace '\r?\n', ' '
                $text = $text -replace "`t", ' '
                return $text.Trim()
            }

            [void]$lines.Add("$index) $(& $cleanValue $row.Problem)")
            [void]$lines.Add("   Action: $(& $cleanValue $row.FixAction)")
            [void]$lines.Add("   Risk: $(& $cleanValue $row.Risk)")
            [void]$lines.Add("   Confidence: $(& $cleanValue $row.Confidence)")
            [void]$lines.Add("   Default: $(& $cleanValue $row.DefaultAction)")
            [void]$lines.Add("   Type: $(& $cleanValue $row.Type)")
            [void]$lines.Add("   Value: $(& $cleanValue $row.ValueName)")
            [void]$lines.Add("   Data (Path/Value): $(& $cleanValue $row.Data)")
            [void]$lines.Add("   Display Key: $(& $cleanValue $row.Key)")
            [void]$lines.Add("   Exact Registry Path: $(& $cleanValue $row.FullPath)")
            if (-not [string]::IsNullOrWhiteSpace([string]$row.NewData)) {
                [void]$lines.Add("   New Data: $(& $cleanValue $row.NewData)")
            }
            [void]$lines.Add("   Why Flagged: $(& $cleanValue $row.Details)")
            [void]$lines.Add("")
            $index++
        }

        return ($lines -join [Environment]::NewLine)
    }

    function script:ConvertTo-WmtRegeditPath {
        param([string]$RegistryPath)

        if ([string]::IsNullOrWhiteSpace($RegistryPath)) { return $null }
        $normalized = ([string]$RegistryPath).Trim()
        $normalized = $normalized -replace '/', '\'
        $normalized = $normalized -replace '^Microsoft\.PowerShell\.Core\\Registry::', ''
        $normalized = $normalized.TrimEnd('\')

        if ($normalized -match '^(?i)(HKEY_LOCAL_MACHINE|HKEY_CURRENT_USER|HKEY_CLASSES_ROOT|HKEY_USERS|HKEY_CURRENT_CONFIG)(\\.*)?$') {
            return $normalized
        }
        if ($normalized -match '^(?i)HKLM:\\?(?<Rest>.*)$') {
            return "HKEY_LOCAL_MACHINE\$($Matches.Rest.TrimStart('\'))".TrimEnd('\')
        }
        if ($normalized -match '^(?i)HKCU:\\?(?<Rest>.*)$') {
            return "HKEY_CURRENT_USER\$($Matches.Rest.TrimStart('\'))".TrimEnd('\')
        }
        if ($normalized -match '^(?i)HKCR:\\?(?<Rest>.*)$') {
            return "HKEY_CLASSES_ROOT\$($Matches.Rest.TrimStart('\'))".TrimEnd('\')
        }
        if ($normalized -match '^(?i)HKU:\\?(?<Rest>.*)$') {
            return "HKEY_USERS\$($Matches.Rest.TrimStart('\'))".TrimEnd('\')
        }
        if ($normalized -match '^(?i)HKCC:\\?(?<Rest>.*)$') {
            return "HKEY_CURRENT_CONFIG\$($Matches.Rest.TrimStart('\'))".TrimEnd('\')
        }

        return $normalized
    }

    function script:Open-WmtRegistryPathInRegedit {
        param([string]$RegistryPath)

        $regeditPath = ConvertTo-WmtRegeditPath -RegistryPath $RegistryPath
        if ([string]::IsNullOrWhiteSpace($regeditPath)) {
            [System.Windows.MessageBox]::Show("No registry path is available for the selected result.", "Registry Cleaner", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Information) | Out-Null
            return $false
        }

        try {
            $regeditStatePath = 'HKCU:\Software\Microsoft\Windows\CurrentVersion\Applets\Regedit'
            if (-not (Test-Path -LiteralPath $regeditStatePath)) {
                [void](New-Item -Path $regeditStatePath -Force)
            }
            Set-ItemProperty -LiteralPath $regeditStatePath -Name LastKey -Value $regeditPath -Force
            Start-Process -FilePath "regedit.exe" | Out-Null
            return $true
        }
        catch {
            [System.Windows.MessageBox]::Show("Could not open Regedit to:`n$regeditPath`n`n$($_.Exception.Message)", "Registry Cleaner", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Error) | Out-Null
            return $false
        }
    }

    function script:Get-WmtVisualParentOfType {
        param(
            [object]$Source,
            [type]$TargetType
        )

        if ($null -eq $Source -or $null -eq $TargetType) { return $null }

        $current = $Source
        while ($null -ne $current) {
            try {
                if ($TargetType.IsInstanceOfType($current)) { return $current }
            }
            catch {
                return $null
            }

            # VisualTreeHelper.GetParent only accepts DependencyObject instances.
            # Right-clicks on headers, scrollbars, adorner elements, or text runs can
            # surface non-visual objects; do not let that bubble into an unhandled WPF
            # event exception and terminate the script.
            if (-not ($current -is [System.Windows.DependencyObject])) { return $null }

            try {
                $current = [System.Windows.Media.VisualTreeHelper]::GetParent([System.Windows.DependencyObject]$current)
            }
            catch {
                return $null
            }
        }
        return $null
    }

    function script:Select-WmtRegistryGridRowFromOriginalSource {
        param(
            [System.Windows.Controls.DataGrid]$Grid,
            [object]$OriginalSource
        )

        if ($null -eq $Grid -or $null -eq $OriginalSource) { return $false }

        try {
            $rowElement = Get-WmtVisualParentOfType -Source $OriginalSource -TargetType ([System.Windows.Controls.DataGridRow])
            if ($null -eq $rowElement) { return $false }

            if (-not $rowElement.IsSelected) {
                try { $Grid.SelectedItems.Clear() } catch {}
                try { $rowElement.IsSelected = $true } catch {}
            }

            try { $Grid.SelectedItem = $rowElement.Item } catch {}
            try { $Grid.CurrentItem = $rowElement.Item } catch {}
            try { [void]$rowElement.Focus() } catch {}
            return $true
        }
        catch {
            try { Write-GuiLog "Registry result right-click row selection failed: $($_.Exception.Message)" } catch {}
            return $false
        }
    }

    function Test-WmtRegistryFindingAutoSelected {
        param($Item)

        if ($Item -and $Item.PSObject.Properties["SafeToFix"]) {
            return [bool]$Item.SafeToFix
        }

        $problem = [string]$Item.Problem
        $type = [string]$Item.Type
        $reviewOnlyPatterns = @(
            '^ActiveX Issue$',
            '^Protected ActiveX Issue$',
            '^Unused Extension$',
            '^Missing App Path$',
            '^Invalid App Command',
            '^Missing Uninstaller$',
            '^Obsolete App Module Cache$',
            '^Empty User Software Key$',
            '^Invalid Shell Extension$',
            '^Invalid Explorer Namespace$',
            '^Invalid Font Entry$',
            '^Orphaned TaskCache',
            '^Invalid User Shell Command$',
            '^Orphaned Service$',
            '^Missing HelpDir$',
            '^Missing TypeLib Path$',
            '^Invalid Default Icon$',
            '^Missing Shared Ref$'
        )

        foreach ($pattern in $reviewOnlyPatterns) {
            if ($problem -match $pattern) { return $false }
        }

        if ($type -eq "Key" -and $problem -ne "Obsolete Notify Icon") {
            return $false
        }

        return $true
    }

    [xml]$registryCleanerXaml = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="Deep Registry Cleaner" Width="1280" Height="680" MinWidth="980" MinHeight="560"
        WindowStartupLocation="CenterOwner" Background="{DynamicResource BgDark}" Foreground="{DynamicResource TextPrimary}"
        FontFamily="Segoe UI Variable Display, Segoe UI, Arial" FontSize="13">
    <Window.Resources>
        <Style TargetType="Button">
            <Setter Property="Height" Value="34"/>
            <Setter Property="MinWidth" Value="104"/>
            <Setter Property="Margin" Value="6,0,0,0"/>
            <Setter Property="Padding" Value="14,0"/>
            <Setter Property="Background" Value="{DynamicResource BgElevated}"/>
            <Setter Property="Foreground" Value="{DynamicResource TextPrimary}"/>
            <Setter Property="BorderBrush" Value="{DynamicResource BorderBrush}"/>
            <Setter Property="BorderThickness" Value="1"/>
        </Style>
        <Style TargetType="DataGrid">
            <Setter Property="Background" Value="{DynamicResource BgDark}"/>
            <Setter Property="Foreground" Value="{DynamicResource TextPrimary}"/>
            <Setter Property="BorderBrush" Value="{DynamicResource BorderBrush}"/>
            <Setter Property="GridLinesVisibility" Value="Horizontal"/>
            <Setter Property="HorizontalGridLinesBrush" Value="{DynamicResource BorderBrush}"/>
            <Setter Property="VerticalGridLinesBrush" Value="{DynamicResource BorderBrush}"/>
            <Setter Property="RowBackground" Value="{DynamicResource BgDark}"/>
            <Setter Property="AlternatingRowBackground" Value="{DynamicResource BgPanel}"/>
            <Setter Property="CanUserAddRows" Value="False"/>
            <Setter Property="CanUserDeleteRows" Value="False"/>
            <Setter Property="HeadersVisibility" Value="Column"/>
            <Setter Property="SelectionMode" Value="Extended"/>
            <Setter Property="SelectionUnit" Value="FullRow"/>
            <Setter Property="AutoGenerateColumns" Value="False"/>
            <Setter Property="ClipboardCopyMode" Value="IncludeHeader"/>
        </Style>
        <Style TargetType="DataGridColumnHeader">
            <Setter Property="Background" Value="{DynamicResource BgPanel}"/>
            <Setter Property="Foreground" Value="{DynamicResource TextPrimary}"/>
            <Setter Property="BorderBrush" Value="{DynamicResource BorderBrush}"/>
            <Setter Property="BorderThickness" Value="0,0,1,1"/>
            <Setter Property="Padding" Value="8,6"/>
            <Setter Property="FontWeight" Value="SemiBold"/>
        </Style>
        <Style TargetType="DataGridCell">
            <Setter Property="Background" Value="Transparent"/>
            <Setter Property="Foreground" Value="{DynamicResource TextPrimary}"/>
            <Setter Property="BorderThickness" Value="0"/>
            <Setter Property="Padding" Value="6,3"/>
        </Style>
        <Style TargetType="DataGridRow">
            <Setter Property="Foreground" Value="{DynamicResource TextPrimary}"/>
            <Style.Triggers>
                <Trigger Property="IsSelected" Value="True">
                    <Setter Property="Background" Value="{DynamicResource Accent}"/>
                    <Setter Property="Foreground" Value="{DynamicResource AccentText}"/>
                </Trigger>
            </Style.Triggers>
        </Style>
    </Window.Resources>
    <Grid Margin="16">
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="*"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>

        <Border Grid.Row="0" Background="{DynamicResource BgPanel}" BorderBrush="{DynamicResource BorderBrush}" BorderThickness="1" CornerRadius="4" Padding="14" Margin="0,0,0,12">
            <StackPanel>
                <TextBlock Name="lblStatus" FontSize="18" FontWeight="SemiBold" Foreground="{DynamicResource TextPrimary}"/>
                <TextBlock Text="Review checked findings before fixing. Missing-file COM server entries are selected by default unless WMT classifies them as protected/merged Microsoft COM registrations. Press Enter to check highlighted rows. Right-click a row to open its key in Regedit or copy details. Review-only rows are never fixed automatically." Margin="0,4,0,0" Foreground="{DynamicResource TextSecondary}"/>
            </StackPanel>
        </Border>

        <DataGrid Name="dgRegistry" Grid.Row="1" AlternationCount="2">
            <DataGrid.Columns>
                <DataGridTemplateColumn Header=" " Width="42" SortMemberPath="Check">
                    <DataGridTemplateColumn.CellTemplate>
                        <DataTemplate>
                            <CheckBox IsChecked="{Binding Check, Mode=TwoWay, UpdateSourceTrigger=PropertyChanged}"
                                      HorizontalAlignment="Center"
                                      VerticalAlignment="Center"
                                      Focusable="False"/>
                        </DataTemplate>
                    </DataGridTemplateColumn.CellTemplate>
                </DataGridTemplateColumn>
                <DataGridTextColumn Header="Problem" Binding="{Binding Problem}" Width="185" IsReadOnly="True"/>
                <DataGridTextColumn Header="Action" Binding="{Binding FixAction}" Width="90" IsReadOnly="True"/>
                <DataGridTextColumn Header="Risk" Binding="{Binding Risk}" Width="75" IsReadOnly="True"/>
                <DataGridTextColumn Header="Confidence" Binding="{Binding Confidence}" Width="92" IsReadOnly="True"/>
                <DataGridTextColumn Header="Default" Binding="{Binding DefaultAction}" Width="82" IsReadOnly="True"/>
                <DataGridTextColumn Header="Type" Binding="{Binding Type}" Width="80" IsReadOnly="True"/>
                <DataGridTextColumn Header="Value" Binding="{Binding ValueName}" Width="150" IsReadOnly="True"/>
                <DataGridTextColumn Header="Data (Path/Value)" Binding="{Binding Data}" Width="2*" IsReadOnly="True"/>
                <DataGridTextColumn Header="Display Key" Binding="{Binding Key}" Width="1.4*" IsReadOnly="True"/>
                <DataGridTextColumn Header="Exact Registry Path" Binding="{Binding FullPath}" Width="2*" IsReadOnly="True"/>
                <DataGridTextColumn Header="Why Flagged" Binding="{Binding Details}" Width="2*" IsReadOnly="True"/>
            </DataGrid.Columns>
        </DataGrid>

        <Grid Grid.Row="2" Margin="0,12,0,0">
            <Button Name="btnClose" Content="Close" IsCancel="True" HorizontalAlignment="Left"/>
            <StackPanel Orientation="Horizontal" HorizontalAlignment="Right">
                <Button Name="btnCopySelected" Content="Copy Selected Details" MinWidth="160"/>
                <Button Name="btnCopyAll" Content="Copy All Details" MinWidth="140"/>
                <Button Name="btnFix" Content="Fix Selected Issues..." MinWidth="180" Background="{DynamicResource Accent}" Foreground="{DynamicResource AccentText}"/>
            </StackPanel>
        </Grid>
    </Grid>
</Window>
'@

    $dialog = New-WmtWindowFromFullXaml -Xaml $registryCleanerXaml

    $lblStatus = $dialog.FindName("lblStatus")
    $dg = $dialog.FindName("dgRegistry")
    $btnFix = $dialog.FindName("btnFix")
    $btnCopySelected = $dialog.FindName("btnCopySelected")
    $btnCopyAll = $dialog.FindName("btnCopyAll")
    $btnClose = $dialog.FindName("btnClose")

    $lblStatus.Text = "Scan complete. Issues found: $($ScanResults.Count)"

    $registryRows = @(
        foreach ($item in $ScanResults) {
            $autoSelected = Test-WmtRegistryFindingAutoSelected -Item $item
            $fixAction = if ($item.Type -eq "ReviewOnly") { "Review" } elseif ($item.Type -eq "Key") { "Delete key" } elseif ($item.Type -eq "SetValue") { "Update value" } else { "Delete value" }
            $risk = if ($item.PSObject.Properties["Risk"] -and -not [string]::IsNullOrWhiteSpace([string]$item.Risk)) {
                [string]$item.Risk
            }
            elseif (-not $autoSelected) {
                "Review"
            }
            elseif ($item.Type -eq "Key") {
                "Medium"
            }
            else {
                "Low"
            }
            $confidence = if ($item.PSObject.Properties["Confidence"] -and -not [string]::IsNullOrWhiteSpace([string]$item.Confidence)) {
                [string]$item.Confidence
            }
            elseif ($autoSelected) {
                "High"
            }
            else {
                "Medium"
            }
            $details = if ($item.PSObject.Properties["Details"] -and -not [string]::IsNullOrWhiteSpace([string]$item.Details)) {
                [string]$item.Details
            }
            else {
                $valueText = if ($null -ne $item.ValueName) { "; Value=$($item.ValueName)" } else { "" }
                "$fixAction; Target=$($item.RegPath)$valueText"
            }
            if (-not $autoSelected) {
                $details = "Review only; not selected by default. $details"
            }
            [PSCustomObject]@{
                Check         = $autoSelected
                Problem       = $item.Problem
                Data          = $item.Data
                Key           = $item.DisplayKey
                FullPath      = $item.RegPath
                ValueName     = $item.ValueName
                FixAction     = $fixAction
                Risk          = $risk
                Confidence    = $confidence
                DefaultAction = if ($autoSelected) { "Selected" } else { "Review" }
                Type          = $item.Type
                NewData       = if ($item.PSObject.Properties["NewData"]) { [string]$item.NewData } else { $null }
                Details       = $details
            }
        }
    )
    $dg.ItemsSource = $registryRows

    $registryContextMenu = [System.Windows.Controls.ContextMenu]::new()
    try { Set-WmtContextMenuChrome -ContextMenu $registryContextMenu } catch {}

    $mniOpenRegedit = [System.Windows.Controls.MenuItem]::new()
    $mniOpenRegedit.Header = "Open in Regedit"
    $mniOpenRegedit.Add_Click({
            try {
                $row = $dg.SelectedItem
                if ($null -eq $row -and $dg.CurrentItem) { $row = $dg.CurrentItem }
                if ($null -eq $row) { return }
                [void](Open-WmtRegistryPathInRegedit -RegistryPath ([string]$row.FullPath))
            }
            catch {
                try { Write-GuiLog "Open in Regedit failed: $($_.Exception.Message)" } catch {}
                [System.Windows.MessageBox]::Show("Could not open the selected registry path:`n$($_.Exception.Message)", "Registry Cleaner", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Error) | Out-Null
            }
        }.GetNewClosure())

    $mniCopyContextDetails = [System.Windows.Controls.MenuItem]::new()
    $mniCopyContextDetails.Header = "Copy Selected Details"
    $mniCopyContextDetails.Add_Click({
            try {
                $rowsToCopy = @($dg.SelectedItems | Where-Object { $_ })
                if ($rowsToCopy.Count -eq 0 -and $dg.CurrentItem) { $rowsToCopy = @($dg.CurrentItem) }
                if ($rowsToCopy.Count -eq 0) { return }
                [System.Windows.Clipboard]::SetText((ConvertTo-WmtRegistryResultClipboardText -Rows $rowsToCopy))
            }
            catch {
                try { Write-GuiLog "Copy selected registry details failed: $($_.Exception.Message)" } catch {}
            }
        }.GetNewClosure())

    $mniCheckHighlighted = [System.Windows.Controls.MenuItem]::new()
    $mniCheckHighlighted.Header = "Check Highlighted Rows"
    $mniCheckHighlighted.Add_Click({
            try {
                $changed = Set-WmtRegistryHighlightedRowsChecked -Grid $dg -Checked $true
                if ($changed -gt 0) {
                    $lblStatus.Text = "Scan complete. Issues found: $($ScanResults.Count). Checked $changed highlighted row(s)."
                }
            }
            catch {
                try { Write-GuiLog "Check highlighted registry rows failed: $($_.Exception.Message)" } catch {}
            }
        }.GetNewClosure())

    [void]$registryContextMenu.Items.Add($mniOpenRegedit)
    [void]$registryContextMenu.Items.Add($mniCopyContextDetails)
    [void]$registryContextMenu.Items.Add((New-Object System.Windows.Controls.Separator))
    [void]$registryContextMenu.Items.Add($mniCheckHighlighted)
    try { $registryContextMenu.Placement = [System.Windows.Controls.Primitives.PlacementMode]::MousePoint } catch {}
    $dg.ContextMenu = $registryContextMenu

    $updateRegistryContextMenuState = {
        param([System.Windows.Controls.DataGrid]$Grid)

        $hasSelection = $false
        try {
            $hasSelection = (($null -ne $Grid) -and (($Grid.SelectedItems.Count -gt 0) -or ($null -ne $Grid.CurrentItem)))
        }
        catch {
            $hasSelection = $false
        }

        try { $mniOpenRegedit.IsEnabled = $hasSelection } catch {}
        try { $mniCopyContextDetails.IsEnabled = $hasSelection } catch {}
        try { $mniCheckHighlighted.IsEnabled = $hasSelection } catch {}
        return $hasSelection
    }.GetNewClosure()

    $openRegistryContextMenu = {
        param($gridSender, $mouseArgs)

        try {
            if ($null -eq $dg -or $null -eq $registryContextMenu) { return }

            # Selection is best-effort only.  Never suppress the menu just because the
            # click happened on a TextBlock, header, scrollbar, or empty DataGrid area.
            try {
                $sourceObject = $null
                if ($null -ne $mouseArgs) { $sourceObject = $mouseArgs.OriginalSource }
                if ($null -ne $sourceObject) {
                    [void](Select-WmtRegistryGridRowFromOriginalSource -Grid $dg -OriginalSource $sourceObject)
                }
            }
            catch {
                try { Write-GuiLog "Registry result right-click selection ignored: $($_.Exception.Message)" } catch {}
            }

            [void](& $updateRegistryContextMenuState -Grid $dg)
            try { $registryContextMenu.PlacementTarget = $dg } catch {}

            # Explicitly open the menu.  Some WPF-hosted PowerShell windows do not show a
            # programmatically assigned ContextMenu reliably from ContextMenuOpening alone.
            try {
                $registryContextMenu.IsOpen = $true
                if ($null -ne $mouseArgs) { $mouseArgs.Handled = $true }
            }
            catch {
                try { Write-GuiLog "Registry result context menu open failed: $($_.Exception.Message)" } catch {}
            }
        }
        catch {
            try { Write-GuiLog "Registry result context menu failed: $($_.Exception.Message)" } catch {}
        }
    }.GetNewClosure()

    $dg.Add_PreviewMouseRightButtonDown($openRegistryContextMenu)

    $dg.Add_ContextMenuOpening({
            param($gridSender, $menuArgs)
            try {
                [void](& $updateRegistryContextMenuState -Grid $dg)
            }
            catch {
                # Do not mark Handled here.  Even if state refresh fails, WPF should still
                # display the menu instead of making right-click look broken.
                try { Write-GuiLog "Registry result context menu state refresh failed: $($_.Exception.Message)" } catch {}
            }
        }.GetNewClosure())

    function script:Set-WmtRegistryHighlightedRowsChecked {
        param(
            [System.Windows.Controls.DataGrid]$Grid,
            [bool]$Checked = $true
        )

        if ($null -eq $Grid) { return 0 }
        try {
            [void]$Grid.CommitEdit([System.Windows.Controls.DataGridEditingUnit]::Cell, $true)
            [void]$Grid.CommitEdit([System.Windows.Controls.DataGridEditingUnit]::Row, $true)
        }
        catch {}

        $selectedRows = @($Grid.SelectedItems | Where-Object { $_ })
        if ($selectedRows.Count -eq 0 -and $Grid.CurrentItem) {
            $selectedRows = @($Grid.CurrentItem)
        }
        if ($selectedRows.Count -eq 0) { return 0 }

        $changed = 0
        foreach ($row in $selectedRows) {
            if ($row.PSObject.Properties["Check"]) {
                $row.Check = $Checked
                $changed++
            }
        }

        try { $Grid.Items.Refresh() } catch {}
        return $changed
    }

    $dg.Add_PreviewKeyDown({
            param($gridSender, $keyArgs)

            if ([string]$keyArgs.Key -notin @("Return", "Enter")) { return }

            $changed = Set-WmtRegistryHighlightedRowsChecked -Grid $gridSender -Checked $true
            if ($changed -gt 0) {
                $lblStatus.Text = "Scan complete. Issues found: $($ScanResults.Count). Checked $changed highlighted row(s)."
                $keyArgs.Handled = $true
            }
        })

    $btnCopySelected.Add_Click({
            $rowsToCopy = @($dg.SelectedItems | Where-Object { $_ })
            if ($rowsToCopy.Count -eq 0) {
                $rowsToCopy = @($registryRows | Where-Object { $_.Check -eq $true })
            }
            if ($rowsToCopy.Count -eq 0) { return }

            try {
                [System.Windows.Clipboard]::SetText((ConvertTo-WmtRegistryResultClipboardText -Rows $rowsToCopy))
                [System.Windows.MessageBox]::Show("Copied $($rowsToCopy.Count) registry result(s).", "Registry Cleaner", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Information) | Out-Null
            }
            catch {
                [System.Windows.MessageBox]::Show("Could not copy details:`n$($_.Exception.Message)", "Registry Cleaner", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Error) | Out-Null
            }
        })

    $btnCopyAll.Add_Click({
            try {
                [System.Windows.Clipboard]::SetText((ConvertTo-WmtRegistryResultClipboardText -Rows @($registryRows)))
                [System.Windows.MessageBox]::Show("Copied $($registryRows.Count) registry result(s).", "Registry Cleaner", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Information) | Out-Null
            }
            catch {
                [System.Windows.MessageBox]::Show("Could not copy details:`n$($_.Exception.Message)", "Registry Cleaner", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Error) | Out-Null
            }
        })

    # --- 7. Fix Button Logic ---
    $btnFix.Add_Click({
            $toFix = [System.Collections.Generic.List[object]]::new()
            try {
                [void]$dg.CommitEdit([System.Windows.Controls.DataGridEditingUnit]::Cell, $true)
                [void]$dg.CommitEdit([System.Windows.Controls.DataGridEditingUnit]::Row, $true)
            }
            catch {}
            foreach ($row in $registryRows) {
                if ($row.Check -eq $true) {
                    [void]$toFix.Add([PSCustomObject]@{
                            Problem       = $row.Problem
                            Action        = $row.FixAction
                            Risk          = $row.Risk
                            Confidence    = $row.Confidence
                            DefaultAction = $row.DefaultAction
                            RegPath       = $row.FullPath
                            ValueName     = $row.ValueName
                            Type          = $row.Type
                            DisplayKey    = $row.Key
                            Data          = $row.Data
                            WhyFlagged    = $row.Details
                            NewData       = $row.NewData
                        })
                }
            }

            if ($toFix.Count -eq 0) {
                [System.Windows.MessageBox]::Show("No issues selected.", "Registry Cleaner", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Information) | Out-Null
                return
            }

            # Return results to the main controller
            $dialog.Tag = @($toFix.ToArray())
            $dialog.DialogResult = $true
            $dialog.Close()
        })

    $btnClose.Add_Click({ $dialog.Close() })

    if ($dialog.ShowDialog() -eq $true) { return $dialog.Tag }
    return $null
}
# =========================================================
# 1. GLOBAL REGISTRY HELPERS
# (Place these ABOVE Invoke-RegistryTask)
# =========================================================

function Test-PathExists {
    param(
        $Path,
        $RegistryView = $null
    )
    if ([string]::IsNullOrWhiteSpace($Path)) { return $false }

    $rawPathText = ([string]$Path).Trim()
    $expanded = [Environment]::ExpandEnvironmentVariables($rawPathText)
    $expanded = $expanded -replace '^(?i)\\\?\?\\', ''
    $expanded = $expanded -replace '^(?i)\\\\\?\\', ''

    $systemRoot = [Environment]::GetEnvironmentVariable("SystemRoot")
    if ([string]::IsNullOrWhiteSpace($systemRoot)) { $systemRoot = "$env:SystemDrive\Windows" }
    if ($expanded -match '^(?i)\\SystemRoot\\(?<SubPath>.+)$') {
        $expanded = Join-Path $systemRoot $Matches.SubPath
    }
    elseif ($expanded -match '^(?i)System32\\(?<SubPath>.+)$') {
        $expanded = Join-Path (Join-Path $systemRoot "System32") $Matches.SubPath
    }

    if ($expanded -match "%.*%" -or $expanded -match "\$\(.*\)") { return $false }

    $probeCandidates = [System.Collections.Generic.List[string]]::new()
    $seenCandidates = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
    $addProbeCandidate = {
        param([string]$Candidate)
        if ([string]::IsNullOrWhiteSpace($Candidate)) { return }
        $candidateText = ([string]$Candidate).Trim()
        if ($candidateText -match "%.*%" -or $candidateText -match "\$\(.*\)") { return }
        if ($seenCandidates.Add($candidateText)) { [void]$probeCandidates.Add($candidateText) }
    }
    $useDefaultExpandedCandidate = $true
    if ([Environment]::Is64BitOperatingSystem -and [string]$RegistryView -eq "Registry32") {
        $commonProgramFilesX86 = [Environment]::GetEnvironmentVariable("CommonProgramFiles(x86)")
        if (-not [string]::IsNullOrWhiteSpace($commonProgramFilesX86) -and $rawPathText -match '(?i)%CommonProgramFiles%\\(?<Rest>.+)$') {
            & $addProbeCandidate (Join-Path $commonProgramFilesX86 $Matches.Rest)
            $useDefaultExpandedCandidate = $false
        }
        $programFilesX86 = [Environment]::GetEnvironmentVariable("ProgramFiles(x86)")
        if (-not [string]::IsNullOrWhiteSpace($programFilesX86) -and $rawPathText -match '(?i)%ProgramFiles%\\(?<Rest>.+)$') {
            & $addProbeCandidate (Join-Path $programFilesX86 $Matches.Rest)
            $useDefaultExpandedCandidate = $false
        }

        # 32-bit COM values often store REG_EXPAND_SZ like %CommonProgramFiles%.
        # If another helper expanded it first inside 64-bit PowerShell, it becomes
        # C:\Program Files\Common Files, even though the 32-bit COM server normally
        # resolves to C:\Program Files (x86)\Common Files. Probe both forms to avoid
        # false ActiveX findings for legacy DAO/OLE DB registrations.
        $commonProgramFiles64 = [Environment]::GetEnvironmentVariable("CommonProgramFiles")
        if (-not [string]::IsNullOrWhiteSpace($commonProgramFiles64) -and -not [string]::IsNullOrWhiteSpace($commonProgramFilesX86)) {
            $common64Pattern = "^(?i)$([regex]::Escape($commonProgramFiles64))\\(?<Rest>.+)$"
            if ($rawPathText -match $common64Pattern -or $expanded -match $common64Pattern) {
                & $addProbeCandidate (Join-Path $commonProgramFilesX86 $Matches.Rest)
            }
        }

        $programFiles64 = [Environment]::GetEnvironmentVariable("ProgramFiles")
        if (-not [string]::IsNullOrWhiteSpace($programFiles64) -and -not [string]::IsNullOrWhiteSpace($programFilesX86)) {
            $pf64Pattern = "^(?i)$([regex]::Escape($programFiles64))\\(?<Rest>.+)$"
            if ($rawPathText -match $pf64Pattern -or $expanded -match $pf64Pattern) {
                & $addProbeCandidate (Join-Path $programFilesX86 $Matches.Rest)
            }
        }
    }
    if ($useDefaultExpandedCandidate) { & $addProbeCandidate $expanded }

    if ([Environment]::Is64BitOperatingSystem) {
        $system32Pattern = "^(?i)$([regex]::Escape($systemRoot))\\System32\\(?<SubPath>.+)$"
        if ($expanded -match $system32Pattern) {
            if ([string]$RegistryView -eq "Registry32") {
                $wow64Candidate = (Join-Path (Join-Path $systemRoot "SysWOW64") $Matches.SubPath).Trim()
                if ($seenCandidates.Add($wow64Candidate)) { [void]$probeCandidates.Add($wow64Candidate) }
            }
            $sysnativeCandidate = (Join-Path (Join-Path $systemRoot "Sysnative") $Matches.SubPath).Trim()
            if ($seenCandidates.Add($sysnativeCandidate)) { [void]$probeCandidates.Add($sysnativeCandidate) }
        }
    }

    foreach ($candidate in $probeCandidates) {
        try {
            if (Test-Path -LiteralPath $candidate -ErrorAction Stop) { return $true }
        }
        catch [System.UnauthorizedAccessException] { return $true }
        catch [System.Security.SecurityException] { return $true }
        catch {}
        try {
            [void](Get-Item -LiteralPath $candidate -Force -ErrorAction Stop)
            return $true
        }
        catch {
            if ($_.Exception.Message -match '(?i)access.*denied|unauthorized') { return $true }
        }
        if ($candidate -match '^(?i)[a-z]:\\Program Files\\WindowsApps\\(?<PackageName>[^\\]+)') {
            $packageParts = ([string]$Matches.PackageName).Split([char[]]@('_'), [System.StringSplitOptions]::RemoveEmptyEntries)
            if ($packageParts.Length -ge 2) {
                $packageFamily = "$($packageParts[0])_$($packageParts[$packageParts.Length - 1])"
                try {
                    $packageFamilyKey = "SOFTWARE\Microsoft\Windows\CurrentVersion\AppModel\StateRepository\Cache\PackageFamily\Index\PackageFamilyName\$packageFamily"
                    $root = [Microsoft.Win32.Registry]::LocalMachine.OpenSubKey($packageFamilyKey)
                    if ($root) { $root.Close(); return $true }
                }
                catch {}
            }
        }
    }

    return $false
}

function Convert-WmtRegistryPath {
    param([string]$Path)
    if ([string]::IsNullOrWhiteSpace($Path)) { return $null }

    $normalized = $Path.Trim()
    $normalized = $normalized -replace "^Registry::", ""
    $normalized = $normalized -replace "^Computer\\", ""
    $normalized = $normalized -replace "^HKEY_LOCAL_MACHINE\\", "HKLM:\"
    $normalized = $normalized -replace "^HKEY_CURRENT_USER\\", "HKCU:\"
    $normalized = $normalized -replace "^HKEY_CLASSES_ROOT\\", "HKCR:\"
    $normalized = $normalized -replace "^HKEY_USERS\\", "HKU:\"

    if ($normalized -notmatch '^(?<Hive>HKLM|HKCU|HKCR|HKU):\\(?<SubPath>.*)$') { return $null }

    $hive = switch ($Matches.Hive) {
        "HKLM" { [Microsoft.Win32.RegistryHive]::LocalMachine }
        "HKCU" { [Microsoft.Win32.RegistryHive]::CurrentUser }
        "HKCR" { [Microsoft.Win32.RegistryHive]::ClassesRoot }
        "HKU" { [Microsoft.Win32.RegistryHive]::Users }
    }

    [PSCustomObject]@{
        Hive    = $hive
        Root    = $Matches.Hive
        SubPath = $Matches.SubPath
    }
}

function Convert-WmtRegistryPathToRegExePath {
    param([string]$Path)
    if ([string]::IsNullOrWhiteSpace($Path)) { return $null }

    $normalized = $Path.Trim()
    $normalized = $normalized -replace "^Registry::", ""
    $normalized = $normalized -replace "^Computer\\", ""
    $normalized = $normalized -replace "^HKLM:?\\", "HKEY_LOCAL_MACHINE\"
    $normalized = $normalized -replace "^HKCU:?\\", "HKEY_CURRENT_USER\"
    $normalized = $normalized -replace "^HKCR:?\\", "HKEY_CLASSES_ROOT\"
    $normalized = $normalized -replace "^HKU:?\\", "HKEY_USERS\"
    return $normalized
}

function Test-WmtRegistryValueExists {
    param(
        [string]$Path,
        [string]$ValueName
    )
    if ([string]::IsNullOrWhiteSpace($Path) -or $null -eq $ValueName) { return $false }

    $parts = Convert-WmtRegistryPath -Path $Path
    if (-not $parts) { return $false }

    $views = @([Microsoft.Win32.RegistryView]::Default)
    foreach ($view in $views) {
        $baseKey = $null
        $key = $null
        try {
            $baseKey = [Microsoft.Win32.RegistryKey]::OpenBaseKey($parts.Hive, $view)
            $key = $baseKey.OpenSubKey($parts.SubPath, $false)
            if ($key) {
                return ($key.GetValueNames() -contains $ValueName)
            }
        }
        catch {}
        finally {
            if ($key) { $key.Close() }
            if ($baseKey) { $baseKey.Close() }
        }
    }

    return $false
}

function Remove-WmtRegistryValueNative {
    param(
        [string]$Path,
        [string]$ValueName
    )
    if ([string]::IsNullOrWhiteSpace($Path) -or $null -eq $ValueName) { return $false }

    $parts = Convert-WmtRegistryPath -Path $Path
    if (-not $parts) { return $false }

    $views = @([Microsoft.Win32.RegistryView]::Default)
    foreach ($view in $views) {
        $baseKey = $null
        $key = $null
        try {
            $baseKey = [Microsoft.Win32.RegistryKey]::OpenBaseKey($parts.Hive, $view)
            $key = $baseKey.OpenSubKey($parts.SubPath, $true)
            if ($key) {
                $key.DeleteValue($ValueName, $false)
                $key.Close(); $key = $null
                if (-not (Test-WmtRegistryValueExists -Path $Path -ValueName $ValueName)) { return $true }
            }
        }
        catch {}
        finally {
            if ($key) { $key.Close() }
            if ($baseKey) { $baseKey.Close() }
        }
    }

    return $false
}

function Test-WmtRegistryKeyExistsNative {
    param(
        [Microsoft.Win32.RegistryHive]$Hive,
        $View,
        [string]$SubPath
    )
    if ([string]::IsNullOrWhiteSpace($SubPath)) { return $false }

    $baseKey = $null
    $key = $null
    try {
        $baseKey = [Microsoft.Win32.RegistryKey]::OpenBaseKey($Hive, $View)
        $key = $baseKey.OpenSubKey($SubPath, $false)
        return ($null -ne $key)
    }
    catch {}
    finally {
        if ($key) { $key.Close() }
        if ($baseKey) { $baseKey.Close() }
    }

    return $false
}

function Remove-WmtRegistryKeyNative {
    param(
        [Microsoft.Win32.RegistryHive]$Hive,
        $View,
        [string]$SubPath
    )
    if ([string]::IsNullOrWhiteSpace($SubPath)) { return $false }

    $baseKey = $null
    try {
        $baseKey = [Microsoft.Win32.RegistryKey]::OpenBaseKey($Hive, $View)
        $baseKey.DeleteSubKeyTree($SubPath, $false)
        return (-not (Test-WmtRegistryKeyExistsNative -Hive $Hive -View $View -SubPath $SubPath))
    }
    catch {}
    finally {
        if ($baseKey) { $baseKey.Close() }
    }

    return (-not (Test-WmtRegistryKeyExistsNative -Hive $Hive -View $View -SubPath $SubPath))
}


function Grant-WmtRegistryKeyFullControlNative {
    param(
        [Microsoft.Win32.RegistryHive]$Hive,
        $View,
        [string]$SubPath
    )
    if ([string]::IsNullOrWhiteSpace($SubPath)) { return $false }

    $root = $null
    $changedAny = $false
    try {
        $root = [Microsoft.Win32.RegistryKey]::OpenBaseKey($Hive, $View)
        $adminSid = New-Object System.Security.Principal.SecurityIdentifier([System.Security.Principal.WellKnownSidType]::BuiltinAdministratorsSid, $null)
        $adminAccount = $adminSid.Translate([System.Security.Principal.NTAccount])
        $rights = [System.Security.AccessControl.RegistryRights]::FullControl
        $rule = New-Object System.Security.AccessControl.RegistryAccessRule(
            $adminAccount,
            $rights,
            [System.Security.AccessControl.InheritanceFlags]::ContainerInherit,
            [System.Security.AccessControl.PropagationFlags]::None,
            [System.Security.AccessControl.AccessControlType]::Allow
        )
        $openRights = [System.Security.AccessControl.RegistryRights]::TakeOwnership -bor `
            [System.Security.AccessControl.RegistryRights]::ChangePermissions -bor `
            [System.Security.AccessControl.RegistryRights]::ReadKey -bor `
            [System.Security.AccessControl.RegistryRights]::WriteKey

        $stack = [System.Collections.Generic.Stack[string]]::new()
        $stack.Push(([string]$SubPath).TrimStart('\'))
        $seen = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)

        while ($stack.Count -gt 0) {
            $current = $stack.Pop()
            if ([string]::IsNullOrWhiteSpace($current) -or -not $seen.Add($current)) { continue }

            $key = $null
            try {
                $key = $root.OpenSubKey($current, [Microsoft.Win32.RegistryKeyPermissionCheck]::ReadWriteSubTree, $openRights)
                if (-not $key) { continue }

                try {
                    $ownerSecurity = $key.GetAccessControl([System.Security.AccessControl.AccessControlSections]::Owner)
                    $ownerSecurity.SetOwner($adminAccount)
                    $key.SetAccessControl($ownerSecurity)
                    $changedAny = $true
                }
                catch {}

                try {
                    $accessSecurity = $key.GetAccessControl([System.Security.AccessControl.AccessControlSections]::Access)
                    $accessSecurity.SetAccessRule($rule)
                    $key.SetAccessControl($accessSecurity)
                    $changedAny = $true
                }
                catch {}

                try {
                    foreach ($childName in @($key.GetSubKeyNames())) {
                        if (-not [string]::IsNullOrWhiteSpace($childName)) {
                            $stack.Push("$current\$childName")
                        }
                    }
                }
                catch {}
            }
            catch {}
            finally {
                if ($key) { $key.Close() }
            }
        }
    }
    catch {}
    finally {
        if ($root) { $root.Close() }
    }

    return $changedAny
}

function ConvertTo-WmtRegistryDeleteTargetSet {
    param([string]$Path)

    $targets = [System.Collections.Generic.List[object]]::new()
    $seen = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
    if ([string]::IsNullOrWhiteSpace($Path)) { return $targets }

    $normalized = ([string]$Path).Trim() -replace '^Registry::', '' -replace '^Computer\\', ''
    $normalized = $normalized -replace '^HKEY_LOCAL_MACHINE\\', 'HKLM:\'
    $normalized = $normalized -replace '^HKEY_CURRENT_USER\\', 'HKCU:\'
    $normalized = $normalized -replace '^HKEY_CLASSES_ROOT\\', 'HKCR:\'
    $normalized = $normalized -replace '^HKEY_USERS\\', 'HKU:\'

    $addProvider = {
        param([string]$ProviderPath)
        if ([string]::IsNullOrWhiteSpace($ProviderPath)) { return }
        $k = "P|$ProviderPath"
        if ($seen.Add($k)) {
            [void]$targets.Add([PSCustomObject]@{ Kind = "Provider"; Path = $ProviderPath })
        }
    }

    $addNative = {
        param([Microsoft.Win32.RegistryHive]$Hive, $View, [string]$SubPath, [string]$Label)
        if ([string]::IsNullOrWhiteSpace($SubPath)) { return }
        $sub = ([string]$SubPath).TrimStart('\')
        $k = "N|$Hive|$View|$sub"
        if ($seen.Add($k)) {
            [void]$targets.Add([PSCustomObject]@{ Kind = "Native"; Hive = $Hive; View = $View; SubPath = $sub; Label = $Label })
        }
    }

    & $addProvider $normalized

    if ($normalized -match '^(?i)HKCR:\\WOW6432Node\\(?<Rest>.+)$') {
        $rest = $Matches.Rest
        & $addProvider "HKLM:\SOFTWARE\WOW6432Node\Classes\$rest"
        & $addProvider "HKLM:\SOFTWARE\Classes\WOW6432Node\$rest"
        & $addProvider "HKCU:\Software\Classes\WOW6432Node\$rest"
        & $addNative ([Microsoft.Win32.RegistryHive]::ClassesRoot) ([Microsoft.Win32.RegistryView]::Registry32) $rest "HKCR Registry32"
        & $addNative ([Microsoft.Win32.RegistryHive]::LocalMachine) ([Microsoft.Win32.RegistryView]::Registry32) "SOFTWARE\Classes\$rest" "HKLM Classes Registry32"
        & $addNative ([Microsoft.Win32.RegistryHive]::LocalMachine) ([Microsoft.Win32.RegistryView]::Registry64) "SOFTWARE\WOW6432Node\Classes\$rest" "HKLM physical WOW6432Node Classes"
        & $addNative ([Microsoft.Win32.RegistryHive]::CurrentUser) ([Microsoft.Win32.RegistryView]::Registry32) "Software\Classes\$rest" "HKCU Classes Registry32"
        & $addNative ([Microsoft.Win32.RegistryHive]::CurrentUser) ([Microsoft.Win32.RegistryView]::Registry64) "Software\Classes\WOW6432Node\$rest" "HKCU physical WOW6432Node Classes"
    }
    elseif ($normalized -match '^(?i)HKLM:\\SOFTWARE\\WOW6432Node\\Classes\\(?<Rest>.+)$') {
        $rest = $Matches.Rest
        & $addProvider "HKCR:\WOW6432Node\$rest"
        & $addNative ([Microsoft.Win32.RegistryHive]::LocalMachine) ([Microsoft.Win32.RegistryView]::Registry32) "SOFTWARE\Classes\$rest" "HKLM Classes Registry32"
        & $addNative ([Microsoft.Win32.RegistryHive]::LocalMachine) ([Microsoft.Win32.RegistryView]::Registry64) "SOFTWARE\WOW6432Node\Classes\$rest" "HKLM physical WOW6432Node Classes"
        & $addNative ([Microsoft.Win32.RegistryHive]::ClassesRoot) ([Microsoft.Win32.RegistryView]::Registry32) $rest "HKCR Registry32"
    }
    elseif ($normalized -match '^(?i)HKLM:\\SOFTWARE\\Classes\\(?<Rest>.+)$') {
        $rest = $Matches.Rest
        & $addProvider "HKCR:\$rest"
        & $addNative ([Microsoft.Win32.RegistryHive]::LocalMachine) ([Microsoft.Win32.RegistryView]::Registry64) "SOFTWARE\Classes\$rest" "HKLM Classes Registry64"
        & $addNative ([Microsoft.Win32.RegistryHive]::ClassesRoot) ([Microsoft.Win32.RegistryView]::Registry64) $rest "HKCR Registry64"
    }
    elseif ($normalized -match '^(?i)HKCR:\\(?<Rest>.+)$') {
        $rest = $Matches.Rest
        & $addProvider "HKLM:\SOFTWARE\Classes\$rest"
        & $addProvider "HKCU:\Software\Classes\$rest"
        & $addNative ([Microsoft.Win32.RegistryHive]::ClassesRoot) ([Microsoft.Win32.RegistryView]::Default) $rest "HKCR default"
        & $addNative ([Microsoft.Win32.RegistryHive]::LocalMachine) ([Microsoft.Win32.RegistryView]::Registry64) "SOFTWARE\Classes\$rest" "HKLM Classes Registry64"
        & $addNative ([Microsoft.Win32.RegistryHive]::CurrentUser) ([Microsoft.Win32.RegistryView]::Default) "Software\Classes\$rest" "HKCU Classes default"
    }
    elseif ($normalized -match '^(?i)HKLM:\\(?<Rest>.+)$') {
        $rest = $Matches.Rest
        & $addNative ([Microsoft.Win32.RegistryHive]::LocalMachine) ([Microsoft.Win32.RegistryView]::Default) $rest "HKLM default"
        if ([Environment]::Is64BitOperatingSystem) {
            & $addNative ([Microsoft.Win32.RegistryHive]::LocalMachine) ([Microsoft.Win32.RegistryView]::Registry64) $rest "HKLM Registry64"
            if ($rest -match '^(?i)SOFTWARE\\WOW6432Node\\(?<WowRest>.+)$') {
                & $addNative ([Microsoft.Win32.RegistryHive]::LocalMachine) ([Microsoft.Win32.RegistryView]::Registry32) "SOFTWARE\$($Matches.WowRest)" "HKLM Registry32 redirected"
            }
        }
    }
    elseif ($normalized -match '^(?i)HKCU:\\(?<Rest>.+)$') {
        $rest = $Matches.Rest
        & $addNative ([Microsoft.Win32.RegistryHive]::CurrentUser) ([Microsoft.Win32.RegistryView]::Default) $rest "HKCU default"
        if ([Environment]::Is64BitOperatingSystem) {
            & $addNative ([Microsoft.Win32.RegistryHive]::CurrentUser) ([Microsoft.Win32.RegistryView]::Registry64) $rest "HKCU Registry64"
            if ($rest -match '^(?i)Software\\Classes\\WOW6432Node\\(?<WowRest>.+)$') {
                & $addNative ([Microsoft.Win32.RegistryHive]::CurrentUser) ([Microsoft.Win32.RegistryView]::Registry32) "Software\Classes\$($Matches.WowRest)" "HKCU Registry32 redirected"
            }
        }
    }
    elseif ($normalized -match '^(?i)HKU:\\(?<Rest>.+)$') {
        & $addNative ([Microsoft.Win32.RegistryHive]::Users) ([Microsoft.Win32.RegistryView]::Default) $Matches.Rest "HKU default"
    }

    return $targets
}

function Set-WmtRegistryValueNative {
    param(
        [string]$Path,
        [string]$ValueName,
        [string]$ValueData
    )
    if ([string]::IsNullOrWhiteSpace($Path) -or $null -eq $ValueName) { return $false }

    $parts = Convert-WmtRegistryPath -Path $Path
    if (-not $parts) { return $false }

    $views = @([Microsoft.Win32.RegistryView]::Default)
    foreach ($view in $views) {
        $baseKey = $null
        $key = $null
        try {
            $baseKey = [Microsoft.Win32.RegistryKey]::OpenBaseKey($parts.Hive, $view)
            $key = $baseKey.OpenSubKey($parts.SubPath, $true)
            if ($key) {
                $kind = [Microsoft.Win32.RegistryValueKind]::String
                try { $kind = $key.GetValueKind($ValueName) } catch {}
                if ($kind -notin @([Microsoft.Win32.RegistryValueKind]::String, [Microsoft.Win32.RegistryValueKind]::ExpandString)) {
                    $kind = [Microsoft.Win32.RegistryValueKind]::String
                }
                $key.SetValue($ValueName, [string]$ValueData, $kind)
                $written = [string]$key.GetValue($ValueName, $null, [Microsoft.Win32.RegistryValueOptions]::DoNotExpandEnvironmentNames)
                return ($written -eq [string]$ValueData)
            }
        }
        catch {}
        finally {
            if ($key) { $key.Close() }
            if ($baseKey) { $baseKey.Close() }
        }
    }

    return $false
}

function Remove-WmtRegistryValueRegExe {
    param(
        [string]$Path,
        [string]$ValueName
    )
    if ([string]::IsNullOrWhiteSpace($Path) -or $null -eq $ValueName) { return $false }

    $regPath = Convert-WmtRegistryPathToRegExePath -Path $Path
    if ([string]::IsNullOrWhiteSpace($regPath)) { return $false }

    foreach ($regExe in @(Get-WmtRegExeCandidatePaths)) {
        try {
            & $regExe delete $regPath /v $ValueName /f 1>$null 2>$null
            if ($LASTEXITCODE -eq 0 -or -not (Test-WmtRegistryValueExists -Path $Path -ValueName $ValueName)) { return $true }
        }
        catch {}
    }

    return (-not (Test-WmtRegistryValueExists -Path $Path -ValueName $ValueName))
}

function Get-WmtRegExeCandidatePaths {
    $paths = [System.Collections.Generic.List[string]]::new()
    $seen = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
    $windir = [Environment]::GetFolderPath([Environment+SpecialFolder]::Windows)
    if ([string]::IsNullOrWhiteSpace($windir)) { $windir = $env:WINDIR }

    $candidates = @()
    if (-not [string]::IsNullOrWhiteSpace($windir)) {
        $candidates += (Join-Path $windir 'Sysnative\reg.exe')
        $candidates += (Join-Path $windir 'System32\reg.exe')
        $candidates += (Join-Path $windir 'SysWOW64\reg.exe')
    }
    $candidates += 'reg.exe'

    foreach ($candidate in $candidates) {
        if ([string]::IsNullOrWhiteSpace($candidate)) { continue }
        if ($candidate -ne 'reg.exe' -and -not (Test-Path -LiteralPath $candidate -PathType Leaf -ErrorAction SilentlyContinue)) { continue }
        if ($seen.Add($candidate)) { [void]$paths.Add($candidate) }
    }

    return @($paths)
}

function ConvertTo-WmtComClassParentPath {
    param([string]$Path)
    if ([string]::IsNullOrWhiteSpace($Path)) { return $null }

    $normalized = ([string]$Path).Trim() -replace '^Registry::', '' -replace '^Computer\\', ''
    $normalized = $normalized -replace '^HKEY_LOCAL_MACHINE\\', 'HKLM:\'
    $normalized = $normalized -replace '^HKEY_CURRENT_USER\\', 'HKCU:\'
    $normalized = $normalized -replace '^HKEY_CLASSES_ROOT\\', 'HKCR:\'
    $normalized = $normalized -replace '^HKEY_USERS\\', 'HKU:\'
    $normalized = $normalized -replace '\\+$', ''

    $serverPattern = '^(?<Parent>(?:HKLM:\\SOFTWARE\\(?:WOW6432Node\\)?Classes\\CLSID|HKCR:\\(?:WOW6432Node\\)?CLSID|HKCU:\\Software\\Classes\\(?:WOW6432Node\\)?CLSID|HKU:\\[^\\]+\\Software\\Classes\\(?:WOW6432Node\\)?CLSID)\\\{[0-9A-Fa-f-]+\})\\(?:InProcServer32|LocalServer32)$'
    if ($normalized -match $serverPattern) { return $Matches.Parent }

    return $null
}

function ConvertTo-WmtComClassServerSubPath {
    param([string]$Path)
    if ([string]::IsNullOrWhiteSpace($Path)) { return $null }

    $normalized = ([string]$Path).Trim() -replace '^Registry::', '' -replace '^Computer\\', ''
    $normalized = $normalized -replace '^HKEY_LOCAL_MACHINE\\', 'HKLM:\'
    $normalized = $normalized -replace '^HKEY_CURRENT_USER\\', 'HKCU:\'
    $normalized = $normalized -replace '^HKEY_CLASSES_ROOT\\', 'HKCR:\'
    $normalized = $normalized -replace '^HKEY_USERS\\', 'HKU:\'
    $normalized = $normalized -replace '\\+$', ''

    if ($normalized -match '^(?<Parent>.+?\\CLSID\\\{[0-9A-Fa-f-]+\})\\(?<Server>InProcServer32|LocalServer32)$') {
        return [PSCustomObject]@{ ParentPath = $Matches.Parent; ServerPath = $normalized; ServerSubKey = $Matches.Server }
    }

    return $null
}

function Invoke-WmtRegExeDeleteImportFallback {
    param([object[]]$RegTargets)
    if ($null -eq $RegTargets -or $RegTargets.Count -eq 0) { return $false }

    $deletePaths = [System.Collections.Generic.List[string]]::new()
    $seen = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
    foreach ($target in @($RegTargets)) {
        if ($null -eq $target -or [string]::IsNullOrWhiteSpace([string]$target.RegPath)) { continue }
        $path = ([string]$target.RegPath).Trim()
        if ($path -match '^(?i)HKEY_CLASSES_ROOT\\WOW6432Node\\|^HKEY_LOCAL_MACHINE\\SOFTWARE\\WOW6432Node\\|^HKEY_LOCAL_MACHINE\\SOFTWARE\\Classes\\|^HKEY_CURRENT_USER\\Software\\Classes\\|^HKEY_CLASSES_ROOT\\CLSID\\') {
            if ($seen.Add($path)) { [void]$deletePaths.Add($path) }
        }
    }
    if ($deletePaths.Count -eq 0) { return $false }

    $tmpFile = Join-Path ([System.IO.Path]::GetTempPath()) ("WMT_RegDelete_{0}.reg" -f ([guid]::NewGuid().ToString('N')))
    try {
        $content = [System.Text.StringBuilder]::new()
        [void]$content.AppendLine('Windows Registry Editor Version 5.00')
        [void]$content.AppendLine('')
        foreach ($path in $deletePaths) {
            [void]$content.AppendLine("[-$path]")
            [void]$content.AppendLine('')
        }
        [System.IO.File]::WriteAllText($tmpFile, $content.ToString(), [System.Text.Encoding]::Unicode)

        foreach ($regExe in @(Get-WmtRegExeCandidatePaths)) {
            try { & $regExe import $tmpFile 1>$null 2>$null } catch {}
        }
    }
    catch {}
    finally {
        Remove-Item -LiteralPath $tmpFile -Force -ErrorAction SilentlyContinue
    }

    return $true
}

function Add-WmtRegExeTarget {
    param(
        [System.Collections.Generic.List[object]]$Targets,
        [System.Collections.Generic.HashSet[string]]$Seen,
        [string]$RegPath,
        [string]$View
    )
    if ([string]::IsNullOrWhiteSpace($RegPath)) { return }
    $cleanPath = ([string]$RegPath).Trim()
    $cleanView = if ([string]::IsNullOrWhiteSpace($View)) { "" } else { ([string]$View).Trim() }
    $key = "$cleanPath`0$cleanView"
    if ($Seen.Add($key)) {
        [void]$Targets.Add([PSCustomObject]@{ RegPath = $cleanPath; View = $cleanView })
    }
}

function ConvertTo-WmtRegExeKeyDeleteTargets {
    param([string]$Path)

    $targets = [System.Collections.Generic.List[object]]::new()
    $seen = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
    if ([string]::IsNullOrWhiteSpace($Path)) { return $targets }

    $normalized = ([string]$Path).Trim() -replace '^Registry::', '' -replace '^Computer\\', ''
    $normalized = $normalized -replace '^HKEY_LOCAL_MACHINE\\', 'HKLM:\'
    $normalized = $normalized -replace '^HKEY_CURRENT_USER\\', 'HKCU:\'
    $normalized = $normalized -replace '^HKEY_CLASSES_ROOT\\', 'HKCR:\'
    $normalized = $normalized -replace '^HKEY_USERS\\', 'HKU:\'

    $baseRegPath = Convert-WmtRegistryPathToRegExePath -Path $normalized
    Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath $baseRegPath -View $null

    if ($normalized -match '^(?i)HKCR:\\WOW6432Node\\(?<Rest>.+)$') {
        $rest = $Matches.Rest
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_CLASSES_ROOT\$rest" -View "32"
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_LOCAL_MACHINE\SOFTWARE\Classes\$rest" -View "32"
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_LOCAL_MACHINE\SOFTWARE\WOW6432Node\Classes\$rest" -View "64"
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_LOCAL_MACHINE\SOFTWARE\Classes\WOW6432Node\$rest" -View "64"
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_CURRENT_USER\Software\Classes\WOW6432Node\$rest" -View "64"
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_CLASSES_ROOT\WOW6432Node\$rest" -View "64"
    }
    elseif ($normalized -match '^(?i)HKLM:\\SOFTWARE\\WOW6432Node\\Classes\\(?<Rest>.+)$') {
        $rest = $Matches.Rest
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_LOCAL_MACHINE\SOFTWARE\Classes\$rest" -View "32"
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_LOCAL_MACHINE\SOFTWARE\WOW6432Node\Classes\$rest" -View "64"
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_CLASSES_ROOT\$rest" -View "32"
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_CLASSES_ROOT\WOW6432Node\$rest" -View "64"
    }
    elseif ($normalized -match '^(?i)HKLM:\\SOFTWARE\\Classes\\WOW6432Node\\(?<Rest>.+)$') {
        $rest = $Matches.Rest
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_LOCAL_MACHINE\SOFTWARE\Classes\WOW6432Node\$rest" -View "64"
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_LOCAL_MACHINE\SOFTWARE\WOW6432Node\Classes\$rest" -View "64"
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_LOCAL_MACHINE\SOFTWARE\Classes\$rest" -View "32"
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_CLASSES_ROOT\WOW6432Node\$rest" -View "64"
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_CLASSES_ROOT\$rest" -View "32"
    }
    elseif ($normalized -match '^(?i)HKLM:\\SOFTWARE\\Classes\\(?<Rest>.+)$') {
        $rest = $Matches.Rest
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_LOCAL_MACHINE\SOFTWARE\Classes\$rest" -View "64"
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_CLASSES_ROOT\$rest" -View "64"
    }
    elseif ($normalized -match '^(?i)HKLM:\\SOFTWARE\\WOW6432Node\\(?<Rest>.+)$') {
        $rest = $Matches.Rest
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_LOCAL_MACHINE\SOFTWARE\$rest" -View "32"
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_LOCAL_MACHINE\SOFTWARE\WOW6432Node\$rest" -View "64"
    }
    elseif ($normalized -match '^(?i)HKLM:\\(?<Rest>.+)$') {
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_LOCAL_MACHINE\$($Matches.Rest)" -View "64"
    }
    elseif ($normalized -match '^(?i)HKCU:\\Software\\Classes\\WOW6432Node\\(?<Rest>.+)$') {
        $rest = $Matches.Rest
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_CURRENT_USER\Software\Classes\$rest" -View "32"
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_CURRENT_USER\Software\Classes\WOW6432Node\$rest" -View "64"
    }
    elseif ($normalized -match '^(?i)HKCU:\\(?<Rest>.+)$') {
        Add-WmtRegExeTarget -Targets $targets -Seen $seen -RegPath "HKEY_CURRENT_USER\$($Matches.Rest)" -View $null
    }

    return $targets
}

function Test-WmtRegExeKeyExists {
    param(
        [string]$RegPath,
        [string]$View
    )
    if ([string]::IsNullOrWhiteSpace($RegPath)) { return $false }

    $regArgs = @('query', $RegPath)
    if ($View -eq '32') { $regArgs += '/reg:32' }
    elseif ($View -eq '64') { $regArgs += '/reg:64' }

    foreach ($regExe in @(Get-WmtRegExeCandidatePaths)) {
        try {
            & $regExe @regArgs 1>$null 2>$null
            if ($LASTEXITCODE -eq 0) { return $true }
        }
        catch {}
    }

    return $false
}

function Remove-WmtRegistryKeyRegExe {
    param(
        [string]$RegPath,
        [string]$View
    )
    if ([string]::IsNullOrWhiteSpace($RegPath)) { return $false }

    $regArgs = @('delete', $RegPath, '/f')
    if ($View -eq '32') { $regArgs += '/reg:32' }
    elseif ($View -eq '64') { $regArgs += '/reg:64' }

    $errors = [System.Collections.Generic.List[string]]::new()
    foreach ($regExe in @(Get-WmtRegExeCandidatePaths)) {
        try {
            $deleteOutput = (& $regExe @regArgs 2>&1 | Out-String).Trim()
            $exit = $LASTEXITCODE
            $stillExistsAfterDelete = Test-WmtRegExeKeyExists -RegPath $RegPath -View $View
            if ($exit -eq 0 -and -not $stillExistsAfterDelete) { return $true }
            if ($exit -ne 0 -or $stillExistsAfterDelete -or -not [string]::IsNullOrWhiteSpace($deleteOutput)) {
                $viewText = if ([string]::IsNullOrWhiteSpace($View)) { 'default' } else { "reg:$View" }
                $statusText = if ($stillExistsAfterDelete) { 'still-exists-after-delete' } else { 'not-present-after-delete' }
                [void]$errors.Add("$regExe $viewText exit=$exit status=$statusText output=$deleteOutput")
            }
        }
        catch {
            $viewText = if ([string]::IsNullOrWhiteSpace($View)) { 'default' } else { "reg:$View" }
            [void]$errors.Add("$regExe $viewText exception=$($_.Exception.Message)")
        }
    }

    if ($errors.Count -gt 0) {
        $script:WmtLastRegExeDeleteError = ($errors -join ' | ')
    }
    return (-not (Test-WmtRegExeKeyExists -RegPath $RegPath -View $View))
}

function Remove-RegKeyForced {
    param($Path, $IsKey, $ValName)

    $script:WmtLastRegistryDeleteFailure = $null
    $script:WmtLastRegExeDeleteError = $null

    $attemptLog = [System.Collections.Generic.List[string]]::new()
    $AddAttempt = {
        param([string]$Message)
        if (-not [string]::IsNullOrWhiteSpace($Message)) { [void]$attemptLog.Add($Message) }
    }
    $GetElevationState = {
        try {
            $identity = [System.Security.Principal.WindowsIdentity]::GetCurrent()
            $principal = New-Object System.Security.Principal.WindowsPrincipal($identity)
            return [bool]$principal.IsInRole([System.Security.Principal.WindowsBuiltInRole]::Administrator)
        }
        catch { return $false }
    }
    $SetDeleteFailure = {
        param([string]$Reason)
        $elevated = & $GetElevationState
        $attemptText = if ($attemptLog.Count -gt 0) { " Attempts: " + (($attemptLog | Select-Object -Unique) -join ' | ') } else { " Attempts: none captured" }
        $regExeError = if (-not [string]::IsNullOrWhiteSpace([string]$script:WmtLastRegExeDeleteError)) { " reg.exe detail: $script:WmtLastRegExeDeleteError" } else { "" }
        $elevationHint = if ($elevated) { "Process elevated: True." } else { "Process elevated: False. HKLM/HKCR machine keys usually require Run as administrator." }
        $script:WmtLastRegistryDeleteFailure = "$Reason $elevationHint$attemptText$regExeError"
    }

    try {
        if ([string]::IsNullOrWhiteSpace([string]$Path)) {
            & $SetDeleteFailure "Registry path was blank, so WMT skipped deletion."
            return $false
        }

        $normalizedPath = ([string]$Path).Trim() -replace "^Registry::", "" -replace "^Computer\\", ""
        $normalizedPath = $normalizedPath -replace "^HKEY_CLASSES_ROOT\\", "HKCR:\\"
        $normalizedPath = $normalizedPath -replace "^HKEY_LOCAL_MACHINE\\", "HKLM:\\"
        $normalizedPath = $normalizedPath -replace "^HKEY_CURRENT_USER\\", "HKCU:\\"
        $normalizedPath = $normalizedPath -replace "^HKEY_USERS\\", "HKU:\\"
        & $AddAttempt "normalized=$normalizedPath"

        if (-not $IsKey) {
            $targetPaths = @()
            foreach ($target in @(ConvertTo-WmtRegistryDeleteTargetSet -Path $normalizedPath)) {
                if ($target.Kind -eq "Provider" -and -not [string]::IsNullOrWhiteSpace([string]$target.Path)) {
                    $targetPaths += [string]$target.Path
                }
            }
            if ($targetPaths.Count -eq 0) { $targetPaths = @($normalizedPath) }

            $globalValueSuccess = $true
            $literalValueName = if ($null -ne $ValName) { [System.Management.Automation.WildcardPattern]::Escape([string]$ValName) } else { $ValName }
            foreach ($targetPath in ($targetPaths | Select-Object -Unique)) {
                & $AddAttempt "value-target=$targetPath value=$ValName"
                if (-not (Test-WmtRegistryValueExists -Path $targetPath -ValueName $ValName)) { continue }
                try {
                    [void](Remove-WmtRegistryValueNative -Path $targetPath -ValueName $ValName)
                    if (Test-WmtRegistryValueExists -Path $targetPath -ValueName $ValName) {
                        try { Remove-ItemProperty -LiteralPath $targetPath -Name $literalValueName -ErrorAction Stop } catch { & $AddAttempt "Remove-ItemProperty failed: $($_.Exception.Message)" }
                    }
                    if (Test-WmtRegistryValueExists -Path $targetPath -ValueName $ValName) {
                        [void](Remove-WmtRegistryValueRegExe -Path $targetPath -ValueName $ValName)
                    }
                    if (Test-WmtRegistryValueExists -Path $targetPath -ValueName $ValName) {
                        $globalValueSuccess = $false
                        & $AddAttempt "value-still-exists=$targetPath value=$ValName"
                    }
                }
                catch {
                    $globalValueSuccess = $false
                    & $AddAttempt "value-delete-exception=$targetPath error=$($_.Exception.Message)"
                }
            }
            if (-not $globalValueSuccess) { & $SetDeleteFailure "Value deletion failed verification." }
            return $globalValueSuccess
        }

        $comServerInfo = ConvertTo-WmtComClassServerSubPath -Path $normalizedPath
        $comClassParentPath = if ($comServerInfo) { [string]$comServerInfo.ParentPath } else { $null }
        $allowNativeAclUnlock = ($normalizedPath -match '^(?i)(HKLM:\\SOFTWARE\\(WOW6432Node\\)?Classes\\CLSID\\|HKCR:\\(WOW6432Node\\)?CLSID\\)' -or -not [string]::IsNullOrWhiteSpace($comClassParentPath))
        if (-not [string]::IsNullOrWhiteSpace($comClassParentPath)) {
            & $AddAttempt "COM server path detected; deleting parent CLSID=$comClassParentPath"
        }

        $deleteTargets = @()
        if (-not [string]::IsNullOrWhiteSpace($comClassParentPath)) {
            $deleteTargets += @(ConvertTo-WmtRegistryDeleteTargetSet -Path $comClassParentPath)
        }
        $deleteTargets += @(ConvertTo-WmtRegistryDeleteTargetSet -Path $normalizedPath)
        if ($deleteTargets.Count -eq 0) {
            $deleteTargets = @([PSCustomObject]@{ Kind = "Provider"; Path = $normalizedPath })
        }

        $regExeTargets = @()
        if (-not [string]::IsNullOrWhiteSpace($comClassParentPath)) { $regExeTargets += @(ConvertTo-WmtRegExeKeyDeleteTargets -Path $comClassParentPath) }
        $regExeTargets += @(ConvertTo-WmtRegExeKeyDeleteTargets -Path $normalizedPath)

        $DescribeTarget = {
            param($Target)
            if ($null -eq $Target) { return "<null>" }
            if ($Target.Kind -eq "Native") { return "$($Target.Label): $($Target.SubPath)" }
            return [string]$Target.Path
        }
        $TestTargetExists = {
            param($Target)
            try {
                if ($Target.Kind -eq "Native") {
                    return (Test-WmtRegistryKeyExistsNative -Hive $Target.Hive -View $Target.View -SubPath $Target.SubPath)
                }
                return (Test-Path -LiteralPath ([string]$Target.Path) -ErrorAction SilentlyContinue)
            }
            catch {
                & $AddAttempt "exist-check-exception=$(& $DescribeTarget $Target) error=$($_.Exception.Message)"
                return $false
            }
        }

        foreach ($target in @($deleteTargets)) { & $AddAttempt "candidate=$(& $DescribeTarget $target)" }
        foreach ($target in @($regExeTargets)) {
            $viewText = if ([string]::IsNullOrWhiteSpace([string]$target.View)) { "default" } else { "reg:$($target.View)" }
            & $AddAttempt "reg-candidate=$viewText $($target.RegPath)"
        }

        $UnlockProviderPath = {
            param([string]$ProviderPath)
            if ([string]::IsNullOrWhiteSpace($ProviderPath) -or -not (Test-Path -LiteralPath $ProviderPath -ErrorAction SilentlyContinue)) { return }
            try {
                $sid = New-Object System.Security.Principal.SecurityIdentifier([System.Security.Principal.WellKnownSidType]::BuiltinAdministratorsSid, $null)
                $adminUser = $sid.Translate([System.Security.Principal.NTAccount])
                $rule = New-Object System.Security.AccessControl.RegistryAccessRule($adminUser, "FullControl", "ContainerInherit,ObjectInherit", "None", "Allow")
                $unlockOne = {
                    param([string]$p)
                    try {
                        $acl = Get-Acl -LiteralPath $p -ErrorAction Stop
                        $acl.SetOwner($adminUser)
                        Set-Acl -LiteralPath $p -AclObject $acl -ErrorAction Stop
                        $acl = Get-Acl -LiteralPath $p -ErrorAction Stop
                        $acl.SetAccessRule($rule)
                        Set-Acl -LiteralPath $p -AclObject $acl -ErrorAction Stop
                    }
                    catch { & $AddAttempt "acl-provider-failed=$p error=$($_.Exception.Message)" }
                }
                try {
                    foreach ($child in @(Get-ChildItem -LiteralPath $ProviderPath -Recurse -ErrorAction SilentlyContinue)) {
                        & $unlockOne ([string]$child.PSPath)
                    }
                }
                catch { & $AddAttempt "acl-enumerate-failed=$ProviderPath error=$($_.Exception.Message)" }
                & $unlockOne $ProviderPath
            }
            catch { & $AddAttempt "acl-provider-wrapper-failed=$ProviderPath error=$($_.Exception.Message)" }
        }

        $existingTargets = @($deleteTargets | Where-Object { & $TestTargetExists $_ })
        $existingRegExeTargets = @($regExeTargets | Where-Object { Test-WmtRegExeKeyExists -RegPath $_.RegPath -View $_.View })
        if ($existingTargets.Count -eq 0 -and $existingRegExeTargets.Count -eq 0) { return $true }
        & $AddAttempt "existing-provider/native=$($existingTargets.Count) existing-regexe=$($existingRegExeTargets.Count)"

        foreach ($target in $existingTargets) {
            if ($target.Kind -eq "Provider") { & $UnlockProviderPath ([string]$target.Path) }
        }
        if ($allowNativeAclUnlock) {
            foreach ($target in $existingTargets) {
                if ($target.Kind -eq "Native") {
                    try {
                        $aclChanged = Grant-WmtRegistryKeyFullControlNative -Hive $target.Hive -View $target.View -SubPath $target.SubPath
                        & $AddAttempt "acl-native=$($target.Label):$($target.SubPath) changed=$aclChanged"
                    }
                    catch { & $AddAttempt "acl-native-exception=$($target.Label):$($target.SubPath) error=$($_.Exception.Message)" }
                }
            }
        }

        foreach ($target in $existingTargets) {
            if (-not (& $TestTargetExists $target)) { continue }
            try {
                if ($target.Kind -eq "Native") {
                    $nativeResult = Remove-WmtRegistryKeyNative -Hive $target.Hive -View $target.View -SubPath $target.SubPath
                    & $AddAttempt "delete-native=$($target.Label):$($target.SubPath) result=$nativeResult"
                }
                else {
                    Remove-Item -LiteralPath ([string]$target.Path) -Recurse -Force -ErrorAction Stop
                    & $AddAttempt "delete-provider=$($target.Path) result=True"
                }
            }
            catch {
                & $AddAttempt "delete-exception=$(& $DescribeTarget $target) error=$($_.Exception.Message)"
                if ($target.Kind -eq "Provider") {
                    try {
                        & $UnlockProviderPath ([string]$target.Path)
                        Remove-Item -LiteralPath ([string]$target.Path) -Recurse -Force -ErrorAction Stop
                        & $AddAttempt "delete-provider-retry=$($target.Path) result=True"
                    }
                    catch { & $AddAttempt "delete-provider-retry-failed=$($target.Path) error=$($_.Exception.Message)" }
                }
            }
        }

        foreach ($target in $existingTargets) {
            if ($target.Kind -eq "Native" -and (& $TestTargetExists $target)) {
                try {
                    if ($allowNativeAclUnlock) { [void](Grant-WmtRegistryKeyFullControlNative -Hive $target.Hive -View $target.View -SubPath $target.SubPath) }
                    $nativeRetryResult = Remove-WmtRegistryKeyNative -Hive $target.Hive -View $target.View -SubPath $target.SubPath
                    & $AddAttempt "delete-native-retry=$($target.Label):$($target.SubPath) result=$nativeRetryResult"
                }
                catch { & $AddAttempt "delete-native-retry-exception=$($target.Label):$($target.SubPath) error=$($_.Exception.Message)" }
            }
        }

        foreach ($regTarget in $regExeTargets) {
            try {
                $viewText = if ([string]::IsNullOrWhiteSpace([string]$regTarget.View)) { "default" } else { "reg:$($regTarget.View)" }
                if (Test-WmtRegExeKeyExists -RegPath $regTarget.RegPath -View $regTarget.View) {
                    $regResult = Remove-WmtRegistryKeyRegExe -RegPath $regTarget.RegPath -View $regTarget.View
                    & $AddAttempt "delete-regexe=$viewText $($regTarget.RegPath) result=$regResult"
                }
                else {
                    & $AddAttempt "delete-regexe-skip-not-found=$viewText $($regTarget.RegPath)"
                }
            }
            catch { & $AddAttempt "delete-regexe-exception=$($regTarget.RegPath) error=$($_.Exception.Message)" }
        }
        if ($allowNativeAclUnlock) {
            try {
                $importResult = Invoke-WmtRegExeDeleteImportFallback -RegTargets $regExeTargets
                & $AddAttempt "delete-reg-import-fallback result=$importResult"
            }
            catch { & $AddAttempt "delete-reg-import-fallback-exception=$($_.Exception.Message)" }
        }

        $remainingTargets = @($deleteTargets | Where-Object { & $TestTargetExists $_ })
        $remainingRegExeTargets = @($regExeTargets | Where-Object { Test-WmtRegExeKeyExists -RegPath $_.RegPath -View $_.View })
        $success = ($remainingTargets.Count -eq 0 -and $remainingRegExeTargets.Count -eq 0)
        if (-not $success) {
            $remainingLabels = @(
                foreach ($target in $remainingTargets) { & $DescribeTarget $target }
                foreach ($target in $remainingRegExeTargets) {
                    $viewText = if ([string]::IsNullOrWhiteSpace([string]$target.View)) { "default" } else { "reg:$($target.View)" }
                    "reg.exe ${viewText}: $($target.RegPath)"
                }
            )
            $likely = if (-not (& $GetElevationState)) {
                "Likely cause: WMT is not elevated, so HKLM/HKCR machine keys cannot be deleted."
            }
            else {
                "Likely cause: ACL protection/ownership blocked deletion, or a Windows/Office component recreated the COM registration before verification."
            }
            & $SetDeleteFailure "Key still exists after all delete attempts. Remaining target(s): $($remainingLabels -join '; '). $likely"
        }
        return $success
    }
    catch {
        & $AddAttempt "top-level-exception=$($_.Exception.Message)"
        & $SetDeleteFailure "Registry delete helper crashed before verification."
        return $false
    }
}

function Backup-RegKey {
    param($ItemObj, $FilePath)
    $path = $ItemObj.RegPath; $targetValue = $ItemObj.ValueName; $type = $ItemObj.Type
    if ([string]::IsNullOrWhiteSpace($path)) { return }
    $comBackupParent = if ($type -eq "Key") { ConvertTo-WmtComClassParentPath -Path $path } else { $null }
    if (-not [string]::IsNullOrWhiteSpace($comBackupParent)) { $path = $comBackupParent }
    $regKeyPath = Convert-WmtRegistryPathToRegExePath -Path $path
    if ([string]::IsNullOrWhiteSpace($regKeyPath)) { return }
    $providerPath = ([string]$path).Trim() -replace "^Registry::", "" -replace "^Computer\\", ""
    $providerPath = $providerPath -replace "^HKEY_LOCAL_MACHINE\\", "Registry::HKEY_LOCAL_MACHINE\"
    $providerPath = $providerPath -replace "^HKEY_CURRENT_USER\\", "Registry::HKEY_CURRENT_USER\"
    $providerPath = $providerPath -replace "^HKEY_CLASSES_ROOT\\", "Registry::HKEY_CLASSES_ROOT\"
    $providerPath = $providerPath -replace "^HKEY_USERS\\", "Registry::HKEY_USERS\"
    $providerPath = $providerPath -replace "^HKLM:?\\", "Registry::HKEY_LOCAL_MACHINE\"
    $providerPath = $providerPath -replace "^HKCU:?\\", "Registry::HKEY_CURRENT_USER\"
    $providerPath = $providerPath -replace "^HKCR:?\\", "Registry::HKEY_CLASSES_ROOT\"
    $providerPath = $providerPath -replace "^HKU:?\\", "Registry::HKEY_USERS\"
    $sb = [System.Text.StringBuilder]::new(); [void]$sb.AppendLine("[$regKeyPath]")
    try {
        if ($type -eq "Key" -or $type -eq "SetValue") {
            $tmpFile = Join-Path ([System.IO.Path]::GetTempPath()) ("WMT_RegBackup_{0}.reg" -f ([guid]::NewGuid().ToString("N")))
            try {
                & reg.exe export $regKeyPath $tmpFile /y | Out-Null
                if (Test-Path -LiteralPath $tmpFile) {
                    $content = Get-Content -LiteralPath $tmpFile -Raw -Encoding Unicode
                    $content = $content -replace "^\uFEFF?Windows Registry Editor Version 5\.00\r?\n\r?\n", ""
                    if (-not [string]::IsNullOrWhiteSpace($content)) {
                        Add-Content -Path $FilePath -Value $content -Encoding Unicode
                        return
                    }
                }
            }
            catch {}
            finally {
                Remove-Item -LiteralPath $tmpFile -Force -ErrorAction SilentlyContinue
            }
        }
        elseif ($type -eq "Value") {
            $val = Get-ItemProperty -Path $providerPath -Name $targetValue -ErrorAction SilentlyContinue
            if ($val) { 
                $vData = $val.$targetValue
                if ($vData -is [string]) { $vData = '"' + ($vData -replace '\\', '\\' -replace '"', '\"') + '"' } 
                elseif ($vData -is [int]) { $vData = "dword:{0:x8}" -f $vData }
                [void]$sb.AppendLine("`"$targetValue`"=$vData") 
            }
        }
        [void]$sb.AppendLine(""); Add-Content -Path $FilePath -Value $sb.ToString() -Encoding Unicode
    }
    catch {}
}


function Start-WmtRegistryCleanupBackground {
    param(
        [object[]]$Items,
        [string]$BackupDirectory
    )

    if ($script:WmtRegistryCleanupActive) {
        Show-WmtMessageBox -Message "A registry cleanup is already running in the background. Please wait for it to finish before starting another cleanup." -Title "Registry Cleaner" -Image Information | Out-Null
        return
    }

    $selectedItems = @($Items | Where-Object { $null -ne $_ -and -not [string]::IsNullOrWhiteSpace([string]$_.RegPath) })
    if ($selectedItems.Count -eq 0) { return }

    if ([string]::IsNullOrWhiteSpace($BackupDirectory)) {
        $BackupDirectory = Join-Path (Get-DataPath) "RegistryBackups"
    }
    if (-not (Test-Path -LiteralPath $BackupDirectory -PathType Container -ErrorAction SilentlyContinue)) {
        New-Item -Path $BackupDirectory -ItemType Directory -Force | Out-Null
    }

    [xml]$cleanupProgressXaml = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="Registry Cleanup Running" Width="620" Height="216" MinWidth="580" MinHeight="200" ResizeMode="NoResize" WindowStartupLocation="CenterOwner"
        Background="{DynamicResource BgDark}" Foreground="{DynamicResource TextPrimary}"
        FontFamily="Segoe UI Variable Display, Segoe UI, Arial" FontSize="13">
    <Grid Margin="20">
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="42"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="*"/>
        </Grid.RowDefinitions>
        <TextBlock Name="lblTitle" Text="Registry cleanup is running in the background" FontSize="17" FontWeight="SemiBold" Foreground="{DynamicResource TextPrimary}"/>
        <TextBlock Name="lblStatus" Grid.Row="1" Margin="0,8,0,8" Text="Starting..." Foreground="{DynamicResource TextSecondary}"
                   TextTrimming="CharacterEllipsis" TextWrapping="NoWrap" Height="26" MaxHeight="26"
                   ToolTip="{Binding Text, RelativeSource={RelativeSource Self}}"/>
        <ProgressBar Name="barProgress" Grid.Row="2" Minimum="0" Maximum="100" Height="12" IsIndeterminate="False"/>
        <Grid Grid.Row="3" Margin="0,18,0,0">
            <TextBlock Text="You can keep using WMT while this runs." VerticalAlignment="Bottom" HorizontalAlignment="Left" Foreground="{DynamicResource TextSecondary}"/>
            <Button Name="btnHide" Content="Hide" Width="96" Height="34" HorizontalAlignment="Right" VerticalAlignment="Bottom"/>
        </Grid>
    </Grid>
</Window>
'@

    $progressWindow = $null
    $lblStatus = $null
    $barProgress = $null
    try {
        $progressWindow = New-WmtWindowFromFullXaml -Xaml $cleanupProgressXaml
        $lblStatus = $progressWindow.FindName("lblStatus")
        $barProgress = $progressWindow.FindName("barProgress")
        $btnHide = $progressWindow.FindName("btnHide")
        if ($btnHide) {
            $btnHide.Add_Click({ try { $progressWindow.Close() } catch {} }.GetNewClosure())
        }
        $progressWindow.Show() | Out-Null
    }
    catch {
        Write-GuiLog "Registry cleanup progress window could not open: $($_.Exception.Message)"
    }

    $cleanupSync = [hashtable]::Synchronized(@{
            Logs        = [System.Collections.ArrayList]::Synchronized([System.Collections.ArrayList]::new())
            Status      = "Starting registry cleanup..."
            Progress    = 0
            IsCompleted = $false
            Error       = $null
            Result      = $null
        })

    $functionNames = @(
        "Convert-WmtRegistryPath",
        "Convert-WmtRegistryPathToRegExePath",
        "Test-WmtRegistryValueExists",
        "Remove-WmtRegistryValueNative",
        "Test-WmtRegistryKeyExistsNative",
        "Remove-WmtRegistryKeyNative",
        "Grant-WmtRegistryKeyFullControlNative",
        "ConvertTo-WmtRegistryDeleteTargetSet",
        "Set-WmtRegistryValueNative",
        "Remove-WmtRegistryValueRegExe",
        "Get-WmtRegExeCandidatePaths",
        "ConvertTo-WmtComClassParentPath",
        "ConvertTo-WmtComClassServerSubPath",
        "Invoke-WmtRegExeDeleteImportFallback",
        "Add-WmtRegExeTarget",
        "ConvertTo-WmtRegExeKeyDeleteTargets",
        "Test-WmtRegExeKeyExists",
        "Remove-WmtRegistryKeyRegExe",
        "Remove-RegKeyForced",
        "Backup-RegKey"
    )

    $iss = [System.Management.Automation.Runspaces.InitialSessionState]::CreateDefault()
    foreach ($fnName in $functionNames) {
        try {
            $cmd = Get-Command -Name $fnName -CommandType Function -ErrorAction Stop
            $iss.Commands.Add([System.Management.Automation.Runspaces.SessionStateFunctionEntry]::new($fnName, $cmd.Definition))
        }
        catch {
            Write-GuiLog "Registry cleanup background worker missing helper $fnName`: $($_.Exception.Message)"
        }
    }

    $runspace = $null
    $ps = $null
    try {
        $runspace = [System.Management.Automation.Runspaces.RunspaceFactory]::CreateRunspace($iss)
        $runspace.ApartmentState = "STA"
        $runspace.ThreadOptions = "ReuseThread"
        $runspace.Open()
        $runspace.SessionStateProxy.SetVariable("CleanupSync", $cleanupSync)
        $runspace.SessionStateProxy.SetVariable("CleanupItems", $selectedItems)
        $runspace.SessionStateProxy.SetVariable("CleanupBackupDirectory", $BackupDirectory)

        $workerScript = {
            Import-Module Microsoft.PowerShell.Management
            Import-Module Microsoft.PowerShell.Security

            function Add-WmtCleanupWorkerLog {
                param([string]$Message)
                if ([string]::IsNullOrWhiteSpace($Message)) { return }
                try { [void]$CleanupSync.Logs.Add($Message) } catch {}
            }

            try {
                $itemsToClean = @($CleanupItems | Where-Object { $null -ne $_ -and -not [string]::IsNullOrWhiteSpace([string]$_.RegPath) })
                if (-not (Test-Path -LiteralPath $CleanupBackupDirectory -PathType Container -ErrorAction SilentlyContinue)) {
                    New-Item -Path $CleanupBackupDirectory -ItemType Directory -Force | Out-Null
                }

                $timestamp = Get-Date -Format "yyyyMMdd_HHmmss"
                $bkFile = Join-Path $CleanupBackupDirectory ("DeepClean_Backup_{0}.reg" -f $timestamp)
                $skipLogFile = Join-Path $CleanupBackupDirectory ("DeepClean_Skipped_{0}.log" -f $timestamp)
                $fixed = 0
                $skipped = 0
                $backedUpKeys = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
                $backupState = [pscustomobject]@{ Created = $false; Count = 0 }
                $skipLogState = [pscustomobject]@{ Created = $false }

                $ensureSkippedRegistryLog = {
                    try {
                        if (-not $skipLogState.Created) {
                            Set-Content -Path $skipLogFile -Value @(
                                "WMT Registry Cleanup skipped/failed item log",
                                "Started: $(Get-Date -Format o)",
                                "Only successfully changed registry entries are appended to the .reg backup.",
                                "No .reg backup is written unless at least one selected item is successfully changed.",
                                ""
                            ) -Encoding UTF8
                            $skipLogState.Created = $true
                        }
                    }
                    catch {}
                }

                $writeSkippedRegistryLog = {
                    param($Item, [string]$Reason, [string]$Detail)
                    try {
                        & $ensureSkippedRegistryLog
                        $lines = @(
                            "[$(Get-Date -Format o)] $Reason",
                            "Problem: $($Item.Problem)",
                            "Action: $($Item.Action)",
                            "Type: $($Item.Type)",
                            "DisplayKey: $($Item.DisplayKey)",
                            "RegPath: $($Item.RegPath)",
                            "ValueName: $($Item.ValueName)",
                            "Data: $($Item.Data)",
                            "WhyFlagged: $($Item.WhyFlagged)",
                            "Detail: $Detail",
                            ""
                        )
                        Add-Content -Path $skipLogFile -Value $lines -Encoding UTF8
                    }
                    catch {}
                }

                $appendVerifiedBackup = {
                    param([string]$TempBackupFile)
                    if ([string]::IsNullOrWhiteSpace($TempBackupFile) -or -not (Test-Path -LiteralPath $TempBackupFile -PathType Leaf -ErrorAction SilentlyContinue)) { return }
                    try {
                        $content = Get-Content -LiteralPath $TempBackupFile -Raw -Encoding Unicode
                        $content = $content -replace '^\uFEFF?Windows Registry Editor Version 5\.00\r?\n\r?\n', ''
                        if (-not [string]::IsNullOrWhiteSpace($content)) {
                            if (-not $backupState.Created) {
                                Set-Content -Path $bkFile -Value "Windows Registry Editor Version 5.00`r`n`r`n" -Encoding Unicode
                                $backupState.Created = $true
                            }
                            Add-Content -Path $bkFile -Value $content -Encoding Unicode
                            $backupState.Count++
                        }
                    }
                    catch {
                        try {
                            & $ensureSkippedRegistryLog
                            Add-Content -Path $skipLogFile -Value @("[$(Get-Date -Format o)] Backup append failed", "Detail: $($_.Exception.Message)", "") -Encoding UTF8
                        }
                        catch {}
                    }
                }

                $total = [Math]::Max(1, $itemsToClean.Count)
                $index = 0
                Add-WmtCleanupWorkerLog "Registry cleanup started in background. Selected items: $($itemsToClean.Count)"

                foreach ($item in $itemsToClean) {
                    $index++
                    $CleanupSync.Progress = [Math]::Min(100, [int](($index - 1) * 100 / $total))
                    $CleanupSync.Status = "Processing $index of $total`: $($item.DisplayKey)"

                    if ($item.Type -eq "ReviewOnly") {
                        $skipped++
                        Add-WmtCleanupWorkerLog "Review only (not changed): $($item.DisplayKey)"
                        & $writeSkippedRegistryLog $item "ReviewOnly" "Item is informational/review-only and WMT intentionally did not modify it."
                        continue
                    }

                    $uid = "$($item.RegPath):$($item.ValueName)"
                    $itemBackupFile = Join-Path ([System.IO.Path]::GetTempPath()) ("WMT_RegistryItemBackup_{0}.reg" -f ([guid]::NewGuid().ToString("N")))
                    $shouldAppendItemBackup = $false
                    if ($backedUpKeys.Add($uid)) {
                        Set-Content -Path $itemBackupFile -Value "Windows Registry Editor Version 5.00`r`n`r`n" -Encoding Unicode
                        Backup-RegKey -ItemObj $item -FilePath $itemBackupFile
                        $shouldAppendItemBackup = $true
                    }

                    if ($item.Type -eq "SetValue") {
                        Add-WmtCleanupWorkerLog "Updating: $($item.DisplayKey)"
                    }
                    else {
                        Add-WmtCleanupWorkerLog "Removing: $($item.DisplayKey)"
                    }

                    if ($item.Type -eq "SetValue") {
                        $success = Set-WmtRegistryValueNative -Path $item.RegPath -ValueName $item.ValueName -ValueData $item.NewData
                    }
                    else {
                        $isKey = ($item.Type -eq "Key")
                        $success = Remove-RegKeyForced -Path $item.RegPath -IsKey $isKey -ValName $item.ValueName
                    }

                    if ($success) {
                        $fixed++
                        if ($shouldAppendItemBackup) { & $appendVerifiedBackup $itemBackupFile }
                        if ($item.Type -eq "SetValue") {
                            Add-WmtCleanupWorkerLog "Updated: $($item.RegPath)\$($item.ValueName)"
                        }
                        else {
                            Add-WmtCleanupWorkerLog "Removed: $($item.RegPath)"
                        }
                    }
                    else {
                        $skipped++
                        if ($item.Type -eq "SetValue") {
                            Add-WmtCleanupWorkerLog "Failed to update: $($item.RegPath)\$($item.ValueName)"
                            & $writeSkippedRegistryLog $item "Update failed" "The value was still present or could not be verified after SetValue."
                        }
                        else {
                            $deleteFailureDetail = if (-not [string]::IsNullOrWhiteSpace([string]$script:WmtLastRegistryDeleteFailure)) { $script:WmtLastRegistryDeleteFailure } else { "Delete helper returned failure but did not provide a remaining target. Run elevated and check whether another service recreated the key immediately." }
                            Add-WmtCleanupWorkerLog "Failed to remove: $($item.RegPath) - $deleteFailureDetail"
                            & $writeSkippedRegistryLog $item "Delete failed" $deleteFailureDetail
                        }
                    }

                    Remove-Item -LiteralPath $itemBackupFile -Force -ErrorAction SilentlyContinue
                    $CleanupSync.Progress = [Math]::Min(100, [int]($index * 100 / $total))
                }

                if ($backupState.Count -le 0 -and (Test-Path -LiteralPath $bkFile -PathType Leaf -ErrorAction SilentlyContinue)) {
                    Remove-Item -LiteralPath $bkFile -Force -ErrorAction SilentlyContinue
                }

                if ($skipLogState.Created -and (Test-Path -LiteralPath $skipLogFile -PathType Leaf -ErrorAction SilentlyContinue)) {
                    Add-Content -Path $skipLogFile -Value "Finished: $(Get-Date -Format o)`r`nFixed: $fixed`r`nSkipped: $skipped" -Encoding UTF8
                    if ($backupState.Count -le 0) {
                        Add-Content -Path $skipLogFile -Value "Backup: not created because no selected registry entries were successfully changed." -Encoding UTF8
                    }
                    else {
                        Add-Content -Path $skipLogFile -Value "Backup: $bkFile" -Encoding UTF8
                    }
                }

                $CleanupSync.Progress = 100
                $CleanupSync.Status = "Registry cleanup complete."
                $CleanupSync.Result = [pscustomobject]@{
                    Fixed          = $fixed
                    Skipped        = $skipped
                    BackupFile     = if ($backupState.Count -gt 0 -and (Test-Path -LiteralPath $bkFile -PathType Leaf -ErrorAction SilentlyContinue)) { $bkFile } else { $null }
                    SkippedLogFile = if ($skipLogState.Created -and (Test-Path -LiteralPath $skipLogFile -PathType Leaf -ErrorAction SilentlyContinue)) { $skipLogFile } else { $null }
                    BackupCount    = $backupState.Count
                }
                Add-WmtCleanupWorkerLog "Registry cleanup finished. Fixed: $fixed. Skipped: $skipped."
            }
            catch {
                $CleanupSync.Error = $_.Exception.Message
                try { [void]$CleanupSync.Logs.Add("Registry cleanup background worker failed: $($_.Exception.Message)") } catch {}
            }
            finally {
                $CleanupSync.IsCompleted = $true
            }
        }

        $ps = [PowerShell]::Create()
        $ps.Runspace = $runspace
        [void]$ps.AddScript($workerScript)
        $async = $ps.BeginInvoke()
        $script:WmtRegistryCleanupActive = $true
        $script:WmtRegistryCleanupRunspace = $runspace
        $script:WmtRegistryCleanupPowerShell = $ps
        $script:WmtRegistryCleanupAsync = $async
        $script:WmtRegistryCleanupSync = $cleanupSync
        Write-GuiLog "Registry cleanup started in the background. WMT remains usable."
    }
    catch {
        $script:WmtRegistryCleanupActive = $false
        try { if ($ps) { $ps.Dispose() } } catch {}
        try { if ($runspace) { $runspace.Dispose() } } catch {}
        Write-GuiLog "Registry cleanup failed to start: $($_.Exception.Message)"
        Show-WmtMessageBox -Message "Registry cleanup failed to start:`n$($_.Exception.Message)" -Title "Registry Cleaner" -Image Error | Out-Null
        return
    }

    $lastLogIndex = 0
    $cleanupTimer = [System.Windows.Threading.DispatcherTimer]::new()
    $cleanupTimer.Interval = [TimeSpan]::FromMilliseconds(250)
    $cleanupTimer.Add_Tick({
            try {
                while ($lastLogIndex -lt $cleanupSync.Logs.Count) {
                    Write-GuiLog ([string]$cleanupSync.Logs[$lastLogIndex])
                    $lastLogIndex++
                }

                try {
                    if ($lblStatus) {
                        $cleanupStatusText = [string]$cleanupSync.Status
                        $cleanupStatusText = ($cleanupStatusText -replace '[\r\n\t]+', '  ').Trim()
                        if ($cleanupStatusText.Length -gt 220) { $cleanupStatusText = $cleanupStatusText.Substring(0, 217) + '...' }
                        $lblStatus.Text = $cleanupStatusText
                    }
                    if ($barProgress) { $barProgress.Value = [double]$cleanupSync.Progress }
                }
                catch {}

                if (-not $cleanupSync.IsCompleted -and $async -and -not $async.IsCompleted) { return }

                $cleanupTimer.Stop()
                while ($lastLogIndex -lt $cleanupSync.Logs.Count) {
                    Write-GuiLog ([string]$cleanupSync.Logs[$lastLogIndex])
                    $lastLogIndex++
                }

                try {
                    if ($ps -and $async) { [void]$ps.EndInvoke($async) }
                }
                catch {
                    if (-not $cleanupSync.Error) { $cleanupSync.Error = $_.Exception.Message }
                }
                finally {
                    try { if ($ps) { $ps.Dispose() } } catch {}
                    try { if ($runspace) { $runspace.Dispose() } } catch {}
                    $script:WmtRegistryCleanupActive = $false
                    if ([object]::ReferenceEquals($script:WmtRegistryCleanupRunspace, $runspace)) { $script:WmtRegistryCleanupRunspace = $null }
                    if ([object]::ReferenceEquals($script:WmtRegistryCleanupPowerShell, $ps)) { $script:WmtRegistryCleanupPowerShell = $null }
                    if ([object]::ReferenceEquals($script:WmtRegistryCleanupTimer, $cleanupTimer)) { $script:WmtRegistryCleanupTimer = $null }
                    if ([object]::ReferenceEquals($script:WmtRegistryCleanupSync, $cleanupSync)) { $script:WmtRegistryCleanupSync = $null }
                    $script:WmtRegistryCleanupAsync = $null
                }

                try { if ($progressWindow) { $progressWindow.Close() } } catch {}

                if ($cleanupSync.Error) {
                    Write-GuiLog "Registry cleanup background worker error: $($cleanupSync.Error)"
                    Show-WmtMessageBox -Message "Registry cleanup failed:`n$($cleanupSync.Error)" -Title "Registry Cleaner" -Image Error | Out-Null
                    return
                }

                $result = $cleanupSync.Result
                if ($null -eq $result) {
                    Show-WmtMessageBox -Message "Registry cleanup finished, but no result summary was returned." -Title "Registry Cleaner" -Image Information | Out-Null
                    return
                }

                $finalMsg = "Cleanup Complete.`n`nFixed: $($result.Fixed) item(s)"
                if ([int]$result.Skipped -gt 0 -and -not [string]::IsNullOrWhiteSpace([string]$result.SkippedLogFile)) {
                    $finalMsg += "`nSkipped: $($result.Skipped) (details: $($result.SkippedLogFile))"
                }
                elseif ([int]$result.Skipped -gt 0) {
                    $finalMsg += "`nSkipped: $($result.Skipped)"
                }
                if (-not [string]::IsNullOrWhiteSpace([string]$result.BackupFile)) {
                    $finalMsg += "`n`nBackup: $($result.BackupFile)"
                }
                else {
                    $finalMsg += "`n`nBackup: not created because nothing was successfully changed."
                }
                if (-not [string]::IsNullOrWhiteSpace([string]$result.SkippedLogFile)) {
                    $finalMsg += "`nSkipped log: $($result.SkippedLogFile)"
                }
                Show-WmtMessageBox -Message $finalMsg -Title "Result" -Image Information | Out-Null
            }
            catch {
                try { $cleanupTimer.Stop() } catch {}
                try { if ($ps) { $ps.Dispose() } } catch {}
                try { if ($runspace) { $runspace.Dispose() } } catch {}
                $script:WmtRegistryCleanupActive = $false
                if ([object]::ReferenceEquals($script:WmtRegistryCleanupRunspace, $runspace)) { $script:WmtRegistryCleanupRunspace = $null }
                if ([object]::ReferenceEquals($script:WmtRegistryCleanupPowerShell, $ps)) { $script:WmtRegistryCleanupPowerShell = $null }
                if ([object]::ReferenceEquals($script:WmtRegistryCleanupTimer, $cleanupTimer)) { $script:WmtRegistryCleanupTimer = $null }
                if ([object]::ReferenceEquals($script:WmtRegistryCleanupSync, $cleanupSync)) { $script:WmtRegistryCleanupSync = $null }
                $script:WmtRegistryCleanupAsync = $null
                Write-GuiLog "Registry cleanup completion handler failed: $($_.Exception.Message)"
            }
        }.GetNewClosure())
    $script:WmtRegistryCleanupTimer = $cleanupTimer
    $cleanupTimer.Start()
}

function Show-SafetyDialog {
    param($Count)

    [xml]$safetyXaml = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="Safety Pre-Check" Width="480" Height="330" ResizeMode="NoResize" WindowStartupLocation="CenterOwner"
        Background="{DynamicResource BgDark}" Foreground="{DynamicResource TextPrimary}"
        FontFamily="Segoe UI Variable Display, Segoe UI, Arial" FontSize="13">
    <Grid Margin="20">
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="*"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>

        <TextBlock Text="Registry cleanup safety check" FontSize="18" FontWeight="SemiBold" Foreground="{DynamicResource TextPrimary}"/>
        <TextBlock Name="lblMessage" Grid.Row="1" Margin="0,12,0,14" Foreground="{DynamicResource TextSecondary}" LineHeight="19"/>

        <StackPanel Grid.Row="2">
            <Button Name="btnRestore" Content="Create Restore Point &amp; Clean" Height="40" Background="{DynamicResource Success}" Foreground="{DynamicResource SuccessText}" Margin="0,0,0,8"/>
            <Button Name="btnBackup" Content="Clean With .reg Backup Only" Height="38" Background="{DynamicResource Danger}" Foreground="{DynamicResource DangerText}" Margin="0,0,0,8"/>
            <Button Name="btnCancel" Content="Cancel" Height="36" IsCancel="True"/>
        </StackPanel>
    </Grid>
</Window>
'@

    $dialog = New-WmtWindowFromFullXaml -Xaml $safetyXaml

    $dialog.FindName("lblMessage").Text = "You are about to apply $Count selected registry cleanup action(s).`n`nWMT creates a .reg backup first. Value cleanup is usually low risk; key deletion and review-selected items carry more risk."
    $dialog.Tag = "Cancel"
    $dialog.FindName("btnRestore").Add_Click({
            $dialog.Tag = "Yes"
            $dialog.DialogResult = $true
        }.GetNewClosure())
    $dialog.FindName("btnBackup").Add_Click({
            $dialog.Tag = "No"
            $dialog.DialogResult = $true
        }.GetNewClosure())
    $dialog.FindName("btnCancel").Add_Click({
            $dialog.Tag = "Cancel"
            $dialog.DialogResult = $false
        }.GetNewClosure())

    $dialog.ShowDialog() | Out-Null
    return [string]$dialog.Tag
}

# =========================================================
# 2. INVOKE-REGISTRYTASK (Full Function)
# =========================================================

function Invoke-RegistryTask {
    param([string]$Action)

    $bkDir = Join-Path (Get-DataPath) "RegistryBackups"
    if (-not (Test-Path $bkDir)) { New-Item -Path $bkDir -ItemType Directory | Out-Null }

    # --- PRIVILEGE BOOSTER ---
    # Only adding the type if it doesn't exist to prevent errors on re-run
    if (-not ([System.Management.Automation.PSTypeName]'Win32.TokenManipulator').Type) {
        Add-Type -TypeDefinition @"
        using System;
        using System.Runtime.InteropServices;
        namespace Win32 {
            public class TokenManipulator {
                [DllImport("advapi32.dll", ExactSpelling = true, SetLastError = true)]
                internal static extern bool AdjustTokenPrivileges(IntPtr htok, bool disall, ref TokPriv1Luid newst, int len, IntPtr prev, IntPtr relen);
                [DllImport("kernel32.dll", ExactSpelling = true)]
                internal static extern IntPtr GetCurrentProcess();
                [DllImport("advapi32.dll", ExactSpelling = true, SetLastError = true)]
                internal static extern bool OpenProcessToken(IntPtr h, int acc, ref IntPtr phtok);
                [DllImport("advapi32.dll", SetLastError = true)]
                internal static extern bool LookupPrivilegeValue(string host, string name, ref long pluid);
                [StructLayout(LayoutKind.Sequential, Pack = 1)]
                internal struct TokPriv1Luid { public int Count; public long Luid; public int Attr; }
                internal const int SE_PRIVILEGE_ENABLED = 0x00000002;
                internal const int TOKEN_ADJUST_PRIVILEGES = 0x00000020;
                internal const int TOKEN_QUERY = 0x00000008;
                public static bool EnablePrivilege(string privilege) {
                    try {
                        IntPtr htok = IntPtr.Zero;
                        if (!OpenProcessToken(GetCurrentProcess(), TOKEN_ADJUST_PRIVILEGES | TOKEN_QUERY, ref htok)) return false;
                        TokPriv1Luid tp; tp.Count = 1; tp.Attr = SE_PRIVILEGE_ENABLED; tp.Luid = 0;
                        if (!LookupPrivilegeValue(null, privilege, ref tp.Luid)) return false;
                        if (!AdjustTokenPrivileges(htok, false, ref tp, 0, IntPtr.Zero, IntPtr.Zero)) return false;
                        return true;
                    } catch { return false; }
                }
            }
        }
"@
    }
    try {
        [WmtNativeStartup.TokenManipulator]::EnablePrivilege("SeTakeOwnershipPrivilege") | Out-Null
        [WmtNativeStartup.TokenManipulator]::EnablePrivilege("SeRestorePrivilege") | Out-Null
    }
    catch {}

    if ($Action -eq "BackupHKLM") {
        Invoke-UiCommand {
            param($BackupDirectory)

            if (-not (Test-Path -LiteralPath $BackupDirectory)) {
                New-Item -Path $BackupDirectory -ItemType Directory -Force | Out-Null
            }

            $bkFile = Join-Path $BackupDirectory ("HKLM_Backup_{0}.reg" -f (Get-Date -Format "yyyyMMdd_HHmmss"))
            Write-Output "Exporting HKLM to: $bkFile"
            & reg.exe export "HKLM" $bkFile /y 2>&1 | ForEach-Object { Write-Output $_ }

            if ($LASTEXITCODE -ne 0 -or -not (Test-Path -LiteralPath $bkFile)) {
                throw "HKLM backup failed. reg.exe exit code: $LASTEXITCODE"
            }

            Show-WmtMessageBox -Message "HKLM export saved to:`n$bkFile" -Title "Registry Export" -Image Information | Out-Null
        } "Exporting HKLM hive..." -ArgumentList $bkDir
        return
    }

    if ($Action -eq "Restore") {
        $dlg = [Microsoft.Win32.OpenFileDialog]::new()
        $dlg.Title = "Select Registry Backup to Import"
        $dlg.Filter = "Registry backup (*.reg)|*.reg|All files (*.*)|*.*"
        if (Test-Path -LiteralPath $bkDir) {
            try { $dlg.InitialDirectory = (Resolve-Path -LiteralPath $bkDir).Path } catch {}
        }

        if ($dlg.ShowDialog() -ne $true) { return }
        $restoreFile = $dlg.FileName

        $confirm = Show-WmtMessageBox -Message "Import this registry backup?`n`n$restoreFile`n`nThis can overwrite current registry values." -Title "Import Registry Backup" -Button YesNo -Image Warning
        if ($confirm -ne [System.Windows.MessageBoxResult]::Yes) { return }

        Invoke-UiCommand {
            param($BackupFile)

            if (-not (Test-Path -LiteralPath $BackupFile)) {
                throw "Backup file not found: $BackupFile"
            }

            Write-Output "Importing registry backup: $BackupFile"
            & reg.exe import $BackupFile 2>&1 | ForEach-Object { Write-Output $_ }
            if ($LASTEXITCODE -ne 0) {
                throw "Registry restore failed. reg.exe exit code: $LASTEXITCODE"
            }

            Show-WmtMessageBox -Message "Registry backup imported from:`n$BackupFile" -Title "Registry Import" -Image Information | Out-Null
        } "Importing registry backup..." -ArgumentList $restoreFile
        return
    }

    # --- MAIN SCAN LOGIC ---
    if ($Action -eq "DeepClean") {
        $selectedScans = Show-RegScanSelection
        if (-not $selectedScans) { return }
        if (@($selectedScans).Count -eq 0) {
            Show-WmtMessageBox -Message "No registry scan targets selected." -Title "Registry Cleaner" -Image Information | Out-Null
            return
        }

        # Progress UI
        [xml]$registryProgressXaml = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="Scanning Registry" Width="640" Height="218" MinWidth="600" MinHeight="200" ResizeMode="NoResize" WindowStartupLocation="CenterOwner"
        Background="{DynamicResource BgDark}" Foreground="{DynamicResource TextPrimary}"
        FontFamily="Segoe UI Variable Display, Segoe UI, Arial" FontSize="13">
    <Grid Margin="20">
        <Grid.RowDefinitions>
            <RowDefinition Height="56"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="*"/>
        </Grid.RowDefinitions>

        <TextBlock Name="pLabel" Grid.Row="0" Text="Initializing Background Scan..." Foreground="{DynamicResource TextPrimary}"
                   TextTrimming="CharacterEllipsis" TextWrapping="NoWrap" Height="46" MaxHeight="46"
                   VerticalAlignment="Center" ToolTip="{Binding Text, RelativeSource={RelativeSource Self}}"/>
        <ProgressBar Name="pBar" Grid.Row="1" Minimum="0" Maximum="100" Height="12" Margin="0,6,0,0"/>
        <Grid Grid.Row="2" Margin="0,16,0,0">
            <Button Name="btnCancelScan" Content="Cancel" Width="100" Height="34" HorizontalAlignment="Right" VerticalAlignment="Bottom"/>
        </Grid>
    </Grid>
</Window>
'@
        $pForm = New-WmtWindowFromFullXaml -Xaml $registryProgressXaml
        $pLabel = $pForm.FindName("pLabel")
        $pBar = $pForm.FindName("pBar")
        $btnCancelScan = $pForm.FindName("btnCancelScan")

        # Shared Data for Thread
        $syncHash = [hashtable]::Synchronized(@{
                Findings        = [System.Collections.ArrayList]::new()
                Status          = "Starting..."
                Progress        = 0
                IsCompleted     = $false
                CancelRequested = $false
                Error           = $null
            })

        $btnCancelScan.Add_Click({
                $syncHash.CancelRequested = $true
                $syncHash.Status = "Canceling scan..."
                $syncHash.Error = "Registry scan canceled."
                $syncHash.IsCompleted = $true
                try { if ($ps) { $ps.Stop() } } catch {}
            }.GetNewClosure())
        $pForm.Show()

        # --- RUNSPACE CONFIGURATION ---
        $iss = [System.Management.Automation.Runspaces.InitialSessionState]::CreateDefault()
        $iss.Commands.Add([System.Management.Automation.Runspaces.SessionStateFunctionEntry]::new("Test-PathExists", ${function:Test-PathExists}.ToString()))
        $rs = [System.Management.Automation.Runspaces.RunspaceFactory]::CreateRunspace($iss)
        # STA Mode is critical for Registry (HKCR) scans to work correctly
        $rs.ApartmentState = "STA"
        $rs.ThreadOptions = "ReuseThread"
        $rs.Open()
        
        $rs.SessionStateProxy.SetVariable("SyncHash", $syncHash)
        $rs.SessionStateProxy.SetVariable("SelectedScans", $selectedScans)

        $ps = [PowerShell]::Create()
        $ps.Runspace = $rs
        
        # --- SCANNING SCRIPT BLOCK ---
        [void]$ps.AddScript({
                Import-Module Microsoft.PowerShell.Management
                Import-Module Microsoft.PowerShell.Security
                $SelectedScans = @($SelectedScans)
                # Registry skip tokens are intentionally split into two groups.
                # Do not let a broad token hide an absolute filesystem path such as:
                #   C:\Program Files\...\WebView2\...\some.dll
                #   C:\BadPath\rundll32.exe
                # Absolute paths must always flow through Test-PathExists / protected-path checks.
                $RegistrySafeNonPathTokens = [string[]]@(
                    "TetheringSettingHandler", "CrossDevice", "Windows.Media.Protection",
                    "System.Data.dll", "System.EnterpriseServices", "AppX", "WindowsApps",
                    "UIEOrchestrator", "Diagnostic.Perfmon", "QuickActionsPS", "VailAudioProxy"
                )
                $RegistrySafeCommandTokens = [string[]]@(
                    "rundll32", "rundll32.exe", "explorer", "explorer.exe", "notepad", "notepad.exe",
                    "write", "write.exe", "mspaint", "mspaint.exe", "svchost", "svchost.exe",
                    "dllhost", "dllhost.exe", "wmiprvse", "wmiprvse.exe", "mmgaserver", "mmgaserver.exe",
                    "pickerhost", "pickerhost.exe", "castsrv", "castsrv.exe", "uihelper", "uihelper.exe",
                    "backgroundtaskhost", "backgroundtaskhost.exe", "smartscreen", "smartscreen.exe",
                    "runtimebroker", "runtimebroker.exe", "mousocoreworker", "mousocoreworker.exe",
                    "spatialaudiolicensesrv", "spatialaudiolicensesrv.exe", "speechruntime", "speechruntime.exe",
                    "mstsc", "mstsc.exe", "searchprotocolhost", "searchprotocolhost.exe", "control", "control.exe",
                    "sdclt", "sdclt.exe", "provtool", "provtool.exe", "perfmon", "perfmon.exe"
                )
                $RegistrySystemRoot = [Environment]::GetEnvironmentVariable("SystemRoot")
                if ([string]::IsNullOrWhiteSpace($RegistrySystemRoot)) { $RegistrySystemRoot = "$env:SystemDrive\Windows" }
                $RegistryProtectedWindowsFolders = @(
                    foreach ($folder in [string[]]@("System32", "SysWOW64", "Sysnative", "WinSxS", "servicing", "SystemApps", "Microsoft.NET", "Fonts")) {
                        Join-Path $RegistrySystemRoot $folder
                    }
                )
                $RegistryPathExistsCache = [System.Collections.Generic.Dictionary[string, bool]]::new([System.StringComparer]::OrdinalIgnoreCase)

                # Internal Helper: skip known virtual/non-path registrations only.
                # Broad substring allow-listing against absolute paths caused stale COM DLLs to be hidden.
                function Test-IsWhitelisted {
                    param($Path)
                    if ([string]::IsNullOrWhiteSpace($Path)) { return $false }

                    $pathText = [Environment]::ExpandEnvironmentVariables(([string]$Path).Trim().Trim('"'))
                    if ([string]::IsNullOrWhiteSpace($pathText)) { return $false }

                    # If this value contains a real filesystem-style path, never whitelist it here.
                    # Let Test-IsProtectedWindowsPath and Test-PathExists decide whether it is safe/valid.
                    if ($pathText -match '(?i)([a-z]:\\|\\\\[^\\]+\\[^\\]+\\|%ProgramFiles%|%ProgramFiles\(x86\)%|%LocalAppData%|%AppData%|%ProgramData%|%SystemDrive%|%SystemRoot%|%windir%|\\SystemRoot\\)') {
                        return $false
                    }

                    $firstToken = ($pathText -split '\s+', 2)[0].Trim('"')
                    $firstTokenName = [System.IO.Path]::GetFileName($firstToken)
                    foreach ($safeCommand in $RegistrySafeCommandTokens) {
                        if ($firstTokenName.Equals($safeCommand, [System.StringComparison]::OrdinalIgnoreCase)) { return $true }
                    }

                    foreach ($safe in $RegistrySafeNonPathTokens) {
                        if ($pathText.IndexOf($safe, [System.StringComparison]::OrdinalIgnoreCase) -ge 0) { return $true }
                    }

                    return $false
                }

                function Test-IsProtectedWindowsPath {
                    param($Path)
                    if ([string]::IsNullOrWhiteSpace($Path)) { return $false }

                    $text = [Environment]::ExpandEnvironmentVariables(([string]$Path).Trim().Trim('"'))
                    $text = $text -replace '^(?i)\\\?\?\\', ''
                    $text = $text -replace '^(?i)\\\\\?\\', ''

                    if ($text -match '^(?i)(%SystemRoot%|%windir%|\\SystemRoot\\|System32\\)') { return $true }
                    foreach ($protectedRoot in $RegistryProtectedWindowsFolders) {
                        if ($text.Equals($protectedRoot, [System.StringComparison]::OrdinalIgnoreCase) -or $text.StartsWith("$protectedRoot\", [System.StringComparison]::OrdinalIgnoreCase)) {
                            return $true
                        }
                    }

                    return $false
                }

                function Test-PathExists {
                    param(
                        $Path,
                        $RegistryView = $null
                    )
                    if ([string]::IsNullOrWhiteSpace($Path)) { return $false }

                    $rawPathText = ([string]$Path).Trim()
                    $expanded = [Environment]::ExpandEnvironmentVariables($rawPathText)
                    $expanded = $expanded -replace '^(?i)\\\?\?\\', ''
                    $expanded = $expanded -replace '^(?i)\\\\\?\\', ''

                    $systemRoot = $RegistrySystemRoot
                    if ($expanded -match '^(?i)\\SystemRoot\\(?<SubPath>.+)$') {
                        $expanded = Join-Path $systemRoot $Matches.SubPath
                    }
                    elseif ($expanded -match '^(?i)System32\\(?<SubPath>.+)$') {
                        $expanded = Join-Path (Join-Path $systemRoot "System32") $Matches.SubPath
                    }

                    if ($expanded -match "%.*%" -or $expanded -match "\$\(.*\)") { return $false }

                    $cacheKey = "$([string]$RegistryView)`0$expanded"
                    if ($RegistryPathExistsCache.ContainsKey($cacheKey)) { return $RegistryPathExistsCache[$cacheKey] }

                    $probeCandidates = [System.Collections.Generic.List[string]]::new()
                    $seenCandidates = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
                    $addProbeCandidate = {
                        param([string]$Candidate)
                        if ([string]::IsNullOrWhiteSpace($Candidate)) { return }
                        $candidateText = ([string]$Candidate).Trim()
                        if ($candidateText -match "%.*%" -or $candidateText -match "\$\(.*\)") { return }
                        if ($seenCandidates.Add($candidateText)) { [void]$probeCandidates.Add($candidateText) }
                    }
                    $useDefaultExpandedCandidate = $true
                    if ([Environment]::Is64BitOperatingSystem -and [string]$RegistryView -eq "Registry32") {
                        $commonProgramFilesX86 = [Environment]::GetEnvironmentVariable("CommonProgramFiles(x86)")
                        if (-not [string]::IsNullOrWhiteSpace($commonProgramFilesX86) -and $rawPathText -match '(?i)%CommonProgramFiles%\\(?<Rest>.+)$') {
                            & $addProbeCandidate (Join-Path $commonProgramFilesX86 $Matches.Rest)
                            $useDefaultExpandedCandidate = $false
                        }
                        $programFilesX86 = [Environment]::GetEnvironmentVariable("ProgramFiles(x86)")
                        if (-not [string]::IsNullOrWhiteSpace($programFilesX86) -and $rawPathText -match '(?i)%ProgramFiles%\\(?<Rest>.+)$') {
                            & $addProbeCandidate (Join-Path $programFilesX86 $Matches.Rest)
                            $useDefaultExpandedCandidate = $false
                        }

                        # 32-bit COM values often store REG_EXPAND_SZ like %CommonProgramFiles%.
                        # If another helper expanded it first inside 64-bit PowerShell, it becomes
                        # C:\Program Files\Common Files, even though the 32-bit COM server normally
                        # resolves to C:\Program Files (x86)\Common Files. Probe both forms to avoid
                        # false ActiveX findings for legacy DAO/OLE DB registrations.
                        $commonProgramFiles64 = [Environment]::GetEnvironmentVariable("CommonProgramFiles")
                        if (-not [string]::IsNullOrWhiteSpace($commonProgramFiles64) -and -not [string]::IsNullOrWhiteSpace($commonProgramFilesX86)) {
                            $common64Pattern = "^(?i)$([regex]::Escape($commonProgramFiles64))\\(?<Rest>.+)$"
                            if ($rawPathText -match $common64Pattern -or $expanded -match $common64Pattern) {
                                & $addProbeCandidate (Join-Path $commonProgramFilesX86 $Matches.Rest)
                            }
                        }

                        $programFiles64 = [Environment]::GetEnvironmentVariable("ProgramFiles")
                        if (-not [string]::IsNullOrWhiteSpace($programFiles64) -and -not [string]::IsNullOrWhiteSpace($programFilesX86)) {
                            $pf64Pattern = "^(?i)$([regex]::Escape($programFiles64))\\(?<Rest>.+)$"
                            if ($rawPathText -match $pf64Pattern -or $expanded -match $pf64Pattern) {
                                & $addProbeCandidate (Join-Path $programFilesX86 $Matches.Rest)
                            }
                        }
                    }
                    if ($useDefaultExpandedCandidate) { & $addProbeCandidate $expanded }

                    if ([Environment]::Is64BitOperatingSystem) {
                        $system32Pattern = "^(?i)$([regex]::Escape($systemRoot))\\System32\\(?<SubPath>.+)$"
                        if ($expanded -match $system32Pattern) {
                            if ([string]$RegistryView -eq "Registry32") {
                                $wow64Candidate = (Join-Path (Join-Path $systemRoot "SysWOW64") $Matches.SubPath).Trim()
                                if ($seenCandidates.Add($wow64Candidate)) { [void]$probeCandidates.Add($wow64Candidate) }
                            }
                            $sysnativeCandidate = (Join-Path (Join-Path $systemRoot "Sysnative") $Matches.SubPath).Trim()
                            if ($seenCandidates.Add($sysnativeCandidate)) { [void]$probeCandidates.Add($sysnativeCandidate) }
                        }
                    }

                    foreach ($candidate in $probeCandidates) {
                        try {
                            if (Test-Path -LiteralPath $candidate -ErrorAction Stop) {
                                $RegistryPathExistsCache[$cacheKey] = $true
                                return $true
                            }
                        }
                        catch [System.UnauthorizedAccessException] { $RegistryPathExistsCache[$cacheKey] = $true; return $true }
                        catch [System.Security.SecurityException] { $RegistryPathExistsCache[$cacheKey] = $true; return $true }
                        catch {}
                        try {
                            [void](Get-Item -LiteralPath $candidate -Force -ErrorAction Stop)
                            $RegistryPathExistsCache[$cacheKey] = $true
                            return $true
                        }
                        catch {
                            if ($_.Exception.Message -match '(?i)access.*denied|unauthorized') {
                                $RegistryPathExistsCache[$cacheKey] = $true
                                return $true
                            }
                        }
                        if ($candidate -match '^(?i)[a-z]:\\Program Files\\WindowsApps\\(?<PackageName>[^\\]+)') {
                            $packageParts = ([string]$Matches.PackageName).Split([char[]]@('_'), [System.StringSplitOptions]::RemoveEmptyEntries)
                            if ($packageParts.Length -ge 2) {
                                $packageFamily = "$($packageParts[0])_$($packageParts[$packageParts.Length - 1])"
                                try {
                                    $packageFamilyKey = "SOFTWARE\Microsoft\Windows\CurrentVersion\AppModel\StateRepository\Cache\PackageFamily\Index\PackageFamilyName\$packageFamily"
                                    $root = [Microsoft.Win32.Registry]::LocalMachine.OpenSubKey($packageFamilyKey)
                                    if ($root) {
                                        $root.Close()
                                        $RegistryPathExistsCache[$cacheKey] = $true
                                        return $true
                                    }
                                }
                                catch {}
                            }
                        }
                    }

                    $RegistryPathExistsCache[$cacheKey] = $false
                    return $false
                }

                # Internal Helper: Clean Path Strings
                function Get-RealExePath {
                    param($RawString)
                    if ([string]::IsNullOrWhiteSpace($RawString)) { return $null }
                    $clean = $RawString.Trim()
                    if ($clean -match "^(.*?),\s*-?\d+$") { $clean = $matches[1].Trim() }
                    if ($clean.StartsWith('"')) {
                        $endQuote = $clean.IndexOf('"', 1)
                        if ($endQuote -gt 1) {
                            $quotedPart = $clean.Substring(1, $endQuote - 1)
                            if ($quotedPart -match "^(.*?),\s*-?\d+$") { $quotedPart = $matches[1].Trim() }
                            if (Test-PathExists $quotedPart) { return $quotedPart }
                            $clean = $quotedPart 
                        }
                    }
                    if (Test-PathExists $clean) { return $clean }
                    if ($clean.Contains(" ")) {
                        $parts = $clean -split " "
                        $candidate = $parts[0]
                        if ((Test-PathExists $candidate) -or (Test-PathExists "$candidate.exe")) { return $candidate }
                        for ($i = 1; $i -lt $parts.Count; $i++) {
                            $candidate += " " + $parts[$i]
                            if ((Test-PathExists $candidate) -or (Test-PathExists "$candidate.exe")) { return $candidate }
                        }
                    }
                    return $clean
                }

                function Test-IsRegistryFlagEnabled {
                    param($Value)
                    if ($null -eq $Value) { return $false }
                    try { return ([int]$Value -eq 1) }
                    catch { return ([string]$Value -eq "1") }
                }

                function Test-IsWindowsInstallerCommand {
                    param($RawString)
                    if ([string]::IsNullOrWhiteSpace($RawString)) { return $false }
                    $expanded = [Environment]::ExpandEnvironmentVariables($RawString.Trim())
                    return ($expanded -match '(?i)(^|[\\/"\s])msiexec(\.exe)?(?=$|[\s/"])')
                }

                function Get-UninstallExecutablePath {
                    param($RawString)
                    if ([string]::IsNullOrWhiteSpace($RawString)) { return $null }
                    $cmd = [Environment]::ExpandEnvironmentVariables($RawString.Trim())
                    if ([string]::IsNullOrWhiteSpace($cmd) -or (Test-IsWindowsInstallerCommand $cmd)) { return $null }

                    $candidate = $null
                    if ($cmd -match '^\s*"([^"]+)"') {
                        $candidate = $matches[1].Trim()
                    }
                    elseif ($cmd -match '^\s*(?<Path>[a-zA-Z]:\\.+?\.(?:exe|msi|cmd|bat|com))(?=$|\s)') {
                        $candidate = $matches.Path.Trim()
                    }
                    elseif ($cmd -match '^\s*(?<Path>[a-zA-Z]:\\[^\s]+)') {
                        $candidate = $matches.Path.Trim()
                    }

                    if ([string]::IsNullOrWhiteSpace($candidate)) { return $null }
                    $candidate = [Environment]::ExpandEnvironmentVariables($candidate)
                    if ($candidate -notmatch '^[a-zA-Z]:\\') { return $null }
                    if ($candidate -match '%.*%' -or $candidate -match '\$\(.*\)') { return $null }
                    return $candidate
                }

                function Get-WmtMalformedComServerCommandIssue {
                    param(
                        $RawString,
                        $RegistryView = $null
                    )
                    if ([string]::IsNullOrWhiteSpace($RawString)) { return $null }

                    $rawText = ([string]$RawString).Trim()
                    if ([string]::IsNullOrWhiteSpace($rawText)) { return $null }

                    $expanded = [Environment]::ExpandEnvironmentVariables($rawText)
                    $expanded = $expanded -replace '^(?i)\\\?\?\\', ''
                    $expanded = $expanded -replace '^(?i)\\\\\?\\', ''

                    $systemRoot = [Environment]::GetEnvironmentVariable("SystemRoot")
                    if ([string]::IsNullOrWhiteSpace($systemRoot)) { $systemRoot = "$env:SystemDrive\Windows" }
                    if ($expanded -match '^(?i)\\SystemRoot\\(?<SubPath>.+)$') {
                        $expanded = Join-Path $systemRoot $Matches.SubPath
                    }
                    elseif ($expanded -match '^(?i)System32\\(?<SubPath>.+)$') {
                        $expanded = Join-Path (Join-Path $systemRoot "System32") $Matches.SubPath
                    }

                    $exePath = $null
                    $argumentText = $null

                    # Some LocalServer32 registrations are malformed as:
                    #   C:\Program Files\App\App.exe/Automation
                    # The executable exists, but the argument is glued directly to the .exe path.
                    # Older WMT path parsing fell through to the first-space fallback and displayed C:\Program.
                    if ($expanded -match '^\s*"(?<Path>[^"]+?\.(?:exe|com|bat|cmd))(?<Args>/[^"]+)"\s*$') {
                        $exePath = $Matches.Path.Trim()
                        $argumentText = $Matches.Args.Trim()
                    }
                    elseif ($expanded -match '^\s*(?<Path>[a-zA-Z]:\\.+?\.(?:exe|com|bat|cmd))(?<Args>/\S.*)$') {
                        $exePath = $Matches.Path.Trim()
                        $argumentText = $Matches.Args.Trim()
                    }

                    if ([string]::IsNullOrWhiteSpace($exePath) -or [string]::IsNullOrWhiteSpace($argumentText)) { return $null }

                    # Keep both the displayed bad command and the rewritten COM command single-line.
                    # Registry Editor/UI wrapping can make this look like a newline, but the value we write must be:
                    #   "C:\Path With Spaces\App.exe" /Automation
                    # not:
                    #   "C:\Path With Spaces\App.exe"
                    #   /Automation
                    $rawCommandSingleLine = (($expanded -replace '[\r\n]+', ' ') -replace '\s{2,}', ' ').Trim()
                    $exePath = (($exePath -replace '[\r\n]+', ' ') -replace '\s{2,}', ' ').Trim()
                    $argumentText = (($argumentText -replace '[\r\n]+', ' ') -replace '\s{2,}', ' ').Trim()

                    if ([string]::IsNullOrWhiteSpace($exePath) -or [string]::IsNullOrWhiteSpace($argumentText)) { return $null }
                    if ($argumentText -notmatch '^/') { return $null }
                    if ($exePath -notmatch '^(?i)[a-z]:\\') { return $null }
                    if ($exePath -match '%.*%' -or $exePath -match '\$\(.*\)') { return $null }
                    if (-not (Test-PathExists -Path $exePath -RegistryView $RegistryView)) { return $null }

                    $fixedCommand = ('"{0}" {1}' -f $exePath, $argumentText).Trim()
                    $fixedCommand = (($fixedCommand -replace '[\r\n]+', ' ') -replace '\s{2,}', ' ').Trim()
                    return [PSCustomObject]@{
                        RawCommand   = $rawCommandSingleLine
                        ExePath      = $exePath
                        Arguments    = $argumentText
                        FixedCommand = $fixedCommand
                    }
                }

                function Get-ServiceImageExecutablePath {
                    param(
                        $RawString,
                        $RegistryView = $null
                    )
                    if ([string]::IsNullOrWhiteSpace($RawString)) { return $null }

                    $cmd = [Environment]::ExpandEnvironmentVariables(([string]$RawString).Trim())
                    $cmd = $cmd -replace '^(?i)\\\?\?\\', ''
                    $cmd = $cmd -replace '^(?i)\\\\\?\\', ''
                    $systemRoot = [Environment]::GetEnvironmentVariable("SystemRoot")
                    if ([string]::IsNullOrWhiteSpace($systemRoot)) { $systemRoot = "$env:SystemDrive\Windows" }
                    if ($cmd -match '^(?i)\\SystemRoot\\(?<SubPath>.+)$') {
                        $cmd = Join-Path $systemRoot $Matches.SubPath
                    }
                    elseif ($cmd -match '^(?i)System32\\(?<SubPath>.+)$') {
                        $cmd = Join-Path (Join-Path $systemRoot "System32") $Matches.SubPath
                    }
                    if ([string]::IsNullOrWhiteSpace($cmd)) { return $null }

                    $candidate = $null
                    if ($cmd -match '^\s*"([^"]+)"') {
                        $candidate = $matches[1].Trim()
                    }
                    elseif (Test-PathExists -Path $cmd -RegistryView $RegistryView) {
                        $candidate = $cmd
                    }
                    elseif ($cmd -match '^\s*(?<Path>[a-zA-Z]:\\.+?\.(?:exe|com|bat|cmd|sys|dll))(?=$|[\s/])') {
                        $candidate = $matches.Path.Trim()
                    }
                    elseif ($cmd -match '^\s*(?<Path>[a-zA-Z]:\\[^\s]+)') {
                        $candidate = $matches.Path.Trim()
                    }

                    if ([string]::IsNullOrWhiteSpace($candidate)) { return $null }
                    if ($candidate -match '%.*%' -or $candidate -match '\$\(.*\)') { return $null }
                    if ($candidate -notmatch '^[a-zA-Z]:\\') { return $null }
                    return $candidate
                }

                function New-PerUserRegistryTargets {
                    param(
                        [string]$SubPath,
                        [string]$HkcuLabel
                    )

                    $targets = New-Object System.Collections.Generic.List[object]
                    $currentSid = $null
                    try { $currentSid = [System.Security.Principal.WindowsIdentity]::GetCurrent().User.Value } catch {}

                    $usersRoot = [Microsoft.Win32.Registry]::Users
                    $currentRegPrefix = "HKEY_CURRENT_USER\$SubPath"
                    $currentLabel = $HkcuLabel
                    if (-not [string]::IsNullOrWhiteSpace($currentSid)) {
                        $currentHive = $null
                        try { $currentHive = $usersRoot.OpenSubKey($currentSid) } catch {}
                        if ($currentHive) {
                            $currentHive.Close()
                            $currentRegPrefix = "HKEY_USERS\$currentSid\$SubPath"
                            $currentLabel = "Current user ($currentSid)\$SubPath"
                        }
                    }

                    [void]$targets.Add([PSCustomObject]@{
                            BaseKey   = [Microsoft.Win32.Registry]::CurrentUser
                            SubPath   = $SubPath
                            RegPrefix = $currentRegPrefix
                            Label     = $currentLabel
                        })

                    $sidNames = @($usersRoot.GetSubKeyNames() | Where-Object { $_ -match '^S-1-5-21-.+-\d+$' -and $_ -notmatch '_Classes$' })
                    foreach ($sid in $sidNames) {
                        if (-not [string]::IsNullOrWhiteSpace($currentSid) -and $sid -eq $currentSid) { continue }
                        [void]$targets.Add([PSCustomObject]@{
                                BaseKey   = $usersRoot
                                SubPath   = "$sid\$SubPath"
                                RegPrefix = "HKEY_USERS\$sid\$SubPath"
                                Label     = "$sid\$SubPath"
                            })
                    }

                    return $targets
                }

                function ConvertTo-WmtComparableAppName {
                    param([string]$Name)
                    if ([string]::IsNullOrWhiteSpace($Name)) { return "" }
                    return (($Name.ToLowerInvariant()) -replace '[^a-z0-9]', '')
                }

                function Add-WmtInstalledAppNameToken {
                    param(
                        [System.Collections.Generic.HashSet[string]]$TokenSet,
                        [string]$Name
                    )
                    $token = ConvertTo-WmtComparableAppName $Name
                    if ($token.Length -ge 5) { [void]$TokenSet.Add($token) }
                }

                function Get-WmtInstalledAppNameTokens {
                    if ($script:WmtInstalledAppNameTokens) { return $script:WmtInstalledAppNameTokens }

                    $tokens = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
                    $uninstallRoots = @(
                        @{ Hive = [Microsoft.Win32.Registry]::LocalMachine; Path = "SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall" },
                        @{ Hive = [Microsoft.Win32.Registry]::LocalMachine; Path = "SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall" },
                        @{ Hive = [Microsoft.Win32.Registry]::CurrentUser; Path = "Software\Microsoft\Windows\CurrentVersion\Uninstall" }
                    )

                    foreach ($rootInfo in $uninstallRoots) {
                        try {
                            $root = $rootInfo.Hive.OpenSubKey($rootInfo.Path)
                            if ($root) {
                                foreach ($subName in $root.GetSubKeyNames()) {
                                    $sub = $null
                                    try {
                                        $sub = $root.OpenSubKey($subName)
                                        if ($sub) {
                                            Add-WmtInstalledAppNameToken -TokenSet $tokens -Name ([string]$sub.GetValue("DisplayName"))
                                            Add-WmtInstalledAppNameToken -TokenSet $tokens -Name ([string]$sub.GetValue("Publisher"))
                                        }
                                    }
                                    catch {}
                                    finally {
                                        if ($sub) { $sub.Close() }
                                    }
                                }
                                $root.Close()
                            }
                        }
                        catch {}
                    }

                    foreach ($packagePath in @(
                            "SOFTWARE\Microsoft\Windows\CurrentVersion\AppModel\StateRepository\Cache\PackageFamily\Index\PackageFamilyName",
                            "SOFTWARE\Microsoft\Windows\CurrentVersion\AppModel\StateRepository\Cache\Package\Index\PackageFullName"
                        )) {
                        try {
                            $root = [Microsoft.Win32.Registry]::LocalMachine.OpenSubKey($packagePath)
                            if ($root) {
                                foreach ($subName in $root.GetSubKeyNames()) {
                                    Add-WmtInstalledAppNameToken -TokenSet $tokens -Name $subName
                                }
                                $root.Close()
                            }
                        }
                        catch {}
                    }

                    $script:WmtInstalledAppNameTokens = $tokens
                    return $script:WmtInstalledAppNameTokens
                }

                function Test-IsInstalledAppName {
                    param([string]$Name)
                    $token = ConvertTo-WmtComparableAppName $Name
                    if ($token.Length -lt 5) { return $false }

                    foreach ($installedToken in (Get-WmtInstalledAppNameTokens)) {
                        if ($installedToken.Length -lt 5) { continue }
                        if ($installedToken.Contains($token) -or ($token.Length -ge 8 -and $token.Contains($installedToken))) {
                            return $true
                        }
                    }

                    return $false
                }

                function Test-IsUserSoftwareKeyExcluded {
                    param([string]$Name)
                    if ([string]::IsNullOrWhiteSpace($Name)) { return $true }

                    $excluded = @(
                        "Classes",
                        "Clients",
                        "Microsoft",
                        "ODBC",
                        "Policies",
                        "RegisteredApplications",
                        "WOW6432Node"
                    )

                    foreach ($item in $excluded) {
                        if ($Name.Equals($item, [System.StringComparison]::OrdinalIgnoreCase)) { return $true }
                    }

                    if (Test-IsInstalledAppName $Name) { return $true }

                    return $false
                }

                function ConvertTo-WmtClsid {
                    param([string]$Value)
                    if ([string]::IsNullOrWhiteSpace($Value)) { return $null }
                    if ($Value -match '\{[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}\}') {
                        return $Matches[0].ToUpperInvariant()
                    }
                    return $null
                }

                function Get-WmtRegistryViews {
                    $views = New-Object System.Collections.Generic.List[object]

                    if ([Environment]::Is64BitOperatingSystem) {
                        foreach ($view in @([Microsoft.Win32.RegistryView]::Registry64, [Microsoft.Win32.RegistryView]::Registry32)) {
                            $probe = $null
                            try {
                                $probe = [Microsoft.Win32.RegistryKey]::OpenBaseKey([Microsoft.Win32.RegistryHive]::LocalMachine, $view)
                                if ($probe) { [void]$views.Add($view) }
                            }
                            catch {}
                            finally {
                                if ($probe) { $probe.Close() }
                            }
                        }
                    }

                    if ($views.Count -eq 0) { [void]$views.Add([Microsoft.Win32.RegistryView]::Default) }
                    return $views.ToArray()
                }

                function Get-WmtRegistryViewLabel {
                    param($View)

                    switch ([string]$View) {
                        "Registry64" { return "64-bit" }
                        "Registry32" { return "32-bit" }
                        default { return "default" }
                    }
                }

                function ConvertTo-WmtHklmViewPath {
                    param(
                        [string]$SubPath,
                        $View
                    )

                    $effectivePath = ([string]$SubPath).TrimStart('\')
                    if ([string]$View -eq "Registry32" -and $effectivePath -match '^(?i)SOFTWARE\\(?!WOW6432Node\\)(?<Rest>.+)$') {
                        $effectivePath = "SOFTWARE\WOW6432Node\$($Matches.Rest)"
                    }

                    return "HKLM:\$effectivePath"
                }

                function ConvertTo-WmtClassesViewPath {
                    param(
                        [string]$SubPath,
                        $View
                    )

                    $effectivePath = ([string]$SubPath).TrimStart('\')
                    if ([string]$View -eq "Registry32" -and [Environment]::Is64BitOperatingSystem) {
                        # Store the real writable backing path, not the merged HKCR\WOW6432Node view.
                        # HKCR is merged/virtual, and deleting through HKCR\WOW6432Node can fail or hit the wrong view.
                        return "HKLM:\SOFTWARE\WOW6432Node\Classes\$effectivePath"
                    }
                    if ([string]$View -eq "Registry64") {
                        return "HKLM:\SOFTWARE\Classes\$effectivePath"
                    }

                    return "HKCR:\$effectivePath"
                }

                function Get-WmtMissingRegistryPathTarget {
                    param(
                        $RawValue,
                        $RegistryView = $null
                    )

                    if ($null -eq $RawValue) { return $null }
                    $cleanPath = Get-RealExePath ([string]$RawValue)
                    if ([string]::IsNullOrWhiteSpace($cleanPath)) { return $null }
                    if ($cleanPath -notmatch '^[a-zA-Z]:\\') { return $null }
                    if (Test-IsWhitelisted $cleanPath) { return $null }
                    if (Test-IsProtectedWindowsPath $cleanPath) { return $null }
                    if (Test-PathExists -Path $cleanPath -RegistryView $RegistryView) { return $null }

                    if ($cleanPath -match '^(?<Path>[a-zA-Z]:\\.+\.(?:dll|exe|ocx|tlb|olb))\\-?\d+$') {
                        $resourceHostPath = $Matches.Path
                        if ((-not (Test-IsProtectedWindowsPath $resourceHostPath)) -and (Test-PathExists -Path $resourceHostPath -RegistryView $RegistryView)) {
                            return $null
                        }
                    }

                    return $cleanPath
                }

                function Test-WmtClsidExists {
                    param([string]$Clsid)
                    $normalized = ConvertTo-WmtClsid $Clsid
                    if (-not $normalized) { return $false }

                    foreach ($view in @(Get-WmtRegistryViews)) {
                        $root = $null; $key = $null
                        try {
                            $root = [Microsoft.Win32.RegistryKey]::OpenBaseKey([Microsoft.Win32.RegistryHive]::ClassesRoot, $view)
                            $key = $root.OpenSubKey("CLSID\$normalized", $false)
                            if ($key) { return $true }
                        }
                        catch {}
                        finally {
                            if ($key) { $key.Close() }
                            if ($root) { $root.Close() }
                        }
                    }

                    return $false
                }

                function Test-WmtClsidExistsForTarget {
                    param(
                        [string]$Clsid,
                        [object]$Target
                    )
                    $normalized = ConvertTo-WmtClsid $Clsid
                    if (-not $normalized) { return $false }
                    if (Test-WmtClsidExists $normalized) { return $true }

                    $userClassesPath = $null
                    if ($Target -and [string]$Target.RegPrefix -match '^HKEY_USERS\\(?<Sid>[^\\]+)\\') {
                        $userClassesPath = "$($Matches.Sid)\Software\Classes\CLSID\$normalized"
                        $usersRoot = [Microsoft.Win32.Registry]::Users
                        $key = $null
                        try {
                            $key = $usersRoot.OpenSubKey($userClassesPath, $false)
                            return ($null -ne $key)
                        }
                        catch { return $false }
                        finally {
                            if ($key) { $key.Close() }
                        }
                    }
                    elseif ($Target -and [string]$Target.RegPrefix -match '^(HKEY_CURRENT_USER|HKCU:)') {
                        $key = $null
                        try {
                            $key = [Microsoft.Win32.Registry]::CurrentUser.OpenSubKey("Software\Classes\CLSID\$normalized", $false)
                            return ($null -ne $key)
                        }
                        catch { return $false }
                        finally {
                            if ($key) { $key.Close() }
                        }
                    }

                    return $false
                }

                function Get-WmtClsidReferenceIssue {
                    param(
                        [string]$Clsid,
                        $View = $null
                    )
                    $normalized = ConvertTo-WmtClsid $Clsid
                    if (-not $normalized) { return $null }

                    $viewsToScan = if ($null -ne $View) { @($View) } else { @(Get-WmtRegistryViews) }
                    $foundClsid = $false

                    foreach ($scanView in $viewsToScan) {
                        $viewLabel = Get-WmtRegistryViewLabel $scanView
                        $root = $null; $clsidKey = $null
                        try {
                            $root = [Microsoft.Win32.RegistryKey]::OpenBaseKey([Microsoft.Win32.RegistryHive]::ClassesRoot, $scanView)
                            $clsidKey = $root.OpenSubKey("CLSID\$normalized", $false)
                            if (-not $clsidKey) { continue }

                            $foundClsid = $true
                            foreach ($serverName in @("InProcServer32", "LocalServer32")) {
                                $serverKey = $null
                                try {
                                    $serverKey = $clsidKey.OpenSubKey($serverName, $false)
                                    if ($serverKey) {
                                        $rawServer = [string]$serverKey.GetValue($null)
                                        $serverPath = Get-ServiceImageExecutablePath -RawString $rawServer -RegistryView $scanView
                                        if ($serverPath -and -not (Test-IsWhitelisted $serverPath) -and -not (Test-IsProtectedWindowsPath $serverPath) -and -not (Test-PathExists -Path $serverPath -RegistryView $scanView)) {
                                            return [PSCustomObject]@{ IsBroken = $true; Data = $serverPath; Details = "Referenced CLSID $normalized ($viewLabel registry view) points to missing COM server $serverPath." }
                                        }
                                    }
                                }
                                catch {}
                                finally {
                                    if ($serverKey) { $serverKey.Close() }
                                }
                            }
                        }
                        catch {}
                        finally {
                            if ($clsidKey) { $clsidKey.Close() }
                            if ($root) { $root.Close() }
                        }
                    }

                    if (-not $foundClsid) {
                        $viewText = if ($null -ne $View) { "$(Get-WmtRegistryViewLabel $View) registry view" } else { "available registry views" }
                        return [PSCustomObject]@{ IsBroken = $true; Data = $normalized; Details = "Referenced CLSID $normalized does not exist under $viewText." }
                    }

                    return [PSCustomObject]@{ IsBroken = $false; Data = $normalized; Details = "" }
                }

                function Get-WmtMissingPathSegments {
                    param([string]$PathValue)
                    $missing = New-Object System.Collections.Generic.List[string]
                    if ([string]::IsNullOrWhiteSpace($PathValue)) { return $missing.ToArray() }

                    foreach ($segment in ($PathValue -split ';')) {
                        $candidate = ([string]$segment).Trim()
                        if ([string]::IsNullOrWhiteSpace($candidate)) { continue }
                        if ($candidate -match '[\*\?]' -or $candidate -match '^\.+$') { continue }
                        if ($candidate -notmatch '^(?i)([a-z]:\\|%[^%]+%\\|\\\\)') { continue }
                        if (-not (Test-PathExists $candidate)) { [void]$missing.Add($candidate) }
                    }

                    return $missing.ToArray()
                }

                function Get-WmtCleanedPathValue {
                    param(
                        [string]$PathValue,
                        [string[]]$MissingSegments
                    )
                    $missingSet = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
                    foreach ($segment in @($MissingSegments)) {
                        if (-not [string]::IsNullOrWhiteSpace($segment)) { [void]$missingSet.Add($segment.Trim()) }
                    }

                    $kept = New-Object System.Collections.Generic.List[string]
                    foreach ($segment in ($PathValue -split ';')) {
                        $trimmed = ([string]$segment).Trim()
                        if ([string]::IsNullOrWhiteSpace($trimmed)) { continue }
                        if (-not $missingSet.Contains($trimmed)) { [void]$kept.Add($trimmed) }
                    }

                    return ($kept -join ';')
                }

                function Get-WmtTaskTreeEntries {
                    param(
                        [Microsoft.Win32.RegistryKey]$Key,
                        [string]$RelativePath
                    )

                    $entries = New-Object System.Collections.Generic.List[object]
                    foreach ($childName in $Key.GetSubKeyNames()) {
                        $child = $null
                        try {
                            $child = $Key.OpenSubKey($childName, $false)
                            if ($child) {
                                $childRelativePath = if ([string]::IsNullOrWhiteSpace($RelativePath)) { $childName } else { "$RelativePath\$childName" }
                                $taskId = [string]$child.GetValue("Id")
                                if (-not [string]::IsNullOrWhiteSpace($taskId)) {
                                    [void]$entries.Add([PSCustomObject]@{ RelativePath = $childRelativePath; Id = $taskId })
                                }
                                foreach ($entry in @(Get-WmtTaskTreeEntries -Key $child -RelativePath $childRelativePath)) {
                                    [void]$entries.Add($entry)
                                }
                            }
                        }
                        catch {}
                        finally {
                            if ($child) { $child.Close() }
                        }
                    }

                    return $entries.ToArray()
                }

                function Get-WmtTaskFilePath {
                    param([string]$TaskPath)
                    if ([string]::IsNullOrWhiteSpace($TaskPath)) { return $null }
                    $relative = $TaskPath.TrimStart('\')
                    if ([string]::IsNullOrWhiteSpace($relative)) { return $null }
                    return (Join-Path (Join-Path $env:windir "System32\Tasks") $relative)
                }

                function Test-WmtProtectedSystemTaskPath {
                    param([string]$TaskPath)
                    if ([string]::IsNullOrWhiteSpace($TaskPath)) { return $false }
                    $relative = ([string]$TaskPath).Trim().TrimStart('\')
                    return ($relative -match '^(?i)Microsoft\\(Windows|OneCore)\\')
                }

                function Get-WmtPathState {
                    param(
                        [string]$Path,
                        [string]$PathType = "Any"
                    )
                    if ([string]::IsNullOrWhiteSpace($Path)) { return "Unknown" }

                    try {
                        if (Test-Path -LiteralPath $Path -PathType $PathType -ErrorAction Stop) { return "Exists" }
                    }
                    catch [System.UnauthorizedAccessException] { return "Unknown" }
                    catch [System.Security.SecurityException] { return "Unknown" }
                    catch {}

                    try {
                        [void](Get-Item -LiteralPath $Path -Force -ErrorAction Stop)
                        return "Exists"
                    }
                    catch {
                        if ($_.CategoryInfo.Category -eq [System.Management.Automation.ErrorCategory]::ObjectNotFound) { return "Missing" }
                        if ($_.Exception.Message -match '(?i)access.*denied|unauthorized') { return "Unknown" }
                    }

                    return "Unknown"
                }

                function Get-WmtTaskSchedulerService {
                    if ($script:WmtTaskSchedulerServiceChecked) { return $script:WmtTaskSchedulerService }
                    $script:WmtTaskSchedulerServiceChecked = $true
                    $script:WmtTaskSchedulerService = $null

                    try {
                        $service = New-Object -ComObject "Schedule.Service"
                        $service.Connect()
                        $script:WmtTaskSchedulerService = $service
                    }
                    catch {
                        $script:WmtTaskSchedulerService = $null
                    }

                    return $script:WmtTaskSchedulerService
                }

                function Get-WmtScheduledTaskState {
                    param([string]$TaskPath)
                    if ([string]::IsNullOrWhiteSpace($TaskPath)) { return "Unknown" }

                    $service = Get-WmtTaskSchedulerService
                    if (-not $service) { return "Unknown" }

                    $normalized = ([string]$TaskPath).Trim() -replace '/', '\'
                    $normalized = $normalized.Trim('\')
                    if ([string]::IsNullOrWhiteSpace($normalized)) { return "Unknown" }

                    $parts = @($normalized -split '\\' | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
                    if ($parts.Count -eq 0) { return "Unknown" }

                    $taskName = $parts[$parts.Count - 1]
                    $folderPath = "\"
                    if ($parts.Count -gt 1) {
                        $folderPath = "\" + (($parts[0..($parts.Count - 2)]) -join "\")
                    }

                    $folder = $null; $task = $null
                    try {
                        $folder = $service.GetFolder($folderPath)
                        $task = $folder.GetTask($taskName)
                        return "Exists"
                    }
                    catch {
                        $hr = $_.Exception.HResult
                        $msg = [string]$_.Exception.Message
                        if ($hr -eq -2147024894 -or $msg -match '(?i)(cannot find|not found|does not exist|0x80070002)') { return "Missing" }
                        if ($hr -eq -2147024891 -or $msg -match '(?i)access.*denied|unauthorized|0x80070005') { return "Unknown" }
                    }
                    finally {
                        try { if ($task) { [void][System.Runtime.InteropServices.Marshal]::ReleaseComObject($task) } } catch {}
                        try { if ($folder) { [void][System.Runtime.InteropServices.Marshal]::ReleaseComObject($folder) } } catch {}
                    }

                    return "Unknown"
                }

                # Define tick helpers BEFORE try block so they're always available
                $categoryWeight = 100.0 / ($SelectedScans.Count)
                $currentBaseProgress = 0.0

                $Tick = {
                    param($DetailText, $CurrentIndex, $TotalEstimated)
                    if ($CurrentIndex % 50 -eq 0) {
                        $SyncHash.Status = $DetailText
                        $fraction = [math]::Min(($CurrentIndex / $TotalEstimated), 1.0)
                        $realVal = $currentBaseProgress + ($fraction * $categoryWeight)
                        $SyncHash.Progress = [int]$realVal
                    }
                }
                $EndCategory = {
                    $currentBaseProgress += $categoryWeight
                    $SyncHash.Progress = [int]$currentBaseProgress
                }

                try {

                    # 1. ACTIVEX & COM
                    if ($SelectedScans -contains "ActiveX") {
                        $SyncHash.Status = "Scanning ActiveX/COM..."

                        $seenComFindings = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
                        $comTargets = [System.Collections.Generic.List[object]]::new()

                        function Add-WmtComClassScanTarget {
                            param(
                                [System.Collections.Generic.List[object]]$Targets,
                                [Microsoft.Win32.RegistryHive]$Hive,
                                $View,
                                [string]$SubPath,
                                [string]$RegPathPrefix,
                                [string]$Label
                            )

                            if ([string]::IsNullOrWhiteSpace($SubPath) -or [string]::IsNullOrWhiteSpace($RegPathPrefix)) { return }

                            $root = $null
                            $probe = $null
                            try {
                                $root = [Microsoft.Win32.RegistryKey]::OpenBaseKey($Hive, $View)
                                $probe = $root.OpenSubKey($SubPath, $false)
                                if ($probe) {
                                    [void]$Targets.Add([PSCustomObject]@{
                                            Root          = $root
                                            SubPath       = $SubPath
                                            RegPathPrefix = $RegPathPrefix
                                            Label         = $Label
                                            View          = $View
                                        })
                                    $root = $null
                                }
                            }
                            catch {}
                            finally {
                                if ($probe) { $probe.Close() }
                                if ($root) { $root.Close() }
                            }
                        }

                        function Get-WmtComServerProtectionClassification {
                            param(
                                [string]$CleanServerPath,
                                [string]$RawServerPath,
                                [string]$RegPath,
                                [string]$TargetLabel
                            )

                            $clean = [string]$CleanServerPath
                            $raw = [string]$RawServerPath
                            $reg = [string]$RegPath
                            $label = [string]$TargetLabel

                            $isMachineClassStore = ($reg -match '^(?i)(HKLM:\\SOFTWARE\\(WOW6432Node\\)?Classes\\CLSID\\|HKCR:\\(WOW6432Node\\)?CLSID\\)') -or ($label -match '(?i)Machine classes|HKCR merged view')
                            $isMicrosoftSharedCom = ($clean -match '(?i)\\Common Files\\Microsoft Shared\\DAO\\dao360\.dll$') -or `
                            ($clean -match '(?i)\\Common Files\\System\\Ole DB\\msdaora\.dll$') -or `
                            ($raw -match '(?i)%CommonProgramFiles%\\(Microsoft Shared\\DAO|System\\Ole DB)\\')
                            $isWindowsCrossDeviceCom = ($clean -match '(?i)\\ProgramData\\CrossDevice\\CrossDevice\.Streaming\.Source\.dll$') -or `
                            ($raw -match '(?i)%PROGRAMDATA%\\CrossDevice\\CrossDevice\.Streaming\.Source\.dll')

                            if ($isMachineClassStore -and ($isMicrosoftSharedCom -or $isWindowsCrossDeviceCom)) {
                                $reason = if ($isWindowsCrossDeviceCom) {
                                    "Windows CrossDevice machine COM registration. These entries are commonly ACL-protected and may be recreated by Windows components."
                                }
                                else {
                                    "Legacy Microsoft DAO/OLE DB machine COM registration in the merged Classes store. These entries are often Windows/Office shared component registrations, ACL-protected, redirected between 32-bit/64-bit views, or recreated."
                                }
                                return [PSCustomObject]@{
                                    IsProtected = $true
                                    Reason      = $reason
                                    Risk        = "Review"
                                    Confidence  = "Medium"
                                }
                            }

                            if ($label -match '(?i)^HKCR merged view' -and $reg -match '(?i)^HKCR:\\WOW6432Node\\CLSID\\') {
                                return [PSCustomObject]@{
                                    IsProtected = $true
                                    Reason      = "HKCR WOW6432Node is a merged/redirected COM view, not a simple writable cleanup location. WMT can report the stale reference, but automatic deletion through this alias has proven unreliable on this system."
                                    Risk        = "Review"
                                    Confidence  = "Medium"
                                }
                            }

                            return [PSCustomObject]@{
                                IsProtected = $false
                                Reason      = ""
                                Risk        = "Medium"
                                Confidence  = "High"
                            }
                        }

                        function Add-WmtMissingComServerFinding {
                            param(
                                [string]$Clsid,
                                [string]$ServerSubKey,
                                [string]$RawServerPath,
                                [string]$RegPath,
                                [string]$TargetLabel,
                                $RegistryView
                            )

                            if ([string]::IsNullOrWhiteSpace($Clsid) -or [string]::IsNullOrWhiteSpace($RawServerPath)) { return }
                            if (Test-IsWhitelisted $RawServerPath) { return }

                            if ($ServerSubKey -eq "LocalServer32") {
                                $malformedCommand = Get-WmtMalformedComServerCommandIssue -RawString $RawServerPath -RegistryView $RegistryView
                                if ($malformedCommand) {
                                    $dedupeMalformedKey = "$Clsid`0$ServerSubKey`0MalformedAttachedArgument`0$($malformedCommand.RawCommand)"
                                    if (-not $seenComFindings.Add($dedupeMalformedKey)) { return }

                                    [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                            Problem    = "Invalid COM LocalServer Command"
                                            Data       = [string]$malformedCommand.RawCommand
                                            DisplayKey = "$Clsid (COM EXE, $TargetLabel)"
                                            RegPath    = $RegPath
                                            ValueName  = ""
                                            Type       = "SetValue"
                                            NewData    = [string]$malformedCommand.FixedCommand
                                            SafeToFix  = $true
                                            Risk       = "Low"
                                            Confidence = "High"
                                            Details    = "LocalServer32 has an argument attached directly to the executable path. Executable exists: $($malformedCommand.ExePath). WMT will rewrite the default value to: $($malformedCommand.FixedCommand). Registry view/source: $TargetLabel. Raw value: $RawServerPath"
                                        })
                                    return
                                }
                            }

                            $cleanServerPath = Get-ServiceImageExecutablePath -RawString $RawServerPath -RegistryView $RegistryView
                            if ([string]::IsNullOrWhiteSpace($cleanServerPath)) { $cleanServerPath = Get-RealExePath $RawServerPath }
                            if ([string]::IsNullOrWhiteSpace($cleanServerPath)) { return }
                            if ($cleanServerPath -notmatch '^(?i)[a-z]:\\') { return }
                            if (Test-IsWhitelisted $cleanServerPath) { return }
                            if (Test-IsProtectedWindowsPath $cleanServerPath) { return }
                            if (Test-PathExists -Path $cleanServerPath -RegistryView $RegistryView) { return }

                            $dedupeKey = "$Clsid`0$ServerSubKey`0$cleanServerPath"
                            if (-not $seenComFindings.Add($dedupeKey)) { return }

                            $serverKind = if ($ServerSubKey -eq "InProcServer32") { "COM DLL" } else { "COM EXE" }
                            $protection = Get-WmtComServerProtectionClassification -CleanServerPath $cleanServerPath -RawServerPath $RawServerPath -RegPath $RegPath -TargetLabel $TargetLabel
                            $isProtectedCom = [bool]$protection.IsProtected
                            $findingProblem = if ($isProtectedCom) { "Protected ActiveX Issue" } else { "ActiveX Issue" }
                            $findingType = if ($isProtectedCom) { "ReviewOnly" } else { "Key" }
                            $findingRisk = if ($isProtectedCom) { [string]$protection.Risk } else { "Medium" }
                            $findingConfidence = if ($isProtectedCom) { [string]$protection.Confidence } else { "High" }
                            $findingDetails = if ($isProtectedCom) {
                                "$serverKind registration points to a missing file, but WMT will not select or delete it automatically because it appears to be a protected/merged Microsoft COM registration. $($protection.Reason) Registry view/source: $TargetLabel. Raw value: $RawServerPath"
                            }
                            else {
                                "$serverKind registration points to a missing file. The target file does not exist and the path is not under a protected Windows folder, so this stale COM server key is selected by default. Registry view/source: $TargetLabel. Raw value: $RawServerPath"
                            }

                            [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                    Problem    = $findingProblem
                                    Data       = $cleanServerPath
                                    DisplayKey = "$Clsid ($serverKind, $TargetLabel)"
                                    RegPath    = $RegPath
                                    ValueName  = $null
                                    Type       = $findingType
                                    SafeToFix  = (-not $isProtectedCom)
                                    Risk       = $findingRisk
                                    Confidence = $findingConfidence
                                    Details    = $findingDetails
                                })
                        }

                        try {
                            foreach ($view in @(Get-WmtRegistryViews)) {
                                $viewLabel = Get-WmtRegistryViewLabel $view
                                Add-WmtComClassScanTarget -Targets $comTargets -Hive ([Microsoft.Win32.RegistryHive]::LocalMachine) -View $view -SubPath "SOFTWARE\Classes\CLSID" -RegPathPrefix (ConvertTo-WmtClassesViewPath -SubPath "CLSID" -View $view) -Label "Machine classes, $viewLabel"
                            }

                            Add-WmtComClassScanTarget -Targets $comTargets -Hive ([Microsoft.Win32.RegistryHive]::CurrentUser) -View ([Microsoft.Win32.RegistryView]::Default) -SubPath "Software\Classes\CLSID" -RegPathPrefix "HKCU:\Software\Classes\CLSID" -Label "Current user classes"
                            if ([Environment]::Is64BitOperatingSystem) {
                                Add-WmtComClassScanTarget -Targets $comTargets -Hive ([Microsoft.Win32.RegistryHive]::CurrentUser) -View ([Microsoft.Win32.RegistryView]::Default) -SubPath "Software\Classes\WOW6432Node\CLSID" -RegPathPrefix "HKCU:\Software\Classes\WOW6432Node\CLSID" -Label "Current user classes, 32-bit"
                            }

                            $currentSid = $null
                            try { $currentSid = [System.Security.Principal.WindowsIdentity]::GetCurrent().User.Value } catch {}
                            $usersRoot = $null
                            try {
                                $usersRoot = [Microsoft.Win32.RegistryKey]::OpenBaseKey([Microsoft.Win32.RegistryHive]::Users, [Microsoft.Win32.RegistryView]::Default)
                                foreach ($sid in @($usersRoot.GetSubKeyNames())) {
                                    if ($sid -notmatch '^S-1-5-21-.+-\d+$' -or $sid -match '_Classes$') { continue }
                                    if (-not [string]::IsNullOrWhiteSpace($currentSid) -and $sid -eq $currentSid) { continue }

                                    Add-WmtComClassScanTarget -Targets $comTargets -Hive ([Microsoft.Win32.RegistryHive]::Users) -View ([Microsoft.Win32.RegistryView]::Default) -SubPath "$sid\Software\Classes\CLSID" -RegPathPrefix "HKU:\$sid\Software\Classes\CLSID" -Label "User classes, $sid"
                                    if ([Environment]::Is64BitOperatingSystem) {
                                        Add-WmtComClassScanTarget -Targets $comTargets -Hive ([Microsoft.Win32.RegistryHive]::Users) -View ([Microsoft.Win32.RegistryView]::Default) -SubPath "$sid\Software\Classes\WOW6432Node\CLSID" -RegPathPrefix "HKU:\$sid\Software\Classes\WOW6432Node\CLSID" -Label "User classes, $sid, 32-bit"
                                    }
                                }
                            }
                            catch {}
                            finally {
                                if ($usersRoot) { $usersRoot.Close() }
                            }

                            # HKCR is a merged view. Scan it as a final fallback because some orphaned COM registrations
                            # are visible to the PowerShell provider under HKCR even when they are not found through the
                            # machine-only Classes paths above. On 64-bit Windows, 32-bit COM entries can also appear under
                            # HKCR:\WOW6432Node\CLSID when viewed from the 64-bit registry provider.
                            Add-WmtComClassScanTarget -Targets $comTargets -Hive ([Microsoft.Win32.RegistryHive]::ClassesRoot) -View ([Microsoft.Win32.RegistryView]::Default) -SubPath "CLSID" -RegPathPrefix "HKCR:\CLSID" -Label "HKCR merged view"
                            if ([Environment]::Is64BitOperatingSystem) {
                                Add-WmtComClassScanTarget -Targets $comTargets -Hive ([Microsoft.Win32.RegistryHive]::ClassesRoot) -View ([Microsoft.Win32.RegistryView]::Default) -SubPath "WOW6432Node\CLSID" -RegPathPrefix "HKCR:\WOW6432Node\CLSID" -Label "HKCR merged view, 32-bit"
                            }

                            foreach ($target in @($comTargets)) {
                                $clsidKey = $null
                                try {
                                    $clsidKey = $target.Root.OpenSubKey([string]$target.SubPath, $false)
                                    if (-not $clsidKey) { continue }

                                    $subKeys = $clsidKey.GetSubKeyNames()
                                    $total = [math]::Max($subKeys.Count, 1)
                                    $i = 0

                                    foreach ($id in $subKeys) {
                                        $i++
                                        & $Tick "Scanning CLSID ($($target.Label)): $id" $i $total

                                        foreach ($serverSubKey in @("InProcServer32", "LocalServer32")) {
                                            $serverKey = $null
                                            try {
                                                $serverKey = $clsidKey.OpenSubKey("$id\$serverSubKey", $false)
                                                if (-not $serverKey) { continue }

                                                $rawServerPath = [string]$serverKey.GetValue($null, $null, [Microsoft.Win32.RegistryValueOptions]::DoNotExpandEnvironmentNames)
                                                if ([string]::IsNullOrWhiteSpace($rawServerPath)) { continue }

                                                $regPath = "$($target.RegPathPrefix)\$id\$serverSubKey"
                                                Add-WmtMissingComServerFinding -Clsid $id -ServerSubKey $serverSubKey -RawServerPath $rawServerPath -RegPath $regPath -TargetLabel ([string]$target.Label) -RegistryView $target.View
                                            }
                                            catch {}
                                            finally {
                                                if ($serverKey) { $serverKey.Close() }
                                            }
                                        }
                                    }
                                }
                                catch {}
                                finally {
                                    if ($clsidKey) { $clsidKey.Close() }
                                }
                            }
                        }
                        finally {
                            foreach ($target in @($comTargets)) {
                                try { if ($target.Root) { $target.Root.Close() } } catch {}
                            }
                        }

                        & $EndCategory
                    }

                    # 2. FILE EXTENSIONS
                    if ($SelectedScans -contains "Ext") { 
                        $SyncHash.Status = "Scanning File Extensions..."
                        $root = [Microsoft.Win32.RegistryKey]::OpenBaseKey([Microsoft.Win32.RegistryHive]::ClassesRoot, [Microsoft.Win32.RegistryView]::Default)
                        $names = $root.GetSubKeyNames(); $total = $names.Count; $i = 0
                        foreach ($ext in $names) { 
                            $i++; & $Tick "Scanning Ext: $ext" $i $total
                            if ($ext.StartsWith(".")) { 
                                try { 
                                    $sub = $root.OpenSubKey($ext)
                                    if ($sub.SubKeyCount -eq 0 -and $sub.ValueCount -eq 0 -and $null -eq $sub.GetValue($null)) { 
                                        [void]$SyncHash.Findings.Add([PSCustomObject]@{ Problem = "Unused Extension"; Data = $ext; DisplayKey = $ext; RegPath = "HKCR:\$ext"; ValueName = $null; Type = "Key" }) 
                                    }; $sub.Close() 
                                }
                                catch {} 
                            } 
                        }
                        & $EndCategory
                    }

                    # 3. USER FILE EXTS
                    if ($SelectedScans -contains "FileExts") {
                        $SyncHash.Status = "Scanning User File Associations..."
                        $path = "Software\Microsoft\Windows\CurrentVersion\Explorer\FileExts"
                        $root = [Microsoft.Win32.Registry]::CurrentUser.OpenSubKey($path)
                        if ($root) {
                            $names = $root.GetSubKeyNames(); $total = $names.Count; $i = 0
                            foreach ($ext in $names) {
                                $i++; & $Tick "Scanning UserExt: $ext" $i $total
                                $owl = $root.OpenSubKey("$ext\OpenWithList")
                                if ($owl) {
                                    foreach ($valName in $owl.GetValueNames()) {
                                        if ($valName -match "^[a-z]$") { 
                                            $val = $owl.GetValue($valName)
                                            if ($val -match '^[a-zA-Z]:\\') {
                                                $cleanPath = Get-RealExePath $val
                                                if (-not (Test-PathExists $cleanPath)) { [void]$SyncHash.Findings.Add([PSCustomObject]@{ Problem = "Invalid FileExt MRU"; Data = $cleanPath; DisplayKey = $ext; RegPath = "HKCU:\$path\$ext\OpenWithList"; ValueName = $valName; Type = "Value" }) }
                                            }
                                        }
                                    }
                                    $owl.Close()
                                }
                            }
                            $root.Close()
                        }
                        & $EndCategory
                    }

                    # 4. APP PATHS
                    if ($SelectedScans -contains "AppPaths") {
                        $SyncHash.Status = "Scanning App Paths..."
                        $key = "SOFTWARE\Microsoft\Windows\CurrentVersion\App Paths"
                        foreach ($view in @(Get-WmtRegistryViews)) {
                            $baseKey = $null; $root = $null
                            try {
                                $baseKey = [Microsoft.Win32.RegistryKey]::OpenBaseKey([Microsoft.Win32.RegistryHive]::LocalMachine, $view)
                                $root = $baseKey.OpenSubKey($key)
                                if ($root) {
                                    $viewLabel = Get-WmtRegistryViewLabel $view
                                    $names = $root.GetSubKeyNames(); $total = $names.Count; $i = 0
                                    foreach ($app in $names) {
                                        $i++; & $Tick "Scanning AppPath ($viewLabel): $app" $i $total
                                        try {
                                            $sub = $root.OpenSubKey($app)
                                            $path = $sub.GetValue($null)
                                            if ($path -and $path -match '^[a-zA-Z]:\\' -and -not (Test-IsWhitelisted $path)) {
                                                $clean = Get-RealExePath $path
                                                if (-not (Test-IsProtectedWindowsPath $clean) -and -not (Test-PathExists $clean)) { [void]$SyncHash.Findings.Add([PSCustomObject]@{ Problem = "Missing App Path"; Data = $clean; DisplayKey = "$app ($viewLabel)"; RegPath = "$(ConvertTo-WmtHklmViewPath -SubPath $key -View $view)\$app"; ValueName = $null; Type = "Key"; Details = "App Paths target is missing in the $viewLabel registry view." }) }
                                            }
                                            $pathValue = [string]$sub.GetValue("Path", $null, [Microsoft.Win32.RegistryValueOptions]::DoNotExpandEnvironmentNames)
                                            $missingSegments = @(Get-WmtMissingPathSegments $pathValue)
                                            if ($missingSegments.Count -gt 0) {
                                                $newPath = Get-WmtCleanedPathValue -PathValue $pathValue -MissingSegments $missingSegments
                                                $data = $missingSegments[0]
                                                if ($missingSegments.Count -gt 1) { $data = "$data ($($missingSegments.Count) missing App Paths entries)" }
                                                [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                                        Problem    = "Invalid App Paths PATH Entry"
                                                        Data       = $data
                                                        DisplayKey = "$app ($viewLabel)"
                                                        RegPath    = "$(ConvertTo-WmtHklmViewPath -SubPath $key -View $view)\$app"
                                                        ValueName  = "Path"
                                                        Type       = "SetValue"
                                                        NewData    = $newPath
                                                        SafeToFix  = $true
                                                        Risk       = "Low"
                                                        Confidence = "High"
                                                        Details    = "Rewrites this App Paths PATH value after removing missing segment(s): $($missingSegments -join '; ')"
                                                    })
                                            }
                                            $sub.Close()
                                        }
                                        catch {}
                                    }
                                }
                            }
                            catch {}
                            finally {
                                if ($root) { $root.Close() }
                                if ($baseKey) { $baseKey.Close() }
                            }
                        }
                        & $EndCategory
                    }

                    # 5. APPLICATIONS & PROGIDs
                    if ($SelectedScans -contains "Apps" -or $SelectedScans -contains "ProgIDs") {
                        $SyncHash.Status = "Scanning Apps & ProgIDs..."
                        $searchRoots = @()
                        if ($SelectedScans -contains "Apps") { 
                            $cr = [Microsoft.Win32.RegistryKey]::OpenBaseKey([Microsoft.Win32.RegistryHive]::ClassesRoot, [Microsoft.Win32.RegistryView]::Default)
                            $searchRoots += $cr.OpenSubKey("Applications") 
                        }
                        if ($SelectedScans -contains "ProgIDs") { 
                            $searchRoots += [Microsoft.Win32.RegistryKey]::OpenBaseKey([Microsoft.Win32.RegistryHive]::ClassesRoot, [Microsoft.Win32.RegistryView]::Default)
                        }

                        foreach ($root in $searchRoots) {
                            if ($root) {
                                $names = $root.GetSubKeyNames(); $total = $names.Count; $i = 0
                                foreach ($app in $names) {
                                    $i++; & $Tick "Scanning App: $app" $i $total
                                    try {
                                        $appKey = $root.OpenSubKey($app); $shellKey = $appKey.OpenSubKey("shell")
                                        if ($shellKey) {
                                            foreach ($verb in $shellKey.GetSubKeyNames()) {
                                                try {
                                                    $cmdKey = $shellKey.OpenSubKey("$verb\command")
                                                    if ($cmdKey) {
                                                        $cmd = $cmdKey.GetValue($null)
                                                        if ($cmd) {
                                                            $clean = Get-RealExePath $cmd
                                                            if ($clean -and $clean -match '^[a-zA-Z]:\\' -and -not (Test-IsWhitelisted $clean)) {
                                                                if (-not (Test-IsProtectedWindowsPath $clean) -and -not (Test-PathExists $clean) -and $clean -notmatch "%1") {
                                                                    [void]$SyncHash.Findings.Add([PSCustomObject]@{ Problem = "Invalid App Command ($verb)"; Data = $clean; DisplayKey = $app; RegPath = "$($root.Name)\$app\shell\$verb\command"; ValueName = $null; Type = "Key" })
                                                                }
                                                            }
                                                        }
                                                        $cmdKey.Close()
                                                    }
                                                }
                                                catch {}
                                            }
                                            $shellKey.Close()
                                        }
                                        $appKey.Close()
                                    }
                                    catch {}
                                }
                            }
                        }
                        & $EndCategory
                    }

                    # 6. UNINSTALLERS
                    if ($SelectedScans -contains "Uninstall") {
                        $SyncHash.Status = "Scanning Uninstallers..."
                        $uninstallTargets = New-Object System.Collections.Generic.List[object]
                        $uninstallPath = "SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall"
                        foreach ($view in @(Get-WmtRegistryViews)) {
                            try {
                                $baseKey = [Microsoft.Win32.RegistryKey]::OpenBaseKey([Microsoft.Win32.RegistryHive]::LocalMachine, $view)
                                [void]$uninstallTargets.Add([PSCustomObject]@{ BaseKey = $baseKey; SubPath = $uninstallPath; RegPrefix = (ConvertTo-WmtHklmViewPath -SubPath $uninstallPath -View $view); Label = "HKLM $(Get-WmtRegistryViewLabel $view)"; OwnsBaseKey = $true })
                            }
                            catch {}
                        }
                        foreach ($target in @(New-PerUserRegistryTargets -SubPath "Software\Microsoft\Windows\CurrentVersion\Uninstall" -HkcuLabel "HKCU\Software\Microsoft\Windows\CurrentVersion\Uninstall")) {
                            [void]$uninstallTargets.Add([PSCustomObject]@{ BaseKey = $target.BaseKey; SubPath = $target.SubPath; RegPrefix = $target.RegPrefix; Label = $target.Label; OwnsBaseKey = $false })
                        }

                        $total = [math]::Max($uninstallTargets.Count * 100, 1); $i = 0
                        foreach ($target in $uninstallTargets) {
                            $rk = $null
                            try {
                                $rk = $target.BaseKey.OpenSubKey($target.SubPath)
                                if ($rk) {
                                    foreach ($subName in $rk.GetSubKeyNames()) {
                                        $i++; & $Tick "Scanning Uninstaller: $subName" $i $total
                                        $sub = $null
                                        try {
                                            $sub = $rk.OpenSubKey($subName)
                                            if (-not $sub) { continue }
                                            $uString = $sub.GetValue("UninstallString")
                                            $displayName = [string]$sub.GetValue("DisplayName")
                                            $isWindowsInstaller = (Test-IsRegistryFlagEnabled $sub.GetValue("WindowsInstaller")) -or (Test-IsWindowsInstallerCommand $uString)
                                            $isSystemComponent = Test-IsRegistryFlagEnabled $sub.GetValue("SystemComponent")
                                            $isNoRemove = Test-IsRegistryFlagEnabled $sub.GetValue("NoRemove")
                                            if ($uString -and -not ([string]::IsNullOrWhiteSpace($displayName)) -and -not $isWindowsInstaller -and -not $isSystemComponent -and -not $isNoRemove) {
                                                $clean = Get-UninstallExecutablePath $uString
                                                if ($clean -and -not (Test-IsWhitelisted $clean) -and -not (Test-IsProtectedWindowsPath $clean) -and -not (Test-PathExists $clean)) {
                                                    [void]$SyncHash.Findings.Add([PSCustomObject]@{ Problem = "Missing Uninstaller"; Data = $clean; DisplayKey = "$displayName ($($target.Label))"; RegPath = "$($target.RegPrefix)\$subName"; ValueName = $null; Type = "Key"; Details = "Uninstall command points to a missing executable." })
                                                }
                                            }
                                        }
                                        catch {}
                                        finally {
                                            if ($sub) { $sub.Close() }
                                        }
                                    }
                                }
                            }
                            catch {}
                            finally {
                                if ($rk) { $rk.Close() }
                                if ($target.OwnsBaseKey -and $target.BaseKey) { $target.BaseKey.Close() }
                            }
                        }
                        & $EndCategory
                    }

                    # 7. MUI CACHE
                    if ($SelectedScans -contains "MuiCache") {
                        $SyncHash.Status = "Scanning MuiCache..."
                        $key = "Software\Classes\Local Settings\Software\Microsoft\Windows\Shell\MuiCache"
                        $root = [Microsoft.Win32.Registry]::CurrentUser.OpenSubKey($key)
                        if ($root) {
                            $names = $root.GetValueNames(); $total = $names.Count; $i = 0
                            foreach ($valName in $names) {
                                $i++; & $Tick "Scanning MuiCache: $valName" $i $total
                                $cleanPath = $valName -replace '\.(FriendlyAppName|ApplicationCompany)$', ''
                                if ($cleanPath -match '^[a-zA-Z]:\\' -and -not (Test-IsWhitelisted $cleanPath)) {
                                    if (-not (Test-PathExists $cleanPath)) { [void]$SyncHash.Findings.Add([PSCustomObject]@{ Problem = "Obsolete MuiCache"; Data = $cleanPath; DisplayKey = "MuiCache"; RegPath = "HKCU:\$key"; ValueName = $valName; Type = "Value" }) }
                                }
                            }
                            $root.Close()
                        }
                        & $EndCategory
                    }

                    # 8. APPCOMPAT FLAGS
                    if ($SelectedScans -contains "AppCompat") {
                        $SyncHash.Status = "Scanning Compatibility Store..."
                        $key = "Software\Microsoft\Windows NT\CurrentVersion\AppCompatFlags\Compatibility Assistant\Store"
                        $root = [Microsoft.Win32.Registry]::CurrentUser.OpenSubKey($key)
                        if ($root) {
                            $names = $root.GetValueNames(); $total = $names.Count; $i = 0
                            foreach ($valName in $names) {
                                $i++; & $Tick "Scanning AppCompat: $valName" $i $total
                                if ($valName -match '^[a-zA-Z]:\\' -and -not (Test-IsWhitelisted $valName)) {
                                    if (-not (Test-PathExists $valName)) { [void]$SyncHash.Findings.Add([PSCustomObject]@{ Problem = "Obsolete Compatibility Ref"; Data = $valName; DisplayKey = "AppCompat"; RegPath = "HKCU:\$key"; ValueName = $valName; Type = "Value" }) }
                                }
                            }
                            $root.Close()
                        }
                        & $EndCategory
                    }

                    # 8B. APPCOMPAT LAYERS
                    if ($SelectedScans -contains "AppCompatLayers") {
                        $SyncHash.Status = "Scanning AppCompat Layers..."
                        $layerTargets = New-Object System.Collections.Generic.List[object]
                        $layerPath = "SOFTWARE\Microsoft\Windows NT\CurrentVersion\AppCompatFlags\Layers"
                        foreach ($view in @(Get-WmtRegistryViews)) {
                            try {
                                $baseKey = [Microsoft.Win32.RegistryKey]::OpenBaseKey([Microsoft.Win32.RegistryHive]::LocalMachine, $view)
                                [void]$layerTargets.Add([PSCustomObject]@{ BaseKey = $baseKey; SubPath = $layerPath; RegPrefix = (ConvertTo-WmtHklmViewPath -SubPath $layerPath -View $view); Label = "HKLM $(Get-WmtRegistryViewLabel $view) AppCompat Layers"; OwnsBaseKey = $true })
                            }
                            catch {}
                        }
                        foreach ($target in @(New-PerUserRegistryTargets -SubPath "Software\Microsoft\Windows NT\CurrentVersion\AppCompatFlags\Layers" -HkcuLabel "HKCU\AppCompat Layers")) {
                            [void]$layerTargets.Add([PSCustomObject]@{ BaseKey = $target.BaseKey; SubPath = $target.SubPath; RegPrefix = $target.RegPrefix; Label = $target.Label; OwnsBaseKey = $false })
                        }

                        $total = [math]::Max($layerTargets.Count, 1); $i = 0
                        foreach ($target in $layerTargets) {
                            $i++; & $Tick "Scanning AppCompat Layers: $($target.Label)" $i $total
                            $root = $null
                            try {
                                $root = $target.BaseKey.OpenSubKey($target.SubPath, $false)
                                if ($root) {
                                    foreach ($valName in $root.GetValueNames()) {
                                        if ($valName -match '^(?i)([a-z]:\\|\\\\)' -and -not (Test-IsWhitelisted $valName) -and -not (Test-IsProtectedWindowsPath $valName) -and -not (Test-PathExists $valName)) {
                                            [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                                    Problem    = "Obsolete AppCompat Layer"
                                                    Data       = $valName
                                                    DisplayKey = $target.Label
                                                    RegPath    = $target.RegPrefix
                                                    ValueName  = $valName
                                                    Type       = "Value"
                                                    SafeToFix  = $true
                                                    Risk       = "Low"
                                                    Confidence = "High"
                                                    Details    = "Compatibility layer value points to a missing executable. Cleanup deletes only this value."
                                                })
                                        }
                                    }
                                }
                            }
                            catch {}
                            finally {
                                if ($root) { $root.Close() }
                                if ($target.OwnsBaseKey -and $target.BaseKey) { $target.BaseKey.Close() }
                            }
                        }
                        & $EndCategory
                    }

                    # 8C. USER MRU CACHES
                    if ($SelectedScans -contains "UserMru") {
                        $SyncHash.Status = "Scanning User MRU Caches..."
                        $mruDefinitions = @(
                            [PSCustomObject]@{ SubPath = "Software\Microsoft\Windows\CurrentVersion\Explorer\RecentDocs"; Label = "Recent documents"; Risk = "Low" },
                            [PSCustomObject]@{ SubPath = "Software\Microsoft\Windows\CurrentVersion\Explorer\ComDlg32\OpenSavePidlMRU"; Label = "Open/save dialog history"; Risk = "Low" },
                            [PSCustomObject]@{ SubPath = "Software\Microsoft\Windows\CurrentVersion\Explorer\ComDlg32\LastVisitedPidlMRU"; Label = "Last visited dialog history"; Risk = "Low" },
                            [PSCustomObject]@{ SubPath = "Software\Microsoft\Windows\CurrentVersion\Explorer\MountPoints2"; Label = "Mounted device/network location cache"; Risk = "Medium" }
                        )

                        $total = [math]::Max($mruDefinitions.Count, 1); $i = 0
                        foreach ($definition in $mruDefinitions) {
                            $i++; & $Tick "Scanning MRU cache: $($definition.Label)" $i $total
                            foreach ($target in @(New-PerUserRegistryTargets -SubPath $definition.SubPath -HkcuLabel "HKCU\$($definition.Label)")) {
                                $root = $null
                                try {
                                    $root = $target.BaseKey.OpenSubKey($target.SubPath, $false)
                                    if ($root -and ($root.SubKeyCount -gt 0 -or $root.ValueCount -gt 0)) {
                                        [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                                Problem    = "User MRU Cache"
                                                Data       = $definition.Label
                                                DisplayKey = $target.Label
                                                RegPath    = $target.RegPrefix
                                                ValueName  = $null
                                                Type       = "Key"
                                                SafeToFix  = $false
                                                Risk       = $definition.Risk
                                                Confidence = "High"
                                                Details    = "Per-user history/cache key. Windows recreates it as needed; cleanup removes stored MRU entries under this key."
                                            })
                                    }
                                }
                                catch {}
                                finally {
                                    if ($root) { $root.Close() }
                                }
                            }
                        }
                        & $EndCategory
                    }

                    # 9. NOTIFICATION AREA ICONS
                    if ($SelectedScans -contains "NotifyIcons") {
                        $SyncHash.Status = "Scanning Notification Area Icons..."
                        $notifyTargets = @(New-PerUserRegistryTargets -SubPath "Control Panel\NotifyIconSettings" -HkcuLabel "HKCU\Control Panel\NotifyIconSettings")

                        $total = [math]::Max($notifyTargets.Count, 1); $i = 0
                        foreach ($target in $notifyTargets) {
                            $i++; & $Tick "Scanning Notify Icons: $($target.Label)" $i $total
                            try {
                                $root = $target.BaseKey.OpenSubKey($target.SubPath)
                                if ($root) {
                                    foreach ($entry in $root.GetSubKeyNames()) {
                                        try {
                                            $sub = $root.OpenSubKey($entry)
                                            if ($sub) {
                                                $exePath = [string]$sub.GetValue("ExecutablePath")
                                                if (-not [string]::IsNullOrWhiteSpace($exePath)) {
                                                    $clean = Get-ServiceImageExecutablePath $exePath
                                                    if ($clean -and -not (Test-IsWhitelisted $clean) -and -not (Test-IsProtectedWindowsPath $clean) -and -not (Test-PathExists $clean)) {
                                                        [void]$SyncHash.Findings.Add([PSCustomObject]@{ Problem = "Obsolete Notify Icon"; Data = $clean; DisplayKey = "$($target.Label)\$entry"; RegPath = "$($target.RegPrefix)\$entry"; ValueName = $null; Type = "Key" })
                                                    }
                                                }
                                                $sub.Close()
                                            }
                                        }
                                        catch {}
                                    }
                                    $root.Close()
                                }
                            }
                            catch {}
                        }
                        & $EndCategory
                    }

                    # 10. APP MODULE CACHES
                    if ($SelectedScans -contains "AppModules") {
                        $SyncHash.Status = "Scanning App Module Caches..."
                        $softwareTargets = @(New-PerUserRegistryTargets -SubPath "Software" -HkcuLabel "HKCU\Software")

                        $total = [math]::Max($softwareTargets.Count, 1); $i = 0
                        foreach ($target in $softwareTargets) {
                            $i++; & $Tick "Scanning App Modules: $($target.Label)" $i $total
                            try {
                                $softwareRoot = $target.BaseKey.OpenSubKey($target.SubPath)
                                if ($softwareRoot) {
                                    foreach ($appName in $softwareRoot.GetSubKeyNames()) {
                                        if (Test-IsUserSoftwareKeyExcluded $appName) { continue }

                                        try {
                                            $appKey = $softwareRoot.OpenSubKey($appName)
                                            if (-not $appKey) { continue }

                                            $modulesKey = $appKey.OpenSubKey("Modules")
                                            if ($modulesKey) {
                                                $modulePaths = New-Object System.Collections.Generic.List[string]
                                                $hasValidPath = $false

                                                foreach ($moduleName in $modulesKey.GetSubKeyNames()) {
                                                    try {
                                                        $moduleKey = $modulesKey.OpenSubKey($moduleName)
                                                        if ($moduleKey) {
                                                            foreach ($valueName in @("path_x64", "path_x86")) {
                                                                $modulePath = [string]$moduleKey.GetValue($valueName)
                                                                if (-not [string]::IsNullOrWhiteSpace($modulePath)) {
                                                                    [void]$modulePaths.Add($modulePath)
                                                                    if (Test-PathExists $modulePath) { $hasValidPath = $true }
                                                                }
                                                            }
                                                            $moduleKey.Close()
                                                        }
                                                    }
                                                    catch {}
                                                }

                                                if ($modulePaths.Count -gt 0 -and -not $hasValidPath) {
                                                    $data = $modulePaths[0]
                                                    if ($modulePaths.Count -gt 1) { $data = "$data ($($modulePaths.Count) missing module paths)" }
                                                    $details = "All populated module path_x64/path_x86 values under $($target.RegPrefix)\$appName\Modules are missing. Cleanup target is the app root key."
                                                    [void]$SyncHash.Findings.Add([PSCustomObject]@{ Problem = "Obsolete App Module Cache"; Data = $data; DisplayKey = "$appName (Modules cache)"; RegPath = "$($target.RegPrefix)\$appName"; ValueName = $null; Type = "Key"; Details = $details })
                                                }

                                                $modulesKey.Close()
                                            }

                                            $appKey.Close()
                                        }
                                        catch {}
                                    }
                                    $softwareRoot.Close()
                                }
                            }
                            catch {}
                        }
                        & $EndCategory
                    }

                    # 11. EMPTY USER SOFTWARE KEYS
                    if ($SelectedScans -contains "EmptyUserSoftware") {
                        $SyncHash.Status = "Scanning User Software Keys..."
                        $softwareTargets = @(New-PerUserRegistryTargets -SubPath "Software" -HkcuLabel "HKCU\Software")

                        $total = [math]::Max($softwareTargets.Count, 1); $i = 0
                        foreach ($target in $softwareTargets) {
                            $i++; & $Tick "Scanning User Software: $($target.Label)" $i $total
                            try {
                                $softwareRoot = $target.BaseKey.OpenSubKey($target.SubPath)
                                if ($softwareRoot) {
                                    foreach ($appName in $softwareRoot.GetSubKeyNames()) {
                                        if (Test-IsUserSoftwareKeyExcluded $appName) { continue }

                                        $appKey = $null
                                        try {
                                            $appKey = $softwareRoot.OpenSubKey($appName)
                                            if (-not $appKey) { continue }

                                            if ($appKey.SubKeyCount -eq 0 -and $appKey.ValueCount -eq 0) {
                                                $details = "Direct child of $($target.RegPrefix) has no values and no subkeys."
                                                [void]$SyncHash.Findings.Add([PSCustomObject]@{ Problem = "Empty User Software Key"; Data = "(empty registry key)"; DisplayKey = "$appName (empty user software key)"; RegPath = "$($target.RegPrefix)\$appName"; ValueName = $null; Type = "Key"; Details = $details })
                                                continue
                                            }
                                        }
                                        catch {}
                                        finally {
                                            if ($appKey) { $appKey.Close() }
                                        }
                                    }
                                    $softwareRoot.Close()
                                }
                            }
                            catch {}
                        }
                        & $EndCategory
                    }

                    # 12. SHELL EXTENSIONS
                    if ($SelectedScans -contains "ShellExtensions") {
                        $SyncHash.Status = "Scanning Shell Extensions..."
                        $handlerRoots = @(
                            "*\shellex\ContextMenuHandlers",
                            "*\shellex\PropertySheetHandlers",
                            "AllFilesystemObjects\shellex\ContextMenuHandlers",
                            "Directory\shellex\ContextMenuHandlers",
                            "Directory\Background\shellex\ContextMenuHandlers",
                            "Directory\shellex\CopyHookHandlers",
                            "Directory\shellex\DragDropHandlers",
                            "Drive\shellex\ContextMenuHandlers",
                            "Drive\shellex\DragDropHandlers",
                            "Folder\shellex\ColumnHandlers",
                            "Folder\shellex\ContextMenuHandlers",
                            "Folder\shellex\PropertySheetHandlers",
                            "LibraryFolder\shellex\ContextMenuHandlers",
                            "lnkfile\shellex\ContextMenuHandlers",
                            "exefile\shellex\ContextMenuHandlers"
                        )

                        foreach ($view in @([Microsoft.Win32.RegistryView]::Default)) {
                            $classesRoot = $null
                            try {
                                $classesRoot = [Microsoft.Win32.RegistryKey]::OpenBaseKey([Microsoft.Win32.RegistryHive]::ClassesRoot, $view)
                                $viewLabel = Get-WmtRegistryViewLabel $view
                                $total = $handlerRoots.Count; $i = 0
                                foreach ($handlerRootPath in $handlerRoots) {
                                    $i++; & $Tick "Scanning Shell Extensions ($viewLabel): $handlerRootPath" $i $total
                                    $handlerRoot = $null
                                    try {
                                        $handlerRoot = $classesRoot.OpenSubKey($handlerRootPath, $false)
                                        if ($handlerRoot) {
                                            foreach ($handlerName in $handlerRoot.GetSubKeyNames()) {
                                                $handlerKey = $null
                                                try {
                                                    $handlerKey = $handlerRoot.OpenSubKey($handlerName, $false)
                                                    if (-not $handlerKey) { continue }

                                                    $clsid = ConvertTo-WmtClsid ([string]$handlerKey.GetValue($null))
                                                    if (-not $clsid) { $clsid = ConvertTo-WmtClsid $handlerName }
                                                    if (-not $clsid) { continue }

                                                    $issue = Get-WmtClsidReferenceIssue -Clsid $clsid -View $view
                                                    if ($issue -and $issue.IsBroken) {
                                                        [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                                                Problem    = "Invalid Shell Extension"
                                                                Data       = $issue.Data
                                                                DisplayKey = "$handlerRootPath\$handlerName ($viewLabel)"
                                                                RegPath    = (ConvertTo-WmtClassesViewPath -SubPath "$handlerRootPath\$handlerName" -View $view)
                                                                ValueName  = $null
                                                                Type       = "Key"
                                                                Details    = $issue.Details
                                                            })
                                                    }
                                                }
                                                catch {}
                                                finally {
                                                    if ($handlerKey) { $handlerKey.Close() }
                                                }
                                            }
                                        }
                                    }
                                    catch {}
                                    finally {
                                        if ($handlerRoot) { $handlerRoot.Close() }
                                    }
                                }

                                foreach ($directHandlerPath in @("exefile\shellex\IconHandler", "lnkfile\shellex\IconHandler")) {
                                    $handlerKey = $null
                                    try {
                                        $handlerKey = $classesRoot.OpenSubKey($directHandlerPath, $false)
                                        if ($handlerKey) {
                                            $clsid = ConvertTo-WmtClsid ([string]$handlerKey.GetValue($null))
                                            $issue = Get-WmtClsidReferenceIssue -Clsid $clsid -View $view
                                            if ($issue -and $issue.IsBroken) {
                                                [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                                        Problem    = "Invalid Shell Extension"
                                                        Data       = $issue.Data
                                                        DisplayKey = "$directHandlerPath ($viewLabel)"
                                                        RegPath    = (ConvertTo-WmtClassesViewPath -SubPath $directHandlerPath -View $view)
                                                        ValueName  = $null
                                                        Type       = "Key"
                                                        Details    = $issue.Details
                                                    })
                                            }
                                        }
                                    }
                                    catch {}
                                    finally {
                                        if ($handlerKey) { $handlerKey.Close() }
                                    }
                                }
                            }
                            catch {}
                            finally {
                                if ($classesRoot) { $classesRoot.Close() }
                            }
                        }
                        & $EndCategory
                    }

                    # 13. EXPLORER NAMESPACE
                    if ($SelectedScans -contains "ExplorerNamespace") {
                        $SyncHash.Status = "Scanning Explorer Namespace Entries..."
                        $namespaceTargets = New-Object System.Collections.Generic.List[object]
                        foreach ($path in @(
                                "SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\Desktop\NameSpace",
                                "SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Explorer\Desktop\NameSpace",
                                "SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\MyComputer\NameSpace",
                                "SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Explorer\MyComputer\NameSpace",
                                "SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\ControlPanel\NameSpace",
                                "SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Explorer\ControlPanel\NameSpace"
                            )) {
                            [void]$namespaceTargets.Add([PSCustomObject]@{ BaseKey = [Microsoft.Win32.Registry]::LocalMachine; SubPath = $path; RegPrefix = "HKLM:\$path"; Label = "HKLM:\$path" })
                        }
                        foreach ($userPath in @(
                                "Software\Microsoft\Windows\CurrentVersion\Explorer\Desktop\NameSpace",
                                "Software\Microsoft\Windows\CurrentVersion\Explorer\MyComputer\NameSpace",
                                "Software\Microsoft\Windows\CurrentVersion\Explorer\ControlPanel\NameSpace"
                            )) {
                            foreach ($target in @(New-PerUserRegistryTargets -SubPath $userPath -HkcuLabel "HKCU\$userPath")) {
                                [void]$namespaceTargets.Add($target)
                            }
                        }

                        $total = [math]::Max($namespaceTargets.Count, 1); $i = 0
                        foreach ($target in $namespaceTargets) {
                            $i++; & $Tick "Scanning Namespace: $($target.Label)" $i $total
                            $root = $null
                            try {
                                $root = $target.BaseKey.OpenSubKey($target.SubPath, $false)
                                if ($root) {
                                    foreach ($entry in $root.GetSubKeyNames()) {
                                        $clsid = ConvertTo-WmtClsid $entry
                                        if ($clsid -and -not (Test-WmtClsidExistsForTarget -Clsid $clsid -Target $target)) {
                                            [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                                    Problem    = "Invalid Explorer Namespace"
                                                    Data       = $clsid
                                                    DisplayKey = "$($target.Label)\$entry"
                                                    RegPath    = "$($target.RegPrefix)\$entry"
                                                    ValueName  = $null
                                                    Type       = "Key"
                                                    Details    = "Explorer namespace entry references missing CLSID $clsid."
                                                })
                                        }
                                    }
                                }
                            }
                            catch {}
                            finally {
                                if ($root) { $root.Close() }
                            }
                        }
                        & $EndCategory
                    }
                    # 14. FONT ENTRIES
                    if ($SelectedScans -contains "Fonts") {
                        $SyncHash.Status = "Scanning Font Registry Entries..."
                        $fontTargets = New-Object System.Collections.Generic.List[object]
                        [void]$fontTargets.Add([PSCustomObject]@{ BaseKey = [Microsoft.Win32.Registry]::LocalMachine; SubPath = "SOFTWARE\Microsoft\Windows NT\CurrentVersion\Fonts"; RegPrefix = "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Fonts"; Label = "Machine Fonts" })
                        foreach ($target in @(New-PerUserRegistryTargets -SubPath "Software\Microsoft\Windows NT\CurrentVersion\Fonts" -HkcuLabel "HKCU\Software\Microsoft\Windows NT\CurrentVersion\Fonts")) {
                            [void]$fontTargets.Add($target)
                        }

                        $fontDir = Join-Path $env:windir "Fonts"
                        $total = [math]::Max($fontTargets.Count, 1); $i = 0
                        foreach ($target in $fontTargets) {
                            $i++; & $Tick "Scanning Fonts: $($target.Label)" $i $total
                            $root = $null
                            try {
                                $root = $target.BaseKey.OpenSubKey($target.SubPath, $false)
                                if ($root) {
                                    foreach ($valueName in $root.GetValueNames()) {
                                        $fontValue = [string]$root.GetValue($valueName, $null, [Microsoft.Win32.RegistryValueOptions]::DoNotExpandEnvironmentNames)
                                        if ([string]::IsNullOrWhiteSpace($fontValue)) { continue }

                                        $fontPath = $fontValue.Trim('"')
                                        if ($fontPath -notmatch '^(?i)([a-z]:\\|\\\\|%[^%]+%\\)') {
                                            $fontPath = Join-Path $fontDir $fontPath
                                        }

                                        if (-not (Test-IsProtectedWindowsPath $fontPath) -and -not (Test-PathExists $fontPath)) {
                                            [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                                    Problem    = "Invalid Font Entry"
                                                    Data       = $fontPath
                                                    DisplayKey = $valueName
                                                    RegPath    = $target.RegPrefix
                                                    ValueName  = $valueName
                                                    Type       = "Value"
                                                    Details    = "Font registry value points to a missing font file."
                                                })
                                        }
                                    }
                                }
                            }
                            catch {}
                            finally {
                                if ($root) { $root.Close() }
                            }
                        }
                        & $EndCategory
                    }

                    # 15. APP EXECUTION ALIASES
                    if ($SelectedScans -contains "AppAliases") {
                        $SyncHash.Status = "Scanning App Execution Aliases..."
                        $aliasTargets = @(New-PerUserRegistryTargets -SubPath "Software\Microsoft\Windows\CurrentVersion\App Paths" -HkcuLabel "HKCU\Software\Microsoft\Windows\CurrentVersion\App Paths")

                        $total = [math]::Max($aliasTargets.Count, 1); $i = 0
                        foreach ($target in $aliasTargets) {
                            $i++; & $Tick "Scanning App Aliases: $($target.Label)" $i $total
                            $root = $null
                            try {
                                $root = $target.BaseKey.OpenSubKey($target.SubPath, $false)
                                if ($root) {
                                    foreach ($aliasName in $root.GetSubKeyNames()) {
                                        $aliasKey = $null
                                        try {
                                            $aliasKey = $root.OpenSubKey($aliasName, $false)
                                            if (-not $aliasKey) { continue }

                                            $rawTarget = [string]$aliasKey.GetValue($null)
                                            $targetPath = Get-ServiceImageExecutablePath $rawTarget
                                            if ($targetPath -and -not (Test-IsWhitelisted $targetPath) -and -not (Test-IsProtectedWindowsPath $targetPath) -and -not (Test-PathExists $targetPath)) {
                                                [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                                        Problem    = "Invalid App Execution Alias"
                                                        Data       = $targetPath
                                                        DisplayKey = $aliasName
                                                        RegPath    = "$($target.RegPrefix)\$aliasName"
                                                        ValueName  = $null
                                                        Type       = "Key"
                                                        Details    = "Per-user App Paths alias target is missing."
                                                    })
                                            }
                                        }
                                        catch {}
                                        finally {
                                            if ($aliasKey) { $aliasKey.Close() }
                                        }
                                    }
                                }
                            }
                            catch {}
                            finally {
                                if ($root) { $root.Close() }
                            }
                        }
                        & $EndCategory
                    }

                    # 16. SCHEDULED TASK CACHE
                    if ($SelectedScans -contains "TaskCache") {
                        $SyncHash.Status = "Scanning Scheduled Task Cache..."
                        $treePath = "SOFTWARE\Microsoft\Windows NT\CurrentVersion\Schedule\TaskCache\Tree"
                        $tasksPath = "SOFTWARE\Microsoft\Windows NT\CurrentVersion\Schedule\TaskCache\Tasks"
                        $treeRoot = $null; $tasksRoot = $null
                        try {
                            $treeRoot = [Microsoft.Win32.Registry]::LocalMachine.OpenSubKey($treePath, $false)
                            $tasksRoot = [Microsoft.Win32.Registry]::LocalMachine.OpenSubKey($tasksPath, $false)
                            if ($treeRoot -and $tasksRoot) {
                                $treeEntries = @(Get-WmtTaskTreeEntries -Key $treeRoot -RelativePath "")
                                $treeIds = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
                                foreach ($entry in $treeEntries) {
                                    if (-not [string]::IsNullOrWhiteSpace([string]$entry.Id)) { [void]$treeIds.Add([string]$entry.Id) }
                                }

                                $taskIds = @()
                                $taskIdsSet = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
                                $canEnumerateTaskIds = $false
                                try {
                                    $taskIds = @($tasksRoot.GetSubKeyNames())
                                    foreach ($taskId in $taskIds) { [void]$taskIdsSet.Add($taskId) }
                                    $canEnumerateTaskIds = $true
                                }
                                catch {
                                    $canEnumerateTaskIds = $false
                                }

                                $total = [math]::Max($treeEntries.Count, 1); $i = 0
                                foreach ($entry in $treeEntries) {
                                    $i++; & $Tick "Scanning TaskCache Tree: $($entry.RelativePath)" $i $total
                                    if (Test-WmtProtectedSystemTaskPath $entry.RelativePath) { continue }

                                    $taskFile = Get-WmtTaskFilePath $entry.RelativePath
                                    $taskGuidState = if ($canEnumerateTaskIds) {
                                        if ($taskIdsSet.Contains([string]$entry.Id)) { "Exists" } else { "Missing" }
                                    }
                                    else {
                                        "Unknown"
                                    }
                                    $registeredTaskState = Get-WmtScheduledTaskState $entry.RelativePath
                                    $taskFileState = Get-WmtPathState -Path $taskFile -PathType "Leaf"

                                    if ($taskGuidState -eq "Missing" -and $registeredTaskState -eq "Missing" -and $taskFileState -eq "Missing") {
                                        [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                                Problem    = "Orphaned TaskCache Tree Entry"
                                                Data       = $taskFile
                                                DisplayKey = $entry.RelativePath
                                                RegPath    = "HKLM:\$treePath\$($entry.RelativePath)"
                                                ValueName  = $null
                                                Type       = "Key"
                                                Details    = "TaskCache Tree entry has no matching Tasks GUID key, Task Scheduler cannot find the task, and the task file is definitely missing."
                                            })
                                    }
                                }

                                $total = [math]::Max($taskIds.Count, 1); $i = 0
                                foreach ($taskId in $taskIds) {
                                    $i++; & $Tick "Scanning TaskCache Tasks: $taskId" $i $total
                                    $taskKey = $null
                                    try {
                                        $taskKey = $tasksRoot.OpenSubKey($taskId, $false)
                                        if (-not $taskKey) { continue }

                                        $taskPathValue = [string]$taskKey.GetValue("Path")
                                        if ([string]::IsNullOrWhiteSpace($taskPathValue)) { continue }
                                        if (Test-WmtProtectedSystemTaskPath $taskPathValue) { continue }

                                        $taskFile = Get-WmtTaskFilePath $taskPathValue
                                        $registeredTaskState = Get-WmtScheduledTaskState $taskPathValue
                                        $taskFileState = Get-WmtPathState -Path $taskFile -PathType "Leaf"
                                        $treeGuidState = if ($treeIds.Contains($taskId)) { "Exists" } else { "Missing" }

                                        if ($treeGuidState -eq "Missing" -and $registeredTaskState -eq "Missing" -and $taskFileState -eq "Missing") {
                                            [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                                    Problem    = "Orphaned TaskCache Task Entry"
                                                    Data       = $taskFile
                                                    DisplayKey = $taskPathValue
                                                    RegPath    = "HKLM:\$tasksPath\$taskId"
                                                    ValueName  = $null
                                                    Type       = "Key"
                                                    Details    = "TaskCache Tasks GUID key has no matching Tree entry, Task Scheduler cannot find the task, and the task file is definitely missing."
                                                })
                                        }
                                    }
                                    catch {}
                                    finally {
                                        if ($taskKey) { $taskKey.Close() }
                                    }
                                }
                            }
                        }
                        catch {}
                        finally {
                            if ($treeRoot) { $treeRoot.Close() }
                            if ($tasksRoot) { $tasksRoot.Close() }
                        }
                        & $EndCategory
                    }

                    # 16B. SCHEDULED TASK ACTIONS
                    if ($SelectedScans -contains "TaskActions") {
                        $SyncHash.Status = "Scanning Scheduled Task Actions..."
                        $taskRootPath = Join-Path (Join-Path $env:windir "System32") "Tasks"
                        $taskFiles = [System.Collections.Generic.List[string]]::new()
                        if ([System.IO.Directory]::Exists($taskRootPath)) {
                            $pendingDirs = [System.Collections.Generic.Stack[string]]::new()
                            $pendingDirs.Push($taskRootPath)
                            while ($pendingDirs.Count -gt 0) {
                                $dir = $pendingDirs.Pop()
                                try {
                                    foreach ($file in [System.IO.Directory]::EnumerateFiles($dir, "*", [System.IO.SearchOption]::TopDirectoryOnly)) {
                                        [void]$taskFiles.Add($file)
                                    }
                                }
                                catch {}
                                try {
                                    foreach ($childDir in [System.IO.Directory]::EnumerateDirectories($dir, "*", [System.IO.SearchOption]::TopDirectoryOnly)) {
                                        [void]$pendingDirs.Push($childDir)
                                    }
                                }
                                catch {}
                            }
                        }

                        $total = [math]::Max($taskFiles.Count, 1); $i = 0
                        foreach ($taskFile in $taskFiles) {
                            $i++; & $Tick "Scanning Task Action: $taskFile" $i $total
                            $relativeTask = $taskFile.Substring($taskRootPath.Length).TrimStart('\')
                            if (Test-WmtProtectedSystemTaskPath $relativeTask) { continue }

                            try {
                                [xml]$taskXml = Get-Content -LiteralPath $taskFile -Raw -ErrorAction Stop
                                $execNodes = $taskXml.SelectNodes("//*[local-name()='Exec']")
                                foreach ($execNode in $execNodes) {
                                    $commandNode = $execNode.SelectSingleNode("*[local-name()='Command']")
                                    if (-not $commandNode) { continue }

                                    $command = [string]$commandNode.InnerText
                                    $commandPath = Get-ServiceImageExecutablePath $command
                                    if ([string]::IsNullOrWhiteSpace($commandPath)) { continue }
                                    if (Test-IsWhitelisted $commandPath) { continue }
                                    if (Test-IsProtectedWindowsPath $commandPath) { continue }
                                    if (Test-PathExists $commandPath) { continue }

                                    $argumentNode = $execNode.SelectSingleNode("*[local-name()='Arguments']")
                                    $argumentText = if ($argumentNode) { [string]$argumentNode.InnerText } else { "" }
                                    [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                            Problem    = "Broken Scheduled Task Action"
                                            Data       = $commandPath
                                            DisplayKey = "\$relativeTask"
                                            RegPath    = $taskFile
                                            ValueName  = $null
                                            Type       = "ReviewOnly"
                                            SafeToFix  = $false
                                            Risk       = "Review"
                                            Confidence = "High"
                                            Details    = "Scheduled task Exec action points to a missing command. Command: $command Arguments: $argumentText. Review or edit the task in Task Scheduler."
                                        })
                                }
                            }
                            catch {}
                        }
                        & $EndCategory
                    }

                    # 17. UNINSTALL METADATA VALUES
                    if ($SelectedScans -contains "UninstallMetadata") {
                        $SyncHash.Status = "Scanning Uninstall Metadata..."
                        $uninstallTargets = New-Object System.Collections.Generic.List[object]
                        $uninstallPath = "SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall"
                        foreach ($view in @(Get-WmtRegistryViews)) {
                            try {
                                $baseKey = [Microsoft.Win32.RegistryKey]::OpenBaseKey([Microsoft.Win32.RegistryHive]::LocalMachine, $view)
                                [void]$uninstallTargets.Add([PSCustomObject]@{ BaseKey = $baseKey; SubPath = $uninstallPath; RegPrefix = (ConvertTo-WmtHklmViewPath -SubPath $uninstallPath -View $view); Label = "HKLM $(Get-WmtRegistryViewLabel $view)"; OwnsBaseKey = $true })
                            }
                            catch {}
                        }
                        foreach ($target in @(New-PerUserRegistryTargets -SubPath "Software\Microsoft\Windows\CurrentVersion\Uninstall" -HkcuLabel "HKCU\Software\Microsoft\Windows\CurrentVersion\Uninstall")) {
                            [void]$uninstallTargets.Add([PSCustomObject]@{ BaseKey = $target.BaseKey; SubPath = $target.SubPath; RegPrefix = $target.RegPrefix; Label = $target.Label; OwnsBaseKey = $false })
                        }

                        $metadataValues = @("DisplayIcon", "InstallLocation", "InstallSource", "ModifyPath", "QuietUninstallString", "Readme", "HelpLink", "URLInfoAbout")
                        $total = [math]::Max($uninstallTargets.Count, 1); $i = 0
                        foreach ($target in $uninstallTargets) {
                            $i++; & $Tick "Scanning Uninstall Metadata: $($target.Label)" $i $total
                            $root = $null
                            try {
                                $root = $target.BaseKey.OpenSubKey($target.SubPath, $false)
                                if ($root) {
                                    foreach ($appKeyName in $root.GetSubKeyNames()) {
                                        $appKey = $null
                                        try {
                                            $appKey = $root.OpenSubKey($appKeyName, $false)
                                            if (-not $appKey) { continue }

                                            $displayName = [string]$appKey.GetValue("DisplayName")
                                            if ([string]::IsNullOrWhiteSpace($displayName)) { $displayName = $appKeyName }

                                            foreach ($valueName in $metadataValues) {
                                                $rawValue = [string]$appKey.GetValue($valueName, $null, [Microsoft.Win32.RegistryValueOptions]::DoNotExpandEnvironmentNames)
                                                if ([string]::IsNullOrWhiteSpace($rawValue)) { continue }
                                                if ($rawValue -match '^(?i)(https?|mailto):') { continue }

                                                $candidate = if ($valueName -eq "ModifyPath" -or $valueName -eq "QuietUninstallString") { Get-ServiceImageExecutablePath $rawValue } elseif ($valueName -eq "DisplayIcon") { Get-RealExePath $rawValue } else { [Environment]::ExpandEnvironmentVariables($rawValue.Trim('"')) }
                                                if ([string]::IsNullOrWhiteSpace($candidate)) { continue }
                                                if ($candidate -notmatch '^(?i)([a-z]:\\|\\\\)') { continue }
                                                if (Test-IsWhitelisted $candidate) { continue }
                                                if (Test-IsProtectedWindowsPath $candidate) { continue }
                                                if (Test-PathExists $candidate) { continue }

                                                $isCommandMetadata = ($valueName -eq "ModifyPath" -or $valueName -eq "QuietUninstallString")

                                                [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                                        Problem    = "Invalid Uninstall Metadata"
                                                        Data       = $candidate
                                                        DisplayKey = "$displayName [$valueName]"
                                                        RegPath    = "$($target.RegPrefix)\$appKeyName"
                                                        ValueName  = $valueName
                                                        Type       = "Value"
                                                        SafeToFix  = (-not $isCommandMetadata)
                                                        Risk       = if ($isCommandMetadata) { "Review" } else { "Low" }
                                                        Confidence = "High"
                                                        Details    = if ($isCommandMetadata) { "Uninstall command metadata points to a missing executable. Review before deleting because the app may still be installed." } else { "Uninstall metadata value points to a missing local path. Cleanup deletes only this value, not the uninstall key." }
                                                    })
                                            }
                                        }
                                        catch {}
                                        finally {
                                            if ($appKey) { $appKey.Close() }
                                        }
                                    }
                                }
                            }
                            catch {}
                            finally {
                                if ($root) { $root.Close() }
                                if ($target.OwnsBaseKey -and $target.BaseKey) { $target.BaseKey.Close() }
                            }
                        }
                        & $EndCategory
                    }

                    # 18. ENVIRONMENT PATH ENTRIES
                    if ($SelectedScans -contains "EnvPath") {
                        $SyncHash.Status = "Scanning Environment PATH Entries..."
                        $envTargets = New-Object System.Collections.Generic.List[object]
                        [void]$envTargets.Add([PSCustomObject]@{ BaseKey = [Microsoft.Win32.Registry]::LocalMachine; SubPath = "SYSTEM\CurrentControlSet\Control\Session Manager\Environment"; RegPrefix = "HKLM:\SYSTEM\CurrentControlSet\Control\Session Manager\Environment"; Label = "Machine PATH" })
                        foreach ($target in @(New-PerUserRegistryTargets -SubPath "Environment" -HkcuLabel "HKCU\Environment")) {
                            [void]$envTargets.Add([PSCustomObject]@{ BaseKey = $target.BaseKey; SubPath = $target.SubPath; RegPrefix = $target.RegPrefix; Label = "$($target.Label) PATH" })
                        }

                        $total = [math]::Max($envTargets.Count, 1); $i = 0
                        foreach ($target in $envTargets) {
                            $i++; & $Tick "Scanning PATH: $($target.Label)" $i $total
                            $root = $null
                            try {
                                $root = $target.BaseKey.OpenSubKey($target.SubPath, $false)
                                if ($root) {
                                    $pathValue = [string]$root.GetValue("Path", $null, [Microsoft.Win32.RegistryValueOptions]::DoNotExpandEnvironmentNames)
                                    $missingSegments = @(Get-WmtMissingPathSegments $pathValue)
                                    if ($missingSegments.Count -gt 0) {
                                        $newPath = Get-WmtCleanedPathValue -PathValue $pathValue -MissingSegments $missingSegments
                                        $data = $missingSegments[0]
                                        if ($missingSegments.Count -gt 1) { $data = "$data ($($missingSegments.Count) missing PATH entries)" }
                                        [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                                Problem    = "Invalid PATH Entry"
                                                Data       = $data
                                                DisplayKey = $target.Label
                                                RegPath    = $target.RegPrefix
                                                ValueName  = "Path"
                                                Type       = "SetValue"
                                                NewData    = $newPath
                                                Details    = "Rewrites PATH after removing missing segment(s): $($missingSegments -join '; ')"
                                            })
                                    }
                                }
                            }
                            catch {}
                            finally {
                                if ($root) { $root.Close() }
                            }
                        }
                        & $EndCategory
                    }

                    # 19. PER-USER SHELL COMMANDS
                    if ($SelectedScans -contains "UserShellCommands") {
                        $SyncHash.Status = "Scanning Per-User Shell Commands..."
                        $classTargets = @(New-PerUserRegistryTargets -SubPath "Software\Classes" -HkcuLabel "HKCU\Software\Classes")

                        $total = [math]::Max($classTargets.Count, 1); $i = 0
                        foreach ($target in $classTargets) {
                            $i++; & $Tick "Scanning User Shell Commands: $($target.Label)" $i $total
                            $root = $null
                            try {
                                $root = $target.BaseKey.OpenSubKey($target.SubPath, $false)
                                if ($root) {
                                    foreach ($className in $root.GetSubKeyNames()) {
                                        $classKey = $null
                                        try {
                                            $classKey = $root.OpenSubKey($className, $false)
                                            if (-not $classKey) { continue }

                                            $shellKey = $classKey.OpenSubKey("shell", $false)
                                            if ($shellKey) {
                                                foreach ($verb in $shellKey.GetSubKeyNames()) {
                                                    $cmdKey = $null
                                                    try {
                                                        $cmdKey = $shellKey.OpenSubKey("$verb\command", $false)
                                                        if (-not $cmdKey) { continue }

                                                        $cmd = [string]$cmdKey.GetValue($null)
                                                        $clean = Get-ServiceImageExecutablePath $cmd
                                                        if ($clean -and -not (Test-IsWhitelisted $clean) -and -not (Test-IsProtectedWindowsPath $clean) -and -not (Test-PathExists $clean)) {
                                                            [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                                                    Problem    = "Invalid User Shell Command"
                                                                    Data       = $clean
                                                                    DisplayKey = "$className\$verb"
                                                                    RegPath    = "$($target.RegPrefix)\$className\shell\$verb\command"
                                                                    ValueName  = $null
                                                                    Type       = "Key"
                                                                    Details    = "Per-user file association command points to a missing executable."
                                                                })
                                                        }
                                                    }
                                                    catch {}
                                                    finally {
                                                        if ($cmdKey) { $cmdKey.Close() }
                                                    }
                                                }
                                                $shellKey.Close()
                                            }
                                        }
                                        catch {}
                                        finally {
                                            if ($classKey) { $classKey.Close() }
                                        }
                                    }
                                }
                            }
                            catch {}
                            finally {
                                if ($root) { $root.Close() }
                            }
                        }
                        & $EndCategory
                    }

                    # 19B. IMAGE FILE EXECUTION OPTIONS
                    if ($SelectedScans -contains "IFEO") {
                        $SyncHash.Status = "Scanning Image File Execution Options..."
                        $ifeoPath = "SOFTWARE\Microsoft\Windows NT\CurrentVersion\Image File Execution Options"
                        $silentPath = "SOFTWARE\Microsoft\Windows NT\CurrentVersion\SilentProcessExit"

                        foreach ($view in @(Get-WmtRegistryViews)) {
                            $baseKey = $null; $ifeoRoot = $null; $silentRoot = $null
                            try {
                                $baseKey = [Microsoft.Win32.RegistryKey]::OpenBaseKey([Microsoft.Win32.RegistryHive]::LocalMachine, $view)
                                $viewLabel = Get-WmtRegistryViewLabel $view

                                $ifeoRoot = $baseKey.OpenSubKey($ifeoPath, $false)
                                if ($ifeoRoot) {
                                    $names = $ifeoRoot.GetSubKeyNames(); $total = [math]::Max($names.Count, 1); $i = 0
                                    foreach ($imageName in $names) {
                                        $i++; & $Tick "Scanning IFEO ($viewLabel): $imageName" $i $total
                                        $imageKey = $null
                                        try {
                                            $imageKey = $ifeoRoot.OpenSubKey($imageName, $false)
                                            if (-not $imageKey) { continue }

                                            $debugger = [string]$imageKey.GetValue("Debugger", $null, [Microsoft.Win32.RegistryValueOptions]::DoNotExpandEnvironmentNames)
                                            $debuggerPath = Get-ServiceImageExecutablePath $debugger
                                            if ($debuggerPath -and -not (Test-IsWhitelisted $debuggerPath) -and -not (Test-IsProtectedWindowsPath $debuggerPath) -and -not (Test-PathExists $debuggerPath)) {
                                                [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                                        Problem    = "Invalid IFEO Debugger"
                                                        Data       = $debuggerPath
                                                        DisplayKey = "$imageName ($viewLabel)"
                                                        RegPath    = "$(ConvertTo-WmtHklmViewPath -SubPath $ifeoPath -View $view)\$imageName"
                                                        ValueName  = "Debugger"
                                                        Type       = "Value"
                                                        SafeToFix  = $false
                                                        Risk       = "Review"
                                                        Confidence = "Medium"
                                                        Details    = "Image File Execution Options Debugger points to a missing executable. Review before deleting because IFEO can be intentionally configured."
                                                    })
                                            }

                                            $verifierDlls = [string]$imageKey.GetValue("VerifierDlls", $null, [Microsoft.Win32.RegistryValueOptions]::DoNotExpandEnvironmentNames)
                                            foreach ($dllPath in @($verifierDlls -split ';')) {
                                                $candidate = Get-RealExePath $dllPath
                                                if ($candidate -and $candidate -match '^(?i)([a-z]:\\|\\\\)' -and -not (Test-IsWhitelisted $candidate) -and -not (Test-IsProtectedWindowsPath $candidate) -and -not (Test-PathExists $candidate)) {
                                                    [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                                            Problem    = "Invalid IFEO Verifier DLL"
                                                            Data       = $candidate
                                                            DisplayKey = "$imageName ($viewLabel)"
                                                            RegPath    = "$(ConvertTo-WmtHklmViewPath -SubPath $ifeoPath -View $view)\$imageName"
                                                            ValueName  = "VerifierDlls"
                                                            Type       = "Value"
                                                            SafeToFix  = $false
                                                            Risk       = "Review"
                                                            Confidence = "Medium"
                                                            Details    = "IFEO VerifierDlls references a missing DLL. Review before deleting because verifier settings can be intentional."
                                                        })
                                                }
                                            }
                                        }
                                        catch {}
                                        finally {
                                            if ($imageKey) { $imageKey.Close() }
                                        }
                                    }
                                }

                                $silentRoot = $baseKey.OpenSubKey($silentPath, $false)
                                if ($silentRoot) {
                                    $names = $silentRoot.GetSubKeyNames(); $total = [math]::Max($names.Count, 1); $i = 0
                                    foreach ($imageName in $names) {
                                        $i++; & $Tick "Scanning SilentProcessExit ($viewLabel): $imageName" $i $total
                                        $imageKey = $null
                                        try {
                                            $imageKey = $silentRoot.OpenSubKey($imageName, $false)
                                            if (-not $imageKey) { continue }

                                            $monitor = [string]$imageKey.GetValue("MonitorProcess", $null, [Microsoft.Win32.RegistryValueOptions]::DoNotExpandEnvironmentNames)
                                            $monitorPath = Get-ServiceImageExecutablePath $monitor
                                            if ($monitorPath -and -not (Test-IsWhitelisted $monitorPath) -and -not (Test-IsProtectedWindowsPath $monitorPath) -and -not (Test-PathExists $monitorPath)) {
                                                [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                                        Problem    = "Invalid SilentProcessExit Monitor"
                                                        Data       = $monitorPath
                                                        DisplayKey = "$imageName ($viewLabel)"
                                                        RegPath    = "$(ConvertTo-WmtHklmViewPath -SubPath $silentPath -View $view)\$imageName"
                                                        ValueName  = "MonitorProcess"
                                                        Type       = "Value"
                                                        SafeToFix  = $false
                                                        Risk       = "Review"
                                                        Confidence = "Medium"
                                                        Details    = "SilentProcessExit monitor points to a missing executable. Review before deleting because process-monitor settings can be intentional."
                                                    })
                                            }
                                        }
                                        catch {}
                                        finally {
                                            if ($imageKey) { $imageKey.Close() }
                                        }
                                    }
                                }
                            }
                            catch {}
                            finally {
                                if ($ifeoRoot) { $ifeoRoot.Close() }
                                if ($silentRoot) { $silentRoot.Close() }
                                if ($baseKey) { $baseKey.Close() }
                            }
                        }
                        & $EndCategory
                    }

                    # 20. FIREWALL
                    if ($SelectedScans -contains "Firewall") {
                        $SyncHash.Status = "Scanning Firewall Rules..."
                        $key = "SYSTEM\CurrentControlSet\Services\SharedAccess\Parameters\FirewallPolicy\FirewallRules"
                        $root = [Microsoft.Win32.Registry]::LocalMachine.OpenSubKey($key)
                        if ($root) {
                            $names = $root.GetValueNames(); $total = $names.Count; $i = 0
                            foreach ($valName in $names) {
                                $i++; & $Tick "Scanning Firewall: $valName" $i $total
                                $data = $root.GetValue($valName)
                                if ($data -match "App=([^|]+)") {
                                    $appPath = $matches[1]; $expanded = [Environment]::ExpandEnvironmentVariables($appPath)
                                    if ($expanded -match '^[a-zA-Z]:\\' -and -not (Test-IsWhitelisted $expanded)) {
                                        if (-not (Test-IsProtectedWindowsPath $expanded) -and -not (Test-PathExists $expanded)) { [void]$SyncHash.Findings.Add([PSCustomObject]@{ Problem = "Invalid Firewall Rule"; Data = $expanded; DisplayKey = $valName; RegPath = "HKLM:\$key"; ValueName = $valName; Type = "Value" }) }
                                    }
                                }
                            }
                            $root.Close()
                        }
                        & $EndCategory
                    }

                    # 13. SERVICES
                    if ($SelectedScans -contains "Services") {
                        $SyncHash.Status = "Scanning Services..."
                        $serviceRoots = New-Object System.Collections.Generic.List[string]
                        try {
                            $systemRoot = [Microsoft.Win32.Registry]::LocalMachine.OpenSubKey("SYSTEM")
                            if ($systemRoot) {
                                foreach ($controlSet in $systemRoot.GetSubKeyNames()) {
                                    if ($controlSet -match '^ControlSet\d{3}$') {
                                        [void]$serviceRoots.Add("SYSTEM\$controlSet\Services")
                                    }
                                }
                                $systemRoot.Close()
                            }
                        }
                        catch {}
                        if ($serviceRoots.Count -eq 0) { [void]$serviceRoots.Add("SYSTEM\CurrentControlSet\Services") }

                        foreach ($key in $serviceRoots) {
                            $root = [Microsoft.Win32.Registry]::LocalMachine.OpenSubKey($key)
                            if ($root) {
                                $names = $root.GetSubKeyNames(); $total = $names.Count; $i = 0
                                foreach ($svc in $names) {
                                    $i++; & $Tick "Scanning Service: $svc" $i $total
                                    try {
                                        $sub = $root.OpenSubKey($svc)
                                        $img = [string]$sub.GetValue("ImagePath")
                                        if ($img -and $img -notmatch "\\drivers\\") {
                                            $clean = Get-ServiceImageExecutablePath $img
                                            if ($clean -and -not (Test-IsWhitelisted $clean) -and -not (Test-IsProtectedWindowsPath $clean) -and -not (Test-PathExists $clean)) {
                                                [void]$SyncHash.Findings.Add([PSCustomObject]@{ Problem = "Orphaned Service"; Data = $clean; DisplayKey = "$key\$svc"; RegPath = "HKLM:\$key\$svc"; ValueName = $null; Type = "Key" })
                                            }
                                        }
                                        $sub.Close()
                                    }
                                    catch {}
                                }
                                $root.Close()
                            }
                        }
                        & $EndCategory
                    }

                    # 12. TYPE LIBRARIES
                    if ($SelectedScans -contains "TypeLib") {
                        $SyncHash.Status = "Scanning Type Libraries..."
                        foreach ($view in @(Get-WmtRegistryViews)) {
                            $root = $null; $tlKey = $null
                            try {
                                $root = [Microsoft.Win32.RegistryKey]::OpenBaseKey([Microsoft.Win32.RegistryHive]::ClassesRoot, $view)
                                $tlKey = $root.OpenSubKey("TypeLib", $false)
                                if ($tlKey) {
                                    $viewLabel = Get-WmtRegistryViewLabel $view
                                    $names = @($tlKey.GetSubKeyNames()); $total = [math]::Max($names.Count, 1); $i = 0
                                    foreach ($guid in $names) {
                                        $i++; & $Tick "Scanning TypeLib ($viewLabel): $guid" $i $total
                                        try {
                                            $verKey = $tlKey.OpenSubKey($guid)
                                            if ($verKey) {
                                                foreach ($ver in @($verKey.GetSubKeyNames())) {
                                                    $numKey = $null
                                                    try {
                                                        $numKey = $verKey.OpenSubKey($ver)
                                                        if (-not $numKey) { continue }

                                                        $helpDirValue = $numKey.GetValue("HELPDIR", $null, [Microsoft.Win32.RegistryValueOptions]::DoNotExpandEnvironmentNames)
                                                        $missingHelpDir = Get-WmtMissingRegistryPathTarget -RawValue $helpDirValue -RegistryView $view
                                                        if ($missingHelpDir) {
                                                            [void]$SyncHash.Findings.Add([PSCustomObject]@{ Problem = "Missing HelpDir"; Data = $missingHelpDir; DisplayKey = "$guid\$ver ($viewLabel)"; RegPath = (ConvertTo-WmtClassesViewPath -SubPath "TypeLib\$guid\$ver" -View $view); ValueName = "HELPDIR"; Type = "Value"; Details = "Type library HELPDIR value points to a missing path in the $viewLabel registry view." })
                                                        }

                                                        $helpKey = $null
                                                        try {
                                                            $helpKey = $numKey.OpenSubKey("HELPDIR", $false)
                                                            if ($helpKey) {
                                                                $helpDir = $helpKey.GetValue($null, $null, [Microsoft.Win32.RegistryValueOptions]::DoNotExpandEnvironmentNames)
                                                                $missingHelpDir = Get-WmtMissingRegistryPathTarget -RawValue $helpDir -RegistryView $view
                                                                if ($missingHelpDir) {
                                                                    [void]$SyncHash.Findings.Add([PSCustomObject]@{ Problem = "Missing HelpDir"; Data = $missingHelpDir; DisplayKey = "$guid\$ver\HELPDIR ($viewLabel)"; RegPath = (ConvertTo-WmtClassesViewPath -SubPath "TypeLib\$guid\$ver\HELPDIR" -View $view); ValueName = $null; Type = "Key"; Details = "Type library HELPDIR default path points to a missing path in the $viewLabel registry view." })
                                                                }
                                                            }
                                                        }
                                                        catch {}
                                                        finally {
                                                            if ($helpKey) { $helpKey.Close() }
                                                        }

                                                        foreach ($locale in @($numKey.GetSubKeyNames())) {
                                                            if ($locale -ieq "HELPDIR") { continue }

                                                            $localeKey = $null
                                                            try {
                                                                $localeKey = $numKey.OpenSubKey($locale, $false)
                                                                if (-not $localeKey) { continue }

                                                                foreach ($platform in @($localeKey.GetSubKeyNames())) {
                                                                    if ($platform -notmatch '^(?i)win') { continue }

                                                                    $platformKey = $null
                                                                    try {
                                                                        $platformKey = $localeKey.OpenSubKey($platform, $false)
                                                                        if (-not $platformKey) { continue }

                                                                        $typeLibPath = $platformKey.GetValue($null, $null, [Microsoft.Win32.RegistryValueOptions]::DoNotExpandEnvironmentNames)
                                                                        $missingTypeLibPath = Get-WmtMissingRegistryPathTarget -RawValue $typeLibPath -RegistryView $view
                                                                        if ($missingTypeLibPath) {
                                                                            [void]$SyncHash.Findings.Add([PSCustomObject]@{ Problem = "Missing TypeLib Path"; Data = $missingTypeLibPath; DisplayKey = "$guid\$ver\$locale\$platform ($viewLabel)"; RegPath = (ConvertTo-WmtClassesViewPath -SubPath "TypeLib\$guid\$ver\$locale\$platform" -View $view); ValueName = $null; Type = "Key"; Details = "Type library $platform default path points to a missing file or folder in the $viewLabel registry view." })
                                                                        }
                                                                    }
                                                                    catch {}
                                                                    finally {
                                                                        if ($platformKey) { $platformKey.Close() }
                                                                    }
                                                                }
                                                            }
                                                            catch {}
                                                            finally {
                                                                if ($localeKey) { $localeKey.Close() }
                                                            }
                                                        }
                                                    }
                                                    catch {}
                                                    finally {
                                                        if ($numKey) { $numKey.Close() }
                                                    }
                                                }
                                                $verKey.Close()
                                            }
                                        }
                                        catch {}
                                    }
                                }
                            }
                            catch {}
                            finally {
                                if ($tlKey) { $tlKey.Close() }
                                if ($root) { $root.Close() }
                            }
                        }
                        & $EndCategory
                    }

                    # 13. DEFAULT ICONS
                    if ($SelectedScans -contains "Icons") {
                        $SyncHash.Status = "Scanning Default Icons..."
                        foreach ($view in @([Microsoft.Win32.RegistryView]::Default)) {
                            $root = $null
                            try {
                                $root = [Microsoft.Win32.RegistryKey]::OpenBaseKey([Microsoft.Win32.RegistryHive]::ClassesRoot, $view)
                                $viewLabel = Get-WmtRegistryViewLabel $view
                                $names = $root.GetSubKeyNames(); $total = $names.Count; $i = 0
                                foreach ($ext in $names) {
                                    $i++; & $Tick "Scanning Icon ($viewLabel): $ext" $i $total
                                    try {
                                        $iconKey = $root.OpenSubKey("$ext\DefaultIcon")
                                        if ($iconKey) {
                                            $val = $iconKey.GetValue($null)
                                            if ($val) {
                                                $cleanPath = Get-RealExePath $val
                                                if ($cleanPath -match '^[a-zA-Z]:\\' -and -not (Test-IsWhitelisted $cleanPath) -and -not (Test-IsProtectedWindowsPath $cleanPath) -and -not (Test-PathExists $cleanPath) -and $cleanPath -notmatch "%1") {
                                                    [void]$SyncHash.Findings.Add([PSCustomObject]@{ Problem = "Invalid Default Icon"; Data = $cleanPath; DisplayKey = "$ext ($viewLabel)"; RegPath = (ConvertTo-WmtClassesViewPath -SubPath "$ext\DefaultIcon" -View $view); ValueName = $null; Type = "Key"; Details = "DefaultIcon path is missing in the $viewLabel registry view." })
                                                }
                                            }
                                            $iconKey.Close()
                                        }
                                    }
                                    catch {}
                                }
                            }
                            catch {}
                            finally {
                                if ($root) { $root.Close() }
                            }
                        }
                        & $EndCategory
                    }

                    # 14. SHARED DLLs
                    if ($SelectedScans -contains "SharedDLLs") { 
                        $SyncHash.Status = "Scanning Shared DLLs..."
                        $key = "SOFTWARE\Microsoft\Windows\CurrentVersion\SharedDlls"
                        foreach ($view in @(Get-WmtRegistryViews)) {
                            $baseKey = $null; $rk = $null
                            try {
                                $baseKey = [Microsoft.Win32.RegistryKey]::OpenBaseKey([Microsoft.Win32.RegistryHive]::LocalMachine, $view)
                                $rk = $baseKey.OpenSubKey($key)
                                if ($rk) {
                                    $viewLabel = Get-WmtRegistryViewLabel $view
                                    $names = $rk.GetValueNames(); $total = $names.Count; $i = 0
                                    foreach ($val in $names) {
                                        $i++; & $Tick "Scanning DLL ($viewLabel): $val" $i $total
                                        if ($val -match '^[a-zA-Z]:\\' -and -not (Test-IsProtectedWindowsPath $val) -and -not(Test-PathExists -Path $val -RegistryView $view)) { [void]$SyncHash.Findings.Add([PSCustomObject]@{ Problem = "Missing Shared Ref"; Data = $val; DisplayKey = "SharedDlls ($viewLabel)"; RegPath = (ConvertTo-WmtHklmViewPath -SubPath $key -View $view); ValueName = $val; Type = "Value"; Details = "SharedDlls value points to a missing path in the $viewLabel registry view." }) }
                                    }
                                }
                            }
                            catch {}
                            finally {
                                if ($rk) { $rk.Close() }
                                if ($baseKey) { $baseKey.Close() }
                            }
                        }
                        & $EndCategory
                    }

                    # 15. STARTUP
                    if ($SelectedScans -contains "Startup") { 
                        $SyncHash.Status = "Scanning Startup Items..."
                        $paths = @("HKCU:\Software\Microsoft\Windows\CurrentVersion\Run", "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Run", "HKLM:\SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Run")
                        foreach ($p in $paths) { 
                            if (Test-Path $p) { 
                                $props = Get-ItemProperty $p
                                $names = $props.PSObject.Properties.Name; $total = $names.Count; $i = 0
                                foreach ($n in $names) { 
                                    $i++; & $Tick "Scanning Startup: $n" $i $total
                                    $v = $props.$n
                                    if ($v -is [string] -and $v -match '^[a-zA-Z]:\\') { 
                                        $cleanExe = Get-RealExePath $v
                                        if (-not (Test-IsProtectedWindowsPath $cleanExe) -and -not (Test-PathExists $cleanExe)) { [void]$SyncHash.Findings.Add([PSCustomObject]@{ Problem = "Broken Startup"; Data = $cleanExe; DisplayKey = $n; RegPath = $p; ValueName = $n; Type = "Value" }) } 
                                    } 
                                } 
                            } 
                        } 
                        & $EndCategory
                    }

                    # 15B. RUNONCE AND POLICY STARTUP
                    if ($SelectedScans -contains "StartupExtended") {
                        $SyncHash.Status = "Scanning RunOnce and Policy Startup..."
                        $startupTargets = New-Object System.Collections.Generic.List[object]
                        $startupSubPaths = @(
                            "SOFTWARE\Microsoft\Windows\CurrentVersion\RunOnce",
                            "SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\Explorer\Run"
                        )
                        foreach ($subPath in $startupSubPaths) {
                            foreach ($view in @(Get-WmtRegistryViews)) {
                                try {
                                    $baseKey = [Microsoft.Win32.RegistryKey]::OpenBaseKey([Microsoft.Win32.RegistryHive]::LocalMachine, $view)
                                    [void]$startupTargets.Add([PSCustomObject]@{ BaseKey = $baseKey; SubPath = $subPath; RegPrefix = (ConvertTo-WmtHklmViewPath -SubPath $subPath -View $view); Label = "HKLM $(Get-WmtRegistryViewLabel $view)\$subPath"; OwnsBaseKey = $true })
                                }
                                catch {}
                            }
                            $userSubPath = $subPath -replace '^SOFTWARE\\', 'Software\'
                            foreach ($target in @(New-PerUserRegistryTargets -SubPath $userSubPath -HkcuLabel "HKCU\$userSubPath")) {
                                [void]$startupTargets.Add([PSCustomObject]@{ BaseKey = $target.BaseKey; SubPath = $target.SubPath; RegPrefix = $target.RegPrefix; Label = $target.Label; OwnsBaseKey = $false })
                            }
                        }

                        $total = [math]::Max($startupTargets.Count, 1); $i = 0
                        foreach ($target in $startupTargets) {
                            $i++; & $Tick "Scanning Startup Extension: $($target.Label)" $i $total
                            $root = $null
                            try {
                                $root = $target.BaseKey.OpenSubKey($target.SubPath, $false)
                                if ($root) {
                                    foreach ($valName in $root.GetValueNames()) {
                                        $rawValue = [string]$root.GetValue($valName, $null, [Microsoft.Win32.RegistryValueOptions]::DoNotExpandEnvironmentNames)
                                        $cleanExe = Get-ServiceImageExecutablePath $rawValue
                                        if ($cleanExe -and -not (Test-IsWhitelisted $cleanExe) -and -not (Test-IsProtectedWindowsPath $cleanExe) -and -not (Test-PathExists $cleanExe)) {
                                            [void]$SyncHash.Findings.Add([PSCustomObject]@{
                                                    Problem    = "Broken Startup Extension"
                                                    Data       = $cleanExe
                                                    DisplayKey = "$($target.Label)\$valName"
                                                    RegPath    = $target.RegPrefix
                                                    ValueName  = $valName
                                                    Type       = "Value"
                                                    SafeToFix  = $true
                                                    Risk       = "Low"
                                                    Confidence = "High"
                                                    Details    = "RunOnce or policy startup value points to a missing executable. Cleanup deletes only this startup value."
                                                })
                                        }
                                    }
                                }
                            }
                            catch {}
                            finally {
                                if ($root) { $root.Close() }
                                if ($target.OwnsBaseKey -and $target.BaseKey) { $target.BaseKey.Close() }
                            }
                        }
                        & $EndCategory
                    }

                    # 15. INSTALLER FOLDERS
                    if ($SelectedScans -contains "Installer") { 
                        $SyncHash.Status = "Scanning Installer Folders..."
                        $k = "SOFTWARE\Microsoft\Windows\CurrentVersion\Installer\Folders"
                        $rk = [Microsoft.Win32.Registry]::LocalMachine.OpenSubKey($k)
                        if ($rk) { 
                            $names = $rk.GetValueNames(); $total = $names.Count; $i = 0
                            foreach ($val in $names) { 
                                $i++; & $Tick "Scanning Installer: $val" $i $total
                                if ($val -match '^[a-zA-Z]:\\' -and -not (Test-IsProtectedWindowsPath $val) -and -not(Test-PathExists $val)) { [void]$SyncHash.Findings.Add([PSCustomObject]@{ Problem = "Missing Installer Folder"; Data = $val; DisplayKey = "Installer"; RegPath = "HKLM:\$k"; ValueName = $val; Type = "Value" }) } 
                            }; $rk.Close() 
                        } 
                        & $EndCategory
                    }

                    $SyncHash.IsCompleted = $true
                }
                catch {
                    $SyncHash.Error = $_.Exception.Message
                    $SyncHash.IsCompleted = $true
                }
            })

        [void]$ps.BeginInvoke()
        
        # --- UI TIMER (Main Thread) ---
        $timer = New-Object System.Windows.Threading.DispatcherTimer
        $timer.Interval = [TimeSpan]::FromMilliseconds(100)
        
        $timer.Add_Tick({
                $statusText = [string]$syncHash.Status
                $statusText = ($statusText -replace '[\r\n\t]+', '  ').Trim()
                if ($statusText.Length -gt 220) { $statusText = $statusText.Substring(0, 217) + '...' }
                $pLabel.Text = $statusText
                $pBar.Value = $syncHash.Progress
            
                if ($syncHash.IsCompleted) {
                    $timer.Stop()
                    $pForm.Close()
                    $ps.Dispose()
                    $rs.Dispose()

                    if ($syncHash.Error) {
                        if ([string]$syncHash.Error -eq "Registry scan canceled.") {
                            Write-GuiLog "Registry scan canceled."
                            return
                        }
                        Show-WmtMessageBox -Message "Scan Error: $($syncHash.Error)" -Title "Error" -Image Error | Out-Null
                        return
                    }

                    $findings = $syncHash.Findings
                    $uniqueFindings = [System.Collections.Generic.List[object]]::new()
                    $seenFindings = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
                    foreach ($finding in @($findings)) {
                        if ($null -eq $finding) { continue }
                        $newData = if ($finding.PSObject.Properties["NewData"]) { [string]$finding.NewData } else { "" }
                        $key = "$($finding.Type)`0$($finding.RegPath)`0$($finding.ValueName)`0$($finding.Problem)`0$newData"
                        if ($seenFindings.Add($key)) { [void]$uniqueFindings.Add($finding) }
                    }
                    $findings = $uniqueFindings
                
                    # --- RESULTS PROCESSING ---
                    if ($findings.Count -eq 0) {
                        Show-WmtMessageBox -Message "Registry Cleaner: No issues found!" -Title "Scan Complete" -Image Information | Out-Null
                        return
                    }
                
                    $rawSelection = Show-RegistryCleaner -ScanResults ($findings | Select-Object *)
                
                    $toDelete = @()
                    if ($rawSelection) {
                        $toDelete = $rawSelection | Where-Object { $null -ne $_ -and $null -ne $_.RegPath }
                    }

                    if ($toDelete.Count -eq 0) { return }

                    # --- SAFETY PROMPT ---
                    $res = Show-SafetyDialog -Count $toDelete.Count
                    if ($res -eq "Cancel") { return }
                    if ($res -eq "Yes") {
                        Invoke-UiCommand { try { Checkpoint-Computer -Description "WMT DeepClean" -RestorePointType "MODIFY_SETTINGS" -ErrorAction Stop; "Restore Point created." } catch { "Restore Point failed (Disabled?). Continuing..." } } "Creating Restore Point..."
                    }

                    # --- EXECUTE FIX (Background Runspace) ---
                    Start-WmtRegistryCleanupBackground -Items $toDelete -BackupDirectory $bkDir
                }
            }.GetNewClosure())

        $timer.Start()
    }
}

function Invoke-SSDTrim {
    Invoke-UiCommand {
        $log = Join-Path (Get-DataPath) ("SSD_OPTIMIZE_{0}.log" -f (Get-Date -Format "yyyy-MM-dd_HHmmss"))
        $out = @("SSD Optimize Log - $(Get-Date)")

        $volumes = Get-Volume -ErrorAction SilentlyContinue | Where-Object {
            $null -ne $_.DriveLetter -and $_.DriveType -eq 'Fixed'
        }
        if (-not $volumes -or $volumes.Count -eq 0) {
            $out += "No fixed volumes with drive letters were found."
            $out | Out-File -FilePath $log -Encoding UTF8
            Write-Output "SSD optimization skipped. Log: $log"
            return
        }

        $optimized = 0
        $skipped = 0
        $failed = 0

        foreach ($v in $volumes) {
            $driveLetter = [string]$v.DriveLetter
            $mediaType = "Unknown"

            try {
                $part = Get-Partition -DriveLetter $v.DriveLetter -ErrorAction Stop | Select-Object -First 1
                if ($part) {
                    $disk = Get-Disk -Number $part.DiskNumber -ErrorAction Stop
                    if ($disk -and $disk.MediaType) { $mediaType = [string]$disk.MediaType }
                }
            }
            catch {}

            if ($mediaType -notin @("SSD", "SCM", "Unspecified", "Unknown")) {
                $out += "Skipping $driveLetter`: (MediaType=$mediaType)"
                $skipped++
                continue
            }

            $mediaTypeLabel = switch ($mediaType) {
                "Unknown" { "Unknown (treated as SSD)" }
                "Unspecified" { "Unspecified (treated as SSD)" }
                default { $mediaType }
            }
            $out += "Optimizing $driveLetter`: (MediaType=$mediaTypeLabel)"

            try {
                $result = Optimize-Volume -DriveLetter $v.DriveLetter -ReTrim -Verbose -ErrorAction Stop 4>&1 | Out-String
                if (-not [string]::IsNullOrWhiteSpace($result)) { $out += $result.TrimEnd() }
                $optimized++
            }
            catch {
                $out += "Optimize-Volume failed on $driveLetter`: $($_.Exception.Message)"
                try {
                    $fallback = (& defrag "$driveLetter`:" /L 2>&1 | Out-String).TrimEnd()
                    if (-not [string]::IsNullOrWhiteSpace($fallback)) { $out += $fallback }
                    $out += "Fallback completed on $driveLetter`: defrag /L"
                    $optimized++
                }
                catch {
                    $out += "Fallback failed on $driveLetter`: $($_.Exception.Message)"
                    $failed++
                }
            }
        }

        $out += "Summary: optimized=$optimized, skipped=$skipped, failed=$failed"
        $out | Out-File -FilePath $log -Encoding UTF8
        if ($failed -gt 0) {
            Write-Output "SSD optimization completed with some failures. Log: $log"
        }
        else {
            Write-Output "SSD optimization complete. Log: $log"
        }
    } "Running SSD Trim/ReTrim..."
}

function Start-SSDTrimConsole {
    $consoleScript = @'
[Console]::OutputEncoding = [System.Text.UTF8Encoding]::new($false)
$ErrorActionPreference = "Continue"

Write-Host "WMT: SSD Trim/ReTrim started at $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')"
Write-Host ""

$volumes = Get-Volume -ErrorAction SilentlyContinue |
    Where-Object { $null -ne $_.DriveLetter -and $_.DriveType -eq "Fixed" } |
    Sort-Object DriveLetter -Unique

if (-not $volumes -or $volumes.Count -eq 0) {
    Write-Host "No fixed volumes with drive letters were found."
    Write-Host ""
    [void](Read-Host "Press Enter to close")
    exit
}

$optimized = 0
$skipped = 0
$failed = 0

foreach ($v in $volumes) {
    $driveLetter = [string]$v.DriveLetter
    $mediaType = "Unknown"

    try {
        $part = Get-Partition -DriveLetter $v.DriveLetter -ErrorAction Stop | Select-Object -First 1
        if ($part) {
            $disk = Get-Disk -Number $part.DiskNumber -ErrorAction Stop
            if ($disk -and $disk.MediaType) { $mediaType = [string]$disk.MediaType }
        }
    } catch {}

    if ($mediaType -notin @("SSD", "SCM", "Unspecified", "Unknown")) {
        Write-Host "Skipping $driveLetter`: (MediaType=$mediaType)"
        $skipped++
        continue
    }

    $mediaTypeLabel = switch ($mediaType) {
        "Unknown" { "Unknown (treated as SSD)" }
        "Unspecified" { "Unspecified (treated as SSD)" }
        default { $mediaType }
    }

    Write-Host ""
    Write-Host "Optimizing $driveLetter`: (MediaType=$mediaTypeLabel)"

    try {
        Optimize-Volume -DriveLetter $v.DriveLetter -ReTrim -Verbose -ErrorAction Stop
        $optimized++
    } catch {
        Write-Warning "Optimize-Volume failed on $driveLetter`: $($_.Exception.Message)"
        try {
            defrag "$driveLetter`:" /L
            Write-Host "Fallback completed on $driveLetter`: defrag /L"
            $optimized++
        } catch {
            Write-Warning "Fallback failed on $driveLetter`: $($_.Exception.Message)"
            $failed++
        }
    }
}

Write-Host ""
Write-Host "Summary: optimized=$optimized, skipped=$skipped, failed=$failed"
Write-Host ""
[void](Read-Host "Press Enter to close")
'@

    $encoded = [Convert]::ToBase64String([System.Text.Encoding]::Unicode.GetBytes($consoleScript))
    Start-Process -FilePath "powershell.exe" -ArgumentList "-NoProfile -ExecutionPolicy Bypass -EncodedCommand $encoded" -WindowStyle Normal
    Write-GuiLog "[Trim] Opened live SSD trim console window."
}

function Start-DiskManagementGui {
    try {
        Start-Process -FilePath "diskmgmt.msc" -WindowStyle Normal
        Write-GuiLog "[Storage] Opened Disk Management."
    }
    catch {
        Write-GuiLog "[Storage] Failed to open Disk Management: $($_.Exception.Message)"
    }
}

function Open-PowerSettings {
    try {
        Start-Process "ms-settings:powersleep"
        Write-GuiLog "[Power] Opened Windows Power settings."
    }
    catch {
        try {
            Start-Process -FilePath "control.exe" -ArgumentList "powercfg.cpl"
            Write-GuiLog "[Power] Opened Control Panel Power Options."
        }
        catch {
            Write-GuiLog "[Power] Failed to open power settings: $($_.Exception.Message)"
        }
    }
}

function Start-DriveBenchmark {
    $launcherButton = Get-Ctrl "btnMyDeviceDriveBenchmark"

    if ($script:DriveBenchmarkWindow) {
        try {
            if ($script:DriveBenchmarkWindow.IsVisible) {
                $script:DriveBenchmarkWindow.Activate() | Out-Null
                return
            }
        }
        catch {}

        $script:DriveBenchmarkWindow = $null
    }

    Add-Type -AssemblyName PresentationFramework -ErrorAction SilentlyContinue
    Add-Type -AssemblyName PresentationCore -ErrorAction SilentlyContinue
    Add-Type -AssemblyName WindowsBase -ErrorAction SilentlyContinue

    if ($launcherButton) {
        $launcherButton.IsEnabled = $false
    }

    Write-GuiLog "[Storage Benchmark] Opening drive benchmark window."


    $BrushHeaderBg = New-WmtBrush "BgPanel"
    $BrushHeaderText = New-WmtBrush "TextPrimary"
    $BrushHeaderBorder = New-WmtBrush "BorderBrush"
    $BrushHeaderSelectBg = New-WmtBrush "BgHover"

    function Set-DbSystemColors {
        param([System.Windows.FrameworkElement]$Element)

        $Element.Resources[[System.Windows.SystemColors]::WindowBrushKey] = New-WmtBrush "BgPanel"
        $Element.Resources[[System.Windows.SystemColors]::WindowTextBrushKey] = New-WmtBrush "TextPrimary"
        $Element.Resources[[System.Windows.SystemColors]::ControlBrushKey] = New-WmtBrush "BgElevated"
        $Element.Resources[[System.Windows.SystemColors]::ControlTextBrushKey] = New-WmtBrush "TextPrimary"
        $Element.Resources[[System.Windows.SystemColors]::HighlightBrushKey] = New-WmtBrush "Accent"
        $Element.Resources[[System.Windows.SystemColors]::HighlightTextBrushKey] = New-WmtBrush "AccentText"
    }

    function Set-DbHeaderSystemColors {
        param([System.Windows.FrameworkElement]$Element)

        $Element.Resources[[System.Windows.SystemColors]::WindowBrushKey] = $BrushHeaderBg
        $Element.Resources[[System.Windows.SystemColors]::WindowTextBrushKey] = $BrushHeaderText
        $Element.Resources[[System.Windows.SystemColors]::ControlBrushKey] = $BrushHeaderBg
        $Element.Resources[[System.Windows.SystemColors]::ControlTextBrushKey] = $BrushHeaderText
        $Element.Resources[[System.Windows.SystemColors]::HighlightBrushKey] = $BrushHeaderSelectBg
        $Element.Resources[[System.Windows.SystemColors]::HighlightTextBrushKey] = $BrushHeaderText
        $Element.Resources[[System.Windows.SystemColors]::GrayTextBrushKey] = $BrushHeaderText
    }

    function New-DbTextBlock {
        param(
            [string]$Text,
            [double]$FontSize = 12,
            [object]$Foreground = "TextPrimary",
            [System.Windows.Thickness]$Margin = (New-Object System.Windows.Thickness(0))
        )

        $tb = New-Object System.Windows.Controls.TextBlock
        $tb.Text = $Text
        $tb.FontSize = $FontSize
        if ($Foreground -is [string]) {
            Set-WmtThemedBrush -Object $tb -Property ([System.Windows.Controls.TextBlock]::ForegroundProperty) -ColorOrKey ([string]$Foreground)
        }
        else {
            $tb.Foreground = $Foreground
        }
        $tb.Margin = $Margin
        $tb.VerticalAlignment = "Center"
        $tb.TextWrapping = "Wrap"

        return $tb
    }

    function Set-DbButtonStyle {
        param([System.Windows.Controls.Button]$Button)

        Set-WmtThemedBrush -Object $Button -Property ([System.Windows.Controls.Control]::BackgroundProperty) -ColorOrKey "BgElevated"
        Set-WmtThemedBrush -Object $Button -Property ([System.Windows.Controls.Control]::ForegroundProperty) -ColorOrKey "TextPrimary"
        Set-WmtThemedBrush -Object $Button -Property ([System.Windows.Controls.Control]::BorderBrushProperty) -ColorOrKey "BorderBrush"
        $Button.Padding = New-Object System.Windows.Thickness(8, 3, 8, 3)

        Set-DbSystemColors $Button
    }

    function Set-DbHeaderButtonStyle {
        param([System.Windows.Controls.Button]$Button)

        Set-WmtThemedBrush -Object $Button -Property ([System.Windows.Controls.Control]::BackgroundProperty) -ColorOrKey "BgPanel"
        Set-WmtThemedBrush -Object $Button -Property ([System.Windows.Controls.Control]::ForegroundProperty) -ColorOrKey "TextPrimary"
        Set-WmtThemedBrush -Object $Button -Property ([System.Windows.Controls.Control]::BorderBrushProperty) -ColorOrKey "BorderBrush"
        $Button.Padding = New-Object System.Windows.Thickness(8, 3, 8, 3)

        Set-DbHeaderSystemColors $Button
    }

    function Set-DbHeaderComboStyle {
        param([System.Windows.Controls.ComboBox]$ComboBox)

        Set-WmtThemedBrush -Object $ComboBox -Property ([System.Windows.Controls.Control]::BackgroundProperty) -ColorOrKey "BgPanel"
        Set-WmtThemedBrush -Object $ComboBox -Property ([System.Windows.Controls.Control]::ForegroundProperty) -ColorOrKey "TextPrimary"
        Set-WmtThemedBrush -Object $ComboBox -Property ([System.Windows.Controls.Control]::BorderBrushProperty) -ColorOrKey "BorderBrush"
        $ComboBox.IsEditable = $false

        Set-DbHeaderSystemColors $ComboBox

        $itemStyle = New-Object System.Windows.Style([System.Windows.Controls.ComboBoxItem])

        [void]$itemStyle.Setters.Add((New-Object System.Windows.Setter([System.Windows.Controls.Control]::BackgroundProperty, $BrushHeaderBg)))
        [void]$itemStyle.Setters.Add((New-Object System.Windows.Setter([System.Windows.Controls.Control]::ForegroundProperty, $BrushHeaderText)))
        [void]$itemStyle.Setters.Add((New-Object System.Windows.Setter([System.Windows.Controls.Control]::BorderBrushProperty, $BrushHeaderBorder)))
        [void]$itemStyle.Setters.Add((New-Object System.Windows.Setter([System.Windows.Controls.Control]::PaddingProperty, (New-Object System.Windows.Thickness(8, 3, 8, 3)))))

        $ComboBox.ItemContainerStyle = $itemStyle
    }

    $state = [hashtable]::Synchronized(@{
            Lines       = [System.Collections.ArrayList]::Synchronized([System.Collections.ArrayList]::new())
            Status      = "Ready."
            Progress    = 0
            IsRunning   = $false
            IsCompleted = $false
            Error       = ""
            Cancel      = $false
            TargetDrive = "ALL"
            TargetSize  = 1024
            ActiveFiles = [System.Collections.ArrayList]::Synchronized([System.Collections.ArrayList]::new())
        })

    $worker = @{
        PowerShell = $null
        Runspace   = $null
        Async      = $null
        StartedAt  = $null
    }

    $driveValueMap = @{}
    $sizeValueMap = @{}
    $isWindowCleanupDone = $false

    $benchWindow = New-Object System.Windows.Window
    $benchWindow.Title = "Drive Benchmark"
    $benchWindow.Width = 720
    $benchWindow.Height = 540
    $benchWindow.MinWidth = 620
    $benchWindow.MinHeight = 420
    $benchWindow.WindowStartupLocation = "CenterOwner"
    Add-WmtThemeResources -Element $benchWindow
    Set-WmtThemedBrush -Object $benchWindow -Property ([System.Windows.Controls.Control]::BackgroundProperty) -ColorOrKey "BgDark"
    Set-WmtThemedBrush -Object $benchWindow -Property ([System.Windows.Controls.Control]::ForegroundProperty) -ColorOrKey "TextPrimary"

    if ($window) { $benchWindow.Owner = $window }
    Set-DbSystemColors $benchWindow

    $root = New-Object System.Windows.Controls.Grid
    $root.Margin = New-Object System.Windows.Thickness(18)
    Set-WmtThemedBrush -Object $root -Property ([System.Windows.Controls.Panel]::BackgroundProperty) -ColorOrKey "BgDark"
    Set-DbSystemColors $root

    foreach ($rowHeight in @("Auto", "Auto", "Auto", "*", "Auto")) {
        $row = New-Object System.Windows.Controls.RowDefinition
        if ($rowHeight -eq "*") { $row.Height = [System.Windows.GridLength]::new(1, [System.Windows.GridUnitType]::Star) }
        else { $row.Height = [System.Windows.GridLength]::Auto }
        [void]$root.RowDefinitions.Add($row)
    }

    $title = New-DbTextBlock -Text "Drive Benchmark" -FontSize 18 -Foreground "TextPrimary" -Margin (New-Object System.Windows.Thickness(0, 0, 0, 8))
    $title.FontWeight = [System.Windows.FontWeights]::SemiBold
    [System.Windows.Controls.Grid]::SetRow($title, 0)
    [void]$root.Children.Add($title)

    $controlsPanel = New-Object System.Windows.Controls.StackPanel
    $controlsPanel.Orientation = "Horizontal"
    $controlsPanel.Margin = New-Object System.Windows.Thickness(0, 0, 0, 12)
    [System.Windows.Controls.Grid]::SetRow($controlsPanel, 1)

    $lblDrive = New-DbTextBlock -Text "Target:" -Foreground "TextPrimary" -Margin (New-Object System.Windows.Thickness(0, 0, 8, 0))
    [void]$controlsPanel.Children.Add($lblDrive)

    $cmbDrive = New-Object System.Windows.Controls.ComboBox
    $cmbDrive.Width = 180
    $cmbDrive.Height = 30
    $cmbDrive.Margin = New-Object System.Windows.Thickness(0, 0, 16, 0)
    Set-DbHeaderComboStyle $cmbDrive

    [void]$cmbDrive.Items.Add("All Fixed Drives")
    $driveValueMap["All Fixed Drives"] = "ALL"

    foreach ($driveInfo in [System.IO.DriveInfo]::GetDrives()) {
        if ($driveInfo.DriveType -eq [System.IO.DriveType]::Fixed -and $driveInfo.IsReady) {
            $driveLetter = $driveInfo.Name.Substring(0, 1)
            $driveLabel = if ([string]::IsNullOrWhiteSpace($driveInfo.VolumeLabel)) { "Local Disk" } else { $driveInfo.VolumeLabel }
            $displayText = "$driveLetter`: ($driveLabel)"
            [void]$cmbDrive.Items.Add($displayText)
            $driveValueMap[$displayText] = $driveLetter
        }
    }
    $cmbDrive.SelectedIndex = 0
    [void]$controlsPanel.Children.Add($cmbDrive)

    $lblSize = New-DbTextBlock -Text "Test Size:" -Foreground "TextPrimary" -Margin (New-Object System.Windows.Thickness(0, 0, 8, 0))
    [void]$controlsPanel.Children.Add($lblSize)

    $cmbSize = New-Object System.Windows.Controls.ComboBox
    $cmbSize.Width = 110
    $cmbSize.Height = 30
    $cmbSize.Margin = New-Object System.Windows.Thickness(0, 0, 16, 0)
    Set-DbHeaderComboStyle $cmbSize

    foreach ($sizeMb in @(16, 32, 64, 128, 256, 512, 1024, 2048, 4096, 8192)) {
        $sizeText = "$sizeMb MB"
        [void]$cmbSize.Items.Add($sizeText)
        $sizeValueMap[$sizeText] = $sizeMb
    }
    $cmbSize.SelectedItem = "1024 MB"
    [void]$controlsPanel.Children.Add($cmbSize)

    $btnRun = New-Object System.Windows.Controls.Button
    $btnRun.Content = "Run Benchmark"
    $btnRun.Width = 125
    $btnRun.Height = 30
    Set-DbHeaderButtonStyle $btnRun
    [void]$controlsPanel.Children.Add($btnRun)
    [void]$root.Children.Add($controlsPanel)

    $statusText = New-DbTextBlock -Text "Ready." -Foreground "Warning" -Margin (New-Object System.Windows.Thickness(0, 0, 0, 8))
    [System.Windows.Controls.Grid]::SetRow($statusText, 2)
    [void]$root.Children.Add($statusText)

    $logBox = New-Object System.Windows.Controls.TextBox
    $logBox.IsReadOnly = $true
    $logBox.AcceptsReturn = $true
    $logBox.TextWrapping = "NoWrap"
    $logBox.VerticalScrollBarVisibility = "Auto"
    $logBox.HorizontalScrollBarVisibility = "Auto"
    $logBox.FontFamily = "Cascadia Mono, Consolas"
    $logBox.FontSize = 12
    Set-WmtThemedBrush -Object $logBox -Property ([System.Windows.Controls.Control]::BackgroundProperty) -ColorOrKey "BgPanel"
    Set-WmtThemedBrush -Object $logBox -Property ([System.Windows.Controls.Control]::ForegroundProperty) -ColorOrKey "TextPrimary"
    Set-WmtThemedBrush -Object $logBox -Property ([System.Windows.Controls.Control]::BorderBrushProperty) -ColorOrKey "BorderBrush"
    $logBox.BorderThickness = [System.Windows.Thickness]::new(1)
    $logBox.Padding = [System.Windows.Thickness]::new(10)
    Set-DbSystemColors $logBox
    [System.Windows.Controls.Grid]::SetRow($logBox, 3)
    [void]$root.Children.Add($logBox)

    $bottom = New-Object System.Windows.Controls.Grid
    $bottom.Margin = New-Object System.Windows.Thickness(0, 12, 0, 0)

    $colProgress = New-Object System.Windows.Controls.ColumnDefinition
    $colProgress.Width = [System.Windows.GridLength]::new(1, [System.Windows.GridUnitType]::Star)
    $colExport = New-Object System.Windows.Controls.ColumnDefinition
    $colExport.Width = [System.Windows.GridLength]::Auto
    $colClose = New-Object System.Windows.Controls.ColumnDefinition
    $colClose.Width = [System.Windows.GridLength]::Auto

    [void]$bottom.ColumnDefinitions.Add($colProgress)
    [void]$bottom.ColumnDefinitions.Add($colExport)
    [void]$bottom.ColumnDefinitions.Add($colClose)

    $progress = New-Object System.Windows.Controls.ProgressBar
    $progress.Minimum = 0
    $progress.Maximum = 100
    $progress.Height = 12
    $progress.Margin = New-Object System.Windows.Thickness(0, 8, 12, 0)
    Set-WmtThemedBrush -Object $progress -Property ([System.Windows.Controls.Control]::ForegroundProperty) -ColorOrKey "Accent"
    Set-WmtThemedBrush -Object $progress -Property ([System.Windows.Controls.Control]::BackgroundProperty) -ColorOrKey "BorderBrush"
    [System.Windows.Controls.Grid]::SetColumn($progress, 0)
    [void]$bottom.Children.Add($progress)

    $exportBtn = New-Object System.Windows.Controls.Button
    $exportBtn.Content = "Export"
    $exportBtn.Width = 80
    $exportBtn.Height = 32
    $exportBtn.Margin = New-Object System.Windows.Thickness(0, 0, 8, 0)
    Set-DbButtonStyle $exportBtn

    $exportBtn.Add_Click({
            $dialog = [Microsoft.Win32.SaveFileDialog]::new()
            $dialog.Filter = "Text Files (*.txt)|*.txt|All Files (*.*)|*.*"
            $dialog.FileName = "WMT_DriveBenchmark_Results.txt"

            if ($dialog.ShowDialog() -eq $true) {
                try {
                    [System.IO.File]::WriteAllText($dialog.FileName, $logBox.Text, [System.Text.Encoding]::UTF8)
                    Write-GuiLog "[Storage Benchmark] Exported results to $($dialog.FileName)"
                }
                catch { Write-GuiLog "[Storage Benchmark] Export failed: $($_.Exception.Message)" }
            }
        }.GetNewClosure())

    [System.Windows.Controls.Grid]::SetColumn($exportBtn, 1)
    [void]$bottom.Children.Add($exportBtn)

    $closeBtn = New-Object System.Windows.Controls.Button
    $closeBtn.Content = "Close"
    $closeBtn.Width = 80
    $closeBtn.Height = 32
    Set-DbButtonStyle $closeBtn

    $closeBtn.Add_Click({
            try { $benchWindow.Close() }
            catch { Write-GuiLog "[Storage Benchmark] Close failed: $($_.Exception.Message)" }
        }.GetNewClosure())

    [System.Windows.Controls.Grid]::SetColumn($closeBtn, 2)
    [void]$bottom.Children.Add($closeBtn)

    [System.Windows.Controls.Grid]::SetRow($bottom, 4)
    [void]$root.Children.Add($bottom)

    $benchWindow.Content = $root
    $script:DriveBenchmarkWindow = $benchWindow

    $timer = New-Object System.Windows.Threading.DispatcherTimer
    $timer.Interval = [TimeSpan]::FromMilliseconds(200)

    $releaseWindowState = {
        try {
            if ($isWindowCleanupDone) { return }
            $isWindowCleanupDone = $true
            $script:DriveBenchmarkWindow = $null
            if ($launcherButton) { $launcherButton.IsEnabled = $true }
            Write-GuiLog "[Storage Benchmark] Window closed."
        }
        catch {
            try { $script:DriveBenchmarkWindow = $null } catch {}
            try { if ($launcherButton) { $launcherButton.IsEnabled = $true } } catch {}
        }
    }.GetNewClosure()

    $setRunningUi = {
        param([bool]$Running)
        if ($Running) {
            $btnRun.Content = "Stop Benchmark"
            $cmbDrive.IsEnabled = $false
            $cmbSize.IsEnabled = $false
        }
        else {
            $btnRun.Content = "Run Benchmark"
            $cmbDrive.IsEnabled = $true
            $cmbSize.IsEnabled = $true
        }
        $btnRun.IsEnabled = $true

        Set-WmtThemedBrush -Object $cmbDrive -Property ([System.Windows.Controls.Control]::BackgroundProperty) -ColorOrKey "BgPanel"
        Set-WmtThemedBrush -Object $cmbDrive -Property ([System.Windows.Controls.Control]::ForegroundProperty) -ColorOrKey "TextPrimary"
        Set-WmtThemedBrush -Object $cmbDrive -Property ([System.Windows.Controls.Control]::BorderBrushProperty) -ColorOrKey "BorderBrush"
        Set-WmtThemedBrush -Object $cmbSize -Property ([System.Windows.Controls.Control]::BackgroundProperty) -ColorOrKey "BgPanel"
        Set-WmtThemedBrush -Object $cmbSize -Property ([System.Windows.Controls.Control]::ForegroundProperty) -ColorOrKey "TextPrimary"
        Set-WmtThemedBrush -Object $cmbSize -Property ([System.Windows.Controls.Control]::BorderBrushProperty) -ColorOrKey "BorderBrush"
        Set-WmtThemedBrush -Object $btnRun -Property ([System.Windows.Controls.Control]::BackgroundProperty) -ColorOrKey "BgPanel"
        Set-WmtThemedBrush -Object $btnRun -Property ([System.Windows.Controls.Control]::ForegroundProperty) -ColorOrKey "TextPrimary"
        Set-WmtThemedBrush -Object $btnRun -Property ([System.Windows.Controls.Control]::BorderBrushProperty) -ColorOrKey "BorderBrush"

        $exportBtn.IsEnabled = $true
        $closeBtn.IsEnabled = $true
    }.GetNewClosure()

    $disposeWorker = {
        try { if ($worker["PowerShell"]) { $worker["PowerShell"].Dispose() } } catch {}
        try { if ($worker["Runspace"]) { $worker["Runspace"].Close(); $worker["Runspace"].Dispose() } } catch {}
        $worker["PowerShell"] = $null
        $worker["Runspace"] = $null
        $worker["Async"] = $null
        $worker["StartedAt"] = $null
    }.GetNewClosure()

    $cleanupTrackedBenchmarkFiles = {
        try {
            if (-not $state["ActiveFiles"]) { return }
            foreach ($path in @($state["ActiveFiles"])) {
                try {
                    if (-not [string]::IsNullOrWhiteSpace([string]$path) -and [System.IO.File]::Exists([string]$path)) {
                        [System.IO.File]::Delete([string]$path)
                    }
                }
                catch {}
            }
            try { $state["ActiveFiles"].Clear() } catch {}
        }
        catch {}
    }.GetNewClosure()

    $stopBenchmark = {
        try {
            if (-not $state["IsRunning"]) { return }
            $state["Cancel"] = $true
            $state["Status"] = "Stopping benchmark..."
            $btnRun.Content = "Stopping..."
            $btnRun.IsEnabled = $false

            try { [void]$state["Lines"].Add(""); [void]$state["Lines"].Add("Stopping benchmark...") } catch {}
            try { if ($worker["PowerShell"]) { $worker["PowerShell"].Stop() } } catch {}
            Write-GuiLog "[Storage Benchmark] Stop requested."
            & $refreshUi
        }
        catch { Write-GuiLog "[Storage Benchmark] Stop failed: $($_.Exception.Message)" }
    }.GetNewClosure()

    $refreshUi = {
        try {
            $statusText.Text = [string]$state["Status"]
            $progress.Value = [double]$state["Progress"]

            if ($state["Lines"]) {
                $logBox.Text = (@($state["Lines"]) -join "`r`n")
                $logBox.ScrollToEnd()
            }
        }
        catch { Write-GuiLog "[Storage Benchmark] UI refresh failed: $($_.Exception.Message)" }
    }.GetNewClosure()

    $timerTick = {
        try {
            & $refreshUi
            if (-not $worker["Async"]) { return }

            if ($state["IsRunning"] -and $worker["StartedAt"]) {
                $elapsedMinutes = ((Get-Date) - $worker["StartedAt"]).TotalMinutes
                if ($elapsedMinutes -ge 60) {
                    $state["Cancel"] = $true
                    $state["Error"] = "Benchmark timed out after 60 minutes."
                    $state["Status"] = "Benchmark timed out."
                    $state["Progress"] = 100
                    $state["IsRunning"] = $false
                    $state["IsCompleted"] = $true
                    [void]$state["Lines"].Add(""); [void]$state["Lines"].Add("ERROR: Benchmark timed out after 60 minutes.")
                    try { if ($worker["PowerShell"]) { $worker["PowerShell"].Stop() } } catch {}
                }
            }

            if ($worker["Async"].IsCompleted -or $state["IsCompleted"]) {
                $timer.Stop()

                try {
                    if ($worker["Async"] -and $worker["Async"].IsCompleted -and $worker["PowerShell"]) {
                        [void]$worker["PowerShell"].EndInvoke($worker["Async"])
                    }
                }
                catch {
                    if ($state["Cancel"]) {
                        $state["Error"] = ""
                        [void]$state["Lines"].Add("Benchmark stopped by user.")
                    }
                    elseif ([string]::IsNullOrWhiteSpace([string]$state["Error"])) {
                        $state["Error"] = $_.Exception.Message
                        [void]$state["Lines"].Add(""); [void]$state["Lines"].Add("ERROR: $($_.Exception.Message)")
                    }
                    Write-GuiLog "[Storage Benchmark] Runspace failed: $($_.Exception.Message)"
                }

                $state["IsRunning"] = $false
                $state["IsCompleted"] = $true
                $state["Progress"] = 100

                if ($state["Cancel"] -and [string]::IsNullOrWhiteSpace([string]$state["Error"])) {
                    $state["Status"] = "Benchmark stopped."
                    Set-WmtThemedBrush -Object $statusText -Property ([System.Windows.Controls.TextBlock]::ForegroundProperty) -ColorOrKey "Warning"
                }
                elseif ([string]::IsNullOrWhiteSpace([string]$state["Error"])) {
                    $state["Status"] = "Benchmark complete."
                    Set-WmtThemedBrush -Object $statusText -Property ([System.Windows.Controls.TextBlock]::ForegroundProperty) -ColorOrKey "Success"
                }
                else {
                    $state["Status"] = "Benchmark failed: $($state["Error"])"
                    Set-WmtThemedBrush -Object $statusText -Property ([System.Windows.Controls.TextBlock]::ForegroundProperty) -ColorOrKey "Danger"
                }

                & $refreshUi
                foreach ($line in @($state["Lines"])) {
                    if (-not [string]::IsNullOrWhiteSpace([string]$line)) { Write-GuiLog "[Storage Benchmark] $line" }
                }

                & $setRunningUi $false
                & $disposeWorker
                & $cleanupTrackedBenchmarkFiles
            }
        }
        catch {
            $timer.Stop()
            $state["IsRunning"] = $false
            $state["IsCompleted"] = $true
            $state["Error"] = $_.Exception.Message
            $state["Status"] = "Benchmark UI failed."
            $state["Progress"] = 100
            try { [void]$state["Lines"].Add(""); [void]$state["Lines"].Add("TIMER ERROR: $($_.Exception.Message)") } catch {}
            $statusText.Text = "Benchmark UI failed: $($_.Exception.Message)"
            Set-WmtThemedBrush -Object $statusText -Property ([System.Windows.Controls.TextBlock]::ForegroundProperty) -ColorOrKey "Danger"

            & $refreshUi
            & $setRunningUi $false
            & $disposeWorker
            & $cleanupTrackedBenchmarkFiles
            Write-GuiLog "[Storage Benchmark] Timer failed: $($_.Exception.Message)"
        }
    }.GetNewClosure()

    $timer.Add_Tick($timerTick)

    $startBenchmark = {
        if ($state["IsRunning"]) { return }

        & $disposeWorker

        $selectedDrive = "ALL"
        if ($cmbDrive.SelectedItem) {
            $driveKey = [string]$cmbDrive.SelectedItem
            if ($driveValueMap.ContainsKey($driveKey)) { $selectedDrive = [string]$driveValueMap[$driveKey] }
        }

        $selectedSize = 1024
        if ($cmbSize.SelectedItem) {
            $sizeKey = [string]$cmbSize.SelectedItem
            if ($sizeValueMap.ContainsKey($sizeKey)) { $selectedSize = [int]$sizeValueMap[$sizeKey] }
        }

        $state["Lines"].Clear()
        $state["Status"] = "Preparing benchmark..."
        $state["Progress"] = 0
        $state["IsRunning"] = $true
        $state["IsCompleted"] = $false
        $state["Error"] = ""
        $state["Cancel"] = $false
        $state["TargetDrive"] = $selectedDrive
        $state["TargetSize"] = $selectedSize
        try { $state["ActiveFiles"].Clear() } catch {}

        $targetLabel = if ($selectedDrive -eq "ALL") { "All Fixed Drives" } else { "{0}:\" -f $selectedDrive }

        [void]$state["Lines"].Add("Storage Benchmark (Native Direct I/O)")
        [void]$state["Lines"].Add("Target: $targetLabel | Size: $selectedSize MB")
        [void]$state["Lines"].Add("Note: Uses direct volume mappings to test physical capabilities.")
        [void]$state["Lines"].Add("")

        Set-WmtThemedBrush -Object $statusText -Property ([System.Windows.Controls.TextBlock]::ForegroundProperty) -ColorOrKey "Warning"
        & $setRunningUi $true
        & $refreshUi

        try {
            $runspace = [runspacefactory]::CreateRunspace()
            $runspace.ApartmentState = "MTA"
            $runspace.ThreadOptions = "ReuseThread"
            $runspace.Open()

            $ps = [PowerShell]::Create()
            $ps.Runspace = $runspace

            [void]$ps.AddScript({
                    param($State)

                    $ErrorActionPreference = "Stop"

                    function Add-Line([string]$Text) { [void]$State["Lines"].Add($Text) }
                    function Set-BenchmarkStatus([string]$Text, [int]$Progress) {
                        $State["Status"] = $Text
                        $State["Progress"] = [math]::Max(0, [math]::Min(100, $Progress))
                    }
                    function Test-Cancelled { if ($State["Cancel"]) { throw "Benchmark cancelled." } }

                    function Get-BenchmarkDriveHardwareMap {
                        $map = @{}
                        try {
                            $partitionByDriveLetter = @{}
                            $diskByNumber = @{}
                            $cimDiskByIndex = @{}

                            foreach ($p in @(Get-Partition -ErrorAction SilentlyContinue)) {
                                if ($null -ne $p.DriveLetter -and -not [string]::IsNullOrWhiteSpace([string]$p.DriveLetter)) {
                                    $partitionByDriveLetter[[string]$p.DriveLetter] = $p
                                }
                            }
                            foreach ($d in @(Get-Disk -ErrorAction SilentlyContinue)) {
                                if ($null -ne $d.Number) { $diskByNumber[[int]$d.Number] = $d }
                            }
                            foreach ($d in @(Get-CimInstance Win32_DiskDrive -Property Index, Model, InterfaceType -ErrorAction SilentlyContinue)) {
                                if ($null -ne $d.Index) { $cimDiskByIndex[[int]$d.Index] = $d }
                            }

                            foreach ($driveLetter in @($partitionByDriveLetter.Keys)) {
                                $partition = $partitionByDriveLetter[$driveLetter]
                                $disk = $null; $cimDisk = $null

                                if ($partition -and $null -ne $partition.DiskNumber) {
                                    $diskNumber = [int]$partition.DiskNumber
                                    if ($diskByNumber.ContainsKey($diskNumber)) { $disk = $diskByNumber[$diskNumber] }
                                    if ($cimDiskByIndex.ContainsKey($diskNumber)) { $cimDisk = $cimDiskByIndex[$diskNumber] }
                                }

                                $model = $null
                                if ($cimDisk -and -not [string]::IsNullOrWhiteSpace([string]$cimDisk.Model)) { $model = ([string]$cimDisk.Model).Trim() }
                                elseif ($disk -and -not [string]::IsNullOrWhiteSpace([string]$disk.FriendlyName)) { $model = ([string]$disk.FriendlyName).Trim() }

                                $parts = @()
                                if (-not [string]::IsNullOrWhiteSpace($model)) { $parts += $model }
                                if ($partition -and $null -ne $partition.DiskNumber) { $parts += ("Disk {0}" -f $partition.DiskNumber) }
                                if ($disk -and $disk.BusType) { $parts += [string]$disk.BusType }
                                elseif ($cimDisk -and -not [string]::IsNullOrWhiteSpace([string]$cimDisk.InterfaceType)) { $parts += [string]$cimDisk.InterfaceType }

                                if ($parts.Count -gt 0) { $map[[string]$driveLetter] = ($parts -join " | ") }
                            }
                        }
                        catch {}
                        return $map
                    }

                    function Initialize-NativeDiskBenchmark {
                        if (([System.Management.Automation.PSTypeName]'Wmt.NativeDiskBenchmark').Type) { return }

                        Add-Type -TypeDefinition @'
using System;
using System.ComponentModel;
using System.Diagnostics;
using System.Runtime.InteropServices;
using Microsoft.Win32.SafeHandles;

namespace Wmt {
    public static class NativeDiskBenchmark {
        [DllImport("kernel32.dll", CharSet = CharSet.Unicode, SetLastError = true)]
        public static extern SafeFileHandle CreateFile(string lpFileName, uint dwDesiredAccess, uint dwShareMode, IntPtr lpSecurityAttributes, uint dwCreationDisposition, uint dwFlagsAndAttributes, IntPtr hTemplateFile);

        [DllImport("kernel32.dll", SetLastError = true)]
        [return: MarshalAs(UnmanagedType.Bool)]
        public static extern bool ReadFile(SafeFileHandle hFile, IntPtr lpBuffer, uint nNumberOfBytesToRead, out uint lpNumberOfBytesRead, IntPtr lpOverlapped);

        [DllImport("kernel32.dll", SetLastError = true)]
        [return: MarshalAs(UnmanagedType.Bool)]
        public static extern bool WriteFile(SafeFileHandle hFile, IntPtr lpBuffer, uint nNumberOfBytesToWrite, out uint lpNumberOfBytesWritten, IntPtr lpOverlapped);

        [DllImport("kernel32.dll", SetLastError = true)]
        [return: MarshalAs(UnmanagedType.Bool)]
        public static extern bool SetFilePointerEx(SafeFileHandle hFile, long liDistanceToMove, out long lpNewFilePointer, uint dwMoveMethod);

        [DllImport("kernel32.dll", SetLastError = true)]
        [return: MarshalAs(UnmanagedType.Bool)]
        public static extern bool FlushFileBuffers(SafeFileHandle hFile);

        [DllImport("kernel32.dll", SetLastError = true)]
        [return: MarshalAs(UnmanagedType.Bool)]
        public static extern bool SetEndOfFile(SafeFileHandle hFile);

        [DllImport("kernel32.dll", SetLastError = true)]
        [return: MarshalAs(UnmanagedType.Bool)]
        public static extern bool SetFileValidData(SafeFileHandle hFile, long ValidDataLength);

        [DllImport("kernel32.dll", SetLastError = true)]
        [return: MarshalAs(UnmanagedType.Bool)]
        public static extern bool CloseHandle(IntPtr hObject);

        [DllImport("kernel32.dll", SetLastError = true)]
        public static extern IntPtr CreateIoCompletionPort(SafeFileHandle FileHandle, IntPtr ExistingCompletionPort, UIntPtr CompletionKey, uint NumberOfConcurrentThreads);

        [DllImport("kernel32.dll", SetLastError = true)]
        [return: MarshalAs(UnmanagedType.Bool)]
        public static extern bool GetQueuedCompletionStatusEx(IntPtr CompletionPort, IntPtr lpCompletionPortEntries, uint ulCount, out uint ulNumEntriesRemoved, uint dwMilliseconds, [MarshalAs(UnmanagedType.Bool)] bool fAlertable);

        [DllImport("kernel32.dll", SetLastError = true)]
        public static extern IntPtr VirtualAlloc(IntPtr lpAddress, UIntPtr dwSize, uint flAllocationType, uint flProtect);

        [DllImport("kernel32.dll", SetLastError = true)]
        [return: MarshalAs(UnmanagedType.Bool)]
        public static extern bool VirtualFree(IntPtr lpAddress, UIntPtr dwSize, uint dwFreeType);

        [DllImport("advapi32.dll", ExactSpelling = true, SetLastError = true)]
        [return: MarshalAs(UnmanagedType.Bool)]
        public static extern bool OpenProcessToken(IntPtr ProcessHandle, uint DesiredAccess, out IntPtr TokenHandle);

        [DllImport("advapi32.dll", CharSet = CharSet.Unicode, SetLastError = true)]
        [return: MarshalAs(UnmanagedType.Bool)]
        public static extern bool LookupPrivilegeValue(string lpSystemName, string lpName, out long lpLuid);

        [DllImport("advapi32.dll", ExactSpelling = true, SetLastError = true)]
        [return: MarshalAs(UnmanagedType.Bool)]
        public static extern bool AdjustTokenPrivileges(IntPtr TokenHandle, [MarshalAs(UnmanagedType.Bool)] bool DisableAllPrivileges, ref TokenPrivileges NewState, uint BufferLength, IntPtr PreviousState, IntPtr ReturnLength);

        [DllImport("kernel32.dll", ExactSpelling = true)]
        public static extern IntPtr GetCurrentProcess();

        public const uint GENERIC_READ = 0x80000000;
        public const uint GENERIC_WRITE = 0x40000000;
        public const uint FILE_SHARE_READ = 0x00000001;
        public const uint FILE_SHARE_WRITE = 0x00000002;
        public const uint CREATE_ALWAYS = 2;
        public const uint OPEN_EXISTING = 3;
        public const uint FILE_ATTRIBUTE_NORMAL = 0x00000080;
        public const uint FILE_FLAG_NO_BUFFERING = 0x20000000;
        public const uint FILE_FLAG_OVERLAPPED = 0x40000000;
        public const uint FILE_FLAG_WRITE_THROUGH = 0x80000000;
        public const uint FILE_FLAG_RANDOM_ACCESS = 0x10000000;
        public const uint MEM_COMMIT = 0x1000;
        public const uint MEM_RESERVE = 0x2000;
        public const uint MEM_RELEASE = 0x8000;
        public const uint PAGE_READWRITE = 0x04;
        public const uint FILE_BEGIN = 0;
        public const int ERROR_IO_PENDING = 997;
        public const uint INFINITE = 0xFFFFFFFF;
        public const uint TOKEN_ADJUST_PRIVILEGES = 0x00000020;
        public const uint TOKEN_QUERY = 0x00000008;
        public const uint SE_PRIVILEGE_ENABLED = 0x00000002;

        [StructLayout(LayoutKind.Sequential)]
        private struct NativeOverlapped {
            public IntPtr Internal;
            public IntPtr InternalHigh;
            public uint Offset;
            public uint OffsetHigh;
            public IntPtr hEvent;
        }

        [StructLayout(LayoutKind.Sequential, Pack = 1)]
        public struct TokenPrivileges {
            public int PrivilegeCount;
            public long Luid;
            public uint Attributes;
        }

        [StructLayout(LayoutKind.Sequential)]
        private struct OverlappedEntry {
            public UIntPtr CompletionKey;
            public IntPtr Overlapped;
            public UIntPtr Internal;
            public uint NumberOfBytesTransferred;
        }

        private static readonly int OverlappedInternalOffset = (int)Marshal.OffsetOf(typeof(NativeOverlapped), "Internal");
        private static readonly int OverlappedInternalHighOffset = (int)Marshal.OffsetOf(typeof(NativeOverlapped), "InternalHigh");
        private static readonly int OverlappedOffsetOffset = (int)Marshal.OffsetOf(typeof(NativeOverlapped), "Offset");
        private static readonly int OverlappedOffsetHighOffset = (int)Marshal.OffsetOf(typeof(NativeOverlapped), "OffsetHigh");
        private static readonly int OverlappedEventOffset = (int)Marshal.OffsetOf(typeof(NativeOverlapped), "hEvent");
        private static readonly int CompletionEntryOverlappedOffset = (int)Marshal.OffsetOf(typeof(OverlappedEntry), "Overlapped");
        private static readonly int CompletionEntryBytesOffset = (int)Marshal.OffsetOf(typeof(OverlappedEntry), "NumberOfBytesTransferred");

        public sealed class BenchmarkMeasure {
            public long Bytes { get; set; }
            public int Operations { get; set; }
            public double Seconds { get; set; }
            public double MBps {
                get {
                    if (Seconds <= 0) return 0;
                    return Math.Round((Bytes / 1000000.0) / Seconds, 1);
                }
            }
            public double Iops {
                get {
                    if (Seconds <= 0) return 0;
                    return Math.Round(Operations / Seconds, 0);
                }
            }
        }

        private static Exception LastError(string action) {
            return new Win32Exception(Marshal.GetLastWin32Error(), action + " failed");
        }

        private static long AlignBytes(long bytes, int blockSize) {
            long blocks = bytes / blockSize;
            if (blocks < 1) throw new ArgumentOutOfRangeException("bytes", "Benchmark size is smaller than the I/O block size.");
            return blocks * blockSize;
        }

        private static SafeFileHandle OpenNativeFile(string path, uint access, uint creationDisposition, bool randomAccess, bool writeThrough, uint shareMode, bool overlapped) {
            uint flags = FILE_ATTRIBUTE_NORMAL | FILE_FLAG_NO_BUFFERING;
            if (randomAccess) flags |= FILE_FLAG_RANDOM_ACCESS;
            if (writeThrough) flags |= FILE_FLAG_WRITE_THROUGH;
            if (overlapped) flags |= FILE_FLAG_OVERLAPPED;

            SafeFileHandle handle = CreateFile(path, access, shareMode, IntPtr.Zero, creationDisposition, flags, IntPtr.Zero);
            if (handle.IsInvalid) throw LastError("CreateFile " + path);
            return handle;
        }

        private static void EnablePrivilege(string privilegeName) {
            IntPtr token = IntPtr.Zero;
            try {
                if (!OpenProcessToken(GetCurrentProcess(), TOKEN_ADJUST_PRIVILEGES | TOKEN_QUERY, out token)) return;
                long luid;
                if (!LookupPrivilegeValue(null, privilegeName, out luid)) return;

                TokenPrivileges privileges = new TokenPrivileges {
                    PrivilegeCount = 1,
                    Luid = luid,
                    Attributes = SE_PRIVILEGE_ENABLED
                };
                AdjustTokenPrivileges(token, false, ref privileges, 0, IntPtr.Zero, IntPtr.Zero);
            }
            finally {
                if (token != IntPtr.Zero) CloseHandle(token);
            }
        }

        public static void PrepareFile(string path, long bytes) {
            EnablePrivilege("SeManageVolumePrivilege");
            SafeFileHandle handle = null;
            bool validDataReady = false;

            try {
                handle = OpenNativeFile(path, GENERIC_READ | GENERIC_WRITE, CREATE_ALWAYS, false, false, FILE_SHARE_READ | FILE_SHARE_WRITE, false);
                long ignored;
                SetFilePointerEx(handle, bytes, out ignored, FILE_BEGIN);
                SetEndOfFile(handle);
                validDataReady = SetFileValidData(handle, bytes);
                FlushFileBuffers(handle);
            }
            finally {
                if (handle != null) handle.Dispose();
            }

            if (!validDataReady) {
                // Modified fallback: Using standard FileStream buffering for non-admins to prevent setup thrashing.
                byte[] buffer = new byte[1048576];
                new Random(Environment.TickCount).NextBytes(buffer);
                using (System.IO.FileStream fs = new System.IO.FileStream(path, System.IO.FileMode.Create, System.IO.FileAccess.Write, System.IO.FileShare.None, 1048576, System.IO.FileOptions.SequentialScan)) {
                    long p = 0;
                    while (p < bytes) {
                        int toWrite = (int)Math.Min(buffer.Length, bytes - p);
                        fs.Write(buffer, 0, toWrite);
                        p += toWrite;
                    }
                    fs.Flush(true);
                }
            }
        }

        private sealed class NativeIoSlot : IDisposable {
            public IntPtr Buffer = IntPtr.Zero;
            public IntPtr Overlapped = IntPtr.Zero;

            public NativeIoSlot(int blockSize, int seed) {
                Buffer = VirtualAlloc(IntPtr.Zero, new UIntPtr((ulong)blockSize), MEM_COMMIT | MEM_RESERVE, PAGE_READWRITE);
                byte[] managed = new byte[blockSize];
                new Random(seed).NextBytes(managed);
                Marshal.Copy(managed, 0, Buffer, blockSize);
                Overlapped = Marshal.AllocHGlobal(Marshal.SizeOf(typeof(NativeOverlapped)));
            }

            public void Dispose() {
                if (Overlapped != IntPtr.Zero) { Marshal.FreeHGlobal(Overlapped); Overlapped = IntPtr.Zero; }
                if (Buffer != IntPtr.Zero) { VirtualFree(Buffer, UIntPtr.Zero, MEM_RELEASE); Buffer = IntPtr.Zero; }
            }
        }

        public static BenchmarkMeasure MeasureQueued(string path, long totalBytes, int blockSize, int queueDepth, double durationSeconds, bool isWrite, bool isRandom) {
            totalBytes = AlignBytes(totalBytes, blockSize);
            long blockCount = totalBytes / blockSize;
            bool timedRun = durationSeconds > 0;
            int operationLimit = timedRun ? int.MaxValue : (int)blockCount;
            queueDepth = Math.Max(1, Math.Min(queueDepth, operationLimit));

            NativeIoSlot[] slots = new NativeIoSlot[queueDepth];
            SafeFileHandle handle = null;
            IntPtr completionPort = IntPtr.Zero;

            try {
                for (int i = 0; i < queueDepth; i++) {
                    slots[i] = new NativeIoSlot(blockSize, Environment.TickCount + i);
                }

                uint access = isWrite ? (GENERIC_READ | GENERIC_WRITE) : GENERIC_READ;
                uint share = isWrite ? 0 : (FILE_SHARE_READ | FILE_SHARE_WRITE);

                // --- THE BUG FIX IS HERE ---
                // We pass 'false' for writeThrough so the SSD can use its DRAM/SLC hardware caches normally.
                handle = OpenNativeFile(path, access, OPEN_EXISTING, isRandom, false, share, true);

                completionPort = CreateIoCompletionPort(handle, IntPtr.Zero, UIntPtr.Zero, 1);

                Random random = isRandom ? new Random(Environment.TickCount) : null;
                int completed = 0;
                int issued = 0;
                long nextSequentialBlock = 0;
                System.Collections.Generic.Dictionary<IntPtr, NativeIoSlot> slotByOverlapped = new System.Collections.Generic.Dictionary<IntPtr, NativeIoSlot>(queueDepth);

                Stopwatch stopwatch = new Stopwatch();
                stopwatch.Start();

                for (int i = 0; i < queueDepth && issued < operationLimit && (!timedRun || stopwatch.Elapsed.TotalSeconds < durationSeconds); i++) {
                    long blockIndex = isRandom ? random.Next((int)blockCount) : (nextSequentialBlock++ % blockCount);
                    long offset = blockIndex * blockSize;

                    Marshal.WriteIntPtr(slots[i].Overlapped, OverlappedInternalOffset, IntPtr.Zero);
                    Marshal.WriteIntPtr(slots[i].Overlapped, OverlappedInternalHighOffset, IntPtr.Zero);
                    Marshal.WriteInt32(slots[i].Overlapped, OverlappedOffsetOffset, unchecked((int)(offset & 0xFFFFFFFFL)));
                    Marshal.WriteInt32(slots[i].Overlapped, OverlappedOffsetHighOffset, unchecked((int)((offset >> 32) & 0xFFFFFFFFL)));
                    Marshal.WriteIntPtr(slots[i].Overlapped, OverlappedEventOffset, IntPtr.Zero);

                    uint ignored;
                    bool ok = isWrite ? WriteFile(handle, slots[i].Buffer, (uint)blockSize, out ignored, slots[i].Overlapped)
                                      : ReadFile(handle, slots[i].Buffer, (uint)blockSize, out ignored, slots[i].Overlapped);

                    int code = Marshal.GetLastWin32Error();
                    if (!ok && code != ERROR_IO_PENDING) throw new Win32Exception(code, "IO Error");

                    slotByOverlapped[slots[i].Overlapped] = slots[i];
                    issued++;
                }

                int completionEntrySize = Marshal.SizeOf(typeof(OverlappedEntry));
                IntPtr completionEntries = Marshal.AllocHGlobal(completionEntrySize * queueDepth);

                try {
                    while (completed < issued || (issued < operationLimit && (!timedRun || stopwatch.Elapsed.TotalSeconds < durationSeconds))) {
                        uint removed;
                        if (!GetQueuedCompletionStatusEx(completionPort, completionEntries, (uint)queueDepth, out removed, INFINITE, false)) {
                            throw LastError("GetQueuedCompletionStatusEx");
                        }

                        for (int i = 0; i < removed; i++) {
                            IntPtr entryPointer = IntPtr.Add(completionEntries, i * completionEntrySize);
                            IntPtr completedOverlapped = Marshal.ReadIntPtr(entryPointer, CompletionEntryOverlappedOffset);
                            NativeIoSlot slot = slotByOverlapped[completedOverlapped];
                            completed++;

                            if (issued < operationLimit && (!timedRun || stopwatch.Elapsed.TotalSeconds < durationSeconds)) {
                                long blockIndex = isRandom ? random.Next((int)blockCount) : (nextSequentialBlock++ % blockCount);
                                long offset = blockIndex * blockSize;

                                Marshal.WriteIntPtr(slot.Overlapped, OverlappedInternalOffset, IntPtr.Zero);
                                Marshal.WriteIntPtr(slot.Overlapped, OverlappedInternalHighOffset, IntPtr.Zero);
                                Marshal.WriteInt32(slot.Overlapped, OverlappedOffsetOffset, unchecked((int)(offset & 0xFFFFFFFFL)));
                                Marshal.WriteInt32(slot.Overlapped, OverlappedOffsetHighOffset, unchecked((int)((offset >> 32) & 0xFFFFFFFFL)));

                                uint ignored;
                                bool ok = isWrite ? WriteFile(handle, slot.Buffer, (uint)blockSize, out ignored, slot.Overlapped)
                                                  : ReadFile(handle, slot.Buffer, (uint)blockSize, out ignored, slot.Overlapped);

                                int code = Marshal.GetLastWin32Error();
                                if (!ok && code != ERROR_IO_PENDING) throw new Win32Exception(code, "IO Error");
                                issued++;
                            }
                        }
                    }
                }
                finally {
                    if (completionEntries != IntPtr.Zero) Marshal.FreeHGlobal(completionEntries);
                }

                stopwatch.Stop();
                return new BenchmarkMeasure { Bytes = (long)completed * blockSize, Operations = completed, Seconds = stopwatch.Elapsed.TotalSeconds };
            }
            finally {
                if (completionPort != IntPtr.Zero) CloseHandle(completionPort);
                if (handle != null) handle.Dispose();
                for (int i = 0; i < slots.Length; i++) { if (slots[i] != null) slots[i].Dispose(); }
            }
        }
    }
}
'@
                    }

                    function Measure-Drive {
                        param([string]$DriveLetter, [int]$FileSizeMb, [int]$BaseProgress, [int]$StepWeight)

                        $root = "{0}:\" -f $DriveLetter
                        $folder = [System.IO.Path]::Combine($root, "WMT_Benchmark_Data")
                        $file = [System.IO.Path]::Combine($folder, "wmt_io_test_{0}.dat" -f ([guid]::NewGuid().ToString("N")))

                        $seqBufferSize = 2MB
                        $randomBlockSize = 4KB
                        $targetBytes = [int64]$FileSizeMb * 1MB

                        $seqPeakQueueDepth = 8
                        $randomPeakQueueDepth = 32
                        $measureSeconds = 5.0
                        $useTimedMode = $FileSizeMb -lt 512
                        $activeMeasureSeconds = if ($useTimedMode) { $measureSeconds } else { 0.0 }

                        try {
                            try { if ($State["ActiveFiles"]) { [void]$State["ActiveFiles"].Add($file) } } catch {}
                            Initialize-NativeDiskBenchmark
                            Test-Cancelled

                            if (-not [System.IO.Directory]::Exists($folder)) { [void][System.IO.Directory]::CreateDirectory($folder) }

                            try {
                                foreach ($oldFile in [System.IO.Directory]::EnumerateFiles($folder, "wmt_io_test_*.dat")) {
                                    try { [System.IO.File]::Delete($oldFile) } catch {}
                                }
                            }
                            catch {}

                            Add-Line ("  Test file: {0}" -f $file)

                            Set-BenchmarkStatus "Allocating test file on $DriveLetter`..." $BaseProgress
                            [Wmt.NativeDiskBenchmark]::PrepareFile($file, $targetBytes)

                            if ($useTimedMode) { Add-Line ("  Mode: {0:N0}s measured loop per result (decimal MB/s)" -f $measureSeconds) }
                            else { Add-Line "  Mode: one full selected-size pass per result, no timer (decimal MB/s)" }

                            $runMeasure = {
                                param([string]$Label, [int]$Progress, [scriptblock]$Measure)
                                Set-BenchmarkStatus "Testing $DriveLetter`: $Label..." $Progress
                                Test-Cancelled
                                return & $Measure
                            }.GetNewClosure()

                            $seqQ8Write = & $runMeasure "SEQ2M Q8T1 write" $BaseProgress {
                                [Wmt.NativeDiskBenchmark]::MeasureQueued($file, $targetBytes, $seqBufferSize, $seqPeakQueueDepth, $activeMeasureSeconds, $true, $false)
                            }

                            $seqQ8Read = & $runMeasure "SEQ2M Q8T1 read" ($BaseProgress + $StepWeight) {
                                [Wmt.NativeDiskBenchmark]::MeasureQueued($file, $targetBytes, $seqBufferSize, $seqPeakQueueDepth, $activeMeasureSeconds, $false, $false)
                            }
                            Add-Line ("  SEQ2M Q8T1 Read  {0} MB/s | Write {1} MB/s" -f $seqQ8Read.MBps, $seqQ8Write.MBps)

                            $seqQ1Write = & $runMeasure "SEQ2M Q1T1 write" ($BaseProgress + ($StepWeight * 2)) {
                                [Wmt.NativeDiskBenchmark]::MeasureQueued($file, $targetBytes, $seqBufferSize, 1, $activeMeasureSeconds, $true, $false)
                            }

                            $seqQ1Read = & $runMeasure "SEQ2M Q1T1 read" ($BaseProgress + ($StepWeight * 3)) {
                                [Wmt.NativeDiskBenchmark]::MeasureQueued($file, $targetBytes, $seqBufferSize, 1, $activeMeasureSeconds, $false, $false)
                            }
                            Add-Line ("  SEQ2M Q1T1 Read  {0} MB/s | Write {1} MB/s" -f $seqQ1Read.MBps, $seqQ1Write.MBps)

                            $rndQ32Write = & $runMeasure "RND4K Q32T1 write" ($BaseProgress + ($StepWeight * 4)) {
                                [Wmt.NativeDiskBenchmark]::MeasureQueued($file, $targetBytes, $randomBlockSize, $randomPeakQueueDepth, $activeMeasureSeconds, $true, $true)
                            }

                            $rndQ32Read = & $runMeasure "RND4K Q32T1 read" ($BaseProgress + ($StepWeight * 5)) {
                                [Wmt.NativeDiskBenchmark]::MeasureQueued($file, $targetBytes, $randomBlockSize, $randomPeakQueueDepth, $activeMeasureSeconds, $false, $true)
                            }
                            Add-Line ("  RND4K Q32T1 Read  {0} MB/s ({1} IOPS) | Write {2} MB/s ({3} IOPS)" -f $rndQ32Read.MBps, $rndQ32Read.Iops, $rndQ32Write.MBps, $rndQ32Write.Iops)

                            $rndQ1Write = & $runMeasure "RND4K Q1T1 write" ($BaseProgress + ($StepWeight * 6)) {
                                [Wmt.NativeDiskBenchmark]::MeasureQueued($file, $targetBytes, $randomBlockSize, 1, $activeMeasureSeconds, $true, $true)
                            }

                            $rndQ1Read = & $runMeasure "RND4K Q1T1 read" ($BaseProgress + ($StepWeight * 7)) {
                                [Wmt.NativeDiskBenchmark]::MeasureQueued($file, $targetBytes, $randomBlockSize, 1, $activeMeasureSeconds, $false, $true)
                            }
                            Add-Line ("  RND4K Q1T1 Read  {0} MB/s ({1} IOPS) | Write {2} MB/s ({3} IOPS)" -f $rndQ1Read.MBps, $rndQ1Read.Iops, $rndQ1Write.MBps, $rndQ1Write.Iops)

                            Set-BenchmarkStatus "Completed $DriveLetter`." ($BaseProgress + ($StepWeight * 8))
                        }
                        finally {
                            try { if ([System.IO.File]::Exists($file)) { [System.IO.File]::Delete($file) } } catch {}
                            try { if ($State["ActiveFiles"]) { [void]$State["ActiveFiles"].Remove($file) } } catch {}
                            try {
                                if ([System.IO.Directory]::Exists($folder)) {
                                    $hasEntries = $false
                                    foreach ($entry in [System.IO.Directory]::EnumerateFileSystemEntries($folder)) {
                                        $hasEntries = $true
                                        break
                                    }
                                    if (-not $hasEntries) { [System.IO.Directory]::Delete($folder, $false) }
                                }
                            }
                            catch {}
                        }
                    }

                    try {
                        $targetDrive = [string]$State["TargetDrive"]
                        $targetSize = [int]$State["TargetSize"]

                        Set-BenchmarkStatus "Finding fixed drives..." 0
                        $drives = @([System.IO.DriveInfo]::GetDrives() | Where-Object { $_.DriveType -eq [System.IO.DriveType]::Fixed -and $_.IsReady })
                        if ($targetDrive -ne "ALL") {
                            $drives = @($drives | Where-Object { $_.Name.Substring(0, 1).ToUpperInvariant() -eq $targetDrive.ToUpperInvariant() })
                        }
                        if (-not $drives -or $drives.Count -eq 0) { throw "No suitable fixed drives were found." }

                        $driveHardwareMap = Get-BenchmarkDriveHardwareMap
                        $requiredBytes = ([int64]$targetSize * 1MB) + 96MB
                        $testableDrives = @($drives | Where-Object { [int64]$_.AvailableFreeSpace -ge $requiredBytes })

                        if (-not $testableDrives -or $testableDrives.Count -eq 0) { throw "Selected drive(s) do not have enough free space for a $targetSize MB benchmark." }

                        $totalSteps = [math]::Max(1, $testableDrives.Count * 8)
                        $stepWeight = [math]::Max(1, [int](100 / $totalSteps))
                        $stepIndex = 0

                        foreach ($driveInfo in $drives) {
                            Test-Cancelled
                            $driveLetter = $driveInfo.Name.Substring(0, 1)
                            $driveLabel = if ([string]::IsNullOrWhiteSpace($driveInfo.VolumeLabel)) { "(No label)" } else { $driveInfo.VolumeLabel }

                            $driveHardware = $null
                            if ($driveHardwareMap.ContainsKey($driveLetter)) { $driveHardware = [string]$driveHardwareMap[$driveLetter] }
                            $driveDisplayName = if ([string]::IsNullOrWhiteSpace($driveHardware)) { "{0}: {1}" -f $driveLetter, $driveLabel } else { "{0}: {1} - {2}" -f $driveLetter, $driveLabel, $driveHardware }

                            if ([int64]$driveInfo.AvailableFreeSpace -lt $requiredBytes) {
                                Add-Line ("{0} - skipped, not enough free space for a {1} MB test." -f $driveDisplayName, $targetSize)
                                continue
                            }

                            Add-Line ""
                            Add-Line ("{0} ({1} MiB test file)" -f $driveDisplayName, $targetSize)

                            $baseProgress = $stepIndex * $stepWeight
                            try { Measure-Drive -DriveLetter $driveLetter -FileSizeMb $targetSize -BaseProgress $baseProgress -StepWeight $stepWeight }
                            catch {
                                if ($State["Cancel"]) { throw }
                                Add-Line ("{0} - benchmark failed: {1}" -f $driveDisplayName, $_.Exception.Message)
                            }
                            $stepIndex += 8
                        }

                        Add-Line ""
                        Add-Line ("Completed: {0}" -f (Get-Date -Format "yyyy-MM-dd HH:mm:ss"))
                        Set-BenchmarkStatus "Benchmark complete." 100
                    }
                    catch {
                        if ($State["Cancel"]) {
                            $State["Error"] = ""
                            Add-Line ""; Add-Line "Benchmark stopped by user."
                            Set-BenchmarkStatus "Benchmark stopped." 100
                        }
                        else {
                            $State["Error"] = $_.Exception.Message
                            Add-Line ""; Add-Line ("ERROR: {0}" -f $_.Exception.Message)
                            Set-BenchmarkStatus "Benchmark failed." 100
                        }
                    }
                    finally {
                        $State["IsRunning"] = $false
                        $State["IsCompleted"] = $true
                    }
                }).AddArgument($state)

            $worker["Runspace"] = $runspace
            $worker["PowerShell"] = $ps
            $worker["StartedAt"] = Get-Date
            $worker["Async"] = $ps.BeginInvoke()
            $timer.Start()
        }
        catch {
            $state["IsRunning"] = $false
            $state["IsCompleted"] = $true
            $state["Error"] = $_.Exception.Message
            $state["Status"] = "Failed to start benchmark."
            $state["Progress"] = 100
            [void]$state["Lines"].Add(""); [void]$state["Lines"].Add("START ERROR: $($_.Exception.Message)")
            Set-WmtThemedBrush -Object $statusText -Property ([System.Windows.Controls.TextBlock]::ForegroundProperty) -ColorOrKey "Danger"

            & $refreshUi
            & $setRunningUi $false
            & $disposeWorker
            & $cleanupTrackedBenchmarkFiles
            Write-GuiLog "[Storage Benchmark] Start failed: $($_.Exception.Message)"
        }
    }.GetNewClosure()

    $btnRun.Add_Click({
            if ($state["IsRunning"]) { & $stopBenchmark } else { & $startBenchmark }
        }.GetNewClosure())

    $windowCleanup = {
        $state["Cancel"] = $true
        try { $timer.Stop() } catch {}
        try { if ($worker["PowerShell"] -and $state["IsRunning"]) { $worker["PowerShell"].Stop() } } catch {}
        & $disposeWorker
        & $cleanupTrackedBenchmarkFiles
        & $releaseWindowState
    }.GetNewClosure()

    $benchWindow.Add_Closing({ & $windowCleanup }.GetNewClosure())
    $benchWindow.Add_Closed({ & $releaseWindowState }.GetNewClosure())
    $benchWindow.Show() | Out-Null
}

function Expand-ShortcutTarget {
    param([string]$Target)
    if ([string]::IsNullOrWhiteSpace($Target)) { return "" }
    $trimmed = $Target.Trim().Trim('"')
    try { return [System.Environment]::ExpandEnvironmentVariables($trimmed) }
    catch { return $trimmed }
}

function Test-ShortcutTargetIsSpecial {
    param([string]$Target)
    if ([string]::IsNullOrWhiteSpace($Target)) { return $true }
    $trimmed = $Target.Trim().Trim('"')
    if ($trimmed -match '^shell:' -or $trimmed -match '^\s*::{') { return $true }
    if ($trimmed -match '^[a-zA-Z][a-zA-Z0-9+.-]+:' -and $trimmed -notmatch '^[a-zA-Z]:[\\/]') { return $true }
    try {
        if ($trimmed.IndexOfAny([System.IO.Path]::GetInvalidPathChars()) -ge 0) { return $true }
    }
    catch { return $true }
    return $false
}

function Show-BrokenShortcuts {
    $content = @"
    <Grid Margin="16">
        <Grid.RowDefinitions><RowDefinition Height="*"/><RowDefinition Height="Auto"/><RowDefinition Height="Auto"/></Grid.RowDefinitions>
        <DataGrid Name="dgShortcuts" IsReadOnly="True" SelectionMode="Extended" CanUserAddRows="False" CanUserDeleteRows="False" AlternationCount="2"/>
        <TextBlock Name="lblStatus" Grid.Row="1" Text="Ready." Foreground="{DynamicResource Warning}" Margin="0,10,0,0"/>
        <WrapPanel Grid.Row="2" HorizontalAlignment="Right" Margin="0,12,0,0">
            <Button Name="btnDelete" Content="Delete Now" MinWidth="106" Background="{DynamicResource Danger}" Foreground="{DynamicResource DangerText}" Margin="0,0,8,8"/>
            <Button Name="btnBrowse" Content="Browse" MinWidth="92" Margin="0,0,8,8"/>
            <Button Name="btnRescan" Content="Rescan" MinWidth="92" Margin="0,0,8,8"/>
            <Button Name="btnApply" Content="Apply Fixes" MinWidth="112" Background="{DynamicResource Success}" Foreground="{DynamicResource SuccessText}" Margin="0,0,8,8"/>
            <Button Name="btnClose" Content="Close" Width="92" IsCancel="True" Margin="0,0,8,8"/>
        </WrapPanel>
    </Grid>
"@
    $dialog = New-WmtWindowFromXaml -Title "Broken Shortcut Manager" -ContentXaml $content -Width 1220 -Height 720 -MinWidth 940 -MinHeight 560
    $dg = $dialog.FindName("dgShortcuts")
    $lblStatus = $dialog.FindName("lblStatus")
    $btnDelete = $dialog.FindName("btnDelete")
    $btnBrowse = $dialog.FindName("btnBrowse")
    $btnRescan = $dialog.FindName("btnRescan")
    $btnApply = $dialog.FindName("btnApply")
    $btnClose = $dialog.FindName("btnClose")

    $rows = [System.Collections.ObjectModel.ObservableCollection[object]]::new()
    $dg.ItemsSource = $rows
    Set-WmtDataGridColumns -DataGrid $dg -Columns @("Shortcut", "Location", "Action", "Details", "BrokenTarget", "NewTarget", "FullPath") -Widths @{ Shortcut = 150; Location = 210; Action = 90; Details = 180; BrokenTarget = "*"; NewTarget = "*" } -Hidden @("FullPath")
    $knownFixes = @{
        "This PC"       = "::{20D04FE0-3AEA-1069-A2D8-08002B30309D}"
        "My Computer"   = "::{20D04FE0-3AEA-1069-A2D8-08002B30309D}"
        "Recycle Bin"   = "::{645FF040-5081-101B-9F08-00AA002F954E}"
        "Control Panel" = "::{21EC2020-3AEA-1069-A2DD-08002B30309D}"
        "Documents"     = "::{450D8FBA-AD25-11D0-98A8-0800361B1103}"
    }

    $getRoots = {
        $roots = [System.Collections.Generic.List[string]]::new()
        $seen = @{}
        $paths = @(
            [Environment]::GetFolderPath('CommonStartMenu'),
            [Environment]::GetFolderPath('StartMenu'),
            [Environment]::GetFolderPath('CommonDesktopDirectory'),
            [Environment]::GetFolderPath('DesktopDirectory'),
            "$env:ProgramData\Microsoft\Windows\Start Menu",
            "$env:APPDATA\Microsoft\Windows\Start Menu",
            "$env:USERPROFILE\Desktop",
            "$env:PUBLIC\Desktop"
        )
        foreach ($pathItem in $paths) {
            if ([string]::IsNullOrWhiteSpace($pathItem) -or -not (Test-Path -LiteralPath $pathItem)) { continue }
            $full = ([System.IO.DirectoryInfo]::new($pathItem)).FullName.TrimEnd("\")
            $key = $full.ToUpperInvariant()
            if (-not $seen.ContainsKey($key)) { $seen[$key] = $true; [void]$roots.Add($full) }
        }
        return @($roots)
    }.GetNewClosure()

    $findAppTarget = {
        param([string]$FileName)
        if ([string]::IsNullOrWhiteSpace($FileName) -or $FileName -notmatch '\.exe$') { return $null }
        foreach ($hive in @([Microsoft.Win32.RegistryHive]::CurrentUser, [Microsoft.Win32.RegistryHive]::LocalMachine)) {
            $base = $null
            $key = $null
            try {
                $base = [Microsoft.Win32.RegistryKey]::OpenBaseKey($hive, [Microsoft.Win32.RegistryView]::Default)
                $key = $base.OpenSubKey("SOFTWARE\Microsoft\Windows\CurrentVersion\App Paths\$FileName")
                if ($key) {
                    $candidate = Expand-ShortcutTarget ([string]$key.GetValue(""))
                    if ([System.IO.File]::Exists($candidate)) { return $candidate }
                }
            }
            catch {}
            finally {
                try { if ($key) { $key.Close() } } catch {}
                try { if ($base) { $base.Close() } } catch {}
            }
        }
        foreach ($dir in @(([string]$env:Path).Split(";"))) {
            try {
                $candidate = Join-Path ([Environment]::ExpandEnvironmentVariables($dir.Trim())) $FileName
                if ([System.IO.File]::Exists($candidate)) { return $candidate }
            }
            catch {}
        }
        return $null
    }.GetNewClosure()

    $scan = {
        $rows.Clear()
        $lblStatus.Text = "Scanning shortcuts..."
        Set-WmtBusyCursor -Busy
        $shell = $null
        $scanned = 0
        try {
            $shell = New-Object -ComObject WScript.Shell
            foreach ($root in & $getRoots) {
                $lblStatus.Text = "Scanning $root"
                Invoke-WmtDispatcherPump -Dispatcher $dialog.Dispatcher
                foreach ($lnk in @(Get-ChildItem -LiteralPath $root -Filter *.lnk -Recurse -Force -ErrorAction SilentlyContinue)) {
                    $scanned++
                    try {
                        $sc = $shell.CreateShortcut($lnk.FullName)
                        $target = [string]$sc.TargetPath
                        if (Test-ShortcutTargetIsSpecial $target) { continue }
                        $expanded = Expand-ShortcutTarget $target
                        if ([System.IO.File]::Exists($expanded) -or [System.IO.Directory]::Exists($expanded)) { continue }
                        $action = "None"
                        $details = "Review Needed"
                        $newTarget = ""
                        if ($knownFixes.ContainsKey($lnk.BaseName)) {
                            $action = "Fix"; $details = "Restore System Path"; $newTarget = $knownFixes[$lnk.BaseName]
                        }
                        else {
                            $guess = [System.IO.Path]::GetFileName($expanded)
                            if ([string]::IsNullOrWhiteSpace($guess)) { $guess = "$($lnk.BaseName).exe" }
                            $candidate = & $findAppTarget $guess
                            if ($candidate) { $action = "Fix"; $details = "Located installed app"; $newTarget = $candidate }
                        }
                        [void]$rows.Add([PSCustomObject]@{
                                Shortcut = $lnk.Name; Location = $lnk.DirectoryName; Action = $action; Details = $details
                                BrokenTarget = $target; NewTarget = $newTarget; FullPath = $lnk.FullName
                            })
                    }
                    catch {}
                }
            }
            $lblStatus.Text = "Scan complete. Scanned $scanned shortcut(s); found $($rows.Count)."
            if ($rows.Count -eq 0) { Show-WmtMessageBox -Owner $dialog -Message "Scan complete. No broken shortcuts found." -Title "All Clean" -Image Information | Out-Null }
        }
        catch {
            Show-WmtMessageBox -Owner $dialog -Message "Shortcut scan failed:`n$($_.Exception.Message)" -Title "Scan Failed" -Image Error | Out-Null
        }
        finally {
            try { if ($shell) { [void][Runtime.InteropServices.Marshal]::ReleaseComObject($shell) } } catch {}
            Set-WmtBusyCursor
        }
    }.GetNewClosure()

    $selected = { @($dg.SelectedItems | Where-Object { $_ }) }.GetNewClosure()
    $btnBrowse.Add_Click({
            $item = (& $selected | Select-Object -First 1)
            if (-not $item) { return }
            $dlg = [Microsoft.Win32.OpenFileDialog]::new()
            $dlg.Filter = "Programs|*.exe;*.bat;*.cmd;*.lnk|All Files|*.*"
            if ($dlg.ShowDialog() -eq $true) {
                $item.Action = "Fix"
                $item.Details = "Manual Browse"
                $item.NewTarget = $dlg.FileName
                $dg.Items.Refresh()
            }
        }.GetNewClosure())
    $btnDelete.Add_Click({
            $items = & $selected
            if ($items.Count -eq 0) { return }
            if ((Show-WmtMessageBox -Owner $dialog -Message "Permanently delete $($items.Count) selected shortcut(s)?`n`nThis action is immediate." -Title "Confirm Delete" -Button YesNo -Image Warning) -ne [System.Windows.MessageBoxResult]::Yes) { return }
            foreach ($item in $items) {
                try { Remove-Item -LiteralPath ([string]$item.FullPath) -Force -ErrorAction Stop }
                catch { Show-WmtMessageBox -Owner $dialog -Message "Could not delete: $($item.FullPath)`n$($_.Exception.Message)" -Title "Delete Failed" -Image Error | Out-Null }
                [void]$rows.Remove($item)
            }
        }.GetNewClosure())

    $state = @{ Result = $null }
    $btnRescan.Add_Click({ & $scan }.GetNewClosure())
    $btnApply.Add_Click({ $state.Result = @($rows); $dialog.DialogResult = $true }.GetNewClosure())
    $btnClose.Add_Click({ $dialog.Close() }.GetNewClosure())
    $dg.Add_MouseDoubleClick({
            $item = (& $selected | Select-Object -First 1)
            if ($item) {
                Show-TextDialog -Title "Shortcut Details" -Text ("Shortcut: {0}`r`nLocation: {1}`r`nAction: {2}`r`nDetails: {3}`r`nBrokenTarget: {4}`r`nNewTarget: {5}`r`nFullPath: {6}" -f $item.Shortcut, $item.Location, $item.Action, $item.Details, $item.BrokenTarget, $item.NewTarget, $item.FullPath)
            }
        }.GetNewClosure())
    $dialog.Add_ContentRendered({ & $scan }.GetNewClosure())
    $dialog.ShowDialog() | Out-Null
    return $state.Result
}

function Invoke-ShortcutFix {
    $items = Show-BrokenShortcuts
    if (-not $items -or $items.Count -eq 0) { return }

    $toFix = @($items | Where-Object { $_.Action -eq "Fix" -and -not [string]::IsNullOrWhiteSpace([string]$_.FullPath) -and -not [string]::IsNullOrWhiteSpace([string]$_.NewTarget) })

    if ($toFix.Count -eq 0) {
        Show-WmtMessageBox -Message "No fixes were selected.`n`nUse Browse to pick a replacement target, or Delete Now to remove shortcuts immediately." -Title "No Action" -Image Information | Out-Null
        return
    }

    $msg = "You are about to fix $($toFix.Count) shortcut(s)."
    $msg += "`nAre you sure you want to continue?"

    $confirm = Show-WmtMessageBox -Message $msg -Title "Confirm Actions" -Button YesNo -Image Warning
    
    if ($confirm -ne [System.Windows.MessageBoxResult]::Yes) { return }

    Invoke-UiCommand {
        param($toFix)
        $shell = $null

        try {
            $shell = New-Object -ComObject WScript.Shell

            foreach ($item in $toFix) {
                try {
                    if (-not [System.IO.File]::Exists([string]$item.FullPath)) { throw "Shortcut file no longer exists." }
                    $newTarget = [string]$item.NewTarget
                    $sc = $shell.CreateShortcut([string]$item.FullPath)
                    $sc.TargetPath = $newTarget

                    if (-not (Test-ShortcutTargetIsSpecial $newTarget)) {
                        $expandedTarget = Expand-ShortcutTarget $newTarget
                        if ([System.IO.File]::Exists($expandedTarget)) {
                            $targetDir = [System.IO.Path]::GetDirectoryName($expandedTarget)
                            if (-not [string]::IsNullOrWhiteSpace($targetDir) -and [System.IO.Directory]::Exists($targetDir)) {
                                $sc.WorkingDirectory = $targetDir
                            }
                        }
                    }

                    $sc.Save()
                    Write-Output "Fixed: $($item.Shortcut) -> $newTarget"
                }
                catch { Write-Output "Failed to fix $($item.Shortcut): $($_.Exception.Message)" }
            }

            Write-Output "Shortcut operation complete."
        }
        finally {
            try { if ($shell) { [void][System.Runtime.InteropServices.Marshal]::ReleaseComObject($shell) } } catch {}
        }

    } "Applying shortcut fixes..." -ArgumentList $toFix
}

# --- FIREWALL TOOLS ---
function Invoke-FirewallExport {
    $target = Join-Path (Get-DataPath) ("firewall_rules_{0}.wfw" -f (Get-Date -Format "yyyyMMdd_HHmmss"))
    Invoke-UiCommand { param($target) netsh advfirewall export "$target" } "Exporting firewall rules..." -ArgumentList $target
}

function Invoke-FirewallImport {
    $dlg = [Microsoft.Win32.OpenFileDialog]::new()
    $dlg.Filter = "Windows Firewall Policy (*.wfw)|*.wfw"
    if ($dlg.ShowDialog() -ne $true) { return }
    $file = $dlg.FileName
    Invoke-UiCommand { param($file) netsh advfirewall import "$file" } "Importing firewall rules..." -ArgumentList $file
}

function Invoke-FirewallDefaults {
    $confirm = [System.Windows.MessageBox]::Show("Restore default Windows Firewall rules? Custom rules will be removed.", "Restore Defaults", [System.Windows.MessageBoxButton]::YesNo, [System.Windows.MessageBoxImage]::Warning)
    if ($confirm -ne "Yes") { return }
    Invoke-UiCommand { netsh advfirewall reset } "Restoring default firewall rules..."
}

function Invoke-FirewallPurge {
    $confirm = [System.Windows.MessageBox]::Show("Delete ALL firewall rules? This is destructive.", "Delete All Rules", [System.Windows.MessageBoxButton]::YesNo, [System.Windows.MessageBoxImage]::Warning)
    if ($confirm -ne "Yes") { return }
    Invoke-UiCommand { Remove-NetFirewallRule -All } "Deleting all firewall rules..."
}

# --- DRIVER TOOLS ---
function Invoke-DriverReport {
    Invoke-UiCommand {
        $outfile = Join-Path (Get-DataPath) "Installed_Drivers.txt"
        driverquery /v > $outfile
        Write-Output "Driver report saved to $outfile"
    } "Creating driver report..."
}

function Invoke-ExportDrivers {
    Write-GuiLog "Starting Driver Export Tool..."
    $dataPath = try { Get-DataPath } catch { Join-Path $env:PUBLIC "WMT_Exports" }

    Set-WmtBusyCursor -Busy
    try {
        $drivers = @()
        foreach ($d in @(Get-WindowsDriver -Online -All | Where-Object { $_.Inbox -eq $false })) {
            $classProbe = "$($d.ClassName) $($d.ProviderName)".ToLowerInvariant()
            $class = "Other"
            if ($classProbe -match "display|graphics|nvidia|amd|intel.*graphics") { $class = "Display" }
            elseif ($classProbe -match "net|network|wifi|ethernet|realtek|broadcom|intel.*network") { $class = "Network" }
            elseif ($classProbe -match "audio|sound") { $class = "Audio" }
            elseif ($classProbe -match "storage|sata|nvme|raid|disk") { $class = "Storage" }
            elseif ($classProbe -match "usb") { $class = "USB" }
            elseif ($classProbe -match "print") { $class = "Printer" }
            elseif ($classProbe -match "system|chipset|acpi") { $class = "System" }

            $drivers += [PSCustomObject]@{
                PublishedName = [string]$d.Driver
                OriginalName  = [string]$d.OriginalFileName
                Class         = $class
                Provider      = [string]$d.ProviderName
                Version       = [string]$d.Version
                Date          = if ($d.Date) { $d.Date.ToString("yyyy-MM-dd") } else { "" }
            }
        }
    }
    finally { Set-WmtBusyCursor }

    if (-not $drivers -or $drivers.Count -eq 0) {
        Show-WmtMessageBox -Message "No 3rd-party drivers found to export." -Title "Driver Export Tool" -Image Information | Out-Null
        return
    }

    $content = @"
    <Grid Margin="16">
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="*"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>
        <Grid Grid.Row="0" Margin="0,0,0,12">
            <Grid.ColumnDefinitions><ColumnDefinition Width="220"/><ColumnDefinition Width="*"/></Grid.ColumnDefinitions>
            <TextBlock Text="Class" Foreground="{DynamicResource TextSecondary}"/>
            <TextBox Name="txtSearch" Grid.Column="1" Height="34" VerticalContentAlignment="Center"/>
        </Grid>
        <Grid Grid.Row="1">
            <Grid.ColumnDefinitions><ColumnDefinition Width="220"/><ColumnDefinition Width="12"/><ColumnDefinition Width="*"/></Grid.ColumnDefinitions>
            <ListBox Name="lstClasses"/>
            <DataGrid Name="dgDrivers" Grid.Column="2" IsReadOnly="True" SelectionMode="Extended" CanUserAddRows="False" CanUserDeleteRows="False" AlternationCount="2"/>
        </Grid>
        <Grid Grid.Row="2" Margin="0,12,0,0">
            <TextBlock Name="lblStatus" Text="Ready" VerticalAlignment="Center" Foreground="{DynamicResource Accent}"/>
            <StackPanel Orientation="Horizontal" HorizontalAlignment="Right">
                <Button Name="btnExportSel" Content="Export Selected" MinWidth="128" Background="{DynamicResource Success}" Foreground="{DynamicResource SuccessText}" Margin="0,0,8,0"/>
                <Button Name="btnExportAll" Content="Export All" MinWidth="104" Margin="0,0,8,0"/>
                <Button Name="btnClose" Content="Close" Width="90" IsCancel="True"/>
            </StackPanel>
        </Grid>
    </Grid>
"@
    $dialog = New-WmtWindowFromXaml -Title "Driver Export Tool" -ContentXaml $content -Width 940 -Height 680 -MinWidth 760 -MinHeight 520
    $lstClasses = $dialog.FindName("lstClasses")
    $txtSearch = $dialog.FindName("txtSearch")
    $dg = $dialog.FindName("dgDrivers")
    $lblStatus = $dialog.FindName("lblStatus")
    $btnExportSel = $dialog.FindName("btnExportSel")
    $btnExportAll = $dialog.FindName("btnExportAll")
    $btnClose = $dialog.FindName("btnClose")

    Set-WmtDataGridColumns -DataGrid $dg -Columns @("PublishedName", "OriginalName", "Provider", "Version", "Date", "Class") -Widths @{ PublishedName = 130; OriginalName = "*"; Provider = 160; Version = 110; Date = 90; Class = 90 }
    $rows = [System.Collections.ObjectModel.ObservableCollection[object]]::new()
    $dg.ItemsSource = $rows

    $classes = @([PSCustomObject]@{ Display = "All ($($drivers.Count))"; Class = "" })
    $classes += @($drivers | Group-Object Class | Sort-Object Name | ForEach-Object { [PSCustomObject]@{ Display = "$($_.Name) ($($_.Count))"; Class = $_.Name } })
    $lstClasses.DisplayMemberPath = "Display"
    $lstClasses.ItemsSource = $classes
    $lstClasses.SelectedIndex = 0

    $refresh = {
        $rows.Clear()
        $selectedClass = if ($lstClasses.SelectedItem) { [string]$lstClasses.SelectedItem.Class } else { "" }
        $search = ([string]$txtSearch.Text).Trim().ToLowerInvariant()
        foreach ($d in @($drivers)) {
            if ($selectedClass -and $d.Class -ne $selectedClass) { continue }
            $haystack = "$($d.PublishedName) $($d.OriginalName) $($d.Provider) $($d.Version)".ToLowerInvariant()
            if ($search -and -not $haystack.Contains($search)) { continue }
            [void]$rows.Add($d)
        }
        $lblStatus.Text = "$($rows.Count) shown / $($drivers.Count) drivers"
    }.GetNewClosure()

    $exportDrivers = {
        param([object[]]$DriversToExport)
        $targets = @($DriversToExport | Where-Object { $_ })
        if ($targets.Count -eq 0) {
            Show-WmtMessageBox -Owner $dialog -Message "Please select at least one driver to export." -Title "Driver Export Tool" -Image Warning | Out-Null
            return
        }

        $exportPath = Join-Path $dataPath "Drivers_Backup_$(Get-Date -Format yyyyMMdd_HHmm)"
        New-Item -ItemType Directory -Path $exportPath -Force | Out-Null
        Set-WmtBusyCursor -Busy
        $dialog.IsEnabled = $false
        try {
            $done = 0
            foreach ($drv in $targets) {
                $done++
                $lblStatus.Text = "Exporting $done / $($targets.Count): $($drv.PublishedName)"
                Invoke-WmtDispatcherPump -Dispatcher $dialog.Dispatcher
                $dir = Join-Path $exportPath $drv.Class
                if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
                $process = Start-Process pnputil -ArgumentList "/export-driver", $drv.PublishedName, "`"$dir`"" -NoNewWindow -Wait -PassThru
                if ($process.ExitCode -ne 0) { Write-GuiLog "Driver export failed for $($drv.PublishedName) (exit $($process.ExitCode))." }
            }
            $lblStatus.Text = "Done"
            Show-WmtMessageBox -Owner $dialog -Message "Export Complete!`n`nSaved to:`n$exportPath" -Title "Success" -Image Information | Out-Null
        }
        catch {
            $lblStatus.Text = "Error"
            Show-WmtMessageBox -Owner $dialog -Message "An error occurred during export:`n`n$($_.Exception.Message)" -Title "Error" -Image Error | Out-Null
        }
        finally {
            $dialog.IsEnabled = $true
            Set-WmtBusyCursor
        }
    }.GetNewClosure()

    $lstClasses.Add_SelectionChanged({ & $refresh }.GetNewClosure())
    $txtSearch.Add_TextChanged({ & $refresh }.GetNewClosure())
    $btnExportSel.Add_Click({ & $exportDrivers -DriversToExport @($dg.SelectedItems) }.GetNewClosure())
    $btnExportAll.Add_Click({ & $exportDrivers -DriversToExport @($drivers) }.GetNewClosure())
    $btnClose.Add_Click({ $dialog.Close() }.GetNewClosure())
    & $refresh
    $dialog.ShowDialog() | Out-Null
}


function Show-GhostDevicesDialog {
    $content = @"
    <Grid Margin="16">
        <Grid.RowDefinitions>
            <RowDefinition Height="*"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>
        <DataGrid Name="dgGhost" IsReadOnly="True" CanUserAddRows="False" CanUserDeleteRows="False" AlternationCount="2"/>
        <StackPanel Grid.Row="1" Orientation="Horizontal" HorizontalAlignment="Right" Margin="0,12,0,0">
            <Button Name="btnRefresh" Content="Refresh" Width="104" Margin="0,0,8,0" Background="{DynamicResource Accent}" Foreground="{DynamicResource AccentText}"/>
            <Button Name="btnRemoveSel" Content="Remove Selected" MinWidth="132" Margin="0,0,8,0" Background="{DynamicResource Danger}" Foreground="{DynamicResource DangerText}"/>
            <Button Name="btnRemoveAll" Content="Remove All" Width="108" Margin="0,0,8,0" Background="{DynamicResource Danger}" Foreground="{DynamicResource DangerText}"/>
            <Button Name="btnClose" Content="Close" Width="90" IsCancel="True"/>
        </StackPanel>
    </Grid>
"@
    $dialog = New-WmtWindowFromXaml -Title "Ghost Devices" -ContentXaml $content -Width 840 -Height 520 -MinWidth 680 -MinHeight 420
    $dg = $dialog.FindName("dgGhost")
    $btnRefresh = $dialog.FindName("btnRefresh")
    $btnRemoveSel = $dialog.FindName("btnRemoveSel")
    $btnRemoveAll = $dialog.FindName("btnRemoveAll")
    $btnClose = $dialog.FindName("btnClose")

    $items = [System.Collections.ObjectModel.ObservableCollection[object]]::new()
    $dg.ItemsSource = $items
    Set-WmtDataGridColumns -DataGrid $dg -Columns @("InstanceId", "Class", "FriendlyName") -Widths @{ InstanceId = "*"; Class = 120; FriendlyName = 260 }

    $load = {
        $items.Clear()
        Set-WmtBusyCursor -Busy
        try {
            foreach ($d in @(Get-PnpDevice -ErrorAction SilentlyContinue | Where-Object { $_.Status -eq 'Unknown' })) {
                [void]$items.Add([PSCustomObject]@{
                        InstanceId   = [string]$d.InstanceId
                        Class        = [string]$d.Class
                        FriendlyName = [string]$d.FriendlyName
                    })
            }
            if ($items.Count -eq 0) {
                Show-WmtMessageBox -Owner $dialog -Message "No hidden/ghost devices found." -Title "Ghost Devices" -Image Information | Out-Null
            }
        }
        finally { Set-WmtBusyCursor }
    }.GetNewClosure()

    $removeRows = {
        param([object[]]$Rows)
        foreach ($row in @($Rows)) {
            $id = [string]$row.InstanceId
            if (-not [string]::IsNullOrWhiteSpace($id)) { pnputil /remove-device $id | Out-Null }
        }
        & $load
    }.GetNewClosure()

    $btnRefresh.Add_Click({ & $load }.GetNewClosure())
    $btnRemoveSel.Add_Click({ & $removeRows -Rows @($dg.SelectedItems) }.GetNewClosure())
    $btnRemoveAll.Add_Click({ & $removeRows -Rows @($items) }.GetNewClosure())
    $btnClose.Add_Click({ $dialog.Close() }.GetNewClosure())
    $dialog.Add_ContentRendered({ & $load }.GetNewClosure())
    $dialog.ShowDialog() | Out-Null
}


function Invoke-DriverUpdates {
    param([bool]$Enable)
    $value = if ($Enable) { 0 } else { 1 }
    $msg = if ($Enable) { "Enabled automatic driver updates." } else { "Disabled automatic driver updates." }
    Invoke-UiCommand {
        param($value, $msg)
        $path = "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\DriverSearching"
        if (-not (Test-Path $path)) { New-Item -Path $path -Force | Out-Null }
        Set-ItemProperty -Path $path -Name "SearchOrderConfig" -Value $value -Type DWord
        Write-Output $msg
    } "Updating driver update policy..." -ArgumentList $value, $msg
}

function Invoke-DeviceMetadata {
    param([bool]$Enable)
    $value = if ($Enable) { 0 } else { 1 }
    $msg = if ($Enable) { "Device metadata downloads enabled." } else { "Device metadata downloads disabled." }
    Invoke-UiCommand {
        param($value, $msg)
        $path = "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Device Metadata"
        if (-not (Test-Path $path)) { New-Item -Path $path -Force | Out-Null }
        Set-ItemProperty -Path $path -Name "PreventDeviceMetadataFromNetwork" -Value $value -Type DWord
        Write-Output $msg
    } "Updating device metadata policy..." -ArgumentList $value, $msg
}

function Show-DriverCleanupDialog {
    $rawOutput = pnputil.exe /enum-drivers 2>&1
    $drivers = @()
    $current = $null

    foreach ($line in $rawOutput) {
        $line = $line.ToString().Trim()
        if (-not $line.Contains(":")) { continue }

        $parts = $line -split ":", 2
        $key = $parts[0].Trim()
        $val = $parts[1].Trim()
        if ($val -match '^(oem\d+\.inf)$') {
            if ($current) { $drivers += [PSCustomObject]$current }
            $current = [ordered]@{
                PublishedName = $val
                OriginalName  = $null
                Provider      = "Unknown"
                Version       = [Version]"0.0.0.0"
                DisplayVer    = "Unknown"
                SortDate      = [DateTime]::MinValue
                DisplayDate   = "Unknown"
            }
            continue
        }

        if (-not $current) { continue }
        if ($key -match "Original Name" -and $val -notmatch '^oem\d+\.inf$') { $current.OriginalName = $val }
        elseif ($key -match "Provider") { $current.Provider = $val }
        elseif ($key -match "Version") {
            if ($val -match '(\d+(\.\d+){1,3})') {
                $current.DisplayVer = $matches[1]
                try { $current.Version = [Version]$matches[1] } catch {}
            }
            else { $current.DisplayVer = $val }
            if ($current.DisplayDate -eq "Unknown" -and $val -match '(\d{2}[/\-]\d{2}[/\-]\d{4})' -and ($matches[1] -as [DateTime])) {
                $current.DisplayDate = $matches[1]
                $current.SortDate = [DateTime]$matches[1]
            }
        }
        elseif ($key -match "Date") {
            if ($val -as [DateTime]) { $current.DisplayDate = $val; $current.SortDate = [DateTime]$val }
            elseif ($val -match '(\d{2}[/\-]\d{2}[/\-]\d{4})' -and ($matches[1] -as [DateTime])) { $current.DisplayDate = $matches[1]; $current.SortDate = [DateTime]$matches[1] }
        }
        elseif ($null -eq $current.OriginalName -and $val -match '\.inf$') { $current.OriginalName = $val }
    }
    if ($current) { $drivers += [PSCustomObject]$current }

    $toDelete = @()
    foreach ($group in @($drivers | Where-Object { $_.OriginalName } | Group-Object OriginalName)) {
        if ($group.Count -gt 1) { $toDelete += @($group.Group | Sort-Object SortDate, Version -Descending | Select-Object -Skip 1) }
    }

    if (-not $toDelete -or $toDelete.Count -eq 0) {
        Show-WmtMessageBox -Message "Driver store is already clean. No duplicates found." -Title "Clean Old Drivers" -Image Information | Out-Null
        return
    }

    $content = @"
    <Grid Margin="16">
        <Grid.RowDefinitions>
            <RowDefinition Height="*"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>
        <DataGrid Name="dgDrivers" IsReadOnly="True" CanUserAddRows="False" CanUserDeleteRows="False" AlternationCount="2"/>
        <Grid Grid.Row="1" Margin="0,12,0,0">
            <StackPanel Orientation="Horizontal" HorizontalAlignment="Left">
                <Button Name="btnRemoveAll" Content="Remove All" MinWidth="116" Background="{DynamicResource Success}" Foreground="{DynamicResource SuccessText}" Margin="0,0,8,0"/>
                <Button Name="btnRemoveSel" Content="Remove Selected" MinWidth="140" Background="{DynamicResource Danger}" Foreground="{DynamicResource DangerText}"/>
            </StackPanel>
            <Button Name="btnClose" Content="Close" Width="90" HorizontalAlignment="Right" IsCancel="True"/>
        </Grid>
    </Grid>
"@
    $dialog = New-WmtWindowFromXaml -Title "Clean Old Drivers" -ContentXaml $content -Width 960 -Height 620 -MinWidth 760 -MinHeight 480
    $dg = $dialog.FindName("dgDrivers")
    $btnRemoveAll = $dialog.FindName("btnRemoveAll")
    $btnRemoveSel = $dialog.FindName("btnRemoveSel")
    $btnClose = $dialog.FindName("btnClose")

    $currentList = [System.Collections.Generic.List[object]]::new()
    foreach ($item in @($toDelete)) { [void]$currentList.Add($item) }
    $rows = [System.Collections.ObjectModel.ObservableCollection[object]]::new()
    $dg.ItemsSource = $rows
    Set-WmtDataGridColumns -DataGrid $dg -Columns @("PublishedName", "OriginalName", "Provider", "Version", "Date") -Widths @{ PublishedName = 120; OriginalName = "*"; Provider = 180; Version = 120; Date = 110 }

    $loadGrid = {
        $rows.Clear()
        foreach ($d in @($currentList.ToArray())) {
            [void]$rows.Add([PSCustomObject]@{
                    PublishedName = [string]$d.PublishedName
                    OriginalName  = [string]$d.OriginalName
                    Provider      = [string]$d.Provider
                    Version       = [string]$d.DisplayVer
                    Date          = [string]$d.DisplayDate
                    Source        = $d
                })
        }
        $dialog.Title = "Clean Old Drivers ($($rows.Count) duplicate package(s))"
    }.GetNewClosure()

    $chooseCleanupMode = {
        param([int]$Count)
        $choiceContent = @"
    <Grid Margin="18">
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>
        <TextBlock Name="lblPrompt" TextWrapping="Wrap"/>
        <StackPanel Grid.Row="1" Orientation="Horizontal" HorizontalAlignment="Right" Margin="0,18,0,0">
            <Button Name="btnBackup" Content="Backup and Clean" MinWidth="132" Background="{DynamicResource Success}" Foreground="{DynamicResource SuccessText}" Margin="0,0,8,0"/>
            <Button Name="btnNoBackup" Content="Clean Only" MinWidth="112" Background="{DynamicResource Danger}" Foreground="{DynamicResource DangerText}" Margin="0,0,8,0"/>
            <Button Name="btnCancel" Content="Cancel" Width="92" IsCancel="True"/>
        </StackPanel>
    </Grid>
"@
        $choice = New-WmtWindowFromXaml -Title "Confirm Driver Cleanup" -ContentXaml $choiceContent -Width 470 -Height 170 -NoResize
        try { $choice.Owner = $dialog } catch {}
        $choice.FindName("lblPrompt").Text = "You are about to remove $Count driver package(s). How would you like to proceed?"
        $state = @{ Result = "Cancel" }
        $choice.FindName("btnBackup").Add_Click({ $state.Result = "Backup"; $choice.DialogResult = $true }.GetNewClosure())
        $choice.FindName("btnNoBackup").Add_Click({ $state.Result = "NoBackup"; $choice.DialogResult = $true }.GetNewClosure())
        $choice.FindName("btnCancel").Add_Click({ $choice.Close() }.GetNewClosure())
        $choice.ShowDialog() | Out-Null
        return $state.Result
    }.GetNewClosure()

    $doRemove = {
        param([object[]]$Items, [bool]$CloseWindow)
        $itemsToRemove = @($Items | ForEach-Object { if ($_.PSObject.Properties["Source"]) { $_.Source } else { $_ } })
        if ($itemsToRemove.Count -eq 0) { return }

        $mode = & $chooseCleanupMode -Count $itemsToRemove.Count
        if ($mode -eq "Cancel") { return }

        Set-WmtBusyCursor -Busy
        $backupCount = 0
        $timestamp = Get-Date -Format 'yyyyMMdd_HHmm'
        $mainBkPath = Join-Path (Get-DataPath) "Drivers_Backup_$timestamp"
        try {
            if ($mode -eq "Backup") {
                if (-not (Test-Path $mainBkPath)) { New-Item -Path $mainBkPath -ItemType Directory -Force | Out-Null }
                $i = 1
                foreach ($item in $itemsToRemove) {
                    $dialog.Title = "Backing up ($i/$($itemsToRemove.Count)): $($item.OriginalName)..."
                    Invoke-WmtDispatcherPump -Dispatcher $dialog.Dispatcher
                    $folderName = if ($item.OriginalName) { $item.OriginalName } else { $item.PublishedName }
                    $drvPath = Join-Path $mainBkPath $folderName
                    New-Item -Path $drvPath -ItemType Directory -Force | Out-Null
                    $proc = Start-Process pnputil.exe -ArgumentList "/export-driver", $item.PublishedName, "`"$drvPath`"" -NoNewWindow -Wait -PassThru
                    if ($proc.ExitCode -eq 0) { $backupCount++ }
                    $i++
                }
            }

            $deleted = 0
            $failed = 0
            foreach ($item in $itemsToRemove) {
                $name = [string]$item.PublishedName
                $dialog.Title = "Removing $name..."
                Invoke-WmtDispatcherPump -Dispatcher $dialog.Dispatcher
                $p = [System.Diagnostics.Process]::new()
                $p.StartInfo.FileName = "pnputil.exe"
                $p.StartInfo.Arguments = "/delete-driver $name /uninstall"
                $p.StartInfo.RedirectStandardOutput = $true
                $p.StartInfo.RedirectStandardError = $true
                $p.StartInfo.UseShellExecute = $false
                $p.StartInfo.CreateNoWindow = $true
                $p.Start() | Out-Null
                $stdOut = $p.StandardOutput.ReadToEnd()
                $stdErr = $p.StandardError.ReadToEnd()
                $p.WaitForExit()
                if ($p.ExitCode -eq 0 -or $p.ExitCode -eq 3010) { $deleted++ }
                else {
                    $warnMsg = "Driver: $($item.OriginalName) ($name)`n`nError:`n$($stdOut)`n$($stdErr)`n`nForce delete?"
                    if ((Show-WmtMessageBox -Owner $dialog -Message $warnMsg -Title "Deletion Failed" -Button YesNo -Image Error) -eq [System.Windows.MessageBoxResult]::Yes) {
                        $procForce = Start-Process pnputil.exe -ArgumentList "/delete-driver $name /uninstall /force" -NoNewWindow -Wait -PassThru
                        if ($procForce.ExitCode -eq 0 -or $procForce.ExitCode -eq 3010) { $deleted++ } else { $failed++ }
                    }
                    else { $failed++ }
                }
            }

            $resMsg = "Done.`nDeleted: $deleted`nFailed: $failed"
            if ($mode -eq "Backup") { $resMsg += "`nBackups: $backupCount`nPath: $mainBkPath" }
            Show-WmtMessageBox -Owner $dialog -Message $resMsg -Title "Result" -Image Information | Out-Null

            if ($deleted -gt 0) {
                foreach ($item in $itemsToRemove) {
                    for ($idx = $currentList.Count - 1; $idx -ge 0; $idx--) {
                        if ($currentList[$idx].PublishedName -eq $item.PublishedName) { $currentList.RemoveAt($idx) }
                    }
                }
                & $loadGrid
            }
        }
        finally {
            $dialog.Title = "Clean Old Drivers"
            Set-WmtBusyCursor
        }
        if ($CloseWindow) { $dialog.Close() }
    }.GetNewClosure()

    $btnRemoveAll.Add_Click({ & $doRemove -Items @($currentList.ToArray()) -CloseWindow $true }.GetNewClosure())
    $btnRemoveSel.Add_Click({ & $doRemove -Items @($dg.SelectedItems) -CloseWindow $false }.GetNewClosure())
    $btnClose.Add_Click({ $dialog.Close() }.GetNewClosure())
    & $loadGrid
    $dialog.ShowDialog() | Out-Null
}


# --- RESTORE DRIVERS ---
function Invoke-RestoreDrivers {
    $dataPath = Get-DataPath
    $backups = @()
    try {
        $backups = @([System.IO.Directory]::EnumerateDirectories($dataPath) | ForEach-Object { [System.IO.DirectoryInfo]::new($_) } | Where-Object { $_.Name -match '^DriverBackup_' -or $_.Name -match '^Drivers_Backup_' })
    }
    catch {}

    $selectedPath = $null
    if ($backups -and $backups.Count -gt 0) {
        $items = @($backups | Sort-Object LastWriteTime -Descending | ForEach-Object {
                [PSCustomObject]@{
                    Name    = $_.Name
                    Path    = $_.FullName
                    Display = "{0}  (modified {1})" -f $_.Name, $_.LastWriteTime
                }
            })

        $content = @"
    <Grid Margin="16">
        <Grid.RowDefinitions>
            <RowDefinition Height="*"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>
        <ListBox Name="lstBackups" DisplayMemberPath="Display"/>
        <StackPanel Grid.Row="1" Orientation="Horizontal" HorizontalAlignment="Right" Margin="0,12,0,0">
            <Button Name="btnUse" Content="Use Selected" MinWidth="118" Background="{DynamicResource Success}" Foreground="{DynamicResource SuccessText}" Margin="0,0,8,0"/>
            <Button Name="btnBrowse" Content="Browse" Width="96" Margin="0,0,8,0"/>
            <Button Name="btnCancel" Content="Cancel" Width="96" IsCancel="True"/>
        </StackPanel>
    </Grid>
"@
        $dialog = New-WmtWindowFromXaml -Title "Select Driver Backup" -ContentXaml $content -Width 640 -Height 420 -MinWidth 520 -MinHeight 340
        $lstBackups = $dialog.FindName("lstBackups")
        $btnUse = $dialog.FindName("btnUse")
        $btnBrowse = $dialog.FindName("btnBrowse")
        $btnCancel = $dialog.FindName("btnCancel")
        $lstBackups.ItemsSource = $items
        if ($items.Count -gt 0) { $lstBackups.SelectedIndex = 0 }
        $dialogState = @{ Browse = $false; Selected = $null }
        $btnUse.Add_Click({ if ($lstBackups.SelectedItem) { $dialogState.Selected = [string]$lstBackups.SelectedItem.Path; $dialog.DialogResult = $true } }.GetNewClosure())
        $btnBrowse.Add_Click({ $dialogState.Browse = $true; $dialog.DialogResult = $true }.GetNewClosure())
        $btnCancel.Add_Click({ $dialog.Close() }.GetNewClosure())
        $dialog.ShowDialog() | Out-Null
        if ($dialogState.Selected) { $selectedPath = $dialogState.Selected }
        elseif (-not $dialogState.Browse) { return }
    }

    if (-not $selectedPath) {
        $selectedPath = Select-WmtFolder -Description "Select DriverBackup folder" -InitialDirectory $dataPath
        if ([string]::IsNullOrWhiteSpace($selectedPath)) { return }
    }

    Invoke-UiCommand {
        param($Path)
        if (-not (Test-Path $Path)) {
            Write-Output "Restore failed: path not found $Path"
            Show-WmtMessageBox -Message "Restore failed: path not found.`n$Path" -Title "Restore Drivers" -Image Error | Out-Null
            return
        }

        $firstInf = Find-WmtFirstEnumeratedFile -Path $Path -Filter "*.inf"
        if (-not $firstInf) {
            Write-Output "Restore aborted: no INF files found in $Path"
            Show-WmtMessageBox -Message "No INF files found in:`n$Path" -Title "Restore Drivers" -Image Warning | Out-Null
            return
        }

        $output = pnputil.exe /add-driver "$Path\*.inf" /subdirs 2>&1
        $code = $LASTEXITCODE
        Write-Output $output
        if ($code -eq 0 -or $code -eq 3010) {
            Write-Output "Drivers restored from $Path"
            Show-WmtMessageBox -Message "Drivers restored from:`n$Path" -Title "Restore Drivers" -Image Information | Out-Null
        }
        else {
            Write-Output "Restore failed (exit $code)."
            $msg = "Restore failed (exit $code)." + "`n`nOutput:`n" + ($output | Out-String)
            Show-WmtMessageBox -Message $msg -Title "Restore Drivers" -Image Error | Out-Null
        }
    } "Restoring drivers..." -ArgumentList $selectedPath
}


# --- UPDATE / REPORT TOOLS ---
function Invoke-WindowsUpdateRepairFull {
    Invoke-UiCommand {
        $services = @('wuauserv', 'bits', 'cryptsvc', 'msiserver', 'usosvc', 'trustedinstaller')
        foreach ($svc in $services) { try { Stop-Service -Name $svc -Force -ErrorAction SilentlyContinue } catch {} }
        try { Get-BitsTransfer -AllUsers | Remove-BitsTransfer -Confirm:$false } catch {}
        $suffix = ".bak_{0}" -f (Get-Random -Maximum 99999)
        if (Test-Path "$env:windir\\SoftwareDistribution") { try { Rename-Item "$env:windir\\SoftwareDistribution" ("SoftwareDistribution" + $suffix) -ErrorAction SilentlyContinue; Write-Output "Renamed SoftwareDistribution$suffix" } catch {} }
        if (Test-Path "$env:windir\\System32\\catroot2") { try { Rename-Item "$env:windir\\System32\\catroot2" ("catroot2" + $suffix) -ErrorAction SilentlyContinue; Write-Output "Renamed catroot2$suffix" } catch {} }
        $dlls = @("atl.dll", "urlmon.dll", "mshtml.dll", "shdocvw.dll", "browseui.dll", "jscript.dll", "vbscript.dll", "scrrun.dll", "msxml.dll", "msxml3.dll", "msxml6.dll", "actxprxy.dll", "softpub.dll", "wintrust.dll", "dssenh.dll", "rsaenh.dll", "gpkcsp.dll", "sccbase.dll", "slbcsp.dll", "cryptdlg.dll", "oleaut32.dll", "ole32.dll", "shell32.dll", "initpki.dll", "wuapi.dll", "wuaueng.dll", "wuaueng1.dll", "wucltui.dll", "wups.dll", "wups2.dll", "wuweb.dll", "qmgr.dll", "qmgrprxy.dll", "wucltux.dll", "muweb.dll", "wuwebv.dll")
        foreach ($dll in $dlls) { try { regsvr32.exe /s $dll } catch {} }
        try { netsh winsock reset | Out-Null } catch {}
        try { netsh winhttp reset proxy | Out-Null } catch {}
        foreach ($svc in $services) { try { Start-Service -Name $svc -ErrorAction SilentlyContinue } catch {} }
        Write-Output "Windows Update repair completed."
    } "Running full Windows Update repair..."
}

function Invoke-SystemReports {
    $selectedFolder = Select-WmtFolder -Description "Select output folder for system reports" -InitialDirectory (Get-DataPath)
    if ([string]::IsNullOrWhiteSpace($selectedFolder)) { return }
    $outdir = Join-Path $selectedFolder ("SystemReports_{0}" -f (Get-Date -Format "yyyy-MM-dd_HHmm"))
    if (-not (Test-Path $outdir)) { New-Item -ItemType Directory -Path $outdir | Out-Null }
    
    Invoke-UiCommand {
        param($outdir)
        $date = Get-Date -Format "yyyy-MM-dd"
        $sys = Join-Path $outdir "System_Info_$date.txt"
        $net = Join-Path $outdir "Network_Info_$date.txt"
        $drv = Join-Path $outdir "Driver_List_$date.txt"
        systeminfo | Out-File -FilePath $sys -Encoding UTF8
        ipconfig /all | Out-File -FilePath $net -Encoding UTF8
        driverquery | Out-File -FilePath $drv -Encoding UTF8
        Write-Output "Reports saved to $outdir"
        # CHANGE IS HERE: Passing the argument explicitly
    } "Generating system reports..." -ArgumentList $outdir
}

function Invoke-UpdateServiceReset {
    Invoke-UiCommand {
        try {
            $script:UpdateSvcResult = "OK"
            Stop-Service -Name wuauserv -Force -ErrorAction SilentlyContinue
            Stop-Service -Name cryptsvc -Force -ErrorAction SilentlyContinue
            Start-Service -Name appidsvc -ErrorAction SilentlyContinue
            Start-Service -Name wuauserv -ErrorAction SilentlyContinue
            Start-Service -Name cryptsvc -ErrorAction SilentlyContinue
            Start-Service -Name bits -ErrorAction SilentlyContinue
            Write-Output "Restarted Windows Update related services."
        }
        catch {
            $script:UpdateSvcResult = "ERR: $($_.Exception.Message)"
            throw
        }
    } "Restarting Windows Update services..."
}

function Set-DotNetRollForward {
    param([string]$Mode)
    switch ($Mode) {
        "Runtime" { [System.Environment]::SetEnvironmentVariable("DOTNET_ROLL_FORWARD", "LatestMajor", "Machine"); Write-Output "Runtime roll-forward enabled (LatestMajor)." }
        "SDK" {
            $latestSdk = & dotnet --list-sdks | Sort-Object -Descending | Select-Object -First 1
            if ($latestSdk) {
                $version = $latestSdk.Split()[0]
                $globalJsonPath = "$env:USERPROFILE\global.json"
                @{
                    sdk = @{
                        version     = $version
                        rollForward = "latestMajor"
                    }
                } | ConvertTo-Json -Depth 3 | Out-File -Encoding UTF8 $globalJsonPath
                Write-Output "SDK roll-forward set to $version (global.json at $globalJsonPath)."
            }
            else { Write-Output "No SDK detected." }
        }
        "Both" {
            [System.Environment]::SetEnvironmentVariable("DOTNET_ROLL_FORWARD", "LatestMajor", "Machine")
            $latestSdk = & dotnet --list-sdks | Sort-Object -Descending | Select-Object -First 1
            if ($latestSdk) {
                $version = $latestSdk.Split()[0]
                $globalJsonPath = "$env:USERPROFILE\global.json"
                @{
                    sdk = @{
                        version     = $version
                        rollForward = "latestMajor"
                    }
                } | ConvertTo-Json -Depth 3 | Out-File -Encoding UTF8 $globalJsonPath
            }
            Write-Output "Runtime + SDK roll-forward configured."
        }
        "Disable" {
            [System.Environment]::SetEnvironmentVariable("DOTNET_ROLL_FORWARD", $null, "Machine")
            $globalJsonPath = "$env:USERPROFILE\global.json"
            if (Test-Path $globalJsonPath) {
                try {
                    $json = Get-Content $globalJsonPath -Raw | ConvertFrom-Json
                    if ($json.sdk.rollForward) { $json.sdk.PSObject.Properties.Remove("rollForward"); $json | ConvertTo-Json -Depth 3 | Out-File -Encoding UTF8 $globalJsonPath }
                }
                catch {}
            }
            Write-Output ".NET roll-forward disabled."
        }
    }
}

function Invoke-MASActivation {
    $masInput = Show-WmtInputDialog -Title "MAS Activation Confirmation" -Prompt "Type YES, I UNDERSTAND to download and run MAS from massgrave.dev"
    if ($masInput -ne "YES, I UNDERSTAND") { return }
    Invoke-UiCommand {
        $scriptContent = Invoke-RestMethod -Uri "https://get.activated.win"
        Invoke-Expression -Command $scriptContent
        Write-Output "MAS script executed."
    } "Running MAS activation..."
}

function Show-ContextMenuBuilder {
    $content = @"
    <Grid Margin="18">
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>
        <TextBlock Grid.Row="0" Text="This replaces the 'Set as desktop background' command with your custom top-level Windows 11 context menu action." Foreground="{DynamicResource Warning}" TextWrapping="Wrap" Margin="0,0,0,12"/>
        <StackPanel Grid.Row="1" Margin="0,0,0,10">
            <TextBlock Text="Menu Name" Foreground="{DynamicResource TextSecondary}" Margin="0,0,0,4"/>
            <TextBox Name="txtName" Height="34" VerticalContentAlignment="Center"/>
        </StackPanel>
        <Grid Grid.Row="2" Margin="0,0,0,10">
            <Grid.ColumnDefinitions><ColumnDefinition Width="*"/><ColumnDefinition Width="Auto"/></Grid.ColumnDefinitions>
            <StackPanel>
                <TextBlock Text="Command" Foreground="{DynamicResource TextSecondary}" Margin="0,0,0,4"/>
                <TextBox Name="txtCmd" Height="34" VerticalContentAlignment="Center"/>
            </StackPanel>
            <Button Name="btnBrowseCmd" Grid.Column="1" Content="Browse" Width="88" Margin="8,22,0,0"/>
        </Grid>
        <Grid Grid.Row="3" Margin="0,0,0,10">
            <Grid.ColumnDefinitions><ColumnDefinition Width="*"/><ColumnDefinition Width="Auto"/></Grid.ColumnDefinitions>
            <StackPanel>
                <TextBlock Text="Icon Path" Foreground="{DynamicResource TextSecondary}" Margin="0,0,0,4"/>
                <TextBox Name="txtIcon" Height="34" VerticalContentAlignment="Center"/>
            </StackPanel>
            <Button Name="btnBrowseIcon" Grid.Column="1" Content="Browse" Width="88" Margin="8,22,0,0"/>
        </Grid>
        <TextBlock Grid.Row="4" Text="Hint: use &quot;%1&quot; for the selected file." Foreground="{DynamicResource TextMuted}" Margin="0,0,0,16"/>
        <StackPanel Grid.Row="5" Orientation="Horizontal" HorizontalAlignment="Right">
            <Button Name="btnRemove" Content="Remove from Menu" MinWidth="142" Background="{DynamicResource Danger}" Foreground="{DynamicResource DangerText}" Margin="0,0,8,0"/>
            <Button Name="btnClose" Content="Cancel" Width="92" IsCancel="True" Margin="0,0,8,0"/>
            <Button Name="btnApply" Content="Apply to Menu" MinWidth="124" IsDefault="True" Background="{DynamicResource Success}" Foreground="{DynamicResource SuccessText}"/>
        </StackPanel>
    </Grid>
"@
    $dialog = New-WmtWindowFromXaml -Title "Custom Context Menu Builder" -ContentXaml $content -Width 640 -Height 430 -MinWidth 560 -MinHeight 390 -NoResize
    $txtName = $dialog.FindName("txtName")
    $txtCmd = $dialog.FindName("txtCmd")
    $txtIcon = $dialog.FindName("txtIcon")
    $btnBrowseCmd = $dialog.FindName("btnBrowseCmd")
    $btnBrowseIcon = $dialog.FindName("btnBrowseIcon")
    $btnApply = $dialog.FindName("btnApply")
    $btnRemove = $dialog.FindName("btnRemove")
    $btnClose = $dialog.FindName("btnClose")

    $txtName.Text = "Take Ownership"
    $txtCmd.Text = 'powershell -windowstyle hidden -command "Start-Process cmd -ArgumentList ''/c takeown /f \"%1\" /r /d y && icacls \"%1\" /grant administrators:F /t'' -Verb runAs"'
    $txtIcon.Text = "imageres.dll,-78"

    $btnBrowseCmd.Add_Click({
            $dlg = [Microsoft.Win32.OpenFileDialog]::new()
            $dlg.Filter = "Programs|*.exe;*.bat;*.cmd|All Files|*.*"
            if ($dlg.ShowDialog() -eq $true) { $txtCmd.Text = "`"$($dlg.FileName)`" `"%1`"" }
        }.GetNewClosure())
    $btnBrowseIcon.Add_Click({
            $dlg = [Microsoft.Win32.OpenFileDialog]::new()
            $dlg.Filter = "Icons|*.ico;*.exe;*.dll|All Files|*.*"
            if ($dlg.ShowDialog() -eq $true) { $txtIcon.Text = $dlg.FileName }
        }.GetNewClosure())

    $btnApply.Add_Click({
            if ([string]::IsNullOrWhiteSpace($txtName.Text) -or [string]::IsNullOrWhiteSpace($txtCmd.Text)) {
                Show-WmtMessageBox -Owner $dialog -Message "Name and Command are required." -Title "Custom Context Menu" -Image Warning | Out-Null
                return
            }
            $targets = @("HKCU:\Software\Classes\*\shell\SetDesktopWallpaper", "HKCU:\Software\Classes\Directory\shell\SetDesktopWallpaper")
            try {
                foreach ($key in $targets) {
                    if (-not (Test-Path -LiteralPath $key)) { New-Item -Path $key -Force | Out-Null }
                    Set-ItemProperty -LiteralPath $key -Name "MUIVerb" -Value $txtName.Text
                    Set-ItemProperty -LiteralPath $key -Name "MultiSelectModel" -Value "Player"
                    if (-not [string]::IsNullOrWhiteSpace($txtIcon.Text)) { Set-ItemProperty -LiteralPath $key -Name "Icon" -Value $txtIcon.Text }
                    $cmdKey = Join-Path $key "command"
                    if (-not (Test-Path -LiteralPath $cmdKey)) { New-Item -Path $cmdKey -Force | Out-Null }
                    Set-Item -LiteralPath $cmdKey -Value $txtCmd.Text
                }
                Show-WmtMessageBox -Owner $dialog -Message "Context Menu updated successfully!" -Title "Success" -Image Information | Out-Null
                $dialog.Close()
            }
            catch { Show-WmtMessageBox -Owner $dialog -Message $_.Exception.Message -Title "Context Menu Error" -Image Error | Out-Null }
        }.GetNewClosure())

    $btnRemove.Add_Click({
            if ((Show-WmtMessageBox -Owner $dialog -Message "Remove the custom menu item?" -Title "Confirm" -Button YesNo -Image Warning) -ne [System.Windows.MessageBoxResult]::Yes) { return }
            $targets = @("HKCU:\Software\Classes\*\shell\SetDesktopWallpaper", "HKCU:\Software\Classes\Directory\shell\SetDesktopWallpaper")
            foreach ($key in $targets) { if (Test-Path -LiteralPath $key) { Remove-Item -LiteralPath $key -Recurse -Force -ErrorAction SilentlyContinue } }
            Show-WmtMessageBox -Owner $dialog -Message "Item removed." -Title "Success" -Image Information | Out-Null
            $dialog.Close()
        }.GetNewClosure())
    $btnClose.Add_Click({ $dialog.Close() }.GetNewClosure())
    $dialog.ShowDialog() | Out-Null
}


# --- FIREWALL RULE DIALOG ---
function Show-RuleDialog {
    param($Title, $RuleObj = $null)

    $content = @"
    <Grid Margin="18">
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/><RowDefinition Height="Auto"/><RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/><RowDefinition Height="Auto"/><RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>
        <StackPanel Grid.Row="0" Margin="0,0,0,10"><TextBlock Text="Rule Name" Foreground="{DynamicResource TextSecondary}"/><TextBox Name="txtName" Height="34" VerticalContentAlignment="Center"/></StackPanel>
        <StackPanel Grid.Row="1" Margin="0,0,0,10"><TextBlock Text="Direction" Foreground="{DynamicResource TextSecondary}"/><ComboBox Name="cmbDirection" Height="34"/></StackPanel>
        <StackPanel Grid.Row="2" Margin="0,0,0,10"><TextBlock Text="Action" Foreground="{DynamicResource TextSecondary}"/><ComboBox Name="cmbAction" Height="34"/></StackPanel>
        <StackPanel Grid.Row="3" Margin="0,0,0,10"><TextBlock Text="Protocol" Foreground="{DynamicResource TextSecondary}"/><ComboBox Name="cmbProtocol" Height="34"/></StackPanel>
        <StackPanel Grid.Row="4" Margin="0,0,0,14"><TextBlock Text="Local Port" Foreground="{DynamicResource TextSecondary}"/><TextBox Name="txtPort" Height="34" VerticalContentAlignment="Center"/></StackPanel>
        <StackPanel Grid.Row="5" Orientation="Horizontal" HorizontalAlignment="Right">
            <Button Name="btnCancel" Content="Cancel" Width="92" IsCancel="True" Margin="0,0,8,0"/>
            <Button Name="btnSave" Content="Save" Width="110" IsDefault="True" Background="{DynamicResource Success}" Foreground="{DynamicResource SuccessText}"/>
        </StackPanel>
    </Grid>
"@
    $dialog = New-WmtWindowFromXaml -Title $Title -ContentXaml $content -Width 460 -Height 440 -MinWidth 400 -MinHeight 410 -NoResize
    $txtName = $dialog.FindName("txtName")
    $cmbDirection = $dialog.FindName("cmbDirection")
    $cmbAction = $dialog.FindName("cmbAction")
    $cmbProtocol = $dialog.FindName("cmbProtocol")
    $txtPort = $dialog.FindName("txtPort")
    $btnSave = $dialog.FindName("btnSave")
    $btnCancel = $dialog.FindName("btnCancel")

    foreach ($item in @("Inbound", "Outbound")) { [void]$cmbDirection.Items.Add($item) }
    foreach ($item in @("Allow", "Block")) { [void]$cmbAction.Items.Add($item) }
    foreach ($item in @("TCP", "UDP", "Any")) { [void]$cmbProtocol.Items.Add($item) }

    $txtName.Text = if ($RuleObj) { [string]$RuleObj.DisplayName } else { "" }
    $cmbDirection.SelectedItem = if ($RuleObj) { [string]$RuleObj.Direction } else { "Inbound" }
    $cmbAction.SelectedItem = if ($RuleObj) { [string]$RuleObj.Action } else { "Block" }
    $cmbProtocol.SelectedItem = if ($RuleObj) { [string]$RuleObj.Protocol } else { "TCP" }
    $txtPort.Text = if ($RuleObj) { [string]$RuleObj.LocalPort } else { "" }
    if ($RuleObj) { $txtName.IsReadOnly = $true }

    $state = @{ Result = $null }
    $btnSave.Add_Click({
            $state.Result = @{
                Name      = [string]$txtName.Text
                Direction = [string]$cmbDirection.SelectedItem
                Action    = [string]$cmbAction.SelectedItem
                Protocol  = [string]$cmbProtocol.SelectedItem
                Port      = [string]$txtPort.Text
            }
            $dialog.DialogResult = $true
        }.GetNewClosure())
    $btnCancel.Add_Click({ $dialog.Close() }.GetNewClosure())
    $dialog.ShowDialog() | Out-Null
    return $state.Result
}


# --- WINRE STATUS CHECK ---
function Invoke-WinREStatusCheck {
    Invoke-UiCommand {
        # 1. FIX THE ENCODING
        $oldEnc = [Console]::OutputEncoding
        [Console]::OutputEncoding = [System.Text.Encoding]::GetEncoding([System.Globalization.CultureInfo]::CurrentCulture.TextInfo.OEMCodePage)
        
        $raw = & reagentc.exe /info 2>&1
        $exitCode = $LASTEXITCODE
        
        [Console]::OutputEncoding = $oldEnc

        $text = ($raw | Out-String).Trim()
        if ([string]::IsNullOrWhiteSpace($text)) {
            $text = "No output returned from reagentc /info."
        }

        $status = "Unknown"
        $location = "Unknown"
        
        # 2. UNIVERSAL EXTRACTION (Indentation-based)
        # We only grab lines that are INDENTED with spaces and contain a colon.
        # This perfectly ignores unindented header lines that might have colons!
        $colonLines = $text -split "`r`n" | Where-Object { $_ -match '^\s+[^:]+:' }
        
        if ($colonLines.Count -ge 2) {
            # The 1st indented line is ALWAYS the Status
            $status = ($colonLines[0] -split ":", 2)[1].Trim()
            # The 2nd indented line is ALWAYS the Location
            $location = ($colonLines[1] -split ":", 2)[1].Trim()
        }

        $warnings = New-Object System.Collections.Generic.List[string]
        if ($exitCode -ne 0) { [void]$warnings.Add("reagentc returned exit code: $exitCode") }
        
        # 3. UNIVERSAL HEALTH CHECK & AUTO-CORRECT
        if ([string]::IsNullOrWhiteSpace($location) -or $location.Length -lt 5) { 
            [void]$warnings.Add("Windows RE is not enabled or recovery location is missing.") 
            
            if ([string]::IsNullOrWhiteSpace($status) -or $status -eq "Unknown") {
                $status = "Disabled (Inferred)"
            }
        }
        else {
            if ([string]::IsNullOrWhiteSpace($status) -or $status -eq "Unknown") {
                $status = "Enabled (Inferred)"
            }
        }

        $health = if ($warnings.Count -eq 0) { "OK" } else { "Needs Attention" }
        $headline = if ($warnings.Count -eq 0) { "WinRE looks healthy." } else { "WinRE needs attention." }

        $summary = @(
            "Windows Recovery Environment (WinRE)",
            "Checked: $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')",
            "",
            "Health: $health",
            "Status: $status",
            "Location: $location",
            ""
        )

        if ($warnings.Count -gt 0) {
            $summary += "What to check next:"
            foreach ($w in $warnings) { $summary += " - $w" }
            $summary += ""
            $summary += "Tip: You can usually fix this with:"
            $summary += " - reagentc /disable"
            $summary += " - reagentc /enable"
        }
        else {
            $summary += "No immediate issues found."
        }

        $msg = ($summary -join "`r`n")
        Write-Output $msg

        $icon = if ($warnings.Count -eq 0) {
            [System.Windows.MessageBoxImage]::Information
        }
        else {
            [System.Windows.MessageBoxImage]::Warning
        }

        $res = Show-WmtMessageBox -Message "$headline`r`n`r`n$msg`r`n`r`nShow technical details?" -Title "WinRE Status" -Button YesNo -Image $icon

        if ($res -eq [System.Windows.MessageBoxResult]::Yes) {
            Show-TextDialog -Title "WinRE Technical Details" -Text $text
        }
    } "Checking WinRE status..."
}

function Invoke-QuickFixSuite {
    $confirmMsg = @"
Run Quick Fix now?

This will run:
1) SFC /SCANNOW
2) DISM /CheckHealth
3) DISM /RestoreHealth
4) Temp cleanup (User + Windows Temp)


It can take a while.
"@
    $res = [System.Windows.MessageBox]::Show(
        $confirmMsg,
        "Quick Fix",
        [System.Windows.MessageBoxButton]::YesNo,
        [System.Windows.MessageBoxImage]::Question
    )
    if ($res -ne [System.Windows.MessageBoxResult]::Yes) { return }

    $runner = @'
$ErrorActionPreference = "Continue"
$ProgressPreference = "Continue"
[Console]::OutputEncoding = [System.Text.UTF8Encoding]::new($false)

Write-Host ("WMT Quick Fix started at {0}" -f (Get-Date -Format "yyyy-MM-dd HH:mm:ss")) -ForegroundColor Cyan
Write-Host ""

Write-Host "[1/4] Running SFC /SCANNOW..." -ForegroundColor Yellow
sfc /scannow
$sfcCode = $LASTEXITCODE

Write-Host ""
Write-Host "[2/4] Running DISM /Online /Cleanup-Image /CheckHealth..." -ForegroundColor Yellow
dism /online /cleanup-image /checkhealth
$dismCheckCode = $LASTEXITCODE

Write-Host ""
Write-Host "[3/4] Running DISM /Online /Cleanup-Image /RestoreHealth..." -ForegroundColor Yellow
dism /online /cleanup-image /restorehealth
$dismRestoreCode = $LASTEXITCODE

Write-Host ""
Write-Host "[4/4] Cleaning temporary files..." -ForegroundColor Yellow
function Get-TempFilesStreamed {
    param([string]$Root)
    if (-not $Root -or -not [System.IO.Directory]::Exists($Root)) { return }
    $pending = [System.Collections.Generic.Stack[string]]::new()
    $pending.Push($Root)
    while ($pending.Count -gt 0) {
        $dir = $pending.Pop()
        try {
            foreach ($file in [System.IO.Directory]::EnumerateFiles($dir, "*", [System.IO.SearchOption]::TopDirectoryOnly)) { $file }
        } catch {}
        try {
            foreach ($child in [System.IO.Directory]::EnumerateDirectories($dir, "*", [System.IO.SearchOption]::TopDirectoryOnly)) { $pending.Push($child) }
        } catch {}
    }
}
function Remove-EmptyTempDirs {
    param([string]$Root)
    if (-not $Root -or -not [System.IO.Directory]::Exists($Root)) { return }
    try {
        foreach ($dir in [System.IO.Directory]::EnumerateDirectories($Root, "*", [System.IO.SearchOption]::TopDirectoryOnly)) {
            Remove-EmptyTempDirs $dir
            try { [System.IO.Directory]::Delete($dir, $false) } catch {}
        }
    } catch {}
}
$targets = @($env:TEMP, "$env:SystemRoot\Temp")
$deletedCount = 0
$deletedBytes = 0
foreach ($path in $targets) {
    if (-not $path -or -not [System.IO.Directory]::Exists($path)) { continue }
    foreach ($file in Get-TempFilesStreamed $path) {
        try {
            $info = [System.IO.FileInfo]::new($file)
            $deletedBytes += $info.Length
            try { [System.IO.File]::SetAttributes($file, [System.IO.FileAttributes]::Normal) } catch {}
            [System.IO.File]::Delete($file)
            $deletedCount++
        } catch {}
    }
    Remove-EmptyTempDirs $path
}
$tempMb = [math]::Round(($deletedBytes / 1MB), 2)
Write-Host ("Temp cleanup done: {0} item(s), ~{1} MB reclaimed." -f $deletedCount, $tempMb) -ForegroundColor Gray

Write-Host ""
Write-Host "Quick Fix finished." -ForegroundColor Green
Write-Host ("Exit codes -> SFC: {0} | DISM Check: {1} | DISM Restore: {2}" -f $sfcCode, $dismCheckCode, $dismRestoreCode) -ForegroundColor Gray
Write-Host ""
Write-Host ""
Write-Host "Tip: If needed, run CHKDSK separately from the CHKDSK button in System Health." -ForegroundColor DarkGray
Write-Host "Closing in 8 seconds..." -ForegroundColor Gray
Start-Sleep -Seconds 8
'@

    try {
        $encoded = [Convert]::ToBase64String([System.Text.Encoding]::Unicode.GetBytes($runner))
        Start-Process -FilePath "powershell.exe" -ArgumentList "-NoProfile -ExecutionPolicy Bypass -EncodedCommand $encoded" -Verb RunAs -WindowStyle Normal
        Write-GuiLog "Quick Fix launched (SFC + DISM + Temp cleanup)."
    }
    catch {
        Write-GuiLog "Quick Fix launch failed: $($_.Exception.Message)"
        [System.Windows.MessageBox]::Show(
            "Could not start Quick Fix: $($_.Exception.Message)",
            "Quick Fix",
            [System.Windows.MessageBoxButton]::OK,
            [System.Windows.MessageBoxImage]::Error
        ) | Out-Null
    }
}

# --- SYSTEM RESTORE MANAGER ---
function Show-SystemRestoreManager {
    try {
        if ($script:WmtRestoreManagerWindow -and $script:WmtRestoreManagerWindow.IsVisible) {
            $script:WmtRestoreManagerWindow.Activate() | Out-Null
            return
        }
    }
    catch {
        $script:WmtRestoreManagerWindow = $null
    }

    $content = @"
    <Grid Margin="16">
        <Grid.RowDefinitions>
            <RowDefinition Height="*"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>
        <DataGrid Name="dgRestore" IsReadOnly="True" SelectionMode="Extended" SelectionUnit="FullRow" CanUserAddRows="False" CanUserDeleteRows="False" AlternationCount="2"/>
        <Grid Grid.Row="1" Margin="0,12,0,0">
            <Grid.RowDefinitions><RowDefinition Height="Auto"/><RowDefinition Height="Auto"/></Grid.RowDefinitions>
            <TextBlock Name="lblStatus" Text="Restore points: loading..." Foreground="{DynamicResource TextSecondary}"/>
            <WrapPanel Grid.Row="1" Margin="0,10,0,0">
                <Button Name="btnRefresh" Content="Refresh" MinWidth="104" Margin="0,0,8,8"/>
                <Button Name="btnEnable" Content="Enable Protection" MinWidth="136" Margin="0,0,8,8" Background="{DynamicResource Accent}" Foreground="{DynamicResource AccentText}"/>
                <Button Name="btnDisable" Content="Disable Protection" MinWidth="140" Margin="0,0,8,8" Background="{DynamicResource Warning}" Foreground="{DynamicResource WarningText}"/>
                <Button Name="btnCreate" Content="Create Point" MinWidth="116" Margin="0,0,8,8" Background="{DynamicResource Success}" Foreground="{DynamicResource SuccessText}"/>
                <Button Name="btnDelete" Content="Delete Selected" MinWidth="132" Margin="0,0,8,8" Background="{DynamicResource Danger}" Foreground="{DynamicResource DangerText}"/>
                <Button Name="btnRestore" Content="Restore Selected" MinWidth="138" Margin="0,0,8,8" Background="{DynamicResource Warning}" Foreground="{DynamicResource WarningText}"/>
                <Button Name="btnOpenUi" Content="Open Restore UI" MinWidth="128" Margin="0,0,8,8"/>
                <Button Name="btnClose" Content="Close" Width="92" IsCancel="True" Margin="0,0,8,8"/>
            </WrapPanel>
        </Grid>
    </Grid>
"@
    $dialog = New-WmtWindowFromXaml -Title "System Restore Manager" -ContentXaml $content -Width 1000 -Height 640 -MinWidth 780 -MinHeight 520
    $dg = $dialog.FindName("dgRestore")
    $lblStatus = $dialog.FindName("lblStatus")
    $btnRefresh = $dialog.FindName("btnRefresh")
    $btnEnable = $dialog.FindName("btnEnable")
    $btnDisable = $dialog.FindName("btnDisable")
    $btnCreate = $dialog.FindName("btnCreate")
    $btnDelete = $dialog.FindName("btnDelete")
    $btnRestore = $dialog.FindName("btnRestore")
    $btnOpenUi = $dialog.FindName("btnOpenUi")
    $btnClose = $dialog.FindName("btnClose")

    Set-WmtDataGridColumns -DataGrid $dg -Columns @("Description", "Type", "Created") -Widths @{ Description = "*"; Type = 120; Created = 170 }

    $toRestoreCellText = {
        param([object]$Value)

        if ($null -eq $Value) { return "" }
        try { $text = [string]$Value }
        catch { $text = "" }
        if ($null -eq $text) { return "" }
        $text = $text -replace '[\r\n\t]+', ' '
        $text = $text -replace '[\x00-\x08\x0B\x0C\x0E-\x1F]', ' '
        return ([string]$text).Trim()
    }.GetNewClosure()

    $getRestorePointValue = {
        param(
            [object]$Item,
            [string[]]$Names
        )

        if ($null -eq $Item) { return $null }
        foreach ($name in @($Names)) {
            if ([string]::IsNullOrWhiteSpace($name)) { continue }

            try {
                $prop = $null
                try { $prop = $Item.PSObject.Properties[$name] } catch {}
                if ($prop) {
                    $value = $null
                    try { $value = $prop.Value } catch {}
                    if ($null -ne $value) { return $value }
                }
            }
            catch {}

            try {
                if ($Item -is [System.Management.ManagementBaseObject]) {
                    $propertyData = $null
                    try { $propertyData = $Item.Properties[$name] } catch {}
                    if ($propertyData) {
                        $value = $null
                        try { $value = $propertyData.Value } catch {}
                        if ($null -ne $value) { return $value }
                    }
                }
            }
            catch {}
        }

        return $null
    }.GetNewClosure()

    $formatRestorePointType = {
        param([object]$Value)

        $text = & $toRestoreCellText $Value
        if ([string]::IsNullOrWhiteSpace($text)) { return "" }
        if ($text -notmatch '^\d+$') { return $text }

        switch ([int]$text) {
            0 { return "Application Install" }
            1 { return "Application Uninstall" }
            10 { return "Device Driver Install" }
            12 { return "System" }
            13 { return "Cancelled Operation" }
            100 { return "Begin System Change" }
            101 { return "End System Change" }
            102 { return "Begin Nested System Change" }
            103 { return "End Nested System Change" }
            default { return $text }
        }
    }.GetNewClosure()

    $formatRestorePointTime = {
        param([object]$Value)

        $text = & $toRestoreCellText $Value
        if ([string]::IsNullOrWhiteSpace($text)) { return "" }

        if ($text -match '^\d{14}\.\d{6}[+-]\d{3}$') {
            try {
                $convertedTime = [System.Management.ManagementDateTimeConverter]::ToDateTime($text)
                if ($null -ne $convertedTime) { return $convertedTime.ToString("yyyy-MM-dd HH:mm:ss") }
            }
            catch {}
        }

        try {
            $parsedTime = [datetime]::Parse($text, [System.Globalization.CultureInfo]::CurrentCulture)
            return $parsedTime.ToString("yyyy-MM-dd HH:mm:ss")
        }
        catch {}

        return $text
    }.GetNewClosure()

    $getRestorePointItems = {
        $errors = [System.Collections.Generic.List[string]]::new()

        try {
            $items = @(Get-CimInstance -Namespace "root/default" -ClassName "SystemRestore" -ErrorAction Stop)
            return [PSCustomObject]@{ Source = "CIM"; Items = $items }
        }
        catch { [void]$errors.Add("CIM: $($_.Exception.Message)") }

        try {
            $items = @(Get-WmiObject -Namespace "root/default" -Class "SystemRestore" -ErrorAction Stop)
            return [PSCustomObject]@{ Source = "WMI"; Items = $items }
        }
        catch { [void]$errors.Add("WMI: $($_.Exception.Message)") }

        try {
            $items = @(Get-ComputerRestorePoint -ErrorAction Stop)
            return [PSCustomObject]@{ Source = "Get-ComputerRestorePoint"; Items = $items }
        }
        catch { [void]$errors.Add("Get-ComputerRestorePoint: $($_.Exception.Message)") }

        throw "All restore point queries failed. $($errors -join ' | ')"
    }.GetNewClosure()

    $restoreRefreshState = [hashtable]::Synchronized(@{
            Handler = $null
            Timer   = $null
        })

    $startRestorePointCreate = {
        param([string]$Description)

        $descriptionText = & $toRestoreCellText $Description
        if ([string]::IsNullOrWhiteSpace($descriptionText)) { return }

        $restoreDialog = $null
        $restoreStatusLabel = $null
        $restoreCreateButton = $null
        $restoreRefreshButton = $null
        try { $restoreDialog = $dialog } catch {}
        try { $restoreStatusLabel = $lblStatus } catch {}
        try { $restoreCreateButton = $btnCreate } catch {}
        try {
            if ($null -ne $restoreDialog) { $restoreRefreshButton = $restoreDialog.FindName("btnRefresh") }
        }
        catch {}
        try {
            if ($null -eq $restoreRefreshButton) { $restoreRefreshButton = $btnRefresh }
        }
        catch {}

        if ($script:WmtRestorePointCreateActive) {
            Show-WmtMessageBox -Owner $restoreDialog -Message "A restore point is already being created. Please wait for it to finish." -Title "System Restore Manager" -Image Information | Out-Null
            return
        }

        if ($descriptionText.Length -gt 256) { $descriptionText = $descriptionText.Substring(0, 256) }
        $script:WmtRestorePointCreateActive = $true
        if ($null -ne $restoreCreateButton) { $restoreCreateButton.IsEnabled = $false }
        if ($null -ne $restoreStatusLabel) { $restoreStatusLabel.Text = "Creating restore point..." }

        $progressContent = @'
    <Grid Margin="20">
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>
        <TextBlock Name="lblCreateTitle" Text="Creating restore point in the background" FontSize="17" FontWeight="SemiBold" Margin="0,0,0,10"/>
        <TextBlock Name="lblCreateDetail" Grid.Row="1" Text="Starting Windows System Restore..." Foreground="{DynamicResource TextSecondary}" Margin="0,0,0,10" TextWrapping="Wrap"/>
        <ProgressBar Name="pbCreate" Grid.Row="2" Height="12" IsIndeterminate="True"/>
        <Button Name="btnHide" Grid.Row="3" Content="Hide" Width="96" Height="34" HorizontalAlignment="Right" Margin="0,18,0,0"/>
    </Grid>
'@
        $progressWindow = $null
        try {
            $progressWindow = New-WmtWindowFromXaml -Title "Create Restore Point" -ContentXaml $progressContent -Width 560 -Height 205 -MinWidth 520 -MinHeight 190 -NoResize
        }
        catch {
            $script:WmtRestorePointCreateActive = $false
            if ($null -ne $restoreCreateButton) { $restoreCreateButton.IsEnabled = $true }
            if ($null -ne $restoreStatusLabel) { $restoreStatusLabel.Text = "Restore point creation failed to start." }
            Show-WmtMessageBox -Owner $restoreDialog -Message "Could not open the restore point progress window.`n$($_.Exception.Message)" -Title "System Restore Manager" -Image Error | Out-Null
            return
        }

        try {
            if ($null -ne $restoreDialog) { $progressWindow.Owner = $restoreDialog }
        }
        catch {}
        try { $progressWindow.ShowInTaskbar = $false } catch {}
        $lblCreateDetail = $progressWindow.FindName("lblCreateDetail")
        $btnHideCreate = $progressWindow.FindName("btnHide")
        if ($btnHideCreate) {
            $btnHideCreate.Add_Click({ try { $progressWindow.Close() } catch {} }.GetNewClosure())
        }

        $workerId = [guid]::NewGuid().ToString("N")
        $tempPath = [System.IO.Path]::GetTempPath()
        $scriptPath = Join-Path $tempPath ("WMT_CreateRestorePoint_{0}.ps1" -f $workerId)
        $resultPath = Join-Path $tempPath ("WMT_CreateRestorePoint_{0}.json" -f $workerId)
        $encodedDescription = [Convert]::ToBase64String([System.Text.Encoding]::UTF8.GetBytes($descriptionText))
        $childScriptTemplate = @'
$ErrorActionPreference = "Stop"
$ProgressPreference = "SilentlyContinue"
$resultPath = '__RESULT_PATH__'
$descriptionText = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String('__DESCRIPTION_B64__'))

function Complete-RestorePointWorker {
    param(
        [bool]$Success,
        [string]$Message,
        [string]$ErrorMessage
    )

    try {
        $payload = [PSCustomObject]@{
            Success = $Success
            Message = $Message
            Error   = $ErrorMessage
        }
        $payload | ConvertTo-Json -Compress | Set-Content -LiteralPath $resultPath -Encoding UTF8 -Force
    }
    catch {}
}

try {
    if ([string]::IsNullOrWhiteSpace($descriptionText)) { throw "Restore point description is blank." }
    if ($descriptionText.Length -gt 256) { $descriptionText = $descriptionText.Substring(0, 256) }

    $errors = [System.Collections.Generic.List[string]]::new()
    $arguments = @{
        Description      = $descriptionText
        RestorePointType = 12
        EventType        = 100
    }

    $frequencyPath = "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\SystemRestore"
    $frequencyName = "SystemRestorePointCreationFrequency"
    $frequencyState = @{ Changed = $false; Existed = $false; Value = $null }

    try {
        if (-not (Test-Path -LiteralPath $frequencyPath)) { New-Item -Path $frequencyPath -Force | Out-Null }
        $existing = Get-ItemProperty -LiteralPath $frequencyPath -Name $frequencyName -ErrorAction SilentlyContinue
        if ($existing -and $null -ne $existing.$frequencyName) {
            $frequencyState.Existed = $true
            $frequencyState.Value = [int]$existing.$frequencyName
        }
        if (-not $frequencyState.Existed -or [int]$frequencyState.Value -ne 0) {
            New-ItemProperty -LiteralPath $frequencyPath -Name $frequencyName -Value 0 -PropertyType DWord -Force | Out-Null
            $frequencyState.Changed = $true
        }
    }
    catch { [void]$errors.Add("Frequency override: $($_.Exception.Message)") }

    $successMessage = $null
    try {
        try {
            $result = Invoke-CimMethod -Namespace "root/default" -ClassName "SystemRestore" -MethodName "CreateRestorePoint" -Arguments $arguments -ErrorAction Stop
            $returnValue = if ($result -and $result.PSObject.Properties["ReturnValue"]) { [int]$result.ReturnValue } else { 0 }
            if ($returnValue -eq 0) {
                $successMessage = "Restore point created via CIM."
            }
            else { throw "ReturnValue=$returnValue" }
        }
        catch { [void]$errors.Add("CIM CreateRestorePoint: $($_.Exception.Message)") }

        if ([string]::IsNullOrWhiteSpace($successMessage)) {
            try {
                $systemRestoreClass = Get-WmiObject -Namespace "root/default" -Class "SystemRestore" -List -ErrorAction Stop
                $result = $systemRestoreClass.CreateRestorePoint($descriptionText, 12, 100)
                $returnValue = if ($result -and $result.PSObject.Properties["ReturnValue"]) { [int]$result.ReturnValue } else { [int]$result }
                if ($returnValue -eq 0) {
                    $successMessage = "Restore point created via WMI."
                }
                else { throw "ReturnValue=$returnValue" }
            }
            catch { [void]$errors.Add("WMI CreateRestorePoint: $($_.Exception.Message)") }
        }

        if ([string]::IsNullOrWhiteSpace($successMessage)) {
            try {
                Checkpoint-Computer -Description $descriptionText -RestorePointType "MODIFY_SETTINGS" -ErrorAction Stop | Out-Null
                $successMessage = "Restore point created via Checkpoint-Computer."
            }
            catch { [void]$errors.Add("Checkpoint-Computer: $($_.Exception.Message)") }
        }

        if ([string]::IsNullOrWhiteSpace($successMessage)) {
            throw "Failed to create restore point. $($errors -join ' | ')"
        }
    }
    finally {
        if ($frequencyState.Changed) {
            try {
                if ($frequencyState.Existed) {
                    New-ItemProperty -LiteralPath $frequencyPath -Name $frequencyName -Value ([int]$frequencyState.Value) -PropertyType DWord -Force | Out-Null
                }
                else {
                    Remove-ItemProperty -LiteralPath $frequencyPath -Name $frequencyName -ErrorAction SilentlyContinue
                }
            }
            catch {}
        }
    }

    Complete-RestorePointWorker -Success $true -Message $successMessage -ErrorMessage ""
    exit 0
}
catch {
    Complete-RestorePointWorker -Success $false -Message "" -ErrorMessage $_.Exception.Message
    exit 1
}
'@
        $childScript = $childScriptTemplate.Replace('__RESULT_PATH__', ($resultPath -replace "'", "''")).Replace('__DESCRIPTION_B64__', $encodedDescription)

        $process = $null
        try {
            Set-Content -LiteralPath $scriptPath -Value $childScript -Encoding UTF8 -Force
            $powershellPath = Join-Path $env:SystemRoot "System32\WindowsPowerShell\v1.0\powershell.exe"
            if (-not (Test-Path -LiteralPath $powershellPath -PathType Leaf -ErrorAction SilentlyContinue)) { $powershellPath = "powershell.exe" }
            $psi = [System.Diagnostics.ProcessStartInfo]::new()
            $psi.FileName = $powershellPath
            $psi.Arguments = '-NoProfile -ExecutionPolicy Bypass -File "{0}"' -f ($scriptPath -replace '"', '\"')
            $psi.UseShellExecute = $false
            $psi.CreateNoWindow = $true
            $psi.WindowStyle = [System.Diagnostics.ProcessWindowStyle]::Hidden
            $process = [System.Diagnostics.Process]::Start($psi)
            if ($null -eq $process) { throw "Windows did not return a restore-point worker process." }
            Write-GuiLog "Restore point creation started in a background process. PID: $($process.Id)"
        }
        catch {
            try { Remove-Item -LiteralPath $scriptPath -Force -ErrorAction SilentlyContinue } catch {}
            try { Remove-Item -LiteralPath $resultPath -Force -ErrorAction SilentlyContinue } catch {}
            try { $progressWindow.Close() } catch {}
            $script:WmtRestorePointCreateActive = $false
            if ($null -ne $restoreCreateButton) { $restoreCreateButton.IsEnabled = $true }
            if ($null -ne $restoreStatusLabel) { $restoreStatusLabel.Text = "Restore point creation failed to start." }
            Show-WmtMessageBox -Owner $restoreDialog -Message "Failed to start restore point creation.`n$($_.Exception.Message)" -Title "System Restore Manager" -Image Error | Out-Null
            return
        }

        $startedAt = Get-Date
        $timer = [System.Windows.Threading.DispatcherTimer]::new()
        $timer.Interval = [TimeSpan]::FromMilliseconds(350)
        $timer.Add_Tick({
                try {
                    $elapsed = [int]((Get-Date) - $startedAt).TotalSeconds
                    if ($lblCreateDetail) { $lblCreateDetail.Text = "Windows is creating the restore point... ${elapsed}s" }

                    if ($process -and -not $process.HasExited) { return }

                    $timer.Stop()
                    $exitCode = -1
                    try { if ($process) { $exitCode = [int]$process.ExitCode } } catch {}

                    $result = $null
                    $resultError = $null
                    try {
                        if (Test-Path -LiteralPath $resultPath -PathType Leaf -ErrorAction SilentlyContinue) {
                            $result = Get-Content -LiteralPath $resultPath -Raw -ErrorAction Stop | ConvertFrom-Json -ErrorAction Stop
                        }
                    }
                    catch { $resultError = $_.Exception.Message }

                    try { if ($process) { $process.Dispose() } } catch {}
                    try { Remove-Item -LiteralPath $scriptPath -Force -ErrorAction SilentlyContinue } catch {}
                    try { Remove-Item -LiteralPath $resultPath -Force -ErrorAction SilentlyContinue } catch {}
                    try { if ($progressWindow) { $progressWindow.Close() } } catch {}

                    $script:WmtRestorePointCreateActive = $false
                    if ([object]::ReferenceEquals($script:WmtRestorePointCreateTimer, $timer)) { $script:WmtRestorePointCreateTimer = $null }
                    if ([object]::ReferenceEquals($script:WmtRestorePointCreateProcess, $process)) { $script:WmtRestorePointCreateProcess = $null }
                    if ($null -ne $restoreCreateButton) { $restoreCreateButton.IsEnabled = $true }

                    $messageOwner = $null
                    try { if ($null -ne $restoreDialog) { $messageOwner = $restoreDialog } } catch {}
                    if ($result -and [bool]$result.Success) {
                        if (-not [string]::IsNullOrWhiteSpace([string]$result.Message)) { try { Write-GuiLog ([string]$result.Message) } catch {} }
                        Show-WmtMessageBox -Owner $messageOwner -Message "Restore point created successfully." -Title "Success" -Image Information | Out-Null
                        try {
                            if ($null -ne $restoreStatusLabel) { $restoreStatusLabel.Text = "Restore point created. Refreshing list..." }
                        }
                        catch {}
                        if ($null -eq $restoreRefreshButton) {
                            try {
                                if ($null -ne $restoreDialog) { $restoreRefreshButton = $restoreDialog.FindName("btnRefresh") }
                            }
                            catch {}
                        }
                        if ($null -ne $restoreRefreshButton) {
                            try {
                                Write-GuiLog "Clicking restore point Refresh button after creation."
                                $restoreRefreshButton.RaiseEvent((New-Object System.Windows.RoutedEventArgs([System.Windows.Controls.Button]::ClickEvent)))
                            }
                            catch {
                                try { Write-GuiLog "Restore point Refresh button click failed: $($_.Exception.Message)" } catch {}
                            }
                        }
                        else {
                            try { Write-GuiLog "Restore point was created, but the Refresh button was not available." } catch {}
                        }
                    }
                    else {
                        $errorText = $null
                        if ($result -and -not [string]::IsNullOrWhiteSpace([string]$result.Error)) { $errorText = [string]$result.Error }
                        elseif (-not [string]::IsNullOrWhiteSpace([string]$resultError)) { $errorText = "Could not read worker result: $resultError" }
                        else { $errorText = "The restore-point worker exited with code $exitCode and did not return details." }
                        Write-GuiLog "Restore point creation failed: $errorText"
                        Show-WmtMessageBox -Owner $messageOwner -Message "Failed to create restore point.`n$errorText" -Title "Error" -Image Error | Out-Null
                    }
                }
                catch {
                    try { $timer.Stop() } catch {}
                    try { if ($process) { $process.Dispose() } } catch {}
                    try { Remove-Item -LiteralPath $scriptPath -Force -ErrorAction SilentlyContinue } catch {}
                    try { Remove-Item -LiteralPath $resultPath -Force -ErrorAction SilentlyContinue } catch {}
                    $script:WmtRestorePointCreateActive = $false
                    if ([object]::ReferenceEquals($script:WmtRestorePointCreateTimer, $timer)) { $script:WmtRestorePointCreateTimer = $null }
                    if ([object]::ReferenceEquals($script:WmtRestorePointCreateProcess, $process)) { $script:WmtRestorePointCreateProcess = $null }
                    if ($null -ne $restoreCreateButton) { $restoreCreateButton.IsEnabled = $true }
                    try {
                        if ($null -ne $restoreStatusLabel) { $restoreStatusLabel.Text = "Restore point creation failed." }
                    }
                    catch {}
                    try { Write-GuiLog "Restore point completion handler failed: $($_.Exception.Message)" } catch {}
                    $messageOwner = $null
                    try { if ($null -ne $restoreDialog -and $restoreDialog.IsVisible) { $messageOwner = $restoreDialog } } catch {}
                    Show-WmtMessageBox -Owner $messageOwner -Message "Restore point creation finished, but WMT could not process the result.`n$($_.Exception.Message)" -Title "System Restore Manager" -Image Error | Out-Null
                }
            }.GetNewClosure())

        [void]$progressWindow.Show()
        $script:WmtRestorePointCreateTimer = $timer
        $script:WmtRestorePointCreateProcess = $process
        $timer.Start()
    }.GetNewClosure()

    $getRestoreRowValue = {
        param(
            [object]$Row,
            [string]$Name
        )

        if ($null -eq $Row -or [string]::IsNullOrWhiteSpace($Name)) { return "" }
        try {
            if ($Row -is [System.Data.DataRow]) { return & $toRestoreCellText $Row[$Name] }
            if ($Row -is [System.Data.DataRowView]) { return & $toRestoreCellText $Row.Row[$Name] }
            if ($Row -is [System.Collections.IDictionary] -and $Row.Contains($Name)) { return & $toRestoreCellText $Row[$Name] }
            $prop = $Row.PSObject.Properties[$Name]
            if ($prop) { return & $toRestoreCellText $prop.Value }
        }
        catch {}
        return ""
    }.GetNewClosure()

    $loadRestorePoints = {
        param([switch]$ShowError)

        $lblStatus.Text = "Restore points: loading..."
        if ($btnRefresh) { $btnRefresh.IsEnabled = $false }
        Set-WmtBusyCursor -Busy
        Invoke-WmtDispatcherPump -Dispatcher $dialog.Dispatcher

        try {
            $queryResult = & $getRestorePointItems
            $list = @($queryResult.Items | Sort-Object @{ Expression = {
                        $seqText = & $toRestoreCellText (& $getRestorePointValue $_ @("SequenceNumber", "Sequence"))
                        try { [int]$seqText } catch { 0 }
                    }; Descending                                    = $true 
                })
            $rows = [System.Collections.ObjectModel.ObservableCollection[object]]::new()
            foreach ($rp in $list) {
                if ($null -eq $rp) { continue }
                try {
                    $rawTime = & $toRestoreCellText (& $getRestorePointValue $rp @("CreationTime", "Date and Time", "DateAndTime", "DateTime"))
                    $restoreType = & $getRestorePointValue $rp @("Type", "RestorePointType", "EventType")

                    [void]$rows.Add([PSCustomObject]@{
                            SequenceNumber = & $toRestoreCellText (& $getRestorePointValue $rp @("SequenceNumber", "Sequence"))
                            Description    = & $toRestoreCellText (& $getRestorePointValue $rp @("Description"))
                            Type           = & $formatRestorePointType $restoreType
                            Created        = & $formatRestorePointTime $rawTime
                            RawTime        = $rawTime
                        })
                }
                catch {
                    Write-GuiLog "Could not display one restore point row: $($_.Exception.Message)"
                }
            }

            $dg.ItemsSource = $null
            $dg.ItemsSource = $rows
            try { $dg.Items.Refresh() } catch {}
            try { $dg.UpdateLayout() } catch {}
            $lblStatus.Text = "Restore points: $($rows.Count)"
            Write-GuiLog "System Restore Manager loaded $($rows.Count) restore point(s) via $($queryResult.Source). Grid items: $($dg.Items.Count)."
        }
        catch {
            $message = "Could not load restore points: $($_.Exception.Message)"
            Write-GuiLog $message
            $dg.ItemsSource = $null
            $lblStatus.Text = $message
            if ($ShowError) {
                Show-WmtMessageBox -Owner $dialog -Message $message -Title "System Restore Manager" -Image Warning | Out-Null
            }
        }
        finally {
            if ($btnRefresh) { $btnRefresh.IsEnabled = $true }
            Set-WmtBusyCursor
        }
    }.GetNewClosure()

    $refreshRestorePointsAfterCreate = {
        try {
            if ($restoreRefreshState.Timer) {
                $restoreRefreshState.Timer.Stop()
                $restoreRefreshState.Timer = $null
            }
        }
        catch {}

        $refreshState = [hashtable]::Synchronized(@{ Attempt = 0; MaxAttempts = 6 })
        $invokeRestoreRefresh = {
            param([switch]$ShowError)

            if (-not $dialog) { return $false }
            $refreshState.Attempt = [int]$refreshState.Attempt + 1
            if ([int]$refreshState.Attempt -eq 1) {
                $lblStatus.Text = "Restore point created. Refreshing list..."
            }
            else {
                $lblStatus.Text = "Refreshing restore points... ($($refreshState.Attempt)/$($refreshState.MaxAttempts))"
            }

            if ($btnRefresh) {
                try {
                    $btnRefresh.RaiseEvent((New-Object System.Windows.RoutedEventArgs([System.Windows.Controls.Button]::ClickEvent)))
                }
                catch {
                    Write-GuiLog "Restore point Refresh button click failed: $($_.Exception.Message)"
                    & $loadRestorePoints -ShowError:$ShowError
                }
            }
            else {
                & $loadRestorePoints -ShowError:$ShowError
            }
            return $true
        }.GetNewClosure()

        try { [void](& $invokeRestoreRefresh -ShowError) }
        catch { Write-GuiLog "Immediate restore point refresh failed: $($_.Exception.Message)" }

        $refreshTimer = [System.Windows.Threading.DispatcherTimer]::new()
        $refreshTimer.Interval = [TimeSpan]::FromSeconds(2)
        $refreshTimer.Add_Tick({
                try {
                    if ([int]$refreshState.Attempt -ge [int]$refreshState.MaxAttempts) {
                        $refreshTimer.Stop()
                        if ([object]::ReferenceEquals($restoreRefreshState.Timer, $refreshTimer)) { $restoreRefreshState.Timer = $null }
                        return
                    }
                    if (-not (& $invokeRestoreRefresh)) {
                        $refreshTimer.Stop()
                        if ([object]::ReferenceEquals($restoreRefreshState.Timer, $refreshTimer)) { $restoreRefreshState.Timer = $null }
                    }
                }
                catch {
                    $refreshTimer.Stop()
                    if ([object]::ReferenceEquals($restoreRefreshState.Timer, $refreshTimer)) { $restoreRefreshState.Timer = $null }
                    Write-GuiLog "Delayed restore point refresh failed: $($_.Exception.Message)"
                }
            }.GetNewClosure())
        $restoreRefreshState.Timer = $refreshTimer
        $refreshTimer.Start()
    }.GetNewClosure()
    $restoreRefreshState.Handler = $refreshRestorePointsAfterCreate

    $getSelectedRows = { @(Get-WmtDataGridSelectedRows -DataGrid $dg) }.GetNewClosure()

    $btnRefresh.Add_Click({ & $loadRestorePoints -ShowError }.GetNewClosure())
    $btnEnable.Add_Click({
            try {
                Enable-ComputerRestore -Drive "$env:SystemDrive\" -ErrorAction Stop
                Show-WmtMessageBox -Owner $dialog -Message "System Restore has been ENABLED on $env:SystemDrive." -Title "Success" -Image Information | Out-Null
                & $loadRestorePoints -ShowError
            }
            catch { Show-WmtMessageBox -Owner $dialog -Message "Failed to enable protection.`n$($_.Exception.Message)" -Title "Error" -Image Error | Out-Null }
        }.GetNewClosure())
    $btnDisable.Add_Click({
            $res = Show-WmtMessageBox -Owner $dialog -Message "Are you sure you want to disable System Restore on $env:SystemDrive?`n`nWARNING: This will immediately delete ALL existing restore points." -Title "Confirm Disable" -Button YesNo -Image Warning
            if ($res -ne [System.Windows.MessageBoxResult]::Yes) { return }
            try {
                Disable-ComputerRestore -Drive "$env:SystemDrive\" -ErrorAction Stop
                Show-WmtMessageBox -Owner $dialog -Message "System Restore has been DISABLED." -Title "Success" -Image Information | Out-Null
                & $loadRestorePoints -ShowError
            }
            catch { Show-WmtMessageBox -Owner $dialog -Message "Failed to disable protection.`n$($_.Exception.Message)" -Title "Error" -Image Error | Out-Null }
        }.GetNewClosure())
    $btnCreate.Add_Click({
            $desc = Show-WmtInputDialog -Title "Create Restore Point" -Prompt "Description for the restore point:" -DefaultValue "WMT Manual Restore Point"
            if ([string]::IsNullOrWhiteSpace($desc)) { return }
            & $startRestorePointCreate $desc
        }.GetNewClosure())
    $btnDelete.Add_Click({
            $selected = & $getSelectedRows
            if ($selected.Count -eq 0) { return }
            if ((Show-WmtMessageBox -Owner $dialog -Message "Delete $($selected.Count) selected restore point(s)?" -Title "Confirm Delete" -Button YesNo -Image Warning) -ne [System.Windows.MessageBoxResult]::Yes) { return }
            if (-not ([System.Management.Automation.PSTypeName]'Win32.SysRestoreAPI').Type) {
                $apiCode = '[DllImport("srclient.dll")] public static extern int SRRemoveRestorePoint(int index);'
                Add-Type -MemberDefinition $apiCode -Name "SysRestoreAPI" -Namespace "Win32" -ErrorAction SilentlyContinue
            }
            $ok = 0; $fail = 0
            foreach ($row in $selected) {
                try { $seq = [int](& $getRestoreRowValue $row "SequenceNumber") } catch { $seq = 0 }
                if ($seq -le 0) { $fail++; continue }
                try {
                    $ret = [Win32.SysRestoreAPI]::SRRemoveRestorePoint($seq)
                    if ($ret -eq 0) { $ok++ } else { $fail++; Show-WmtMessageBox -Owner $dialog -Message "Deletion failed for Sequence $seq. Windows Error Code: $ret" -Title "Error Details" -Image Error | Out-Null }
                }
                catch { $fail++; Show-WmtMessageBox -Owner $dialog -Message "Exception for Sequence ${seq}: $($_.Exception.Message)" -Title "Error Details" -Image Error | Out-Null }
            }
            Show-WmtMessageBox -Owner $dialog -Message "Deleted: $ok`nFailed: $fail" -Title "Deletion Complete" -Image Information | Out-Null
            & $loadRestorePoints -ShowError
        }.GetNewClosure())
    $btnRestore.Add_Click({
            $selected = & $getSelectedRows
            if ($selected.Count -ne 1) { Show-WmtMessageBox -Owner $dialog -Message "Please select exactly ONE restore point to restore." -Title "Notice" -Image Warning | Out-Null; return }
            try { $seq = [int](& $getRestoreRowValue $selected[0] "SequenceNumber") } catch { $seq = 0 }
            if ($seq -le 0) { return }
            $res = Show-WmtMessageBox -Owner $dialog -Message "WARNING: This will restore your system to Sequence $seq and RESTART your computer immediately.`n`nPlease save all open work before proceeding.`n`nProceed with System Restore?" -Title "Confirm Restore" -Button YesNo -Image Warning
            if ($res -ne [System.Windows.MessageBoxResult]::Yes) { return }
            try { Restore-Computer -RestorePoint $seq -Confirm:$false }
            catch { Show-WmtMessageBox -Owner $dialog -Message "Failed to initialize restore.`n$($_.Exception.Message)" -Title "Error" -Image Error | Out-Null }
        }.GetNewClosure())
    $btnOpenUi.Add_Click({ Start-Process "rstrui.exe" }.GetNewClosure())
    $btnClose.Add_Click({ $dialog.Close() }.GetNewClosure())

    $dialog.Add_ContentRendered({ & $loadRestorePoints }.GetNewClosure())
    $dialog.Add_Closed({
            if ($script:WmtRestoreManagerWindow -eq $dialog) { $script:WmtRestoreManagerWindow = $null }
            try { $restoreRefreshState.Handler = $null } catch {}
            try {
                if ($restoreRefreshState.Timer) {
                    $restoreRefreshState.Timer.Stop()
                    $restoreRefreshState.Timer = $null
                }
            }
            catch {}
        }.GetNewClosure())
    $script:WmtRestoreManagerWindow = $dialog
    [void]$dialog.Show()
    try { $dialog.Activate() | Out-Null } catch {}
}


# --- STARTUP MANAGER (Windows / Tasks / Context Menu / Services) ---
function Show-StartupManager {
    param([string]$DefaultTab = "Windows")

    $content = @'
    <Grid Margin="0" Background="{DynamicResource BgDark}">
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="*"/>
        </Grid.RowDefinitions>
        <Border Grid.Row="0" Background="{DynamicResource BgDark}" BorderBrush="{DynamicResource BorderBrush}" BorderThickness="0,0,0,1" Padding="14,10">
            <StackPanel Name="tabHeader" Orientation="Horizontal"/>
        </Border>
        <Grid Name="mainHost" Grid.Row="1" Background="{DynamicResource BgDark}"/>
    </Grid>
'@
    $dialog = New-WmtWindowFromXaml -Title "Startup Manager" -ContentXaml $content -Width 1220 -Height 720 -MinWidth 960 -MinHeight 560
    $tabHeader = $dialog.FindName("tabHeader")
    $mainHost = $dialog.FindName("mainHost")
    $tabs = @{}
    $tabButtons = @{}
    $tabLoaded = @{
        "Windows"         = $false
        "Scheduled Tasks" = $false
        "Context Menu"    = $false
        "Services"        = $false
    }

    function Set-StartupButtonRole {
        param(
            [System.Windows.Controls.Button]$Button,
            [string]$Role = "Standard"
        )
        if (-not $Button) { return }
        $bgKey = switch ($Role) {
            "Success" { "Success"; break }
            "Danger" { "Danger"; break }
            "Warning" { "Warning"; break }
            "Primary" { "Accent"; break }
            default { "BgElevated"; break }
        }
        $fgKey = switch ($Role) {
            "Success" { "SuccessText"; break }
            "Danger" { "DangerText"; break }
            "Warning" { "WarningText"; break }
            "Primary" { "AccentText"; break }
            default { "TextPrimary"; break }
        }
        Set-WmtThemedBrush -Object $Button -Property ([System.Windows.Controls.Control]::BackgroundProperty) -ColorOrKey $bgKey
        Set-WmtThemedBrush -Object $Button -Property ([System.Windows.Controls.Control]::ForegroundProperty) -ColorOrKey $fgKey
        Set-WmtThemedBrush -Object $Button -Property ([System.Windows.Controls.Control]::BorderBrushProperty) -ColorOrKey "BorderBrush"
    }

    function New-StartupButton {
        param(
            [System.Windows.Controls.Panel]$Parent,
            [string]$Text,
            [string]$Role = "Standard"
        )
        $button = [System.Windows.Controls.Button]::new()
        $button.Content = $Text
        $button.MinWidth = 108
        $button.Height = 34
        $button.Margin = [System.Windows.Thickness]::new(0, 0, 10, 0)
        $button.Padding = [System.Windows.Thickness]::new(14, 0, 14, 0)
        $button.BorderThickness = [System.Windows.Thickness]::new(1)
        $button.FocusVisualStyle = $null
        Set-StartupButtonRole -Button $button -Role $Role
        [void]$Parent.Children.Add($button)
        return $button
    }

    function New-TabButton {
        param([string]$Text)
        $button = [System.Windows.Controls.Button]::new()
        $button.Content = $Text
        $button.Width = 160
        $button.Height = 32
        $button.Margin = [System.Windows.Thickness]::new(0, 0, 8, 0)
        $button.Padding = [System.Windows.Thickness]::new(12, 0, 12, 0)
        $button.BorderThickness = [System.Windows.Thickness]::new(1)
        $button.FocusVisualStyle = $null
        $button.Cursor = [System.Windows.Input.Cursors]::Hand
        Set-StartupButtonRole -Button $button -Role "Standard"
        Set-WmtThemedBrush -Object $button -Property ([System.Windows.Controls.Control]::ForegroundProperty) -ColorOrKey "TextSecondary"
        [void]$tabHeader.Children.Add($button)
        $tabButtons[$Text] = $button
        return $button
    }

    function Set-TabButtonActive {
        param([string]$Title)
        foreach ($key in @($tabButtons.Keys)) {
            $button = $tabButtons[$key]
            if ($key -eq $Title) {
                Set-WmtThemedBrush -Object $button -Property ([System.Windows.Controls.Control]::BackgroundProperty) -ColorOrKey "BgElevated"
                Set-WmtThemedBrush -Object $button -Property ([System.Windows.Controls.Control]::ForegroundProperty) -ColorOrKey "TextPrimary"
                Set-WmtThemedBrush -Object $button -Property ([System.Windows.Controls.Control]::BorderBrushProperty) -ColorOrKey "Accent"
            }
            else {
                Set-WmtThemedBrush -Object $button -Property ([System.Windows.Controls.Control]::BackgroundProperty) -ColorOrKey "BgPanel"
                Set-WmtThemedBrush -Object $button -Property ([System.Windows.Controls.Control]::ForegroundProperty) -ColorOrKey "TextSecondary"
                Set-WmtThemedBrush -Object $button -Property ([System.Windows.Controls.Control]::BorderBrushProperty) -ColorOrKey "BorderBrush"
            }
        }
    }

    function New-StartupPage {
        param([string]$Title)

        $root = [System.Windows.Controls.Grid]::new()
        $root.Background = $dialog.Resources["BgDark"]
        $root.Visibility = [System.Windows.Visibility]::Collapsed
        foreach ($h in @("Auto", "*", "Auto")) {
            $row = [System.Windows.Controls.RowDefinition]::new()
            $row.Height = if ($h -eq "*") { [System.Windows.GridLength]::new(1, [System.Windows.GridUnitType]::Star) } else { [System.Windows.GridLength]::Auto }
            [void]$root.RowDefinitions.Add($row)
        }
        [void]$mainHost.Children.Add($root)

        $topBorder = [System.Windows.Controls.Border]::new()
        $topBorder.Padding = [System.Windows.Thickness]::new(14, 10, 14, 10)
        $topBorder.BorderThickness = [System.Windows.Thickness]::new(0, 0, 0, 1)
        Set-WmtThemedBrush -Object $topBorder -Property ([System.Windows.Controls.Border]::BackgroundProperty) -ColorOrKey "BgPanel"
        Set-WmtThemedBrush -Object $topBorder -Property ([System.Windows.Controls.Border]::BorderBrushProperty) -ColorOrKey "BorderBrush"
        $top = [System.Windows.Controls.Grid]::new()
        foreach ($width in @("Auto", "360", "Auto", "Auto", "*")) {
            $col = [System.Windows.Controls.ColumnDefinition]::new()
            $col.Width = if ($width -eq "*") { [System.Windows.GridLength]::new(1, [System.Windows.GridUnitType]::Star) } elseif ($width -eq "Auto") { [System.Windows.GridLength]::Auto } else { [System.Windows.GridLength]::new([double]$width) }
            [void]$top.ColumnDefinitions.Add($col)
        }
        $label = [System.Windows.Controls.TextBlock]::new()
        $label.Text = "Search:"
        $label.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
        $label.Margin = [System.Windows.Thickness]::new(0, 0, 10, 0)
        $label.FontWeight = [System.Windows.FontWeights]::SemiBold
        Set-WmtThemedBrush -Object $label -Property ([System.Windows.Controls.TextBlock]::ForegroundProperty) -ColorOrKey "TextPrimary"
        [void]$top.Children.Add($label)

        $search = [System.Windows.Controls.TextBox]::new()
        $search.Height = 34
        $search.FocusVisualStyle = $null
        $search.VerticalContentAlignment = [System.Windows.VerticalAlignment]::Center
        [System.Windows.Controls.Grid]::SetColumn($search, 1)
        [void]$top.Children.Add($search)

        $clear = [System.Windows.Controls.Button]::new()
        $clear.Content = "Clear"
        $clear.Height = 32
        $clear.MinWidth = 72
        $clear.Margin = [System.Windows.Thickness]::new(8, 0, 12, 0)
        $clear.FocusVisualStyle = $null
        Set-StartupButtonRole -Button $clear -Role "Standard"
        [System.Windows.Controls.Grid]::SetColumn($clear, 2)
        [void]$top.Children.Add($clear)

        $count = [System.Windows.Controls.TextBlock]::new()
        $count.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
        $count.Text = "0 items"
        Set-WmtThemedBrush -Object $count -Property ([System.Windows.Controls.TextBlock]::ForegroundProperty) -ColorOrKey "TextSecondary"
        [System.Windows.Controls.Grid]::SetColumn($count, 3)
        [void]$top.Children.Add($count)
        $topBorder.Child = $top
        [System.Windows.Controls.Grid]::SetRow($topBorder, 0)
        [void]$root.Children.Add($topBorder)

        $grid = [System.Windows.Controls.DataGrid]::new()
        $grid.IsReadOnly = $true
        $grid.CanUserAddRows = $false
        $grid.CanUserDeleteRows = $false
        $grid.SelectionMode = [System.Windows.Controls.DataGridSelectionMode]::Extended
        $grid.SelectionUnit = [System.Windows.Controls.DataGridSelectionUnit]::FullRow
        $grid.AlternationCount = 2
        $grid.BorderThickness = [System.Windows.Thickness]::new(0)
        $grid.FocusVisualStyle = $null
        $grid.HeadersVisibility = [System.Windows.Controls.DataGridHeadersVisibility]::Column
        $grid.GridLinesVisibility = [System.Windows.Controls.DataGridGridLinesVisibility]::Horizontal
        Set-WmtThemedBrush -Object $grid -Property ([System.Windows.Controls.Control]::BackgroundProperty) -ColorOrKey "BgDark"
        Set-WmtThemedBrush -Object $grid -Property ([System.Windows.Controls.Control]::ForegroundProperty) -ColorOrKey "TextPrimary"
        Set-WmtThemedBrush -Object $grid -Property ([System.Windows.Controls.Control]::BorderBrushProperty) -ColorOrKey "BorderBrush"
        [System.Windows.Controls.Grid]::SetRow($grid, 1)
        [void]$root.Children.Add($grid)

        $bottomBorder = [System.Windows.Controls.Border]::new()
        $bottomBorder.Padding = [System.Windows.Thickness]::new(14, 12, 14, 12)
        $bottomBorder.BorderThickness = [System.Windows.Thickness]::new(0, 1, 0, 0)
        Set-WmtThemedBrush -Object $bottomBorder -Property ([System.Windows.Controls.Border]::BackgroundProperty) -ColorOrKey "BgPanel"
        Set-WmtThemedBrush -Object $bottomBorder -Property ([System.Windows.Controls.Border]::BorderBrushProperty) -ColorOrKey "BorderBrush"
        $buttons = [System.Windows.Controls.WrapPanel]::new()
        $buttons.HorizontalAlignment = [System.Windows.HorizontalAlignment]::Left
        $bottomBorder.Child = $buttons
        [System.Windows.Controls.Grid]::SetRow($bottomBorder, 2)
        [void]$root.Children.Add($bottomBorder)

        $grid.Add_PreviewMouseRightButtonDown({
                param($eventSource, $e)
                $row = Get-WmtVisualAncestor -Element $e.OriginalSource -AncestorType ([System.Windows.Controls.DataGridRow])
                if ($row) {
                    if (-not $row.IsSelected) {
                        $eventSource.SelectedItems.Clear()
                        $row.IsSelected = $true
                    }
                    try { $row.Focus() | Out-Null } catch {}
                }
            }.GetNewClosure())

        $obj = [PSCustomObject]@{ Header = $Title; Root = $root; Grid = $grid; SearchBox = $search; CountLabel = $count; ClearButton = $clear; Buttons = $buttons; Meta = $null }
        $tabs[$Title] = $obj
        return $obj
    }

    function Set-StartupTabData {
        param($TabObj, [System.Data.DataTable]$DataTable, [string[]]$SearchColumns, [string[]]$Hidden = @(), [hashtable]$Widths = @{})
        $TabObj.Grid.ItemsSource = $DataTable.DefaultView
        Set-WmtDataGridColumns -DataGrid $TabObj.Grid -Columns @($DataTable.Columns | ForEach-Object { $_.ColumnName }) -Widths $Widths -Hidden $Hidden
        $TabObj.Meta = [PSCustomObject]@{ Table = $DataTable; View = $DataTable.DefaultView; SearchColumns = $SearchColumns }
        $TabObj.CountLabel.Text = "$($DataTable.Rows.Count) items"
    }

    function Update-StartupTabFilter {
        param($TabObj)
        if (-not $TabObj -or -not $TabObj.Meta) { return }
        $q = $TabObj.SearchBox.Text.Trim()
        if ([string]::IsNullOrWhiteSpace($q)) {
            $TabObj.Meta.View.RowFilter = ""
            $TabObj.CountLabel.Text = "$($TabObj.Meta.Table.Rows.Count) items"
            return
        }
        $safe = $q.Replace("'", "''").Replace("[", "[[]").Replace("%", "[%]").Replace("*", "[*]")
        $clauses = @()
        foreach ($col in $TabObj.Meta.SearchColumns) {
            if ($TabObj.Meta.Table.Columns.Contains($col)) { $clauses += "CONVERT([$col], 'System.String') LIKE '%$safe%'" }
        }
        try { $TabObj.Meta.View.RowFilter = ($clauses -join " OR ") } catch { $TabObj.Meta.View.RowFilter = "" }
        $TabObj.CountLabel.Text = "$($TabObj.Meta.View.Count) shown / $($TabObj.Meta.Table.Rows.Count) total"
    }

    function Show-StartupRowDetails {
        param($TabObj, [string]$Title)

        $selectedRows = @(Get-WmtDataGridSelectedRows -DataGrid $TabObj.Grid)
        if ($selectedRows.Count -eq 0) {
            Show-WmtMessageBox -Owner $dialog -Message "Select one startup entry first." -Title "Startup Manager" -Image Information | Out-Null
            return
        }

        $row = $selectedRows | Select-Object -First 1
        $tabName = [string]$TabObj.Header

        function Get-StartupCellValue {
            param($Row, [string]$Name)
            try {
                if ($Row -is [System.Data.DataRow]) {
                    if ($Row.Table.Columns.Contains($Name)) { return [string]$Row[$Name] }
                }
                elseif ($Row -is [System.Data.DataRowView]) {
                    if ($Row.Row.Table.Columns.Contains($Name)) { return [string]$Row.Row[$Name] }
                }
                elseif ($Row -is [System.Collections.IDictionary]) {
                    if ($Row.Contains($Name)) { return [string]$Row[$Name] }
                }
                else {
                    $prop = $Row.PSObject.Properties[$Name]
                    if ($prop) { return [string]$prop.Value }
                }
            }
            catch {}
            return ""
        }

        function Set-StartupCellValue {
            param($Row, [string]$Name, [string]$Value)
            try {
                if ($Row -is [System.Data.DataRow]) {
                    if ($Row.Table.Columns.Contains($Name)) { $Row[$Name] = $Value }
                }
                elseif ($Row -is [System.Data.DataRowView]) {
                    if ($Row.Row.Table.Columns.Contains($Name)) { $Row.Row[$Name] = $Value }
                }
                elseif ($Row -is [System.Collections.IDictionary]) {
                    $Row[$Name] = $Value
                }
                else {
                    $prop = $Row.PSObject.Properties[$Name]
                    if ($prop) { $prop.Value = $Value }
                }
            }
            catch {}
        }

        function Set-StartupEditorVisibility {
            param([object[]]$Controls, [bool]$Visible)
            $visibility = if ($Visible) { [System.Windows.Visibility]::Visible } else { [System.Windows.Visibility]::Collapsed }
            foreach ($control in @($Controls)) {
                try { if ($control) { $control.Visibility = $visibility } } catch {}
            }
        }

        function Split-WmtStartupCommandLine {
            param([string]$CommandLine)
            $cmd = ([string]$CommandLine).Trim()
            if ([string]::IsNullOrWhiteSpace($cmd)) { return [PSCustomObject]@{ Target = ""; Arguments = "" } }
            if ($cmd.StartsWith('"')) {
                $closingQuote = $cmd.IndexOf('"', 1)
                if ($closingQuote -gt 1) {
                    return [PSCustomObject]@{
                        Target    = $cmd.Substring(1, $closingQuote - 1)
                        Arguments = $cmd.Substring($closingQuote + 1).Trim()
                    }
                }
            }
            $exeMatch = [regex]::Match($cmd, '^(?<target>.+?\.exe)(?<args>\s+.*)?$', [System.Text.RegularExpressions.RegexOptions]::IgnoreCase)
            if ($exeMatch.Success) {
                return [PSCustomObject]@{
                    Target    = $exeMatch.Groups['target'].Value.Trim()
                    Arguments = $exeMatch.Groups['args'].Value.Trim()
                }
            }
            $firstSpace = $cmd.IndexOf(' ')
            if ($firstSpace -gt 0) {
                return [PSCustomObject]@{
                    Target    = $cmd.Substring(0, $firstSpace).Trim()
                    Arguments = $cmd.Substring($firstSpace + 1).Trim()
                }
            }
            return [PSCustomObject]@{ Target = $cmd; Arguments = "" }
        }

        function Get-WmtShortcutCommandLine {
            param([string]$ShortcutPath)
            if ([string]::IsNullOrWhiteSpace($ShortcutPath) -or -not $ShortcutPath.EndsWith(".lnk", [System.StringComparison]::OrdinalIgnoreCase) -or -not [System.IO.File]::Exists($ShortcutPath)) { return "" }
            $shell = $null
            try {
                $shell = New-Object -ComObject WScript.Shell
                $shortcut = $shell.CreateShortcut($ShortcutPath)
                $target = [string]$shortcut.TargetPath
                $arguments = [string]$shortcut.Arguments
                if ([string]::IsNullOrWhiteSpace($target)) { return "" }
                if ($target -match '\s') { $target = '"{0}"' -f $target }
                return (($target, $arguments) -join " ").Trim()
            }
            catch { return "" }
            finally { try { if ($shell) { [void][Runtime.InteropServices.Marshal]::ReleaseComObject($shell) } } catch {} }
        }

        function Set-WmtShortcutCommandLine {
            param([string]$ShortcutPath, [string]$CommandLine)
            if ([string]::IsNullOrWhiteSpace($ShortcutPath) -or -not $ShortcutPath.EndsWith(".lnk", [System.StringComparison]::OrdinalIgnoreCase)) { return }
            if (-not [System.IO.File]::Exists($ShortcutPath)) { throw "Shortcut file was not found: $ShortcutPath" }
            $parts = Split-WmtStartupCommandLine $CommandLine
            if ([string]::IsNullOrWhiteSpace([string]$parts.Target)) { throw "Shortcut target cannot be blank." }
            $shell = $null
            try {
                $shell = New-Object -ComObject WScript.Shell
                $shortcut = $shell.CreateShortcut($ShortcutPath)
                $shortcut.TargetPath = [string]$parts.Target
                $shortcut.Arguments = [string]$parts.Arguments
                $expandedTarget = [Environment]::ExpandEnvironmentVariables(([string]$parts.Target).Trim('"'))
                if ([System.IO.File]::Exists($expandedTarget)) {
                    $targetDir = [System.IO.Path]::GetDirectoryName($expandedTarget)
                    if (-not [string]::IsNullOrWhiteSpace($targetDir) -and [System.IO.Directory]::Exists($targetDir)) { $shortcut.WorkingDirectory = $targetDir }
                }
                $shortcut.Save()
            }
            finally { try { if ($shell) { [void][Runtime.InteropServices.Marshal]::ReleaseComObject($shell) } } catch {} }
        }

        function Get-WmtRegistryDefaultValue {
            param([string]$Path)
            try {
                if (-not [string]::IsNullOrWhiteSpace($Path) -and (Test-Path -LiteralPath $Path)) {
                    $key = Get-Item -LiteralPath $Path -ErrorAction Stop
                    return [string]$key.GetValue("")
                }
            }
            catch {}
            return ""
        }

        function Set-WmtRegistryDefaultValue {
            param([string]$Path, [string]$Value)
            if ([string]::IsNullOrWhiteSpace($Path)) { return }
            if (-not (Test-Path -LiteralPath $Path)) { throw "Registry key was not found: $Path" }
            $key = Get-Item -LiteralPath $Path -ErrorAction Stop
            $key.SetValue("", [string]$Value)
        }

        $content = @'
    <Grid Margin="16">
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="*"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>

        <StackPanel Grid.Row="0" Margin="0,0,0,12">
            <TextBlock Name="lblHeading" FontSize="18" FontWeight="SemiBold" Foreground="{DynamicResource TextPrimary}"/>
            <TextBlock Name="lblHint" Margin="0,4,0,0" TextWrapping="Wrap" Foreground="{DynamicResource TextSecondary}"/>
        </StackPanel>

        <ScrollViewer Grid.Row="1" VerticalScrollBarVisibility="Auto">
            <Grid>
                <Grid.ColumnDefinitions>
                    <ColumnDefinition Width="140"/>
                    <ColumnDefinition Width="*"/>
                </Grid.ColumnDefinitions>
                <Grid.RowDefinitions>
                    <RowDefinition Height="Auto"/>
                    <RowDefinition Height="Auto"/>
                    <RowDefinition Height="Auto"/>
                    <RowDefinition Height="Auto"/>
                    <RowDefinition Height="Auto"/>
                    <RowDefinition Height="Auto"/>
                    <RowDefinition Height="Auto"/>
                </Grid.RowDefinitions>

                <TextBlock Name="lblName" Grid.Row="0" Grid.Column="0" Text="Name" Margin="0,0,12,10" VerticalAlignment="Center" Foreground="{DynamicResource TextSecondary}"/>
                <TextBox Name="txtName" Grid.Row="0" Grid.Column="1" Height="34" Margin="0,0,0,10" VerticalContentAlignment="Center"/>

                <TextBlock Name="lblDisplayName" Grid.Row="1" Grid.Column="0" Text="Display name" Margin="0,0,12,10" VerticalAlignment="Center" Foreground="{DynamicResource TextSecondary}"/>
                <TextBox Name="txtDisplayName" Grid.Row="1" Grid.Column="1" Height="34" Margin="0,0,0,10" VerticalContentAlignment="Center"/>

                <TextBlock Name="lblCommand" Grid.Row="2" Grid.Column="0" Text="Command" Margin="0,0,12,10" VerticalAlignment="Top" Foreground="{DynamicResource TextSecondary}"/>
                <TextBox Name="txtCommand" Grid.Row="2" Grid.Column="1" Height="96" Margin="0,0,0,10" AcceptsReturn="True" TextWrapping="Wrap" VerticalScrollBarVisibility="Auto"/>

                <TextBlock Name="lblLocation" Grid.Row="3" Grid.Column="0" Text="Location" Margin="0,0,12,10" VerticalAlignment="Center" Foreground="{DynamicResource TextSecondary}"/>
                <TextBox Name="txtLocation" Grid.Row="3" Grid.Column="1" Height="34" Margin="0,0,0,10" IsReadOnly="True" VerticalContentAlignment="Center"/>

                <TextBlock Name="lblValueName" Grid.Row="4" Grid.Column="0" Text="Value / path" Margin="0,0,12,10" VerticalAlignment="Center" Foreground="{DynamicResource TextSecondary}"/>
                <TextBox Name="txtValueName" Grid.Row="4" Grid.Column="1" Height="34" Margin="0,0,0,10" IsReadOnly="True" VerticalContentAlignment="Center"/>

                <TextBlock Name="lblStartupType" Grid.Row="5" Grid.Column="0" Text="Startup type" Margin="0,0,12,10" VerticalAlignment="Center" Foreground="{DynamicResource TextSecondary}"/>
                <ComboBox Name="cboStartupType" Grid.Row="5" Grid.Column="1" Height="34" Margin="0,0,0,10"/>

                <TextBlock Name="lblEnabled" Grid.Row="6" Grid.Column="0" Text="Enabled" Margin="0,0,12,10" VerticalAlignment="Center" Foreground="{DynamicResource TextSecondary}"/>
                <CheckBox Name="chkEnabled" Grid.Row="6" Grid.Column="1" Margin="0,0,0,10" VerticalAlignment="Center" Content="Enabled" Foreground="{DynamicResource TextPrimary}"/>
            </Grid>
        </ScrollViewer>

        <Grid Grid.Row="2" Margin="0,14,0,0">
            <Grid.ColumnDefinitions>
                <ColumnDefinition Width="*"/>
                <ColumnDefinition Width="Auto"/>
            </Grid.ColumnDefinitions>
            <TextBlock Name="lblStatus" Grid.Column="0" VerticalAlignment="Center" TextWrapping="Wrap" Foreground="{DynamicResource Warning}"/>
            <WrapPanel Grid.Column="1" HorizontalAlignment="Right">
                <Button Name="btnBrowse" Content="Browse Command" MinWidth="124" Margin="0,0,8,8"/>
                <Button Name="btnOpenLocation" Content="Open Location" MinWidth="112" Margin="0,0,8,8"/>
                <Button Name="btnOpenNative" Content="Open Native Editor" MinWidth="136" Margin="0,0,8,8"/>
                <Button Name="btnSave" Content="Save" MinWidth="94" IsDefault="True" Background="{DynamicResource Success}" Foreground="{DynamicResource SuccessText}" Margin="0,0,8,8"/>
                <Button Name="btnClose" Content="Close" MinWidth="94" IsCancel="True" Margin="0,0,0,8"/>
            </WrapPanel>
        </Grid>
    </Grid>
'@

        $editor = New-WmtWindowFromXaml -Title $Title -ContentXaml $content -Width 820 -Height 560 -MinWidth 680 -MinHeight 460
        try { $editor.Owner = $dialog } catch {}

        $lblHeading = $editor.FindName("lblHeading")
        $lblHint = $editor.FindName("lblHint")
        $lblName = $editor.FindName("lblName")
        $txtName = $editor.FindName("txtName")
        $lblDisplayName = $editor.FindName("lblDisplayName")
        $txtDisplayName = $editor.FindName("txtDisplayName")
        $lblCommand = $editor.FindName("lblCommand")
        $txtCommand = $editor.FindName("txtCommand")
        $lblLocation = $editor.FindName("lblLocation")
        $txtLocation = $editor.FindName("txtLocation")
        $lblValueName = $editor.FindName("lblValueName")
        $txtValueName = $editor.FindName("txtValueName")
        $lblStartupType = $editor.FindName("lblStartupType")
        $cboStartupType = $editor.FindName("cboStartupType")
        $lblEnabled = $editor.FindName("lblEnabled")
        $chkEnabled = $editor.FindName("chkEnabled")
        $lblStatus = $editor.FindName("lblStatus")
        $btnBrowse = $editor.FindName("btnBrowse")
        $btnOpenLocation = $editor.FindName("btnOpenLocation")
        $btnOpenNative = $editor.FindName("btnOpenNative")
        $btnSave = $editor.FindName("btnSave")
        $btnClose = $editor.FindName("btnClose")

        [void]$cboStartupType.Items.Add("Automatic")
        [void]$cboStartupType.Items.Add("Manual")
        [void]$cboStartupType.Items.Add("Disabled")

        $entryType = Get-StartupCellValue $row "Type"
        $itemPath = Get-StartupCellValue $row "ItemPath"
        $valueName = Get-StartupCellValue $row "ValueName"
        $rootRunPath = Get-StartupCellValue $row "RootRunPath"
        $ctxPath = Get-StartupCellValue $row "Path"
        $serviceName = Get-StartupCellValue $row "Name"
        $taskName = Get-StartupCellValue $row "TaskName"
        $taskPath = Get-StartupCellValue $row "Path"

        $lblHeading.Text = "Edit $tabName entry"
        $lblHint.Text = "Changes are written immediately when you press Save. Protected/all-users entries may require running WMT as administrator."
        $txtName.Text = Get-StartupCellValue $row "Name"
        $txtDisplayName.Text = Get-StartupCellValue $row "DisplayName"
        $txtCommand.Text = Get-StartupCellValue $row "Command"
        $txtLocation.Text = Get-StartupCellValue $row "Location"
        $txtValueName.Text = $valueName
        $chkEnabled.IsChecked = ((Get-StartupCellValue $row "Enabled") -ne "No")

        Set-StartupEditorVisibility @($lblDisplayName, $txtDisplayName, $lblStartupType, $cboStartupType, $btnOpenNative) $false
        $btnBrowse.Visibility = [System.Windows.Visibility]::Visible

        switch ($tabName) {
            "Windows" {
                if ($entryType -eq "StartupFolder") {
                    $shortcutCommand = Get-WmtShortcutCommandLine $itemPath
                    if (-not [string]::IsNullOrWhiteSpace($shortcutCommand)) { $txtCommand.Text = $shortcutCommand }
                    $txtValueName.Text = $itemPath
                    $lblCommand.Text = "Shortcut target"
                    $lblValueName.Text = "File path"
                    $lblHint.Text = "For Startup Folder shortcuts, Save can rename the file and update .lnk targets/arguments. Non-shortcut startup files can be renamed here."
                }
                else {
                    $lblCommand.Text = "Run command"
                    $lblValueName.Text = "Registry value"
                    $lblHint.Text = "Edit the Run value name, command, and StartupApproved enabled state. HKLM entries may require administrator rights."
                }
            }
            "Scheduled Tasks" {
                $txtName.Text = $taskName
                $txtName.IsReadOnly = $true
                $txtCommand.Text = "Use the native Task Scheduler editor for actions, triggers, conditions, and arguments. This WMT editor can enable or disable the task."
                $txtCommand.IsReadOnly = $true
                $txtLocation.Text = $taskPath
                $txtValueName.Text = ("{0}{1}" -f $taskPath, $taskName)
                $chkEnabled.IsChecked = ((Get-StartupCellValue $row "State") -ne "Disabled")
                $lblCommand.Text = "Notes"
                $lblLocation.Text = "Task path"
                $lblValueName.Text = "Task identity"
                Set-StartupEditorVisibility @($btnBrowse, $btnOpenNative) $true
                $btnBrowse.Visibility = [System.Windows.Visibility]::Collapsed
                $btnOpenNative.Content = "Open Task Scheduler"
                $lblHint.Text = "Task names/paths are read-only here. Use Save to enable or disable, or open Task Scheduler for advanced edits."
            }
            "Context Menu" {
                $display = Get-WmtRegistryDefaultValue $ctxPath
                if ([string]::IsNullOrWhiteSpace($display)) { $display = Get-StartupCellValue $row "Name" }
                $txtName.Text = $display
                $cmdPath = if ([string]::IsNullOrWhiteSpace($ctxPath)) { "" } else { "$ctxPath\command" }
                $txtCommand.Text = Get-WmtRegistryDefaultValue $cmdPath
                $txtLocation.Text = $ctxPath
                $txtValueName.Text = Get-StartupCellValue $row "KeyName"
                $chkEnabled.IsChecked = ((Get-StartupCellValue $row "Enabled") -ne "No")
                $lblName.Text = "Menu text"
                $lblCommand.Text = "Command"
                $lblLocation.Text = "Registry key"
                $lblValueName.Text = "Key name"
                $lblHint.Text = "Edit the menu text/default value, command subkey, and LegacyDisable enabled state."
            }
            "Services" {
                $txtName.Text = $serviceName
                $txtName.IsReadOnly = $true
                $txtDisplayName.Text = Get-StartupCellValue $row "DisplayName"
                $txtCommand.Text = "Service binary paths are not edited here. Use Registry Editor or sc.exe config for advanced service path changes."
                $txtCommand.IsReadOnly = $true
                $txtLocation.Text = "HKLM:\SYSTEM\CurrentControlSet\Services\$serviceName"
                $txtValueName.Text = $serviceName
                $currentStartType = Get-StartupCellValue $row "StartType"
                if (-not (@("Automatic", "Manual", "Disabled") -contains $currentStartType) -and -not [string]::IsNullOrWhiteSpace($currentStartType)) { [void]$cboStartupType.Items.Add($currentStartType) }
                $cboStartupType.SelectedItem = $currentStartType
                Set-StartupEditorVisibility @($lblDisplayName, $txtDisplayName, $lblStartupType, $cboStartupType, $btnOpenNative) $true
                Set-StartupEditorVisibility @($lblEnabled, $chkEnabled, $btnBrowse) $false
                $btnOpenNative.Content = "Open Services"
                $lblName.Text = "Service name"
                $lblCommand.Text = "Notes"
                $lblLocation.Text = "Registry key"
                $lblValueName.Text = "Service name"
                $lblHint.Text = "Edit the service display name and startup type. Service name and binary path are kept read-only for safety."
            }
        }

        $btnBrowse.Add_Click({
                $picker = [Microsoft.Win32.OpenFileDialog]::new()
                $picker.Filter = "Programs and scripts|*.exe;*.bat;*.cmd;*.ps1;*.vbs;*.lnk|All files|*.*"
                $existingParts = Split-WmtStartupCommandLine $txtCommand.Text
                $existingTarget = [Environment]::ExpandEnvironmentVariables(([string]$existingParts.Target).Trim('"'))
                try {
                    if (-not [string]::IsNullOrWhiteSpace($existingTarget) -and [System.IO.File]::Exists($existingTarget)) {
                        $picker.InitialDirectory = [System.IO.Path]::GetDirectoryName($existingTarget)
                        $picker.FileName = [System.IO.Path]::GetFileName($existingTarget)
                    }
                }
                catch {}
                if ($picker.ShowDialog($editor) -eq $true) {
                    $picked = [string]$picker.FileName
                    if ($picked -match '\s') { $picked = '"{0}"' -f $picked }
                    $txtCommand.Text = $picked
                }
            }.GetNewClosure())

        $btnOpenLocation.Add_Click({
                try {
                    switch ($tabName) {
                        "Windows" {
                            if ($entryType -eq "StartupFolder" -and -not [string]::IsNullOrWhiteSpace($itemPath) -and [System.IO.File]::Exists($itemPath)) { Start-Process explorer.exe -ArgumentList ("/select,`"{0}`"" -f $itemPath) }
                            elseif (-not [string]::IsNullOrWhiteSpace($rootRunPath)) { Start-Process regedit.exe }
                        }
                        "Scheduled Tasks" { Start-Process taskschd.msc }
                        "Context Menu" { Start-Process regedit.exe }
                        "Services" { Start-Process services.msc }
                    }
                }
                catch { $lblStatus.Text = "Open failed: $($_.Exception.Message)" }
            }.GetNewClosure())

        $btnOpenNative.Add_Click({
                try {
                    switch ($tabName) {
                        "Scheduled Tasks" { Start-Process taskschd.msc }
                        "Services" { Start-Process services.msc }
                        default { Start-Process regedit.exe }
                    }
                }
                catch { $lblStatus.Text = "Open failed: $($_.Exception.Message)" }
            }.GetNewClosure())

        $btnSave.Add_Click({
                Set-WmtBusyCursor -Busy
                $lblStatus.Text = "Saving..."
                try {
                    switch ($tabName) {
                        "Windows" {
                            $newName = ([string]$txtName.Text).Trim()
                            $newCommand = ([string]$txtCommand.Text).Trim()
                            $enabled = [bool]$chkEnabled.IsChecked
                            if ([string]::IsNullOrWhiteSpace($newName)) { throw "Name cannot be blank." }

                            if ($entryType -eq "Registry") {
                                $runPath = if ([string]::IsNullOrWhiteSpace($rootRunPath)) { $itemPath } else { $rootRunPath }
                                if ([string]::IsNullOrWhiteSpace($runPath)) { throw "Registry path is missing." }
                                if ([string]::IsNullOrWhiteSpace($newCommand)) { throw "Run command cannot be blank." }
                                if (-not (Test-Path -LiteralPath $runPath)) { New-Item -Path $runPath -Force -ErrorAction Stop | Out-Null }
                                Set-ItemProperty -Path $runPath -Name $newName -Value $newCommand -ErrorAction Stop
                                if ($valueName -and $newName -ne $valueName) {
                                    Remove-ItemProperty -Path $runPath -Name $valueName -ErrorAction SilentlyContinue
                                }
                                & $fnSetStartupApprovedState "Registry" $runPath $newName $enabled
                                Set-StartupCellValue $row "Name" $newName
                                Set-StartupCellValue $row "Command" $newCommand
                                Set-StartupCellValue $row "ItemPath" $runPath
                                Set-StartupCellValue $row "ValueName" $newName
                                Set-StartupCellValue $row "RootRunPath" $runPath
                                Set-StartupCellValue $row "Enabled" $(if ($enabled) { "Yes" } else { "No" })
                            }
                            elseif ($entryType -eq "StartupFolder") {
                                if ([string]::IsNullOrWhiteSpace($itemPath) -or -not [System.IO.File]::Exists($itemPath)) { throw "Startup folder item was not found." }
                                $directory = [System.IO.Path]::GetDirectoryName($itemPath)
                                $extension = [System.IO.Path]::GetExtension($itemPath)
                                if ([string]::IsNullOrWhiteSpace($extension)) { $extension = ".lnk" }
                                $newFileName = $newName
                                if ([System.IO.Path]::GetExtension($newFileName) -eq "") { $newFileName = "$newFileName$extension" }
                                if ($newFileName.IndexOfAny([System.IO.Path]::GetInvalidFileNameChars()) -ge 0) { throw "Name contains invalid file-name characters." }
                                $newPath = Join-Path $directory $newFileName
                                if ($newPath -ne $itemPath) {
                                    Move-Item -LiteralPath $itemPath -Destination $newPath -Force -ErrorAction Stop
                                    $itemPath = $newPath
                                    $valueName = [System.IO.Path]::GetFileName($newPath)
                                }
                                if ($itemPath.EndsWith(".lnk", [System.StringComparison]::OrdinalIgnoreCase) -and -not [string]::IsNullOrWhiteSpace($newCommand)) {
                                    Set-WmtShortcutCommandLine -ShortcutPath $itemPath -CommandLine $newCommand
                                }
                                & $fnSetStartupApprovedState "StartupFolder" $directory ([System.IO.Path]::GetFileName($itemPath)) $enabled
                                Set-StartupCellValue $row "Name" ([System.IO.Path]::GetFileNameWithoutExtension($itemPath))
                                Set-StartupCellValue $row "Command" $(if ($itemPath.EndsWith(".lnk", [System.StringComparison]::OrdinalIgnoreCase) -and -not [string]::IsNullOrWhiteSpace($newCommand)) { $newCommand } else { $itemPath })
                                Set-StartupCellValue $row "Location" $directory
                                Set-StartupCellValue $row "ItemPath" $itemPath
                                Set-StartupCellValue $row "ValueName" ([System.IO.Path]::GetFileName($itemPath))
                                Set-StartupCellValue $row "RootRunPath" $directory
                                Set-StartupCellValue $row "Enabled" $(if ($enabled) { "Yes" } else { "No" })
                            }
                        }
                        "Scheduled Tasks" {
                            if ([string]::IsNullOrWhiteSpace($taskName)) { throw "Task name is missing." }
                            if ([bool]$chkEnabled.IsChecked) {
                                Enable-ScheduledTask -TaskName $taskName -TaskPath $taskPath -ErrorAction Stop | Out-Null
                                Set-StartupCellValue $row "State" "Ready"
                            }
                            else {
                                Disable-ScheduledTask -TaskName $taskName -TaskPath $taskPath -ErrorAction Stop | Out-Null
                                Set-StartupCellValue $row "State" "Disabled"
                            }
                        }
                        "Context Menu" {
                            if ([string]::IsNullOrWhiteSpace($ctxPath)) { throw "Registry key is missing." }
                            $newDisplayName = ([string]$txtName.Text).Trim()
                            $newCommand = ([string]$txtCommand.Text).Trim()
                            if (-not (Test-Path -LiteralPath $ctxPath)) { throw "Registry key was not found." }
                            if (-not [string]::IsNullOrWhiteSpace($newDisplayName)) {
                                Set-WmtRegistryDefaultValue -Path $ctxPath -Value $newDisplayName
                                Set-ItemProperty -LiteralPath $ctxPath -Name "MUIVerb" -Value $newDisplayName -ErrorAction SilentlyContinue
                                Set-StartupCellValue $row "Name" $newDisplayName
                            }
                            if (-not [string]::IsNullOrWhiteSpace($newCommand)) {
                                Set-WmtRegistryDefaultValue -Path "$ctxPath\command" -Value $newCommand
                            }
                            if ([bool]$chkEnabled.IsChecked) {
                                Remove-ItemProperty -LiteralPath $ctxPath -Name "LegacyDisable" -ErrorAction SilentlyContinue
                                Set-StartupCellValue $row "Enabled" "Yes"
                            }
                            else {
                                Set-ItemProperty -LiteralPath $ctxPath -Name "LegacyDisable" -Value "" -ErrorAction Stop
                                Set-StartupCellValue $row "Enabled" "No"
                            }
                        }
                        "Services" {
                            if ([string]::IsNullOrWhiteSpace($serviceName)) { throw "Service name is missing." }
                            $newDisplayName = ([string]$txtDisplayName.Text).Trim()
                            $newStartType = [string]$cboStartupType.SelectedItem
                            if (-not [string]::IsNullOrWhiteSpace($newDisplayName)) {
                                Set-Service -Name $serviceName -DisplayName $newDisplayName -ErrorAction Stop
                                Set-StartupCellValue $row "DisplayName" $newDisplayName
                            }
                            if (@("Automatic", "Manual", "Disabled") -contains $newStartType) {
                                Set-Service -Name $serviceName -StartupType $newStartType -ErrorAction Stop
                                Set-StartupCellValue $row "StartType" $newStartType
                            }
                        }
                    }
                    try { $TabObj.Grid.Items.Refresh() } catch {}
                    & $fnUpdateStartupTabFilter $TabObj
                    $lblStatus.Text = "Saved."
                    $editor.DialogResult = $true
                }
                catch {
                    $lblStatus.Text = "Save failed: $($_.Exception.Message)"
                    Show-WmtMessageBox -Owner $editor -Message "Could not save changes.`n$($_.Exception.Message)" -Title "Startup Manager" -Image Error | Out-Null
                }
                finally { Set-WmtBusyCursor }
            }.GetNewClosure())

        $btnClose.Add_Click({ $editor.Close() }.GetNewClosure())
        $editor.ShowDialog() | Out-Null
    }

    function Remove-WmtDataRows {
        param($TabObj, [object[]]$Rows)
        foreach ($row in @($Rows)) { try { $row.Delete() } catch {} }
        $TabObj.Meta.Table.AcceptChanges()
        & $fnUpdateStartupTabFilter $TabObj
    }

    function Get-StartupApprovedState {
        param([string]$Type, [string]$RootPath, [string]$ValueName)
        $approvedPath = if ($Type -eq "Registry") {
            if ($RootPath -match "(?i)WOW6432Node") { $RootPath -replace "(?i)WOW6432Node\\", "" -replace "(?i)CurrentVersion\\Run", "CurrentVersion\Explorer\StartupApproved\Run32" }
            else { $RootPath -replace "(?i)CurrentVersion\\Run", "CurrentVersion\Explorer\StartupApproved\Run" }
        }
        else {
            if ($RootPath -match "(?i)Roaming") { "HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\StartupApproved\StartupFolder" }
            else { "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\StartupApproved\StartupFolder" }
        }
        if ($approvedPath -and (Test-Path $approvedPath)) {
            $val = Get-ItemProperty -Path $approvedPath -ErrorAction SilentlyContinue
            if ($null -ne $val.$ValueName) { return ($val.$ValueName[0] % 2 -eq 0) }
        }
        return $true
    }

    function Set-StartupApprovedState {
        param([string]$Type, [string]$RootPath, [string]$ValueName, [bool]$Enable)
        $approvedPath = if ($Type -eq "Registry") {
            if ($RootPath -match "(?i)WOW6432Node") { $RootPath -replace "(?i)WOW6432Node\\", "" -replace "(?i)CurrentVersion\\Run", "CurrentVersion\Explorer\StartupApproved\Run32" }
            else { $RootPath -replace "(?i)CurrentVersion\\Run", "CurrentVersion\Explorer\StartupApproved\Run" }
        }
        else {
            if ($RootPath -match "(?i)Roaming") { "HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\StartupApproved\StartupFolder" }
            else { "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\StartupApproved\StartupFolder" }
        }
        if (-not (Test-Path $approvedPath)) { New-Item -Path $approvedPath -Force | Out-Null }
        $stateByte = if ($Enable) { [byte]0x02 } else { [byte]0x03 }
        $payload = [byte[]]($stateByte, 0x00, 0x00, 0x00) + [BitConverter]::GetBytes([DateTime]::Now.ToFileTime())
        Set-ItemProperty -Path $approvedPath -Name $ValueName -Value $payload -Type Binary -ErrorAction SilentlyContinue
    }

    function Get-RegRunEntries {
        param([string]$Path, [string]$Scope)
        $items = @()
        if (-not (Test-Path $Path)) { return $items }
        $props = Get-ItemProperty -Path $Path -ErrorAction SilentlyContinue
        if (-not $props) { return $items }
        foreach ($p in $props.PSObject.Properties) {
            if ($p.Name -in @("PSPath", "PSParentPath", "PSChildName", "PSDrive", "PSProvider")) { continue }
            $items += [PSCustomObject]@{
                Name        = $p.Name
                Command     = "$($p.Value)"
                Location    = $Path
                EntryType   = "Registry"
                Scope       = $Scope
                Enabled     = (& $fnGetStartupApprovedState "Registry" $Path $p.Name)
                ItemPath    = $Path
                ValueName   = $p.Name
                RootRunPath = $Path
            }
        }
        return $items
    }

    function Get-StartupFolderEntries {
        param([string]$Path, [string]$Scope)
        $items = @()
        if (-not (Test-Path $Path)) { return $items }
        foreach ($filePath in Get-WmtEnumeratedFiles -Path $Path) {
            $file = [System.IO.FileInfo]::new($filePath)
            $items += [PSCustomObject]@{
                Name        = $file.BaseName
                Command     = $file.FullName
                Location    = $Path
                EntryType   = "StartupFolder"
                Scope       = $Scope
                Enabled     = (& $fnGetStartupApprovedState "StartupFolder" $Path $file.Name)
                ItemPath    = $file.FullName
                ValueName   = $file.Name
                RootRunPath = $Path
            }
        }
        return $items
    }

    function Add-GridContextMenu {
        param($TabObj, [System.Windows.Controls.Button[]]$Buttons)
        $menu = [System.Windows.Controls.ContextMenu]::new()
        Set-WmtContextMenuChrome -ContextMenu $menu
        foreach ($button in @($Buttons)) {
            $item = [System.Windows.Controls.MenuItem]::new()
            $item.Header = [string]$button.Content
            $item.Tag = $button
            $item.Add_Click({
                    param($eventSource, $e)
                    $button = [System.Windows.Controls.Button]$eventSource.Tag
                    $button.RaiseEvent([System.Windows.RoutedEventArgs]::new([System.Windows.Controls.Primitives.ButtonBase]::ClickEvent, $button))
                }.GetNewClosure())
            [void]$menu.Items.Add($item)
        }
        $TabObj.Grid.ContextMenu = $menu
    }

    function Invoke-StartupWindowsLoad {
        $items = @()
        $items += & $fnGetRegRunEntries "HKCU:\Software\Microsoft\Windows\CurrentVersion\Run" "Current User"
        $items += & $fnGetRegRunEntries "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Run" "All Users"
        $items += & $fnGetRegRunEntries "HKLM:\SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Run" "All Users (32-bit)"
        $items += & $fnGetStartupFolderEntries "$env:APPDATA\Microsoft\Windows\Start Menu\Programs\Startup" "Current User"
        $items += & $fnGetStartupFolderEntries "$env:ProgramData\Microsoft\Windows\Start Menu\Programs\Startup" "All Users"

        $table = [System.Data.DataTable]::new()
        foreach ($name in @("Name", "Enabled", "Scope", "Type", "Command", "Location", "ItemPath", "ValueName", "RootRunPath")) { [void]$table.Columns.Add($name) }
        foreach ($item in @($items)) {
            $row = $table.NewRow()
            $row["Name"] = [string]$item.Name
            $row["Enabled"] = if ([bool]$item.Enabled) { "Yes" } else { "No" }
            $row["Scope"] = [string]$item.Scope
            $row["Type"] = [string]$item.EntryType
            $row["Command"] = [string]$item.Command
            $row["Location"] = [string]$item.Location
            $row["ItemPath"] = [string]$item.ItemPath
            $row["ValueName"] = [string]$item.ValueName
            $row["RootRunPath"] = [string]$item.RootRunPath
            [void]$table.Rows.Add($row)
        }
        & $fnSetStartupTabData $winTab $table @("Name", "Enabled", "Scope", "Type", "Command", "Location") @("Command", "Location", "ItemPath", "ValueName", "RootRunPath") @{ Name = "44*"; Enabled = "12*"; Scope = "24*"; Type = "20*" }
        & $fnUpdateStartupTabFilter $winTab
    }

    function Invoke-StartupTasksLoad {
        $tasks = @(Get-ScheduledTask -ErrorAction SilentlyContinue | Select-Object TaskName, TaskPath, State)
        $table = [System.Data.DataTable]::new()
        foreach ($name in @("TaskName", "Path", "State")) { [void]$table.Columns.Add($name) }
        foreach ($task in @($tasks)) {
            $row = $table.NewRow()
            $row["TaskName"] = [string]$task.TaskName
            $row["Path"] = [string]$task.TaskPath
            $row["State"] = [string]$task.State
            [void]$table.Rows.Add($row)
        }
        & $fnSetStartupTabData $taskTab $table @("TaskName", "Path", "State") @() @{ TaskName = "*"; Path = 260; State = 120 }
        & $fnUpdateStartupTabFilter $taskTab
    }

    function Invoke-StartupContextMenuLoad {
        if (-not (Get-PSDrive HKCR -ErrorAction SilentlyContinue)) { New-PSDrive -Name HKCR -PSProvider Registry -Root HKEY_CLASSES_ROOT -ErrorAction SilentlyContinue | Out-Null }
        $table = [System.Data.DataTable]::new()
        foreach ($name in @("Name", "Enabled", "Root", "Path", "KeyName")) { [void]$table.Columns.Add($name) }
        foreach ($rootInfo in @(
                @{ Path = "HKCR:\*\shell"; RootName = "All Files (*)" },
                @{ Path = "HKCR:\Directory\shell"; RootName = "Directory" },
                @{ Path = "HKCR:\Directory\Background\shell"; RootName = "Directory Background" },
                @{ Path = "HKCR:\Drive\shell"; RootName = "Drive" }
            )) {
            if (-not (Test-Path -LiteralPath $rootInfo.Path -ErrorAction SilentlyContinue)) { continue }
            foreach ($subKey in @(Get-ChildItem -LiteralPath $rootInfo.Path -ErrorAction SilentlyContinue)) {
                $row = $table.NewRow()
                $row["Name"] = [string]$subKey.PSChildName
                $row["Enabled"] = if ($null -ne (Get-ItemProperty -LiteralPath $subKey.PSPath -Name "LegacyDisable" -ErrorAction SilentlyContinue)) { "No" } else { "Yes" }
                $row["Root"] = [string]$rootInfo.RootName
                $row["Path"] = [string]$subKey.PSPath
                $row["KeyName"] = [string]$subKey.Name
                [void]$table.Rows.Add($row)
            }
        }
        & $fnSetStartupTabData $ctxTab $table @("Name", "Enabled", "Root", "KeyName") @("Path", "KeyName") @{ Name = "68*"; Enabled = "12*"; Root = "20*" }
        & $fnUpdateStartupTabFilter $ctxTab
    }

    function Invoke-StartupServicesLoad {
        $table = [System.Data.DataTable]::new()
        foreach ($name in @("Name", "DisplayName", "StartType", "State")) { [void]$table.Columns.Add($name) }
        foreach ($service in @(Get-Service -ErrorAction SilentlyContinue | Sort-Object DisplayName)) {
            $startType = "Unknown"
            try {
                $rawStart = (Get-ItemProperty -Path ("HKLM:\SYSTEM\CurrentControlSet\Services\" + $service.Name) -Name Start -ErrorAction SilentlyContinue).Start
                switch ($rawStart) {
                    0 { $startType = "Boot" }
                    1 { $startType = "System" }
                    2 { $startType = "Automatic" }
                    3 { $startType = "Manual" }
                    4 { $startType = "Disabled" }
                    default { if ($null -ne $rawStart) { $startType = [string]$rawStart } }
                }
            }
            catch {}
            $row = $table.NewRow()
            $row["Name"] = [string]$service.Name
            $row["DisplayName"] = [string]$service.DisplayName
            $row["StartType"] = [string]$startType
            $row["State"] = [string]$service.Status
            [void]$table.Rows.Add($row)
        }
        & $fnSetStartupTabData $svcTab $table @("Name", "DisplayName", "StartType", "State") @() @{ DisplayName = "56*"; Name = "24*"; StartType = "10*"; State = "10*" }
        & $fnUpdateStartupTabFilter $svcTab
    }

    function Invoke-StartupTabLoad {
        param([string]$TabName, [bool]$Force = $false)
        if (-not $Force -and $tabLoaded.ContainsKey($TabName) -and $tabLoaded[$TabName]) { return }
        Set-WmtBusyCursor -Busy
        try {
            switch ($TabName) {
                "Windows" { & $LoadWindowsStartup }
                "Scheduled Tasks" { & $LoadScheduledTasks }
                "Context Menu" { & $LoadContextMenu }
                "Services" { & $LoadServices }
            }
            if ($tabLoaded.ContainsKey($TabName)) { $tabLoaded[$TabName] = $true }
        }
        catch {
            Show-WmtMessageBox -Owner $dialog -Message "Failed to load tab '$TabName'.`n$($_.Exception.Message)" -Title "Startup Manager" -Image Error | Out-Null
        }
        finally {
            Set-WmtBusyCursor
        }
    }

    function Set-StartupView {
        param([string]$Title)
        foreach ($key in @($tabs.Keys)) {
            $tabs[$key].Root.Visibility = if ($key -eq $Title) { [System.Windows.Visibility]::Visible } else { [System.Windows.Visibility]::Collapsed }
        }
        & $fnSetTabButtonActive $Title
        & $fnInvokeStartupTabLoad $Title $false
    }

    function Invoke-WmtStartupTaskSelection {
        param([ValidateSet("Enable", "Disable", "Delete")][string]$Action)

        $selected = @(Get-WmtDataGridSelectedRows -DataGrid $taskTab.Grid)
        if ($selected.Count -eq 0) { return }
        if ($Action -eq "Delete") {
            $confirm = Show-WmtMessageBox -Owner $dialog -Message "Delete $($selected.Count) selected scheduled task(s)?" -Title "Confirm" -Button YesNo -Image Warning
            if ($confirm -ne [System.Windows.MessageBoxResult]::Yes) { return }
        }

        Set-WmtBusyCursor -Busy
        $failures = @()
        try {
            foreach ($row in $selected) {
                $name = [string]$row["TaskName"]
                $path = [string]$row["Path"]
                $result = Invoke-WmtScheduledTaskAction -Action $Action -TaskName $name -TaskPath $path
                if ($result.Success) {
                    if ($Action -eq "Enable") { $row["State"] = "Ready" }
                    elseif ($Action -eq "Disable") { $row["State"] = "Disabled" }
                    elseif ($Action -eq "Delete") { $row.Delete() }
                }
                else {
                    $failures += "$($result.Task): $($result.Message)"
                }
            }
            if ($Action -eq "Delete") { $taskTab.Meta.Table.AcceptChanges() }
            & $fnUpdateStartupTabFilter $taskTab
        }
        finally {
            Set-WmtBusyCursor
        }

        if ($failures.Count -gt 0) {
            Show-WmtMessageBox -Owner $dialog -Message ($failures -join "`r`n") -Title "Scheduled Tasks" -Image Warning | Out-Null
        }
    }

    $btnWinTab = New-TabButton "Windows"
    $btnTaskTab = New-TabButton "Scheduled Tasks"
    $btnCtxTab = New-TabButton "Context Menu"
    $btnSvcTab = New-TabButton "Services"

    $winTab = New-StartupPage "Windows"
    $taskTab = New-StartupPage "Scheduled Tasks"
    $ctxTab = New-StartupPage "Context Menu"
    $svcTab = New-StartupPage "Services"

    $fnSetTabButtonActive = ${function:Set-TabButtonActive}.GetNewClosure()
    $fnSetStartupTabData = ${function:Set-StartupTabData}.GetNewClosure()
    $fnUpdateStartupTabFilter = ${function:Update-StartupTabFilter}.GetNewClosure()
    $fnShowStartupRowDetails = ${function:Show-StartupRowDetails}.GetNewClosure()
    $fnGetStartupApprovedState = ${function:Get-StartupApprovedState}.GetNewClosure()
    $fnSetStartupApprovedState = ${function:Set-StartupApprovedState}.GetNewClosure()
    $fnRemoveWmtDataRows = ${function:Remove-WmtDataRows}.GetNewClosure()
    $fnGetRegRunEntries = ${function:Get-RegRunEntries}.GetNewClosure()
    $fnGetStartupFolderEntries = ${function:Get-StartupFolderEntries}.GetNewClosure()
    $LoadWindowsStartup = ${function:Invoke-StartupWindowsLoad}.GetNewClosure()
    $LoadScheduledTasks = ${function:Invoke-StartupTasksLoad}.GetNewClosure()
    $LoadContextMenu = ${function:Invoke-StartupContextMenuLoad}.GetNewClosure()
    $LoadServices = ${function:Invoke-StartupServicesLoad}.GetNewClosure()
    $fnInvokeStartupTabLoad = ${function:Invoke-StartupTabLoad}.GetNewClosure()
    $fnSetStartupView = ${function:Set-StartupView}.GetNewClosure()
    $fnInvokeStartupTaskSelection = ${function:Invoke-WmtStartupTaskSelection}.GetNewClosure()

    $btnWinTab.Add_Click({ & $fnSetStartupView "Windows" }.GetNewClosure())
    $btnTaskTab.Add_Click({ & $fnSetStartupView "Scheduled Tasks" }.GetNewClosure())
    $btnCtxTab.Add_Click({ & $fnSetStartupView "Context Menu" }.GetNewClosure())
    $btnSvcTab.Add_Click({ & $fnSetStartupView "Services" }.GetNewClosure())

    foreach ($t in @($winTab, $taskTab, $ctxTab, $svcTab)) {
        $t.SearchBox.Tag = $t
        $t.Grid.Tag = $t
        $t.ClearButton.Tag = $t
        $t.SearchBox.Add_TextChanged({
                param($eventSource, $e)
                & $fnUpdateStartupTabFilter $eventSource.Tag
            }.GetNewClosure())
        $t.ClearButton.Add_Click({
                param($eventSource, $e)
                $eventSource.Tag.SearchBox.Text = ""
            }.GetNewClosure())
        $t.Grid.Add_MouseDoubleClick({
                param($eventSource, $e)
                & $fnShowStartupRowDetails $eventSource.Tag "$($eventSource.Tag.Header) Details"
            }.GetNewClosure())
    }

    $btnWinRefresh = New-StartupButton $winTab.Buttons "Refresh" "Standard"
    $btnWinDetails = New-StartupButton $winTab.Buttons "Details" "Standard"
    $btnWinEnable = New-StartupButton $winTab.Buttons "Enable" "Success"
    $btnWinDisable = New-StartupButton $winTab.Buttons "Disable" "Warning"
    $btnWinDelete = New-StartupButton $winTab.Buttons "Delete" "Danger"
    Add-GridContextMenu -TabObj $winTab -Buttons @($btnWinRefresh, $btnWinDetails, $btnWinEnable, $btnWinDisable, $btnWinDelete)

    $btnTaskRefresh = New-StartupButton $taskTab.Buttons "Refresh" "Standard"
    $btnTaskDetails = New-StartupButton $taskTab.Buttons "Details" "Standard"
    $btnTaskEnable = New-StartupButton $taskTab.Buttons "Enable" "Success"
    $btnTaskDisable = New-StartupButton $taskTab.Buttons "Disable" "Warning"
    $btnTaskDelete = New-StartupButton $taskTab.Buttons "Delete" "Danger"
    Add-GridContextMenu -TabObj $taskTab -Buttons @($btnTaskRefresh, $btnTaskDetails, $btnTaskEnable, $btnTaskDisable, $btnTaskDelete)

    $btnCtxRefresh = New-StartupButton $ctxTab.Buttons "Refresh" "Standard"
    $btnCtxDetails = New-StartupButton $ctxTab.Buttons "Details" "Standard"
    $btnCtxEnable = New-StartupButton $ctxTab.Buttons "Enable" "Success"
    $btnCtxDisable = New-StartupButton $ctxTab.Buttons "Disable" "Warning"
    $btnCtxDelete = New-StartupButton $ctxTab.Buttons "Delete" "Danger"
    Add-GridContextMenu -TabObj $ctxTab -Buttons @($btnCtxRefresh, $btnCtxDetails, $btnCtxEnable, $btnCtxDisable, $btnCtxDelete)

    $btnSvcRefresh = New-StartupButton $svcTab.Buttons "Refresh" "Standard"
    $btnSvcDetails = New-StartupButton $svcTab.Buttons "Details" "Standard"
    $btnSvcEnable = New-StartupButton $svcTab.Buttons "Enable Auto" "Success"
    $btnSvcManual = New-StartupButton $svcTab.Buttons "Manual" "Primary"
    $btnSvcDisable = New-StartupButton $svcTab.Buttons "Disable" "Warning"
    $btnSvcDelete = New-StartupButton $svcTab.Buttons "Delete" "Danger"
    Add-GridContextMenu -TabObj $svcTab -Buttons @($btnSvcRefresh, $btnSvcDetails, $btnSvcEnable, $btnSvcManual, $btnSvcDisable, $btnSvcDelete)

    $btnWinRefresh.Add_Click({ & $fnInvokeStartupTabLoad "Windows" $true }.GetNewClosure())
    $btnWinDetails.Add_Click({ & $fnShowStartupRowDetails $winTab "Windows Startup Details" }.GetNewClosure())
    $btnWinEnable.Add_Click({ foreach ($row in Get-WmtDataGridSelectedRows $winTab.Grid) { & $fnSetStartupApprovedState ([string]$row["Type"]) ([string]$row["RootRunPath"]) ([string]$row["ValueName"]) $true; $row["Enabled"] = "Yes" } }.GetNewClosure())
    $btnWinDisable.Add_Click({ foreach ($row in Get-WmtDataGridSelectedRows $winTab.Grid) { & $fnSetStartupApprovedState ([string]$row["Type"]) ([string]$row["RootRunPath"]) ([string]$row["ValueName"]) $false; $row["Enabled"] = "No" } }.GetNewClosure())
    $btnWinDelete.Add_Click({
            $selected = @(Get-WmtDataGridSelectedRows $winTab.Grid)
            if ($selected.Count -eq 0) { return }
            if ((Show-WmtMessageBox -Owner $dialog -Message "Delete selected entries?" -Title "Confirm" -Button YesNo -Image Warning) -ne [System.Windows.MessageBoxResult]::Yes) { return }
            foreach ($row in $selected) {
                $type = [string]$row["Type"]
                $itemPath = [string]$row["ItemPath"]
                $valueName = [string]$row["ValueName"]
                if ($type -eq "StartupFolder") { Remove-Item -LiteralPath $itemPath -Force -ErrorAction SilentlyContinue }
                elseif ($type -eq "Registry" -and $itemPath -and $valueName) { Remove-ItemProperty -Path $itemPath -Name $valueName -ErrorAction SilentlyContinue }
            }
            & $fnRemoveWmtDataRows $winTab $selected
        }.GetNewClosure())

    $btnTaskRefresh.Add_Click({ & $fnInvokeStartupTabLoad "Scheduled Tasks" $true }.GetNewClosure())
    $btnTaskDetails.Add_Click({ & $fnShowStartupRowDetails $taskTab "Task Details" }.GetNewClosure())
    $btnTaskEnable.Add_Click({ & $fnInvokeStartupTaskSelection Enable }.GetNewClosure())
    $btnTaskDisable.Add_Click({ & $fnInvokeStartupTaskSelection Disable }.GetNewClosure())
    $btnTaskDelete.Add_Click({ & $fnInvokeStartupTaskSelection Delete }.GetNewClosure())

    $btnCtxRefresh.Add_Click({ & $fnInvokeStartupTabLoad "Context Menu" $true }.GetNewClosure())
    $btnCtxDetails.Add_Click({ & $fnShowStartupRowDetails $ctxTab "Context Menu Details" }.GetNewClosure())
    $btnCtxEnable.Add_Click({ foreach ($row in Get-WmtDataGridSelectedRows $ctxTab.Grid) { $path = [string]$row["Path"]; if ($path -and (Test-Path -LiteralPath $path)) { Remove-ItemProperty -LiteralPath $path -Name "LegacyDisable" -ErrorAction SilentlyContinue; $row["Enabled"] = "Yes" } } }.GetNewClosure())
    $btnCtxDisable.Add_Click({ foreach ($row in Get-WmtDataGridSelectedRows $ctxTab.Grid) { $path = [string]$row["Path"]; if ($path -and (Test-Path -LiteralPath $path)) { Set-ItemProperty -LiteralPath $path -Name "LegacyDisable" -Value "" -ErrorAction SilentlyContinue; $row["Enabled"] = "No" } } }.GetNewClosure())
    $btnCtxDelete.Add_Click({
            $selected = @(Get-WmtDataGridSelectedRows $ctxTab.Grid)
            if ($selected.Count -eq 0) { return }
            if ((Show-WmtMessageBox -Owner $dialog -Message "Delete selected context menu entries?" -Title "Confirm" -Button YesNo -Image Warning) -ne [System.Windows.MessageBoxResult]::Yes) { return }
            foreach ($row in $selected) { $path = [string]$row["Path"]; if ($path -and (Test-Path -LiteralPath $path)) { Remove-Item -LiteralPath $path -Recurse -Force -ErrorAction SilentlyContinue } }
            & $fnRemoveWmtDataRows $ctxTab $selected
        }.GetNewClosure())

    $btnSvcRefresh.Add_Click({ & $fnInvokeStartupTabLoad "Services" $true }.GetNewClosure())
    $btnSvcDetails.Add_Click({ & $fnShowStartupRowDetails $svcTab "Service Details" }.GetNewClosure())
    $btnSvcEnable.Add_Click({ foreach ($row in Get-WmtDataGridSelectedRows $svcTab.Grid) { $name = [string]$row["Name"]; if ($name) { Set-Service -Name $name -StartupType Automatic -ErrorAction SilentlyContinue; $row["StartType"] = "Automatic" } } }.GetNewClosure())
    $btnSvcManual.Add_Click({ foreach ($row in Get-WmtDataGridSelectedRows $svcTab.Grid) { $name = [string]$row["Name"]; if ($name) { Set-Service -Name $name -StartupType Manual -ErrorAction SilentlyContinue; $row["StartType"] = "Manual" } } }.GetNewClosure())
    $btnSvcDisable.Add_Click({ foreach ($row in Get-WmtDataGridSelectedRows $svcTab.Grid) { $name = [string]$row["Name"]; if ($name) { Set-Service -Name $name -StartupType Disabled -ErrorAction SilentlyContinue; $row["StartType"] = "Disabled" } } }.GetNewClosure())
    $btnSvcDelete.Add_Click({
            $selected = @(Get-WmtDataGridSelectedRows $svcTab.Grid)
            if ($selected.Count -eq 0) { return }
            if ((Show-WmtMessageBox -Owner $dialog -Message "Delete selected services? This is risky." -Title "Confirm" -Button YesNo -Image Warning) -ne [System.Windows.MessageBoxResult]::Yes) { return }
            foreach ($row in $selected) { $name = [string]$row["Name"]; if ($name) { sc.exe delete $name | Out-Null } }
            & $fnRemoveWmtDataRows $svcTab $selected
        }.GetNewClosure())

    $dialog.Add_ContentRendered({
            switch ($DefaultTab) {
                "Scheduled Tasks" { & $fnSetStartupView "Scheduled Tasks" }
                "Context Menu" { & $fnSetStartupView "Context Menu" }
                "Services" { & $fnSetStartupView "Services" }
                default { & $fnSetStartupView "Windows" }
            }
        }.GetNewClosure())
    $dialog.ShowDialog() | Out-Null
}


# --- Tweaks Functions ---
function Set-Hags {
    param([bool]$Enable)
    
    if ($Enable) {
        Invoke-UiCommand {
            $path = "HKLM:\SYSTEM\CurrentControlSet\Control\GraphicsDrivers"
            if (-not (Test-Path $path)) { New-Item -Path $path -Force | Out-Null }
                
            Set-ItemProperty -Path $path -Name "HwSchMode" -Value 2 -Type DWord
            Write-Output "Hardware-Accelerated GPU Scheduling (HAGS) enabled. Reboot required."
                
            [System.Windows.MessageBox]::Show("HAGS enabled successfully. Please restart your computer to apply the changes.", "HAGS Status", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Information) | Out-Null
        } "Enabling HAGS..."
    }
    else {
        Invoke-UiCommand {
            $path = "HKLM:\SYSTEM\CurrentControlSet\Control\GraphicsDrivers"
            if (-not (Test-Path $path)) { New-Item -Path $path -Force | Out-Null }
                
            Set-ItemProperty -Path $path -Name "HwSchMode" -Value 1 -Type DWord
            Write-Output "Hardware-Accelerated GPU Scheduling (HAGS) disabled. Reboot required."
                
            [System.Windows.MessageBox]::Show("HAGS disabled successfully. Please restart your computer to apply the changes.", "HAGS Status", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Information) | Out-Null
        } "Disabling HAGS..."
    }
}

function Get-WmtRegValue {
    param(
        [string]$Path,
        [string]$Name,
        $Default = $null
    )

    try {
        $item = Get-ItemProperty -Path $Path -Name $Name -ErrorAction Stop
        return $item.$Name
    }
    catch {
        return $Default
    }
}

function Set-WmtRegDword {
    param(
        [string]$Path,
        [string]$Name,
        [int]$Value
    )

    if (-not (Test-Path $Path)) { New-Item -Path $Path -Force | Out-Null }
    Set-ItemProperty -Path $Path -Name $Name -Value $Value -Type DWord -Force
}

function Set-WmtRegString {
    param(
        [string]$Path,
        [string]$Name,
        [string]$Value
    )

    if (-not (Test-Path $Path)) { New-Item -Path $Path -Force | Out-Null }
    Set-ItemProperty -Path $Path -Name $Name -Value $Value -Type String -Force
}

function Remove-WmtRegValue {
    param(
        [string]$Path,
        [string]$Name
    )

    if (Test-Path $Path) {
        Remove-ItemProperty -Path $Path -Name $Name -ErrorAction SilentlyContinue
    }
}

function Restart-WmtExplorer {
    try { Stop-Process -Name explorer -Force -ErrorAction SilentlyContinue } catch {}
}

function Invoke-WmtUserSettingRefresh {
    try {
        Start-Process -FilePath "$env:SystemRoot\System32\RUNDLL32.EXE" -ArgumentList "USER32.DLL,UpdatePerUserSystemParameters" -WindowStyle Hidden -ErrorAction SilentlyContinue | Out-Null
    }
    catch {}
}

function Test-WmtExplorerSingleClick {
    $shellState = Get-WmtRegValue "HKCU:\Software\Microsoft\Windows\CurrentVersion\Explorer" "ShellState"
    return ($shellState -and $shellState.Length -gt 4 -and [int]$shellState[4] -eq 0x1E)
}

function Set-WmtExplorerClickMode {
    param([bool]$SingleClick)

    $path = "HKCU:\Software\Microsoft\Windows\CurrentVersion\Explorer"
    if (-not (Test-Path $path)) { New-Item -Path $path -Force | Out-Null }

    $shellState = Get-WmtRegValue $path "ShellState"
    if (-not $shellState -or $shellState.Length -lt 5) {
        $shellState = [byte[]](0x24, 0x00, 0x00, 0x00, 0x3E, 0x28, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00)
    }

    $shellState[4] = if ($SingleClick) { [byte]0x1E } else { [byte]0x3E }
    Set-ItemProperty -Path $path -Name "ShellState" -Value $shellState -Type Binary -Force
    Set-WmtRegDword $path "IconUnderline" $(if ($SingleClick) { 2 } else { 3 })
    Restart-WmtExplorer
}

function Set-WmtMouseSpeed {
    param([int]$Speed)

    $speed = [math]::Max(1, [math]::Min(20, $Speed))
    $path = "HKCU:\Control Panel\Mouse"
    Set-WmtRegString $path "MouseSensitivity" ([string]$speed)
    Invoke-WmtUserSettingRefresh
}

function Set-WmtMouseAcceleration {
    param([bool]$Enable)

    $path = "HKCU:\Control Panel\Mouse"
    if ($Enable) {
        Set-WmtRegString $path "MouseSpeed" "1"
        Set-WmtRegString $path "MouseThreshold1" "6"
        Set-WmtRegString $path "MouseThreshold2" "10"
    }
    else {
        Set-WmtRegString $path "MouseSpeed" "0"
        Set-WmtRegString $path "MouseThreshold1" "0"
        Set-WmtRegString $path "MouseThreshold2" "0"
    }
    Invoke-WmtUserSettingRefresh
}

function Set-WmtContentDeliveryValues {
    param(
        [string[]]$Names,
        [int]$Value
    )

    $path = "HKCU:\Software\Microsoft\Windows\CurrentVersion\ContentDeliveryManager"
    foreach ($name in $Names) {
        Set-WmtRegDword $path $name $Value
    }
}

function Set-WmtClassicContextMenu {
    param([bool]$Enable)

    $clsid = "HKCU:\Software\Classes\CLSID\{86ca1aa0-34aa-4e8b-a509-50c905bae2a2}"
    $inproc = Join-Path $clsid "InprocServer32"
    if ($Enable) {
        if (-not (Test-Path $inproc)) { New-Item -Path $inproc -Force | Out-Null }
        Set-Item -Path $inproc -Value "" -Force
    }
    else {
        if (Test-Path $clsid) { Remove-Item -Path $clsid -Recurse -Force -ErrorAction SilentlyContinue }
    }
    Restart-WmtExplorer
}

function Set-WmtTakeOwnershipMenu {
    param([bool]$Enable)

    $targets = @(
        @{Path = "Registry::HKEY_CLASSES_ROOT\*\shell\WMT_TakeOwnership"; Command = 'powershell.exe -NoProfile -ExecutionPolicy Bypass -Command "Start-Process cmd.exe -Verb RunAs -ArgumentList ''/c takeown /f ""%1"" /a && icacls ""%1"" /grant *S-1-5-32-544:F /c && pause''"' },
        @{Path = "Registry::HKEY_CLASSES_ROOT\Directory\shell\WMT_TakeOwnership"; Command = 'powershell.exe -NoProfile -ExecutionPolicy Bypass -Command "Start-Process cmd.exe -Verb RunAs -ArgumentList ''/c takeown /f ""%1"" /r /d y /a && icacls ""%1"" /grant *S-1-5-32-544:F /t /c && pause''"' },
        @{Path = "Registry::HKEY_CLASSES_ROOT\Drive\shell\WMT_TakeOwnership"; Command = 'powershell.exe -NoProfile -ExecutionPolicy Bypass -Command "Start-Process cmd.exe -Verb RunAs -ArgumentList ''/c takeown /f ""%1"" /r /d y /a && icacls ""%1"" /grant *S-1-5-32-544:F /t /c && pause''"' }
    )

    foreach ($target in $targets) {
        $path = $target.Path
        if ($Enable) {
            if (-not (Test-Path $path)) { New-Item -Path $path -Force | Out-Null }
            Set-Item -Path $path -Value "Take Ownership" -Force
            New-ItemProperty -Path $path -Name "HasLUAShield" -Value "" -PropertyType String -Force | Out-Null
            $cmdPath = Join-Path $path "command"
            if (-not (Test-Path $cmdPath)) { New-Item -Path $cmdPath -Force | Out-Null }
            Set-Item -Path $cmdPath -Value $target.Command -Force
        }
        else {
            if (Test-Path $path) { Remove-Item -Path $path -Recurse -Force -ErrorAction SilentlyContinue }
        }
    }
}

function Set-WmtPowerShellHereMenu {
    param([bool]$Enable)

    $targets = @(
        @{Path = "Registry::HKEY_CLASSES_ROOT\Directory\Background\shell\WMT_OpenPowerShell"; Location = "%V" },
        @{Path = "Registry::HKEY_CLASSES_ROOT\Directory\shell\WMT_OpenPowerShell"; Location = "%1" },
        @{Path = "Registry::HKEY_CLASSES_ROOT\Drive\shell\WMT_OpenPowerShell"; Location = "%1" }
    )

    foreach ($target in $targets) {
        $path = $target.Path
        if ($Enable) {
            if (-not (Test-Path $path)) { New-Item -Path $path -Force | Out-Null }
            Set-Item -Path $path -Value "Open PowerShell Here" -Force
            Set-ItemProperty -Path $path -Name "Icon" -Value "powershell.exe" -Type String -Force
            $cmdPath = Join-Path $path "command"
            if (-not (Test-Path $cmdPath)) { New-Item -Path $cmdPath -Force | Out-Null }
            Set-Item -Path $cmdPath -Value "powershell.exe -NoExit -NoProfile -ExecutionPolicy Bypass -Command `"Set-Location -LiteralPath '$($target.Location)'`"" -Force
        }
        else {
            if (Test-Path $path) { Remove-Item -Path $path -Recurse -Force -ErrorAction SilentlyContinue }
        }
    }
}

function Set-WmtVisualPreset {
    param([ValidateSet("Appearance", "Performance", "Snappy")] [string]$Mode)

    $visualPath = "HKCU:\Software\Microsoft\Windows\CurrentVersion\Explorer\VisualEffects"
    $desktopPath = "HKCU:\Control Panel\Desktop"
    $advancedPath = "HKCU:\Software\Microsoft\Windows\CurrentVersion\Explorer\Advanced"
    $dwmPath = "HKCU:\Software\Microsoft\Windows\DWM"
    $personalizePath = "HKCU:\Software\Microsoft\Windows\CurrentVersion\Themes\Personalize"

    switch ($Mode) {
        "Appearance" {
            Set-WmtRegDword $visualPath "VisualFXSetting" 1
            Set-WmtRegString $desktopPath "MinAnimate" "1"
            Set-WmtRegDword $advancedPath "TaskbarAnimations" 1
            Set-WmtRegDword $dwmPath "EnableAeroPeek" 1
            Set-WmtRegDword $personalizePath "EnableTransparency" 1
        }
        "Performance" {
            Set-WmtRegDword $visualPath "VisualFXSetting" 2
        }
        "Snappy" {
            Set-WmtRegDword $visualPath "VisualFXSetting" 3
            Set-WmtRegString $desktopPath "MinAnimate" "0"
            Set-WmtRegDword $advancedPath "TaskbarAnimations" 0
            Set-WmtRegDword $dwmPath "EnableAeroPeek" 0
            Set-WmtRegDword $personalizePath "EnableTransparency" 0
        }
    }

    Restart-WmtExplorer
}

function Get-WmtPowerSettingIndex {
    param(
        [string]$SubGroup,
        [string]$Setting,
        [ValidateSet("AC", "DC")] [string]$Mode = "AC"
    )

    try {
        $output = powercfg /query SCHEME_CURRENT $SubGroup $Setting 2>$null
        $label = if ($Mode -eq "DC") { "Current DC Power Setting Index" } else { "Current AC Power Setting Index" }
        $pattern = [regex]::Escape($label) + "\s*:\s*0x([0-9a-fA-F]+)"
        foreach ($line in $output) {
            if ($line -match $pattern) { return [Convert]::ToInt32($matches[1], 16) }
        }
        $output = powercfg /qh SCHEME_CURRENT $SubGroup $Setting 2>$null
        foreach ($line in $output) {
            if ($line -match $pattern) { return [Convert]::ToInt32($matches[1], 16) }
        }
    }
    catch {}
    return $null
}

function Set-WmtPowerSettingIndex {
    param(
        [string]$SubGroup,
        [string]$Setting,
        [int]$Value,
        [switch]$DCOnly
    )

    if (-not $DCOnly) { powercfg /setacvalueindex SCHEME_CURRENT $SubGroup $Setting $Value | Out-Null }
    powercfg /setdcvalueindex SCHEME_CURRENT $SubGroup $Setting $Value | Out-Null
    powercfg /S SCHEME_CURRENT | Out-Null
}

# ==========================================
# 3. XAML GUI
# ==========================================
[xml]$xaml = @"
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="Windows Maintenance Tool v$AppVersion" Height="820" Width="1280" MinHeight="620" MinWidth="960"
        WindowStartupLocation="CenterScreen" Background="{DynamicResource BgDark}" Foreground="{DynamicResource TextPrimary}"
        FontFamily="Segoe UI Variable Display, Segoe UI, Arial" FontSize="13"
        TextOptions.TextFormattingMode="Display"
        TextOptions.TextRenderingMode="ClearType"
        UseLayoutRounding="True"
        SnapsToDevicePixels="True">

    <Window.Resources>
        <!-- Modern Color Palette (GitHub Dark inspired) -->
        <SolidColorBrush x:Key="BgDark" Color="#0D1117"/>
        <SolidColorBrush x:Key="BgPanel" Color="#161B22"/>
        <SolidColorBrush x:Key="BgElevated" Color="#21262D"/>
        <SolidColorBrush x:Key="BgHover" Color="#30363D"/>
        <SolidColorBrush x:Key="BorderBrush" Color="#30363D"/>
        <SolidColorBrush x:Key="BorderAccent" Color="#58A6FF"/>
        <SolidColorBrush x:Key="Accent" Color="#58A6FF"/>
        <SolidColorBrush x:Key="AccentHover" Color="#79C0FF"/>
        <SolidColorBrush x:Key="TextPrimary" Color="#E6EDF3"/>
        <SolidColorBrush x:Key="TextSecondary" Color="#8B949E"/>
        <SolidColorBrush x:Key="TextMuted" Color="#6E7681"/>
        <SolidColorBrush x:Key="Success" Color="#238636"/>
        <SolidColorBrush x:Key="SuccessHover" Color="#2EA043"/>
        <SolidColorBrush x:Key="Danger" Color="#DA3633"/>
        <SolidColorBrush x:Key="DangerHover" Color="#F85149"/>
        <SolidColorBrush x:Key="Warning" Color="#D29922"/>
        <SolidColorBrush x:Key="WarningHover" Color="#E3B341"/>
        <SolidColorBrush x:Key="Info" Color="#1F6FEB"/>
        <SolidColorBrush x:Key="AccentText" Color="#0D1117"/>
        <SolidColorBrush x:Key="SuccessText" Color="#F6FFFA"/>
        <SolidColorBrush x:Key="DangerText" Color="#FFF5F5"/>
        <SolidColorBrush x:Key="WarningText" Color="#0D1117"/>
        <SolidColorBrush x:Key="InfoText" Color="#F0F6FC"/>

        <!-- Subtle Shadow Effects (reduced for clarity) -->
        <DropShadowEffect x:Key="CardShadow" ShadowDepth="1" BlurRadius="4" Opacity="0.15" Color="#000000"/>

        <!-- Transparent, theme-aware scrollbars for all WPF scroll viewers -->
        <Style x:Key="TransparentScrollRepeatButton" TargetType="{x:Type RepeatButton}">
            <Setter Property="Focusable" Value="False"/>
            <Setter Property="Background" Value="Transparent"/>
            <Setter Property="BorderThickness" Value="0"/>
            <Setter Property="Template">
                <Setter.Value>
                    <ControlTemplate TargetType="{x:Type RepeatButton}">
                        <Border Background="Transparent"/>
                    </ControlTemplate>
                </Setter.Value>
            </Setter>
        </Style>

        <Style TargetType="{x:Type ScrollBar}">
            <Setter Property="Width" Value="10"/>
            <Setter Property="MinWidth" Value="10"/>
            <Setter Property="Background" Value="Transparent"/>
            <Setter Property="Template">
                <Setter.Value>
                    <ControlTemplate TargetType="{x:Type ScrollBar}">
                        <Grid Background="{TemplateBinding Background}" SnapsToDevicePixels="True">
                            <Track x:Name="PART_Track" IsDirectionReversed="True">
                                <Track.DecreaseRepeatButton>
                                    <RepeatButton x:Name="PageDecreaseButton" Command="{x:Static ScrollBar.PageUpCommand}" Style="{StaticResource TransparentScrollRepeatButton}"/>
                                </Track.DecreaseRepeatButton>
                                <Track.Thumb>
                                    <Thumb x:Name="ScrollThumb" MinHeight="34" Background="{DynamicResource BorderBrush}">
                                        <Thumb.Template>
                                            <ControlTemplate TargetType="{x:Type Thumb}">
                                                <Border Background="{TemplateBinding Background}" CornerRadius="5" Margin="2"/>
                                            </ControlTemplate>
                                        </Thumb.Template>
                                    </Thumb>
                                </Track.Thumb>
                                <Track.IncreaseRepeatButton>
                                    <RepeatButton x:Name="PageIncreaseButton" Command="{x:Static ScrollBar.PageDownCommand}" Style="{StaticResource TransparentScrollRepeatButton}"/>
                                </Track.IncreaseRepeatButton>
                            </Track>
                        </Grid>
                        <ControlTemplate.Triggers>
                            <Trigger Property="Orientation" Value="Horizontal">
                                <Setter Property="Width" Value="Auto"/>
                                <Setter Property="MinWidth" Value="0"/>
                                <Setter Property="Height" Value="10"/>
                                <Setter Property="MinHeight" Value="10"/>
                                <Setter TargetName="PART_Track" Property="IsDirectionReversed" Value="False"/>
                                <Setter TargetName="ScrollThumb" Property="MinWidth" Value="34"/>
                                <Setter TargetName="ScrollThumb" Property="MinHeight" Value="0"/>
                                <Setter TargetName="PageDecreaseButton" Property="Command" Value="{x:Static ScrollBar.PageLeftCommand}"/>
                                <Setter TargetName="PageIncreaseButton" Property="Command" Value="{x:Static ScrollBar.PageRightCommand}"/>
                            </Trigger>
                            <Trigger Property="IsMouseOver" Value="True">
                                <Setter TargetName="ScrollThumb" Property="Background" Value="{DynamicResource TextSecondary}"/>
                            </Trigger>
                            <Trigger SourceName="ScrollThumb" Property="IsDragging" Value="True">
                                <Setter TargetName="ScrollThumb" Property="Background" Value="{DynamicResource Accent}"/>
                            </Trigger>
                            <Trigger Property="IsEnabled" Value="False">
                                <Setter Property="Opacity" Value="0.4"/>
                            </Trigger>
                        </ControlTemplate.Triggers>
                    </ControlTemplate>
                </Setter.Value>
            </Setter>
        </Style>

        <!-- Modern TextBox (crisp text) -->
        <Style TargetType="TextBox">
            <Setter Property="Background" Value="{DynamicResource BgDark}"/>
            <Setter Property="Foreground" Value="{DynamicResource TextPrimary}"/>
            <Setter Property="BorderBrush" Value="{DynamicResource BorderBrush}"/>
            <Setter Property="BorderThickness" Value="1"/>
            <Setter Property="Padding" Value="10,6"/>
            <Setter Property="FontSize" Value="13"/>
            <Setter Property="SnapsToDevicePixels" Value="True"/>
            <Setter Property="UseLayoutRounding" Value="True"/>
            <Setter Property="TextOptions.TextFormattingMode" Value="Display"/>
            <Setter Property="TextOptions.TextRenderingMode" Value="ClearType"/>
            <Style.Triggers>
                <Trigger Property="IsFocused" Value="True">
                    <Setter Property="BorderBrush" Value="{DynamicResource BorderAccent}"/>
                </Trigger>
            </Style.Triggers>
        </Style>

        <Style TargetType="CheckBox">
            <Setter Property="Foreground" Value="{DynamicResource TextPrimary}"/>
            <Setter Property="VerticalAlignment" Value="Center"/>
            <Setter Property="SnapsToDevicePixels" Value="True"/>
            <Setter Property="UseLayoutRounding" Value="True"/>
            <Setter Property="TextOptions.TextFormattingMode" Value="Display"/>
            <Setter Property="TextOptions.TextRenderingMode" Value="ClearType"/>
        </Style>

        <!-- Modern Navigation Button (crisp text) -->
        <Style TargetType="Button" x:Key="NavBtn">
            <Setter Property="Background" Value="Transparent"/>
            <Setter Property="Foreground" Value="{DynamicResource TextSecondary}"/>
            <Setter Property="BorderThickness" Value="0"/>
            <Setter Property="Height" Value="38"/>
            <Setter Property="Margin" Value="2"/>
            <Setter Property="HorizontalContentAlignment" Value="Left"/>
            <Setter Property="Padding" Value="12,0"/>
            <Setter Property="FontSize" Value="13"/>
            <Setter Property="SnapsToDevicePixels" Value="True"/>
            <Setter Property="UseLayoutRounding" Value="True"/>
            <Setter Property="TextOptions.TextFormattingMode" Value="Display"/>
            <Setter Property="TextOptions.TextRenderingMode" Value="ClearType"/>
            <Setter Property="Template">
                <Setter.Value>
                    <ControlTemplate TargetType="Button">
                        <Grid>
                            <Border Name="Bd" Background="{TemplateBinding Background}" CornerRadius="4" UseLayoutRounding="True">
                                <ContentPresenter VerticalAlignment="Center" Margin="{TemplateBinding Padding}"/>
                            </Border>
                            <!-- Active Indicator Bar (left side) -->
                            <Border Name="Indicator" Width="3" Background="{DynamicResource Accent}" HorizontalAlignment="Left" 
                                    CornerRadius="2,0,0,2" Visibility="{TemplateBinding Tag}" UseLayoutRounding="True"/>
                        </Grid>
                        <ControlTemplate.Triggers>
                            <Trigger Property="IsMouseOver" Value="True">
                                <Setter TargetName="Bd" Property="Background" Value="{DynamicResource BgElevated}"/>
                                <Setter Property="Foreground" Value="{DynamicResource TextPrimary}"/>
                            </Trigger>
                        </ControlTemplate.Triggers>
                    </ControlTemplate>
                </Setter.Value>
            </Setter>
        </Style>

        <!-- Modern Action Button (clean, no blur) -->
        <Style TargetType="Button" x:Key="ActionBtn">
            <Setter Property="Background" Value="{DynamicResource BgElevated}"/>
            <Setter Property="Foreground" Value="{DynamicResource TextPrimary}"/>
            <Setter Property="BorderBrush" Value="{DynamicResource BorderBrush}"/>
            <Setter Property="Height" Value="32"/>
            <Setter Property="Margin" Value="4"/>
            <Setter Property="FontSize" Value="12"/>
            <Setter Property="FontWeight" Value="Normal"/>
            <Setter Property="SnapsToDevicePixels" Value="True"/>
            <Setter Property="UseLayoutRounding" Value="True"/>
            <Setter Property="TextOptions.TextFormattingMode" Value="Display"/>
            <Setter Property="TextOptions.TextRenderingMode" Value="ClearType"/>
            <Setter Property="Template">
                <Setter.Value>
                    <ControlTemplate TargetType="Button">
                        <Border Name="Bd" Background="{TemplateBinding Background}" CornerRadius="4" 
                                BorderBrush="{TemplateBinding BorderBrush}" BorderThickness="1">
                            <ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center" Margin="16,0"/>
                        </Border>
                    </ControlTemplate>
                </Setter.Value>
            </Setter>
            <Style.Triggers>
                <Trigger Property="IsMouseOver" Value="True">
                    <Setter Property="Background" Value="{DynamicResource BgHover}"/>
                    <Setter Property="BorderBrush" Value="{DynamicResource TextSecondary}"/>
                </Trigger>
                <Trigger Property="IsEnabled" Value="False">
                    <Setter Property="Background" Value="{DynamicResource BgPanel}"/>
                    <Setter Property="Foreground" Value="{DynamicResource TextMuted}"/>
                    <Setter Property="Opacity" Value="0.55"/>
                </Trigger>
            </Style.Triggers>
        </Style>

        <!-- Success/Green Button -->
        <Style TargetType="Button" x:Key="PositiveBtn" BasedOn="{StaticResource ActionBtn}">
            <Setter Property="Background" Value="{DynamicResource Success}"/>
            <Setter Property="BorderBrush" Value="{DynamicResource SuccessHover}"/>
            <Setter Property="Foreground" Value="{DynamicResource SuccessText}"/>
            <Style.Triggers>
                <Trigger Property="IsMouseOver" Value="True">
                    <Setter Property="Background" Value="{DynamicResource SuccessHover}"/>
                    <Setter Property="BorderBrush" Value="{DynamicResource SuccessHover}"/>
                </Trigger>
            </Style.Triggers>
        </Style>

        <!-- Danger/Red Button -->
        <Style TargetType="Button" x:Key="DestructiveBtn" BasedOn="{StaticResource ActionBtn}">
            <Setter Property="Background" Value="{DynamicResource Danger}"/>
            <Setter Property="BorderBrush" Value="{DynamicResource DangerHover}"/>
            <Setter Property="Foreground" Value="{DynamicResource DangerText}"/>
            <Style.Triggers>
                <Trigger Property="IsMouseOver" Value="True">
                    <Setter Property="Background" Value="{DynamicResource DangerHover}"/>
                    <Setter Property="BorderBrush" Value="{DynamicResource DangerHover}"/>
                </Trigger>
            </Style.Triggers>
        </Style>

        <!-- Warning/Yellow Button -->
        <Style TargetType="Button" x:Key="WarningBtn" BasedOn="{StaticResource ActionBtn}">
            <Setter Property="Background" Value="{DynamicResource Warning}"/>
            <Setter Property="BorderBrush" Value="{DynamicResource WarningHover}"/>
            <Setter Property="Foreground" Value="{DynamicResource WarningText}"/>
            <Style.Triggers>
                <Trigger Property="IsMouseOver" Value="True">
                    <Setter Property="Background" Value="{DynamicResource WarningHover}"/>
                    <Setter Property="BorderBrush" Value="{DynamicResource WarningHover}"/>
                </Trigger>
            </Style.Triggers>
        </Style>

        <!-- Info/Blue Button -->
        <Style TargetType="Button" x:Key="UtilityBtn" BasedOn="{StaticResource ActionBtn}">
            <Setter Property="Background" Value="{DynamicResource Info}"/>
            <Setter Property="BorderBrush" Value="{DynamicResource Accent}"/>
            <Setter Property="Foreground" Value="{DynamicResource InfoText}"/>
            <Style.Triggers>
                <Trigger Property="IsMouseOver" Value="True">
                    <Setter Property="Background" Value="{DynamicResource Accent}"/>
                    <Setter Property="BorderBrush" Value="{DynamicResource AccentHover}"/>
                </Trigger>
            </Style.Triggers>
        </Style>

        <!-- Accent Button -->
        <Style TargetType="Button" x:Key="AccentBtn" BasedOn="{StaticResource ActionBtn}">
            <Setter Property="Background" Value="{DynamicResource Accent}"/>
            <Setter Property="BorderBrush" Value="{DynamicResource AccentHover}"/>
            <Setter Property="Foreground" Value="{DynamicResource AccentText}"/>
            <Setter Property="FontWeight" Value="Bold"/>
            <Style.Triggers>
                <Trigger Property="IsMouseOver" Value="True">
                    <Setter Property="Background" Value="{DynamicResource AccentHover}"/>
                </Trigger>
            </Style.Triggers>
        </Style>

        <!-- Modern ListView Item (crisp text) -->
        <Style x:Key="FwItem" TargetType="ListViewItem">
            <Setter Property="BorderThickness" Value="0"/>
            <Setter Property="Padding" Value="12,6"/>
            <Setter Property="Margin" Value="2,1"/>
            <Setter Property="Background" Value="Transparent"/>
            <Setter Property="SnapsToDevicePixels" Value="True"/>
            <Setter Property="UseLayoutRounding" Value="True"/>
            <Setter Property="TextOptions.TextFormattingMode" Value="Display"/>
            <Setter Property="TextOptions.TextRenderingMode" Value="ClearType"/>
            <Style.Triggers>
                <Trigger Property="ItemsControl.AlternationIndex" Value="0">
                    <Setter Property="Background" Value="{DynamicResource BgPanel}"/>
                </Trigger>
                <Trigger Property="ItemsControl.AlternationIndex" Value="1">
                    <Setter Property="Background" Value="{DynamicResource BgDark}"/>
                </Trigger>
                <Trigger Property="IsSelected" Value="True">
                    <Setter Property="Background" Value="{DynamicResource Accent}"/>
                    <Setter Property="Foreground" Value="{DynamicResource AccentText}"/>
                    <Setter Property="FontWeight" Value="Medium"/>
                </Trigger>
                <Trigger Property="IsMouseOver" Value="True">
                    <Setter Property="Background" Value="{DynamicResource BgHover}"/>
                </Trigger>
            </Style.Triggers>
        </Style>

        <!-- Card Style Border (clean, crisp) -->
        <Style x:Key="CardStyle" TargetType="Border">
            <Setter Property="Background" Value="{DynamicResource BgPanel}"/>
            <Setter Property="BorderBrush" Value="{DynamicResource BorderBrush}"/>
            <Setter Property="BorderThickness" Value="1"/>
            <Setter Property="CornerRadius" Value="4"/>
            <Setter Property="Margin" Value="6"/>
            <Setter Property="Padding" Value="16"/>
            <Setter Property="SnapsToDevicePixels" Value="True"/>
            <Setter Property="UseLayoutRounding" Value="True"/>
        </Style>

        <!-- Section Header Text (crisp) -->
        <Style x:Key="SectionHeader" TargetType="TextBlock">
            <Setter Property="FontSize" Value="26"/>
            <Setter Property="FontWeight" Value="SemiBold"/>
            <Setter Property="Foreground" Value="{DynamicResource TextPrimary}"/>
            <Setter Property="Margin" Value="0,0,0,16"/>
            <Setter Property="SnapsToDevicePixels" Value="True"/>
            <Setter Property="TextOptions.TextFormattingMode" Value="Display"/>
            <Setter Property="TextOptions.TextRenderingMode" Value="ClearType"/>
        </Style>

        <!-- Subsection Header (crisp) -->
        <Style x:Key="SubHeader" TargetType="TextBlock">
            <Setter Property="FontSize" Value="11"/>
            <Setter Property="FontWeight" Value="Bold"/>
            <Setter Property="Foreground" Value="{DynamicResource TextSecondary}"/>
            <Setter Property="Margin" Value="0,0,0,10"/>
            <Setter Property="FontFamily" Value="Segoe UI, Arial"/>
            <Setter Property="SnapsToDevicePixels" Value="True"/>
            <Setter Property="TextOptions.TextFormattingMode" Value="Display"/>
        </Style>
    </Window.Resources>

    <Grid>
        <Grid.ColumnDefinitions>
            <ColumnDefinition Width="300"/>
            <ColumnDefinition Width="*"/>
        </Grid.ColumnDefinitions>

        <!-- Sidebar -->
        <Border Grid.Column="0" Background="{DynamicResource BgPanel}" BorderBrush="{DynamicResource BorderBrush}" BorderThickness="0,0,1,0">
            <Grid>
                <Grid.RowDefinitions>
                    <RowDefinition Height="Auto"/> 
                    <RowDefinition Height="Auto"/> 
                    <RowDefinition Height="Auto"/>    
                    <RowDefinition Height="6"/>
                    <RowDefinition Height="*"/>
                </Grid.RowDefinitions>

                <!-- Header/Search -->
                <Border Name="bdQuickFind" Grid.Row="0" Background="{DynamicResource BgDark}" Margin="16,20,16,12" CornerRadius="8" BorderBrush="{DynamicResource BorderBrush}" BorderThickness="1" Cursor="IBeam">
                    <StackPanel Margin="12">
                        <TextBlock Text="Quick Find" FontSize="11" Foreground="{DynamicResource TextMuted}" FontWeight="SemiBold" Margin="0,0,0,8"/>
                        <TextBox Name="txtGlobalSearch" Height="36" ToolTip="Search any function..." VerticalContentAlignment="Center"
                                 Background="{DynamicResource BgPanel}" Foreground="{DynamicResource TextPrimary}"
                                 BorderBrush="{DynamicResource BorderBrush}" BorderThickness="1" Padding="10,0"/>
                    </StackPanel>
                </Border>

                <!-- Navigation -->
                <StackPanel Grid.Row="1" Margin="8,8,8,0">
                    <TextBlock Text="NAVIGATION" Style="{StaticResource SubHeader}" Margin="12,0,0,4"/>
                    <StackPanel Name="pnlNavButtons">
                        <Button Name="btnTabUpdates" Content="Updates" Style="{StaticResource NavBtn}" Tag="pnlUpdates"/>
                        <Button Name="btnTabTweaks" Content="Tweaks" Style="{StaticResource NavBtn}" Tag="pnlTweaks"/>
                        <Button Name="btnTabHealth" Content="System Health" Style="{StaticResource NavBtn}" Tag="pnlHealth"/>
                        <Button Name="btnTabNetwork" Content="Network &amp; DNS" Style="{StaticResource NavBtn}" Tag="pnlNetwork"/>
                        <Button Name="btnTabFirewall" Content="Firewall" Style="{StaticResource NavBtn}" Tag="pnlFirewall"/>
                        <Button Name="btnTabDrivers" Content="Drivers" Style="{StaticResource NavBtn}" Tag="pnlDrivers"/>
                        <Button Name="btnTabCleanup" Content="Cleanup" Style="{StaticResource NavBtn}" Tag="pnlCleanup"/>
                        <Button Name="btnTabUtils" Content="Utilities" Style="{StaticResource NavBtn}" Tag="pnlUtils"/>
                        <Button Name="btnTabMyDevice" Style="{StaticResource NavBtn}" Tag="pnlMyDevice">
                            <StackPanel Orientation="Horizontal">
                                <Path Data="M21 2H3c-1.1 0-2 .9-2 2v12c0 1.1.9 2 2 2h7v2H8v2h8v-2h-2v-2h7c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2zm0 14H3V4h18v12z" 
                                      Fill="{DynamicResource TextSecondary}" 
                                      Width="16" Height="16" Stretch="Uniform" Margin="0,0,10,0" VerticalAlignment="Center"/>
                                <TextBlock Text="My Device" VerticalAlignment="Center"/>
                            </StackPanel>
                        </Button>
                        <Button Name="btnTabSupport" Content="Support" Style="{StaticResource NavBtn}" Tag="pnlSupport"/>
                        <Button Name="btnNavDownloads" Content="Download Stats" Style="{StaticResource NavBtn}" ToolTip="Show latest release download counts"/>
                    </StackPanel>
                </StackPanel>
                
                <ListBox Name="lstSearchResults" Grid.Row="2" Background="{DynamicResource BgDark}" BorderThickness="0" Foreground="{DynamicResource Accent}" Visibility="Collapsed" Margin="8" MaxHeight="220"/>

                <GridSplitter Grid.Row="3" Height="8" Margin="12,0" HorizontalAlignment="Stretch" VerticalAlignment="Center"
                              Background="Transparent" Cursor="SizeNS" ResizeDirection="Rows" ResizeBehavior="PreviousAndNext"
                              ShowsPreview="True"/>

                <!-- Log Panel -->
                <Border Grid.Row="4" Background="{DynamicResource BgDark}" Margin="12" CornerRadius="8" BorderBrush="{DynamicResource BorderBrush}" BorderThickness="1" MinHeight="140" VerticalAlignment="Stretch">
                    <Grid>
                        <Grid.RowDefinitions>
                            <RowDefinition Height="Auto"/>
                            <RowDefinition Height="*"/>
                        </Grid.RowDefinitions>
                        <Border Grid.Row="0" Background="{DynamicResource BgPanel}" CornerRadius="8,8,0,0" Padding="12,8">
                            <TextBlock Text="Activity Log" FontSize="11" Foreground="{DynamicResource TextMuted}" FontWeight="SemiBold"/>
                        </Border>
                        <ScrollViewer Name="svLog" Grid.Row="1" VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Disabled" Margin="8" UseLayoutRounding="True" VerticalAlignment="Stretch">
                            <TextBox Name="LogBox" IsReadOnly="True" TextWrapping="Wrap" FontFamily="Consolas, monospace" FontSize="12" 
                                     Background="Transparent" Foreground="#3FB950" BorderThickness="0" Padding="4"
                                     VerticalAlignment="Stretch" AcceptsReturn="True"
                                     SnapsToDevicePixels="True" TextOptions.TextFormattingMode="Display"/>
                        </ScrollViewer>
                    </Grid>
                </Border>
            </Grid>
        </Border>

        <Border Grid.Column="1" Background="{DynamicResource BgDark}">
            <Grid Margin="20">
                
                <!-- UPDATES PANEL -->
                <Grid Name="pnlUpdates" Visibility="Visible">
                    <Grid.RowDefinitions>
                        <RowDefinition Height="Auto"/>
                        <RowDefinition Height="*"/>
                        <RowDefinition Height="Auto"/>
                    </Grid.RowDefinitions>
                    
                    <!-- Header Card -->
                    <Border Grid.Row="0" Style="{StaticResource CardStyle}" Margin="0,0,0,12">
                        <Grid>
                            <Grid.ColumnDefinitions>
                                <ColumnDefinition Width="*"/>
                                <ColumnDefinition Width="320"/>
                            </Grid.ColumnDefinitions>
                            <StackPanel VerticalAlignment="Center">
                                <StackPanel>
                                    <TextBlock Name="lblWingetTitle" Text="Package Updates" Style="{StaticResource SectionHeader}" Margin="0"/>
                                    <TextBlock Name="lblWingetStatus" Text="Ready to scan" Foreground="#D29922" FontSize="13" Visibility="Visible"/>
                                    <StackPanel Orientation="Horizontal" Margin="0,8,0,0" VerticalAlignment="Center">
                                        <ProgressBar Name="pbWingetProgress" Width="260" Height="8" Minimum="0" Maximum="100" Value="0" Visibility="Collapsed"/>
                                        <TextBlock Name="lblWingetProgress" Text="" Margin="10,0,0,0" Foreground="{DynamicResource TextMuted}" FontSize="12" Visibility="Collapsed"/>
                                    </StackPanel>
                                    <TextBlock Name="lblWingetLastResult" Text="" Margin="0,6,0,0" Foreground="{DynamicResource TextMuted}" FontSize="12" Visibility="Collapsed"/>
                                </StackPanel>
                            </StackPanel>
                            <Grid Grid.Column="1">
                                <Grid.ColumnDefinitions>
                                    <ColumnDefinition Width="*"/>
                                    <ColumnDefinition Width="Auto"/>
                                </Grid.ColumnDefinitions>
                                <TextBox Name="txtWingetSearch" Grid.Column="0" Height="40" VerticalContentAlignment="Center" Text="Search packages..."/>
                                <Button Name="btnWingetFind" Grid.Column="1" Content="Search" Width="100" Height="40" Margin="8,0,0,0" Style="{StaticResource AccentBtn}"/>
                            </Grid>
                        </Grid>
                    </Border>

                    <!-- List Card -->
                    <Border Grid.Row="1" Style="{StaticResource CardStyle}" Padding="0">
                        <ListView Name="lstWinget" Background="Transparent" Foreground="{DynamicResource TextPrimary}" BorderThickness="0" 
                                  SelectionMode="Extended" AlternationCount="2" ItemContainerStyle="{StaticResource FwItem}"
                                  VirtualizingStackPanel.IsVirtualizing="True" VirtualizingStackPanel.VirtualizationMode="Recycling" ScrollViewer.CanContentScroll="True">
                            <ListView.View>
                                <GridView>
                                    <GridViewColumn Header="Select" Width="64">
                                        <GridViewColumn.CellTemplate>
                                            <DataTemplate>
                                                <CheckBox IsChecked="{Binding IsChecked, Mode=TwoWay, UpdateSourceTrigger=PropertyChanged}"
                                                          HorizontalAlignment="Center" VerticalAlignment="Center"
                                                          ToolTip="Check this item to include it when you click Update Checked"/>
                                            </DataTemplate>
                                        </GridViewColumn.CellTemplate>
                                    </GridViewColumn>
                                    <GridViewColumn Header="Source" Width="90" DisplayMemberBinding="{Binding Source}"/>
                                    <GridViewColumn Header="Package Name" Width="280" DisplayMemberBinding="{Binding Name}"/>
                                    <GridViewColumn Header="ID" Width="220" DisplayMemberBinding="{Binding Id}"/>
                                    <GridViewColumn Header="Installed" Width="110" DisplayMemberBinding="{Binding Version}"/>
                                    <GridViewColumn Header="Latest" Width="110" DisplayMemberBinding="{Binding Available}"/>
                                </GridView>
                            </ListView.View>
                        </ListView>
                    </Border>

                    <!-- Action Bar -->
                    <Border Grid.Row="2" Style="{StaticResource CardStyle}" Margin="0,12,0,0">
                        <WrapPanel HorizontalAlignment="Right">
                            <Button Name="btnManageProviders" Content="Providers" Style="{StaticResource ActionBtn}" ToolTip="Manage package sources"/>
                            <Button Name="btnShowCatalog" Content="Software Catalog" Style="{StaticResource ActionBtn}" ToolTip="Browse our curated catalog of popular free applications. Install multiple apps at once with one click."/>
                            <Button Name="btnWingetScan" Content="Refresh All" Style="{StaticResource AccentBtn}"/>
                            <Button Name="btnWingetUpdateSel" Content="Update Checked" Style="{StaticResource PositiveBtn}" ToolTip="Update checked rows. If none are checked, selected rows are used."/>
                            <Button Name="btnWingetUpdateAll" Content="Update All" Style="{StaticResource PositiveBtn}"/>
                            <Button Name="btnWingetInstall" Content="Install" Style="{StaticResource PositiveBtn}" Visibility="Collapsed"/>
                            <Button Name="btnWingetUninstall" Content="Uninstall" Style="{StaticResource DestructiveBtn}"/>
                            <Button Name="btnWingetIgnore" Content="Ignore" Style="{StaticResource WarningBtn}"/>
                            <Button Name="btnWingetUnignore" Content="Manage Ignored" Style="{StaticResource ActionBtn}"/>
                        </WrapPanel>
                    </Border>
                </Grid>

                <!-- SOFTWARE CATALOG PANEL (Initially Hidden) -->
                <Grid Name="pnlCatalog" Visibility="Collapsed">
                    <Grid.RowDefinitions>
                        <RowDefinition Height="Auto"/>
                        <RowDefinition Height="Auto"/>
                        <RowDefinition Height="*"/>
                        <RowDefinition Height="Auto"/>
                    </Grid.RowDefinitions>
                    
                    <!-- Header -->
                    <Border Grid.Row="0" Style="{StaticResource CardStyle}" Margin="0,0,0,12">
                        <StackPanel>
                            <TextBlock Text="Software Catalog" Style="{StaticResource SectionHeader}" Margin="0"/>
                            <TextBlock Text="Curated selection of popular applications" Foreground="{DynamicResource TextSecondary}" FontSize="13"/>
                        </StackPanel>
                    </Border>

                    <!-- Category Filter + Your Library button -->
                    <Grid Grid.Row="1" Margin="6,0,6,12">
                        <Grid.ColumnDefinitions>
                            <ColumnDefinition Width="*"/>
                            <ColumnDefinition Width="Auto"/>
                        </Grid.ColumnDefinitions>
                        <StackPanel Name="pnlCategoryFilter" Grid.Column="0" Orientation="Horizontal">
                            <Button Name="btnCatAll" Content="All" Width="80" Style="{StaticResource AccentBtn}" ToolTip="Show all applications"/>
                            <Button Name="btnCatBrowsers" Content="Browsers" Width="90" Style="{StaticResource ActionBtn}" ToolTip="Filter: Web browsers"/>
                            <Button Name="btnCatDev" Content="Development" Width="Auto" MinWidth="120" Style="{StaticResource ActionBtn}" ToolTip="Filter: Developer tools, IDEs, runtimes"/>
                            <Button Name="btnCatUtils" Content="Utilities" Width="90" Style="{StaticResource ActionBtn}" ToolTip="Filter: System utilities and tools"/>
                            <Button Name="btnCatMedia" Content="Multimedia" Width="100" Style="{StaticResource ActionBtn}" ToolTip="Filter: Media players, editors, streaming"/>
                            <Button Name="btnCatGames" Content="Gaming" Width="80" Style="{StaticResource ActionBtn}" ToolTip="Filter: Game platforms and gaming tools"/>
                            <Button Name="btnCatSecurity" Content="Security" Width="90" Style="{StaticResource ActionBtn}" ToolTip="Filter: Antivirus, password managers, security tools"/>
                        </StackPanel>
                        <Button Name="btnShowLibrary" Content="Your Library" Grid.Column="1" Style="{StaticResource ActionBtn}" ToolTip="Show games you own from Steam, Epic (Legendary), and GOG (GOGDL)"/>
                    </Grid>

                    <!-- Catalog List -->
                    <Border Name="brdCatalogList" Grid.Row="2" Style="{StaticResource CardStyle}" Padding="0">
                        <ListView Name="lstCatalog" Background="Transparent" Foreground="{DynamicResource TextPrimary}" BorderThickness="0" 
                                  SelectionMode="Extended" AlternationCount="2" ItemContainerStyle="{StaticResource FwItem}"
                                  VirtualizingStackPanel.IsVirtualizing="True" VirtualizingStackPanel.VirtualizationMode="Recycling" ScrollViewer.CanContentScroll="True">
                            <ListView.View>
                                <GridView>
                                    <GridViewColumn Header="Category" Width="100" DisplayMemberBinding="{Binding Category}"/>
                                    <GridViewColumn Header="Name" Width="200" DisplayMemberBinding="{Binding Name}"/>
                                    <GridViewColumn Header="Description" Width="350" DisplayMemberBinding="{Binding Description}"/>
                                    <GridViewColumn Header="Source" Width="80" DisplayMemberBinding="{Binding Source}"/>
                                </GridView>
                            </ListView.View>
                        </ListView>
                    </Border>

                    <!-- Library List (initially hidden) -->
                    <Border Name="brdLibraryList" Grid.Row="2" Style="{StaticResource CardStyle}" Padding="0" Visibility="Collapsed">
                        <DockPanel>
                            <Border DockPanel.Dock="Top" Padding="8,6" Background="{DynamicResource BgPanel}" BorderBrush="{DynamicResource BorderBrush}" BorderThickness="0,0,0,1">
                                <Grid>
                                    <Grid.ColumnDefinitions>
                                        <ColumnDefinition Width="*"/>
                                        <ColumnDefinition Width="Auto"/>
                                    </Grid.ColumnDefinitions>
                                    <TextBox Name="txtLibrarySearch" Grid.Column="0" Height="28" VerticalContentAlignment="Center" Text="Search library..." Foreground="{DynamicResource TextSecondary}" BorderBrush="{DynamicResource BorderBrush}" Background="{DynamicResource BgDark}" ToolTip="Type to filter your library by name or ID"/>
                                    <Button Name="btnLibraryClearSearch" Grid.Column="1" Content="Clear" Width="60" Height="28" Margin="6,0,0,0" Style="{StaticResource ActionBtn}" ToolTip="Clear the search filter"/>
                                </Grid>
                            </Border>
                            <ListView Name="lstLibrary" Background="Transparent" Foreground="{DynamicResource TextPrimary}" BorderThickness="0"
                                      SelectionMode="Single" AlternationCount="2" ItemContainerStyle="{StaticResource FwItem}"
                                      VirtualizingStackPanel.IsVirtualizing="True" VirtualizingStackPanel.VirtualizationMode="Recycling" ScrollViewer.CanContentScroll="True">
                                <ListView.ContextMenu>
                                    <ContextMenu Name="ctxLibrary" StaysOpen="True">
                                        <MenuItem Name="miLibLaunch" Header="Launch / Play" ToolTip="Launch the game if it is installed"/>
                                        <MenuItem Name="miLibInstall" Header="Install" ToolTip="Download and install this game"/>
                                        <MenuItem Name="miLibUninstall" Header="Uninstall / Delete" ToolTip="Remove the game from your system"/>
                                        <Separator/>
                                        <MenuItem Name="miLibGoToDir" Header="Go to install directory" ToolTip="Open the folder where the game is installed"/>
                                        <MenuItem Name="miLibStorePage" Header="Open store page" ToolTip="Open the game's store page in your browser"/>
                                        <MenuItem Name="miLibCopyId" Header="Copy ID" ToolTip="Copy the game ID to clipboard"/>
                                    </ContextMenu>
                                </ListView.ContextMenu>
                                <ListView.View>
                                    <GridView>
                                        <GridViewColumn Header="Source" Width="90" DisplayMemberBinding="{Binding Source}"/>
                                        <GridViewColumn Header="Name" Width="280" DisplayMemberBinding="{Binding Name}"/>
                                        <GridViewColumn Header="ID" Width="180" DisplayMemberBinding="{Binding Id}"/>
                                        <GridViewColumn Header="Installed" Width="120" DisplayMemberBinding="{Binding Version}"/>
                                        <GridViewColumn Header="Latest" Width="120" DisplayMemberBinding="{Binding Available}"/>
                                    </GridView>
                                </ListView.View>
                            </ListView>
                        </DockPanel>
                    </Border>

                    <!-- Actions -->
                    <Border Grid.Row="3" Style="{StaticResource CardStyle}" Margin="0,12,0,0">
                        <Grid>
                            <Grid.ColumnDefinitions>
                                <ColumnDefinition Width="*"/>
                                <ColumnDefinition Width="Auto"/>
                            </Grid.ColumnDefinitions>
                            <!-- Library status (left side, shows when in library view) -->
                            <StackPanel Grid.Column="0" Orientation="Horizontal" HorizontalAlignment="Left">
                                <Button Name="btnBackToCatalog" Content="Back to Catalog" Style="{StaticResource ActionBtn}" ToolTip="Return to the software catalog" Visibility="Collapsed"/>
                                <Button Name="btnLibraryRefresh" Content="Refresh Library" Style="{StaticResource ActionBtn}" ToolTip="Re-scan Steam manifests and refresh Legendary/GOGDL caches" Visibility="Collapsed"/>
                                <TextBlock Name="lblLibraryStatus" Text="" VerticalAlignment="Center" Foreground="{DynamicResource TextSecondary}" FontStyle="Italic" Margin="12,0,0,0"/>
                            </StackPanel>
                            <!-- Catalog actions (always visible) -->
                            <StackPanel Name="pnlCatalogActions" Grid.Column="1" Orientation="Horizontal" HorizontalAlignment="Right">
                                <Button Name="btnBackToUpdates" Content="Back to Updates" Style="{StaticResource ActionBtn}" ToolTip="Return to the package updates view"/>
                                <Button Name="btnCatalogInstall" Content="Install Selected" Style="{StaticResource PositiveBtn}" ToolTip="Install all selected applications using winget. May take several minutes depending on app size."/>
                                <Button Name="btnCatalogSelectAll" Content="Select All" Style="{StaticResource ActionBtn}" ToolTip="Select all visible applications in the list"/>
                                <Button Name="btnCatalogClear" Content="Clear Selection" Style="{StaticResource ActionBtn}" ToolTip="Unselect all applications"/>
                            </StackPanel>
                        </Grid>
                    </Border>
                </Grid>

                <!-- TWEAKS PANEL -->
        <ScrollViewer Name="pnlTweaks" Visibility="Collapsed" VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Disabled">
            <StackPanel>
                <Border Style="{StaticResource CardStyle}">
                    <StackPanel>
                        <StackPanel Margin="0,0,0,12">
                            <TextBlock Text="Performance Tweaks" Style="{StaticResource SectionHeader}" Margin="0"/>
                        </StackPanel>
                        <TextBlock Text="POWER &amp; PERFORMANCE" Style="{StaticResource SubHeader}"/>
                        <WrapPanel>
                            <Button Name="btnPerfServicesManual" Content="Services to Manual" Style="{StaticResource ActionBtn}" ToolTip="Optimize 100+ Windows services by setting them to Manual startup. Improves boot time and reduces background RAM usage."/>
                            <Button Name="btnPerfServicesRevert" Content="Revert Services" Style="{StaticResource WarningBtn}" ToolTip="Restore all services to their default startup type (Automatic/Manual/Disabled). Use this if you experience issues after optimization."/>
                            <Button Name="btnToggleHibernate" Content="Disable Hibernation" Style="{StaticResource ActionBtn}" ToolTip="Toggle hibernation. When enabled (blue), hibernation is off and hiberfil.sys is deleted."/>
                            <Button Name="btnToggleSuperfetch" Content="Disable Superfetch" Style="{StaticResource ActionBtn}" ToolTip="Toggle SysMain (Superfetch) service. When enabled (blue), Superfetch is disabled."/>
                            <Button Name="btnToggleMemCompress" Content="Disable Mem Compression" Style="{StaticResource ActionBtn}" ToolTip="Toggle Windows memory compression. Compresses inactive RAM pages to free physical memory."/>
                            <Button Name="btnPerfUltimatePower" Content="Ultimate Performance" Style="{StaticResource PositiveBtn}" ToolTip="Enable the Ultimate Performance power plan. Removes all power throttling for maximum performance. Best for desktops and high-performance laptops."/>
                            <Button Name="btnToggleHags" Content="Enable HAGS" Style="{StaticResource ActionBtn}" ToolTip="Toggle Hardware-Accelerated GPU Scheduling for better VRAM management and lower latency."/>
                        </WrapPanel>
                    </StackPanel>
                </Border>

                <Border Style="{StaticResource CardStyle}">
                    <StackPanel>
                        <TextBlock Text="APPX BLOATWARE REMOVAL" Style="{StaticResource SubHeader}" ToolTip="Remove pre-installed Windows apps (UWP/Modern apps) that you don't use. Frees disk space and reduces background processes."/>
                        <TextBlock Text="Select apps to remove (use Ctrl+Click for multiple)" Foreground="{DynamicResource TextSecondary}" Margin="0,0,0,8"/>
                        <ListView Name="lstAppxPackages" Height="200" Background="{DynamicResource BgDark}" Foreground="{DynamicResource TextPrimary}" BorderBrush="{DynamicResource BorderBrush}" BorderThickness="1" SelectionMode="Multiple"
                                  VirtualizingStackPanel.IsVirtualizing="True" VirtualizingStackPanel.VirtualizationMode="Recycling" ScrollViewer.CanContentScroll="True">
                            <ListView.View>
                                <GridView>
                                    <GridViewColumn Header="App Name" Width="250" DisplayMemberBinding="{Binding Name}"/>
                                    <GridViewColumn Header="Package" Width="300" DisplayMemberBinding="{Binding Package}"/>
                                </GridView>
                            </ListView.View>
                        </ListView>
                        <WrapPanel Margin="0,12,0,0">
                            <Button Name="btnAppxLoad" Content="Load Apps" Style="{StaticResource ActionBtn}" ToolTip="Scan for installed UWP/Modern apps that can be removed. Populates the list above with removable bloatware."/>
                            <Button Name="btnAppxRemoveSel" Content="Remove Selected" Style="{StaticResource DestructiveBtn}" ToolTip="Remove the selected apps from your system. These apps can be reinstalled from the Microsoft Store if needed later."/>
                            <Button Name="btnAppxRemoveAll" Content="Remove All" Style="{StaticResource DestructiveBtn}" ToolTip="Remove ALL listed apps at once. This is faster but be careful - only click if you're sure you don't need any of these apps!"/>
                        </WrapPanel>
                    </StackPanel>
                </Border>

                <Border Style="{StaticResource CardStyle}">
                    <StackPanel>
                        <TextBlock Text="WINDOWS OPTIONAL FEATURES" Style="{StaticResource SubHeader}"/>
                        <WrapPanel>
                            <Button Name="btnFeatHyperV" Content="Hyper-V" Style="{StaticResource ActionBtn}" ToolTip="Microsoft's hardware virtualization platform. Create and run virtual machines. Requires Pro/Enterprise edition and CPU virtualization support."/>
                            <Button Name="btnFeatWSL" Content="WSL" Style="{StaticResource ActionBtn}" ToolTip="Windows Subsystem for Linux. Run Linux command-line tools and apps directly on Windows without a VM. Popular for developers."/>
                            <Button Name="btnFeatSandbox" Content="Sandbox" Style="{StaticResource ActionBtn}" ToolTip="Windows Sandbox - a lightweight, temporary desktop environment to safely run untrusted apps. Discards all changes when closed. Requires Pro/Enterprise."/>
                            <Button Name="btnFeatDotNet35" Content=".NET 3.5" Style="{StaticResource ActionBtn}" ToolTip=".NET Framework 3.5 (includes 2.0 and 3.0). Required for many older Windows applications and some games."/>
                            <Button Name="btnFeatNFS" Content="NFS Client" Style="{StaticResource ActionBtn}" ToolTip="Network File System client. Allows Windows to connect to Linux/UNIX NFS file shares and NAS devices."/>
                            <Button Name="btnFeatTelnet" Content="Telnet" Style="{StaticResource ActionBtn}" ToolTip="Telnet client for command-line remote connections. Not secure (unencrypted) - use SSH when possible."/>
                            <Button Name="btnFeatIIS" Content="IIS" Style="{StaticResource ActionBtn}" ToolTip="Internet Information Services - Microsoft's web server. Host websites locally, useful for web development."/>
                            <Button Name="btnFeatLegacy" Content="Legacy Media" Style="{StaticResource ActionBtn}" ToolTip="Windows Media Player and DirectPlay. Required for some older games and media playback."/>
                        </WrapPanel>
                    </StackPanel>
                </Border>

                <Border Style="{StaticResource CardStyle}">
                    <StackPanel>
                        <TextBlock Text="SERVICES MANAGEMENT" Style="{StaticResource SubHeader}"/>
                        <WrapPanel>
                            <Button Name="btnSvcOptimize" Content="Optimize Services" Style="{StaticResource PositiveBtn}" ToolTip="Set 100+ non-essential Windows services to Manual startup. Significantly improves boot time and reduces background resource usage."/>
                            <Button Name="btnSvcRestore" Content="Restore Defaults" Style="{StaticResource WarningBtn}" ToolTip="Restore ALL services to their original Windows default settings. Use this if you experience system issues after optimization."/>
                            <Button Name="btnSvcView" Content="View Services" Style="{StaticResource ActionBtn}" ToolTip="Open a grid view of all Windows services showing their current startup type and status. Useful for manual troubleshooting."/>
                        </WrapPanel>
                    </StackPanel>
                </Border>

                <Border Style="{StaticResource CardStyle}">
                    <StackPanel>
                        <TextBlock Text="SCHEDULED TASKS" Style="{StaticResource SubHeader}"/>
                        <TextBlock Text="Disable telemetry and tracking tasks" Foreground="{DynamicResource TextSecondary}" Margin="0,0,0,8"/>
                        <WrapPanel>
                            <Button Name="btnTasksDisableTelemetry" Content="Disable Telemetry Tasks" Style="{StaticResource DestructiveBtn}" ToolTip="Disable Windows telemetry scheduled tasks including: CEIP (Customer Experience), Error Reporting, Compatibility Appraiser. Reduces background activity and privacy concerns."/>
                            <Button Name="btnTasksRestore" Content="Restore Tasks" Style="{StaticResource WarningBtn}" ToolTip="Re-enable all telemetry and diagnostic scheduled tasks. Restores Windows default behavior for diagnostics and feedback."/>
                            <Button Name="btnTasksView" Content="View Tasks" Style="{StaticResource ActionBtn}" ToolTip="View telemetry-related scheduled tasks in a grid. Shows task name, path, and current enabled/disabled state."/>
                        </WrapPanel>
                    </StackPanel>
                </Border>

                <Border Style="{StaticResource CardStyle}">
                    <StackPanel>
                        <TextBlock Text="WINDOWS UPDATE PRESETS" Style="{StaticResource SubHeader}"/>
                        <WrapPanel>
                            <Button Name="btnWUDefault" Content="Default" Style="{StaticResource ActionBtn}" ToolTip="Standard Windows Update behavior. Feature and security updates install automatically. Recommended for most users."/>
                            <Button Name="btnWUSecurity" Content="Security Only" Style="{StaticResource UtilityBtn}" ToolTip="Defer feature updates for 1 year, install security updates only. Get new features later while staying secure. Good for stability."/>
                            <Button Name="btnWUDisable" Content="Disable All" Style="{StaticResource DestructiveBtn}" ToolTip="Completely disable Windows Update. NOT RECOMMENDED - your system will become vulnerable to security threats. Use with caution."/>
                        </WrapPanel>
                    </StackPanel>
                </Border>

                <Border Style="{StaticResource CardStyle}">
                    <StackPanel>
                        <TextBlock Text="TASKBAR &amp; SYSTEM CLOCK" Style="{StaticResource SubHeader}"/>
                        <WrapPanel>
                            <Button Name="btnToggleTaskbarAlign" Content="Align Taskbar Left" Style="{StaticResource ActionBtn}" ToolTip="Toggle taskbar alignment: Left or Center. Blue = aligned left. Gray = centered (default)."/>
                            <Button Name="btnToggleClockFormat" Content="24-Hour Clock" Style="{StaticResource ActionBtn}" ToolTip="Toggle clock format: 24-hour or 12-hour. Blue = 24-hour. Gray = 12-hour (default)."/>
                            <Button Name="btnToggleClockSecs" Content="Show Clock Seconds" Style="{StaticResource ActionBtn}" ToolTip="Toggle seconds display on the system tray clock."/>
                            <Button Name="btnToggleSearchDisplay" Content="Hide Search" Style="{StaticResource ActionBtn}" ToolTip="Cycle search display: Hidden, Icon only, or Search box. Blue = hidden, Gray = icon, default = box."/>
                            <Button Name="btnToggleWidgets" Content="Hide Widgets" Style="{StaticResource ActionBtn}" ToolTip="Toggle Widgets/Weather panel on the taskbar. Blue = widgets hidden. Gray = widgets visible (default)."/>
                            <Button Name="btnToggleTaskView" Content="Hide Task View" Style="{StaticResource ActionBtn}" ToolTip="Toggle Task View button on the taskbar. Blue = task view hidden. Gray = task view visible (default)."/>
                            <Button Name="btnToggleChat" Content="Hide Chat" Style="{StaticResource ActionBtn}" ToolTip="Toggle Chat (Teams) icon on the taskbar. Blue = chat hidden. Gray = chat visible (default)."/>
                            <Button Name="btnToggleCombine" Content="Never Combine" Style="{StaticResource ActionBtn}" ToolTip="Toggle taskbar button combining: Never Combine (show labels) or Always Combine (Windows 11 default)."/>
                            </WrapPanel>
                    </StackPanel>
                </Border>

                <Border Style="{StaticResource CardStyle}">
                    <StackPanel>
                        <TextBlock Text="EXPLORER &amp; FILES" Style="{StaticResource SubHeader}"/>
                        <WrapPanel>
                            <Button Name="btnToggleExtensions" Content="Show Extensions" Style="{StaticResource ActionBtn}" ToolTip="Show or hide known file extensions in File Explorer."/>
                            <Button Name="btnToggleHiddenFiles" Content="Show Hidden Files" Style="{StaticResource ActionBtn}" ToolTip="Show or hide hidden files and folders in File Explorer."/>
                            <Button Name="btnToggleFullPath" Content="Full Path On" Style="{StaticResource ActionBtn}" ToolTip="Show or hide the full folder path in File Explorer title bars."/>
                            <Button Name="btnToggleExplorerLaunch" Content="Open to This PC" Style="{StaticResource ActionBtn}" ToolTip="Make File Explorer open to This PC or Quick Access/Home."/>
                            <Button Name="btnToggleRecents" Content="Hide Recents" Style="{StaticResource ActionBtn}" ToolTip="Hide or restore recent and frequent items in Quick Access/Home."/>
                        </WrapPanel>
                    </StackPanel>
                </Border>

                <Border Style="{StaticResource CardStyle}">
                    <StackPanel>
                        <TextBlock Text="MOUSE &amp; FOLDER OPENING" Style="{StaticResource SubHeader}"/>
                        <WrapPanel>
                            <Button Name="btnMouseSpeedSlow" Content="Cursor Slow" Style="{StaticResource ActionBtn}" ToolTip="Set mouse pointer speed to 6."/>
                            <Button Name="btnMouseSpeedDefault" Content="Cursor Default" Style="{StaticResource ActionBtn}" ToolTip="Set mouse pointer speed to the Windows default of 10."/>
                            <Button Name="btnMouseSpeedFast" Content="Cursor Fast" Style="{StaticResource ActionBtn}" ToolTip="Set mouse pointer speed to 15."/>
                            <Button Name="btnToggleMouseAccel" Content="Acceleration On" Style="{StaticResource ActionBtn}" ToolTip="Enable or disable enhanced pointer precision / mouse acceleration."/>
                            <Button Name="btnToggleClickMode" Content="Single-Click Folders" Style="{StaticResource ActionBtn}" ToolTip="Open files and folders with a single click or restore double-click."/>
                            <Button Name="btnMouseSettings" Content="Mouse Settings" Style="{StaticResource UtilityBtn}" ToolTip="Open Windows mouse settings."/>
                        </WrapPanel>
                    </StackPanel>
                </Border>

                <Border Style="{StaticResource CardStyle}">
                    <StackPanel>
                        <TextBlock Text="CONTEXT MENU" Style="{StaticResource SubHeader}"/>
                        <WrapPanel>
                            <Button Name="btnToggleCtxMenu" Content="Classic Right-Click" Style="{StaticResource ActionBtn}" ToolTip="Use the classic Windows 10-style context menu or restore the default Windows 11 context menu."/>
                            <Button Name="btnToggleTakeOwnership" Content="Add Take Ownership" Style="{StaticResource ActionBtn}" ToolTip="Add or remove an elevated Take Ownership action on file, folder, and drive context menus."/>
                            <Button Name="btnTogglePsHere" Content="Add PowerShell Here" Style="{StaticResource ActionBtn}" ToolTip="Add or remove the Open PowerShell Here context menu action."/>
                        </WrapPanel>
                    </StackPanel>
                </Border>

                <Border Style="{StaticResource CardStyle}">
                    <StackPanel>
                        <TextBlock Text="PRIVACY" Style="{StaticResource SubHeader}"/>
                        <WrapPanel>
                            <Button Name="btnToggleAds" Content="Ad ID Off" Style="{StaticResource ActionBtn}" ToolTip="Disable or re-enable the per-user Windows advertising ID."/>
                            <Button Name="btnToggleSuggested" Content="Suggestions Off" Style="{StaticResource ActionBtn}" ToolTip="Disable or restore suggested apps, settings suggestions, and consumer content prompts."/>
                            <Button Name="btnToggleTailored" Content="Tailored Off" Style="{StaticResource ActionBtn}" ToolTip="Disable or restore tailored experiences based on diagnostic data."/>
                            <Button Name="btnToggleActivity" Content="Activity History Off" Style="{StaticResource ActionBtn}" ToolTip="Disable or restore Windows activity history publishing and upload policies."/>
                            <Button Name="btnToggleAppLaunch" Content="Launch Tracking Off" Style="{StaticResource ActionBtn}" ToolTip="Disable or restore Windows app launch tracking."/>
                        </WrapPanel>
                    </StackPanel>
                </Border>

                <Border Style="{StaticResource CardStyle}">
                    <StackPanel>
                        <TextBlock Text="SEARCH &amp; INDEXING" Style="{StaticResource SubHeader}"/>
                        <WrapPanel>
                            <Button Name="btnToggleWebSearch" Content="Web Search Off" Style="{StaticResource ActionBtn}" ToolTip="Disable or restore Bing/web results in Windows Start search."/>
                            <Button Name="btnToggleSearchIndex" Content="Reduce Indexing" Style="{StaticResource ActionBtn}" ToolTip="Reduce Windows Search indexing to Manual or restore it to Automatic."/>
                            <Button Name="btnSearchIndexRebuild" Content="Rebuild Index" Style="{StaticResource WarningBtn}" ToolTip="Delete the Windows search index database so Windows rebuilds it."/>
                            <Button Name="btnSearchIndexOptions" Content="Index Options" Style="{StaticResource UtilityBtn}" ToolTip="Open Windows Indexing Options."/>
                        </WrapPanel>
                    </StackPanel>
                </Border>

                <Border Style="{StaticResource CardStyle}">
                    <StackPanel>
                        <TextBlock Text="GAMING" Style="{StaticResource SubHeader}"/>
                        <WrapPanel>
                            <Button Name="btnToggleGameMode" Content="Game Mode On" Style="{StaticResource ActionBtn}" ToolTip="Enable or disable Windows Game Mode."/>
                            <Button Name="btnToggleGameBar" Content="Game Bar On" Style="{StaticResource ActionBtn}" ToolTip="Enable or disable Xbox Game Bar and Game DVR toggles."/>
                            <Button Name="btnToggleGameCapture" Content="Capture Off" Style="{StaticResource ActionBtn}" ToolTip="Disable or restore background gameplay capture."/>
                            <Button Name="btnToggleFso" Content="Disable FS Optimizations" Style="{StaticResource ActionBtn}" ToolTip="Disable fullscreen optimizations globally or restore default registry values."/>
                        </WrapPanel>
                    </StackPanel>
                </Border>

                <Border Style="{StaticResource CardStyle}">
                    <StackPanel>
                        <TextBlock Text="VISUAL EFFECTS" Style="{StaticResource SubHeader}"/>
                        <WrapPanel>
                            <Button Name="btnVisualBestAppearance" Content="Best Appearance" Style="{StaticResource ActionBtn}" ToolTip="Set Windows visual effects to best appearance."/>
                            <Button Name="btnVisualBestPerformance" Content="Best Performance" Style="{StaticResource ActionBtn}" ToolTip="Set Windows visual effects to best performance."/>
                            <Button Name="btnVisualSnappy" Content="Snappy Desktop" Style="{StaticResource PositiveBtn}" ToolTip="Disable taskbar animations, window minimize animations, Aero Peek, and transparency."/>
                        </WrapPanel>
                    </StackPanel>
                </Border>

                <Border Style="{StaticResource CardStyle}">
                    <StackPanel>
                        <TextBlock Text="NOTIFICATIONS &amp; LOCK SCREEN" Style="{StaticResource SubHeader}"/>
                        <WrapPanel>
                            <Button Name="btnNotifyFocusSettings" Content="Focus Settings" Style="{StaticResource UtilityBtn}" ToolTip="Open Focus Assist / Do Not Disturb settings."/>
                            <Button Name="btnToggleTips" Content="Tips Off" Style="{StaticResource ActionBtn}" ToolTip="Disable or restore Windows tips, welcome experience, and suggestion notifications."/>
                            <Button Name="btnToggleSetupPrompts" Content="Setup Prompts Off" Style="{StaticResource ActionBtn}" ToolTip="Toggle finish setting up this device prompts. When enabled (blue), setup prompts are disabled."/>
                            <Button Name="btnToggleLockFacts" Content="Lock Facts Off" Style="{StaticResource ActionBtn}" ToolTip="Disable or restore lock screen fun facts, tips, and overlays."/>
                            <Button Name="btnToggleLockSpotlight" Content="Spotlight Off" Style="{StaticResource ActionBtn}" ToolTip="Disable or restore Windows Spotlight on the lock screen."/>
                            <Button Name="btnToggleLockScreen" Content="Plain Lock Screen" Style="{StaticResource ActionBtn}" ToolTip="Apply a plain lock screen (no Spotlight or overlay) or restore default lock screen content."/>
                        </WrapPanel>
                    </StackPanel>
                </Border>

                <Border Style="{StaticResource CardStyle}">
                    <StackPanel>
                        <TextBlock Text="STARTUP BEHAVIOR" Style="{StaticResource SubHeader}"/>
                        <WrapPanel>
                            <Button Name="btnToggleFastStartup" Content="Fast Startup Off" Style="{StaticResource ActionBtn}" ToolTip="Disable or enable Windows Fast Startup."/>
                            <Button Name="btnToggleRestoreFolders" Content="Restore Folders On" Style="{StaticResource ActionBtn}" ToolTip="Restore or skip previous folder windows at logon."/>
                        </WrapPanel>
                    </StackPanel>
                </Border>

                <Border Style="{StaticResource CardStyle}">
                    <StackPanel>
                        <TextBlock Text="SECURITY SHORTCUTS" Style="{StaticResource SubHeader}"/>
                        <WrapPanel>
                            <Button Name="btnSecurityUacOpen" Content="UAC Settings" Style="{StaticResource UtilityBtn}" ToolTip="Open User Account Control settings."/>
                            <Button Name="btnSecurityUacStatus" Content="UAC Status" Style="{StaticResource ActionBtn}" ToolTip="Log the current UAC registry status."/>
                            <Button Name="btnSecuritySmartScreenOpen" Content="SmartScreen Settings" Style="{StaticResource UtilityBtn}" ToolTip="Open Windows App and Browser Control settings."/>
                            <Button Name="btnSecuritySmartScreenStatus" Content="SmartScreen Status" Style="{StaticResource ActionBtn}" ToolTip="Log the current SmartScreen status."/>
                            <Button Name="btnSecurityCfaOpen" Content="Controlled Folders" Style="{StaticResource UtilityBtn}" ToolTip="Open Controlled Folder Access / ransomware protection settings."/>
                        </WrapPanel>
                    </StackPanel>
                </Border>

                <Border Style="{StaticResource CardStyle}">
                    <StackPanel>
                        <TextBlock Text="POWER &amp; BATTERY" Style="{StaticResource SubHeader}"/>
                        <WrapPanel>
                            <Button Name="btnPowerBatterySaverOff" Content="Saver Off" Style="{StaticResource ActionBtn}" ToolTip="Set battery saver threshold to 0 percent."/>
                            <Button Name="btnPowerBatterySaver20" Content="Saver 20%" Style="{StaticResource ActionBtn}" ToolTip="Set battery saver threshold to 20 percent."/>
                            <Button Name="btnPowerBatterySaver50" Content="Saver 50%" Style="{StaticResource ActionBtn}" ToolTip="Set battery saver threshold to 50 percent."/>
                            <Button Name="btnToggleUsbSuspend" Content="USB Suspend On" Style="{StaticResource ActionBtn}" ToolTip="Enable or disable USB selective suspend for the active power plan."/>
                            <Button Name="btnTogglePcie" Content="PCIe Savings" Style="{StaticResource ActionBtn}" ToolTip="Set PCI Express link state power management to moderate savings or turn it off."/>
                        </WrapPanel>
                    </StackPanel>
                </Border>

                <Border Style="{StaticResource CardStyle}">
                    <StackPanel>
                        <TextBlock Text="DEVELOPER" Style="{StaticResource SubHeader}"/>
                        <WrapPanel>
                            <Button Name="btnToggleLongPaths" Content="Long Paths On" Style="{StaticResource ActionBtn}" ToolTip="Enable or disable Win32 long path support."/>
                            <Button Name="btnToggleDevMode" Content="Developer Mode On" Style="{StaticResource ActionBtn}" ToolTip="Enable or disable Windows Developer Mode policies."/>
                            <Button Name="btnDevSettings" Content="Developer Settings" Style="{StaticResource UtilityBtn}" ToolTip="Open Windows Developer Settings."/>
                        </WrapPanel>
                    </StackPanel>
                </Border>
            </StackPanel>
        </ScrollViewer>
                

                <!-- SYSTEM HEALTH PANEL -->
                <StackPanel Name="pnlHealth" Visibility="Collapsed">
                    <Border Style="{StaticResource CardStyle}">
