        $chatHidden = (([int](Get-WmtRegValue $ap "TaskbarMn" 1) -eq 0)); $btnToggleChat = Get-Ctrl "btnToggleChat"; Update-WmtTweakToggle $btnToggleChat $chatHidden "Show Chat" "Hide Chat"

