        $btnToggleDrvUpdates = Get-Ctrl "btnToggleDrvUpdates"
        Update-WmtTweakToggle $btnToggleDrvUpdates $drvWUDisabled "Enable Auto-Drivers" "Disable Auto-Drivers" "Toggle automatic driver updates via Windows Update."
    }
    catch {}
}


