        if ($q.Length -gt 1 -and $q -ne $script:QuickFindPlaceholder) {
            $pnlNavButtons.Visibility = "Collapsed"
            $lstSearchResults.Visibility = "Visible"
            $lstSearchResults.Items.Clear()
            foreach ($entry in $script:WmtSearchIndexEntries) {
