                }
                break
            }
            default { "" }
        }

        if ([string]::IsNullOrWhiteSpace($body)) { return "" }

        return @"
`$ErrorActionPreference = "Continue"
[Console]::OutputEncoding = [System.Text.UTF8Encoding]::new(`$false)
function Update-WmtProviderPathEnvironment {
    try {
        `$pathParts = New-Object System.Collections.Generic.List[string]
        foreach (`$pathValue in @([Environment]::GetEnvironmentVariable("Path", "Machine"), [Environment]::GetEnvironmentVariable("Path", "User"), `$env:Path)) {
            foreach (`$part in @(([string]`$pathValue) -split ";")) {
                `$trimmed = `$part.Trim()
                if (-not [string]::IsNullOrWhiteSpace(`$trimmed) -and -not `$pathParts.Contains(`$trimmed)) {
                    [void]`$pathParts.Add(`$trimmed)
                }
            }
        }
        `$env:Path = `$pathParts -join ";"
    }
    catch {}
}
Update-WmtProviderPathEnvironment

`$exitCode = 0
try {
    Write-Host "WMT provider $Action`: $ProviderKey"
    Write-Host ""
$body
    Write-Host ""
    Write-Host "Provider $Action completed."
}
catch {
    `$exitCode = 1
    Write-Host ""
    Write-Host "ERROR: `$(`$_.Exception.Message)" -ForegroundColor Red
}
Write-Host ""
Write-Host "Closing in 8 seconds..."
Start-Sleep -Seconds 8
exit `$exitCode
"@
    }

    $getWinCtrl = { param($name) $win.FindName($name) }.GetNewClosure()
    $updateProviderPathEnvironment = ${function:Update-WmtProviderPathEnvironment}.GetNewClosure()
    $getProviderActionScript = ${function:Get-WmtProviderActionScript}.GetNewClosure()
    $testProviderInstalled = {
        param($Provider)

        if (-not $Provider) { return $false }
        & $updateProviderPathEnvironment
        foreach ($cmd in @($Provider.Commands)) {
            if ([string]::IsNullOrWhiteSpace($cmd)) { continue }
            if (Get-Command $cmd -ErrorAction SilentlyContinue) { return $true }
        }
        if ($Provider.PSObject.Properties["RegistryPaths"]) {
            foreach ($registryPath in @($Provider.RegistryPaths)) {
                if ([string]::IsNullOrWhiteSpace($registryPath)) { continue }
                if (Test-Path -LiteralPath $registryPath) { return $true }
            }
        }
        if ($Provider.PSObject.Properties["LocalPaths"]) {
            foreach ($localPath in @($Provider.LocalPaths)) {
                if ([string]::IsNullOrWhiteSpace($localPath)) { continue }
                if (Test-Path -LiteralPath $localPath -PathType Leaf) { return $true }
            }
        }
        return $false
    }.GetNewClosure()
    $updateProviderStatuses = {
        & $updateProviderPathEnvironment
        foreach ($provider in $providerDefinitions) {
            $labelCtrl = & $getWinCtrl $provider.Label
            $buttonCtrl = & $getWinCtrl $provider.Button
            $installed = [bool](& $testProviderInstalled -Provider $provider)
            $providerInstallState[$provider.Key] = $installed

            if ($installed) {
                if ($labelCtrl) {
                    $labelCtrl.Text = "Installed"
                    Set-WmtThemedBrush -Object $labelCtrl -Property ([System.Windows.Controls.TextBlock]::ForegroundProperty) -ColorOrKey "Success"
                }
                if ($buttonCtrl) {
                    if ($provider.Key -eq "steam") {
                        $buttonCtrl.Content = "Open"
                        $buttonCtrl.ToolTip = "Open Steam and its Downloads updater"
                    }
                    elseif ($provider.Key -eq "windowsupdate") {
                        $buttonCtrl.Content = "Open"
                        $buttonCtrl.ToolTip = "Open Windows Update optional updates"
                    }
                    else {
                        $buttonCtrl.Content = "Repair"
                        $buttonCtrl.ToolTip = "Repair or refresh $($provider.DisplayName)"
                    }
                    $buttonCtrl.IsEnabled = $true
                }
            }
            else {
                if ($labelCtrl) {
                    $labelCtrl.Text = "Not Found"
                    Set-WmtThemedBrush -Object $labelCtrl -Property ([System.Windows.Controls.TextBlock]::ForegroundProperty) -ColorOrKey "Warning"
                }
                if ($buttonCtrl) {
                    $buttonCtrl.Content = "Install"
                    $buttonCtrl.ToolTip = "Install $($provider.DisplayName)"
                    $buttonCtrl.IsEnabled = $true
                }
            }
        }
    }.GetNewClosure()
    $startProviderAction = {
        param([string]$ProviderKey)

        $provider = @($providerDefinitions | Where-Object { $_.Key -eq $ProviderKey } | Select-Object -First 1)
        if (-not $provider) { return }

        $installed = if ($providerInstallState.ContainsKey($ProviderKey)) { [bool]$providerInstallState[$ProviderKey] } else { [bool](& $testProviderInstalled -Provider $provider) }
        $action = if (($ProviderKey -eq "steam" -or $ProviderKey -eq "windowsupdate") -and $installed) { "Open" } elseif ($installed) { "Repair" } else { "Install" }
        $message = if ($ProviderKey -eq "steam" -and $action -eq "Open") {
            "Open Steam Downloads?`r`n`r`nThis starts Steam so its own updater can process pending game updates."
        }
        elseif ($ProviderKey -eq "windowsupdate" -and $action -eq "Open") {
            "Open Windows Update optional updates?`r`n`r`nWMT scans Windows Update from the Updates page when this provider is enabled."
        }
        else {
            "$action $($provider.DisplayName)?`r`n`r`nThis opens a PowerShell window and may download provider files from the internet."
        }
        if ((Show-WmtMessageBox -Owner $win -Message $message -Title "$action Provider" -Button YesNo -Image Question) -ne [System.Windows.MessageBoxResult]::Yes) {
            return
        }

        $scriptText = & $getProviderActionScript -ProviderKey $ProviderKey -Action $action
        if ([string]::IsNullOrWhiteSpace($scriptText)) {
            Show-WmtMessageBox -Owner $win -Message "No $action action is configured for $($provider.DisplayName)." -Title "Provider Action" -Button OK -Image Warning | Out-Null
            return
        }

        $buttonCtrl = & $getWinCtrl $provider.Button
        $labelCtrl = & $getWinCtrl $provider.Label
        foreach ($providerDef in $providerDefinitions) {
            $otherButton = & $getWinCtrl $providerDef.Button
            if ($otherButton) { $otherButton.IsEnabled = $false }
        }
        if ($buttonCtrl) { $buttonCtrl.Content = "Running" }
        if ($labelCtrl) {
            $labelCtrl.Text = "$action running..."
            Set-WmtThemedBrush -Object $labelCtrl -Property ([System.Windows.Controls.TextBlock]::ForegroundProperty) -ColorOrKey "Accent"
        }

        $tempScriptPath = Join-Path $env:TEMP ("WMT_Provider_{0}_{1}.ps1" -f $ProviderKey, ([Guid]::NewGuid().ToString("N")))
        try {
            Set-Content -Path $tempScriptPath -Value $scriptText -Encoding UTF8 -Force
            Write-GuiLog "[$($provider.DisplayName)] $action started."
            $providerWindowStyle = if ($ProviderKey -eq "steam") { "Hidden" } else { "Normal" }
            $proc = Start-Process -FilePath "powershell.exe" -ArgumentList "-NoProfile -ExecutionPolicy Bypass -File `"$tempScriptPath`"" -WindowStyle $providerWindowStyle -PassThru
        }
        catch {
            Write-GuiLog "[$($provider.DisplayName)] $action failed to start: $($_.Exception.Message)"
            try { Remove-Item -LiteralPath $tempScriptPath -Force -ErrorAction SilentlyContinue } catch {}
            & $updateProviderStatuses
            foreach ($prov in $providerDefinitions) {
                & $updateProviderToggleState -ProviderKey ([string]$prov.Key)
            }
            return
        }

        $monitorKey = "$ProviderKey-$([Guid]::NewGuid().ToString("N"))"
        $timer = New-Object System.Windows.Threading.DispatcherTimer
        $timer.Interval = [TimeSpan]::FromSeconds(1)
        $monitorState = [PSCustomObject]@{
            Key            = $monitorKey
            Timer          = $timer
            Process        = $proc
            TempScriptPath = $tempScriptPath
            ProviderKey    = $ProviderKey
            ProviderName   = [string]$provider.DisplayName
            Action         = [string]$action
            Monitors       = $providerActionMonitors
            UpdateStatuses = $updateProviderStatuses
        }
        $timer.Tag = $monitorState
        $timer.Add_Tick({
                param($s, $eA)

                $state = $sender.Tag
                if (-not $state) {
                    try { $sender.Stop() } catch {}
                    return
                }

                try {
                    $hasExited = $false
                    try { $hasExited = [bool]$state.Process.HasExited } catch { $hasExited = $true }
                    if (-not $hasExited) { return }

                    try { $sender.Stop() } catch {}
                    try { $state.Monitors.Remove($state.Key) } catch {}
                    $exitCode = 1
                    try { $exitCode = [int]$state.Process.ExitCode } catch {}
                    try { Remove-Item -LiteralPath $state.TempScriptPath -Force -ErrorAction SilentlyContinue } catch {}
                    if ($exitCode -eq 0) {
                        try { Write-GuiLog "[$($state.ProviderName)] $($state.Action) completed." } catch {}
                    }
                    else {
                        try { Write-GuiLog "[$($state.ProviderName)] $($state.Action) exited with code $exitCode." } catch {}
                    }
                    try { & $state.UpdateStatuses } catch {
                        try { Write-GuiLog "[$($state.ProviderName)] Could not refresh provider status: $($_.Exception.Message)" } catch {}
                    }
                }
                catch {
                    try { $sender.Stop() } catch {}
                    try { $state.Monitors.Remove($state.Key) } catch {}
                    try { Write-GuiLog "[$($state.ProviderName)] Provider completion monitor failed: $($_.Exception.Message)" } catch {}
                    try { & $state.UpdateStatuses } catch {}
                }
            })
        $providerActionMonitors[$monitorKey] = $monitorState
        $timer.Start()
    }.GetNewClosure()

    $win.Add_Closed({
            foreach ($monitor in @($providerActionMonitors.Values)) {
                try { if ($monitor.Timer) { $monitor.Timer.Stop() } } catch {}
                try {
                    if ($monitor.Process -and $monitor.Process.HasExited -and $monitor.TempScriptPath) {
                        Remove-Item -LiteralPath $monitor.TempScriptPath -Force -ErrorAction SilentlyContinue
                    }
                }
                catch {}
            }
            try { $providerActionMonitors.Clear() } catch {}
        }.GetNewClosure())
    # Load settings
    $autoScanMinutes = Get-WmtUpdateAutoScanMinutes -Settings $settings
    if ($cmbAutoScanInterval) {
        foreach ($item in @($cmbAutoScanInterval.Items)) {
            try {
                if ([int]$item.Tag -eq [int]$autoScanMinutes) {
                    $cmbAutoScanInterval.SelectedItem = $item
                    break
                }
            }
            catch {}
        }
        if (-not $cmbAutoScanInterval.SelectedItem -and $cmbAutoScanInterval.Items.Count -gt 0) {
            $cmbAutoScanInterval.SelectedIndex = 0
        }
    }
    if ($chkUpdateNotifications) { $chkUpdateNotifications.IsChecked = (Get-WmtUpdateNotificationsEnabled -Settings $settings) }
    if ($chkRunInTrayOnClose) { $chkRunInTrayOnClose.IsChecked = (Get-WmtRunInTrayOnClose -Settings $settings) }
    if ($chkReduceRamInTray) { $chkReduceRamInTray.IsChecked = (Get-WmtReduceRamInTray -Settings $settings) }
    if ($chkUpdateSilentInstall) { $chkUpdateSilentInstall.IsChecked = (Get-WmtUpdateSilentInstallEnabled -Settings $settings) }
    if ($chkUpdateAutoInstall) { $chkUpdateAutoInstall.IsChecked = (Get-WmtUpdateAutoInstallEnabled -Settings $settings) }
    $chkIncludeUnknown.IsChecked = (Get-WmtWingetIncludeUnknown -Settings $settings)

    # Load Windows Update category toggle states.
    $wuToggles = Get-WmtWuCategoryToggles -Settings $settings
    if ($btnWuCatUpdates) { $btnWuCatUpdates.IsChecked = [bool]$wuToggles.Updates }
    if ($btnWuCatOptional) { $btnWuCatOptional.IsChecked = [bool]$wuToggles.Optional }
    if ($btnWuCatDriver) { $btnWuCatDriver.IsChecked = [bool]$wuToggles.Driver }
    if ($btnWuCatSecurity) { $btnWuCatSecurity.IsChecked = [bool]$wuToggles.Security }
    if ($btnWuCatInsider) { $btnWuCatInsider.IsChecked = [bool]$wuToggles.Insider }

    # Reflect each provider's main checkbox state from $enabled.
    foreach ($provider in $providerDefinitions) {
        $key = [string]$provider.Key
        $chkMain = & $getWinCtrl "chk$key"
        if (-not $chkMain) { continue }
        if ($provider.PSObject.Properties["LockedOn"] -and [bool]$provider.LockedOn) {
            $chkMain.IsChecked = $true
        }
        else {
            $chkMain.IsChecked = ($key -in $enabled)
        }
        # Also reflect per-provider toggle state.
        $toggles = $providerToggles[$key]
        $searchVal = if ($toggles -is [System.Collections.IDictionary]) { $toggles["Search"] } else { $toggles.Search }
        $scanVal = if ($toggles -is [System.Collections.IDictionary]) { $toggles["Scan"] } else { $toggles.Scan }
        $headVal = if ($toggles -is [System.Collections.IDictionary]) { $toggles["Headless"] } else { $toggles.Headless }
        $autoVal = if ($toggles -is [System.Collections.IDictionary]) { $toggles["AutoUpdate"] } else { $toggles.AutoUpdate }
        $chkSearch = & $getWinCtrl "chk${key}Search"
        $chkScan = & $getWinCtrl "chk${key}Scan"
        $chkHeadless = & $getWinCtrl "chk${key}Headless"
        $chkAuto = & $getWinCtrl "chk${key}AutoUpdate"
        if ($chkSearch) { $chkSearch.IsChecked = [bool]$searchVal }
        if ($chkScan) { $chkScan.IsChecked = [bool]$scanVal }
        if ($chkHeadless) { $chkHeadless.IsChecked = [bool]$headVal }
        if ($chkAuto) { $chkAuto.IsChecked = [bool]$autoVal }
        # Store controls for later event wiring.
        $providerControls[$key] = @{
            Main       = $chkMain
            Search     = $chkSearch
            Scan       = $chkScan
            Headless   = $chkHeadless
            AutoUpdate = $chkAuto
        }
    }

    # Helper: enable/disable the per-provider sub-toggles based on the
    # main checkbox and the Scan toggle. The Search toggle is additionally
    # gated by the capability matrix (it is created disabled in XAML when
    # the provider does not support search).
    $updateProviderToggleState = {
        param([string]$ProviderKey)

        $controls = $providerControls[$ProviderKey]
        if (-not $controls) { return }
        $caps = $providerCapabilities[$ProviderKey]
        $searchSupported = [bool]$caps.Search
        $mainChecked = [bool]$controls.Main.IsChecked
        $scanChecked = [bool]$controls.Scan.IsChecked

        # Get provider display name for tooltip messages.
        $provider = @($providerDefinitions | Where-Object { $_.Key -eq $ProviderKey } | Select-Object -First 1)
        $dispName = if ($provider) { [string]$provider.DisplayName } else { $ProviderKey }

        # Check if the provider is installed.
        $isInstalled = $true
        if ($providerInstallState.ContainsKey($ProviderKey)) {
            $isInstalled = [bool]$providerInstallState[$ProviderKey]
        }
        if ($ProviderKey -eq "winget") { $isInstalled = $true }

        # Base tooltips (shown when enabled).
        $mainTip = "Enable or disable $dispName for scanning and updates."
        $searchTip = "Allow searching this provider's catalog or owned library from the WMT search box."
        $scanTip = "Include this provider in update scans. Disabling also disables Headless and Auto-update."
        $headlessTip = "Run this provider's update/install commands without showing their console windows. Requires Scan to be enabled."
        $autoTip = "After a completed scan, automatically install this provider's available updates without confirmation. Requires Scan to be enabled."

        if (-not $isInstalled) {
            # Provider not installed: disable main + all toggles.
            $notInstalledMsg = "$dispName is not installed. Click the Install button to set it up."
            if ($controls.Main) {
                $controls.Main.IsEnabled = $false
                $controls.Main.ToolTip = $notInstalledMsg
            }
            if ($controls.Search) { $controls.Search.IsEnabled = $false; $controls.Search.ToolTip = $notInstalledMsg }
            if ($controls.Scan) { $controls.Scan.IsEnabled = $false; $controls.Scan.ToolTip = $notInstalledMsg }
            if ($controls.Headless) { $controls.Headless.IsEnabled = $false; $controls.Headless.ToolTip = $notInstalledMsg }
            if ($controls.AutoUpdate) { $controls.AutoUpdate.IsEnabled = $false; $controls.AutoUpdate.ToolTip = $notInstalledMsg }

            # Slash out the name.
            $nameCtrl = & $getWinCtrl "lbl${ProviderKey}Name"
            if ($nameCtrl) {
                $nameCtrl.TextDecorations = [System.Windows.TextDecorations]::Strikethrough
                $nameCtrl.Opacity = 0.35
                $nameCtrl.ToolTip = $notInstalledMsg
            }
            return
        }

        # Provider IS installed: apply normal gray-out rules.
        if ($controls.Main) {
            if ($ProviderKey -eq "winget") {
                $controls.Main.IsEnabled = $false
                $controls.Main.ToolTip = "Winget is the core package manager and is always enabled."
            }
            else {
                $controls.Main.IsEnabled = $true
                $controls.Main.ToolTip = $mainTip
            }
        }

        # Search toggle
        if ($controls.Search) {
            if (-not $searchSupported) {
                $controls.Search.IsEnabled = $false
                $controls.Search.IsChecked = $false
                $controls.Search.ToolTip = "$dispName does not support catalog or library search."
            }
            elseif (-not $mainChecked) {
                $controls.Search.IsEnabled = $false
                $controls.Search.ToolTip = "Enable $dispName (check the box on the left) to use search."
            }
            else {
                $controls.Search.IsEnabled = $true
                $controls.Search.ToolTip = $searchTip
            }
        }

        # Scan toggle
        if ($controls.Scan) {
            if (-not $mainChecked) {
                $controls.Scan.IsEnabled = $false
                $controls.Scan.ToolTip = "Enable $dispName (check the box on the left) to use scanning."
            }
            else {
                $controls.Scan.IsEnabled = $true
                $controls.Scan.ToolTip = $scanTip
            }
        }

        # Headless toggle
        if ($controls.Headless) {
            if (-not $mainChecked) {
                $controls.Headless.IsEnabled = $false
                $controls.Headless.ToolTip = "Enable $dispName and Scan to use headless mode."
            }
            elseif (-not $scanChecked) {
                $controls.Headless.IsEnabled = $false
                $controls.Headless.ToolTip = "Enable Scan for $dispName to use headless mode."
            }
            else {
                $controls.Headless.IsEnabled = $true
                $controls.Headless.ToolTip = $headlessTip
            }
        }

        # AutoUpdate toggle
        if ($controls.AutoUpdate) {
            if (-not $mainChecked) {
                $controls.AutoUpdate.IsEnabled = $false
                $controls.AutoUpdate.ToolTip = "Enable $dispName and Scan to use auto-update."
            }
            elseif (-not $scanChecked) {
                $controls.AutoUpdate.IsEnabled = $false
                $controls.AutoUpdate.ToolTip = "Enable Scan for $dispName to use auto-update."
            }
            else {
                $controls.AutoUpdate.IsEnabled = $true
                $controls.AutoUpdate.ToolTip = $autoTip
            }
        }

        # Visually "slash out" the provider name when the provider is disabled.
        $nameCtrl = & $getWinCtrl "lbl${ProviderKey}Name"
        if ($nameCtrl) {
            if ($mainChecked) {
                $nameCtrl.TextDecorations = $null
                $nameCtrl.Opacity = 1.0
                $nameCtrl.ToolTip = $dispName
            }
            else {
                $nameCtrl.TextDecorations = [System.Windows.TextDecorations]::Strikethrough
                $nameCtrl.Opacity = 0.45
                $nameCtrl.ToolTip = "$dispName is disabled. Check the box on the left to enable it."
            }
        }
    }.GetNewClosure()

    # Apply initial toggle state    }.GetNewClosure()

    # Apply initial toggle state for every provider.
    foreach ($provider in $providerDefinitions) {
        & $updateProviderToggleState -ProviderKey ([string]$provider.Key)
    }

    # Wire up checkbox change handlers so the sub-toggles react live.
    foreach ($provider in $providerDefinitions) {
        $key = [string]$provider.Key
        $controls = $providerControls[$key]
        if (-not $controls) { continue }
        if ($controls.Main) {
            $controls.Main.Add_Checked({ & $updateProviderToggleState -ProviderKey $key }.GetNewClosure())
            $controls.Main.Add_Unchecked({ & $updateProviderToggleState -ProviderKey $key }.GetNewClosure())
        }
        if ($controls.Scan) {
            $controls.Scan.Add_Checked({ & $updateProviderToggleState -ProviderKey $key }.GetNewClosure())
            $controls.Scan.Add_Unchecked({ & $updateProviderToggleState -ProviderKey $key }.GetNewClosure())
        }
    }

    & $updateProviderStatuses
    # Re-apply toggle state for all providers now that install state is known.
    # (Done here, not inside $updateProviderStatuses, because $updateProviderToggleState
    # is defined below and .GetNewClosure() on $updateProviderStatuses would capture $null.)
    foreach ($provider in $providerDefinitions) {
        & $updateProviderToggleState -ProviderKey ([string]$provider.Key)
    }
    foreach ($provider in $providerDefinitions) {
        $buttonCtrl = & $getWinCtrl $provider.Button
        if (-not $buttonCtrl) { continue }
        $providerKey = [string]$provider.Key
        $buttonCtrl.Add_Click({ & $startProviderAction -ProviderKey $providerKey }.GetNewClosure())
    }

    # Library cache files for Legendary/GOGDL are populated lazily by the
    # main Updates search box (background runspace), not here — calling
    # Get-WmtLegendaryLibrary/Get-WmtGogLibrary synchronously on the UI
    # thread would hang the window for up to 30+ seconds.

    # Save Event
    (Get-WinCtrl "btnSave").Add_Click({
            $newEnabled = @("winget")
            foreach ($provider in $providerDefinitions) {
                $key = [string]$provider.Key
                if ($provider.PSObject.Properties["LockedOn"] -and [bool]$provider.LockedOn) { continue }
                $chkMain = & $getWinCtrl "chk$key"
                if ($chkMain -and [bool]$chkMain.IsChecked) { $newEnabled += $key }
            }

            $current = Get-WmtSettings
            $current.EnabledProviders = $newEnabled
            if ($current -is [System.Collections.IDictionary]) {
                $current["WingetIncludeUnknown"] = [bool]$chkIncludeUnknown.IsChecked
            }
            else {
                $current.WingetIncludeUnknown = [bool]$chkIncludeUnknown.IsChecked
            }

            # Save Windows Update category toggles.
            $wuTogglesToSave = [ordered]@{
                Updates  = if ($btnWuCatUpdates) { [bool]$btnWuCatUpdates.IsChecked }  else { $true }
                Optional = if ($btnWuCatOptional) { [bool]$btnWuCatOptional.IsChecked } else { $true }
                Driver   = if ($btnWuCatDriver) { [bool]$btnWuCatDriver.IsChecked }   else { $true }
                Security = if ($btnWuCatSecurity) { [bool]$btnWuCatSecurity.IsChecked } else { $true }
                Insider  = if ($btnWuCatInsider) { [bool]$btnWuCatInsider.IsChecked }  else { $false }
            }
            if ($current -is [System.Collections.IDictionary]) {
                $current["WuCategoryToggles"] = $wuTogglesToSave
            }
            elseif ($current.PSObject.Properties["WuCategoryToggles"]) {
                $current.WuCategoryToggles = $wuTogglesToSave
            }
            else {
                $current | Add-Member -MemberType NoteProperty -Name "WuCategoryToggles" -Value $wuTogglesToSave -Force
            }

            # Build the per-provider toggles object to save.
            $togglesToSave = [ordered]@{}
            foreach ($provider in $providerDefinitions) {
                $key = [string]$provider.Key
                $chkSearch = & $getWinCtrl "chk${key}Search"
                $chkScan = & $getWinCtrl "chk${key}Scan"
                $chkHeadless = & $getWinCtrl "chk${key}Headless"
                $chkAuto = & $getWinCtrl "chk${key}AutoUpdate"
                $defaults = Get-WmtProviderToggleDefaults -ProviderKey $key
                $togglesToSave[$key] = [ordered]@{
                    Search     = if ($defaults.Search -and $chkSearch) { [bool]$chkSearch.IsChecked }   else { $false }
                    Scan       = if ($chkScan) { [bool]$chkScan.IsChecked }     else { $true }
                    Headless   = if ($chkHeadless) { [bool]$chkHeadless.IsChecked } else { $false }
                    AutoUpdate = if ($chkAuto) { [bool]$chkAuto.IsChecked }     else { $false }
                }
            }
            if ($current -is [System.Collections.IDictionary]) {
                $current["ProviderToggles"] = $togglesToSave
            }
            elseif ($current.PSObject.Properties["ProviderToggles"]) {
                $current.ProviderToggles = $togglesToSave
            }
            else {
                $current | Add-Member -MemberType NoteProperty -Name "ProviderToggles" -Value $togglesToSave -Force
            }

            $selectedAutoScanMinutes = 0
            if ($cmbAutoScanInterval -and $cmbAutoScanInterval.SelectedItem) {
                try { $selectedAutoScanMinutes = [int]$cmbAutoScanInterval.SelectedItem.Tag } catch { $selectedAutoScanMinutes = 0 }
            }
            if ($current -is [System.Collections.IDictionary]) {
                $current["UpdateAutoScanMinutes"] = $selectedAutoScanMinutes
                $current["UpdateNotificationsEnabled"] = [bool]$chkUpdateNotifications.IsChecked
                $current["UpdateSilentInstallEnabled"] = [bool]$chkUpdateSilentInstall.IsChecked
                $current["UpdateAutoInstallEnabled"] = [bool]$chkUpdateAutoInstall.IsChecked
                $current["RunInTrayOnClose"] = [bool]$chkRunInTrayOnClose.IsChecked
                $current["ReduceRamInTray"] = [bool]$chkReduceRamInTray.IsChecked
            }
            elseif ($current.PSObject.Properties["UpdateAutoScanMinutes"]) {
                $current.UpdateAutoScanMinutes = $selectedAutoScanMinutes
                if ($current.PSObject.Properties["UpdateNotificationsEnabled"]) {
                    $current.UpdateNotificationsEnabled = [bool]$chkUpdateNotifications.IsChecked
                }
                else {
                    $current | Add-Member -MemberType NoteProperty -Name "UpdateNotificationsEnabled" -Value ([bool]$chkUpdateNotifications.IsChecked) -Force
                }
                if ($current.PSObject.Properties["UpdateSilentInstallEnabled"]) {
                    $current.UpdateSilentInstallEnabled = [bool]$chkUpdateSilentInstall.IsChecked
                }
                else {
                    $current | Add-Member -MemberType NoteProperty -Name "UpdateSilentInstallEnabled" -Value ([bool]$chkUpdateSilentInstall.IsChecked) -Force
                }
                if ($current.PSObject.Properties["UpdateAutoInstallEnabled"]) {
                    $current.UpdateAutoInstallEnabled = [bool]$chkUpdateAutoInstall.IsChecked
                }
                else {
                    $current | Add-Member -MemberType NoteProperty -Name "UpdateAutoInstallEnabled" -Value ([bool]$chkUpdateAutoInstall.IsChecked) -Force
                }
                if ($current.PSObject.Properties["RunInTrayOnClose"]) {
                    $current.RunInTrayOnClose = [bool]$chkRunInTrayOnClose.IsChecked
                }
                else {
                    $current | Add-Member -MemberType NoteProperty -Name "RunInTrayOnClose" -Value ([bool]$chkRunInTrayOnClose.IsChecked) -Force
                }
                if ($current.PSObject.Properties["ReduceRamInTray"]) {
                    $current.ReduceRamInTray = [bool]$chkReduceRamInTray.IsChecked
                }
                else {
                    $current | Add-Member -MemberType NoteProperty -Name "ReduceRamInTray" -Value ([bool]$chkReduceRamInTray.IsChecked) -Force
                }
            }
            else {
                $current | Add-Member -MemberType NoteProperty -Name "UpdateAutoScanMinutes" -Value $selectedAutoScanMinutes -Force
                $current | Add-Member -MemberType NoteProperty -Name "UpdateNotificationsEnabled" -Value ([bool]$chkUpdateNotifications.IsChecked) -Force
                $current | Add-Member -MemberType NoteProperty -Name "UpdateSilentInstallEnabled" -Value ([bool]$chkUpdateSilentInstall.IsChecked) -Force
                $current | Add-Member -MemberType NoteProperty -Name "UpdateAutoInstallEnabled" -Value ([bool]$chkUpdateAutoInstall.IsChecked) -Force
                $current | Add-Member -MemberType NoteProperty -Name "RunInTrayOnClose" -Value ([bool]$chkRunInTrayOnClose.IsChecked) -Force
                $current | Add-Member -MemberType NoteProperty -Name "ReduceRamInTray" -Value ([bool]$chkReduceRamInTray.IsChecked) -Force
            }

            Save-WmtSettings -Settings $current
            Start-WmtUpdateAutoScanTimer -ResetNextRun
            if (-not (Get-WmtRunInTrayOnClose -Settings $current)) { Remove-WmtTrayIcon }
            $win.Close()
        })

    $win.ShowDialog() | Out-Null

}


function Test-WmtUpdateScanEngineBusy {
    try {
        if ($script:ActiveScans -and $script:ActiveScans.Count -gt 0) { return $true }
        if ($script:ScanTimer -and $script:ScanTimer.IsEnabled) { return $true }
        if ($script:GlobalScanTimer -and $script:GlobalScanTimer.IsEnabled) { return $true }
        if ($script:WingetScanSourcePreflightInProgress) { return $true }
        if ($script:WingetActiveAction) { return $true }
        if ($btnWingetScan -and -not $btnWingetScan.IsEnabled) { return $true }
    }
    catch {}
    return $false
}

function Test-WmtPackageSearchActive {
    try {
        # A live package search always owns the shared Updates/Search result list.
        if ($script:AsyncSearch) { return $true }
        if ($script:AsyncPowerShell) { return $true }
        if ($script:SearchTimer -and $script:SearchTimer.IsEnabled) { return $true }
        if ($btnWingetFind -and -not $btnWingetFind.IsEnabled) { return $true }
        if ($txtWingetSearch -and -not $txtWingetSearch.IsEnabled) { return $true }

        # Completed search results should only block auto scans while the user can actually see that view.
        $windowVisible = $true
        if ($window) {
            $windowVisible = ($window.Visibility -eq [System.Windows.Visibility]::Visible -and $window.WindowState -ne [System.Windows.WindowState]::Minimized)
        }
        if (-not $windowVisible) { return $false }

        $updatesVisible = $true
        if ($pnlUpdates) { $updatesVisible = ($pnlUpdates.Visibility -eq [System.Windows.Visibility]::Visible) }
        if (-not $updatesVisible) { return $false }

        if ($script:WmtPackageSearchActive) { return $true }
        if ($lblWingetTitle -and ([string]$lblWingetTitle.Text).StartsWith("Search Results:", [System.StringComparison]::OrdinalIgnoreCase)) { return $true }
        if ($btnWingetInstall -and $btnWingetInstall.Visibility -eq [System.Windows.Visibility]::Visible) { return $true }
    }
    catch {}
    return $false
}

function Test-WmtUpdateAutoScanBusy {
    try {
        if (Test-WmtUpdateScanEngineBusy) { return $true }
        if (Test-WmtPackageSearchActive) { return $true }
    }
    catch {}
    return $false
}

function Get-WmtUpdateListItemKey {
    param([object]$Item)
    if (-not $Item) { return "" }

    $source = ([string]$Item.Source).Trim().ToLowerInvariant()
    $id = ([string]$Item.Id).Trim().ToLowerInvariant()
    $name = ([string]$Item.Name).Trim().ToLowerInvariant()
    $available = ([string]$Item.Available).Trim().ToLowerInvariant()

    if ([string]::IsNullOrWhiteSpace($id)) { $id = $name }
    if ([string]::IsNullOrWhiteSpace($source) -or [string]::IsNullOrWhiteSpace($id)) { return "" }
    return "$source|$id|$available"
}

function Remove-WmtSteamUpdateListItem {
    param(
        [string]$PackageName,
        [string]$AppId = ""
    )

    if (-not $lstWinget) { return 0 }

    $targetName = ([string]$PackageName).Trim()
    $targetId = ([string]$AppId).Trim()
    $removed = 0
    $itemsToRemove = New-Object System.Collections.Generic.List[object]

    foreach ($item in @($lstWinget.Items)) {
        if (-not $item -or -not $item.PSObject.Properties["Source"]) { continue }
        if (([string]$item.Source).Trim().ToLowerInvariant() -ne "steam") { continue }

        $itemId = ([string]$item.Id).Trim()
        $itemName = ([string]$item.Name).Trim()
        $idMatches = (-not [string]::IsNullOrWhiteSpace($targetId) -and $itemId -eq $targetId)
        $nameMatches = (-not [string]::IsNullOrWhiteSpace($targetName) -and $itemName -eq $targetName)
        if ($idMatches -or $nameMatches) { [void]$itemsToRemove.Add($item) }
    }

    foreach ($item in @($itemsToRemove)) {
        try {
            $lstWinget.Items.Remove($item)
            $removed++
        }
        catch {}
    }

    if ($removed -gt 0) {
        try {
            $lstWinget.Items.Refresh()
            $lstWinget.UpdateLayout()
            Request-WmtUpdateListSmartColumnResize -ListView $lstWinget
        }
        catch {}
        $displayName = if ([string]::IsNullOrWhiteSpace($targetName)) { "Steam item" } else { $targetName }
        Write-GuiLog "[Steam] Removed $displayName from the visible update list after Steam update delegation."
    }

    return $removed
}

function Remove-WmtDelegatedProviderUpdateListItem {
    param(
        [string]$ProviderKey,
        [string]$ProviderLabel,
        [string]$PackageName,
        [string]$PackageId = "",
        [switch]$RemoveAllProviderItems
    )

    if (-not $lstWinget) { return 0 }

    $provider = ([string]$ProviderKey).Trim().ToLowerInvariant()
    if ([string]::IsNullOrWhiteSpace($provider)) { return 0 }
    $label = ([string]$ProviderLabel).Trim()
    if ([string]::IsNullOrWhiteSpace($label)) { $label = $ProviderKey }

    $targetName = ([string]$PackageName).Trim()
    $targetId = ([string]$PackageId).Trim()
    $removed = 0
    $itemsToRemove = New-Object System.Collections.Generic.List[object]

    foreach ($item in @($lstWinget.Items)) {
        if (-not $item -or -not $item.PSObject.Properties["Source"]) { continue }
        if (([string]$item.Source).Trim().ToLowerInvariant() -ne $provider) { continue }

        if ($RemoveAllProviderItems) {
            [void]$itemsToRemove.Add($item)
            continue
        }

        $itemId = ([string]$item.Id).Trim()
        $itemName = ([string]$item.Name).Trim()
        $idMatches = (-not [string]::IsNullOrWhiteSpace($targetId) -and $itemId -eq $targetId)
        $nameMatches = (-not [string]::IsNullOrWhiteSpace($targetName) -and $itemName -eq $targetName)
        if ($idMatches -or $nameMatches) { [void]$itemsToRemove.Add($item) }
    }

    foreach ($item in @($itemsToRemove)) {
        try {
            $lstWinget.Items.Remove($item)
            $removed++
        }
        catch {}
    }

    if ($removed -gt 0) {
        try {
            $lstWinget.Items.Refresh()
            $lstWinget.UpdateLayout()
            Request-WmtUpdateListSmartColumnResize -ListView $lstWinget
        }
        catch {}
        $displayName = if ([string]::IsNullOrWhiteSpace($targetName) -or $RemoveAllProviderItems) { "$label item(s)" } else { $targetName }
        Write-GuiLog "[$label] Removed $displayName from the visible update list after delegated update handling."
    }

    return $removed
}

function Get-WmtVisibleUpdateResultItems {
    if (-not $lstWinget) { return @() }

    $seen = @{}
    $items = New-Object System.Collections.Generic.List[object]
    foreach ($item in @($lstWinget.Items)) {
        if (-not $item -or -not $item.PSObject.Properties["Name"]) { continue }

        $source = ([string]$item.Source).Trim()
        $name = ([string]$item.Name).Trim()
        $id = ([string]$item.Id).Trim()
        $available = ([string]$item.Available).Trim()

        if ([string]::IsNullOrWhiteSpace($source)) { continue }
        if ([string]::IsNullOrWhiteSpace($name) -or $name -in @("No results found", "No updates available")) { continue }
        if ([string]::IsNullOrWhiteSpace($available) -or $available -eq "-") { continue }
        if ([string]::IsNullOrWhiteSpace($id) -and ([string]::IsNullOrWhiteSpace($name))) { continue }

        $key = Get-WmtUpdateListItemKey -Item $item
        if ([string]::IsNullOrWhiteSpace($key)) { continue }
        if ($seen.ContainsKey($key)) { continue }

        $seen[$key] = $true
        [void]$items.Add($item)
    }
    return $items.ToArray()
}

function Invoke-WmtUpdateAutoScan {
    param([switch]$Force)

    $minutes = Get-WmtUpdateAutoScanMinutes
    if ($minutes -le 0 -and -not $Force) { return }

    if (Test-WmtUpdateAutoScanBusy) {
        if (Test-WmtPackageSearchActive) {
            Write-GuiLog "Auto scan skipped because package search/results are active."
        }
        else {
            Write-GuiLog "Auto scan skipped because an update scan or package action is already running."
        }
        return
    }

    if (-not $btnWingetScan) { return }
    $script:WmtUpdateAutoScanLastRun = Get-Date
    $script:WmtUpdateAutoScanPending = $true
    Write-GuiLog "Auto scan starting in background..."
    try {
        $btnWingetScan.RaiseEvent((New-Object System.Windows.RoutedEventArgs([System.Windows.Controls.Button]::ClickEvent)))
    }
    catch {
        $script:WmtUpdateAutoScanPending = $false
        $script:WmtUpdateAutoScanActive = $false
        Write-GuiLog "Auto scan failed to start: $($_.Exception.Message)"
    }
}

function Start-WmtUpdateAutoScanTimer {
    param([switch]$ResetNextRun)

    $minutes = Get-WmtUpdateAutoScanMinutes

    # DispatcherTimer is not IDisposable. Stop it and detach the Tick handler instead.
    Stop-WmtUpdateAutoScanTimer

    if ($minutes -le 0) {
        Write-GuiLog "Update auto scan is disabled."
        return
    }

    $script:WmtUpdateAutoScanIntervalMinutes = $minutes
    if ($ResetNextRun -or -not $script:WmtUpdateAutoScanLastRun) {
        $script:WmtUpdateAutoScanLastRun = Get-Date
    }

    $script:WmtUpdateAutoScanTimer = New-Object System.Windows.Threading.DispatcherTimer
    $script:WmtUpdateAutoScanTimer.Interval = [TimeSpan]::FromMinutes($minutes)
    $script:WmtUpdateAutoScanTimerTickHandler = [System.EventHandler] {
        param($s, $eventArg)
        Invoke-WmtUpdateAutoScan
    }
    $script:WmtUpdateAutoScanTimer.Add_Tick($script:WmtUpdateAutoScanTimerTickHandler)
    $script:WmtUpdateAutoScanTimer.Start()
    Write-GuiLog "Update auto scan enabled: every $minutes minute(s) while WMT is open."
}

function Stop-WmtUpdateAutoScanTimer {
    if ($script:WmtUpdateAutoScanTimer) {
        try { $script:WmtUpdateAutoScanTimer.Stop() } catch {}
        try {
            if ($script:WmtUpdateAutoScanTimerTickHandler) {
                $script:WmtUpdateAutoScanTimer.Remove_Tick($script:WmtUpdateAutoScanTimerTickHandler)
            }
        }
        catch {}
        $script:WmtUpdateAutoScanTimer = $null
    }
    $script:WmtUpdateAutoScanTimerTickHandler = $null
}


function Start-WingetScanSourcePreflight {
    param([string[]]$Sources)

    if (-not $Sources -or $Sources.Count -eq 0) {
        $script:WingetSourcePreflightReadyForScan = $true
        if ($btnWingetScan) {
            $btnWingetScan.RaiseEvent((New-Object System.Windows.RoutedEventArgs([System.Windows.Controls.Button]::ClickEvent)))
        }
        return
    }

    if ($script:WingetScanSourcePreflightInProgress) {
        Write-GuiLog "Winget source preflight is already running."
        return
    }

    $script:WingetScanSourcePreflightInProgress = $true
    $script:WingetSourcePreflightReadyForScan = $false
    $script:WingetSourcePreflightSources = @($Sources | Select-Object -Unique)

    Write-GuiLog "Preparing winget sources before package scan: $($script:WingetSourcePreflightSources -join ', ')"
    if ($lblWingetStatus) {
        $lblWingetStatus.Text = "Preparing winget sources before scan..."
        $lblWingetStatus.Visibility = "Visible"
    }

    if ($script:WingetSourcePreflightTimer) {
        try { $script:WingetSourcePreflightTimer.Stop() } catch {}
        $script:WingetSourcePreflightTimer = $null
    }
    if ($script:WingetSourcePreflightRunspace) {
        try { $script:WingetSourcePreflightRunspace.Stop() } catch {}
        try { $script:WingetSourcePreflightRunspace.Dispose() } catch {}
        $script:WingetSourcePreflightRunspace = $null
    }

    $script:WingetSourcePreflightRunspace = [PowerShell]::Create().AddScript({
            param([string[]]$Sources)
            [Console]::OutputEncoding = [System.Text.UTF8Encoding]::new($false)
            $log = New-Object System.Collections.Generic.List[string]

            function Add-Log { param([string]$Text) if (-not [string]::IsNullOrWhiteSpace($Text)) { [void]$log.Add($Text) } }
            function Invoke-WingetProcess {
                param([string]$Arguments, [int]$TimeoutMs = 30000)
                $psi = [System.Diagnostics.ProcessStartInfo]::new()
                $psi.FileName = "winget"
                $psi.Arguments = $Arguments
                $psi.UseShellExecute = $false
                $psi.CreateNoWindow = $true
                $psi.RedirectStandardOutput = $true
                $psi.RedirectStandardError = $true
                try { $psi.StandardOutputEncoding = [System.Text.UTF8Encoding]::new($false) } catch {}
                try { $psi.StandardErrorEncoding = [System.Text.UTF8Encoding]::new($false) } catch {}
                $proc = [System.Diagnostics.Process]::Start($psi)
                try { $proc.BeginOutputReadLine() } catch {}
                try { $proc.BeginErrorReadLine() } catch {}
                if (-not $proc.WaitForExit($TimeoutMs)) {
                    try { $proc.Kill() } catch {}
                    return [PSCustomObject]@{ ExitCode = -1; TimedOut = $true }
                }
                return [PSCustomObject]@{ ExitCode = [int]$proc.ExitCode; TimedOut = $false }
            }

            foreach ($source in @($Sources | Select-Object -Unique)) {
                try {
                    $refreshTimeoutMs = if ($source -eq "msstore") { 15000 } else { 30000 }
                    Add-Log "LOG:Refreshing $source source before scan (quick preflight, max $([int]($refreshTimeoutMs / 1000))s)..."
                    $refresh = Invoke-WingetProcess -Arguments "source update --name $source --disable-interactivity" -TimeoutMs $refreshTimeoutMs

                    if ($refresh.TimedOut) {
                        Add-Log "LOG:$source source refresh timed out after $([int]($refreshTimeoutMs / 1000))s; continuing to scan anyway."
                    }
                    elseif ($refresh.ExitCode -eq 0) {
                        Add-Log "LOG:$source source refresh completed before scan."
                    }
                    else {
                        Add-Log "LOG:$source source refresh exited with code $($refresh.ExitCode); continuing to scan anyway."
                    }
                }
                catch {
                    Add-Log "LOG:$source source preflight failed: $($_.Exception.Message); continuing to scan anyway."
                }
            }

            Add-Log "LOG:Winget source preflight finished; starting package scan."
            return $log.ToArray()
        }).AddArgument([string[]]$script:WingetSourcePreflightSources)

    $script:WingetSourcePreflightAsyncResult = $script:WingetSourcePreflightRunspace.BeginInvoke()
    $script:WingetSourcePreflightTimer = New-Object System.Windows.Threading.DispatcherTimer
    $script:WingetSourcePreflightTimer.Interval = [TimeSpan]::FromMilliseconds(250)
    $script:WingetSourcePreflightTimer.Add_Tick({
            if (-not $script:WingetSourcePreflightAsyncResult) { return }
            if (-not $script:WingetSourcePreflightAsyncResult.IsCompleted) { return }

            $script:WingetSourcePreflightTimer.Stop()
            try {
                $lines = $script:WingetSourcePreflightRunspace.EndInvoke($script:WingetSourcePreflightAsyncResult)
                foreach ($line in $lines) {
                    if ($line -is [string] -and $line.StartsWith("LOG:")) { Write-GuiLog ($line.Substring(4)) }
                    elseif ($line) { Write-GuiLog ([string]$line) }
                }
            }
            catch {
                Write-GuiLog "Winget source preflight background error: $($_.Exception.Message)"
            }
            finally {
                try { $script:WingetSourcePreflightRunspace.Dispose() } catch {}
                $script:WingetSourcePreflightRunspace = $null
                $script:WingetSourcePreflightAsyncResult = $null
                $script:WingetScanSourcePreflightInProgress = $false
                $script:WingetSourcePreflightReadyForScan = $true
            }

            if ($btnWingetScan) {
                $btnWingetScan.IsEnabled = $true
                $btnWingetScan.RaiseEvent((New-Object System.Windows.RoutedEventArgs([System.Windows.Controls.Button]::ClickEvent)))
            }
        })
    $script:WingetSourcePreflightTimer.Start()
}

# ---------------------------------------------------------
# PARALLEL SCAN ENGINE
# ---------------------------------------------------------

# 1. SETUP MULTI-THREAD TIMER
$script:ScanTimer = New-Object System.Windows.Threading.DispatcherTimer
$script:ScanTimer.Interval = [TimeSpan]::FromMilliseconds(200)
# We now use a LIST of active scanners instead of just one
$script:ActiveScans = [System.Collections.ArrayList]::new()
$script:WmtAutoInstallSuppressNextScan = $false
$script:WmtAutoInstallActive = $false
$script:WmtCompletedWindowsUpdateIds = @{}
$script:WmtWindowsUpdateRebootPendingCount = 0

$script:ScanTimer.Add_Tick({
        if ($script:ActiveScans.Count -gt 0) {
        
            # Iterate backwards so we can remove completed tasks safely
            for ($i = $script:ActiveScans.Count - 1; $i -ge 0; $i--) {
                $task = $script:ActiveScans[$i]
            
                if ($task.AsyncResult.IsCompleted) {
                    try {
                        $results = $task.PowerShell.EndInvoke($task.AsyncResult)
                        $task.PowerShell.Dispose()
                    
                        # Process Results
                        foreach ($item in $results) {
                            if ($null -eq $item) { continue }

                            if ($item -is [string] -and $item -match "^STATE:WINDOWS_UPDATE_REBOOT_REQUIRED:(\d+)$") {
                                $script:WmtWindowsUpdateRebootPendingCount = [Math]::Max(
                                    [int]$script:WmtWindowsUpdateRebootPendingCount,
                                    [int]$matches[1]
                                )
                            }
                            elseif ($item -is [string] -and $item.StartsWith("LOG:")) {
                                Write-GuiLog ($item.Substring(4))
                            }
                            elseif ($item.PSObject.Properties["Name"]) {
                                # --- STRICT GARBAGE FILTER ---
                                # Rejects headers, separators, and empty dashed lines
                                if ($item.Name -match "^-+$" -or $item.Id -match "^-+$") { continue }
                                if ($item.Name -eq "Name" -and $item.Id -eq "Id") { continue }
                                if ($item.Name -eq "Source" -and $item.Id -eq "Name") { continue }
                                if ($item.Version -eq "Version" -or $item.Available -eq "Available") { continue }
                            
                                # Add to UI
                                [void](Set-WmtUpdateListItemCheckState -Item $item -DefaultChecked:$false)
                                [void]$lstWinget.Items.Add($item)
                            }
                        }
                    }
                    catch {
                        Write-GuiLog "Scan Error: $($_.Exception.Message)"
                    }
                
                    # Remove finished task
                    $script:ActiveScans.RemoveAt($i)
                }
            }
        }
        else {
            # All tasks finished
            if ($script:ScanTimer.IsEnabled) {
                $script:ScanTimer.Stop()

                # Stop the 120s global timeout timer too — the scan finished
                # before it fired, so leaving it running would falsely report
                # the engine as busy (Test-WmtUpdateScanEngineBusy checks
                # $script:GlobalScanTimer.IsEnabled).
                if ($script:GlobalScanTimer) {
                    try { $script:GlobalScanTimer.Stop() } catch {}
                }
            
                $rebootPendingCount = [Math]::Max(0, [int]$script:WmtWindowsUpdateRebootPendingCount)
                if ($rebootPendingCount -gt 0) {
                    $lblWingetStatus.Text = "Restart required - $rebootPendingCount Windows update(s) waiting"
                    $lblWingetStatus.Visibility = "Visible"
                }
                else {
                    $lblWingetStatus.Visibility = "Hidden"
                }
                if ($pbWingetProgress) { $pbWingetProgress.Visibility = "Collapsed"; $pbWingetProgress.Value = 0 }
                if ($lblWingetProgress) { $lblWingetProgress.Visibility = "Collapsed"; $lblWingetProgress.Text = "" }
                $btnWingetScan.IsEnabled = $true
                if ($btnWingetUpdateAll) { $btnWingetUpdateAll.IsEnabled = $true }
                $btnWingetUpdateSel.IsEnabled = $true
                $lstWinget.Items.Refresh()
                $lstWinget.UpdateLayout()
                Request-WmtUpdateListSmartColumnResize -ListView $lstWinget
            
                if ($lstWinget.Items.Count -eq 0) {
                    if ($rebootPendingCount -gt 0) {
                        Write-GuiLog "No actionable updates found. Restart Windows to finish $rebootPendingCount installed update(s)."
                    }
                    else {
                        Write-GuiLog "System is up to date."
                    }
                }
                else {
                    Write-GuiLog "Scan Complete. Found $($lstWinget.Items.Count) updates."
                }

                if (Get-WmtUpdateAutoInstallEnabled) {
                    if ($script:WmtAutoInstallSuppressNextScan) {
                        $script:WmtAutoInstallSuppressNextScan = $false
                        Write-GuiLog "Auto install skipped for this verification scan."
                    }
                    else {
                        Invoke-WmtAutoInstallAvailableUpdates
                    }
                }
            }
        }
    })

# 2. BUTTON CLICK (Launch Parallel Threads)
$btnWingetScan.Add_Click({
        # UI Prep
        # Clear any stale "package search active" flag so auto-scans are no
        # longer blocked once the user explicitly starts a new scan.
        $script:WmtPackageSearchActive = $false
        $lblWingetTitle.Text = "Package Updates"
        $lblWingetStatus.Text = "Scanning all providers..."
        $lblWingetStatus.Visibility = "Visible"
        if ($pbWingetProgress) { $pbWingetProgress.Visibility = "Collapsed"; $pbWingetProgress.Value = 0 }
        if ($lblWingetProgress) { $lblWingetProgress.Visibility = "Collapsed"; $lblWingetProgress.Text = "" }
        if ($lblWingetLastResult) { $lblWingetLastResult.Visibility = "Collapsed"; $lblWingetLastResult.Text = "" }
        $script:WmtWindowsUpdateRebootPendingCount = 0
    
        $lstWinget.Items.Clear()
        $btnWingetScan.IsEnabled = $false
        if ($btnWingetUpdateAll) { $btnWingetUpdateAll.IsEnabled = $false }
        $btnWingetUpdateSel.IsEnabled = $false
        $btnWingetInstall.Visibility = "Collapsed"
        $btnWingetUpdateSel.Visibility = "Visible"
        if ($btnWingetUpdateAll) { $btnWingetUpdateAll.Visibility = "Visible" }
    
        Write-GuiLog " "
        Write-GuiLog "Starting Parallel Scan (global timeout 120s)..."
        # Winget source refresh is handled before the provider worker starts.
        # Store updates use the Microsoft Store CLI instead of the winget msstore source.
        # Do not kill winget here; source preflight may already be running.
        # Stuck winget processes are cleaned at app start and install/update actions handle their own cleanup.
    
        # --- Load Settings ---
        $settings = Get-WmtSettings
        $enabled = if ($settings.EnabledProviders -and $settings.EnabledProviders.Count -gt 0) { 
            $settings.EnabledProviders 
        }
        else { 
            @("winget", "msstore", "windowsupdate", "pip", "npm", "pnpm", "dotnet", "psmodule", "composer", "chocolatey", "scoop", "gem", "cargo", "steam", "legendary", "gogdl")
        }
        $ignoreList = if ($settings.WingetIgnore) { $settings.WingetIgnore } else { @() }
        $includeUnknown = Get-WmtWingetIncludeUnknown -Settings $settings
        $completedWindowsUpdateIds = if ($script:WmtCompletedWindowsUpdateIds) { @($script:WmtCompletedWindowsUpdateIds.Keys) } else { @() }
    
        Write-GuiLog "Enabled providers: $($enabled -join ', ')"

        # Respect per-provider Scan toggle: providers with Scan=false are
        # skipped during update scans (but still available for search/install).
        $allToggles = Get-WmtProviderToggles -Settings $settings
        $scanEnabled = @()
        foreach ($prov in @($enabled)) {
            $t = $null
            if ($allToggles -is [System.Collections.IDictionary] -and $allToggles.Contains($prov)) {
                $t = $allToggles[$prov]
            }
            $scanOn = $false
            if ($t) {
                if ($t -is [System.Collections.IDictionary]) {
                    if ($t.Contains("Scan")) { $scanOn = [bool]$t["Scan"] }
                }
                else {
                    try { if ($t.PSObject.Properties["Scan"]) { $scanOn = [bool]$t.Scan } } catch {}
                }
            }
            if ($scanOn) { $scanEnabled += $prov }
        }
        $enabled = $scanEnabled

        Write-GuiLog "Scan-enabled providers: $($enabled -join ', ')"
        Write-GuiLog "Winget include unknown: $includeUnknown"

        # Gate the actual winget scan behind a completed source refresh.
        # This keeps startup clickable but ensures the first visible package results are collected after source prep.
        $wingetSourcesToPrep = @()
        if ("winget" -in $enabled) { $wingetSourcesToPrep += "winget" }

        if ($wingetSourcesToPrep.Count -gt 0 -and -not $script:WingetSourcePreflightReadyForScan) {
            if (-not $script:WingetScanSourcePreflightInProgress) {
                Start-WingetScanSourcePreflight -Sources $wingetSourcesToPrep
            }
            else {
                Write-GuiLog "Waiting for winget source preflight to finish before scanning..."
            }
            return
        }
        #$script:WingetSourcePreflightReadyForScan = $false
        # Keep the ready flag set after the first preflight so later page/manual refreshes scan immediately.
    
        # --- Reset scan tracking ---
        $script:ActiveScans.Clear()
        $script:ScanCancelled = $false
        $script:ScanStartTime = Get-Date
    
        # --- Global Timeout Timer (120 seconds) ---
        if ($script:GlobalScanTimer) {
            try { $script:GlobalScanTimer.Stop() } catch {}
            $script:GlobalScanTimer = $null
        }
        $script:GlobalScanTimer = New-Object System.Windows.Threading.DispatcherTimer
        $script:GlobalScanTimer.Interval = [TimeSpan]::FromSeconds(120)
        $script:GlobalScanTimer.Add_Tick({
                if ($script:ActiveScans.Count -gt 0 -and -not $script:ScanCancelled) {
                    $script:ScanCancelled = $true
                    Write-GuiLog "Global scan timeout reached (120s). Cancelling remaining provider scans."
                    # Stop all still-running runspaces
                    foreach ($task in $script:ActiveScans) {
                        try { $null = $task.PowerShell.BeginStop($null, $null) } catch { }
                    }
                    $script:ActiveScans.Clear()
                    # Stop result collection timer
                    if ($script:ScanTimer.IsEnabled) { $script:ScanTimer.Stop() }
                    $lblWingetStatus.Text = "Scan timeout - some providers did not respond."
                    $lblWingetStatus.Visibility = "Visible"
                    $btnWingetScan.IsEnabled = $true
                    if ($btnWingetUpdateAll) { $btnWingetUpdateAll.IsEnabled = $true }
                    $btnWingetUpdateSel.IsEnabled = $true
                    [System.Windows.MessageBox]::Show(
                        "Scan timed out after 120 seconds.`n`nOne of the enabled package providers did not respond.`nTry disabling slow providers and scan again.",
                        "Scan Timeout", "OK", "Warning"
                    ) | Out-Null
                }
                $script:GlobalScanTimer.Stop()
            })
        $script:GlobalScanTimer.Start()
    
        # --- Provider Workers ---
    
        # A. WINGET
        foreach ($wingetSource in @("winget")) {
            if ($wingetSource -notin $enabled) { continue }
    
            $ps = [PowerShell]::Create()
            [void]$ps.AddScript({
                    param($SourceName, $IgnoreList, $IncludeUnknown)
                    [Console]::OutputEncoding = [System.Text.UTF8Encoding]::new($false)
    
                    function Test-Ignored($n, $i) {
                        if ($IgnoreList -and ($IgnoreList -contains $n -or $IgnoreList -contains $i)) { return $true }
                        return $false
                    }

                    function Test-WingetScanNoticeLine {
                        param([string]$Text)

                        if ([string]::IsNullOrWhiteSpace($Text)) { return $true }

                        $trimmed = $Text.Trim()
                        if ($trimmed -match "^-+") { return $true }
                        if ($trimmed -match "(?i)--include-unknown") { return $true }
                        if ($trimmed -match "(?i)explicit targeting" -or $trimmed -match "(?i)following packages have an upgrade available") { return $true }
                        if ($trimmed -match "(?i)^(name|nom)\s+(id|identifiant)\s+version(\s+|$)") { return $true }
                        if ($trimmed -match "(?i)^(no updates|all apps are up to date|your apps are up to date)") { return $true }

                        return $false
                    }
    
                    Write-Output "LOG:$SourceName source preflight already completed; starting scan..."
    
                    # Winget source-backed scans can legitimately take a while.
                    $timeoutMs = 120000
    
                    $includeUnknownFlag = if ([bool]$IncludeUnknown) { " --include-unknown" } else { "" }
                    $wArgs = "list --upgrade-available$includeUnknownFlag --accept-source-agreements --disable-interactivity --source $SourceName"
                    try {
                        $pInfo = New-Object System.Diagnostics.ProcessStartInfo
                        $pInfo.FileName = "winget"
                        $pInfo.Arguments = $wArgs
                        $pInfo.RedirectStandardOutput = $true
                        $pInfo.RedirectStandardError = $false
                        $pInfo.UseShellExecute = $false
                        $pInfo.CreateNoWindow = $true
                        $pInfo.StandardOutputEncoding = [System.Text.UTF8Encoding]::new($false)
                        $p = [System.Diagnostics.Process]::Start($pInfo)
                        $outTask = $p.StandardOutput.ReadToEndAsync()
    
                        if (-not $p.WaitForExit($timeoutMs)) {
                            Write-Output "LOG:$SourceName scan timed out after $([int]($timeoutMs / 1000)) seconds."
                            try { $p.Kill() } catch { }
                            try { [void]$p.WaitForExit(2000) } catch { }
                            return
                        }
    
                        $out = $outTask.GetAwaiter().GetResult()
    
                        # Auto-accept & refresh if needed (existing logic)
                        if ($p.ExitCode -eq -1978335231 -or $p.ExitCode -eq -1978335229) { 
                            Write-Output "LOG:$SourceName connection failed (Code: $($p.ExitCode)). Auto-accepting agreements and refreshing..."
                            $fixInfo1 = New-Object System.Diagnostics.ProcessStartInfo("winget", "search `"Spotify`" --source $SourceName --accept-source-agreements")
                            $fixInfo1.CreateNoWindow = $true; $fixInfo1.UseShellExecute = $false
                            $fixP1 = [System.Diagnostics.Process]::Start($fixInfo1)
                            if (-not $fixP1.WaitForExit(30000)) {
                                try { $fixP1.Kill() } catch {}
                                Write-Output "LOG:$SourceName agreement repair timed out."
                            }
    
                            $fixInfo2 = New-Object System.Diagnostics.ProcessStartInfo("winget", "source update --name $SourceName")
                            $fixInfo2.CreateNoWindow = $true; $fixInfo2.UseShellExecute = $false
                            $fixP2 = [System.Diagnostics.Process]::Start($fixInfo2)
                            if (-not $fixP2.WaitForExit(60000)) {
                                try { $fixP2.Kill() } catch {}
                                Write-Output "LOG:$SourceName refresh repair timed out."
                            }
    
                            Write-Output "LOG:$SourceName refreshed. Retrying scan..."
                            $p = [System.Diagnostics.Process]::Start($pInfo)
                            $outTask = $p.StandardOutput.ReadToEndAsync()
                            if (-not $p.WaitForExit($timeoutMs)) {
                                Write-Output "LOG:$SourceName retry scan timed out after $([int]($timeoutMs / 1000)) seconds."
                                try { $p.Kill() } catch { }
                                try { [void]$p.WaitForExit(2000) } catch { }
                                return
                            }
                            $out = $outTask.GetAwaiter().GetResult()
                        }
    
                        if ($p.ExitCode -ne 0) {
                            Write-Output "LOG:$SourceName scan exited with code $($p.ExitCode)."
                        }
    
                        if (-not [string]::IsNullOrWhiteSpace($out)) {
                            $lines = $out -split "`r`n"
                            foreach ($line in $lines) {
                                $line = $line.Trim()
                                if (Test-WingetScanNoticeLine $line) { continue }
    
                                $parts = $line -split '\s+'
                                $len = $parts.Count
                                if ($len -ge 4) {
                                    $lastWord = $parts[-1]
                                    if ($len -ge 5 -and ($lastWord -eq "winget" -or $lastWord -eq "msstore")) {
                                        $a = $parts[-2]
                                        $v = $parts[-3]
                                        $i = $parts[-4]
                                        $n = ($parts[0..($len - 5)] -join " ")
                                    }
                                    else {
                                        $a = $parts[-1]
                                        $v = $parts[-2]
                                        $i = $parts[-3]
                                        $n = ($parts[0..($len - 4)] -join " ")
                                    }
                                    if ($n -and $i -and $i.Length -gt 2 -and $i -notmatch "^Id$") {
                                        if (Test-Ignored $n $i) { continue }
                                        if ($v -match "^(?i)(unknown|inconnu)$") { $v = "?" }
                                        [PSCustomObject]@{ Source = $SourceName; Name = $n; Id = $i; Version = $v; Available = $a }
                                    }
                                }
                            }
                        }
                    }
                    catch {
                        Write-Output "LOG:$SourceName check failed: $($_.Exception.Message)"
                    }
                }).AddArgument($wingetSource).AddArgument($ignoreList).AddArgument([bool]$includeUnknown)
    
            [void]$script:ActiveScans.Add([PSCustomObject]@{ PowerShell = $ps; AsyncResult = $ps.BeginInvoke() })
        }

        if ("msstore" -in $enabled) {
            $ps = [PowerShell]::Create()
            [void]$ps.AddScript({
                    param($IgnoreList)
                    [Console]::OutputEncoding = [System.Text.UTF8Encoding]::new($false)

                    function Test-Ignored($n, $i) {
                        if ($IgnoreList -and ($IgnoreList -contains $n -or $IgnoreList -contains $i)) { return $true }
                        return $false
                    }

                    function Get-StoreColumnIndex {
                        param([string[]]$Headers, [string[]]$Patterns, [int]$DefaultIndex = -1)
                        if ($Headers) {
                            for ($idx = 0; $idx -lt $Headers.Count; $idx++) {
                                foreach ($pattern in $Patterns) {
                                    if ($Headers[$idx] -match $pattern) { return $idx }
                                }
                            }
                        }
                        return $DefaultIndex
                    }

                    function Get-StoreColumnValue {
                        param([string[]]$Columns, [int]$Index, [string]$Fallback = "")
                        if ($Index -ge 0 -and $Index -lt $Columns.Count) { return ([string]$Columns[$Index]).Trim() }
                        return $Fallback
                    }

                    function Get-StoreCliProductId {
                        param([string]$Value)

                        $text = ([string]$Value).Trim()
                        if ([string]::IsNullOrWhiteSpace($text)) { return "" }

                        $matchPatterns = @(
                            '(?i)(?:product\s*id|productid|product-id)\s*[:=]\s*((?:9[A-Z0-9]{9,19}|XP[A-Z0-9]{8,18}))',
                            '(?i)(?:/detail/|productid=)((?:9[A-Z0-9]{9,19}|XP[A-Z0-9]{8,18}))',
                            '(?i)\b((?:9[A-Z0-9]{9,19}|XP[A-Z0-9]{8,18}))\b'
                        )

                        foreach ($pattern in $matchPatterns) {
                            $match = [regex]::Match($text, $pattern)
                            if ($match.Success) { return $match.Groups[1].Value.ToUpperInvariant() }
                        }

                        return ""
                    }

                    function ConvertFrom-StoreUpdatesOutput {
                        param([string]$OutputText)

                        $items = New-Object System.Collections.Generic.List[object]
                        if ([string]::IsNullOrWhiteSpace($OutputText)) { return $items.ToArray() }

                        $cleanText = [regex]::Replace($OutputText, "`e\[[0-?]*[ -/]*[@-~]", "")
                        $headers = $null
                        $vertical = [string][char]0x2502
                        $lines = $cleanText -split "`r?`n"

                        foreach ($rawLine in $lines) {
                            $line = ([string]$rawLine).Trim()
                            if ([string]::IsNullOrWhiteSpace($line)) { continue }
                            if ($line -notmatch '[\p{L}\p{Nd}]') { continue }
                            if ($line -match '(?i)^(checking|usage:|commands?:|options?:|examples?:)' -or $line -match '(?i)store cli') { continue }
                            if ($line -match '(?i)^(no updates|all apps are up to date|your apps are up to date)') { continue }

                            $cols = @()
                            if ($line.Contains($vertical)) {
                                $rawCols = $line -split [regex]::Escape($vertical)
                                if ($rawCols.Count -gt 2) {
                                    for ($ci = 1; $ci -lt ($rawCols.Count - 1); $ci++) {
                                        $value = ([string]$rawCols[$ci]).Trim()
                                        if ($value -ne "") { $cols += $value }
                                    }
                                }
                            }
                            elseif ($line -match '\s{2,}') {
                                $cols = @($line -split '\s{2,}' | ForEach-Object { ([string]$_).Trim() } | Where-Object { $_ -ne "" })
                            }

                            if ($cols.Count -lt 2) { continue }

                            $lowerCols = @($cols | ForEach-Object { ([string]$_).ToLowerInvariant() })
                            if ($lowerCols -contains "name" -or $lowerCols -contains "app" -or $lowerCols -contains "title") {
                                $headers = [string[]]$cols
                                continue
                            }
                            if ($headers -and ($headers[0] -match '(?i)^command$')) { continue }

                            $nameIndex = Get-StoreColumnIndex -Headers $headers -Patterns @('(?i)^(name|app|title)$') -DefaultIndex 0
                            $idIndex = Get-StoreColumnIndex -Headers $headers -Patterns @('(?i)product\s*id', '(?i)store\s*id', '(?i)catalog\s*id', '(?i)^id$') -DefaultIndex -1
                            $versionIndex = Get-StoreColumnIndex -Headers $headers -Patterns @('(?i)installed', '(?i)current', '(?i)^version$') -DefaultIndex -1
                            $availableIndex = Get-StoreColumnIndex -Headers $headers -Patterns @('(?i)available', '(?i)latest', '(?i)new\s+version', '(?i)update') -DefaultIndex -1

                            if ($availableIndex -eq $versionIndex) { $availableIndex = -1 }

                            $n = Get-StoreColumnValue -Columns $cols -Index $nameIndex
                            if ([string]::IsNullOrWhiteSpace($n) -or $n -match '(?i)^(name|app|title)$') { continue }

                            $i = Get-StoreCliProductId (Get-StoreColumnValue -Columns $cols -Index $idIndex -Fallback "")
                            $detectedProductId = $null
                            for ($colIndex = 0; $colIndex -lt $cols.Count; $colIndex++) {
                                if ($colIndex -eq $nameIndex) { continue }
                                $candidate = Get-StoreCliProductId $cols[$colIndex]
                                if ($candidate) {
                                    $detectedProductId = $candidate
                                    break
                                }
                            }
                            if ($detectedProductId -and [string]::IsNullOrWhiteSpace($i)) {
                                $i = $detectedProductId
                            }
                            if ([string]::IsNullOrWhiteSpace($i)) { $i = "" }
                            $v = Get-StoreColumnValue -Columns $cols -Index $versionIndex -Fallback "?"
                            $a = Get-StoreColumnValue -Columns $cols -Index $availableIndex -Fallback "Update available"

                            if (Test-Ignored $n $i) { continue }
                            [void]$items.Add([PSCustomObject]@{Source = "msstore"; Name = $n; Id = $i; Version = $v; Available = $a })
                        }

                        return $items.ToArray()
                    }

                    Write-Output "LOG:Scanning Microsoft Store with Store CLI..."
                    try {
                        if (-not (Get-Command "store" -ErrorAction SilentlyContinue)) {
                            Write-Output "LOG:Store CLI was not found. Update Microsoft Store, then scan again."
                            return
                        }

                        $pInfo = New-Object System.Diagnostics.ProcessStartInfo
                        $pInfo.FileName = "store"
                        $pInfo.Arguments = "updates"
                        $pInfo.RedirectStandardOutput = $true
                        $pInfo.RedirectStandardError = $true
                        $pInfo.RedirectStandardInput = $true
                        $pInfo.UseShellExecute = $false
                        $pInfo.CreateNoWindow = $true
                        $pInfo.StandardOutputEncoding = [System.Text.UTF8Encoding]::new($false)
                        $pInfo.StandardErrorEncoding = [System.Text.UTF8Encoding]::new($false)

                        $p = [System.Diagnostics.Process]::Start($pInfo)
                        $outTask = $p.StandardOutput.ReadToEndAsync()
                        $errTask = $p.StandardError.ReadToEndAsync()
                        try {
                            $p.StandardInput.WriteLine("n")
                            $p.StandardInput.Close()
                        }
                        catch {}

                        if (-not $p.WaitForExit(60000)) {
                            Write-Output "LOG:Store CLI scan timed out after 60 seconds."
                            try { $p.Kill() } catch {}
                            try { [void]$p.WaitForExit(2000) } catch {}
                            return
                        }

                        $out = $outTask.GetAwaiter().GetResult()
                        $err = $errTask.GetAwaiter().GetResult()
                        $combined = "$out`n$err"

                        if ($p.ExitCode -ne 0) {
                            Write-Output "LOG:Store CLI scan exited with code $($p.ExitCode)."
                            if (-not [string]::IsNullOrWhiteSpace($err)) {
                                foreach ($errLine in ($err -split "`r?`n")) {
                                    if (-not [string]::IsNullOrWhiteSpace($errLine)) { Write-Output "LOG:Store CLI: $errLine" }
                                }
                            }
                        }

                        $storeItems = @(ConvertFrom-StoreUpdatesOutput -OutputText $combined)
                        if ($storeItems.Count -eq 0 -and $combined -match '(?i)(no updates|up to date)') {
                            Write-Output "LOG:No Microsoft Store updates found by Store CLI."
                        }
                        foreach ($storeItem in $storeItems) { $storeItem }
                    }
                    catch {
                        Write-Output "LOG:Store CLI check failed: $($_.Exception.Message)"
                    }
                }).AddArgument($ignoreList)

            [void]$script:ActiveScans.Add([PSCustomObject]@{ PowerShell = $ps; AsyncResult = $ps.BeginInvoke() })
        }

        # Resolve WU category toggles in main scope (can't call functions inside runspace).
        $wuCategoryTogglesForScan = Get-WmtWuCategoryToggles -Settings $settings

        # WINDOWS UPDATE WORKER - includes optional updates.
        if ("windowsupdate" -in $enabled) {
            $ps = [PowerShell]::Create()
            [void]$ps.AddScript({
                    param($IgnoreList, $CompletedUpdateIds, $WuCategoryToggles)
                    [Console]::OutputEncoding = [System.Text.UTF8Encoding]::new($false)

                    function Test-Ignored($n, $i) {
                        if ($IgnoreList -and ($IgnoreList -contains $n -or $IgnoreList -contains $i)) { return $true }
                        return $false
                    }

                    function Get-WmtWuCategoryText {
                        param($Update)
                        $names = New-Object System.Collections.Generic.List[string]
                        try {
                            for ($i = 0; $i -lt $Update.Categories.Count; $i++) {
                                $title = ([string]$Update.Categories.Item($i).Name).Trim()
                                if (-not [string]::IsNullOrWhiteSpace($title) -and -not $names.Contains($title)) { [void]$names.Add($title) }
                            }
                        }
                        catch {}
                        $text = ($names.ToArray() -join ", ")
                        if ([string]::IsNullOrWhiteSpace($text)) {
                            try { $text = [string]$Update.Type } catch { $text = "Windows Update" }
                        }
                        if ([string]::IsNullOrWhiteSpace($text)) { $text = "Windows Update" }
                        return $text
                    }

                    function Test-WmtWuOptionalUpdate {
                        param($Update)
                        $isOptional = $false
                        try { if ([bool]$Update.BrowseOnly) { $isOptional = $true } } catch {}
                        try { if (-not [bool]$Update.AutoSelectOnWebSites) { $isOptional = $true } } catch {}
                        try { if (-not [bool]$Update.IsMandatory -and [bool]$Update.BrowseOnly) { $isOptional = $true } } catch {}
                        return $isOptional
                    }

                    function Get-WmtWuSuccessfulInstallIdsSinceBoot {
                        param($Searcher)

                        $ids = New-Object "System.Collections.Generic.HashSet[string]" ([System.StringComparer]::OrdinalIgnoreCase)
                        try {
                            $lastBootUtc = (Get-CimInstance Win32_OperatingSystem -ErrorAction Stop).LastBootUpTime.ToUniversalTime()
                            $historyCount = [int]$Searcher.GetTotalHistoryCount()
                            $take = [Math]::Min(1000, $historyCount)
                            if ($take -le 0) { return , $ids }

                            $history = $Searcher.QueryHistory(0, $take)
                            for ($historyIndex = 0; $historyIndex -lt $history.Count; $historyIndex++) {
                                $entry = $history.Item($historyIndex)
                                if (-not $entry) { continue }

                                $entryDate = [DateTime]::MinValue
                                try { $entryDate = [DateTime]$entry.Date } catch {}
                                if ($entryDate -lt $lastBootUtc) { continue }

                                $operation = -1
                                $resultCode = -1
                                try { $operation = [int]$entry.Operation } catch {}
                                try { $resultCode = [int]$entry.ResultCode } catch {}
                                if ($operation -ne 1 -or $resultCode -ne 2) { continue }

                                $historyId = ""
                                $historyRevision = -1
                                try { $historyId = ([string]$entry.UpdateIdentity.UpdateID).Trim() } catch {}
                                try { $historyRevision = [int]$entry.UpdateIdentity.RevisionNumber } catch {}
                                if (-not [string]::IsNullOrWhiteSpace($historyId) -and $historyRevision -ge 0) {
                                    [void]$ids.Add("$historyId|$historyRevision")
                                }
                            }
                        }
                        catch {
                            Write-Output "LOG:Windows Update successful-history check failed: $($_.Exception.Message)"
                        }
                        return , $ids
                    }

                    Write-Output "LOG:Scanning Windows Update, including optional updates..."
                    try {
                        $session = New-Object -ComObject Microsoft.Update.Session
                        $searcher = $session.CreateUpdateSearcher()
                        try { $searcher.Online = $true } catch {}
                        $criteria = "IsInstalled=0 and IsHidden=0"
                        $result = $searcher.Search($criteria)
                        if (-not $result -or -not $result.Updates) {
                            Write-Output "LOG:Windows Update returned no scan result."
                            return
                        }

                        $completedIds = Get-WmtWuSuccessfulInstallIdsSinceBoot -Searcher $searcher
                        foreach ($completedId in @($CompletedUpdateIds)) {
                            $trimmedCompletedId = ([string]$completedId).Trim()
                            if (-not [string]::IsNullOrWhiteSpace($trimmedCompletedId)) { [void]$completedIds.Add($trimmedCompletedId) }
                        }

                        $count = [int]$result.Updates.Count
                        $visibleCount = 0
                        $optionalCount = 0
                        $completedSuppressedCount = 0
                        $rebootSuppressedCount = 0
                        for ($i = 0; $i -lt $count; $i++) {
                            $update = $result.Updates.Item($i)
                            if (-not $update) { continue }

                            $title = ([string]$update.Title).Trim()
                            if ([string]::IsNullOrWhiteSpace($title)) { $title = "Windows Update" }
                            $updateId = ""
                            $revision = 0
                            try { $updateId = ([string]$update.Identity.UpdateID).Trim() } catch {}
                            try { $revision = [int]$update.Identity.RevisionNumber } catch { $revision = 0 }
                            if ([string]::IsNullOrWhiteSpace($updateId)) { $updateId = $title }
                            $rowId = "$updateId|$revision"
                            if (Test-Ignored $title $rowId) { continue }
                            if ($completedIds.Contains($rowId)) {
                                $completedSuppressedCount++
                                Write-Output "LOG:Windows Update suppressed already successful revision: $title"
                                continue
                            }
                            $updateRebootRequired = $false
                            try { $updateRebootRequired = [bool]$update.RebootRequired } catch {}
                            if ($updateRebootRequired) {
                                $rebootSuppressedCount++
                                Write-Output "LOG:Windows Update suppressed reboot-pending revision: $title"
                                continue
                            }

                            $categoryText = Get-WmtWuCategoryText -Update $update
                            $kbText = ""
                            try {
                                $kbValues = @()
                                for ($kbIndex = 0; $kbIndex -lt $update.KBArticleIDs.Count; $kbIndex++) {
                                    $kb = ([string]$update.KBArticleIDs.Item($kbIndex)).Trim()
                                    if (-not [string]::IsNullOrWhiteSpace($kb)) { $kbValues += "KB$kb" }
                                }
                                if ($kbValues.Count -gt 0) { $kbText = $kbValues -join ", " }
                            }
                            catch {}

                            $isOptional = Test-WmtWuOptionalUpdate -Update $update
                            if ($isOptional) { $optionalCount++ }
                            $severity = ""
                            try { $severity = ([string]$update.MsrcSeverity).Trim() } catch {}
                            $availability = if ($isOptional) { "Optional" } elseif (-not [string]::IsNullOrWhiteSpace($severity)) { "Security: $severity" } elseif ($categoryText -match '(?i)driver') { "Driver" } else { "Important" }
                            $displayName = if ($isOptional -and $title -notmatch '^\[Optional\]') { "[Optional] $title" } else { $title }
                            if (-not [string]::IsNullOrWhiteSpace($kbText) -and $displayName -notmatch [regex]::Escape($kbText)) {
                                $displayName = "$displayName ($kbText)"
                            }

                            # Apply WU category filter: skip updates whose
                            # categories are disabled in provider settings.
                            # $WuCategoryToggles was passed from the main scope
                            # (runspaces can't call main-scope functions).
                            $isInsider = ($title -match '(?i)insider|preview|beta|dev channel|canary')
                            $isDriver = ($categoryText -match '(?i)driver')
                            $isSecurity = (-not [string]::IsNullOrWhiteSpace($severity))
                            $showThisUpdate = $false
                            if (-not $isOptional -and -not $isDriver -and -not $isSecurity -and -not $isInsider) {
                                if ($WuCategoryToggles.Updates) { $showThisUpdate = $true }
                            }
                            if ($isOptional -and $WuCategoryToggles.Optional) { $showThisUpdate = $true }
                            if ($isDriver -and $WuCategoryToggles.Driver) { $showThisUpdate = $true }
                            if ($isSecurity -and $WuCategoryToggles.Security) { $showThisUpdate = $true }
                            if ($isInsider -and $WuCategoryToggles.Insider) { $showThisUpdate = $true }
                            if (-not $showThisUpdate) { continue }

                            $visibleCount++
                            [PSCustomObject]@{
                                Source       = "windowsupdate"
                                Name         = $displayName
                                Id           = $rowId
                                Version      = $categoryText
                                Available    = $availability
                                WUIsOptional = $isOptional
                            }
                        }

                        if ($visibleCount -eq 0) {
                            Write-Output "LOG:No Windows Update items found."
                        }
                        else {
                            Write-Output "LOG:Windows Update found $visibleCount item(s), including $optionalCount optional item(s)."
                        }
                        if ($completedSuppressedCount -gt 0) {
                            Write-Output "LOG:Windows Update suppressed $completedSuppressedCount exact revision(s) already recorded successful since boot or during this WMT session."
                        }
                        if ($rebootSuppressedCount -gt 0) {
                            Write-Output "STATE:WINDOWS_UPDATE_REBOOT_REQUIRED:$rebootSuppressedCount"
                            Write-Output "LOG:Windows Update suppressed $rebootSuppressedCount update(s) that are already waiting for a reboot."
                        }
                    }
                    catch {
                        Write-Output "LOG:Windows Update scan failed: $($_.Exception.Message)"
                    }
                }).AddArgument($ignoreList).AddArgument($completedWindowsUpdateIds).AddArgument($wuCategoryTogglesForScan)

            [void]$script:ActiveScans.Add([PSCustomObject]@{ PowerShell = $ps; AsyncResult = $ps.BeginInvoke() })
        }
    
        # B. PIP WORKER
        if ("pip" -in $enabled) {
            $ps = [PowerShell]::Create()
            [void]$ps.AddScript({
                    param($IgnoreList)
                    Write-Output "LOG:Scanning Pip..."
                    try {
                        $pInfo = New-Object System.Diagnostics.ProcessStartInfo
                        $pInfo.FileName = "python.exe"
                        $pInfo.Arguments = "-m pip --disable-pip-version-check --no-input --timeout 20 --retries 1 list --outdated --format=json"
                        $pInfo.RedirectStandardOutput = $true
                        $pInfo.RedirectStandardError = $true
                        $pInfo.UseShellExecute = $false
                        $pInfo.CreateNoWindow = $true
                        $pInfo.WindowStyle = [System.Diagnostics.ProcessWindowStyle]::Hidden

                        $pipProcess = [System.Diagnostics.Process]::Start($pInfo)
                        $outTask = $pipProcess.StandardOutput.ReadToEndAsync()
                        $errTask = $pipProcess.StandardError.ReadToEndAsync()
                        if (-not $pipProcess.WaitForExit(60000)) {
                            Write-Output "LOG:Pip scan timed out after 60 seconds. Stopping its process tree."
                            try {
                                $killInfo = New-Object System.Diagnostics.ProcessStartInfo
                                $killInfo.FileName = "taskkill.exe"
                                $killInfo.Arguments = "/PID $($pipProcess.Id) /T /F"
                                $killInfo.UseShellExecute = $false
                                $killInfo.CreateNoWindow = $true
                                $killInfo.WindowStyle = [System.Diagnostics.ProcessWindowStyle]::Hidden
                                $killProcess = [System.Diagnostics.Process]::Start($killInfo)
                                if ($killProcess) { [void]$killProcess.WaitForExit(5000) }
                            }
                            catch {
                                try { $pipProcess.Kill() } catch {}
                            }
                            return
                        }

                        try { [void]$pipProcess.WaitForExit() } catch {}
                        $json = ""
                        $pipError = ""
                        try { if ($outTask.IsCompleted) { $json = $outTask.GetAwaiter().GetResult() } } catch {}
                        try { if ($errTask.IsCompleted) { $pipError = $errTask.GetAwaiter().GetResult() } } catch {}
                        if ($pipProcess.ExitCode -ne 0) {
                            $detail = if ([string]::IsNullOrWhiteSpace($pipError)) { "exit code $($pipProcess.ExitCode)" } else { $pipError.Trim() }
                            Write-Output "LOG:Pip scan failed: $detail"
                            return
                        }
                        if ($json.Trim().StartsWith("[")) { 
                            $pkgs = $json | ConvertFrom-Json
                            foreach ($pkg in $pkgs) {
                                if ($IgnoreList -contains $pkg.name) { continue }
                                [PSCustomObject]@{Source = "pip"; Name = $pkg.name; Id = $pkg.name; Version = $pkg.version; Available = $pkg.latest_version }
                            }
                        }
                    }
                    catch { Write-Output "LOG:Pip check failed: $($_.Exception.Message)" }
                }).AddArgument($ignoreList)
            [void]$script:ActiveScans.Add([PSCustomObject]@{ PowerShell = $ps; AsyncResult = $ps.BeginInvoke() })
        }
    
        # C. NPM WORKER
        if ("npm" -in $enabled) {
            $ps = [PowerShell]::Create()
            [void]$ps.AddScript({
                    param($IgnoreList)
                    Write-Output "LOG:Scanning Npm..."
                    try {
                        # Local packages
                        $pInfo = New-Object System.Diagnostics.ProcessStartInfo("cmd", "/c npm outdated --json 2>nul")
                        $pInfo.RedirectStandardOutput = $true; $pInfo.UseShellExecute = $false; $pInfo.CreateNoWindow = $true
                        $p = [System.Diagnostics.Process]::Start($pInfo)
                        $outTask = $p.StandardOutput.ReadToEndAsync()
                        if ($p.WaitForExit(30000)) { 
                            $json = $outTask.GetAwaiter().GetResult().Trim()
                            if ($json -and $json.StartsWith("{")) { 
                                $pkgs = $json | ConvertFrom-Json
                                foreach ($k in $pkgs.PSObject.Properties.Name) {
                                    if ($IgnoreList -contains $k) { continue }
                                    $o = $pkgs.$k
                                    [PSCustomObject]@{Source = "npm"; Name = $k; Id = $k; Version = $o.current; Available = $o.latest }
                                }
                            }
                        }
                        else {
                            try { & "$env:SystemRoot\System32\taskkill.exe" /PID $p.Id /T /F 2>$null | Out-Null } catch { try { $p.Kill() } catch {} }
                            Write-Output "LOG:Npm local scan timed out."
                        }

                        # Global packages
                        $pInfoG = New-Object System.Diagnostics.ProcessStartInfo("cmd", "/c npm outdated -g --json 2>nul")
                        $pInfoG.RedirectStandardOutput = $true; $pInfoG.UseShellExecute = $false; $pInfoG.CreateNoWindow = $true
                        $pg = [System.Diagnostics.Process]::Start($pInfoG)
                        $outTaskG = $pg.StandardOutput.ReadToEndAsync()
                        if ($pg.WaitForExit(30000)) { 
                            $jsonG = $outTaskG.GetAwaiter().GetResult().Trim()
                            if ($jsonG -and $jsonG.StartsWith("{")) { 
                                $pkgsG = $jsonG | ConvertFrom-Json
                                foreach ($k in $pkgsG.PSObject.Properties.Name) {
                                    if ($IgnoreList -contains $k) { continue }
                                    $o = $pkgsG.$k
                                    [PSCustomObject]@{Source = "npm (global)"; Name = $k; Id = $k; Version = $o.current; Available = $o.latest }
                                }
                            }
                        }
                        else {
                            try { & "$env:SystemRoot\System32\taskkill.exe" /PID $pg.Id /T /F 2>$null | Out-Null } catch { try { $pg.Kill() } catch {} }
                            Write-Output "LOG:Npm global scan timed out."
                        }
                    }
                    catch { Write-Output "LOG:Npm check failed." }
                }).AddArgument($ignoreList)
            [void]$script:ActiveScans.Add([PSCustomObject]@{ PowerShell = $ps; AsyncResult = $ps.BeginInvoke() })
        }
    
        # D. CHOCOLATEY WORKER (unchanged)
        if ("chocolatey" -in $enabled) {
            $ps = [PowerShell]::Create()
            [void]$ps.AddScript({
                    param($IgnoreList)
                    Write-Output "LOG:Scanning Chocolatey..."
                    try {
                        $pInfo = New-Object System.Diagnostics.ProcessStartInfo("choco", "outdated -r")
                        $pInfo.RedirectStandardOutput = $true; $pInfo.UseShellExecute = $false; $pInfo.CreateNoWindow = $true
                        $p = [System.Diagnostics.Process]::Start($pInfo)
                        $outTask = $p.StandardOutput.ReadToEndAsync()
                        if (-not $p.WaitForExit(60000)) { try { & "$env:SystemRoot\System32\taskkill.exe" /PID $p.Id /T /F 2>$null | Out-Null } catch { try { $p.Kill() } catch {} }; Write-Output "LOG:Chocolatey scan timed out."; return }
                        $out = $outTask.GetAwaiter().GetResult()
                        $lines = $out -split "`r`n"
                        foreach ($l in $lines) { 
                            if (!$l) { continue }
                            $p = $l -split "\|"
                            if ($p.Count -ge 4) {
                                $n = $p[0]
                                if ($IgnoreList -contains $n) { continue }
                                [PSCustomObject]@{Source = "chocolatey"; Name = $n; Id = $n; Version = $p[1]; Available = $p[2] }
                            }
                        }
                    }
                    catch { Write-Output "LOG:Choco check failed." }
                }).AddArgument($ignoreList)
            [void]$script:ActiveScans.Add([PSCustomObject]@{ PowerShell = $ps; AsyncResult = $ps.BeginInvoke() })
        }
    
        # E. SCOOP WORKER (unchanged)
        if ("scoop" -in $enabled) {
            $ps = [PowerShell]::Create()
            [void]$ps.AddScript({
                    param($IgnoreList)
                    Write-Output "LOG:Scanning Scoop..."
                    try {
                        $pInfo = New-Object System.Diagnostics.ProcessStartInfo("cmd", "/c scoop status")
                        $pInfo.RedirectStandardOutput = $true; $pInfo.UseShellExecute = $false; $pInfo.CreateNoWindow = $true
                        $p = [System.Diagnostics.Process]::Start($pInfo)
                        $outTask = $p.StandardOutput.ReadToEndAsync()
                        if (-not $p.WaitForExit(30000)) { try { & "$env:SystemRoot\System32\taskkill.exe" /PID $p.Id /T /F 2>$null | Out-Null } catch { try { $p.Kill() } catch {} }; Write-Output "LOG:Scoop scan timed out."; return }
                        $out = $outTask.GetAwaiter().GetResult()
                        $lines = $out -split "`r`n"
                        foreach ($line in $lines) {
                            $line = $line.Trim()
                            if ([string]::IsNullOrWhiteSpace($line) -or $line -match "^Name\s+Version" -or $line -match "^----" -or $line -match "Scoop is up to date") { continue }
                            if ($line -match '^(\S+)\s+(\S+)\s+(\S+)') {
                                $n = $matches[1]; $v = $matches[2]; $l = $matches[3]
                                if ($IgnoreList -contains $n) { continue }
                                [PSCustomObject]@{Source = "scoop"; Name = $n; Id = $n; Version = $v; Available = $l }
                            }
                        }
                    }
                    catch { Write-Output "LOG:Scoop check failed." }
                }).AddArgument($ignoreList)
            [void]$script:ActiveScans.Add([PSCustomObject]@{ PowerShell = $ps; AsyncResult = $ps.BeginInvoke() })
        }
    
        # F. RUBY GEMS WORKER (unchanged)
        if ("gem" -in $enabled) {
            $ps = [PowerShell]::Create()
            [void]$ps.AddScript({
                    param($IgnoreList)
                    Write-Output "LOG:Scanning Ruby Gems..."
                    try {
                        $pInfo = New-Object System.Diagnostics.ProcessStartInfo("cmd", "/c gem outdated")
                        $pInfo.RedirectStandardOutput = $true; $pInfo.UseShellExecute = $false; $pInfo.CreateNoWindow = $true
                        $p = [System.Diagnostics.Process]::Start($pInfo)
                        $outTask = $p.StandardOutput.ReadToEndAsync()
                        if (-not $p.WaitForExit(30000)) { try { & "$env:SystemRoot\System32\taskkill.exe" /PID $p.Id /T /F 2>$null | Out-Null } catch { try { $p.Kill() } catch {} }; Write-Output "LOG:Gem scan timed out."; return }
                        $out = $outTask.GetAwaiter().GetResult()
                        $lines = $out -split "`r`n"
                        foreach ($line in $lines) {
                            if ($line -match '^(\S+)\s+\(([\d\.]+)\s+<\s+([\d\.]+)\)') {
                                $n = $matches[1]; $v = $matches[2]; $a = $matches[3]
                                if ($IgnoreList -contains $n) { continue }
                                [PSCustomObject]@{Source = "gem"; Name = $n; Id = $n; Version = $v; Available = $a }
                            }
                        }
                    }
                    catch { Write-Output "LOG:Gem check failed." }
                }).AddArgument($ignoreList)
            [void]$script:ActiveScans.Add([PSCustomObject]@{ PowerShell = $ps; AsyncResult = $ps.BeginInvoke() })
        }
    
        # G. CARGO WORKER (unchanged)
        if ("cargo" -in $enabled) {
            $ps = [PowerShell]::Create()
            [void]$ps.AddScript({
                    param($IgnoreList)
                    Write-Output "LOG:Scanning Cargo..."
                    try {
                        $pInfo = New-Object System.Diagnostics.ProcessStartInfo("cmd", "/c cargo install --list")
                        $pInfo.RedirectStandardOutput = $true; $pInfo.UseShellExecute = $false; $pInfo.CreateNoWindow = $true
                        $p = [System.Diagnostics.Process]::Start($pInfo)
                        $outTask = $p.StandardOutput.ReadToEndAsync()
                        if (-not $p.WaitForExit(30000)) { try { & "$env:SystemRoot\System32\taskkill.exe" /PID $p.Id /T /F 2>$null | Out-Null } catch { try { $p.Kill() } catch {} }; Write-Output "LOG:Cargo scan timed out."; return }
                        $out = $outTask.GetAwaiter().GetResult()
                        $lines = $out -split "`r`n"
                        foreach ($line in $lines) {
                            if ($line -match '^([a-zA-Z0-9_\-]+)\s+v([\d\.]+):') {
                                $n = $matches[1]; $v = $matches[2]
                                if ($IgnoreList -contains $n) { continue }
                                [PSCustomObject]@{Source = "cargo"; Name = $n; Id = $n; Version = $v; Available = "?" }
                            }
                        }
                    }
                    catch { Write-Output "LOG:Cargo check failed." }
                }).AddArgument($ignoreList)
            [void]$script:ActiveScans.Add([PSCustomObject]@{ PowerShell = $ps; AsyncResult = $ps.BeginInvoke() })
        }
    
        # H. .NET GLOBAL TOOLS WORKER
        if ("dotnet" -in $enabled) {
            $ps = [PowerShell]::Create()
            [void]$ps.AddScript({
                    param($IgnoreList)
                    [Console]::OutputEncoding = [System.Text.UTF8Encoding]::new($false)
                    Write-Output "LOG:Scanning .NET global tools..."

                    function Invoke-DotnetToolCommand {
                        param([string]$Arguments, [int]$TimeoutMs = 15000)
                        $pInfo = New-Object System.Diagnostics.ProcessStartInfo("dotnet", $Arguments)
                        $pInfo.RedirectStandardOutput = $true
                        $pInfo.RedirectStandardError = $true
                        $pInfo.UseShellExecute = $false
                        $pInfo.CreateNoWindow = $true
                        $pInfo.StandardOutputEncoding = [System.Text.UTF8Encoding]::new($false)
                        $proc = [System.Diagnostics.Process]::Start($pInfo)
                        $outTask = $proc.StandardOutput.ReadToEndAsync()
                        $errTask = $proc.StandardError.ReadToEndAsync()
                        if (-not $proc.WaitForExit($TimeoutMs)) {
                            try { $proc.Kill() } catch {}
                            return [PSCustomObject]@{ TimedOut = $true; Out = ""; Err = ""; ExitCode = 124 }
                        }
                        return [PSCustomObject]@{
                            TimedOut = $false
                            Out      = $outTask.GetAwaiter().GetResult()
                            Err      = $errTask.GetAwaiter().GetResult()
                            ExitCode = $proc.ExitCode
                        }
                    }

                    function Test-NewerVersionText {
                        param([string]$Current, [string]$Latest)
                        if ([string]::IsNullOrWhiteSpace($Current) -or [string]::IsNullOrWhiteSpace($Latest)) { return $false }
                        try { return ([version]$Latest -gt [version]$Current) } catch { return (([string]$Latest).Trim() -ne ([string]$Current).Trim()) }
                    }

                    try {
                        if (-not (Get-Command dotnet -ErrorAction SilentlyContinue)) {
                            Write-Output "LOG:.NET SDK was not found."
                            return
                        }

                        $listResult = Invoke-DotnetToolCommand -Arguments "tool list --global" -TimeoutMs 20000
                        if ($listResult.TimedOut) { Write-Output "LOG:.NET tool list timed out."; return }
                        $installed = @()
                        foreach ($line in ($listResult.Out -split "`r?`n")) {
                            $trimmed = ([string]$line).Trim()
                            if ([string]::IsNullOrWhiteSpace($trimmed)) { continue }
                            if ($trimmed -match "(?i)^Package\s+Id\s+Version\s+Commands") { continue }
                            if ($trimmed -match "^-+") { continue }
                            $parts = @($trimmed -split "\s+" | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
                            if ($parts.Count -lt 2) { continue }
                            $pkgId = [string]$parts[0]
                            $currentVersion = [string]$parts[1]
                            if ($IgnoreList -contains $pkgId) { continue }
                            $installed += [PSCustomObject]@{ Id = $pkgId; Version = $currentVersion }
                        }

                        if ($installed.Count -eq 0) {
                            Write-Output "LOG:No global .NET tools are installed."
                            return
                        }

                        foreach ($tool in $installed) {
                            $pkgId = [string]$tool.Id
                            $currentVersion = [string]$tool.Version
                            $searchResult = Invoke-DotnetToolCommand -Arguments "tool search `"$pkgId`" --take 5" -TimeoutMs 12000
                            if ($searchResult.TimedOut) { Write-Output "LOG:.NET search timed out for $pkgId."; continue }
                            $latestVersion = ""
                            foreach ($line in ($searchResult.Out -split "`r?`n")) {
                                $trimmed = ([string]$line).Trim()
                                if ([string]::IsNullOrWhiteSpace($trimmed)) { continue }
                                if ($trimmed -match "(?i)^Package\s+ID\s+Version") { continue }
                                if ($trimmed -match "^-+") { continue }
                                $parts = @($trimmed -split "\s+" | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
                                if ($parts.Count -ge 2 -and ([string]$parts[0]).Equals($pkgId, [StringComparison]::OrdinalIgnoreCase)) {
                                    $latestVersion = [string]$parts[1]
                                    break
                                }
                            }
                            if (Test-NewerVersionText -Current $currentVersion -Latest $latestVersion) {
                                [PSCustomObject]@{ Source = "dotnet"; Name = $pkgId; Id = $pkgId; Version = $currentVersion; Available = $latestVersion }
                            }
                        }
                    }
                    catch { Write-Output "LOG:.NET tools check failed: $($_.Exception.Message)" }
                }).AddArgument($ignoreList)
            [void]$script:ActiveScans.Add([PSCustomObject]@{ PowerShell = $ps; AsyncResult = $ps.BeginInvoke() })
        }

        # I. POWERSHELL MODULES WORKER
        if ("psmodule" -in $enabled) {
            $ps = [PowerShell]::Create()
            [void]$ps.AddScript({
                    param($IgnoreList)
                    [Console]::OutputEncoding = [System.Text.UTF8Encoding]::new($false)
                    Write-Output "LOG:Scanning PowerShell modules..."

                    function Test-NewerVersionText {
                        param([string]$Current, [string]$Latest)
                        if ([string]::IsNullOrWhiteSpace($Current) -or [string]::IsNullOrWhiteSpace($Latest)) { return $false }
                        try { return ([version]$Latest -gt [version]$Current) } catch { return (([string]$Latest).Trim() -ne ([string]$Current).Trim()) }
                    }

                    try {
                        if (-not (Get-Command Get-InstalledModule -ErrorAction SilentlyContinue) -or -not (Get-Command Find-Module -ErrorAction SilentlyContinue)) {
                            Write-Output "LOG:PowerShellGet cmdlets were not found."
                            return
                        }

                        $installed = @(Get-InstalledModule -ErrorAction Stop | Sort-Object Name -Unique)
                        if ($installed.Count -eq 0) {
                            Write-Output "LOG:No PowerShellGet-managed modules are installed."
                            return
                        }

                        $nameList = @(
                            $installed |
                            ForEach-Object { [string]$_.Name } |
                            Where-Object { -not [string]::IsNullOrWhiteSpace($_) -and $IgnoreList -notcontains $_ } |
                            Sort-Object -Unique
                        )
                        if ($nameList.Count -eq 0) {
                            Write-Output "LOG:All PowerShellGet-managed modules are ignored."
                            return
                        }

                        $latestMap = @{}
                        $galleryApiSucceeded = $false
                        $lookupTimer = [Diagnostics.Stopwatch]::StartNew()
                        try {
                            # PowerShellGet routes discovery through PackageManagement and can be
                            # slow even for one Name array. PSGallery's OData feed can resolve a
                            # small batch of exact IDs in a single request.
                            for ($offset = 0; $offset -lt $nameList.Count; $offset += 25) {
                                $last = [Math]::Min($offset + 24, $nameList.Count - 1)
                                $batch = @($nameList[$offset..$last])
                                $clauses = @($batch | ForEach-Object { "Id eq '$(([string]$_).Replace("'", "''"))'" })
                                $filter = "IsLatestVersion eq true and ($($clauses -join ' or '))"
                                $uri = 'https://www.powershellgallery.com/api/v2/Packages?$filter=' +
                                [uri]::EscapeDataString($filter) + '&$select=Id,Version'

                                foreach ($entry in @(Invoke-RestMethod -Uri $uri -UseBasicParsing -TimeoutSec 20 -ErrorAction Stop)) {
                                    $foundName = [string]$entry.properties.Id
                                    $foundVersion = [string]$entry.properties.Version
                                    if (-not [string]::IsNullOrWhiteSpace($foundName) -and
                                        -not [string]::IsNullOrWhiteSpace($foundVersion) -and
                                        -not $latestMap.ContainsKey($foundName)) {
                                        $latestMap[$foundName] = $foundVersion
                                    }
                                }
                            }
                            $galleryApiSucceeded = $true
                        }
                        catch {
                            $latestMap.Clear()
                            Write-Output "LOG:Fast PSGallery metadata lookup failed; retrying with PowerShellGet."
                        }

                        if (-not $galleryApiSucceeded) {
                            try {
                                foreach ($found in @(Find-Module -Name $nameList -Repository PSGallery -ErrorAction SilentlyContinue)) {
                                    if ($found -and $found.Name -and -not $latestMap.ContainsKey([string]$found.Name)) {
                                        $latestMap[[string]$found.Name] = [string]$found.Version
                                    }
                                }
                            }
                            catch {
                                Write-Output "LOG:PSGallery lookup failed: $($_.Exception.Message)"
                            }
                        }
                        $lookupTimer.Stop()
                        $lookupSeconds = [Math]::Round($lookupTimer.Elapsed.TotalSeconds, 2)
                        $lookupMethod = if ($galleryApiSucceeded) { "batched Gallery API" } else { "PowerShellGet fallback" }
                        Write-Output "LOG:PowerShell module metadata loaded via $lookupMethod in ${lookupSeconds}s."

                        foreach ($module in $installed) {
                            $name = [string]$module.Name
                            if ([string]::IsNullOrWhiteSpace($name) -or $IgnoreList -contains $name) { continue }
                            if (-not $latestMap.ContainsKey($name)) { continue }
                            $currentVersion = [string]$module.Version
                            $latestVersion = [string]$latestMap[$name]
                            if (Test-NewerVersionText -Current $currentVersion -Latest $latestVersion) {
                                [PSCustomObject]@{ Source = "psmodule"; Name = $name; Id = $name; Version = $currentVersion; Available = $latestVersion }
                            }
                        }
                    }
                    catch { Write-Output "LOG:PowerShell module check failed: $($_.Exception.Message)" }
                }).AddArgument($ignoreList)
            [void]$script:ActiveScans.Add([PSCustomObject]@{ PowerShell = $ps; AsyncResult = $ps.BeginInvoke() })
        }

        # J. COMPOSER WORKER
        if ("composer" -in $enabled) {
            $ps = [PowerShell]::Create()
            [void]$ps.AddScript({
                    param($IgnoreList)
                    [Console]::OutputEncoding = [System.Text.UTF8Encoding]::new($false)
                    Write-Output "LOG:Scanning Composer global packages..."
                    try {
                        if (-not (Get-Command composer -ErrorAction SilentlyContinue)) {
                            Write-Output "LOG:Composer was not found."
                            return
                        }
                        $pInfo = New-Object System.Diagnostics.ProcessStartInfo("cmd", "/c composer global outdated --format=json --no-interaction 2>nul")
                        $pInfo.RedirectStandardOutput = $true
                        $pInfo.UseShellExecute = $false
                        $pInfo.CreateNoWindow = $true
                        $pInfo.StandardOutputEncoding = [System.Text.UTF8Encoding]::new($false)
                        $p = [System.Diagnostics.Process]::Start($pInfo)
                        $outTask = $p.StandardOutput.ReadToEndAsync()
                        if (-not $p.WaitForExit(45000)) { try { & "$env:SystemRoot\System32\taskkill.exe" /PID $p.Id /T /F 2>$null | Out-Null } catch { try { $p.Kill() } catch {} }; Write-Output "LOG:Composer scan timed out."; return }
                        $json = $outTask.GetAwaiter().GetResult().Trim()
                        if ([string]::IsNullOrWhiteSpace($json) -or -not $json.StartsWith("{")) {
                            Write-Output "LOG:Composer reported no outdated global packages."
                            return
                        }
                        $data = $json | ConvertFrom-Json
                        $packages = @()
                        if ($data.PSObject.Properties["installed"]) { $packages = @($data.installed) }
                        elseif ($data.PSObject.Properties["locked"]) { $packages = @($data.locked) }
                        foreach ($pkg in $packages) {
                            $name = [string]$pkg.name
                            if ([string]::IsNullOrWhiteSpace($name) -or $IgnoreList -contains $name) { continue }
                            $currentVersion = if ($pkg.PSObject.Properties["version"]) { [string]$pkg.version } elseif ($pkg.PSObject.Properties["installed"]) { [string]$pkg.installed } else { "?" }
                            $latestVersion = if ($pkg.PSObject.Properties["latest"]) { [string]$pkg.latest } elseif ($pkg.PSObject.Properties["available"]) { [string]$pkg.available } else { "?" }
                            if ($latestVersion -eq "?" -and $currentVersion -eq "?") { continue }
                            [PSCustomObject]@{ Source = "composer"; Name = $name; Id = $name; Version = $currentVersion; Available = $latestVersion }
                        }
                    }
                    catch { Write-Output "LOG:Composer check failed: $($_.Exception.Message)" }
                }).AddArgument($ignoreList)
            [void]$script:ActiveScans.Add([PSCustomObject]@{ PowerShell = $ps; AsyncResult = $ps.BeginInvoke() })
        }

        # H. PNPM WORKER (unchanged)
        if ("pnpm" -in $enabled) {
            $ps = [PowerShell]::Create()
            [void]$ps.AddScript({
                    param($IgnoreList)
                    Write-Output "LOG:Scanning Pnpm..."
                    try {
                        # Local packages
                        $pInfo = New-Object System.Diagnostics.ProcessStartInfo("cmd", "/c pnpm outdated --format json 2>nul")
                        $pInfo.RedirectStandardOutput = $true; $pInfo.UseShellExecute = $false; $pInfo.CreateNoWindow = $true
                        $p = [System.Diagnostics.Process]::Start($pInfo)
                        $outTask = $p.StandardOutput.ReadToEndAsync()
                        if ($p.WaitForExit(35000)) {
                            $json = $outTask.GetAwaiter().GetResult().Trim()
                            if ($json -and $json.StartsWith("[")) {
                                $pkgs = $json | ConvertFrom-Json
                                foreach ($pkg in $pkgs) {
                                    if ($IgnoreList -contains $pkg.name) { continue }
                                    [PSCustomObject]@{Source = "pnpm"; Name = $pkg.name; Id = $pkg.name; Version = $pkg.current; Available = $pkg.latest }
                                }
                            }
                        }
                        else {
                            try { & "$env:SystemRoot\System32\taskkill.exe" /PID $p.Id /T /F 2>$null | Out-Null } catch { try { $p.Kill() } catch {} }
                            Write-Output "LOG:Pnpm local scan timed out."
                        }
                        # Global packages
                        $pInfoG = New-Object System.Diagnostics.ProcessStartInfo("cmd", "/c pnpm outdated -g --format json 2>nul")
                        $pInfoG.RedirectStandardOutput = $true; $pInfoG.UseShellExecute = $false; $pInfoG.CreateNoWindow = $true
                        $pg = [System.Diagnostics.Process]::Start($pInfoG)
                        $outTaskG = $pg.StandardOutput.ReadToEndAsync()
                        if ($pg.WaitForExit(15000)) {
                            $jsonG = $outTaskG.GetAwaiter().GetResult().Trim()
                            if ($jsonG -and $jsonG.StartsWith("[")) {
                                $pkgsG = $jsonG | ConvertFrom-Json
                                foreach ($pkg in $pkgsG) {
                                    if ($IgnoreList -contains $pkg.name) { continue }
                                    [PSCustomObject]@{Source = "pnpm (global)"; Name = $pkg.name; Id = $pkg.name; Version = $pkg.current; Available = $pkg.latest }
                                }
                            }
                        }
                        else {
                            try { & "$env:SystemRoot\System32\taskkill.exe" /PID $pg.Id /T /F 2>$null | Out-Null } catch { try { $pg.Kill() } catch {} }
                            Write-Output "LOG:Pnpm global scan timed out."
                        }
                    }
                    catch { Write-Output "LOG:Pnpm check failed or pnpm not installed." }
                }).AddArgument($ignoreList)
            [void]$script:ActiveScans.Add([PSCustomObject]@{ PowerShell = $ps; AsyncResult = $ps.BeginInvoke() })
        }

        # I. LEGENDARY / EPIC GAMES WORKER
        if ("legendary" -in $enabled) {
            $ps = [PowerShell]::Create()
            [void]$ps.AddScript({
                    param($IgnoreList, $LegendaryExePath)
                    [Console]::OutputEncoding = [System.Text.UTF8Encoding]::new($false)
                    Write-Output "LOG:Scanning Legendary Epic Games updates..."

                    function Test-Ignored($n, $i) {
                        if ($IgnoreList -and ($IgnoreList -contains $n -or $IgnoreList -contains $i)) { return $true }
                        return $false
                    }

                    function ConvertFrom-LegendaryBuildVersion {
                        param([string]$RawVersion)

                        $raw = ([string]$RawVersion).Trim()
                        if ([string]::IsNullOrWhiteSpace($raw)) {
                            return [PSCustomObject]@{ Display = ""; Sort = "" }
                        }

                        $releaseMatch = [regex]::Match($raw, '(?i)\bRelease-(\d+(?:\.\d+){1,5})(?:-CL-(\d+))?')
                        if ($releaseMatch.Success) {
                            $version = [string]$releaseMatch.Groups[1].Value
                            $cl = [string]$releaseMatch.Groups[2].Value
                            $display = if ([string]::IsNullOrWhiteSpace($cl)) { $version } else { "$version (CL $cl)" }
                            $sort = if ([string]::IsNullOrWhiteSpace($cl)) { $version } else { "$version.$cl" }
                            return [PSCustomObject]@{ Display = $display; Sort = $sort }
                        }

                        $lastVersion = ""
                        foreach ($match in [regex]::Matches($raw, '(?<!\d)(\d+(?:\.\d+){1,5})(?!\d)')) {
                            $lastVersion = [string]$match.Groups[1].Value
                        }
                        if (-not [string]::IsNullOrWhiteSpace($lastVersion)) {
                            return [PSCustomObject]@{ Display = $lastVersion; Sort = $lastVersion }
                        }

                        return [PSCustomObject]@{ Display = $raw; Sort = $raw }
                    }

                    try {
                        $legendaryCommand = ([string]$LegendaryExePath).Trim()
                        if ([string]::IsNullOrWhiteSpace($legendaryCommand) -or -not (Test-Path -LiteralPath $legendaryCommand -PathType Leaf)) {
                            $cmd = Get-Command legendary -ErrorAction SilentlyContinue
                            if ($cmd -and $cmd.Source) {
                                $legendaryCommand = [string]$cmd.Source
                            }
                            else {
                                Write-Output "LOG:Legendary scan skipped: legendary.exe was not found in WMT data or PATH."
                                return
                            }
                        }

                        $pInfo = New-Object System.Diagnostics.ProcessStartInfo
                        $pInfo.FileName = $legendaryCommand
                        $pInfo.Arguments = "list-installed --check-updates --csv --show-dirs"
                        $pInfo.RedirectStandardOutput = $true
                        $pInfo.RedirectStandardError = $true
                        $pInfo.UseShellExecute = $false
                        $pInfo.CreateNoWindow = $true
                        $pInfo.StandardOutputEncoding = [System.Text.UTF8Encoding]::new($false)
                        $pInfo.StandardErrorEncoding = [System.Text.UTF8Encoding]::new($false)

                        $p = [System.Diagnostics.Process]::Start($pInfo)
                        $outTask = $p.StandardOutput.ReadToEndAsync()
                        $errTask = $p.StandardError.ReadToEndAsync()
                        if (-not $p.WaitForExit(90000)) {
                            Write-Output "LOG:Legendary scan timed out after 90 seconds."
                            try { $p.Kill() } catch {}
                            try { [void]$p.WaitForExit(2000) } catch {}
                            return
                        }

                        $out = $outTask.GetAwaiter().GetResult()
                        $err = $errTask.GetAwaiter().GetResult()
                        if ($p.ExitCode -ne 0) {
                            Write-Output "LOG:Legendary scan exited with code $($p.ExitCode)."
                            if (-not [string]::IsNullOrWhiteSpace($err)) {
                                foreach ($errLine in ($err -split "`r?`n")) {
                                    if (-not [string]::IsNullOrWhiteSpace($errLine)) { Write-Output "LOG:Legendary: $errLine" }
                                }
                            }
                        }

                        if ([string]::IsNullOrWhiteSpace($out)) {
                            if (-not [string]::IsNullOrWhiteSpace($err)) { Write-Output "LOG:Legendary returned no CSV output. Run 'legendary auth' if Epic login is not configured." }
                            return
                        }

                        $headerIndex = $out.IndexOf("App name,")
                        if ($headerIndex -gt 0) { $out = $out.Substring($headerIndex) }
                        $rows = @($out | ConvertFrom-Csv)
                        $installedCount = 0
                        $pendingCount = 0
                        foreach ($row in $rows) {
                            if (-not $row) { continue }
                            $appName = ([string]$row.'App name').Trim()
                            $title = ([string]$row.'App title').Trim()
                            $installedVersion = ([string]$row.'Installed version').Trim()
                            $availableVersion = ([string]$row.'Available version').Trim()
                            $updateFlag = ([string]$row.'Update available').Trim()
                            $installPath = ([string]$row.'Install path').Trim()
                            $platform = ([string]$row.Platform).Trim()
                            if ([string]::IsNullOrWhiteSpace($appName)) { continue }
                            $installedCount++
                            if ([string]::IsNullOrWhiteSpace($title)) { $title = $appName }
                            $hasUpdate = ($updateFlag -match '^(?i:true|yes|1)$')
                            if (-not $hasUpdate -and -not [string]::IsNullOrWhiteSpace($availableVersion) -and $availableVersion -ne $installedVersion) {
                                $hasUpdate = $true
                            }
                            if (-not $hasUpdate) { continue }
                            if (Test-Ignored $title $appName) { continue }
                            $pendingCount++
                            $installedVersionInfo = ConvertFrom-LegendaryBuildVersion -RawVersion $installedVersion
                            $availableVersionInfo = ConvertFrom-LegendaryBuildVersion -RawVersion $availableVersion
                            $displayInstalledVersion = if ([string]::IsNullOrWhiteSpace([string]$installedVersionInfo.Display)) { "?" } else { [string]$installedVersionInfo.Display }
                            $displayAvailableVersion = if ([string]::IsNullOrWhiteSpace([string]$availableVersionInfo.Display)) { "Update available" } else { [string]$availableVersionInfo.Display }
                            [PSCustomObject]@{
                                Source         = "legendary"
                                Name           = $title
                                Id             = $appName
                                Version        = $displayInstalledVersion
                                Available      = $displayAvailableVersion
                                VersionSort    = if ([string]::IsNullOrWhiteSpace([string]$installedVersionInfo.Sort)) { $displayInstalledVersion } else { [string]$installedVersionInfo.Sort }
                                AvailableSort  = if ([string]::IsNullOrWhiteSpace([string]$availableVersionInfo.Sort)) { $displayAvailableVersion } else { [string]$availableVersionInfo.Sort }
                                RawVersion     = $installedVersion
                                RawAvailable   = $availableVersion
                                InstallDir     = $installPath
                                ExecutablePath = $legendaryCommand
                                Platform       = $platform
                            }
                        }

                        if ($pendingCount -eq 0) {
                            Write-Output "LOG:Legendary scan found $installedCount installed Epic game(s), with no pending updates."
                        }
                        else {
                            Write-Output "LOG:Legendary scan found $pendingCount pending Epic game update(s)."
                        }
                    }
                    catch {
                        Write-Output "LOG:Legendary scan failed: $($_.Exception.Message)"
                    }
                }).AddArgument($ignoreList).AddArgument((Get-WmtLegendaryExePath))
            [void]$script:ActiveScans.Add([PSCustomObject]@{ PowerShell = $ps; AsyncResult = $ps.BeginInvoke() })
        }

        # J. GOGDL / GOG GAMES WORKER
        if ("gogdl" -in $enabled) {
            $ps = [PowerShell]::Create()
            [void]$ps.AddScript({
                    param($IgnoreList, $GogdlExePath)
                    [Console]::OutputEncoding = [System.Text.UTF8Encoding]::new($false)
                    Write-Output "LOG:Scanning installed GOG games with GOGDL metadata..."

                    function Test-Ignored($n, $i) {
                        if ($IgnoreList -and ($IgnoreList -contains $n -or $IgnoreList -contains $i)) { return $true }
                        return $false
                    }

                    function Get-WmtGogdlCommand {
                        param([string]$LocalPath)

                        $local = ([string]$LocalPath).Trim()
                        if (-not [string]::IsNullOrWhiteSpace($local) -and (Test-Path -LiteralPath $local -PathType Leaf)) {
                            return $local
                        }
                        foreach ($cmdName in @("gogdl", "gogdl.exe", "gogdl_windows_x86_64.exe")) {
                            try {
                                $cmd = Get-Command $cmdName -ErrorAction SilentlyContinue
                                if ($cmd -and $cmd.Source) { return [string]$cmd.Source }
                            }
                            catch {}
                        }
                        return ""
                    }

                    function Get-GogInstalledGames {
                        $items = New-Object System.Collections.Generic.List[object]
                        $seen = @{}
                        $registryRoots = @(
                            "HKLM:\SOFTWARE\WOW6432Node\GOG.com\Games",
                            "HKLM:\SOFTWARE\GOG.com\Games",
                            "HKCU:\SOFTWARE\GOG.com\Games",
                            "HKCU:\SOFTWARE\WOW6432Node\GOG.com\Games"
                        )

                        foreach ($root in $registryRoots) {
                            if (-not (Test-Path -LiteralPath $root)) { continue }
                            foreach ($key in @(Get-ChildItem -LiteralPath $root -ErrorAction SilentlyContinue)) {
                                try {
                                    $props = Get-ItemProperty -LiteralPath $key.PSPath -ErrorAction Stop
                                    $gameId = ([string]$props.gameID).Trim()
                                    if ([string]::IsNullOrWhiteSpace($gameId)) { $gameId = (Split-Path -Leaf $key.Name) }
                                    $installPath = ([string]$props.path).Trim()
                                    if ([string]::IsNullOrWhiteSpace($installPath) -and $props.PSObject.Properties["installPath"]) {
                                        $installPath = ([string]$props.installPath).Trim()
                                    }
                                    if ([string]::IsNullOrWhiteSpace($gameId) -or [string]::IsNullOrWhiteSpace($installPath)) { continue }
                                    $installPath = [Environment]::ExpandEnvironmentVariables($installPath)
                                    if (-not (Test-Path -LiteralPath $installPath -PathType Container)) { continue }
                                    $name = ([string]$props.gameName).Trim()
                                    if ([string]::IsNullOrWhiteSpace($name)) { $name = (Split-Path -Leaf $installPath) }
                                    $dedupeKey = "$gameId`n$installPath"
                                    if ($seen.ContainsKey($dedupeKey)) { continue }
                                    $seen[$dedupeKey] = $true
                                    [void]$items.Add([PSCustomObject]@{
                                            GameID      = $gameId
                                            Name        = $name
                                            InstallPath = $installPath
                                        })
                                }
                                catch {}
                            }
                        }

                        return $items.ToArray()
                    }

                    function Get-GogLocalMetadata {
                        param($Game)

                        $installPath = ([string]$Game.InstallPath).Trim()
                        $registryId = ([string]$Game.GameID).Trim()
                        $title = ([string]$Game.Name).Trim()
                        $platform = "windows"
                        $candidateDirs = @($installPath, (Join-Path $installPath "game"), (Join-Path $installPath "Contents\Resources"))
                        $infoObjects = New-Object System.Collections.Generic.List[object]

                        foreach ($dir in $candidateDirs) {
                            if (-not (Test-Path -LiteralPath $dir -PathType Container)) { continue }
                            foreach ($infoFile in @(Get-ChildItem -LiteralPath $dir -Filter "goggame-*.info" -File -ErrorAction SilentlyContinue)) {
                                try {
                                    $json = Get-Content -LiteralPath $infoFile.FullName -Raw -ErrorAction Stop | ConvertFrom-Json -ErrorAction Stop
                                    [void]$infoObjects.Add([PSCustomObject]@{ Json = $json; Directory = $dir; Path = $infoFile.FullName })
                                }
                                catch {}
                            }
                        }

                        $chosen = $null
                        foreach ($entry in @($infoObjects.ToArray())) {
                            $json = $entry.Json
                            $rootId = ([string]$json.rootGameId).Trim()
                            $gameId = ([string]$json.gameId).Trim()
                            if (-not [string]::IsNullOrWhiteSpace($registryId) -and ($registryId -eq $rootId -or $registryId -eq $gameId)) {
                                $chosen = $entry
                                break
                            }
                            if (-not [string]::IsNullOrWhiteSpace($rootId) -and $rootId -eq $gameId) {
                                $chosen = $entry
                            }
                        }
                        if (-not $chosen -and $infoObjects.Count -gt 0) { $chosen = $infoObjects[0] }

                        $gameId = $registryId
                        $buildId = ""
                        if ($chosen) {
                            $json = $chosen.Json
                            if (-not [string]::IsNullOrWhiteSpace([string]$json.rootGameId)) { $gameId = ([string]$json.rootGameId).Trim() }
                            elseif (-not [string]::IsNullOrWhiteSpace([string]$json.gameId)) { $gameId = ([string]$json.gameId).Trim() }
                            if (-not [string]::IsNullOrWhiteSpace([string]$json.name)) { $title = ([string]$json.name).Trim() }
                            if (-not [string]::IsNullOrWhiteSpace([string]$json.buildId)) { $buildId = ([string]$json.buildId).Trim() }

                            $idPath = Join-Path ([string]$chosen.Directory) ("goggame-{0}.id" -f $gameId)
                            if (-not (Test-Path -LiteralPath $idPath -PathType Leaf)) {
                                $idPath = [System.IO.Path]::ChangeExtension([string]$chosen.Path, ".id")
                            }
                            if (Test-Path -LiteralPath $idPath -PathType Leaf) {
                                try {
                                    $idText = (Get-Content -LiteralPath $idPath -Raw -ErrorAction Stop).Trim()
                                    if (-not [string]::IsNullOrWhiteSpace($idText)) {
                                        try {
                                            $idJson = $idText | ConvertFrom-Json -ErrorAction Stop
                                            if (-not [string]::IsNullOrWhiteSpace([string]$idJson.buildId)) {
                                                $buildId = ([string]$idJson.buildId).Trim()
                                            }
                                        }
                                        catch {
                                            if ($idText -match '^\d+$') { $buildId = $idText }
                                        }
                                    }
                                }
                                catch {}
                            }
                        }

                        return [PSCustomObject]@{
                            GameID      = $gameId
                            Name        = $title
                            InstallPath = $installPath
                            BuildID     = $buildId
                            Platform    = $platform
                        }
                    }

                    function Get-GogBuildCatalog {
                        param([string]$GameID)

                        if ([string]::IsNullOrWhiteSpace($GameID)) { return $null }
                        $escapedId = [uri]::EscapeDataString($GameID)
                        $url = "https://content-system.gog.com/products/$escapedId/os/windows/builds?generation=2"
                        $headers = @{ "User-Agent" = "GOGGalaxyCommunicationService/2.0.4.164 (Windows_32bit)" }
                        return Invoke-RestMethod -Uri $url -Headers $headers -UseBasicParsing -ErrorAction Stop
                    }

                    try {
                        $gogdlCommand = Get-WmtGogdlCommand -LocalPath $GogdlExePath
                        if ([string]::IsNullOrWhiteSpace($gogdlCommand)) {
                            Write-Output "LOG:GOGDL scan skipped: gogdl was not found in WMT data or PATH."
                            return
                        }

                        $games = @(Get-GogInstalledGames)
                        if ($games.Count -eq 0) {
                            Write-Output "LOG:GOGDL scan found no installed GOG games in the registry."
                            return
                        }

                        $pendingCount = 0
                        $checkedCount = 0
                        $missingMetadataCount = 0
                        foreach ($game in $games) {
                            $metadata = Get-GogLocalMetadata -Game $game
                            $gameId = ([string]$metadata.GameID).Trim()
                            $title = ([string]$metadata.Name).Trim()
                            $installPath = ([string]$metadata.InstallPath).Trim()
                            $installedBuild = ([string]$metadata.BuildID).Trim()
                            if ([string]::IsNullOrWhiteSpace($title)) { $title = $gameId }
                            if ([string]::IsNullOrWhiteSpace($gameId) -or [string]::IsNullOrWhiteSpace($installedBuild)) {
                                $missingMetadataCount++
                                continue
                            }

                            $catalog = $null
                            try {
                                $catalog = Get-GogBuildCatalog -GameID $gameId
                            }
                            catch {
                                Write-Output "LOG:GOGDL could not query latest build for $title ($gameId): $($_.Exception.Message)"
                                continue
                            }

                            $items = @($catalog.items)
                            if ($items.Count -eq 0) { continue }
                            $checkedCount++
                            $latest = $items[0]
                            $latestBuild = ([string]$latest.build_id).Trim()
                            if ([string]::IsNullOrWhiteSpace($latestBuild)) { continue }
                            if ($installedBuild -eq $latestBuild) { continue }
                            if (Test-Ignored $title $gameId) { continue }

                            $installedVersionName = ""
                            foreach ($build in $items) {
                                if (([string]$build.build_id).Trim() -eq $installedBuild) {
                                    $installedVersionName = ([string]$build.version_name).Trim()
                                    break
                                }
                            }
                            $pendingCount++
                            $displayInstalled = if ([string]::IsNullOrWhiteSpace($installedVersionName)) { $installedBuild } else { $installedVersionName }
                            $displayLatest = if ([string]::IsNullOrWhiteSpace([string]$latest.version_name)) { $latestBuild } else { ([string]$latest.version_name).Trim() }
                            [PSCustomObject]@{
                                Source         = "gogdl"
                                Name           = $title
                                Id             = $gameId
                                Version        = $displayInstalled
                                Available      = $displayLatest
                                VersionSort    = $installedBuild
                                AvailableSort  = $latestBuild
                                InstallDir     = $installPath
                                ExecutablePath = $gogdlCommand
                                Platform       = "windows"
                            }
                        }

                        if ($pendingCount -eq 0) {
                            Write-Output "LOG:GOGDL scan checked $checkedCount installed GOG game(s), with no pending updates."
                        }
                        else {
                            Write-Output "LOG:GOGDL scan found $pendingCount pending GOG game update(s)."
                        }
                        if ($missingMetadataCount -gt 0) {
                            Write-Output "LOG:GOGDL skipped $missingMetadataCount GOG game(s) without local goggame build metadata."
                        }
                    }
                    catch {
                        Write-Output "LOG:GOGDL scan failed: $($_.Exception.Message)"
                    }
                }).AddArgument($ignoreList).AddArgument((Get-WmtGogdlExePath))
            [void]$script:ActiveScans.Add([PSCustomObject]@{ PowerShell = $ps; AsyncResult = $ps.BeginInvoke() })
        }

        # K. STEAM WORKER
        if ("steam" -in $enabled) {
            $ps = [PowerShell]::Create()
            [void]$ps.AddScript({
                    param($IgnoreList)
                    Write-Output "LOG:Scanning Steam game manifests..."

                    function Add-UniqueSteamPath {
                        param(
                            [System.Collections.Generic.List[string]]$Paths,
                            [string]$Path
                        )

                        if ([string]::IsNullOrWhiteSpace($Path)) { return }
                        $rawPathText = ([string]$Path).Trim()
                        $expanded = [Environment]::ExpandEnvironmentVariables($rawPathText)
                        $expanded = $expanded -replace '/', '\'
                        $expanded = $expanded -replace '\\\\', '\'
                        try {
                            $full = [System.IO.Path]::GetFullPath($expanded)
                            if ((Test-Path -LiteralPath $full) -and -not $Paths.Contains($full)) {
                                [void]$Paths.Add($full)
                            }
                        }
                        catch {}
                    }

                    function ConvertFrom-SteamVdfPath {
                        param([string]$Value)
                        if ([string]::IsNullOrWhiteSpace($Value)) { return "" }
                        $path = ([string]$Value).Trim()
                        $path = $path -replace '\\\\', '\'
                        $path = $path -replace '/', '\'
                        return [Environment]::ExpandEnvironmentVariables($path)
                    }

                    function Get-SteamManifestValue {
                        param(
                            [string]$Text,
                            [string]$Key
                        )

                        if ([string]::IsNullOrWhiteSpace($Text) -or [string]::IsNullOrWhiteSpace($Key)) { return "" }
                        $pattern = '"' + [regex]::Escape($Key) + '"\s+"([^"]*)"'
                        $match = [regex]::Match($Text, $pattern)
                        if ($match.Success) { return [string]$match.Groups[1].Value }
                        return ""
                    }

                    function Get-SteamManifestNumber {
                        param(
                            [string]$Text,
                            [string]$Key
                        )

                        $value = Get-SteamManifestValue -Text $Text -Key $Key
                        $number = [long]0
                        if ([long]::TryParse(([string]$value), [ref]$number)) { return $number }
                        return [long]0
                    }

                    function Get-SteamInstallRoots {
                        $paths = [System.Collections.Generic.List[string]]::new()
                        $registryPaths = @(
                            "HKCU:\Software\Valve\Steam",
                            "HKLM:\SOFTWARE\WOW6432Node\Valve\Steam",
                            "HKLM:\SOFTWARE\Valve\Steam"
                        )

                        foreach ($registryPath in $registryPaths) {
                            try {
                                $props = Get-ItemProperty -LiteralPath $registryPath -ErrorAction Stop
                                foreach ($propName in @("SteamPath", "InstallPath")) {
                                    if ($props.PSObject.Properties[$propName]) {
                                        Add-UniqueSteamPath -Paths $paths -Path ([string]$props.$propName)
                                    }
                                }
                                if ($props.PSObject.Properties["SteamExe"] -and -not [string]::IsNullOrWhiteSpace([string]$props.SteamExe)) {
                                    Add-UniqueSteamPath -Paths $paths -Path (Split-Path -Parent ([string]$props.SteamExe))
                                }
                            }
                            catch {}
                        }

                        foreach ($candidate in @(
                                "${env:ProgramFiles(x86)}\Steam",
                                "${env:ProgramFiles}\Steam",
                                "${env:SystemDrive}\Steam",
                                "${env:SystemDrive}\steamcmd"
                            )) {
                            Add-UniqueSteamPath -Paths $paths -Path $candidate
                        }

                        foreach ($cmdName in @("steamcmd", "steamcmd.exe")) {
                            try {
                                $cmd = Get-Command $cmdName -ErrorAction SilentlyContinue
                                if ($cmd -and $cmd.Source) {
                                    Add-UniqueSteamPath -Paths $paths -Path (Split-Path -Parent ([string]$cmd.Source))
                                }
                            }
                            catch {}
                        }

                        return $paths.ToArray()
                    }

                    function Get-SteamLibraryRoots {
                        $paths = [System.Collections.Generic.List[string]]::new()
                        foreach ($root in @(Get-SteamInstallRoots)) {
                            if ([string]::IsNullOrWhiteSpace($root)) { continue }
                            if (Test-Path -LiteralPath (Join-Path $root "steamapps")) {
                                Add-UniqueSteamPath -Paths $paths -Path $root
                            }

                            $libraryFile = Join-Path $root "steamapps\libraryfolders.vdf"
                            if (-not (Test-Path -LiteralPath $libraryFile)) { continue }

                            $libraryText = Get-Content -LiteralPath $libraryFile -Raw -ErrorAction SilentlyContinue
                            if ([string]::IsNullOrWhiteSpace($libraryText)) { continue }

                            foreach ($match in [regex]::Matches($libraryText, '"path"\s+"([^"]+)"')) {
                                Add-UniqueSteamPath -Paths $paths -Path (ConvertFrom-SteamVdfPath $match.Groups[1].Value)
                            }
                            foreach ($match in [regex]::Matches($libraryText, '"\d+"\s+"([^"]+)"')) {
                                $candidate = ConvertFrom-SteamVdfPath $match.Groups[1].Value
                                if ($candidate -match '^[A-Za-z]:\\|^\\\\') {
                                    Add-UniqueSteamPath -Paths $paths -Path $candidate
                                }
                            }
                        }

                        return $paths.ToArray()
                    }

                    $seenAppIds = @{}
                    $manifestCount = 0
                    $pendingCount = 0

                    try {
                        $libraryRoots = @(Get-SteamLibraryRoots)
                        if ($libraryRoots.Count -eq 0) {
                            Write-Output "LOG:Steam scan skipped: no Steam library folders were found."
                            return
                        }

                        foreach ($libraryRoot in $libraryRoots) {
                            $steamApps = Join-Path $libraryRoot "steamapps"
                            if (-not (Test-Path -LiteralPath $steamApps)) { continue }

                            foreach ($manifest in @(Get-ChildItem -LiteralPath $steamApps -Filter "appmanifest_*.acf" -File -ErrorAction SilentlyContinue)) {
                                $manifestCount++
                                $text = Get-Content -LiteralPath $manifest.FullName -Raw -ErrorAction SilentlyContinue
                                if ([string]::IsNullOrWhiteSpace($text)) { continue }

                                $appId = Get-SteamManifestValue -Text $text -Key "appid"
                                if ([string]::IsNullOrWhiteSpace($appId)) {
                                    $appId = [regex]::Match($manifest.BaseName, '\d+').Value
                                }
                                if ([string]::IsNullOrWhiteSpace($appId)) { continue }
                                if ($seenAppIds.ContainsKey($appId)) { continue }
                                $seenAppIds[$appId] = $true

                                $name = Get-SteamManifestValue -Text $text -Key "name"
                                if ([string]::IsNullOrWhiteSpace($name)) { $name = "Steam App $appId" }
                                if ($IgnoreList -and ($IgnoreList -contains $name -or $IgnoreList -contains $appId)) { continue }

                                $stateFlags = Get-SteamManifestNumber -Text $text -Key "StateFlags"
                                $bytesToDownload = Get-SteamManifestNumber -Text $text -Key "BytesToDownload"
                                $bytesDownloaded = Get-SteamManifestNumber -Text $text -Key "BytesDownloaded"
                                $bytesToStage = Get-SteamManifestNumber -Text $text -Key "BytesToStage"
                                $bytesStaged = Get-SteamManifestNumber -Text $text -Key "BytesStaged"
                                $buildId = Get-SteamManifestValue -Text $text -Key "buildid"
                                $targetBuildId = Get-SteamManifestValue -Text $text -Key "TargetBuildID"
                                $installDir = ConvertFrom-SteamVdfPath (Get-SteamManifestValue -Text $text -Key "installdir")

                                $downloadRemaining = [Math]::Max([long]0, $bytesToDownload - $bytesDownloaded)
                                $stageRemaining = [Math]::Max([long]0, $bytesToStage - $bytesStaged)
                                $hasTargetBuild = (-not [string]::IsNullOrWhiteSpace($targetBuildId) -and $targetBuildId -ne "0" -and $targetBuildId -ne $buildId)
                                $needsAttention = (
                                    ($stateFlags -ne 0 -and $stateFlags -ne 4) -or
                                    $downloadRemaining -gt 0 -or
                                    $stageRemaining -gt 0 -or
                                    $hasTargetBuild
                                )

                                if (-not $needsAttention) { continue }

                                $pendingCount++
                                $versionText = if (-not [string]::IsNullOrWhiteSpace($buildId) -and $buildId -ne "0") { "Build $buildId" } else { "State $stateFlags" }
                                $availableText = "Steam pending"
                                if ($hasTargetBuild) {
                                    $availableText = "Build $targetBuildId"
                                }
                                elseif ($downloadRemaining -gt 0) {
                                    $availableText = "{0:N1} MB pending" -f ($downloadRemaining / 1MB)
                                }
                                elseif ($stageRemaining -gt 0) {
                                    $availableText = "{0:N1} MB staging" -f ($stageRemaining / 1MB)
                                }
                                elseif ($stateFlags -ne 4) {
                                    $availableText = "State $stateFlags"
                                }

                                [PSCustomObject]@{
                                    Source       = "steam"
                                    Name         = $name
                                    Id           = $appId
                                    Version      = $versionText
                                    Available    = $availableText
                                    LibraryPath  = $libraryRoot
                                    InstallDir   = $installDir
                                    ManifestPath = $manifest.FullName
                                }
                            }
                        }

                        if ($pendingCount -eq 0) {
                            Write-Output "LOG:Steam scan found $manifestCount installed Steam app manifest(s), with no manifest-marked pending updates."
                        }
                        else {
                            Write-Output "LOG:Steam scan found $pendingCount manifest-marked pending Steam update(s)."
                        }
                    }
                    catch {
                        Write-Output "LOG:Steam scan failed: $($_.Exception.Message)"
                    }
                }).AddArgument($ignoreList)
            [void]$script:ActiveScans.Add([PSCustomObject]@{ PowerShell = $ps; AsyncResult = $ps.BeginInvoke() })
        }
    
        # --- Start the result collection timer (already defined earlier in script) ---
        $script:ScanTimer.Start()
    })

# --- IGNORE SELECTED ---
if (-not $btnWingetIgnore) { $btnWingetIgnore = Get-Ctrl "btnWingetIgnore" }
$btnWingetIgnore.Add_Click({
        $selected = @($lstWinget.SelectedItems)
        if ($selected.Count -eq 0) { return }

        $msg = "Ignore $($selected.Count) package(s)?`n`nThese updates will be hidden from future scans."
        if ((Show-WmtMessageBox -Message $msg -Title "Ignore Updates" -Button YesNo -Image Question) -eq [System.Windows.MessageBoxResult]::Yes) {
        
            # 1. Get fresh settings
            $settings = Get-WmtSettings
        
            # 2. Create a fresh ArrayList to ensure it is editable
            $newList = New-Object System.Collections.ArrayList
        
            # Add existing items (checking for nulls)
            if ($settings.WingetIgnore) {
                foreach ($existing in $settings.WingetIgnore) {
                    if (-not [string]::IsNullOrWhiteSpace($existing)) {
                        [void]$newList.Add($existing.ToString())
                    }
                }
            }

            # 3. Add NEW items
            foreach ($item in $selected) {
                $id = $item.Id
                # Avoid duplicates
                if ($id -and ($id -notin $newList)) {
                    [void]$newList.Add($id)
                }
                # Remove from GUI immediately
                $lstWinget.Items.Remove($item)
            }

            # 4. Save back as a standard array
            $settings.WingetIgnore = $newList.ToArray()
            Save-WmtSettings -Settings $settings
        
            Write-GuiLog "Ignored $($selected.Count) packages. Saved to settings.json."
        }
    })

# --- MANAGE IGNORED (UNIGNORE) ---
if (-not $btnWingetUnignore) { $btnWingetUnignore = Get-Ctrl "btnWingetUnignore" }
$btnWingetUnignore.Add_Click({
        $jsonPath = Join-Path (Get-DataPath) "settings.json"
        $listItems = @()

        if (Test-Path $jsonPath) {
            try {
                $json = Get-Content $jsonPath -Raw | ConvertFrom-Json
                if ($json.WingetIgnore) { $listItems = @($json.WingetIgnore) | ForEach-Object { "$_".Trim() } | Where-Object { $_ -ne "" } }
            }
            catch { Write-GuiLog "Error: $($_.Exception.Message)" }
        }

        if ($listItems.Count -eq 0) {
            Show-WmtMessageBox -Message "No ignored packages found." -Title "Manage Ignored" -Image Information | Out-Null
            return
        }

        $content = @"
    <Grid Margin="16">
        <Grid.RowDefinitions><RowDefinition Height="Auto"/><RowDefinition Height="*"/><RowDefinition Height="Auto"/></Grid.RowDefinitions>
        <TextBlock Text="Select packages to restore" Foreground="{DynamicResource TextSecondary}" Margin="0,0,0,10"/>
        <ListBox Name="lbIgnored" Grid.Row="1" SelectionMode="Extended"/>
        <StackPanel Grid.Row="2" Orientation="Horizontal" HorizontalAlignment="Right" Margin="0,12,0,0">
            <Button Name="btnRestore" Content="Un-ignore Selected" MinWidth="142" Background="{DynamicResource Success}" Foreground="{DynamicResource SuccessText}" Margin="0,0,8,0"/>
            <Button Name="btnClose" Content="Close" Width="92" IsCancel="True"/>
        </StackPanel>
    </Grid>
"@
        $dialog = New-WmtWindowFromXaml -Title "Manage Ignored Updates" -ContentXaml $content -Width 520 -Height 420 -MinWidth 440 -MinHeight 340
        $lb = $dialog.FindName("lbIgnored")
        $btnRestore = $dialog.FindName("btnRestore")
        $btnClose = $dialog.FindName("btnClose")
        foreach ($item in $listItems) { [void]$lb.Items.Add($item) }
        $refreshNeeded = @{ Value = $false }

        $btnRestore.Add_Click({
                $selected = @($lb.SelectedItems)
                if ($selected.Count -eq 0) { return }
                $s = Get-WmtSettings
                $current = [System.Collections.ArrayList]@($s.WingetIgnore)
                foreach ($item in $selected) {
                    if ($current.Contains($item)) { $current.Remove($item) }
                    $lb.Items.Remove($item)
                }
                $s.WingetIgnore = $current.ToArray()
                Save-WmtSettings -Settings $s
                $refreshNeeded.Value = $true
            }.GetNewClosure())
        $btnClose.Add_Click({ $dialog.Close() }.GetNewClosure())
        $dialog.ShowDialog() | Out-Null

        if ($refreshNeeded.Value) {
            Write-GuiLog "List updated. Refreshing..."
            $btnWingetScan.RaiseEvent((New-Object System.Windows.RoutedEventArgs([System.Windows.Controls.Button]::ClickEvent)))
        }
    })
# --- LISTVIEW SORTING LOGIC ---
$lstWinget = Get-Ctrl "lstWinget"

function Test-WmtUpdateListActionableItem {
    param([object]$Item)

    if (-not $Item) { return $false }
    $source = ([string]$Item.Source).Trim()
    $name = ([string]$Item.Name).Trim()
    $id = ([string]$Item.Id).Trim()

    if ([string]::IsNullOrWhiteSpace($source)) { return $false }
    if ($name -in @("No results found", "No updates available")) { return $false }
    if ([string]::IsNullOrWhiteSpace($name) -and [string]::IsNullOrWhiteSpace($id)) { return $false }

    return $true
}

function Set-WmtUpdateListItemCheckState {
    param(
        [object]$Item,
        [bool]$DefaultChecked = $false
    )

    if (-not $Item) { return $Item }
    $checked = if (Test-WmtUpdateListActionableItem -Item $Item) { [bool]$DefaultChecked } else { $false }
    if ($checked -and $Item.PSObject.Properties["WUIsOptional"] -and [bool]$Item.WUIsOptional) { $checked = $false }

    if (-not $Item.PSObject.Properties["IsChecked"]) {
        try { $Item | Add-Member -MemberType NoteProperty -Name "IsChecked" -Value $checked -Force } catch {}
    }
    elseif ($null -eq $Item.IsChecked) {
        try { $Item.IsChecked = $checked } catch {}
    }

    return $Item
}

function Get-WmtUpdateListCheckedItems {
    param(
        [System.Windows.Controls.ListView]$ListView = $lstWinget,
        [switch]$FallbackToSelection
    )

    if (-not $ListView) { return @() }

    try {
        $checked = [System.Collections.Generic.List[object]]::new()
        $itemCount = [int]$ListView.Items.Count
        for ($i = 0; $i -lt $itemCount; $i++) {
            $item = $null
            try { $item = $ListView.Items.GetItemAt($i) } catch { continue }
            if (-not (Test-WmtUpdateListActionableItem -Item $item)) { continue }
            if (-not $item.PSObject.Properties["IsChecked"]) { continue }
            if ([bool]$item.IsChecked) { [void]$checked.Add($item) }
        }

        if ($checked.Count -eq 0 -and $FallbackToSelection) {
            $selectedCount = [int]$ListView.SelectedItems.Count
            for ($i = 0; $i -lt $selectedCount; $i++) {
                $item = $null
                try { $item = $ListView.SelectedItems[$i] } catch { continue }
                if (Test-WmtUpdateListActionableItem -Item $item) { [void]$checked.Add($item) }
            }
        }

        return $checked.ToArray()
    }
    catch {
        Write-GuiLog "ERROR: Could not read checked update rows: $($_.Exception.Message)"
        return @()
    }
}

function Set-WmtUpdateListCheckedState {
    param(
        [object[]]$Items,
        [bool]$IsChecked
    )

    foreach ($item in @($Items)) {
        if (-not $item) { continue }
        if (-not (Test-WmtUpdateListActionableItem -Item $item)) { continue }
        [void](Set-WmtUpdateListItemCheckState -Item $item -DefaultChecked:$IsChecked)
        try { $item.IsChecked = $IsChecked } catch {}
    }
    try { if ($lstWinget) { $lstWinget.Items.Refresh() } } catch {}
}

function Measure-WmtUpdateListTextScore {
    param([object]$Text)

    if ($null -eq $Text) { return 0.0 }
    $s = [string]$Text
    if ([string]::IsNullOrEmpty($s)) { return 0.0 }

    $score = 0.0
    foreach ($ch in $s.ToCharArray()) {
        $c = [string]$ch
        if ($c -match '\s') { $score += 0.35 }
        elseif ("ilI1.,:;|![]()".IndexOf($c) -ge 0) { $score += 0.35 }
        elseif ("MW@#%&".IndexOf($c) -ge 0) { $score += 1.25 }
        elseif ($c -cmatch '[A-Z0-9]') { $score += 0.90 }
        else { $score += 0.72 }
    }

    return [Math]::Min(140.0, [Math]::Ceiling($score))
}

function Get-WmtUpdateListPropertyText {
    param(
        [object]$Item,
        [string]$PropertyName
    )

    if ($null -eq $Item -or [string]::IsNullOrWhiteSpace($PropertyName)) { return "" }
    if ($Item.PSObject.Properties[$PropertyName]) { return [string]$Item.$PropertyName }
    return ""
}

function Set-WmtUpdateListSmartColumnWidths {
    param([System.Windows.Controls.ListView]$ListView = $lstWinget)

    if (-not $ListView -or -not $ListView.View -or -not ($ListView.View -is [System.Windows.Controls.GridView])) { return }
    $grid = [System.Windows.Controls.GridView]$ListView.View
    if (-not $grid.Columns -or $grid.Columns.Count -lt 6) { return }

    # There should only be six real update columns. If a stale/extra GridViewColumn ever survives
    # a patch merge, collapse it so it cannot look like an unused seventh column.
    if ($grid.Columns.Count -gt 6) {
        for ($i = 6; $i -lt $grid.Columns.Count; $i++) {
            try { $grid.Columns[$i].Width = 0.0 } catch {}
        }
    }

    $available = 0.0
    try {
        $viewer = Get-WmtVisualDescendant -Element $ListView -DescendantType ([System.Windows.Controls.ScrollViewer])
        if ($viewer -and -not [double]::IsNaN([double]$viewer.ViewportWidth) -and [double]$viewer.ViewportWidth -gt 150) {
            # ViewportWidth already excludes the vertical scrollbar, so using it prevents the
            # right-side blank GridView filler from being mistaken for another column.
            $available = [double]$viewer.ViewportWidth
        }
    }
    catch {}

    if ($available -le 150) {
        try { $available = [double]$ListView.ActualWidth - 4.0 } catch {}
    }
    if ($available -le 150) {
        try { $available = [double]$ListView.RenderSize.Width - 4.0 } catch {}
    }
    if ($available -le 150) { return }
    $available = [Math]::Max(420.0, [Math]::Floor($available) - 2.0)

    $specs = @(
        [PSCustomObject]@{ Index = 0; Header = "Select"; Property = "IsChecked"; Min = 64.0; Char = 0.0; Grow = 0.0; Fixed = $true },
        [PSCustomObject]@{ Index = 1; Header = "Source"; Property = "Source"; Min = 82.0; Char = 7.0; Grow = 0.35; Fixed = $false },
        [PSCustomObject]@{ Index = 2; Header = "Package Name"; Property = "Name"; Min = 210.0; Char = 7.0; Grow = 5.00; Fixed = $false },
        [PSCustomObject]@{ Index = 3; Header = "ID"; Property = "Id"; Min = 170.0; Char = 6.7; Grow = 3.50; Fixed = $false },
        [PSCustomObject]@{ Index = 4; Header = "Installed"; Property = "Version"; Min = 100.0; Char = 6.8; Grow = 0.85; Fixed = $false },
        [PSCustomObject]@{ Index = 5; Header = "Latest"; Property = "Available"; Min = 100.0; Char = 6.8; Grow = 0.85; Fixed = $false }
    )

    $scores = @{}
    foreach ($spec in $specs) {
        $scores[[int]$spec.Index] = Measure-WmtUpdateListTextScore $spec.Header
    }

    $sampled = 0
    foreach ($item in @($ListView.Items)) {
        if ($sampled -ge 600) { break }
        $sampled++
        foreach ($spec in $specs) {
            if ([bool]$spec.Fixed) { continue }
            $score = Measure-WmtUpdateListTextScore (Get-WmtUpdateListPropertyText -Item $item -PropertyName $spec.Property)
            if ($score -gt $scores[[int]$spec.Index]) { $scores[[int]$spec.Index] = $score }
        }
    }

    $widths = @{}
    foreach ($spec in $specs) {
        if ([bool]$spec.Fixed) {
            $widths[[int]$spec.Index] = [double]$spec.Min
            continue
        }
        $desired = ([double]$scores[[int]$spec.Index] * [double]$spec.Char) + 30.0
        $widths[[int]$spec.Index] = [Math]::Max([double]$spec.Min, [Math]::Ceiling($desired))
    }

    $total = 0.0
    foreach ($spec in $specs) { $total += [double]$widths[[int]$spec.Index] }

    if ($total -lt $available) {
        $extra = $available - $total
        $growTotal = 0.0
        foreach ($spec in $specs) { if (-not [bool]$spec.Fixed) { $growTotal += [double]$spec.Grow } }
        if ($growTotal -gt 0) {
            foreach ($spec in $specs) {
                if ([bool]$spec.Fixed) { continue }
                $widths[[int]$spec.Index] = [double]$widths[[int]$spec.Index] + ($extra * ([double]$spec.Grow / $growTotal))
            }
        }
    }
    elseif ($total -gt $available) {
        $overflow = $total - $available
        $shrinkRoom = 0.0
        foreach ($spec in $specs) {
            if ([bool]$spec.Fixed) { continue }
            $shrinkRoom += [Math]::Max(0.0, ([double]$widths[[int]$spec.Index] - [double]$spec.Min))
        }
        if ($shrinkRoom -gt 0) {
            foreach ($spec in $specs) {
                if ([bool]$spec.Fixed) { continue }
                $room = [Math]::Max(0.0, ([double]$widths[[int]$spec.Index] - [double]$spec.Min))
                $reduce = [Math]::Min($room, $overflow * ($room / $shrinkRoom))
                $widths[[int]$spec.Index] = [double]$widths[[int]$spec.Index] - $reduce
            }
        }
    }

    $roundedTotal = 0.0
    foreach ($spec in $specs) {
        $idx = [int]$spec.Index
        $newWidth = [Math]::Max([double]$spec.Min, [Math]::Floor([double]$widths[$idx]))
        $grid.Columns[$idx].Width = $newWidth
        $roundedTotal += $newWidth
    }

    $remainder = [Math]::Floor($available - $roundedTotal)
    if ($remainder -gt 0 -and $grid.Columns.Count -gt 2) {
        # Use the name column as the final elastic column so the GridView fills the card cleanly
        # instead of leaving a blank right-side filler that looks like an unused column.
        $grid.Columns[2].Width = [double]$grid.Columns[2].Width + $remainder
    }
    elseif ($remainder -lt -1 -and $grid.Columns.Count -gt 2) {
        # Last-pixel correction for DPI/rounding: trim the elastic name column before WPF creates
        # a horizontal scroll area or visually separates a phantom filler column.
        $trim = [Math]::Min([Math]::Abs($remainder), [Math]::Max(0.0, [double]$grid.Columns[2].Width - 210.0))
        if ($trim -gt 0) { $grid.Columns[2].Width = [double]$grid.Columns[2].Width - $trim }
    }
}

function Request-WmtUpdateListSmartColumnResize {
    param([System.Windows.Controls.ListView]$ListView = $lstWinget)

    if (-not $ListView) { return }
    $targetListView = $ListView
    try {
        $resizeAction = {
            Set-WmtUpdateListSmartColumnWidths -ListView $targetListView
        }.GetNewClosure()
        [void]$targetListView.Dispatcher.BeginInvoke([Action]$resizeAction, [System.Windows.Threading.DispatcherPriority]::Background)
    }
    catch {
        try { Set-WmtUpdateListSmartColumnWidths -ListView $targetListView } catch {}
    }
}

$script:WingetSortChain = New-Object System.Collections.ArrayList
$script:GridSortAscendingGlyph = [string][char]0x25B2
$script:GridSortDescendingGlyph = [string][char]0x25BC

function Get-CleanHeader {
    param([object]$Header)
    if ($null -eq $Header) { return "" }
    return ([regex]::Replace([string]$Header, '\s+(?:[\u25B2\u25BC]|\u00E2\u2013[\u00B2\u00BC])$', '')).Trim()
}

function Get-GridViewColumnHeaderFromSource {
    param([object]$OriginalSource)
    if (-not $OriginalSource) { return $null }
    if ($OriginalSource -is [System.Windows.Controls.GridViewColumnHeader]) { return $OriginalSource }
    return Get-WmtVisualAncestor -Element $OriginalSource -AncestorType ([System.Windows.Controls.GridViewColumnHeader])
}

function Update-GridViewHeaders {
    param([System.Windows.Controls.ListView]$ListView, [string]$ActiveHeader, [bool]$Ascending)
    if (-not $ListView -or -not $ListView.View -or -not ($ListView.View -is [System.Windows.Controls.GridView])) { return }
    foreach ($col in $ListView.View.Columns) {
        $clean = Get-CleanHeader $col.Header
        if ($clean -eq $ActiveHeader) {
            $glyph = if ($Ascending) { $script:GridSortAscendingGlyph } else { $script:GridSortDescendingGlyph }
            $col.Header = "$clean $glyph"
        }
        else {
            $col.Header = $clean
        }
    }
}

function Set-SortChainPrimary {
    param(
        [System.Collections.ArrayList]$Chain,
        [string]$PropertyName
    )
    if ($null -eq $Chain -or [string]::IsNullOrWhiteSpace($PropertyName)) { return $false }

    $existingIndex = -1
    for ($i = 0; $i -lt $Chain.Count; $i++) {
        if ($Chain[$i].Property -eq $PropertyName) { $existingIndex = $i; break }
    }

    if ($existingIndex -eq 0) {
        $Chain[0].Descending = -not [bool]$Chain[0].Descending
        return [bool](-not $Chain[0].Descending)
    }

    if ($existingIndex -gt 0) { $Chain.RemoveAt($existingIndex) }
    $entry = [PSCustomObject]@{ Property = $PropertyName; Descending = $false }
    $Chain.Insert(0, $entry)
    return $true
}

function Get-WmtNaturalSortKey {
    param([object]$Value)

    if ($null -eq $Value) { return "" }
    $text = ([string]$Value).Trim().ToLowerInvariant()
    if ([string]::IsNullOrWhiteSpace($text)) { return "" }

    return [regex]::Replace($text, '\d+', {
            param($Match)
            $Match.Value.PadLeft(20, '0')
        })
}

function Get-WmtListSortValue {
    param(
        [object]$Item,
        [string]$PropertyName
    )

    if ($null -eq $Item -or [string]::IsNullOrWhiteSpace($PropertyName)) { return "" }

    $value = $null
    if ($Item.PSObject.Properties[$PropertyName]) {
        $value = $Item.$PropertyName
    }
    elseif ($PropertyName -eq "VersionSort" -and $Item.PSObject.Properties["Version"]) {
        $value = $Item.Version
    }
    elseif ($PropertyName -eq "AvailableSort" -and $Item.PSObject.Properties["Available"]) {
        $value = $Item.Available
    }

    return Get-WmtNaturalSortKey $value
}

function Set-ListViewSort {
    param(
        [System.Windows.Controls.ListView]$ListView,
        [System.Collections.ArrayList]$Chain
    )
    if (-not $ListView -or $null -eq $Chain -or $Chain.Count -eq 0) { return }
    if ($ListView.Items.Count -eq 0) { return }

    if ($ListView.ItemsSource) {
        try {
            $ListView.Items.SortDescriptions.Clear()
            foreach ($rule in $Chain) {
                if ([string]::IsNullOrWhiteSpace([string]$rule.Property)) { continue }
                $direction = if ([bool]$rule.Descending) {
                    [System.ComponentModel.ListSortDirection]::Descending
                }
                else {
                    [System.ComponentModel.ListSortDirection]::Ascending
                }
                $description = [System.ComponentModel.SortDescription]::new([string]$rule.Property, $direction)
                [void]$ListView.Items.SortDescriptions.Add($description)
            }
            $ListView.Items.Refresh()
            return
        }
        catch {
            try { $ListView.Items.SortDescriptions.Clear() } catch {}
        }
    }

    $items = @($ListView.Items)
    if ($items.Count -eq 0) { return }
    $sortSpec = foreach ($rule in $Chain) {
        $propertyName = [string]$rule.Property
        if (-not [string]::IsNullOrWhiteSpace($propertyName)) {
            $propertyNameForClosure = $propertyName
            @{
                Expression = { Get-WmtListSortValue -Item $_ -PropertyName $propertyNameForClosure }.GetNewClosure()
                Descending = [bool]$rule.Descending
            }
        }
    }
    if (-not $sortSpec -or $sortSpec.Count -eq 0) { return }

    $selectedItems = @($ListView.SelectedItems)
    $sorted = $items | Sort-Object -Property $sortSpec
    try { $ListView.Items.SortDescriptions.Clear() } catch {}
    $ListView.Items.Clear()
    foreach ($item in $sorted) {
        [void]$ListView.Items.Add($item)
        if ($selectedItems -contains $item) {
            try { $ListView.SelectedItems.Add($item) } catch {}
        }
    }
}

function Resolve-WingetSortProperty {
    param([string]$Header)
    switch ($Header) {
        "Select" { return "IsChecked" }
        "Package Name" { return "Name" }
        "Installed" { return "VersionSort" }
        "Latest" { return "AvailableSort" }
        default { return $Header }
    }
}

if ($lstWinget) {
    $wingetSortHandler = [System.Windows.RoutedEventHandler] {
        param($src, $e)
        $columnHeader = Get-GridViewColumnHeaderFromSource -OriginalSource $e.OriginalSource
        if (-not $columnHeader -or -not $columnHeader.Column) { return }
        $header = Get-CleanHeader $columnHeader.Column.Header
        if ([string]::IsNullOrWhiteSpace($header)) { return }

        $propName = Resolve-WingetSortProperty $header
        if ([string]::IsNullOrWhiteSpace($propName)) { return }

        $isAscending = Set-SortChainPrimary -Chain $script:WingetSortChain -PropertyName $propName
        Update-GridViewHeaders -ListView $lstWinget -ActiveHeader $header -Ascending:$isAscending
        Set-ListViewSort -ListView $lstWinget -Chain $script:WingetSortChain
    }
    $lstWinget.AddHandler([System.Windows.Controls.Primitives.ButtonBase]::ClickEvent, $wingetSortHandler, $true)
    $lstWinget.Add_Loaded({ Request-WmtUpdateListSmartColumnResize -ListView $lstWinget })
    $lstWinget.Add_SizeChanged({ Request-WmtUpdateListSmartColumnResize -ListView $lstWinget })
    Request-WmtUpdateListSmartColumnResize -ListView $lstWinget
}

# --- Library list column sorting ---
$script:LibrarySortChain = New-Object System.Collections.ArrayList

function Resolve-LibrarySortProperty {
    param([string]$Header)
    switch ($Header) {
        "Source" { return "Source" }
        "Name" { return "Name" }
        "ID" { return "Id" }
        "Installed" { return "Version" }
        "Latest" { return "Available" }
        default { return $Header }
    }
}

if ($lstLibrary) {
    $librarySortHandler = [System.Windows.RoutedEventHandler] {
        param($src, $e)
        $columnHeader = Get-GridViewColumnHeaderFromSource -OriginalSource $e.OriginalSource
        if (-not $columnHeader -or -not $columnHeader.Column) { return }
        $header = Get-CleanHeader $columnHeader.Column.Header
        if ([string]::IsNullOrWhiteSpace($header)) { return }

        $propName = Resolve-LibrarySortProperty $header
        if ([string]::IsNullOrWhiteSpace($propName)) { return }

        $isAscending = Set-SortChainPrimary -Chain $script:LibrarySortChain -PropertyName $propName
        Update-GridViewHeaders -ListView $lstLibrary -ActiveHeader $header -Ascending:$isAscending
        Set-ListViewSort -ListView $lstLibrary -Chain $script:LibrarySortChain
    }
    $lstLibrary.AddHandler([System.Windows.Controls.Primitives.ButtonBase]::ClickEvent, $librarySortHandler, $true)
}

# ---------------------------------------------------------
# HIGH-PERFORMANCE THREADED SEARCH
# ---------------------------------------------------------

# 1. SETUP UI TIMER (Handles the Thread Callback)
$script:SearchTimer = New-Object System.Windows.Threading.DispatcherTimer
$script:SearchTimer.Interval = [TimeSpan]::FromMilliseconds(100)
$script:AsyncSearch = $null
$script:AsyncPowerShell = $null
$script:WmtPackageSearchActive = $false
$script:WmtPackageSearchStartedAt = $null
$script:WmtPackageSearchTimeoutSeconds = 300

$script:SearchTimer.Add_Tick({
        if ($script:AsyncSearch -and
            -not $script:AsyncSearch.IsCompleted -and
            $script:WmtPackageSearchStartedAt -and
            ((Get-Date) - $script:WmtPackageSearchStartedAt).TotalSeconds -ge $script:WmtPackageSearchTimeoutSeconds) {
            $script:SearchTimer.Stop()
            Write-GuiLog "Package search timed out after $($script:WmtPackageSearchTimeoutSeconds) seconds and was cancelled."
            try { $null = $script:AsyncPowerShell.BeginStop($null, $null) } catch {}

            $lblWingetStatus.Text = "Search timed out"
            $lblWingetStatus.Visibility = "Visible"
            $btnWingetFind.IsEnabled = $true
            $txtWingetSearch.IsEnabled = $true
            # Don't add a placeholder row — the status label already shows
            # "Search timed out" above the list.
            if ($lstWinget.Items.Count -gt 0) {
                Request-WmtUpdateListSmartColumnResize -ListView $lstWinget
            }

            $script:AsyncSearch = $null
            $script:AsyncPowerShell = $null
            $script:WmtPackageSearchStartedAt = $null
            return
        }

        # Check if the thread has finished
        if ($script:AsyncSearch -and $script:AsyncSearch.IsCompleted) {
            $script:SearchTimer.Stop()
        
            try {
                # Get Results from the Thread
                $results = $script:AsyncPowerShell.EndInvoke($script:AsyncSearch)
                $script:AsyncPowerShell.Dispose()
            
                foreach ($item in $results) {
                    # Handle Log Messages vs Result Objects
                    if ($item -is [string] -and $item.StartsWith("LOG:")) {
                        Write-GuiLog ($item.Substring(4))
                    }
                    elseif ($item.PSObject.Properties["Name"]) {
                        [void](Set-WmtUpdateListItemCheckState -Item $item -DefaultChecked:$false)
                        [void]$lstWinget.Items.Add($item)
                    }
                }
            }
            catch {
                Write-GuiLog "Thread Error: $($_.Exception.Message)"
            }

            # UI Cleanup
            $lblWingetStatus.Visibility = "Hidden"
            $btnWingetFind.IsEnabled = $true
            $txtWingetSearch.IsEnabled = $true
            $lblWingetStatus.Text = "Ready"
        
            if ($lstWinget.Items.Count -eq 0) {
                $lblWingetStatus.Text = "No results found"
                $lblWingetStatus.Visibility = "Visible"
                Write-GuiLog "Search Complete. No results found."
            }
            else {
                Request-WmtUpdateListSmartColumnResize -ListView $lstWinget
                Write-GuiLog "Search Complete. Found $($lstWinget.Items.Count) results."
            }
            $script:WmtPackageSearchActive = $true
        
            $script:AsyncSearch = $null
            $script:AsyncPowerShell = $null
            $script:WmtPackageSearchStartedAt = $null
        }
    })

# 2. THE BUTTON CLICK (Starts the Thread)
$btnWingetFind.Add_Click({
        if (Test-WmtUpdateScanEngineBusy) {
            Write-GuiLog "Package search skipped because an update scan or package action is already running."
            return
        }
        if ([string]::IsNullOrWhiteSpace($txtWingetSearch.Text) -or $txtWingetSearch.Text -in @("Search packages...", "Search new packages...")) { return }

        # UI Prep
        $script:WmtPackageSearchActive = $true
        $query = $txtWingetSearch.Text
        $lblWingetTitle.Text = "Search Results: $query"
        $lblWingetStatus.Text = "Searching..."; $lblWingetStatus.Visibility = "Visible"
        $btnWingetUpdateSel.Visibility = "Collapsed"
        if ($btnWingetUpdateAll) { $btnWingetUpdateAll.Visibility = "Collapsed" }
        $btnWingetInstall.Visibility = "Visible"
        $lstWinget.Items.Clear()
        $btnWingetFind.IsEnabled = $false 
    
        Write-GuiLog " "
        Write-GuiLog "Starting Search: '$query'"

        # Get Settings
        $settings = Get-WmtSettings
        
        $enabled = if ($settings.EnabledProviders -and $settings.EnabledProviders.Count -gt 0) { 
            $settings.EnabledProviders 
        }
        else { 
            @("winget", "msstore", "windowsupdate", "pip", "npm", "pnpm", "dotnet", "psmodule", "composer", "chocolatey", "scoop", "gem", "cargo", "steam", "legendary", "gogdl")
        }

        # Respect per-provider Search toggle: providers with Search=false are
        # skipped during package search (but still scanned for updates).
        # This is computed here (main scope) because Get-WmtProviderToggles
        # is not available inside the runspace.
        $allToggles = Get-WmtProviderToggles -Settings $settings
        $searchEnabled = @()
        foreach ($prov in @($enabled)) {
            $t = $null
            if ($allToggles -is [System.Collections.IDictionary] -and $allToggles.Contains($prov)) {
                $t = $allToggles[$prov]
            }
            $searchOn = $false
            if ($t) {
                if ($t -is [System.Collections.IDictionary]) {
                    if ($t.Contains("Search")) { $searchOn = [bool]$t["Search"] }
                }
                else {
                    try { if ($t.PSObject.Properties["Search"]) { $searchOn = [bool]$t.Search } } catch {}
                }
            }
            if ($searchOn) { $searchEnabled += $prov }
        }
        $enabled = $searchEnabled

        Write-GuiLog "Search-enabled providers: $($enabled -join ', ')"

        # Resolve library cache file paths for the runspace (Get-DataPath is
        # not available inside the runspace).
        $dataPath = Get-DataPath
        $legendaryCacheFile = Join-Path $dataPath "legendary_library.json"
        $gogCacheFile = Join-Path $dataPath "gog_library.json"

        # Kick off PyPI index cache refresh if pip is search-enabled and the
        # cache is missing or stale. The search runspace reads from the cache.
        # PyPI Simple API: https://pypi.org/simple/ with Accept header
        # application/vnd.pypi.simple.v1+json returns a JSON index of all
        # package names. We cache this locally and fuzzy-search it.
        $pypiIndexFile = Join-Path $dataPath "pypi_index.json"
        if ("pip" -in $enabled) {
            $needPypiIndex = $false
            $fileExists = (Test-Path -LiteralPath $pypiIndexFile -PathType Leaf)
            $isStale = $false
            if ($fileExists) {
                try {
                    $age = (Get-Date) - (Get-Item -LiteralPath $pypiIndexFile).LastWriteTime
                    if ($age.TotalHours -ge 24) { $isStale = $true }
                }
                catch {}
            }
            $needPypiIndex = (-not $fileExists) -or $isStale
            if ($needPypiIndex) {
                Write-GuiLog "Fetching PyPI package index in background..."
                $pypiPs = [PowerShell]::Create()
                [void]$pypiPs.AddScript({
                        param($CacheFile)
                        try {
                            try { [Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12 } catch {}
                            $headers = @{
                                "Accept"     = "application/vnd.pypi.simple.v1+json"
                                "User-Agent" = "Windows-Maintenance-Tool"
                            }
                            $resp = Invoke-RestMethod -Uri "https://pypi.org/simple/" -Headers $headers -UseBasicParsing -TimeoutSec 120 -ErrorAction Stop
                            if ($resp -and $resp.projects) {
                                # Extract just the package names to keep the cache small.
                                $names = @($resp.projects | ForEach-Object { [string]$_.name })
                                $names | ConvertTo-Json -Depth 1 | Set-Content -LiteralPath $CacheFile -Force -Encoding UTF8
                                Write-Output "LOG:PyPI index cached: $($names.Count) packages."
                            }
                        }
                        catch {
                            Write-Output "LOG:PyPI index fetch failed: $($_.Exception.Message)"
                        }
                    }).AddArgument($pypiIndexFile)
                try { [void]$pypiPs.BeginInvoke() } catch { try { $pypiPs.Dispose() } catch {} }
            }
        }

        # Kick off background library cache refresh for Legendary/GOGDL if
        # the cache files are missing. This runs in a separate runspace so
        # the UI does not hang. The search runspace below will read from
        # the cache files; if they are not ready yet on the first search,
        # it logs a message and the user can search again shortly after.
        # The runspace scriptBlock is self-contained (inline logic) because
        # main-scope functions are NOT available in [PowerShell]::Create().
        $needLegCache = ("legendary" -in $enabled -and -not (Test-Path -LiteralPath $legendaryCacheFile -PathType Leaf))
        $needGogCache = ("gogdl" -in $enabled -and -not (Test-Path -LiteralPath $gogCacheFile -PathType Leaf))
        if ($needLegCache -or $needGogCache) {
            Write-GuiLog "Fetching game libraries in background (Legendary/GOGDL)..."
            # Resolve paths in main scope.
            $legExe = Get-WmtLegendaryExePath
            if ([string]::IsNullOrWhiteSpace($legExe) -or -not (Test-Path -LiteralPath $legExe -PathType Leaf)) {
                try {
                    $cmd = Get-Command legendary -ErrorAction SilentlyContinue
                    if ($cmd -and $cmd.Source) { $legExe = [string]$cmd.Source }
                }
                catch {}
            }
            $gogAuth = Get-WmtGogdlAuthConfigPath
            if ([string]::IsNullOrWhiteSpace($gogAuth) -or -not (Test-Path -LiteralPath $gogAuth -PathType Leaf)) {
                $heroicAuth = Join-Path $env:APPDATA "heroic\gog_store\auth.json"
                if (Test-Path -LiteralPath $heroicAuth -PathType Leaf) { $gogAuth = $heroicAuth }
            }
            $cachePs = [PowerShell]::Create()
            [void]$cachePs.AddScript({
                    param($DoLeg, $DoGog, $LegendaryExe, $LegCacheFile, $GogAuthPath, $GogCacheFile)

                    if ($DoLeg) {
                        try {
                            $result = New-Object System.Collections.Generic.List[object]
                            if ($LegendaryExe -and (Test-Path -LiteralPath $LegendaryExe -PathType Leaf)) {
                                $psi = New-Object System.Diagnostics.ProcessStartInfo
                                $psi.FileName = $LegendaryExe
                                $psi.Arguments = "list --json"
                                $psi.RedirectStandardOutput = $true
                                $psi.RedirectStandardError = $true
                                $psi.UseShellExecute = $false
                                $psi.CreateNoWindow = $true
                                $proc = [System.Diagnostics.Process]::Start($psi)
                                $stdout = $proc.StandardOutput.ReadToEnd()
                                try { $proc.WaitForExit(30000) } catch {}
                                try { if (-not $proc.HasExited) { $proc.Kill() } } catch {}
                                $parsed = $false
                                if (-not $parsed -and -not [string]::IsNullOrWhiteSpace($stdout)) {
                                    try {
                                        $json = $stdout | ConvertFrom-Json -ErrorAction Stop
                                        if ($json) {
                                            foreach ($game in @($json)) {
                                                $title = [string]$game.app_title
                                                if ([string]::IsNullOrWhiteSpace($title)) { $title = [string]$game.title }
                                                if ([string]::IsNullOrWhiteSpace($title)) { continue }
                                                $isInstalled = $false
                                                try { if ($game.PSObject.Properties["is_installed"]) { $isInstalled = [bool]$game.is_installed } } catch {}
                                                $installedVer = ""
                                                $latestVer = [string]$game.app_version
                                                if ($isInstalled) {
                                                    try { if ($game.PSObject.Properties["version"]) { $installedVer = [string]$game.version } } catch {}
                                                    if ([string]::IsNullOrWhiteSpace($installedVer)) { $installedVer = $latestVer }
                                                }
                                                $result.Add([PSCustomObject]@{ Provider = "legendary"; Title = $title; Id = [string]$game.app_name; Version = $latestVer; InstalledVersion = $installedVer; IsInstalled = $isInstalled; Source = "legendary"; Kind = "Library" })
                                            }
                                            if ($result.Count -gt 0) { $parsed = $true }
                                        }
                                    }
                                    catch {}
                                }
                                if (-not $parsed) {
                                    $regex = [regex]'\*+\s*(?<title>.+?)\s*\(\s*App(?:\s+name)?\s*:\s*(?<app>[^,)]+?)\s*(?:,\s*Version\s*:\s*(?<version>[^,)]+?))?\s*(?:,\s*[^)]*)?\)'
                                    foreach ($match in $regex.Matches($stdout)) {
                                        $title = $match.Groups["title"].Value.Trim()
                                        if ([string]::IsNullOrWhiteSpace($title)) { continue }
                                        $ver = if ($match.Groups["version"].Success) { $match.Groups["version"].Value.Trim() } else { "" }
                                        $result.Add([PSCustomObject]@{ Provider = "legendary"; Title = $title; Id = $match.Groups["app"].Value.Trim(); Version = $ver; Source = "legendary"; Kind = "Library" })
                                    }
                                }
                            }
                            $result.ToArray() | ConvertTo-Json -Depth 3 | Set-Content -LiteralPath $LegCacheFile -Force -Encoding UTF8
                        }
                        catch {}
                    }

                    if ($DoGog) {
                        try {
                            $result = New-Object System.Collections.Generic.List[object]
                            if ($GogAuthPath -and (Test-Path -LiteralPath $GogAuthPath -PathType Leaf)) {
                                $text = [System.IO.File]::ReadAllText($GogAuthPath).TrimStart([char]0xFEFF)
                                $json = $text | ConvertFrom-Json -ErrorAction Stop
                                $gogClientId = "46899977096215655"
                                $creds = $null
                                $clientProp = $json.PSObject.Properties[$gogClientId]
                                if ($clientProp) { $creds = $clientProp.Value }
                                elseif (-not [string]::IsNullOrWhiteSpace([string]$json.access_token)) { $creds = $json }
                                if ($creds -and -not [string]::IsNullOrWhiteSpace([string]$creds.access_token)) {
                                    try { [Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12 } catch {}
                                    $token = [string]$creds.access_token
                                    $headers = @{ "Authorization" = "Bearer $token"; "User-Agent" = "Windows-Maintenance-Tool" }
                                    $page = 1
                                    $totalPages = 1
                                    while ($page -le $totalPages -and $page -le 50) {
                                        $url = "https://embed.gog.com/account/getFilteredProducts?mediaType=1&page=$page"
                                        $resp = Invoke-RestMethod -Uri $url -Headers $headers -UseBasicParsing -TimeoutSec 20 -ErrorAction Stop
                                        if (-not $resp) { break }
                                        if ($resp.totalPages) { $totalPages = [int]$resp.totalPages }
                                        if ($resp.products) {
                                            foreach ($prod in @($resp.products)) {
                                                $title = [string]$prod.title
                                                if ([string]::IsNullOrWhiteSpace($title)) { continue }
                                                $result.Add([PSCustomObject]@{ Provider = "gogdl"; Title = $title; Id = [string]$prod.id; Version = [string]$prod.version; Source = "gogdl"; Kind = "Library" })
                                            }
                                        }
                                        $page++
                                    }
                                }
                            }
                            $result.ToArray() | ConvertTo-Json -Depth 3 | Set-Content -LiteralPath $GogCacheFile -Force -Encoding UTF8
                        }
                        catch {}
                    }
                }).AddArgument($needLegCache).AddArgument($needGogCache).AddArgument($legExe).AddArgument($legendaryCacheFile).AddArgument($gogAuth).AddArgument($gogCacheFile)
            try { [void]$cachePs.BeginInvoke() } catch { try { $cachePs.Dispose() } catch {} }
        }

        # Reset Task List
        $script:ActiveScans.Clear()
        # 3. DEFINE THE WORKER THREAD SCRIPT
        # This contains the EXACT logic that worked for you before.
        $scriptBlock = {
            param($Query, $Enabled, $LegendaryCacheFile, $GogCacheFile, $PypiIndexFile)
        
            [Console]::OutputEncoding = [System.Text.UTF8Encoding]::new($false)
            function Log($msg) { Write-Output "LOG:$msg" }

            function Invoke-WmtPackageSearchProcess {
                param(
                    [string]$FileName,
                    [string]$Arguments,
                    [int]$TimeoutSeconds = 60,
                    [switch]$Utf8Output
                )

                $pInfo = New-Object System.Diagnostics.ProcessStartInfo
                $pInfo.FileName = $FileName
                $pInfo.Arguments = $Arguments
                $pInfo.RedirectStandardOutput = $true
                $pInfo.RedirectStandardError = $true
                $pInfo.UseShellExecute = $false
                $pInfo.CreateNoWindow = $true
                if ($Utf8Output) {
                    $pInfo.StandardOutputEncoding = [System.Text.UTF8Encoding]::new($false)
                    $pInfo.StandardErrorEncoding = [System.Text.UTF8Encoding]::new($false)
                }

                $process = New-Object System.Diagnostics.Process
                $process.StartInfo = $pInfo
                try {
                    if (-not $process.Start()) { throw "Could not start $FileName." }
                    $outputTask = $process.StandardOutput.ReadToEndAsync()
                    $errorTask = $process.StandardError.ReadToEndAsync()
                    if (-not $process.WaitForExit($TimeoutSeconds * 1000)) {
                        try {
                            $taskkill = Join-Path $env:SystemRoot "System32\taskkill.exe"
                            & $taskkill /PID $process.Id /T /F 2>$null | Out-Null
                        }
                        catch {
                            try { $process.Kill() } catch {}
                        }
                        throw "$FileName search timed out after $TimeoutSeconds seconds."
                    }
                    $process.WaitForExit()
                    return [PSCustomObject]@{
                        Output   = $outputTask.Result
                        Error    = $errorTask.Result
                        ExitCode = $process.ExitCode
                    }
                }
                finally {
                    $process.Dispose()
                }
            }

            # --- A. WINGET & MSSTORE ---
            if ("winget" -in $Enabled -or "msstore" -in $Enabled) {
                Log "Searching Winget & Store..."
            
                $sourceFlag = ""
                if ("winget" -in $Enabled -and "msstore" -notin $Enabled) { $sourceFlag = "--source winget" }
                elseif ("winget" -notin $Enabled -and "msstore" -in $Enabled) { $sourceFlag = "--source msstore" }
                $defaultSource = if ("winget" -notin $Enabled -and "msstore" -in $Enabled) { "msstore" } else { "winget" }
            
                $cleanQuery = $Query.Replace('"', '')

                try {
                    $result = Invoke-WmtPackageSearchProcess -FileName "winget" -Arguments "search --query `"$cleanQuery`" $sourceFlag --accept-source-agreements" -Utf8Output
                    $out = $result.Output

                    if (-not [string]::IsNullOrWhiteSpace($out)) {
                        $lines = $out -split "`r`n"
                    
                        foreach ($line in $lines) {
                            $line = $line.Trim()
                        
                            # Skip dividers, headers, and empty lines
                            if ([string]::IsNullOrWhiteSpace($line)) { continue }
                            if ($line -match "^-+$" -or $line -match "^Name\s+Id" -or $line -match "^-{3,}") { continue } 
                            if ($line -match "Windows Package Manager" -or $line -match "Copyright" -or $line -match "usage:" -or $line -match "No package found") { continue }
                            if ($line -eq "-") { continue }

                            # Split by 2 OR MORE spaces (\s{2,}). 
                            # This perfectly separates columns without breaking names that have 1 space!
                            $parts = @($line -split '\s{2,}' | ForEach-Object { ([string]$_).Trim() } | Where-Object { $_ -ne "" })
                            $headerTokens = @("name", "id", "version", "match", "source")
                            $nonDividerParts = @($parts | Where-Object { $_ -notmatch "^-+$" })
                            if ($nonDividerParts.Count -eq 0) { continue }
                            if (@($nonDividerParts | Where-Object { $headerTokens -notcontains $_.ToLowerInvariant() }).Count -eq 0) { continue }

                            $len = $parts.Count

                            $n = $null; $i = $null; $v = $null; $s = $defaultSource

                            if ($len -ge 5) {
                                # Layout: Name | Id | Version | Match | Source
                                $n = $parts[0].Trim()
                                $i = $parts[1].Trim()
                                $v = $parts[2].Trim()
                                $s = $parts[4].Trim()
                            }
                            elseif ($len -eq 4) {
                                # Layout: Name | Id | Version | Source (Match column is empty)
                                $n = $parts[0].Trim()
                                $i = $parts[1].Trim()
                                $v = $parts[2].Trim()
                                $s = $parts[3].Trim()
                            }
                            elseif ($len -eq 3) {
                                # Layout: Name | Id | Version (Source is hidden)
                                $n = $parts[0].Trim()
                                $i = $parts[1].Trim()
                                $v = $parts[2].Trim()
                            }

                            if ($n -and $i -and $i.Length -gt 2) {
                                # Final header checks just in case
                                $nText = ([string]$n).Trim()
                                $iText = ([string]$i).Trim()
                                $vText = ([string]$v).Trim()
                                if ($nText -eq "-" -or $nText.ToLowerInvariant() -eq "name") { continue }
                                if ($iText -eq "-" -or $headerTokens -contains $iText.ToLowerInvariant()) { continue }
                                if ($vText -eq "-" -or $headerTokens -contains $vText.ToLowerInvariant()) { continue }

                                if ($s -eq "msstore") { $s = "msstore" } else { $s = "winget" }
                                if ($v -eq "Unknown") { $v = "?" }
                            
                                # Available is hardcoded to "-" since searches don't show updates
                                [PSCustomObject]@{ Source = $s; Name = $n; Id = $i; Version = $v; Available = "-" }
                            }
                        }
                    }
                }
                catch { Log "Winget Error: $_" }
            }

            # --- B. NPM ---
            if ("npm" -in $Enabled) {
                Log "Searching NPM..."
                try {
                    $result = Invoke-WmtPackageSearchProcess -FileName "cmd" -Arguments "/c npm search `"$Query`" --json"
                    $json = $result.Output
                    if ($json.Contains("[")) {
                        $json = $json.Substring($json.IndexOf("[")); $pkgs = $json | ConvertFrom-Json
                        foreach ($pkg in $pkgs) { 
                            [PSCustomObject]@{ Source = "npm"; Name = $pkg.name; Id = $pkg.name; Version = $pkg.version; Available = "-" } 
                        }
                    }
                }
                catch { Log "Npm skipped." }
            }

            # --- C. CHOCO ---
            if ("chocolatey" -in $Enabled) {
                Log "Searching Chocolatey..."
                try {
                    $result = Invoke-WmtPackageSearchProcess -FileName "choco" -Arguments "search `"$Query`" -r"
                    $out = $result.Output
                    $lines = $out -split "`r`n"
                    foreach ($line in $lines) {
                        if ([string]::IsNullOrWhiteSpace($line)) { continue }
                        $parts = $line -split "\|"
                        if ($parts.Count -ge 2) {
                            [PSCustomObject]@{ Source = "chocolatey"; Name = $parts[0]; Id = $parts[0]; Version = $parts[1]; Available = "-" }
                        }
                    }
                }
                catch { Log "Choco skipped." }
            }

            # --- D. .NET TOOLS ---
            if ("dotnet" -in $Enabled) {
                Log "Searching .NET tools..."
                try {
                    $result = Invoke-WmtPackageSearchProcess -FileName "dotnet" -Arguments "tool search `"$Query`" --take 40"
                    $out = $result.Output
                    foreach ($line in ($out -split "`r?`n")) {
                        $trimmed = ([string]$line).Trim()
                        if ([string]::IsNullOrWhiteSpace($trimmed)) { continue }
                        if ($trimmed -match "(?i)^Package\s+ID\s+Version" -or $trimmed -match "^-+") { continue }
                        $parts = @($trimmed -split "\s+" | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
                        if ($parts.Count -ge 2) {
                            [PSCustomObject]@{ Source = "dotnet"; Name = [string]$parts[0]; Id = [string]$parts[0]; Version = [string]$parts[1]; Available = "-" }
                        }
                    }
                }
                catch { Log ".NET tools skipped." }
            }

            # --- E. POWERSHELL MODULES ---
            if ("psmodule" -in $Enabled) {
                Log "Searching PowerShell modules..."
                try {
                    if (Get-Command Find-Module -ErrorAction SilentlyContinue) {
                        $mods = @(Find-Module -Name "*$Query*" -Repository PSGallery -ErrorAction SilentlyContinue | Select-Object -First 40)
                        foreach ($mod in $mods) {
                            [PSCustomObject]@{ Source = "psmodule"; Name = $mod.Name; Id = $mod.Name; Version = [string]$mod.Version; Available = "-" }
                        }
                    }
                }
                catch { Log "PowerShell modules skipped." }
            }

            # --- F. COMPOSER ---
            if ("composer" -in $Enabled) {
                Log "Searching Composer..."
                try {
                    $result = Invoke-WmtPackageSearchProcess -FileName "cmd" -Arguments "/c composer search `"$Query`" --format=json 2>nul"
                    $json = $result.Output
                    $json = $json.Trim()
                    if ($json.StartsWith("[")) {
                        $pkgs = $json | ConvertFrom-Json
                        foreach ($pkg in $pkgs) {
                            $name = if ($pkg.PSObject.Properties["name"]) { [string]$pkg.name } else { "" }
                            if (-not [string]::IsNullOrWhiteSpace($name)) {
                                [PSCustomObject]@{ Source = "composer"; Name = $name; Id = $name; Version = "?"; Available = "-" }
                            }
                        }
                    }
                    else {
                        foreach ($line in ($json -split "`r?`n")) {
                            $trimmed = ([string]$line).Trim()
                            if ([string]::IsNullOrWhiteSpace($trimmed)) { continue }
                            $name = @($trimmed -split "\s+" | Where-Object { $_ })[0]
                            if (-not [string]::IsNullOrWhiteSpace($name)) {
                                [PSCustomObject]@{ Source = "composer"; Name = $name; Id = $name; Version = "?"; Available = "-" }
                            }
                        }
                    }
                }
                catch { Log "Composer skipped." }
            }

            # --- M. PIP (PyPI via cached simple index) ---
            if ("pip" -in $Enabled) {
                Log "Searching PyPI (cached index)..."
                try {
                    if ($PypiIndexFile -and (Test-Path -LiteralPath $PypiIndexFile -PathType Leaf)) {
                        $indexText = [System.IO.File]::ReadAllText($PypiIndexFile)
                        $index = $indexText | ConvertFrom-Json -ErrorAction Stop
                        if ($index) {
                            $needle = $Query.ToLowerInvariant()
                            $count = 0
                            foreach ($pkgName in @($index)) {
                                $name = [string]$pkgName
                                if ([string]::IsNullOrWhiteSpace($name)) { continue }
                                if ($name.ToLowerInvariant().Contains($needle)) {
                                    [PSCustomObject]@{ Source = "pip"; Name = $name; Id = $name; Version = "-"; Available = "-" }
                                    $count++
                                    if ($count -ge 100) { break }
                                }
                            }
                        }
                    }
                    else {
                        Log "PyPI index cache not found. It is fetched in the background on first search."
                    }
                }
                catch { Log "Pip search skipped: $($_.Exception.Message)" }
            }

            # --- G. SCOOP ---
            if ("scoop" -in $Enabled) {
                Log "Searching Scoop..."
                try {
                    $result = Invoke-WmtPackageSearchProcess -FileName "powershell.exe" -Arguments "-NoProfile -Command scoop search `"$Query`"" -TimeoutSeconds 30
                    $out = $result.Output
                    $inResults = $false
                    foreach ($line in ($out -split "`r?`n")) {
                        $trimmed = ([string]$line).Trim()
                        if ($trimmed -match "^Name\s") { $inResults = $true; continue }
                        if (-not $inResults) { continue }
                        if ($trimmed -match "^-+") { continue }
                        if ([string]::IsNullOrWhiteSpace($trimmed)) { continue }
                        $parts = @($trimmed -split '\s{2,}|     ' | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
                        if ($parts.Count -ge 2) {
                            [PSCustomObject]@{ Source = "scoop"; Name = [string]$parts[0]; Id = [string]$parts[0]; Version = [string]$parts[1]; Available = "-" }
                        }
                    }
                }
                catch { Log "Scoop skipped." }
            }

            # --- H. CARGO ---
            if ("cargo" -in $Enabled) {
                Log "Searching Cargo crates..."
                try {
                    $result = Invoke-WmtPackageSearchProcess -FileName "cargo" -Arguments "search `"$Query`"" -TimeoutSeconds 30
                    $out = $result.Output
                    foreach ($line in ($out -split "`r?`n")) {
                        $trimmed = ([string]$line).Trim()
                        if ($trimmed -match '^(?<name>\S+)\s*=\s*"(?<version>[^"]*)"') {
                            [PSCustomObject]@{ Source = "cargo"; Name = $matches["name"]; Id = $matches["name"]; Version = $matches["version"]; Available = "-" }
                        }
                    }
                }
                catch { Log "Cargo skipped." }
            }

            # --- I. RUBYGEMS ---
            if ("gem" -in $Enabled) {
                Log "Searching RubyGems..."
                try {
                    $result = Invoke-WmtPackageSearchProcess -FileName "gem" -Arguments "search `"$Query`" --remote" -TimeoutSeconds 30
                    $out = $result.Output
                    foreach ($line in ($out -split "`r?`n")) {
                        $trimmed = ([string]$line).Trim()
                        if ($trimmed -match '^(?<name>\S+)\s+\((?<version>[^)]+)\)') {
                            [PSCustomObject]@{ Source = "gem"; Name = $matches["name"]; Id = $matches["name"]; Version = $matches["version"]; Available = "-" }
                        }
                    }
                }
                catch { Log "RubyGems skipped." }
            }

            # --- J. STEAM STORE ---
            if ("steam" -in $Enabled) {
                Log "Searching Steam Store..."
                try {
                    try { [Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12 } catch {}
                    $encoded = [Uri]::EscapeDataString($Query)
                    $url = "https://store.steampowered.com/api/storesearch/?term=$encoded&l=english&cc=US"
                    $resp = Invoke-RestMethod -Uri $url -UseBasicParsing -TimeoutSec 20 -ErrorAction Stop
                    if ($resp -and $resp.total -gt 0) {
                        foreach ($item in @($resp.items)) {
                            [PSCustomObject]@{ Source = "steam"; Name = [string]$item.name; Id = [string]$item.id; Version = "-"; Available = "-" }
                        }
                    }
                }
                catch { Log "Steam Store skipped." }
            }

            # --- K. LEGENDARY (Epic Games library) ---
            if ("legendary" -in $Enabled) {
                Log "Searching Legendary library..."
                try {
                    if ($LegendaryCacheFile -and (Test-Path -LiteralPath $LegendaryCacheFile -PathType Leaf)) {
                        $cacheText = [System.IO.File]::ReadAllText($LegendaryCacheFile)
                        $library = $cacheText | ConvertFrom-Json -ErrorAction Stop
                        if ($library) {
                            $needle = $Query.ToLowerInvariant()
                            foreach ($game in @($library)) {
                                $title = [string]$game.Title
                                if ([string]::IsNullOrWhiteSpace($title)) { continue }
                                if ([string]::IsNullOrWhiteSpace($needle) -or $title.ToLowerInvariant().Contains($needle)) {
                                    # Show installed version in Version column, latest in Available.
                                    $isInst = $false
                                    try { if ($game.PSObject.Properties["IsInstalled"]) { $isInst = [bool]$game.IsInstalled } } catch {}
                                    $instVer = ""
                                    try { if ($game.PSObject.Properties["InstalledVersion"]) { $instVer = [string]$game.InstalledVersion } } catch {}
                                    $latestVer = [string]$game.Version
                                    $verCol = if ($isInst -and -not [string]::IsNullOrWhiteSpace($instVer)) { $instVer } else { "-" }
                                    $availCol = if (-not [string]::IsNullOrWhiteSpace($latestVer)) { $latestVer } else { "-" }
                                    [PSCustomObject]@{ Source = "legendary"; Name = $title; Id = [string]$game.Id; Version = $verCol; Available = $availCol }
                                }
                            }
                        }
                    }
                    else {
                        Log "Legendary library cache not found. Open Providers panel to populate."
                    }
                }
                catch { Log "Legendary library skipped: $($_.Exception.Message)" }
            }

            # --- L. GOGDL (GOG library) ---
            if ("gogdl" -in $Enabled) {
                Log "Searching GOG library..."
                try {
                    if ($GogCacheFile -and (Test-Path -LiteralPath $GogCacheFile -PathType Leaf)) {
                        $cacheText = [System.IO.File]::ReadAllText($GogCacheFile)
                        $library = $cacheText | ConvertFrom-Json -ErrorAction Stop
                        if ($library) {
                            $needle = $Query.ToLowerInvariant()
                            foreach ($game in @($library)) {
                                $title = [string]$game.Title
                                if ([string]::IsNullOrWhiteSpace($title)) { continue }
                                if ([string]::IsNullOrWhiteSpace($needle) -or $title.ToLowerInvariant().Contains($needle)) {
                                    [PSCustomObject]@{ Source = "gogdl"; Name = $title; Id = [string]$game.Id; Version = [string]$game.Version; Available = "-" }
                                }
                            }
                        }
                    }
                    else {
                        Log "GOG library cache not found. Open Providers panel to populate."
                    }
                }
                catch { Log "GOG library skipped: $($_.Exception.Message)" }
            }
        }

        # 4. EXECUTE THREAD (The Magic Part)
        $script:AsyncPowerShell = [PowerShell]::Create().AddScript($scriptBlock).AddArgument($query).AddArgument($enabled).AddArgument($legendaryCacheFile).AddArgument($gogCacheFile).AddArgument($pypiIndexFile)
        $script:AsyncSearch = $script:AsyncPowerShell.BeginInvoke()
        $script:WmtPackageSearchStartedAt = Get-Date
        $script:SearchTimer.Start()
    })

function Test-WingetRestartRiskItem {
    param($Item)
    if (-not $Item) { return $false }
    $id = [string]$Item.Id
    $name = [string]$Item.Name
    $eaIdPattern = '(?i)(ElectronicArts|EA\.Desktop|EADesktop|EAapp)'
    $eaNamePattern = '(?i)\b(EA app|Electronic Arts|EA Desktop)\b'
    return ($id -match $eaIdPattern -or $name -match $eaNamePattern)
}

function Show-WingetRestartRiskWarning {
    param(
        [object[]]$Items,
        [string]$Action = "Update"
    )
    if ($Action -ne "Update") { return $true }
    $risky = @($Items | Where-Object { Test-WingetRestartRiskItem $_ })
    if ($risky.Count -eq 0) { return $true }

    $pkgNames = @($risky | ForEach-Object {
            if ([string]::IsNullOrWhiteSpace([string]$_.Name)) { [string]$_.Id } else { [string]$_.Name }
        } | Select-Object -Unique)
    $joined = ($pkgNames -join ", ")
    if ([string]::IsNullOrWhiteSpace($joined)) { $joined = "the selected EA package" }

    $msg = "Warning: Updating $joined may trigger a Windows restart (installer behavior outside WMT control).`n`nDo you want to continue?"
    $res = [System.Windows.MessageBox]::Show($msg, "Restart Warning", [System.Windows.MessageBoxButton]::YesNo, [System.Windows.MessageBoxImage]::Warning)
    return ($res -eq [System.Windows.MessageBoxResult]::Yes)
}

# 1. Update Selected (Removed CmdTemplate to allow smart logic)
$btnWingetUpdateSel.Add_Click({ 
        $selected = @(Get-WmtUpdateListCheckedItems -FallbackToSelection)
        if ($selected.Count -eq 0) {
            Show-WmtMessageBox -Message "Check one or more update rows first, or select rows as a fallback." -Title "No Updates Checked" -Image Information | Out-Null
            return
        }
        if (-not (Show-WingetRestartRiskWarning -Items $selected -Action "Update")) {
            Write-GuiLog "[Update] Cancelled by user after restart warning."
            return
        }
        & $Script:StartWingetAction -ListItems $selected -ActionName "Update"
    })

function Get-WingetListedUpdateItems {
    if (-not $lstWinget) { return @() }
    return @($lstWinget.Items | Where-Object {
            $id = [string]$_.Id
            $source = [string]$_.Source
            $name = [string]$_.Name
            $isStore = ($source.ToLowerInvariant() -eq "msstore")
            ($isStore -or -not [string]::IsNullOrWhiteSpace($id)) -and
            -not [string]::IsNullOrWhiteSpace($source) -and
            $name -notin @("No results found", "No updates available")
        })
}

function Invoke-WmtAutoInstallAvailableUpdates {
    if (-not (Get-WmtUpdateAutoInstallEnabled)) { return }
    if ($script:WmtAutoInstallActive -or $script:WingetActiveAction) {
        Write-GuiLog "Auto install skipped because a package action is already running."
        return
    }

    $items = @(Get-WingetListedUpdateItems)
    if ($items.Count -eq 0) {
        Write-GuiLog "Auto install found no available updates."
        return
    }

    # Filter for restart risks only; game providers are no longer excluded
    $restartRiskItems = @($items | Where-Object { Test-WingetRestartRiskItem $_ })
    
    $eligibleItems = @($items | Where-Object {
            -not (Test-WingetRestartRiskItem $_)
        })

    if ($restartRiskItems.Count -gt 0) {
        $restartRiskNames = @($restartRiskItems | ForEach-Object {
                if ([string]::IsNullOrWhiteSpace([string]$_.Name)) { [string]$_.Id } else { [string]$_.Name }
            } | Select-Object -Unique)
        Write-GuiLog "Auto install skipped $($restartRiskItems.Count) restart-risk update(s): $($restartRiskNames -join ', ')."
    }

    if ($eligibleItems.Count -eq 0) {
        Write-GuiLog "Auto install had no eligible updates after safety filtering."
        return
    }

    $actionItems = @(ConvertTo-WmtUpdateAllActionItems -Items $eligibleItems)
    if ($actionItems.Count -eq 0) { return }

    $script:WmtAutoInstallActive = $true
    Write-GuiLog "Auto install starting $($eligibleItems.Count) available update(s)."
    Show-WmtBackgroundInstallNotification -Status Started -TotalCount $eligibleItems.Count
    & $Script:StartWingetAction -ListItems $actionItems -ActionName "Update"
}

function ConvertTo-WmtUpdateAllActionItems {
    param([object[]]$Items)

    $storeCount = @($Items | Where-Object { ([string]$_.Source).ToLowerInvariant() -eq "msstore" }).Count
    if ($storeCount -eq 0) { return @($Items) }

    $result = New-Object System.Collections.Generic.List[object]
    $storeActionAdded = $false
    foreach ($item in $Items) {
        if (([string]$item.Source).ToLowerInvariant() -eq "msstore") {
            if (-not $storeActionAdded) {
                $storeName = "Microsoft Store Updates"
                if ($storeCount -gt 1) { $storeName = "Microsoft Store Updates ($storeCount listed)" }
                [void]$result.Add([PSCustomObject]@{
                        Source = "msstore"
                        Name   = $storeName
                        Id     = "__WMT_STORE_UPDATES_ALL__"
                    })
                $storeActionAdded = $true
            }
            continue
        }

        [void]$result.Add($item)
    }

    return $result.ToArray()
}

if ($btnWingetUpdateAll) {
    $btnWingetUpdateAll.Add_Click({
            $items = @(Get-WingetListedUpdateItems)
            if ($items.Count -eq 0) { return }

            $msg = "Update all $($items.Count) listed package(s)?"
            $res = [System.Windows.MessageBox]::Show($msg, "Update All", [System.Windows.MessageBoxButton]::YesNo, [System.Windows.MessageBoxImage]::Question)
            if ($res -ne [System.Windows.MessageBoxResult]::Yes) { return }

            if (-not (Show-WingetRestartRiskWarning -Items $items -Action "Update")) {
                Write-GuiLog "[Update All] Cancelled by user after restart warning."
                return
            }
            $actionItems = @(ConvertTo-WmtUpdateAllActionItems -Items $items)
            & $Script:StartWingetAction -ListItems $actionItems -ActionName "Update"
        })
}

